var PACK2026_QUESTIONS = [
  {"num": 1, "subject": "财务报表", "question": "Which of the following is most likely found in the management commentary?", "options": {"A": "Forward-looking disclosures", "B": "Basis of preparation for the financial statements", "C": "Reasonable assurance whether the financial statements as a whole are free from material misstatement"}, "answer": "A", "explanation": "A Correct because the management commentary, or MD&A, is a good starting place for understanding information in the financial statements. In particular, the forward-looking disclosures, such as those about planned capital expenditures, new store openings, or divestitures, can be useful in projecting a company’s future performance.\nB Incorrect because the notes disclose the basis of preparation for the financial statements.\nC Incorrect because under ISAs, the overall objectives of an auditor in conducting an audit of financial statements are: to obtain reasonable assurance about whether the financial statements as a whole are free from material misstatement, whether due to fraud or error, thereby enabling the auditor to express an opinion on whether the financial statements are prepared, in all material respects, in accordance with an applicable financial reporting framework."},
  {"num": 2, "subject": "财务报表", "question": "Which of the following is most appropriately issued when an auditor determines that the financial statements materially depart from accounting standards and are not fairly presented?", "options": {"A": "Adverse opinion", "B": "Qualified opinion", "C": "Disclaimer of opinion"}, "answer": "A", "explanation": "A Correct because \"[a]n adverse audit opinion is issued when an auditor determines that the financial statements materially depart from accounting standards and are not fairly presented.\"\nB Incorrect because \"[a] qualified audit opinion is one in which there is some scope limitation or exception to accounting standards. Exceptions are described in the audit report with additional explanatory paragraphs so that the analyst can determine the importance of the exception.\"\nC Incorrect because \"a disclaimer of opinion occurs when, for some reason, such as a scope limitation, the auditors are unable to issue an opinion.\""},
  {"num": 3, "subject": "财务报表", "question": "Which of the following statements is most accurate? The role of financial statement analysis is to:", "options": {"A": "provide assurance that the audited financial statements are free from material error.", "B": "provide information about a company’s performance, financial position, and changes in financial position.", "C": "evaluate the performance and financial position of a company for making investment, credit, and other economic decisions."}, "answer": "C", "explanation": "A Incorrect because this describes the role of audit report not financial statement analysis as follows: the independent audit report provides reasonable assurance that the financial statements are fairly presented, meaning that there is a high probability that the audited financial statements are free from material error, fraud, or illegal acts that have a direct effect on the financial statements.\nB Incorrect because this describes the role of financial reporting not financial statement analysis as follows: the role of financial statements issued by companies is to provide information about a company’s performance, financial position, and changes in financial position that is useful to a wide range of users in making economic decisions.\nC Correct because the role of financial statement analysis is to use financial reports prepared by companies, combined with other information, to evaluate the past, current, and potential performance and financial position of a company for the purpose of making investment, credit, and other economic decisions."},
  {"num": 4, "subject": "财务报表", "question": "Common-size statements are most likely the output of which of the following phases of the financial statement analysis framework?", "options": {"A": "Process data", "B": "Analyze/interpret the processed data", "C": "Develop and communicate conclusions and recommendations"}, "answer": "A", "explanation": "A Correct because common-size statements are an output of the “process data” phase of the financial statement analysis framework.\nB Incorrect because analytical results, not common-size statements, are the output of the “analyze/interpret the processed data” phase.\nC Incorrect because analytical reports and recommendations, not common-size statements, are outputs of the “develop and communicate conclusions and recommendations” phase."},
  {"num": 5, "subject": "财务报表", "question": "Earnings calls are most likely sourced from:", "options": {"A": "issuers.", "B": "public third parties.", "C": "proprietary third parties."}, "answer": "A", "explanation": "A Correct because \"earnings calls\" are considered to be from \"issuer sources\".\nB Incorrect because \"earnings calls\" are considered to be from \"issuer sources\", not public third-party sources.\nC Incorrect because \"earnings calls\" are considered to be from \"issuer sources\", not proprietary third-party sources."},
  {"num": 6, "subject": "财务报表", "question": "A company establishes a plan to dispose of one of its material lines of business and will have no further involvement in its operation. The income statement most likely reports the results of this line of business as:", "options": {"A": "discontinued operations.", "B": "unusual or infrequent items.", "C": "continuing operations until the actual sale is performed."}, "answer": "A", "explanation": "A Correct because when a company disposes of or establishes a plan to dispose of one of its component operations and will have no further involvement in the operation, the income statement reports separately the effect of this disposal as a “discontinued” operation under both IFRS and US GAAP. Financial standards provide various criteria for reporting the effect separately, which are generally that the discontinued component must be separable both physically and operationally.\nB Incorrect because IFRS require that items of income or expense that are material and/or relevant to the understanding of the entity’s financial performance should be disclosed separately. Unusual or infrequent items are likely to meet these criteria. For example, restructuring charges, such as costs to close plants and employee termination costs, are considered part of a company’s ordinary activities. As another example, gains and losses arising when a company sells an asset or part of a business, for more or less than its carrying value, are also disclosed separately on the income statement. These sales are considered ordinary business activities.\nC Incorrect because both IFRS and US GAAP specify that the results of discontinued operations should be reported separately from continuing operations. When a company disposes of or establishes a plan to dispose of one of its component operations and will have no further involvement in the operation, the income statement reports separately the effect of this disposal as a “discontinued” operation."},
  {"num": 7, "subject": "财务报表", "question": "The adjustments related to changes in the estimated residual value of a long-lived asset should be:", "options": {"A": "handled prospectively.", "B": "shown separately on the income statement.", "C": "handled retrospectively unless impractical to do so."}, "answer": "A", "explanation": "A Correct because in contrast to changes in accounting policies (such as whether to expense the cost of employee stock options), companies sometimes make changes in accounting estimates (such as the useful life of a depreciable asset). Changes in accounting estimates are handled prospectively, with the change affecting the financial statements for the period of change and future periods. No adjustments are made to prior statements, and the adjustment is not shown on the face of the income statement.\nB Incorrect because in contrast to changes in accounting policies (such as whether to expense the cost of employee stock options), companies sometimes make changes in accounting estimates (such as the useful life of a depreciable asset). Changes in accounting estimates are handled prospectively, with the change affecting the financial statements for the period of change and future periods. No adjustments are made to prior statements, and the adjustment is not shown on the face of the income statement.\nC Incorrect because in contrast to changes in accounting policies (such as whether to expense the cost of employee stock options), companies sometimes make changes in accounting estimates (such as the useful life of a depreciable asset). Changes in accounting estimates are handled prospectively, with the change affecting the financial statements for the period of change and future periods. No adjustments are made to prior statements, and the adjustment is not shown on the face of the income statement."},
  {"num": 8, "subject": "财务报表", "question": "Which of the following may be reported using the modified retrospective method?", "options": {"A": "Corrections of prior period errors", "B": "Changes in estimated useful life of PP&E", "C": "Changes in accounting policies based on the new revenue recognition standard"}, "answer": "C", "explanation": "A Incorrect because correction of an error for a prior period is handled by restating the financial statements (including the balance sheet, statement of owners’ equity, and cash flow statement) for the prior periods presented in the current financial statements. Thus, it uses the “full retrospective method,” which requires companies to restate prior periods’ results.\nB Incorrect because changes in accounting estimates are handled prospectively, with the change affecting the financial statements for the period of change and future periods.\nC Correct because at times, standard setters issue new standards that require companies to change accounting policies. Depending on the standard, companies may be permitted to adopt the standards prospectively (in the future) or retrospectively (restate financial statements as though the standard existed in the past) while the new revenue recognition standard also offered companies the option of using a “modified retrospective” method of adoption. Under the modified retrospective approach, companies were not required to revise previously reported financial statements. Instead, they adjusted opening balances of retained earnings (and other applicable accounts) for the cumulative impact of the new standard."},
  {"num": 9, "subject": "财务报表", "question": "According to the converged standards for revenue recognition, a receivable is recognized on the seller's balance sheet when:", "options": {"A": "a contract is signed.", "B": "all performance obligations have been met except for payment.", "C": "consideration is received in advance of transferring goods or services."}, "answer": "B", "explanation": "A Incorrect because it is only at the point when all performance obligations have been met except for payment that a receivable appears on the seller’s balance sheet. According to the converged standards of revenue recognition, the five steps in recognizing revenue are: 1. Identify the contract(s) with a customer 2. Identify the separate or distinct performance obligations in the contract 3. Determine the transaction price 4. Allocate the transaction price to the performance obligations in the contract 5. Recognize revenue when (or as) the entity satisfies a performance obligation While entering into or signing the contract would be covered by steps 1-4, step 5 is required to recognize revenue the entity will only recognize revenue when it is able to satisfy the performance obligation.\nB Correct because it is only at the point when all performance obligations have been met except for payment that a receivable appears on the seller’s balance sheet.\nC Incorrect because it is only at the point when all performance obligations have been met except for payment that a receivable appears on the seller’s balance sheet. If consideration is received in advance of transferring good(s) or service(s), the seller presents a contract liability. Consequently, the seller recognizes a contract liability, rather than a receivable."},
  {"num": 10, "subject": "财务报表", "question": "For a company reporting on a calendar year basis, the receipt of a payment from a client in Year 1 for the delivery of services in Year 2 most likely increases:", "options": {"A": "net income for Year 1.", "B": "liabilities as of 31 December of Year 1.", "C": "cash flow from operating activities for Year 2."}, "answer": "B", "explanation": "A Incorrect because there are situations when a company receives cash in advance and actually delivers the product or service later, perhaps over a period of time. In this case, the company would record a liability for unearned revenue when the cash is initially received, and revenue would be recognized as being earned over time as products and services are delivered. As delivery of services does not happen in the current year, no revenue is recognized in the current year and, therefore, the transaction will not increase net income for the current year.\nB Correct because there are situations when a company receives cash in advance and actually delivers the product or service later, perhaps over a period of time. In this case, the company would record a liability for unearned revenue when the cash is initially received, and revenue would be recognized as being earned over time as products and services are delivered.\nC Incorrect because the cash flow will be recognized in the current year even though the revenue will not be recognized until the following year. The receipt of cash in the current year will increase cash flow from operating activities in the current year rather than the following year."},
  {"num": 11, "subject": "财务报表", "question": "An analyst gathers the following information (in € millions) about a manufacturing company:\nBased only on this information, applying vertical common-size analysis to the income statement, selling, general, and administrative expenses are:", "options": {"A": "12%.", "B": "20%.", "C": "30%."}, "answer": "A", "explanation": "A Correct because a vertical common-size income statement divides each income statement item by revenue. Gross profit is the amount of revenue available after subtracting the costs of delivering goods or services. Accordingly, based only on this information, under vertical common-size analysis, selling, general, and administrative expenses can be expressed as = Selling, general, and administrative expenses / Revenue = Selling, general, and administrative expenses / (Gross profit + Cost of sales) = 30 / (100 + 150); or = 30 / 250 = 12%.\nB Incorrect because it expresses selling, general, and administrative expenses as a percentage of Cost of sales. Consequently, Selling, general, and administrative expenses / Cost of sales = 30 / 150 = 20%.\nC Incorrect because it expresses selling, general, and administrative expenses as a percentage of Gross profit. Consequently, Selling, general, and administrative expenses / Gross profit = 30 / 100 = 30%."},
  {"num": 12, "subject": "财务报表", "question": "According to the converged accounting standards for revenue recognition, which of the following is the first of five steps in recognizing revenue?", "options": {"A": "Determine the transaction price", "B": "Identify the contract with the customer", "C": "Identify the distinct performance obligations in the contract"}, "answer": "B", "explanation": "A Incorrect because this is the third of five steps in recognizing revenue according to the converged accounting standard for revenue recognition.\nB Correct because this is the first of five steps in recognizing revenue according to the converged accounting standard for revenue recognition. The converged accounting standard for revenue recognition describes the application of five steps in recognizing revenue: 1. Identify the contract(s) with a customer 2. Identify the separate or distinct performance obligations in the contract 3. Determine the transaction price 4. Allocate the transaction price to the performance obligations in the contract 5. Recognize revenue when (or as) the entity satisfies a performance obligation.\nC Incorrect because this is the second of five steps in recognizing revenue according to the converged accounting standard for revenue recognition."},
  {"num": 13, "subject": "财务报表", "question": "According to the converged standards for revenue recognition, which of the following might indicate that a seller has transferred control of an asset to a buyer at a point in time? The seller has:", "options": {"A": "legal title of the asset.", "B": "a present right to payment for the asset.", "C": "significant risks and rewards of ownership related to the asset."}, "answer": "B", "explanation": "A Incorrect because the entity will recognize revenue when it is able to satisfy the performance obligation by transferring control to the customer. Factor to consider when assessing whether the customer has obtained control of an asset at a point in time: Customer (not the entity/seller) has legal title.\nB Correct because the entity (seller) will recognize revenue when it is able to satisfy the performance obligation by transferring control to the customer. Factor to consider when assessing whether the customer has obtained control of an asset at a point in time: Entity has a present right to payment.\nC Incorrect because the entity (seller) will recognize revenue when it is able to satisfy the performance obligation by transferring control to the customer. Factor to consider when assessing whether the customer has obtained control of an asset at a point in time: Customer (not the entity/seller) has the significant risks and rewards of ownership."},
  {"num": 14, "subject": "财务报表", "question": "A company entered into a 5-year construction contract with a total sales price of £3,000,000. The estimated total costs are £2,000,000 and the company incurred £500,000 actual costs in the first year. The company has extensive experience with similar types of contracts. Costs incurred provide an appropriate measure of progress toward completing the contract. Assuming it is highly probable that revenue will not be subsequently reversed, revenue recognized under the contract in Year 1 is most likely:", "options": {"A": "£500,000.", "B": "£600,000.", "C": "£750,000."}, "answer": "C", "explanation": "A Incorrect because it assumes only the incurred actual costs as being recognized as revenue = £0.5m. The standard states that for performance obligations satisfied over time (e.g., where there is a long-term contract), revenue is recognized over time by measuring progress toward satisfying the obligation.\nB Incorrect because it assumes that revenue is only recognized according to the time elapsed. But, the standard refers to performance obligations satisfied over time and requires that progress toward complete satisfaction of the performance obligation be measured based on input method such as the one illustrated here (recognizing revenue based on the proportion of total costs that have been incurred in the period) or an output method (recognizing revenue based on units produced or milestones achieved). Accordingly, the calculation becomes £3.0m / 5 years = £0.6m.\nC Correct because the standard states that for performance obligations satisfied over time (e.g., where there is a long-term contract), revenue is recognized over time by measuring progress toward satisfying the obligation. The standard refers to performance obligations satisfied over time and requires that progress toward complete satisfaction of the performance obligation be measured based on input method such as the one illustrated here (recognizing revenue based on the proportion of total costs that have been incurred in the period) or an output method (recognizing revenue based on units produced or milestones achieved). Accordingly, the company has incurred 25% of the total expected costs (£0.5m / £2.0m); and will thus recognize £0.75m (25% × £3.0m) in revenue in Year 1."},
  {"num": 15, "subject": "财务报表", "question": "An analyst gathers the following information about two companies (in ¥ thousands):\nBased only on the companies' common-size income statements, it appears that:", "options": {"A": "Company 1 spent more on advertising than Company 2.", "B": "both companies spent equally on research and development.", "C": "Company 1 has a higher gross profit margin than Company 2."}, "answer": "C", "explanation": "A Incorrect because common-size analysis of the income statement is performed by stating each line item on the income statement as a percentage of revenue. Company 1 spent 7% of its revenue for advertising expenses (being 531,020 / 7,586,000 = 0.07) while Company 2 spent 8% of its revenue for advertising expenses (being 755,600 / 9,445,000 = 0.08).\nB Incorrect because although both companies spent the same dollar amounts for R&D expenses, the R&D expenses make up different percentages of sales revenue given that sales revenue differs (23.73% for Company 1 and 19.06% for Company 2), so proportionally, the companies did not spend equally.\nC Correct because common-size analysis of the income statement can be performed by stating each line item on the income statement as a percentage of revenue. Accordingly, Company 1's gross profit margin = (7,586,000 –3,413,700) ÷ 7,586,000 = 55%, being higher than Company 2's gross profit margin of (9,445,000 –4,533,600)÷ 9,445,000 = 52%."},
  {"num": 16, "subject": "财务报表", "question": "An analyst gathers the following information about a company's fiscal year ended 31 December:\nOne convertible preferred share is convertible into two common shares. If the tax rate is 40% and there are no other potentially dilutive securities outstanding, reported diluted EPS is closest to:", "options": {"A": "€0.38.", "B": "€0.48.", "C": "€0.63."}, "answer": "C", "explanation": "A Incorrect because it subtracts the preferred dividends from net income in the diluted EPS calculation. Accordingly, Diluted EPS = (€2,500,000 – 1,000,000 × €1) ÷ (2,000,000 + 2 × 1,000,000) = €1,500,000 ÷ 4,000,000 = €0.375 ≈ €0.38.\nB Incorrect because it subtracts the preferred dividends multiplied with an after-tax percentage from net income in the diluted EPS calculation. Accordingly, Diluted EPS = (€2,500,000 – 1,000,000 × €1 × (1 – 0.4) ) ÷ (2,000,000 + 2 × 1,000,000) = €1,900,000 ÷ 4,000,000 = €0.475 ≈ €0.48.\nC Correct because when a company has convertible preferred stock outstanding, diluted EPS is calculated using the if-converted method. The formula to calculate diluted EPS using the if-converted method for preferred stock is: Diluted EPS = Net income ÷ (Weighted average number of shares outstanding + New common shares that would have been issued at conversion). Therefore, Diluted EPS = €2,500,000 ÷ (2,000,000 + 2 × 1,000,000) = €2,500,000 ÷ 4,000,000 = €0.625 ≈ €0.63. However, diluted EPS, by definition, is always equal to or less than basic EPS. Basic EPS = (Net income - Preferred dividends) ÷ (Weighted average number of shares outstanding) = (€2,500,000 – 1,000,000 × €1) ÷ 2,000,000 = €1,500,000 ÷ 2,000,000 = €0.75. Therefore the convertible preferred stocks are dilutive and diluted EPS = €0.63."},
  {"num": 17, "subject": "财务报表", "question": "An analyst gathers the following information about a company for its fiscal year ended 31 December:\nIf the bonds are convertible into 30,000 common shares and there are no other potentially dilutive securities outstanding, reported diluted EPS is closest to:", "options": {"A": "$2.21.", "B": "$2.25.", "C": "$2.34."}, "answer": "A", "explanation": "A Correct because when a company has convertible debt outstanding, the diluted EPS calculation also uses the if-converted method. Diluted EPS is calculated as if the convertible debt had been converted at the beginning of the period. Diluted EPS = (Net Income + After-tax interest on convertible debt – Preferred Dividends) / (Weighted average number of shares outstanding + Additional common shares that would have been issued at conversion); or = [$1,250,000 + ($750,000 × 8% × (1 – 0.30)) – $120,000] / (500,000 + 30,000); or = [$1,250,000 + $42,000 – $120,000] / (500,000 + 30,000); or = $1,172,000 / 530,000 = $2.21. In addition, it is possible that some potentially convertible securities are antidilutive (i.e., their inclusion in the computation would result in an EPS higher than the company's basic EPS). Under IFRS and US GAAP, antidilutive securities are not included in the calculation of diluted EPS. Basic EPS = (Net income – Preferred dividends) / Weighted average number of shares outstanding = ($1,250,000 – $120,000) / 500,000 = $2.26. Because the diluted EPS is less than basic EPS, the securities (options) are not antidilutive and are included in the calculation of diluted EPS. Accordingly, reported diluted EPS is $2.21.\nB Incorrect because it did not calculate after tax interest on convertible debt. Diluted EPS = [$1,250,000 + ($750,000 × 8%) – $120,000] / (500,000 + 30,000); or = [$1,250,000 + $60,000 – $120,000] / (500,000 + 30,000); or = $1,190,000 / 530,000 = $2.25.\nC Incorrect because it did not include the Additional common shares that would have been issued at conversion in the denominator. Diluted EPS = [$1,250,000 + ($750,000 × 8% × (1 – 0.30)) – $120,000] / 500,000; or = [$1,250,000 + $42,000 – $120,000] / 500,000 or = $1,172,000 / 500,000 = $2.34. It is also closest to if the preferred dividends are not subtracted from net income in the numerator: Diluted EPS = [$1,250,000 + $750,000 × 8% × (1 – 0.30)] / (500,000 + 30,000) = $2.44."},
  {"num": 18, "subject": "财务报表", "question": "An analyst gathers the following information about a company's fiscal year which ends on 31 December:\nBasic EPS for the year is closest to:", "options": {"A": "€9.63.", "B": "€10.00.", "C": "€10.49."}, "answer": "C", "explanation": "A Incorrect because it subtracts both Preferred dividends and Common dividends. Accordingly, basic EPS = (Net income – Preferred dividends – Common dividends) / Weighted average number of shares outstanding; or = (€445,000 – €15,000 – €35,000) / 41,000 = €395,000 / 41,000 = €9.634 ≈ €9.63.\nB Incorrect because it subtracts Common dividends (instead of Preferred dividends) from Net income. Accordingly, basic EPS = (Net income – Common dividends) / Weighted average number of shares outstanding; or = (€445,000 – €35,000) / 41,000 = €410,000 / 41,000 = €10.00. Alternatively, using Common shares outstanding on 31 December, instead of Weighted average number of shares outstanding; or = (€445,000 – €15,000) / 43,000 = €430,000 / 43,000 = €10.00.\nC Correct because basic EPS = (Net income – Preferred dividends) / Weighted average number of shares outstanding; or = (€445,000 – €15,000) / 41,000 = €430,000 / 41,000 = €10.488 ≈ €10.49."},
  {"num": 19, "subject": "财务报表", "question": "An analyst gathers the following information about a company for the fiscal year ending 31 December:\nBasic EPS for the year is:", "options": {"A": "$0.57.", "B": "$0.59.", "C": "$0.61."}, "answer": "C", "explanation": "A Incorrect because included common dividends paid in the calculation. Basic EPS = (Net income – Preferred dividends – Common dividends) / Weighted average number of shares outstanding = (252 – 8 – 16) / 400 = 0.57 (pp. 101-102, Example 6)\nB Incorrect because included common dividends paid and excluded preferred dividends paid in the calculation. Basic EPS = (Net income – Common dividends) / Weighted average number of shares outstanding = (252 – 16) / 400 = 0.59 (pp. 101-102, Example 6)\nC Correct because Basic EPS = (Net income – Preferred dividends) / Weighted average number of shares outstanding = (252 – 8) / 400 = 0.61 (pp. 101-102, Example 6)"},
  {"num": 20, "subject": "财务报表", "question": "Stock options issued by a company must be antidilutive when the:", "options": {"A": "options are outstanding for the entire fiscal year.", "B": "options' exercise price is less than the average market price of the stock during the period.", "C": "options' exercise proceeds could purchase more shares than would be issued through option exercise."}, "answer": "C", "explanation": "A Incorrect because the proportion of the year the options were outstanding will only affect the magnitude of dilution since it is multiplied by the difference in shares issued with options and shares purchased with option proceeds. The factor by itself does not determine if options are dilutive or antidilutive.\nB Incorrect because if the market price of stock is greater than the exercise price, the options will be exercised. As a result, more shares will be issued through options than can be purchased in the market using option proceeds. This will result in the options becoming a dilutive security.\nC Correct because for stock options, diluted EPS = (Net income – Preferred dividends) / [Weighted average number of shares outstanding + (New shares that would have been issued at option exercise – Shares that could have been repurchased upon exercise) × (Proportion of the year during which the financial instruments were outstanding)]. If option proceeds purchase more shares in the market than what were issued by stock options, it indicates the exercise price is greater than the market price. As a result, the denominator decreases, increasing calculated diluted EPS to be above basic EPS."},
  {"num": 21, "subject": "财务报表", "question": "Which of the following defines a security as antidilutive? If included in the calculation of diluted EPS, it results in a:", "options": {"A": "higher computed EPS than the basic EPS calculation.", "B": "higher pretax income compared to the basic EPS calculation.", "C": "lower number of shares outstanding compared to the basic EPS calculation."}, "answer": "A", "explanation": "A Correct because a security is antidilutive if its inclusion in the diluted EPS computation would result in an EPS higher than the company’s basic EPS.\nB Incorrect because it is the impact on EPS, not pretax income which determines if a security is antidilutive and if its inclusion in the diluted EPS computation would result in an EPS higher than the company’s basic EPS.\nC Incorrect because it is the impact on EPS, not shares outstanding, which determines if a security is antidilutive and if its inclusion in the diluted EPS computation would result in an EPS higher than the company’s basic EPS."},
  {"num": 22, "subject": "财务报表", "question": "A company's diluted EPS calculation including a potentially dilutive security outstanding equals $2.53. Assuming basic EPS of $2.50, the company should report in its financial statements:", "options": {"A": "basic EPS of $2.53.", "B": "basic EPS and diluted EPS of $2.50.", "C": "basic EPS of $2.50 and diluted EPS of $2.53."}, "answer": "B", "explanation": "A Incorrect because the basic EPS of $2.53 included anti-dilutive securities and is higher than basic EPS of $2.50. Companies are required to report both basic and diluted EPS. Under IFRS and US GAAP, antidilutive securities are not included in the calculation of diluted EPS. Diluted EPS should reflect the maximum potential dilution from conversion or exercise of potentially dilutive financial instruments. Diluted EPS will always be less than or equal to basic EPS. Using the if-converted method resulted in diluted EPS of 2.53, which is greater than basic EPS of 2.50, therefore the securities are anti-dilutive and the effect of their conversion would not be included in diluted EPS. Therefore basic and diluted EPS is 2.50.\nB Correct because companies are required to report both basic and diluted EPS. Under IFRS and US GAAP, antidilutive securities are not included in the calculation of diluted EPS. Diluted EPS should reflect the maximum potential dilution from conversion or exercise of potentially dilutive financial instruments. Diluted EPS will always be less than or equal to basic EPS. Using the if-converted method resulted in diluted EPS of 2.53, which is greater than basic EPS of 2.50, therefore the securities are anti-dilutive and the effect of their conversion would not be included in diluted EPS. Therefore basic and diluted EPS is 2.50.\nC Incorrect because the diluted EPS of $2.53 included anti-dilutive securities and is higher than basic EPS of $2.50. Companies are required to report both basic and diluted EPS. Under IFRS and US GAAP, antidilutive securities are not included in the calculation of diluted EPS. Diluted EPS should reflect the maximum potential dilution from conversion or exercise of potentially dilutive financial instruments. Diluted EPS will always be less than or equal to basic EPS."},
  {"num": 23, "subject": "财务报表", "question": "An analyst gathers the following information (in € millions) about a company:\nApplying vertical common-size analysis to the company's balance sheet, cash and cash equivalents are:", "options": {"A": "20%.", "B": "25%.", "C": "32%."}, "answer": "B", "explanation": "A Incorrect because it states Cash and cash equivalents as percentage of Revenue instead of Total assets. Consequently, the calculation becomes Cash and cash equivalents / Revenue = 40 / 200 = 20%. Alternatively, double counting Cash and cash equivalents when calculating Total assets would produce the same result. Consequently, Cash and cash equivalents = Cash and cash equivalents / (Cash and cash equivalents + Total current assets + Total non-current assets) = 40 / (40 + 125 + 35) = 40 / 200 = 20%.\nB Correct because vertical common-size analysis involves stating each balance sheet item as a percentage of total assets. Accordingly, Cash and cash equivalents is stated as a percentage of Total assets = Cash and cash equivalents / (Total current assets + Total non-current assets) = 40 / (125 + 35) = 40 / 160 = 25%.\nC Incorrect because it states Cash and cash equivalents as percentage of Total current assets instead of Total assets. Consequently, the calculation becomes Cash and cash equivalents / Total current assets = 40 / 125 = 32%."},
  {"num": 24, "subject": "财务报表", "question": "Accounting goodwill arising from acquisitions is:", "options": {"A": "expensed in the period it arises.", "B": "capitalized and amortized over a finite period.", "C": "capitalized and tested for impairment annually."}, "answer": "C", "explanation": "A Incorrect because under both IFRS and US GAAP, accounting goodwill arising from acquisitions is capitalized.\nB Incorrect because under both IFRS and US GAAP, accounting goodwill arising from acquisitions is capitalized. Goodwill is not amortised but is tested for impairment annually. If goodwill is deemed to be impaired, an impairment loss is charged against income in the current period.\nC Correct because under both IFRS and US GAAP, accounting goodwill arising from acquisitions is capitalized. Goodwill is not amortised but is tested for impairment annually. If goodwill is deemed to be impaired, an impairment loss is charged against income in the current period."},
  {"num": 25, "subject": "财务报表", "question": "A company reporting under US GAAP purchases an equity security issued by another company. If the equity security represents less than 1% of the outstanding equity of the issuing company and the acquiring company owns no other equity stake in the issuing company, the investment is most likely carried on the acquiring company's balance sheet at:", "options": {"A": "amortized cost.", "B": "fair value with any unrealized holding gains/losses recognized in the income statement.", "C": "fair value with any unrealized holding gains/losses recognized in other comprehensive income."}, "answer": "B", "explanation": "A Incorrect because under US GAAP, all investments in equity securities (other than investments giving rise to ownership positions that confer significant influence over the investee) are measured at fair value with unrealized holding gains or losses recognized in the income statement.\nB Correct because under US GAAP, all investments in equity securities (other than investments giving rise to ownership positions that confer significant influence over the investee) are measured at fair value with unrealized holding gains or losses recognized in the income statement.\nC Incorrect because under US GAAP, all investments in equity securities (other than investments giving rise to ownership positions that confer significant influence over the investee) are measured at fair value with unrealized holding gains or losses recognized in the income statement."},
  {"num": 26, "subject": "财务报表", "question": "A copyright, for which an active market exists, has a set finite life and is used in a company's operations over more than one fiscal period. Under U.S. GAAP, this copyright is reported using:", "options": {"A": "only the cost model.", "B": "only the revaluation model.", "C": "either the cost or the revaluation model."}, "answer": "A", "explanation": "A Correct because, under US GAAP, companies are required to use the cost model to value intangible assets. IFRS allow companies to value intangible assets under a cost model or under a revaluation model. The revaluation model can only be selected when there is an active market for an intangible asset.\nB Incorrect because the revaluation model is not allowed under US GAAP; however, IFRS permit the use of the revaluation model or the cost model.\nC Incorrect because the revaluation model is not allowed under US GAAP; however, IFRS permit the use of the revaluation model or the cost model."},
  {"num": 27, "subject": "财务报表", "question": "On the statement of cash flows, interest payments may be classified as a financing cash flow under:", "options": {"A": "IFRS only.", "B": "US GAAP only.", "C": "both IFRS and US GAAP."}, "answer": "A", "explanation": "A Correct because the cash paid for interest is included in operating cash flows under US GAAP and may be included in operating or financing cash flows under IFRS and US GAAP classify interest expense as an operating activity, even though the principal amount of the debt issued is classified as a financing activity. IFRS allows companies to classify interest expense as either an operating activity or a financing activity.\nB Incorrect because the cash paid for interest is included in operating cash flows under US GAAP.\nC Incorrect because the cash paid for interest is included in operating cash flows under US GAAP and may be included in operating or financing cash flows under IFRS."},
  {"num": 28, "subject": "财务报表", "question": "An analyst gathers the following information (in € thousands) about a company:\nCash received from customers (in € thousands) is:", "options": {"A": "3,800.", "B": "5,000.", "C": "6,200."}, "answer": "A", "explanation": "A Correct because if revenue reported using accrual accounting is higher than the cash actually collected, the result will typically be an increase in accounts receivable. Also, Beginning accounts receivable Plus: Revenues Minus: Cash collected from customers Equals: Ending accounts receivable restated as: Cash collected from customers = Beginning accounts receivable + Revenue – Ending accounts receivable; or = Revenue – Increase in accounts receivable = 5,000 – 1,200 = 3,800.\nB Incorrect because it equals Revenue (5,000) or the Revenue – Change in cash balance [instead of Change in accounts receivable] = 5,000 – (2,000 – 2,000) = 5,000 – 0 = 5,000.\nC Incorrect because it assumes Cash collected from customers = Revenue + Increase in accounts receivable = 5,000 + 1,200 = 6,200."},
  {"num": 29, "subject": "财务报表", "question": "An analyst gathers the following information about a company’s equipment base:\nThe company sold equipment having a historical cost of €5,000,000 and reported a loss on sale of €250,000. The cash received from the sale of equipment is:", "options": {"A": "€750,000.", "B": "€1,750,000.", "C": "€4,750,000."}, "answer": "B", "explanation": "A Incorrect because the cash received from the sale of equipment is calculated as Historical cost of equipment sold (€5,000,000) – Depreciation expense (€4,000,000) – Loss on sale (€250,000) = €750,000.\nB Correct because selling price (cash inflow) minus book value equals gain or loss on sale; therefore, gain or loss on sale plus book value equals selling price (cash inflow). Accumulated depreciation on the equipment sold = Beginning balance accumulated depreciation + Depreciation expense – Ending balance accumulated depreciation; or = €7,000,000 + €4,000,000 – €8,000,000 = €3,000,000. Book value of the equipment sold = Historical cost of equipment sold – Accumulated depreciation on equipment sold; or = €5,000,000 – €3,000,000 = €2,000,000. Cash received from sale of equipment = Book value of the equipment sold – Loss on sale = €2,000,000 – €250,000 = €1,750,000.\nC Incorrect because the cash received from the sale of equipment is calculated as Historical cost of equipment sold (€5,000,000) – Loss on sale (€250,000) = €4,750,000."},
  {"num": 30, "subject": "财务报表", "question": "When calculating cash paid to suppliers based on income statement and balance sheet data, cost of sales is adjusted for changes in:", "options": {"A": "inventory only.", "B": "accounts payable only.", "C": "both inventory and accounts payable."}, "answer": "C", "explanation": "A Incorrect because this is the adjustment to arrive at purchases from suppliers. To determine purchases from suppliers, cost of goods sold is adjusted for the change in inventory.\nB Incorrect because this is the adjustment of purchases from suppliers to paid to suppliers. Therefore, once purchases have been determined, cash paid to suppliers can be calculated by adjusting purchases for the change in accounts payable.\nC Correct because there are two pieces to this calculation: the amount of inventory purchased and the amount paid for it. To determine purchases from suppliers, cost of goods sold is [cost of sales] adjusted for the change in inventory. Therefore, once purchases have been determined, cash paid to suppliers can be calculated by adjusting purchases for the change in accounts payable."},
  {"num": 31, "subject": "财务报表", "question": "On the statement of cash flows, cash dividends paid may be classified as an operating activity under:", "options": {"A": "IFRS only.", "B": "US GAAP only.", "C": "both IFRS and US GAAP."}, "answer": "A", "explanation": "A Correct because US GAAP classify dividends paid to stockholders as a financing activity, whereas IFRS allow companies to classify dividends paid as either an operating activity or a financing activity.\nB Incorrect because US GAAP classify dividends paid to stockholders as a financing activity, whereas IFRS allow companies to classify dividends paid as either an operating activity or a financing activity.\nC Incorrect because US GAAP classify dividends paid to stockholders as a financing activity, whereas IFRS allow companies to classify dividends paid as either an operating activity or a financing activity."},
  {"num": 32, "subject": "财务报表", "question": "On the statement of cash flows, interest paid should be classified as:", "options": {"A": "a financing cash flow only.", "B": "an operating cash flow only.", "C": "either a financing or an operating cash flow."}, "answer": "C", "explanation": "A Incorrect because IFRS allows companies to classify interest expense as either an operating activity or a financing activity. This is the treatment of dividends paid under US GAAP. US GAAP classifies dividends paid to stockholders as a financing activity.\nB Incorrect because IFRS allows companies to classify interest expense as either an operating activity or a financing activity. This is the treatment of interest paid under US GAAP. US GAAP classifies interest expense as an operating activity, even though the principal amount of the debt issued is classified as a financing activity.\nC Correct because IFRS allows more flexibility in the reporting of such items as interest paid. IFRS allows companies to classify interest expense as either an operating activity or a financing activity."},
  {"num": 33, "subject": "财务报表", "question": "Under the indirect method of reporting cash flow from operating activities, a decrease in deferred income tax liabilities is:", "options": {"A": "ignored.", "B": "added back to net income.", "C": "subtracted from net income."}, "answer": "C", "explanation": "A Incorrect because regardless of the originating source of the deferred tax liability, all changes in deferred tax liabilities will either be added back or subtracted from net income under the indirect method of reporting cash flow from operations.\nB Incorrect because an increase in deferred tax liability would be an addition to net income under the indirect method of reporting cash flow from operations.\nC Correct because a decrease in deferred tax liability would be subtracted from net income under the indirect method of reporting cash flow from operations."},
  {"num": 34, "subject": "财务报表", "question": "An analyst gathers the following information about a company's fiscal year ended 31 December:\nInterest payable on 31 December is:", "options": {"A": "£30,000.", "B": "£80,000.", "C": "£95,000."}, "answer": "B", "explanation": "A Incorrect because Interest expense was not added. Accordingly, Ending interest payable = Beginning interest payable – Cash paid for interest = £45,000 – £15,000 = £30,000.\nB Correct because Ending interest payable = Beginning interest payable + Interest expense – Cash paid for interest. Accordingly, Ending interest payable = Beginning interest payable + Interest expense – Cash paid for interest = £45,000 + £50,000 – £15,000 = £80,000.\nC Incorrect because Cash paid for interest was not deducted. Accordingly, Ending interest payable = Beginning interest payable + Interest expense = £45,000 + £50,000 = £95,000."},
  {"num": 35, "subject": "财务报表", "question": "An analyst gathers the following information (in £ millions) about a company:\nCash paid for other operating expenses (in £ millions) is:", "options": {"A": "4,000.", "B": "4,400.", "C": "4,600."}, "answer": "A", "explanation": "A Correct because to determine the cash paid for other operating expenses, it is necessary to adjust the other operating expenses amount on the income statement by the net changes in prepaid expenses and accrued expense liabilities for the year. Accordingly, Cash paid for other operating expenses = Other operating expenses – Decrease in prepaid expenses – Increase in other accrued liabilities = 4,500 – 200 – 300 = 4,000.\nB Incorrect because it added Decrease in prepaid expenses instead of subtracting it. 4,500 + 200 – 300 = 4,400.\nC Incorrect because it added Increase in accrued liabilities instead of subtracting it. 4,500 – 200 + 300 = 4,600."},
  {"num": 36, "subject": "财务报表", "question": "A company with positive net income could report negative cash flow from operating activities if the company:", "options": {"A": "retires outstanding bonds.", "B": "recognizes significant depreciation expense.", "C": "realizes a gain from the sale of a fixed asset."}, "answer": "C", "explanation": "A Incorrect because retiring outstanding bonds results in a cash outflow from financing activities, not from operating activities.\nB Incorrect because the depreciation expense is a non-cash expense and it is added to net profit in calculating operating cash flow. Therefore, higher depreciation expense, all else being equal, would increase operating cash flow.\nC Correct because a gain from the sale of a fixed asset increases net income but does not increase operating cash flow. Therefore, it does not appear in the operating cash flow section under the direct method and is deducted from net profit in calculating cash flow from operating activities under the indirect method."},
  {"num": 37, "subject": "财务报表", "question": "An analyst gathers the following information (in € millions) about a company:\nIf all purchases and sales were made on credit, gross profit (in € millions) is:", "options": {"A": "90.", "B": "110.", "C": "210."}, "answer": "C", "explanation": "A Incorrect because it subtracts (instead of adds) the Increase in accounts receivable to calculate Revenue. Accordingly, Revenue = Cash received from customers – Increase in accounts receivable; or = €800 – €60 = €740; and Cost of sales = Purchases – Increase in inventory; or = €700 – €50 = €650. Therefore, Gross profit = Revenue – Cost of Sales; or = €740 – €650 = €90.\nB Incorrect because it adds (instead of subtracts) the Increase in inventory to calculate Cost of Sales. Accordingly, Revenue = Cash received from customers + Increase in accounts receivable; or = €800 + €60 = €860; and Cost of sales = Purchases + Increase in inventory; or = €700 + €50 = €750. Therefore, Gross profit = Revenue – Cost of Sales; or = €860 – €750 = €110.\nC Correct because Revenue = Cash received from customers + Increase in accounts receivable; or = €800 + €60 = €860; and Beginning inventory + Purchases = Cost of Sales + Ending inventory; or Cost of sales = Purchases – Increase in inventory; or = €700 – €50 = €650. Therefore, Gross profit = Revenue – Cost of Sales; or = €860 – €650 = €210."},
  {"num": 38, "subject": "财务报表", "question": "The following information relates to a fixed asset that has been sold:\nThe transaction is reported on the statement of cash flows as an:", "options": {"A": "investing cash inflow of ¥2 million.", "B": "investing cash inflow of ¥8 million.", "C": "operating cash inflow of ¥8 million."}, "answer": "B", "explanation": "A Incorrect because ¥2 million is the gain on the sale of the equipment. However, the investing cash flow will increase by the entire sale amount of ¥8 million.\nB Correct because the entire proceeds from the sale of a fixed asset are an investing cash inflow, regardless of whether there was a gain or loss from the sale of the asset. Therefore, the selling price of ¥8 million is an investing cash inflow.\nC Incorrect because it recognizes the entire ¥8 million proceeds from sale, but as an increase to operating cash flow rather than investing cash flow. There will be a negative adjustment of ¥2 million (gain on sale) made to net income in arriving at operating cash flows under the indirect method; however, this has no impact on operating cash flow because it only offsets the ¥2 million that became part of net income as a result of the asset sale. Thus there should be no net effect on operating cash flows."},
  {"num": 39, "subject": "财务报表", "question": "An analyst gathers the following information about a company for a fiscal year:\nUnder the direct method of computing cash flow from operating activities, cash received from customers for the year is closest to:", "options": {"A": "$33,500.", "B": "$35,000.", "C": "$37,000."}, "answer": "B", "explanation": "A Incorrect because it is revenue minus ending receivables ($36,000 – $2,500 = $33,500), rather than revenue minus the increase in receivables.\nB Correct because cash collected from customers is equal to revenue ($36,000) less the increase in accounts receivable ($2,500 – $1,500 = $1,000) or $36,000 – $1,000 = $35,000.\nC Incorrect because it adds the increase in accounts receivable to revenue ($36,000 + $1,000 = $37,000), rather than subtracting it from revenue."},
  {"num": 40, "subject": "财务报表", "question": "An analyst gathered the following information (in £ thousands) about a company's fiscal year:\nCash flow from operating activities (in £ thousands) on the Year 2 statement of cash flows should be:", "options": {"A": "107,400.", "B": "144,600.", "C": "159,400."}, "answer": "C", "explanation": "A Incorrect because it treats the increase/decrease in all three working capital accounts the opposite of how they should be treated. The 45,000 decrease in accounts receivable is subtracted rather than added, the 55,000 increase in inventory is added rather than subtracted, and the 36,000 increase in accounts payable is subtracted rather than added. The calculation becomes 112,000 + 14,000 + 7,400 – 45,000 + 55,000 – 36,000 = 107,400.\nB Incorrect because it subtracts rather than adds the amortization of bond discount. The calculation becomes 112,000 + 14,000 – 7,400 + 45,000 – 55,000 + 36,000 = 144,600.\nC Correct because cash flow from operating activities calculated using the indirect method begins with net income and makes adjustments for non-cash operating activities, non-cash operating expenses and changes in operating working capital items. Depreciation is a non-cash operating expense and is added back; amortization of bond discount is a non-cash operating expense and is added back; the decrease in accounts receivable of 45,000 (375,000 – 330,000) is added back; the increase in inventory of 55,000 (335,000 – 280,000) is subtracted; and the increase in accounts payable of 36,000 (172,000 – 136,000) is added back to net income."},
  {"num": 41, "subject": "财务报表", "question": "An analyst gathers the following information (in £ thousands) about a company:\nIf interest paid is classified as a cash flow from operating activities and the income tax rate is 40%, net debt repayment (in £ thousands) is closest to:", "options": {"A": "940.", "B": "1,044.", "C": "1,200."}, "answer": "B", "explanation": "A Incorrect because it subtracts out the entire interest portion as opposed to the net-of-tax interest amount: FCFF – Interest paid = FCFE + Net debt repayment. Therefore, 2,500 – 260 = 1,300 + Net debt repayment; or Net debt repayment = 940.\nB Correct because FCFF = Cash flow from operating activities (“CFO”) + Interest paid (1 – Tax rate) – Capital expenditures (“FCInv”). In addition, FCFE = CFO – FCInv – Net debt repayment. Rearranging FCFF: CFO – FCInv = FCFF – Interest paid (1 – Tax rate) Rearranging FCFE: CFO – FCInv = FCFE + Net debt repayment Therefore: FCFF – Interest paid (1 – Tax rate) = FCFE + Net debt repayment; or = 2,500 – [260 × (1 – 40%)] = 1,300 + Net debt repayment; or 2,344 = 1,300 + Net debt repayment Therefore, Net debt repayment = 2,344 – 1,300 = 1,044.\nC Incorrect because it assumes that interest paid is classified as a cash flow from financing activities and does not need to be added back to CFO. As such, FCFF = FCFE + Net debt repayment; or 2,500 = 1,300 + Net debt repayment; or Net debt repayment = 1,200."},
  {"num": 42, "subject": "财务报表", "question": "An analyst gathers the following information (in € thousands) about a company:\nIf interest paid is classified as a cash flow from operating activities and the income tax rate is 20%, FCFF (in € thousands) is:", "options": {"A": "57.", "B": "65.", "C": "73."}, "answer": "C", "explanation": "A Incorrect because it has deducted the after-tax interest adjustment instead of adding it back. Accordingly, FCFF = CFO – Int(1 – Tax rate) – FCInv ; or = 80 – [10 × (1 – 0.20)] – 15 = 80 – 8 – 15 = 57.\nB Incorrect because it assumed that interest expensed and paid was included in financing activities and no adjustment for Int(1 – Tax rate) has been made. Accordingly, FCFF = CFO – FCInv ; or = 80 – 15 = 65.\nC Correct because FCFF can also be computed from cash flow from operating activities as FCFF = CFO + Int(1 – Tax rate) – FCInv. CFO represents cash flow from operating activities under US GAAP or under IFRS where the company has included interest paid in operating activities. Accordingly, FCFF = CFO + Int(1 – Tax rate) – FCInv; or = 80 + [10 × (1 – 0.20)] – 15 = 80 + 8 – 15 = 73."},
  {"num": 43, "subject": "财务报表", "question": "In a common-size analysis of the cash flow statement, each line item of cash inflow may be stated as a percentage of:", "options": {"A": "total assets.", "B": "net revenue.", "C": "net cash flow."}, "answer": "B", "explanation": "A Incorrect because for the common-size cash flow statement, there are two alternative approaches. The first approach is to express each line item of cash inflow (outflow) as a percentage of total inflows (outflows) of cash, and the second approach is to express each line item as a percentage of net revenue. Thus an inflow is stated either as a percentage of total inflows or total net revenues, not total assets.\nB Correct because for the common-size cash flow statement, there are two alternative approaches. The first approach is to express each line item of cash inflow (outflow) as a percentage of total inflows (outflows) of cash, and the second approach is to express each line item as a percentage of net revenue.\nC Incorrect because for the common-size cash flow statement, there are two alternative approaches. The first approach is to express each line item of cash inflow (outflow) as a percentage of total inflows (outflows) of cash, and the second approach is to express each line item as a percentage of net revenue. Thus an inflow is stated either as a percentage of total inflows or total net revenues, not net cash flows."},
  {"num": 44, "subject": "财务报表", "question": "An analyst gathers the following information (in € millions) about a company:\nOn a common-size statement of cash flows presented using the indirect method, net operating cash flow is:", "options": {"A": "30%.", "B": "50%.", "C": "75%."}, "answer": "A", "explanation": "A Correct because when a cash flow statement has been presented using the indirect method, operating cash inflows and outflows are not separately presented; therefore, the common-size cash flow statement shows only the net operating cash flow (net cash provided by or used in operating activities) as a percentage of total inflows or outflows, depending on whether the net amount was a cash inflow or outflow. Because the net amount is an outflow, it should be calculated as a percentage of total cash outflows as follows: 750/2500 = 30%.\nB Incorrect because when a cash flow statement has been presented using the indirect method, operating cash inflows and outflows are not separately presented; therefore, the common-size cash flow statement shows only the net operating cash flow (net cash provided by or used in operating activities) as a percentage of total inflows or outflows, depending on whether the net amount was a cash inflow or outflow. Because the net amount is an outflow, it should be calculated as a percentage of total cash outflows as follows: 750/2500 = 30%. The incorrect answer is obtained by dividing net cash used in operations by total cash inflows: 750/1500 = 50%.\nC Incorrect because when a cash flow statement has been presented using the indirect method, operating cash inflows and outflows are not separately presented; therefore, the common-size cash flow statement shows only the net operating cash flow (net cash provided by or used in operating activities) as a percentage of total inflows or outflows, depending on whether the net amount was a cash inflow or outflow. Because the net amount is an outflow, it should be calculated as a percentage of total cash outflows as follows: 750/2500 = 30%. The incorrect answer is obtained by dividing net cash used in operations by the net decrease in cash: 750/1000 = 75%."},
  {"num": 45, "subject": "财务报表", "question": "For a mature company, the primary source of cash flows is most likely from:", "options": {"A": "operating activities.", "B": "investing activities.", "C": "financing activities."}, "answer": "A", "explanation": "A Correct because the major sources of cash for a company can vary with its stage of growth. For a mature company, it is expected and desirable that operating activities are the primary source of cash flows. Over the long term, a company must generate cash from its operating activities. If operating cash flow were consistently negative, a company would need to borrow money or issue stock (financing activities) to fund the shortfall. Eventually, these providers of capital need to be repaid from operations or they will no longer be willing to provide capital.\nB Incorrect because for a mature company, it is expected and desirable that operating activities are the primary source of cash flows. Cash generated from operating activities can be used in either investing or financing activities. If the company has good opportunities to grow the business or other investment opportunities, it is desirable to use the cash in investing activities.\nC Incorrect because for a mature company, it is expected and desirable that operating activities are the primary source of cash flows. Cash generated from operating activities can be used in either investing or financing activities. If the company does not have profitable investment opportunities, the cash should be returned to capital providers, a financing activity."},
  {"num": 46, "subject": "财务报表", "question": "An analyst gathers the following information about a company:\nUnder U.S. GAAP, free cash flow to equity is most likely:", "options": {"A": "less than free cash flow to the firm.", "B": "equal to free cash flow to the firm.", "C": "greater than free cash flow to the firm."}, "answer": "B", "explanation": "A Incorrect because FCFE is equal to FCFF.\nB Correct because under U.S. GAAP, free cash flow to the firm is calculated as CFO + int (1− tax rate) – capital expenditures. Since the firm has interest bearing debt outstanding, $18,000 ($30,000 × (1 − .4)) is added back to CFO in calculating FCFF. In addition, the capital expenditures of $82,000 are subtracted so the equation becomes CFO + $18,000 − $82,000 for a net decrease to CFO of $64,000 ($18,000 − $82,000 = − $64,000). The calculation for free cash flow to equity is CFO – capital expenditures + net borrowing with no adjustment for interest paid under U.S. GAAP. The calculation becomes CFO − $82,000 + $18,000 for a net decrease to CFO of $64,000 (− $82,000 + $18,000). Therefore, FCFE will be equal to FCFF; as the after-tax interest add-back to FCFF is equal to the net borrowing add-back to FCFE and CFO and capital expenditures are the same for both.\nC Incorrect because FCFE is equal to FCFF."},
  {"num": 47, "subject": "财务报表", "question": "An analyst gathers the following information (in € millions) relating to a company's merchandise inventory as of 31 December of Year 1:\nOn 31 December of Year 2, the net realizable value of the inventory is €7 million higher than its carrying value. Under US GAAP, the amount (in € millions) of the reversal of the prior write-down is:", "options": {"A": "0.", "B": "5.", "C": "7."}, "answer": "A", "explanation": "A Correct as U.S. GAAP prohibit the reversal of write-downs.\nB Incorrect because this is the reversal under IFRS. Inventories shall be measured (and carried on the balance sheet) at the lower of cost and net realizable value. Reversal (limited to the amount of the original write-down) is required for a subsequent increase in value of inventory previously written down. The reversal of any write-down of inventories is recognized as a reduction in cost of sales (reduction in the amount of inventories recognized as an expense). The write-down in Year 1 is equal to €5 million (€65 cost − €60 net realizable value). The subsequent reversal is limited to the original €5 million write-down. Under U.S. GAAP, reversal of a write-down is prohibited.\nC Incorrect and is the amount of the reversal allowed if the candidate incorrectly calculated the initial write-down as €7 million (€65 cost − €58 current replacement cost) under IFRS. This is also the correct initial write-down under U.S. GAAP, assuming inventories are measured using LIFO or retail inventory methods. Also, it is the amount by which the net realizable value exceeds carrying value at 31 December Year 2. However, under U.S. GAAP, reversal of a write-down is prohibited."},
  {"num": 48, "subject": "财务报表", "question": "In an environment of steadily increasing prices and quantities, reported ending inventory most closely reflects current replacement value under the:", "options": {"A": "FIFO method using a periodic inventory system.", "B": "LIFO method using a periodic inventory system.", "C": "LIFO method using a perpetual inventory system."}, "answer": "A", "explanation": "A Correct because FIFO assumes that the oldest inventory items are sold first, leaving the most recently purchased inventory on the balance sheet. The carrying amount of inventories under FIFO will more closely reflect current replacement values because inventories are assumed to consist of the most recently purchased items. Companies typically record changes to inventory using either a periodic inventory system or a perpetual inventory system. Under either system, the allocation of goods available for sale to cost of sales and ending inventory is the same if the inventory valuation method used is either specific identification or FIFO.\nB Incorrect because under LIFO, the most recently purchased inventory items are assumed to be sold first, so items included in the cost of goods sold more closely reflect current replacement value, however the balance sheet inventory will reflect prior period (lower, in this case) prices. The cost of sales under LIFO will more closely reflect current replacement value. Although the carrying amount of the ending inventory, however, may differ [compared to the periodic system] because the perpetual system will apply LIFO continuously throughout the year, the effect of increasing prices and quantities will result in a lower reported inventory on the balance sheet than current replacement values.\nC Incorrect because under LIFO, the most recently purchased inventory items are assumed to be sold first, so items included in the cost of goods sold more closely reflect current replacement value, however the balance sheet inventory will reflect prior period (lower, in this case) prices. The cost of sales under LIFO will more closely reflect current replacement value. Although the carrying amount of the ending inventory, however, may differ [compared to the periodic system] because the perpetual system will apply LIFO continuously throughout the year, the effect of increasing prices and quantities will result in a lower reported inventory on the balance sheet than current replacement values."},
  {"num": 49, "subject": "财务报表", "question": "An analyst gathers the following information (in € thousands) about a manufacturing company's inventory:\nThe net realizable value of the inventory (in € thousands) is:", "options": {"A": "750.", "B": "850.", "C": "1,000."}, "answer": "C", "explanation": "A Incorrect because it is the carrying amount of the inventory, being Min(Cost; Net realizable value) = Min(750; 1,100 – 50 – 50) = 750 (which is also equal to the cost of the inventory). IFRS state that inventories shall be measured (and carried on the balance sheet) at the lower of cost and net realizable value. While the net realizable value is the estimated selling price in the ordinary course of business less the estimated costs necessary to make the sale and estimated costs to get the inventory in condition for sale.\nB Incorrect because it calculates Net realizable value = Cost of inventory + Estimated costs necessary to make the sale + Estimated costs to get the inventory in condition for sale; or = 750 + 50 + 50 = 850.\nC Correct because the net realizable value is the estimated selling price in the ordinary course of business less the estimated costs necessary to make the sale and estimated costs to get the inventory in condition for sale. Accordingly, the net realizable value = 1,100 – 50 – 50 = 1,000."},
  {"num": 50, "subject": "财务报表", "question": "Under US GAAP and all else being equal, in a period of stable inventory quantities and rising inventory unit costs, which inventory valuation method is least likely to incur inventory write-downs?", "options": {"A": "FIFO", "B": "LIFO", "C": "Weighted average cost"}, "answer": "B", "explanation": "A Incorrect because companies that use specific identification, weighted average cost, or FIFO methods are more likely to incur inventory write-downs than companies that use the LIFO method.\nB Correct because companies that use specific identification, weighted average cost, or FIFO methods are more likely to incur inventory write-downs than companies that use the LIFO method. Under the LIFO method, the oldest costs are reflected in the inventory carrying amount on the balance sheet. Given increasing inventory costs, the inventory carrying amounts under the LIFO method are already conservatively presented at the oldest and lowest costs. Thus, it is far less likely that inventory write-downs will occur under LIFO—and if a write-down does occur, it is likely to be of a lesser magnitude.\nC Incorrect because companies that use specific identification, weighted average cost, or FIFO methods are more likely to incur inventory write-downs than companies that use the LIFO method."},
  {"num": 51, "subject": "财务报表", "question": "Which of the following is an inventory-related financial statement disclosure required under US GAAP?", "options": {"A": "The carrying amount of inventories carried at fair value less costs to sell.", "B": "The circumstances or events that led to the reversal of a prior-year write-down of inventories.", "C": "The amount of reversal of any prior-year write-down of inventories that is recognized as a reduction in cost of sales in the current period."}, "answer": "A", "explanation": "A Correct because IFRS require eight financial statement disclosures concerning inventory, including (i) the carrying amount of inventories carried at fair value less costs to sell; (ii) the amount of any reversal of any write-down that is recognised as a reduction in cost of sales in the period; and (iii) the circumstances or events that led to the reversal of a write-down of inventories. Inventory-related disclosures under US GAAP are very similar to the disclosures above, except that requirements (ii) and (iii) are not relevant because US GAAP do not permit the reversal of prior-year inventory write-downs.\nB Incorrect because inventory-related disclosures under US GAAP are very similar to the disclosures under IFRS, except that requirement the circumstances or events that led to the reversal of a write-down of inventories is not relevant because US GAAP do not permit the reversal of prior-year inventory write-downs.\nC Incorrect because inventory-related disclosures under US GAAP are very similar to the disclosures under IFRS, except that requirements the amount of any reversal of any write-down that is recognized as a reduction in cost of sales in the period is not relevant because US GAAP do not permit the reversal of prior-year inventory write-downs."},
  {"num": 52, "subject": "财务报表", "question": "An analyst gathers the following information (in € millions) about an automobile manufacturer's inventory:\nThe inventory turnover (calculated using average inventory) in Year 2 is closest to:", "options": {"A": "6.0.", "B": "6.3.", "C": "6.7."}, "answer": "C", "explanation": "A Incorrect because the Inventory turnover in Year 2 was calculated based on the average of Net realizable value of Inventory for the 2 years. Consequently, Inventory turnover in Year 2 = Cost of sales or cost of goods sold / Average inventory = 600 / [(120 + 80) / 2] = 600 / 100 = 6.\nB Incorrect because the Inventory turnover in Year 2 was calculated based on the average of Cost of Inventory for the 2 years. Consequently, Inventory turnover in Year 2 = Cost of sales or cost of goods sold / Average inventory = 600 / [(100 + 90) / 2] = 600 / 95 ≈ 6.3.\nC Correct because IFRS state that inventories shall be measured (and carried on the balance sheet) at the lower of cost and net realisable value. Accordingly, Year 1 inventory = 80 (being lower of 90 and 80) and Year 2 inventory = 100 (being lower of 100 and 120). Inventory turnover in Year 2 = Cost of sales or cost of goods sold / Average inventory = 600 / [(100 + 80) / 2] = 600 / 90 ≈ 6.7."},
  {"num": 53, "subject": "财务报表", "question": "Under US GAAP, which of the following is a required financial statement disclosure concerning inventory?", "options": {"A": "Only the material amount of income resulting from the liquidation of LIFO inventory", "B": "Only the amount of any reversal of any write-down that is recognized as a reduction in cost of goods sold in the period", "C": "Both the material amount of income resulting from the liquidation of LIFO inventory, and the amount of any reversal of any write-down that is recognized as a reduction in cost of goods sold in the period"}, "answer": "A", "explanation": "A Correct because disclosures are useful when analyzing a company. IFRS requires eight financial statement disclosures concerning inventory, three of which are: the accounting policies adopted in measuring inventories, including the cost formula (inventory valuation method) used; the amount of any reversal of any write-down that is recognized as a reduction in cost of sales in the period; the circumstances or events that led to the reversal of a write-down of inventories. Inventory-related disclosures under US GAAP are very similar to the disclosures above, except that requirements for the second and third are not relevant because US GAAP does not permit the reversal of prior-year inventory write-downs. US GAAP also requires disclosure of significant estimates applicable to inventories and of any material amount of income resulting from the liquidation of LIFO inventory.\nB Incorrect because disclosures are useful when analyzing a company. IFRS requires eight financial statement disclosures concerning inventory, three of which are: the accounting policies adopted in measuring inventories, including the cost formula (inventory valuation method) used; the amount of any reversal of any write-down that is recognized as a reduction in cost of sales in the period; the circumstances or events that led to the reversal of a write-down of inventories. Inventory-related disclosures under US GAAP are very similar to the disclosures above, except that requirements for the second and third are not relevant because US GAAP does not permit the reversal of prior-year inventory write-downs. US GAAP also requires disclosure of significant estimates applicable to inventories and of any material amount of income resulting from the liquidation of LIFO inventory.\nC Incorrect because disclosures are useful when analyzing a company. IFRS requires eight financial statement disclosures concerning inventory, three of which are:"},
  {"num": 54, "subject": "财务报表", "question": "All else being equal, in a period of declining inventory unit costs and constant inventory quantities, which of the following inventory valuation methods most likely allocates a higher amount of the total cost of goods available for sale to cost of sales on the income statement?", "options": {"A": "FIFO", "B": "LIFO", "C": "Weighted average cost"}, "answer": "A", "explanation": "A Correct because in an environment of declining inventory unit costs and constant or increasing inventory quantities, FIFO (in comparison with weighted average cost or LIFO) will allocate a higher amount of the total cost of goods available for sale to cost of sales on the income statement and a lower amount to ending inventory on the balance sheet. Accordingly, because cost of sales will be higher under FIFO, a company's gross profit, or operating profit, and income taxes will be lower.\nB Incorrect because in an environment of declining inventory unit costs and constant or increasing inventory quantities, FIFO (in comparison with weighted average cost or LIFO) will allocate a higher amount of the total cost of goods available for sale to cost of sales on the income statement and a lower amount to ending inventory on the balance sheet. Accordingly, because cost of sales will be higher under FIFO, a company's gross profit, or operating profit, and income taxes will be lower. In comparison, in a period of declining inventory unit costs, LIFO will result in higher inventory and lower cost of sales. Because cost declined over the period, LIFO had the highest ending inventory, the lowest cost of sales and the highest gross profit [compared to Specific identification, Weighted average cost and FIFO].\nC Incorrect because in an environment of declining inventory unit costs and constant or increasing inventory quantities, FIFO (in comparison with weighted average cost or LIFO) will allocate a higher amount of the total cost of goods available for sale to cost of sales on the income statement and a lower amount to ending inventory on the balance sheet. Accordingly, because cost of sales will be higher under FIFO, a company's gross profit, or operating profit, and income taxes will be lower."},
  {"num": 55, "subject": "财务报表", "question": "All else being equal, in a period of stable inventory quantities and declining inventory unit costs, using the LIFO inventory valuation method will result in a lower:", "options": {"A": "gross profit than if the FIFO inventory valuation method had been used.", "B": "current ratio than if the FIFO inventory valuation method had been used.", "C": "inventory turnover ratio than if the FIFO inventory valuation method had been used."}, "answer": "C", "explanation": "A Incorrect because if purchase prices of inventory are decreasing, using the LIFO inventory valuation method will result in higher gross profit compared to other methods.\nB Incorrect because if purchase prices of inventory are declining, using the LIFO method of inventory valuation method will result in a higher current ratio compared to other methods. In this scenario, the use of the LIFO method results in a higher ending inventory (current asset) compared to other methods. Therefore, the current ratio, defined as current assets divided by current liabilities will be higher as current assets (inventory) will be higher and current liabilities will not be affected by the choice of the inventory valuation method.\nC Correct because if purchase prices of inventory are declining, using the LIFO method of inventory valuation will result in a higher ending inventory and a lower cost of sales compared to other inventory valuation methods. Inventory turnover is defined as cost of sales ÷ average inventory. Since cost of sales will be lower under LIFO as compared to FIFO and average inventory will be higher under LIFO as compared to FIFO in a period of declining unit costs, inventory turnover will be lower under LIFO than FIFO in a period of declining inventory unit costs."},
  {"num": 56, "subject": "财务报表", "question": "Which of the following ratios will most likely increase as a result of an inventory write-down in the current year?", "options": {"A": "Quick ratio", "B": "Current ratio", "C": "Working capital turnover ratio"}, "answer": "C", "explanation": "A Incorrect as the quick ratio is calculated as (cash + short-term marketable investments + receivables)/current liabilities. Neither the numerator nor the denominator is affected by an inventory write-down as any write-down to market value or net realizable value reduces the value of inventory, and the loss in value (expense) is generally reflected in the income statement in cost of goods sold. Therefore, the quick ratio is not affected by an inventory write-down.\nB Incorrect as the current ratio is calculated as Current assets/Current liabilities and an inventory write-down will affect the numerator (since inventory is a current asset) and will have no effect on the denominator since any write-down to market value or net realizable value reduces the value of inventory, and the loss in value (expense) is generally reflected in the income statement in cost of goods sold. Therefore, the current ratio will be lower after the write-down than it was prior to the write-down and a lower ratio indicates less liquidity, implying a greater reliance on operating cash flow and outside financing to meet short-term obligations.\nC Correct because the working capital turnover ratio is calculated as Revenue/Average working capital. Working capital is defined as current assets minus current liabilities. Inventory is a current asset. An inventory write-down will have no effect on revenue and will decrease average working capital as any write-down to market value or net realizable value reduces the value of inventory, and the loss in value (expense) is generally reflected in the income statement in cost of goods sold. Therefore, the numerator is not affected and the denominator is reduced leading to a higher working capital turnover ratio."},
  {"num": 57, "subject": "财务报表", "question": "An analyst gathers the following information (in £ millions) about a retailer's inventory:\nThe carrying amount (in £ millions) of ending inventory is:", "options": {"A": "240.", "B": "250.", "C": "255."}, "answer": "B", "explanation": "A Incorrect because this is net realizable value less a normal profit margin which is the lower limit of market value under US GAAP. Market value cannot exceed net realizable value (selling price less reasonably estimated costs of completion and disposal). The lower limit of market value is net realizable value less a normal profit margin. The 240 net realizable value less a normal profit margin is lower than both the original cost of 250 and the net realizable value of 255. IFRS state that inventories shall be measured (and carried on the balance sheet) at the lower of cost and net realizable value.\nB Correct because IFRS state that inventories shall be measured (and carried on the balance sheet) at the lower of cost and net realizable value. In the event that the value of inventory declines below the carrying amount on the balance sheet, the inventory carrying amount must be written down to its net realizable value and the loss (reduction in value) recognized as an expense on the income statement. Because the original cost of 250 is lower than the net realizable value of 255, the carrying amount of ending inventory is 250.\nC Incorrect because this is net realizable value which is higher than the original cost of 250. IFRS state that inventories shall be measured (and carried on the balance sheet) at the lower of cost and net realizable value."},
  {"num": 58, "subject": "财务报表", "question": "If inventory that was written down in a previous period subsequently increases in value, the amount of the original write-down may be reversed under:", "options": {"A": "IFRS only.", "B": "US GAAP only.", "C": "both IFRS and US GAAP."}, "answer": "A", "explanation": "A Correct because under IFRS, if inventory that was written down in a previous period subsequently increases in value, the amount of the original write-down is reversed. Subsequent reversal of an inventory write-down is not permitted under US GAAP. Under IFRS, in each subsequent period, a new assessment of net realizable value is made. Reversal (limited to the amount of the original write-down) is required for a subsequent increase in value of inventory previously written down. The reversal of any write-down of inventories is recognized as a reduction in cost of sales (reduction in the amount of inventories recognized as an expense).\nB Incorrect because under IFRS, if inventory that was written down in a previous period subsequently increases in value, the amount of the original write-down is reversed. Subsequent reversal of an inventory write-down is not permitted under US GAAP.\nC Incorrect because under IFRS, if inventory that was written down in a previous period subsequently increases in value, the amount of the original write-down is reversed. Subsequent reversal of an inventory write-down is not permitted under US GAAP."},
  {"num": 59, "subject": "财务报表", "question": "An electronics manufacturer measures its inventories at the lower of cost and:", "options": {"A": "replacement cost.", "B": "net realizable value.", "C": "estimated selling price."}, "answer": "B", "explanation": "A Incorrect because IFRS state that inventories shall be measured (and carried on the balance sheet) at the lower of cost and net realizable value. Under US GAAP, for inventories measured using LIFO and retail inventory methods, market value is defined as current replacement cost subject to upper and lower limits.\nB Correct because IFRS state that inventories shall be measured (and carried on the balance sheet) at the lower of cost and net realizable value. Net realizable value is the estimated selling price in the ordinary course of business less the estimated costs necessary to make the sale and estimated costs to get the inventory in condition for sale.\nC Incorrect because IFRS state that inventories shall be measured (and carried on the balance sheet) at the lower of cost and net realizable value. Net realizable value is the estimated selling price in the ordinary course of business less the estimated costs necessary to make the sale and estimated costs to get the inventory in condition for sale."},
  {"num": 60, "subject": "财务报表", "question": "All else being equal, an inventory write-down by an electronics manufacturing company results in a higher:", "options": {"A": "gross profit margin than if the write-down had not occurred.", "B": "total asset turnover ratio than if the write-down had not occurred.", "C": "days of inventory on hand than if the write-down had not occurred."}, "answer": "B", "explanation": "A Incorrect because an inventory write-down reduces both profit and the carrying amount of inventory on the balance sheet and thus has a negative effect on profitability, liquidity, and solvency ratios. In the event that the value of inventory declines below the carrying amount on the balance sheet, the inventory carrying amount must be written down to its net realizable value and the loss (reduction in value) recognized as an expense on the income statement. This expense may be included as part of cost of sales or reported separately. As gross profit (gross margin) is calculated as revenue minus cost of goods sold, Gross profit margin = Gross profit / Revenue will be lower (not higher). If a company reports the write- down expense separately from cost of sales, there is no impact on the gross profit margin.\nB Correct because an inventory write-down reduces both profit and the carrying amount of inventory on the balance sheet and thus has a negative effect on profitability, liquidity, and solvency ratios. However, activity ratios (for example, inventory turnover and total asset turnover) will be positively affected by a write-down because the asset base (denominator) is reduced. Accordingly, Total asset turnover ratio (Revenue / Average total assets) will be higher as Inventory (Average total assets) will be lower, the numerator, being revenue will not be impacted.\nC Incorrect because days of inventory on hand = Number of days in period / Inventory turnover ratio and activity ratios (for example, inventory turnover and total asset turnover) will be positively affected by a write-down because the asset base (denominator) is reduced. Hence, Days of inventory on hand will be lower (not higher) because denominator (inventory turnover ratio) will be higher."},
  {"num": 61, "subject": "财务报表", "question": "An analyst gathers the following information (in € thousands) about an item in a company's merchandise inventory:\nThe inventory item (in € thousands) is carried on the 31 December of Year 2 balance sheet at:", "options": {"A": "15.", "B": "18.", "C": "20."}, "answer": "B", "explanation": "A Incorrect because it does not take into account that a reversal is required for a subsequent increase in value of inventory previously written down. In addition, under US GAAP reversal of a write-down is prohibited. The company should report on 31 December 2015 a merchandise inventory (in € thousands) of €18,000 (instead of €15,000).\nB Correct because, under IFRS, inventories shall be measured (and carried on the balance sheet) at the lower of cost and net realizable value. In each subsequent period, a new assessment of net realizable value is made. Reversal (limited to the amount of the original write-down) is required for a subsequent increase in value of inventory previously written down. Accordingly, the company reports on 31 December of Year 1 a merchandise inventory of €15,000. The net realizable value at 31 December of Year 2 is €20,000; however, as the reversal is limited to the amount of the original write-down (being €3,000), the company reports on 31 December of Year 2 a merchandise inventory (in € thousands) of €18,000.\nC Incorrect because it does not take into account that a reversal (limited to the amount of the original write-down) is required for a subsequent increase in value of inventory previously written down. The company should report on 31 December 2015 a merchandise inventory (in € thousands) of €18,000, the original cost, (not €20,000), not NRV."},
  {"num": 62, "subject": "财务报表", "question": "An analyst gathers the following information about PP&E that is abandoned and accounted for using the cost model:\nAssuming no impairment, the abandonment of PP&E on the financial statements will result in a:", "options": {"A": "decrease of £10 million in PP&E.", "B": "loss of £1 million on the income statement.", "C": "decrease of £1 million on the cash flow statement."}, "answer": "A", "explanation": "A Correct because when an asset is retired or abandoned, the accounting is similar to a sale, except that the company does not record cash proceeds. Assets are reduced by the carrying amount of the asset at the time of retirement or abandonment, and a loss equal to the asset's carrying amount is recorded. The carrying amount of the asset is 10 at the time of abandonment. As a result, the asset's carrying value will be reduced to 0, resulting in a loss of 10 on the income statement, and will have no cash impact on the cash flow statement.\nB Incorrect because it calculates the loss of 1 on the income statement by using the fair value at the time of abandonment which is incorrect because the cost model is applied.\nC Incorrect because there should be no cash impact on the cash flow statement. However, the decrease of 1 on the cash flow statement is due to the incorrect recognition of the 1 fair value at the time of abandonment."},
  {"num": 63, "subject": "财务报表", "question": "Ignoring income taxes, an impairment loss on equipment will most likely decrease:", "options": {"A": "net profit margin.", "B": "total asset turnover.", "C": "working capital turnover."}, "answer": "A", "explanation": "A Correct because net profit margin is calculated by dividing net income by revenue. The amount of the impairment loss will reduce the carrying amount of the asset on the balance sheet and will reduce net income on the income statement. Thus, the impairment loss will reduce net income but will have no effect on revenue, resulting in a reduction of net profit margin.\nB Incorrect because total asset turnover is calculated by dividing revenue by average total assets. The amount of the impairment loss will reduce the carrying amount of the asset on the balance sheet and will reduce net income on the income statement. Thus, the impairment loss will have no effect on revenue but will reduce total assets, resulting in an increase in total asset turnover.\nC Incorrect because working capital turnover is calculated by dividing revenue by average working capital. Working capital is defined as current assets minus current liabilities. The amount of the impairment loss will reduce the carrying amount of the asset on the balance sheet and will reduce net income on the income statement. Thus, the impairment loss although reduces total assets, does not affect current assets or revenue and therefore does not affect the working capital turnover ratio."},
  {"num": 64, "subject": "财务报表", "question": "An analyst gathers the following information (in € thousands) about equipment:\nThe equipment's carrying amount (in € thousands) after impairment is:", "options": {"A": "7,000.", "B": "8,800.", "C": "9,000."}, "answer": "B", "explanation": "A Incorrect because the carrying amount after the impairment charge is equal to the recoverable amount. Under IAS 36, an impairment loss is measured as the excess of carrying amount over the recoverable amount of the asset. The recoverable amount of an asset is defined as 'the higher of its fair value less costs to sell (9,000 – 200 = 8,800) and its value in use (7,000). Value in use is based on the present value of expected future cash flows. Max[(FV-C), PVCF]) ⇔ Max[(8,800; 7,000)] = 8,800. In this case, 7,000 is the lower, and not the higher amount.\nB Correct because the carrying amount after the impairment charge is equal to the recoverable amount. Under IAS 36, an impairment loss is measured as the excess of carrying amount over the recoverable amount of the asset. The recoverable amount of an asset is defined as 'the higher of its fair value less costs to sell (9,000 – 200 = 8,800) and its value in use (7,000). Value in use is based on the present value of expected future cash flows. Max[(FV-C), PVCF]) ⇔ Max[(8,800; 7,000)] = 8,800.\nC Incorrect because it omits to subtract the cost of selling from the fair value. Accordingly, Recoverable amount = Max(FV; PVCF); or = Max(9,000; 7,000) = 9,000."},
  {"num": 65, "subject": "财务报表", "question": "An analyst gathers the following information (in € thousands) about a company's sale of equipment:\nThe gain on the sale (in € thousands) is:", "options": {"A": "3.", "B": "8.", "C": "13."}, "answer": "C", "explanation": "A Incorrect because it calculates the carrying amount of the equipment = historical cost + accumulated depreciation = 50 + 5 = 55. Consequently, the gain on the sale = selling price – carrying amount = 58 – 55 = 3.\nB Incorrect because it calculates the gain on the sale = selling price – historical cost = 58 – 50 = 8.\nC Correct because the gain or loss on the sale of long-lived assets is computed as the sales proceeds minus the carrying amount of the asset at the time of sale. An asset’s carrying amount is typically the net book value (i.e., the historical cost minus accumulated depreciation). The carrying amount of the equipment = historical cost – accumulated depreciation = 50 – 5 = 45, and the gain on the sale = selling price – carrying amount = 58 – 45 = 13."},
  {"num": 66, "subject": "财务报表", "question": "An analyst gathers the following information (in € thousands) about a company's equipment:\nIgnoring taxes, proceeds from sale of the equipment (in € thousands) is:", "options": {"A": "750.", "B": "1,150.", "C": "1,400."}, "answer": "B", "explanation": "A Incorrect because it calculates the carrying amount of the equipment = purchase price of the equipment – accumulated depreciation = 1,000 – 250 = 750.\nB Correct because the gain or loss on the sale of long-lived assets is computed as the sales proceeds minus the carrying amount of the asset at the time of sale. An asset’s carrying amount is typically the net book value (i.e., the historical cost minus accumulated depreciation). Cash flow from the sale of the equipment = sale proceeds = carrying amount of the equipment + gain on sale of the equipment = (1,000 – 250) + 400 = 1,150.\nC Incorrect because it calculates the cashflow from the sale of equipment = purchase price of the equipment + gain on sale of the equipment = 1,000 + 400 = 1,400."},
  {"num": 67, "subject": "财务报表", "question": "Which of the following disclosures is required for each class of PP&E carried under the cost model?", "options": {"A": "Remaining useful life", "B": "Gross carrying amount", "C": "Fair value and details of how it was obtained"}, "answer": "B", "explanation": "A Incorrect because the estimated useful life, rather than the remaining useful life of the class, is required. Under IFRS, for each class of property, plant, and equipment, a company must disclose the useful lives (or, equivalently, the depreciation rate) used.\nB Correct because under IFRS, for each class of property, plant, and equipment, a company must disclose the measurement bases, the depreciation method, the useful lives (or, equivalently, the depreciation rate) used, the gross carrying amount and the accumulated depreciation at the beginning and end of the period, and a reconciliation of the carrying amount at the beginning and end of the period. In addition, disclosures of restrictions on title and pledges as security of property, plant, and equipment and contractual agreements to acquire property, plant, and equipment are required.\nC Incorrect because disclosing how fair value was obtained is only required for classes of PP&E that are carried under the revaluation model instead of the cost model. Under IFRS, for each class of property, plant, and equipment, a company must disclose. If the revaluation model is used, the date of revaluation, details of how the fair value was obtained, the carrying amount under the cost model, and the revaluation surplus must be disclosed."},
  {"num": 68, "subject": "财务报表", "question": "Which of the following financial statement disclosures concerning PP&E is required under US GAAP?", "options": {"A": "The balances of major classes of depreciable assets", "B": "The date of revaluation under the revaluation model", "C": "A reconciliation of carrying amount at the beginning and end of the period"}, "answer": "A", "explanation": "A Correct because the disclosure requirements under US GAAP are less exhaustive. A company must disclose the depreciation expense for the period, the balances of major classes of depreciable assets, accumulated depreciation by major classes or in total, and a general description of the depreciation method(s) used in computing depreciation expense with respect to the major classes of depreciable assets.\nB Incorrect because the revaluation model is not allowed under US GAAP. The alternative model of reporting long-lived assets is the revaluation model, which is permitted under IFRS but not under US GAAP.\nC Incorrect because under IFRS, for each class of property, plant, and equipment, a company must disclose the measurement bases, the depreciation method, the useful lives (or, equivalently, the depreciation rate) used, the gross carrying amount and the accumulated depreciation at the beginning and end of the period, and a reconciliation of the carrying amount at the beginning and end of the period. The disclosure requirements under US GAAP are less exhaustive. A company must disclose the depreciation expense for the period, the balances of major classes of depreciable assets, accumulated depreciation by major classes or in total, and a general description of the depreciation method(s) used in computing depreciation expense with respect to the major classes of depreciable assets. Thus, a reconciliation of carrying amount at the beginning and end of the period is required under IFRS but not required under US GAAP."},
  {"num": 69, "subject": "财务报表", "question": "An analyst gathers the following information (in € millions) about a manufacturing company's land reported under the revaluation model:\nAll else being equal and ignoring taxes, the revaluation at 31 December Year 1 leads to a:", "options": {"A": "higher quick ratio.", "B": "higher total asset turnover.", "C": "lower debt-to-assets ratio."}, "answer": "C", "explanation": "A Incorrect because the quick ratio is unaffected by the upward asset revaluation. Quick ratio = (cash + short-term marketable investments + receivables) / current liabilities. As an initial upward asset revaluation only affects the PP&E on the asset side and the surplus account in equity, neither the numerator nor the denominator is affected. The quick ratio remains unchanged.\nB Incorrect because the upward asset revaluation decreases the total asset turnover ratio and therefore has a negative effect on this activity ratio. Total asset turnover = revenue / average total assets. As an initial upward asset revaluation only affects the PP&E on the asset side and the surplus account in equity, the numerator is unaffected and only the denominator increased. This leads to a decreased total asset turnover.\nC Correct because the upward asset revaluation decreases the debt-to-asset ratio and therefore improves the debt-to-asset ratio / solvency ratio of the company. Debt-to-assets ratio = total debt / total assets. Under the revaluation model, whether an asset revaluation affects earnings depends on whether the revaluation initially increases or decreases an asset class' carrying amount. If a revaluation initially increases the carrying amount of the asset class, the increase in the carrying amount of the asset class bypasses the income statement and goes directly to equity under the heading of revaluation surplus. As this revaluation initially increases the carrying amount of the asset class, the effect is an increase of total assets and total equity. Total debt remains unchanged. Unchanged numerator (total debt) over an increased denominator (total asset) decreases the ratio."},
  {"num": 70, "subject": "财务报表", "question": "An analyst gathers the following information (in € thousands) about a company's equipment reported under the cost model:\nThe impairment loss (in € thousands) is:", "options": {"A": "300.", "B": "350.", "C": "500."}, "answer": "B", "explanation": "A Incorrect because this is the impairment loss recognized under US GAAP instead of IFRS. Under US GAAP, assessing recoverability is separate from measuring the impairment loss. An asset's carrying amount is considered not recoverable when it exceeds the undiscounted expected future cash flows. If the asset's carrying amount is considered not recoverable, the impairment loss is measured as the difference between the asset's fair value and carrying amount. As the carrying amount of 2,000 > undiscounted expected future cash flows of 1,800, the asset is considered not recoverable. The impairment loss = carrying amount – fair value = 2,000 – 1,700 = 300.\nB Correct because under IAS 36, an impairment loss is measured as the excess of carrying amount over the recoverable amount of the asset. The recoverable amount of an asset is defined as the higher of its fair value less costs to sell and its value in use. Value in use is a discounted measure of expected future cash flows. As the recoverable amount = MAX (Fair value less costs to sell, Value in use) = MAX[(1,700 – 50); 1,500] = 1,650, the impairment loss = carrying amount - recoverable amount = 2,000 – 1,650 = 350.\nC Incorrect because it calculates the recoverable amount as the lower of its fair value less costs to sell and its value in use. Accordingly, the recoverable amount = MIN (Fair value less costs to sell, Value in use) = MIN[(1,700 – 50); 1,500] = 1,500, the impairment loss = carrying amount – recoverable amount = 2,000 – 1,500 = 500."},
  {"num": 71, "subject": "财务报表", "question": "An analyst gathers the following information about a company's equipment:\nThe carrying value of the equipment should be:", "options": {"A": "€17,200.", "B": "€17,400.", "C": "€20,000."}, "answer": "B", "explanation": "A Incorrect because it is the fair value of the asset if sold less costs to sell, which is the lower, not higher, of its fair value less costs to sell and its value in use. Under IFRS, the company would compare the carrying value (€20,000) with the higher of its fair value less costs to sell (€19,100 – €1,900 = €17,200), and its value in use (€17,400). Under IFRS, the carrying value is $17,400.\nB Correct because it is the value of the asset in use. Under IFRS, the company would compare the carrying value (€20,000) with the higher of its fair value less cost to sell (€19,100 – €1,900 = €17,200), and its value in use (€17,400). Under IFRS, the carrying value is €17,400.\nC Incorrect because this is the carrying amount after impairment assessment under US GAAP: the carrying amount (€20,000) is compared with the undiscounted expected future cashflows (€22,000). The carrying amount is less than the undiscounted expected future cash flows, so the carrying amount is considered recoverable. The equipment would continue to be carried at €20,000."},
  {"num": 72, "subject": "财务报表", "question": "An analyst gathers the following information (in £ thousands) about equipment currently in use:\nThe carrying amount (in £ thousands) of the equipment after impairment is:", "options": {"A": "330.", "B": "350.", "C": "400."}, "answer": "C", "explanation": "A Incorrect because £330,000 (= £350,000 – £20,000) is the lower of the equipment's fair value less costs to sell and its value in use (£400,000). IFRS requires the new carrying value to be written down to the higher of its fair value less costs to sell (£330,000) and its value in use (£400,000). Under IAS 36, an impairment loss is measured as the excess of carrying amount over the recoverable amount of the asset. The recoverable amount of an asset is defined as the higher of its fair value less costs to sell and its value in use. Value in use is a discounted measure of expected future cash flows.\nB Incorrect because £350,000 is the lower of the equipment's fair value (£350,000) and its value in use (£400,000) and also erroneously omitting the step of subtracting the costs to sell (£20,000) from its fair value. IFRS requires the new carrying value to be written down to the higher of its fair value less costs to sell (£330,000) and its value in use (£400,000). Under IAS 36, an impairment loss is measured as the excess of carrying amount over the recoverable amount of the asset. The recoverable amount of an asset is defined as the higher of its fair value less costs to sell and its value in use. Value in use is a discounted measure of expected future cash flows.\nC Correct because IFRS requires the new carrying value to be written down to the higher of its fair value less costs to sell (£330,000 = £350,000 – £20,000) and its value in use (£400,000). The equipment would be written down to the recoverable amount of £400,000, which would be the new carrying amount under IFRS. Under IAS 36, an impairment loss is measured as the excess of carrying amount over the recoverable amount of the asset. The recoverable amount of an asset is defined as the higher of its fair value less costs to sell and its value in use. Value in use is a discounted measure of expected future cash flows."},
  {"num": 73, "subject": "财务报表", "question": "Ignoring income taxes, acquiring an intangible asset would most likely result in:", "options": {"A": "a lower net operating cash flow than internally developing the intangible asset.", "B": "the same net operating cash flow than internally developing the intangible asset.", "C": "a higher net operating cash flow than internally developing the intangible asset."}, "answer": "C", "explanation": "A Incorrect because acquiring an intangible asset is an investing activity whereas internally developing an intangible asset can be a combination of operating and investing activity. Costs of acquiring intangible assets are classified as investing cash outflows. IFRS require that expenditures on research (or during the research phase of an internal project) be expensed rather than capitalised as an intangible asset. IFRS allow companies to recognise an intangible asset arising from development (or the development phase of an internal project) if certain criteria are met, including a demonstration of the technical feasibility of completing the intangible asset and the intent to use or sell the asset. Consequently, acquiring an intangible asset would result in lower operating cash outflows than internally developing the intangible asset (as the latter would result in increased operating cash outflows during the research phase).\nB Incorrect because acquiring an intangible asset is an investing activity whereas internally developing an intangible asset can be a combination of operating and investing activites. On the statement of cash flows, costs of internally developing intangible assets are classified as operating cash outflows whereas costs of acquiring intangible assets are classified as investing cash outflows.\nC Correct because acquiring an intangible asset is an investing activity whereas internally developing an intangible asset can be a combination of operating and investing activities. On the statement of cash flows, costs of internally developing intangible assets are classified as operating cash outflows whereas costs of acquiring intangible assets are classified as investing cash outflows. Costs of acquiring intangible assets are classified as investing cash outflows. IFRS require that expenditures on research (or during the research phase of an internal project) be expensed rather than capitalised as an intangible asset. IFRS allow companies to recognise an intangible asset arising from development (or the development phase of an internal project) if certain criteria are met, including a demonstration of the technical feasibility of completing the intangible asset and the intent to use or sell the asset."},
  {"num": 74, "subject": "财务报表", "question": "A company acquires a 5-year license for a product it plans to continue selling for the foreseeable future. The license can be renewed at minimal cost. The license should be:", "options": {"A": "carried on the balance sheet at historical cost.", "B": "amortised using the straight-line method over its estimated useful life.", "C": "amortised using the units-of-production method over its estimated useful life."}, "answer": "A", "explanation": "A Correct because the license has an indefinite life and is not amortised. Only those intangible assets assumed to have finite useful lives are amortised over their useful lives, following the pattern in which the benefits are used up. Examples of intangible assets with indefinite useful lives include an acquired license that, although it has a specific expiration date, can be renewed at little or no cost and an acquired trademark that, although it has a specific expiration, can be renewed at a minimal cost and relates to a product that a company plans to continue selling for the foreseeable future. Intangible assets with indefinite lives are not amortised. Instead, they are carried on the balance sheet at historical cost but are tested at least annually for impairment.\nB Incorrect because the license has an indefinite life and is therefore not amortised. Intangible assets with indefinite lives are not amortised. Instead, they are carried on the balance sheet at historical cost but are tested at least annually for impairment.\nC Incorrect because the license has an indefinite life and is therefore not amortised. Intangible assets with indefinite lives are not amortised. Instead, they are carried on the balance sheet at historical cost but are tested at least annually for impairment."},
  {"num": 75, "subject": "财务报表", "question": "A company incurred the following expenditures (in € millions) to internally develop intangible asset:\nIf the recognition criteria for an intangible asset have been met, the maximum amount of capitalized costs (in € millions) is:", "options": {"A": "600.", "B": "900.", "C": "1,500."}, "answer": "A", "explanation": "A Correct because €600 million represents the costs incurred during the development phase which should be capitalized. Costs incurred in the development stage can be capitalized as intangible assets if certain criteria are met, including technological feasibility, the ability to use or sell the resulting asset, and the ability to complete the project.\nB Incorrect because €900 million represents the costs incurred during the research phase. IFRS require that expenditures on research (or during the research phase of an internal project) be expensed rather than capitalized as an intangible asset.\nC Incorrect because €1,500 million is the total costs incurred in the research and the development phases. It includes the €900 million costs incurred in the research phase which should be expensed. Only the €600 million incurred during the development phase should be capitalized."},
  {"num": 76, "subject": "财务报表", "question": "An analyst gathers the following information (in € thousands) about a company’s non-depreciable asset:\nThe maximum allowable carrying amount (in € thousands) on the Year 2 balance sheet is:", "options": {"A": "40.", "B": "50.", "C": "60."}, "answer": "B", "explanation": "A Incorrect because an adjustment is permitted in all cases under IFRS. The only situation where the loss cannot be reversed is under US GAAP for an asset held for use. Under US GAAP the impairment loss would not be reversed remaining at €40,000.\nB Correct because in recognizing the impairment loss in Year 1, carrying cost was reduced from €50,000 to €40,000, so an impairment loss of $10,000 was reported. A reversal can only be taken for the previous carrying amount; not the full recoverable amount. Therefore with the reversal, carrying cost returns to its previous level of €50,000. Note that IFRS permit the reversal of impairment losses only. IFRS do not permit the revaluation to the recoverable amount if the recoverable amount exceeds the previous carrying amount.\nC Incorrect because IFRS permit the reversal of impairment losses only. IFRS do not permit the revaluation to the recoverable amount if the recoverable amount exceeds the previous carrying amount. Previously, carrying cost was reduced from €50,000 to €40,000, so an impairment loss of €10,000 was reported. A reversal can only be taken for up to the previous carrying amount €50,000. As a result of the reversal €10,000 + €40,000 = €50,000. Therefore, the new carrying cost cannot increase to the full recoverable amount of €60,000."},
  {"num": 77, "subject": "财务报表", "question": "An analyst gathers the following information about a company’s non-depreciable asset reported under the revaluation model:\nThe revaluation surplus after the second revaluation is:", "options": {"A": "–€2,500.", "B": "€0.", "C": "€2,500."}, "answer": "B", "explanation": "A Incorrect because as a result of the revaluations, the €2,500 (= €27,500 − €25,000) increase in the value of the asset during the first year is recorded in the revaluation surplus account in equity, and the –€5,000 (= €22,500 – €27,500) decrease in fair value recorded in the second year is assumed to be applied only to the revaluation surplus account leading to a balance of – €2,500 (= €2,500 – €5,000).\nB Correct because if a revaluation initially increases the carrying amount of the asset class, the increase in the carrying amount of the asset class bypasses the income statement and goes directly to equity under the heading of revaluation surplus. Any subsequent decrease in the asset’s value first decreases the revaluation surplus and then goes to income. As a result, the €2,500 (= €27,500 − €25,000) increase in the value of the asset during the first year is recorded in the revaluation surplus account in equity, and out of the –€5,000 (= €22,500 – €27,500) decrease in fair value recorded in the second year, –€2,500 is used to decrease the revaluation account and the remaining –€2,500 flows to the income statement. Therefore, the balance in the revaluation surplus account is zero.\nC Incorrect because as a result of the revaluations, the €2,500 (= €27,500 − €25,000) increase in the value of the asset during the first year is recorded in the revaluation surplus account in equity, and the –€5,000 (= €22,500 – €27,500) is applied only to the income statement and does not affect the revaluation surplus account."},
  {"num": 78, "subject": "财务报表", "question": "If a company sold PP&E with a carrying amount of £75,000 and reported a gain of £2,000, cash flow from investing activities is:", "options": {"A": "£0.", "B": "£73,000.", "C": "£77,000."}, "answer": "C", "explanation": "A Incorrect because it assumes the cash proceeds from the sale of PP&E went towards either cash flow from operating or cash flow from financing, and not cash flow from investing.\nB Incorrect because it incorrectly subtracts the gain from the carrying amount to calculate the sales proceeds. Thus, sales proceeds = carrying amount – gain on sale = 75 – 2 = 73.\nC Correct because the gain or loss on the sale of long-lived assets is computed as the sales proceeds minus the carrying amount of the asset at the time of sale. An asset’s carrying amount is typically the net book value (i.e., the historical cost minus accumulated depreciation), unless the asset’s carrying amount has been changed to reflect impairment and/or revaluation, as previously discussed. Ignoring taxes, the cash flow from the sale would appear as a cash inflow from investing. Thus, gain on sale of long lived asset = sales proceeds – carrying amount. Rearranging, sales proceeds = gain on sale of long lived asset + carrying amount = 2 + 75 = 77."},
  {"num": 79, "subject": "财务报表", "question": "For leases with a term of twelve months or less, the lessee:", "options": {"A": "may recognize lease payments on a straight-line basis.", "B": "must report at lease inception a “right-of-use” asset and a lease liability, which are both equal to the present value of future lease payments.", "C": "must report at lease inception a “right-of-use” asset and a lease liability, which are both equal to the undiscounted value of future lease payments."}, "answer": "A", "explanation": "A Correct because for lessees, there are lease accounting exemptions for certain lease contracts: If its term is 12 months or less (IFRS and US GAAP) or it is for a “low-value asset,” up to $5,000 in sales price (IFRS only), then the lessee can elect to simply expense the lease payments on a straight-line basis. These exemptions are not available to lessors.\nB Incorrect because under IFRS, there is a single accounting model for both finance and operating leases for lessees. At lease inception, the lessee records a lease payable liability and a “right-of-use” (ROU) asset on its balance sheet, both equal to the present value of future lease payments.\nC Incorrect because under IFRS, there is a single accounting model for both finance and operating leases for lessees. At lease inception, the lessee records a lease payable liability and a “right-of-use” (ROU) asset on its balance sheet, both equal to the present value of future lease payments."},
  {"num": 80, "subject": "财务报表", "question": "Under which of the following classifications of leases will a lessor derecognize the leased asset and recognize a lease receivable on the balance sheet at lease inception?", "options": {"A": "Only a finance lease under IFRS", "B": "Only an operating lease under US GAAP", "C": "Both a finance lease under IFRS and an operating lease under US GAAP"}, "answer": "A", "explanation": "A Correct because the accounting for lessors is substantially identical under IFRS and US GAAP. Under both accounting standards, lessors classify leases as finance or operating leases, which determines the financial reporting. At finance lease inception, the lessor recognizes a lease receivable asset equal to the present value of future lease payments and de-recognizes the leased asset, simultaneously recognizing any difference as a gain or loss.\nB Incorrect because the accounting for lessors is substantially identical under IFRS and US GAAP. Under both accounting standards, lessors classify leases as finance or operating leases, which determines the financial reporting. The accounting treatment for an operating lease is different in that, because the contract is essentially a rental agreement, the lessor keeps the leased asset on its books and recognizes lease revenue on a straight-line basis.\nC Incorrect because the accounting for lessors is substantially identical under IFRS and US GAAP. Under both accounting standards, lessors classify leases as finance or operating leases, which determines the financial reporting. The accounting treatment for an operating lease is different in that, because the contract is essentially a rental agreement, the lessor keeps the leased asset on its books and recognizes lease revenue on a straight-line basis."},
  {"num": 81, "subject": "财务报表", "question": "Compared to purchasing an asset using debt, leasing an asset is most likely to:", "options": {"A": "have a higher financing cost.", "B": "require a greater down payment.", "C": "reduce lessee's exposure to obsolescence."}, "answer": "C", "explanation": "A Incorrect because there are several advantages to leasing an asset compared with purchasing it: Cost effectiveness: Leases are a form of secured borrowing; in the event of non-payment, the lessor simply repossesses the leased asset. As a result, the effective interest rate for a lease is typically lower than what the lessee would pay on an unsecured loan or bond.\nB Incorrect because there are several advantages to leasing an asset compared with purchasing it: Less cash is needed up front. Leases typically require little, if any, down payment.\nC Correct because there are several advantages to leasing an asset compared with purchasing it: Convenience and lower risks associated with asset ownership, such as obsolescence."},
  {"num": 82, "subject": "财务报表", "question": "Under US GAAP, in the second year of a multi-year lease, a lessee with an operating lease most likely reports a:", "options": {"A": "higher interest expense than it would if the lease were a finance lease.", "B": "lower depreciation expense than it would if the lease were a finance lease.", "C": "greater financing cash outflow than it would if the lease were a finance lease."}, "answer": "B", "explanation": "A Incorrect because the interest expense for a lessee with an operating lease is lower compared to a finance lease (there is no interest expense under an operating lease). Under IFRS, there is a single accounting model for both finance and operating leases for lessees. At lease inception, the lessee records a lease payable liability and a “right-of-use” (ROU) asset on its balance sheet, both equal to the present value of future lease payments. The following shows how the transaction under IFRS affects the financial statements: Interest expense on the lease liability and the amortization expense related to the ROU asset are reported separately on the income statement. The following shows how the operating lease transaction under US GAAP appears on the financial statements: Interest expense on the lease liability and the amortization expense related to the ROU asset are reported as a single line titled “lease expense” as an operating expense on the income statement. The interest and amortization components are not reported separately, nor are they grouped with other types of interest and amortization expense (e.g., interest on a bond, amortization of an intangible asset).\nB Correct because for operating leases, the lessee recognizes a single lease expense and no depreciation expense; whereas under a finance lease the lessee records depreciation expense on the right-of-use asset. Under IFRS, there is a single accounting model for both finance and operating leases for lessees. At lease inception, the lessee records a lease payable liability and a “right-of-use” (ROU) asset on its balance sheet, both equal to the present value of future lease payments. The following shows how the transaction under IFRS affects the financial statements: Interest expense on the lease liability and the amortization expense related to the ROU asset are reported separately on the income statement. The following shows how the operating lease transaction under US GAAP appears on the financial statements: Interest expense on the lease liability and the amortization expense related to the ROU asset are reported as a single line titled “lease expense” as an operating expense on the income statement. The interest and amortization components are not reported separately, nor are they grouped with other types of interest and amortization expense (e.g., interest on a bond, amortization of an intangible asset).\nC Incorrect because financing cash outflow for a lessee with an operating lease is lower compared to a finance lease. Under IFRS, there is a single accounting model for both finance and operating leases for lessees. At lease inception, the lessee records a lease payable liability and a “right-of-use” (ROU) asset on its balance sheet, both equal to the present value of future lease payments. The following shows how the transaction under IFRS affects the financial statements: The principal repayment component of the lease payment is reported as a cash outflow under financing activities on the statement of cash flows. The following shows how the operating lease transaction under US GAAP appears on the financial statements: The entire lease payment is reported as a cash outflow under operating activities on the statement of cash flows. The interest and principal repayment components are not reported separately."},
  {"num": 83, "subject": "财务报表", "question": "Which of the following could motivate a lessee to lease a high-value, long-lived asset rather than to purchase it? Lease contracts:", "options": {"A": "usually require little, if any, down payment.", "B": "are reported as off-balance sheet financing structures.", "C": "do not require the recognition of a liability on the balance sheet."}, "answer": "A", "explanation": "A Correct because there are several advantages to leasing an asset compared with purchasing it: Less cash is needed up front. Leases typically require little, if any, down payment.\nB Incorrect because under IFRS, there is a single accounting model for both finance and operating leases for lessees. At lease inception, the lessee records a lease payable liability and a “right-of-use” (ROU) asset on its balance sheet, both equal to the present value of future lease payments. For lessees, there are lease accounting exemptions for certain lease contracts: If its term is 12 months or less (IFRS and US GAAP) or it is for a “low-value asset,” up to $5,000 in sales price (IFRS only), then the lessee can elect to simply expense the lease payments on a straight-line basis.\nC Incorrect because under IFRS, there is a single accounting model for both finance and operating leases for lessees. At lease inception, the lessee records a lease payable liability and a “right-of-use” (ROU) asset on its balance sheet, both equal to the present value of future lease payments."},
  {"num": 84, "subject": "财务报表", "question": "Which of the following components of change in the net pension asset or liability of a defined-benefit pension plan is recognized in other comprehensive income?", "options": {"A": "Employees' service costs", "B": "Actuarial gains and losses", "C": "Net interest expense or income accrued on the beginning net pension asset or liability"}, "answer": "B", "explanation": "A Incorrect because it is recognized in profit and loss instead of other comprehensive income. Under IFRS, the change in the net pension asset or liability each period is viewed as having three general components. Two of the components of this change are recognised as pension expense in profit and loss: (1) employees’ service costs, and (2) the net interest expense or income accrued on the beginning net pension asset or liability.\nB Correct because under IFRS, the change in the net pension asset or liability each period is viewed as having three general components. Two of the components of this change are recognised as pension expense in profit and loss: (1) employees’ service costs, and (2) the net interest expense or income accrued on the beginning net pension asset or liability. The third component of the change in the net pension asset or liability during a period —“remeasurements”— is recognised in other comprehensive income. Remeasurements are not amortised into profit or loss over time. Remeasurements include (a) actuarial gains and losses.\nC Incorrect because it is recognized in profit and loss instead of other comprehensive income. Under IFRS, the change in the net pension asset or liability each period is viewed as having three general components. Two of the components of this change are recognised as pension expense in profit and loss: (1) employees’ service costs, and (2) the net interest expense or income accrued on the beginning net pension asset or liability."},
  {"num": 85, "subject": "财务报表", "question": "Deferred tax assets could arise when:", "options": {"A": "taxable income is greater than accounting profit.", "B": "the carrying amount of an asset exceeds its tax base.", "C": "the carrying amount of a liability is lower than its tax base."}, "answer": "A", "explanation": "A Correct because \"[d]eferred tax assets, which appear on the balance sheet, arise when an excess amount is paid for income taxes (taxable income higher than accounting profit) and the company expects to recover the difference during the course of future operations.\"\nB Incorrect because when the carrying amount of an asset exceeds its tax base, this results in a deferred tax liability.\nC Incorrect because when the carrying amount of a liability is lower than its tax base, this results in a deferred tax liability."},
  {"num": 86, "subject": "财务报表", "question": "A company incurred research costs which were all expensed in the current fiscal year for financial reporting purposes. Applicable tax laws require research costs to be expensed over a 5-year period. If taxable profit will be available against which the deductible temporary differences can be utilized, in the current fiscal year the company will most likely record:", "options": {"A": "a deferred tax asset.", "B": "a deferred tax liability.", "C": "neither a deferred tax asset nor a deferred tax liability."}, "answer": "A", "explanation": "A Correct because the carrying amount is zero due to the full amount having been expensed for financial accounting, while the tax base of the asset was only reduced by one-fifth of the total cost in the first year. In addition, taxable profit will be available against which the deductible temporary differences can be utilized. As the asset carrying amount is less than the tax base, it will result in a deferred tax asset.\nB Incorrect because ia deferred tax liability results when the asset carrying amount is greater than the tax base.\nC Incorrect because the asset carrying amount is less than the tax base, therefore it will result in a deferred tax asset."},
  {"num": 87, "subject": "财务报表", "question": "Which of the following statements about the acquisition of a target company with tax loss carryforwards is most accurate? If the acquirer is profitable:", "options": {"A": "its current tax rate will have no impact on the acquisition price.", "B": "the acquirer would theoretically be willing to pay more than another acquirer with a lower tax rate.", "C": "the acquirer would theoretically be willing to pay more than another acquirer with a higher tax rate."}, "answer": "B", "explanation": "A Incorrect because an acquirer with a high current tax rate would theoretically be willing to pay more than an acquirer with a lower tax rate.\nB Correct because if an acquiring company is profitable, it may be able to use MU’s tax loss carryforwards to offset its own tax liabilities. The value to an acquirer would be the present value of the carryforwards, based on the acquirer’s tax rate and expected timing of realization. The higher the acquiring company’s tax rate, and the more profitable the acquirer, the sooner it would be able to benefit. Therefore, an acquirer with a high current tax rate would theoretically be willing to pay more than an acquirer with a lower tax rate.\nC Incorrect because an acquirer with a high current tax rate would theoretically be willing to pay more than an acquirer with a lower tax rate."},
  {"num": 88, "subject": "财务报表", "question": "The carrying amount of an asset being higher than its tax base may be considered a:", "options": {"A": "temporary difference resulting in a deferred tax asset.", "B": "permanent difference resulting in a deferred tax asset.", "C": "temporary difference resulting in a deferred tax liability."}, "answer": "C", "explanation": "A Incorrect because the carrying amount of an asset being higher than its tax base is considered to be a temporary difference that results in a deferred tax liability.\nB Incorrect because the carrying amount of an asset being higher than its tax base is considered to be a temporary difference that results in a deferred tax liability.\nC Correct because the carrying amount of an asset being higher than its tax base is considered to be a temporary difference that results in a deferred tax liability. Deferred tax liabilities, which also appear on the balance sheet, arise when a deficit amount is paid for income taxes and the company expects to eliminate the deficit over the course of future operations."},
  {"num": 89, "subject": "财务报表", "question": "A deferred tax asset has been previously recognized. At the current balance sheet date, the criteria for economic benefits are not met but the tax differences are still expected to be temporary. As a result:", "options": {"A": "the existing deferred tax asset should be reversed.", "B": "a valuation allowance account should be established.", "C": "the existing deferred tax asset should be reclassified as equity."}, "answer": "A", "explanation": "A Correct because if a deferred tax asset or liability resulted in the past, but the criteria of economic benefits is not met on the current balance sheet date, then, under IFRS, an existing deferred tax asset or liability related to the item will be reversed.\nB Incorrect because if a deferred tax asset or liability resulted in the past, but the criteria of economic benefits is not met on the current balance sheet date, then, under IFRS, an existing deferred tax asset or liability related to the item will be reversed. Under US GAAP, a valuation allowance is established.\nC Incorrect because it answers for a deferred tax liability (reported under US GAAP) that is not expected to reverse. The analyst should classify the deferred tax liability as debt if the liability is expected to reverse with subsequent tax payment. If the liability is not expected to reverse, there is no expectation of a cash outflow and the liability should be treated as equity."},
  {"num": 90, "subject": "财务报表", "question": "A deferred tax liability could arise when:", "options": {"A": "the tax base of an asset is greater than its carrying amount.", "B": "the carrying amount of a liability is greater than its tax base.", "C": "financial accounting income tax expense exceeds income taxes payable."}, "answer": "C", "explanation": "A Incorrect because deferred tax assets, rather than deferred tax liabilities arise when the tax base of an asset is greater than its carrying amount.\nB Incorrect because deferred tax assets, rather than deferred tax liabilities arise when the carrying amount of a liability is greater than its tax base.\nC Correct because deferred tax liabilities arise when a financial accounting income tax expense exceeds income taxes payable."},
  {"num": 91, "subject": "财务报表", "question": "Which of the following might indicate that a company uses aggressive accounting choices to increase its reported performance and financial position in the current period?", "options": {"A": "Increasing the estimated salvage values of PP&E", "B": "Changing the depreciation method from straight-line to double-declining balance", "C": "Changing from weighted average to FIFO inventory valuation method in a period of declining inventory prices and constant inventory quantities"}, "answer": "A", "explanation": "A Correct because increasing the estimated salvage values is an example of a non-conservative (or aggressive) accounting policy. Depreciation expense is affected by another set of choices and estimates regarding the salvage value of the assets being depreciated. A salvage value of zero will always increase depreciation expense under any method compared with the choice of a non-zero salvage value.\nB Incorrect because changing the depreciation method from straight-line to double-declining balance is an example of a conservative accounting policy change. Its effect will increase depreciation expense and thus will decrease earnings for the year. Another example of how choices and estimates can affect reported results lies in the selection of a depreciation method for allocating the cost of long-lived assets to accounting periods subsequent to their acquisition. A company’s managers may choose to depreciate long-lived assets (1) on a straight-line basis, with each year bearing the same amount of depreciation expense; (2) using an accelerated method, with greater depreciation expense recognition in the earlier part of an asset’s life; or (3) using an activity-based depreciation method, which allocates depreciation expense based on units of use or production.\nC Incorrect because changing from weighted average to FIFO inventory valuation method in a period of declining inventory prices and quantities is an example of a conservative accounting policy change. In an environment of declining inventory unit costs and constant or increasing inventory quantities, FIFO (in comparison with weighted average cost or LIFO) will allocate a higher amount of the total cost of goods available for sale to cost of sales on the income statement and a lower amount to ending inventory on the balance sheet. Accordingly, because cost of sales will be higher under FIFO, a company’s gross profit, operating profit, and income before taxes will be lower. Assumptions about inventory cost flows provide another example of how accounting choices can affect financial reporting."},
  {"num": 92, "subject": "财务报表", "question": "Which of the following is most accurate with respect to inherent limitations of audits?", "options": {"A": "An audit opinion is based on a review of information only prepared by the auditor", "B": "An audit is based on an exhaustive review of all transactions during a financial year", "C": "An expectations gap may exist between the auditor’s role and the public’s expectation of auditors"}, "answer": "C", "explanation": "A Incorrect because an audit is based on a review of information provided by the company, not the auditor. Although audit opinions provide discipline for financial reporting quality, inherent limitations exist. An audit opinion is based on a review of information prepared by the company.\nB Incorrect because an audit is based on sampling, not an exhaustive review of all transactions. Although audit opinions provide discipline for financial reporting quality, inherent limitations exist. An audit is based on sampling, and the sample might not reveal misstatements.\nC Correct because although audit opinions provide discipline for financial reporting quality, inherent limitations exist. An “expectations gap” may exist between the auditor’s role and the public’s expectation of auditors. An audit is not typically intended to detect fraud; it is intended to provide assurance that the financial reports are fairly presented."},
  {"num": 93, "subject": "财务报表", "question": "A company was previously considered to have high financial reporting quality. If operating profit dramatically increases, primarily due to foreign exchange rate movements, the company most likely demonstrates:", "options": {"A": "low financial reporting quality and high earnings quality.", "B": "high financial reporting quality and low earnings quality.", "C": "high financial reporting quality and high earnings quality."}, "answer": "B", "explanation": "A Incorrect because exchange rate weakening is a less sustainable source of profits than manufacturing and selling cars. In summary, this example is a case of high-quality financial reporting coupled with lower earnings quality. High-quality financial reports conform to the generally accepted accounting principles (GAAP) of the jurisdiction, such as International Financial Reporting Standards (IFRS), US GAAP, or other home-country GAAP. In addition to conforming to GAAP, high-quality financial reports also embody the characteristics of decision-useful information such as those defined in the Conceptual Framework.\nB Correct because an increase in earnings that is due to foreign exchange rate movements represents high reporting quality yet low earnings quality. As an example, consider a company that exports most of its products; if its domestic currency weakens, the company's exports would become less expensive on the international market, driving international sales and profit. On the financial statements, these profits would be registered in a way that conforms to the generally accepted accounting principles (GAAP) of the jurisdiction, such as International Financial Reporting Standards (IFRS), US GAAP, or other home-country GAAP.s. Thus, the increase in profits would represent high reporting quality. However, this earnings increase would be considered low quality, because it is not a sustainable source of profits in the long-term, given that such a decrease in currency will not occur every year.\nC Incorrect because exchange rate weakening is a less sustainable source of profits than manufacturing and selling cars. In summary, this example is a case of high-quality financial reporting coupled with lower earnings quality. High-quality financial reports conform to the generally accepted accounting principles (GAAP) of the jurisdiction, such as International Financial Reporting Standards (IFRS), US GAAP, or other home-country GAAP. In addition to conforming to GAAP, high-quality financial reports also embody the characteristics of decision-useful information such as those defined in the Conceptual Framework."},
  {"num": 94, "subject": "财务报表", "question": "Which of the following is not classified as a liability or equity on the balance sheet?", "options": {"A": "Deferred revenue", "B": "Noncontrolling interest", "C": "Allowance for doubtful accounts"}, "answer": "C", "explanation": "A Incorrect because deferred revenue is a liability. Some of the common types of current liabilities, including trade payables, financial liabilities, accrued expenses, and deferred income. Deferred income (also called deferred revenue or unearned revenue) arises when a company receives payment in advance of delivery of the goods and services associated with the payment.\nB Incorrect because noncontrolling interest is a component of owners’ equity. The sixth component is the equity attributable to non-controlling interests. Noncontrolling interest (or minority interest). The equity interests of minority shareholders in the subsidiary companies that have been consolidated by the parent (controlling) company but that are not wholly owned by the parent company.\nC Correct because the allowance for doubtful accounts is called a contra account because it is netted against (i.e., reduces) the balance of accounts receivable, which is an asset account. The allowance for doubtful accounts reflects the company’s estimate of the amount of receivables that will ultimately be uncollectible."},
  {"num": 95, "subject": "财务报表", "question": "An analyst gathers the following information about three companies (in $ millions):\nBased on this information, which company is most solvent?", "options": {"A": "Company 1", "B": "Company 2", "C": "Company 3"}, "answer": "C", "explanation": "A Incorrect because although Company 1 has the lowest leverage ratio among the three (tied with Company 3), it has a lower interest coverage ratio than Company 3, indicating that it is not the most solvent.\nB Incorrect because Company 2 has higher leverage ratios than Company 1 and Company 3 and a lower interest coverage ratio than Company 3, indicating that it is not the most solvent.\nC Correct because the ability to meet long-term debt obligations is defined as solvency, which can be measured using leverage and coverage ratios. Generally, the higher the leverage ratio, the higher the financial risk and thus the weaker the solvency. A higher interest coverage ratio indicates stronger solvency. Using the information given, leverage and coverage ratios are:"},
  {"num": 96, "subject": "财务报表", "question": "Which of the following most likely indicates improved efficiency of a company's credit and collection policy? An increase in:", "options": {"A": "receivables turnover ratio", "B": "days of sales outstanding", "C": "number of days of payables"}, "answer": "A", "explanation": "A Correct because a relatively high receivables turnover ratio (and commensurately low DSO) might indicate highly efficient credit and collection.\nB Incorrect because a relatively high receivables turnover ratio (and commensurately low DSO) might indicate highly efficient credit and collection.\nC Incorrect because the number of days of payables reflects the average number of days the company takes to pay its suppliers and is not related to account receivables or the efficiency of the company's credit or collections policies."},
  {"num": 97, "subject": "财务报表", "question": "Which of the following is an example of a liquidity ratio?", "options": {"A": "Defensive interval ratio", "B": "Inventory turnover ratio", "C": "Working capital turnover ratio"}, "answer": "A", "explanation": "A Correct because the defensive interval ratio measures how long the company can continue to pay its expenses from its existing liquid assets without receiving any additional cash inflow. A higher defensive interval ratio indicates greater liquidity.\nB Incorrect because inventory turnover (activity ratio) indicates the resources tied up in inventory (i.e., the carrying costs) and can, therefore, be used to indicate inventory management effectiveness. A higher inventory turnover ratio implies a shorter period that inventory is held, and thus a lower DOH (days of inventory on hand). It is a measure of efficiency, not a measure of liquidity.\nC Incorrect because working capital turnover (activity ratio) indicates how efficiently the company generates revenue with its working capital. A high working capital turnover ratio indicates greater efficiency (i.e., the company is generating a high level of revenues relative to working capital). For some companies, working capital can be near zero or negative, rendering this ratio incapable of being interpreted. Although working capital is the difference between current assets and current liabilities, the ratio of revenue divided by average working capital is a measure of efficiency, not a measure of liquidity."},
  {"num": 98, "subject": "财务报表", "question": "An analyst gathers the following information (in € millions) about a company:\nBased only on this information, the financial leverage ratio is closest to:", "options": {"A": "0.33.", "B": "0.50.", "C": "3.00."}, "answer": "C", "explanation": "A Incorrect because it assumes financial leverage = average total equity / average total assets = 50 / 150 ≈ 0.33.\nB Incorrect because it assumes financial leverage = average total equity / (average total assets – average total equity); or average total equity / average total liabilities = 50 / 100 = 0.50.\nC Correct because financial leverage = average total assets / average total equity = 150 / 50 = 3.00."},
  {"num": 99, "subject": "财务报表", "question": "An analyst gathers the following information (in € millions) about a company:\nROA is:", "options": {"A": "11%.", "B": "13%.", "C": "15%."}, "answer": "A", "explanation": "A Correct because ROA = Net income / Average total assets; or = 110 / 1,000 = 11%.\nB Incorrect because it assumes ROA = Earnings before taxes / Total average assets; or = 130 / 1,000 = 13%.\nC Incorrect because it assumes ROA = EBIT / Average total assets; or = 150 / 1,000 = 15%."},
  {"num": 100, "subject": "财务报表", "question": "Which category of financial ratios is most likely used to measure how efficiently a company performs day-to-day tasks?", "options": {"A": "Activity", "B": "Liquidity", "C": "Solvency"}, "answer": "A", "explanation": "A Correct because activity ratios measure how efficiently a company performs day-to-day tasks, such as the collection of receivables and management of inventory.\nB Incorrect because liquidity ratios measure the company’s ability to meet its short-term obligations.\nC Incorrect because solvency ratios measure a company’s ability to meet long-term obligations. Subsets of these ratios are also known as “leverage” and “long-term debt” ratios."},
  {"num": 101, "subject": "财务报表", "question": "Which of the following analyses can be used to compare a company’s financial ratios with those of its major competitors?", "options": {"A": "Trend only", "B": "Cross-sectional only", "C": "Both trend and cross-sectional"}, "answer": "C", "explanation": "A Incorrect because both trend and cross-sectional analyses are used to compare a company’s financial ratios with those of its competitors. In general, the financial ratios of a company are compared with those of its major competitors (cross-sectional and trend analysis) and to the company’s prior periods (trend analysis).\nB Incorrect because both trend and cross-sectional analyses are used to compare a company’s financial ratios with those of its competitors. In general, the financial ratios of a company are compared with those of its major competitors (cross-sectional and trend analysis) and to the company’s prior periods (trend analysis).\nC Correct because both types of analyses are used to compare a company’s financial ratios with those of its competitors. In general, the financial ratios of a company are compared with those of its major competitors (cross-sectional and trend analysis) and to the company’s prior periods (trend analysis)."},
  {"num": 102, "subject": "财务报表", "question": "All else being equal, a company with older assets has a fixed asset turnover ratio that is:", "options": {"A": "lower compared to a company with newer assets.", "B": "the same compared to a company with newer assets.", "C": "higher compared to a company with newer assets."}, "answer": "C", "explanation": "A Incorrect because the fixed asset turnover ratio would be lower for a company whose assets are newer (and, therefore, less depreciated and so reflected in the financial statements at a higher carrying value) than the ratio for a company with older assets (that are thus more depreciated and so reflected at a lower carrying value).\nB Incorrect because the fixed asset turnover ratio would be lower for a company whose assets are newer (and, therefore, less depreciated and so reflected in the financial statements at a higher carrying value) than the ratio for a company with older assets (that are thus more depreciated and so reflected at a lower carrying value).\nC Correct because the fixed asset turnover ratio would be lower for a company whose assets are newer (and, therefore, less depreciated and so reflected in the financial statements at a higher carrying value) than the ratio for a company with older assets (that are thus more depreciated and so reflected at a lower carrying value)."},
  {"num": 103, "subject": "财务报表", "question": "An analyst gathers the following information (in £ millions) about a company:\nThe total debt ratio is:", "options": {"A": "0.25.", "B": "0.50.", "C": "2.00."}, "answer": "A", "explanation": "A Correct because the total debt ratio = total debt / total assets = 100 / 400 = 0.25.\nB Incorrect because it calculates total debt ratio = total debt / total equity, which is the debt-to-equity ratio = 100 / 200 = 0.50. This ratio may also be incorrectly calculated by dividing total liabilities by total assets (200/400 = .50)\nC Incorrect because it calculates total debt ratio = total assets / total equity, which is the financial leverage ratio = 400 / 200 = 2.00."},
  {"num": 104, "subject": "财务报表", "question": "An analyst gathers the following information (in £ thousands) about a company's current assets and liabilities:\nThe company's quick ratio is:", "options": {"A": "0.13.", "B": "0.33.", "C": "0.40."}, "answer": "B", "explanation": "A Incorrect because it is the Cash ratio. The Cash ratio = (Cash and equivalents + Short-term marketable securities) / Current liabilities. The calculation is (800 + 500) / 10,000 = 1,300 / 10,000 = 0.13 or 13%.\nB Correct because the Quick ratio = (Cash and equivalents + Short-term marketable securities + Receivables) / Current liabilities. The calculation is (800 + 500 + 2,000) / 10,000 = 3,300 / 10,000 = 0.33, or 33%.\nC Incorrect because it is the Current ratio. The Current ratio = Current assets / Current liabilities, the calculation is (800 + 500 + 700 + 2,000) / 10,000 = 0.4, or 40%."},
  {"num": 105, "subject": "财务报表", "question": "An analyst gathers the following information (in € thousands) about a company whose fiscal year ends on 31 December:\nThe company’s trailing 12 month earnings (in € thousands) for the period ended 30 June of Year 2 is:", "options": {"A": "1,700.", "B": "3,700.", "C": "4,200."}, "answer": "A", "explanation": "A Correct because the company’s trailing 12 months earnings for the period ended 30 June of Year 2 are calculated as (Earnings as of 31 December of Year 1 – Earnings as of 30 June of Year 1) + Earnings as of 30 June of Year 2 = (1.500 – 2,000) + 2,200 = –500 + 2,200 = 1,700.\nB Incorrect because the company’s trailing 12 months earnings for the period ended 30 June of Year 2 are calculated as Earnings as of 31 December of Year 1 + Earnings as of 30 June of Year 2 = 1.500 + 2,200 = 3,700.\nC Incorrect because the company’s trailing 12 months earnings for the period ended 30 June of Year 2 are calculated as Earnings as of 30 June of Year 1 + Earnings as of 30 June of Year 2 = 2,000 + 2,200 = 4,200."},
  {"num": 106, "subject": "财务报表", "question": "An analyst gathers the following information about a company:\nThe total asset turnover ratio is closest to:", "options": {"A": "1.0.", "B": "1.3.", "C": "1.5."}, "answer": "B", "explanation": "A Incorrect because it has included the EBIT Margin in the calculation instead of Net Profit Margin. Accordingly, Total asset turnover = ROE / (EBIT Margin × Leverage); or = 10% / (5% × 2) = 1.0.\nB Correct because in accordance to the DuPont analysis for ROE, ROE = Net profit margin × Total asset turnover × Leverage. Thus, Total asset turnover = ROE / (Net profit margin × Leverage); or = 10% / (4% × 2) = 1.25 ≈ 1.3.\nC Incorrect because it included Interest burden. Accordingly, Total asset turnover = ROE / (Net profit margin × Leverage × Interest Burden); or = 10% / (4% × 2 × 85%) = 1.471 ≈ 1.5."},
  {"num": 107, "subject": "财务报表", "question": "An analyst gathers the following information about a company:\nThe average tax rate is closest to:", "options": {"A": "43%.", "B": "47%.", "C": "57%."}, "answer": "C", "explanation": "A Incorrect because it calculated the tax burden (42.78%, or ≈ 43%) instead of the average tax rate. Tax burden reflects one minus the average tax rate, or how much of a company’s pretax profits it gets to keep.\nB Incorrect because it mistook ROE for ROA in the calculation. ROA can be decomposed into Tax Burden × Interest burden × EBIT margin × Total asset turnover. Accordingly, Tax burden = ROA / (Interest burden × EBIT margin × Total asset turnover) 15%/ (0.85 × 30% × 1.1) = 53.48%. Tax burden reflects one minus the average tax rate. Thus, average tax rate = 1 – Tax burden = 1 – 53.48% = 46.52% ≈ 47.\nC Correct because using DuPont analysis, ROE = Tax Burden × Interest Burden × EBIT margin × Total asset turnover × Leverage. Accordingly, Tax burden = ROE / (Interest Burden × EBIT margin × Total asset turnover × Leverage) = 15% / (0.85 × 30% × 1.1 × 1.25) = 42.78%. Tax burden reflects one minus the average tax rate, or how much of a company’s pretax profits it gets to keep. Thus, average tax rate = 1 – Tax burden = 1 – 42.78% = 57.22% ≈ 57%."},
  {"num": 108, "subject": "财务报表", "question": "Which of the following ratios is most appropriate in measuring a company's\nability to cover its debt payments?", "options": {"A": "Return on equity", "B": "Fixed asset turnover", "C": "Fixed charge coverage"}, "answer": "C", "explanation": "A Incorrect because this is a profitability ratio and ROE measures the return earned by a company on its equity capital, including minority equity, preferred equity, and common equity. ROE = Net income / Average total equity\nB Incorrect because this is an activity ratio (or asset utilization ratio or operating efficiency ratio), which measures how well a company manages various activities. Fixed asset turnover = Revenue / Average net fixed assets. The fixed assets turnover ratio measures how efficiently the company generates revenues from its investments in fixed assets.\nC Correct because solvency ratios are primarily of two types. Debt ratios, the first type, focus on the balance sheet and measure the amount of debt capital relative to equity capital. Coverage ratios, the second type, focus on the income statement and measure the ability of a company to cover its debt payments. These ratios are useful in assessing a company’s solvency and, therefore, in evaluating the quality of a company’s bonds and other debt obligations."},
  {"num": 109, "subject": "财务报表", "question": "An analyst gathers the following information about a company:\nROE is:", "options": {"A": "8%.", "B": "12%.", "C": "18%."}, "answer": "A", "explanation": "A Correct because ROE = Net profit margin × Total asset turnover × Financial leverage = (Net income / Revenue) × (Revenue / Average total assets) × (Average total assets / Average shareholders' equity) = (60,000 / 1,000,000) × (1,000,000 / 1,500,000) × 2.0 = 0.06 × 0.66 × 2.0 = 0.08 = 8%. Alternatively, ROE = ROA × Financial leverage = (Net income / Average total assets) × Financial leverage = (60,000 / 1,500,000) × 2.0 = 0.04 × 2.0 = 0.08 = 8%. Alternatively, Financial leverage = Average total assets / Average shareholders' equity; or Average shareholders' equity = Average total assets / Financial leverage = 1,500,000 / 2 = 750,000. Thus, ROE = Net income / Average shareholders' equity or 60,000 / 750,000 = 0.08 = 8%.\nB Incorrect because EBIT margin instead of Net profit margin is used in the calculation of ROE: (EBIT / Revenue) × (Revenue / Average total assets) × Financial leverage = (90,000 / 1,000,000) × (1,000,000 / 1,500,000) × 2 = 0.09 × 0.66 × 2.0 = 0.12 = 12%.\nC Incorrect because the total asset turnover ratio is inverted in the calculation or ROE = (Net income / Revenue) × (Average total assets / Revenue) × Leverage = (60,000 / 1,000,000) × (1,500,000 / 1,000,000) × 2; or = 0.06 × 1.5 × 2.0 = 0.18 = 18%."},
  {"num": 110, "subject": "财务报表", "question": "An analyst gathers the following information (in £ millions) about a company:\nThe fixed charge coverage ratio is closest to:", "options": {"A": "1.2.", "B": "1.6.", "C": "2.0."}, "answer": "C", "explanation": "A Incorrect because it uses Net income instead of EBIT. Accordingly, Fixed charge coverage ratio = (Net income + Lease payments) / (Interest payments + Lease payments) = (8 + 4) / (6 + 4) = 1.2.\nB Incorrect because it omits Lease payments in the numerator. Accordingly, Fixed charge coverage ratio = EBIT / (Interest payments + Lease payments) = 16 / (6 + 4) = 1.6.\nC Correct because the fixed charge coverage ratio relates fixed financing charges, or obligations, to the cash flow generated by the company. It measures the number of times a company’s earnings (before interest, taxes, and lease payments) can cover the company’s interest and lease payments. Accordingly, Fixed charge coverage ratio = (EBIT + Lease payments) / (Interest payments + Lease payments) = (16 + 4) / (6 + 4) = 2.0."},
  {"num": 111, "subject": "财务报表", "question": "A debt-to-equity ratio of 1.0 most likely results in a debt-to-capital ratio of:", "options": {"A": "0.5.", "B": "1.0.", "C": "2.0."}, "answer": "A", "explanation": "A Correct because the debt-to-equity ratio measures the amount of debt financing relative to equity financing. A debt-to-equity ratio of 1.0 indicates equal amounts of debt and equity, which is the same as a debt-to-capital ratio of 50 percent. Debt-to-equity ratio = Total debt / Total shareholder's equity = 1.0. Accordingly, Total debt = Total shareholder's equity, while Debt-to-capital ratio = Total Debt / (Total Debt + Total shareholder's equity) = Total Debt / (2 × Total Debt) = 1/2 = 0.5.\nB Incorrect because it considers Capital = Equity. Accordingly, Debt-to-equity ratio = Debt-to-capital ratio = 1.0.\nC Incorrect because it considers debt-to-capital ratio to be a financial leverage ratio."},
  {"num": 112, "subject": "财务报表", "question": "All else being equal, the cash conversion cycle most likely shortens if:", "options": {"A": "payables turnover decreases.", "B": "inventory turnover decreases.", "C": "days of sales outstanding increases."}, "answer": "A", "explanation": "A Correct because the Cash conversion cycle = Days of inventory on hand + Days of sales outstanding – Number of days of payables. Number of days of payables = Days in the period / Payables turnover. If payables turnover were to decrease, it would increase the Number of days of payables, decreasing the CCC.\nB Incorrect because the Cash conversion cycle = Days of inventory on hand + Days of sales outstanding – Number of days of payables. Days of inventory on hand = Days in the period / Inventory turnover. A decrease in inventory turnover would therefore increase the Days of inventory on hand, thereby increasing the cash conversion cycle.\nC Incorrect because the Cash conversion cycle = Days of inventory on hand + Days of sales outstanding – Number of days of payables. An increase in the Days of sales outstanding would increase, not decrease, the cash conversion cycle."},
  {"num": 113, "subject": "财务报表", "question": "An analyst gathers the following information about a company (in millions):\nBased only on this information, which ratio most likely increased in Year 2 over Year 1?", "options": {"A": "Return on equity", "B": "Financial leverage", "C": "Total asset turnover"}, "answer": "C", "explanation": "A Incorrect because ROE decreased: Year 2 ROE = Net income / Average total equity = 23/220 = 0.1045 Year 1 ROE = Net income / Average total equity = 21/195 = 0.1077\nB Incorrect because financial leverage decreased: Year 2 Financial leverage = Average total assets / Average total equity = 536/220 = 2.44 Year 1 Financial leverage = Average total assets / Average total equity = 529/195 = 2.71\nC Correct because total asset turnover increased:"},
  {"num": 114, "subject": "财务报表", "question": "An analyst gathers the following information (in € millions) about a company:\nThe receivables turnover ratio is closest to:", "options": {"A": "0.7.", "B": "1.2.", "C": "1.5."}, "answer": "C", "explanation": "A Incorrect because it calculates the ratio as average receivables ÷ revenue. The calculation becomes 10 ÷ 15 ≈ 0.67.\nB Incorrect because it uses cost of sales in the numerator. The calculation becomes = 12 ÷ 10 = 1.2\nC Correct because the receivables turnover ratio is calculated as revenue ÷ average receivables. The calculation is receivables turnover ratio = 15 ÷ 10 = 1.5."},
  {"num": 115, "subject": "财务报表", "question": "An analyst gathers the following information about a company:\nDuring Year 2, return on equity most likely:", "options": {"A": "decreased.", "B": "remained the same.", "C": "increased."}, "answer": "A", "explanation": "A Correct because ROE = ROA × leverage. ROA is given in the table. Leverage is equal to average total assets/average shareholders' equity. Therefore, ROE for Year 1 is 25.2% (0.14 × (9,000/5,000)) while the ROE for Year 2 is 23.1% (0.15 × (7,300/4,750)), i.e. during Year 2 ROE decreased.\nB Incorrect because ROE decreased from 25.2% in Year 1 to 23.1% in Year 2.\nC Incorrect because ROE decreased from 25.2% in Year 1 to 23.1% in Year 2."},
  {"num": 116, "subject": "财务报表", "question": "An analyst gathers the following information from a company's balance sheet (in millions):\nBased on this information, the company's liquidity ratios at the end of Year 2 have:", "options": {"A": "decreased since the end of Year 1.", "B": "remained the same since the end of Year 1.", "C": "increased since the end of Year 1."}, "answer": "B", "explanation": "A Incorrect because the two liquidity ratios which can be calculated from the information, current ratio and cash ratio, are unchanged in Year 2 vs. Year 1 (as shown in the Response Rationale for the answer key). The faster increase in total liabilities vs. total assets may draw candidates into thinking that liquidity worsened (but it was solvency that likely worsened).\nB Correct because the two liquidity ratios which can be calculated from the information provided, current ratio and cash ratio, are unchanged in Year 2 vs. Year 1, meaning liquidity is most likely the same. Current ratio = current assets / current liabilities = 110/352 (in Year 2) = 0.3125 = 100/320 (in Year 1) Cash ratio = cash and marketable securities / current liabilities = 55/352 (in Year 2) = 0.15625 = 50/320 (in Year 1)\nC Incorrect because the two liquidity ratios which can be calculated from the information provided, current ratio and cash ratio, are unchanged in Year 2 vs. Year 1 (as shown in the Response Rationale for the answer key). Candidates may notice that total liabilities increased faster than total assets, think this is an indicator of liquidity, and get the direction of the change reversed."},
  {"num": 117, "subject": "财务报表", "question": "An analyst gathers the following information about two companies:\nWhich company most likely needs to raise additional funds for working capital purposes?", "options": {"A": "Only Company 1", "B": "Only Company 2", "C": "Both Company 1 and Company 2"}, "answer": "B", "explanation": "A Incorrect because Company 1's cash conversion cycle is –10 days (40 + 20 – 70). Company 1 does not need to raise capital for working capital purposes; it actually has 10 days of excess cash to invest.\nB Correct because the cash conversion cycle is positive for Company 2, which means the company must finance its working capital. The time between the outlay of cash and the collection of cash is called the ‘cash conversion cycle.' Cash conversion cycle = Days of sales outstanding + Days of inventory on hand – Number of days of payables. Company 2's cash conversion cycle = 40 + 25 – 60 = 5 days. Company 1's cash conversion cycle = 40 + 20 – 70 = –10 days. Company 1 does not need to raise capital for working capital purposes; it actually has 10 days of excess cash to invest.\nC Incorrect because although Company 2 has a positive cash conversion cycle of 5 days and thus must finance its working capital, Company 1 has a negative cash conversion cycle of 10 days and thus does not need to raise capital for working capital purposes (it actually has 10 days of excess cash to invest)."},
  {"num": 118, "subject": "财务报表", "question": "Which of the following most likely lengthens the cash conversion cycle? An increase in:", "options": {"A": "payables turnover.", "B": "inventory turnover.", "C": "receivables turnover."}, "answer": "A", "explanation": "A Correct because the cash conversion cycle = days of inventory on hand + days of sales outstanding – number of days of payables = + − As payables turnover increases, the number of days of payables decrease, increasing the cash conversion cycle.\nB Incorrect because an increase in inventory turnover would decrease the days of inventory on hand which would decrease the cash conversion cycle.\nC Incorrect because an increase in receivables turnover would decrease the days of sales outstanding which would decrease the cash conversion cycle."},
  {"num": 119, "subject": "财务报表", "question": "If the price elasticity of demand for a product is 0.8 and its unit cost remains constant, a 10% increase in its selling price will most likely result in:", "options": {"A": "no change in cost of sales.", "B": "a decrease in volume of 8%.", "C": "an increase in revenue of 8%."}, "answer": "B", "explanation": "A Incorrect because the impact of higher prices on volume depends on the price elasticity of demand (i.e., how the quantity demanded varies with price). Since volumes will decline, cost of goods sold will also decline.\nB Correct because the impact of higher prices on volume depends on the price elasticity of demand (i.e., how the quantity demanded varies with price). Price elasticity of demand gives the impact to volume, and not total revenues, for a given level of price increases. Furthermore, Analyst A expects price elasticity of 0.8, indicating that volume will fall by 8 percent given the 10 percent retail price increase.\nC Incorrect because the impact of higher prices on volume depends on the price elasticity of demand (i.e., how the quantity demanded varies with price). Price elasticity of demand gives the impact to volume, and not total revenues, for a given level of price increases."},
  {"num": 120, "subject": "财务报表", "question": "Porter's five forces analysis, used in conjunction with financial forecasting, can be used to estimate a company's future profit margin relative to:", "options": {"A": "only its competitors.", "B": "only its historic margins.", "C": "both its competitors and its historic margins."}, "answer": "C", "explanation": "A Incorrect because Porter’s five forces framework and similar analytical tools can help analysts assess the relative profit potential of a company by helping analysts estimate whether profit margins are likely to be relatively high or low (relative to historical profit margins and relative to competing companies).\nB Incorrect because Porter’s five forces framework and similar analytical tools can help analysts assess the relative profit potential of a company by helping analysts estimate whether profit margins are likely to be relatively high or low (relative to historical profit margins and relative to competing companies).\nC Correct because Porter’s five forces framework and similar analytical tools can help analysts assess the relative profit potential of a company by helping them understand the company’s industry and its position within that industry. Understanding the industry and competitive contexts of a company helps analysts estimate whether, for example, sales growth is likely to be relatively high or low (relative to history, relative to the overall growth in the economy or a sector, and/or relative to competing companies) and whether profit margins are likely to be relatively high or low (relative to historical profit margins and relative to competing companies)."},
  {"num": 121, "subject": "财务报表", "question": "An analyst uses the following information to forecast a company's gross profit margin:\nThe analyst's forecasted gross profit margin should be closest to a(n):", "options": {"A": "decrease of 1%.", "B": "increase of 1%.", "C": "increase of 4%."}, "answer": "B", "explanation": "A Incorrect because it computes the gross profit margin as cost of sales / sales. Current gross profit margin is 25% (300 / 1,200) and the forecasted gross profit margin is 24.1% (312 / 1,296) a decrease of approximately 1%.\nB Correct because the gross profit for the current year is 900 (=1,200 – 300), therefore the current gross profit margin is 75%. If sales increase by 8% (to 1,296) and cost of sales increase by 4% (to 312), the forecasted gross profit is 984 (= 1,296 – 312), and the forecasted gross profit margin is 75.9%. This is an increase of approximately 1% (= 75.9% – 75%).\nC Incorrect because it assumes the starting values have the same base and takes the difference in the growth rates; 4% = sales growth – cost of sales growth = 8% – 4%."},
  {"num": 122, "subject": "财务报表", "question": "All else being equal, forecasting an increase in which of the following will most likely increase forecasted EPS for a company?", "options": {"A": "Share repurchases", "B": "Secondary stock issuances", "C": "Equity-based compensation of employees"}, "answer": "A", "explanation": "A Correct because share repurchases decrease the number of shares outstanding. A decrease in the number of shares outstanding will raise the EPS all things being equal.\nB Incorrect because a secondary stock issuance increases the number of shares outstanding. An increase in the number of shares outstanding will decrease the EPS all things being equal.\nC Incorrect because an increase in equity-based compensation increases the number of shares outstanding. An increase in the number of shares outstanding will decrease the EPS all things being equal."},
  {"num": 123, "subject": "财务报表", "question": "For a company in a cyclical industry, normalized earnings are best described as:", "options": {"A": "current earnings that include the impact of acquisitions.", "B": "mid-cycle earnings in the absence of temporary factors.", "C": "earnings from the peak years excluding temporary factors."}, "answer": "B", "explanation": "A Incorrect because normalized earnings remove the impact of temporary factors and unusual events such as acquisitions.\nB Correct because normalized earnings are the expected level of mid-cycle earnings for a company in the absence of any unusual or temporary factors that affect profitability.\nC Incorrect because normalized earning are based on mid-cycle earnings, not peak-year earnings."},
  {"num": 124, "subject": "财务报表", "question": "Maintaining prior views or forecasts by inadequately incorporating new information best describes:", "options": {"A": "conservatism bias.", "B": "overconfidence bias.", "C": "representativeness bias."}, "answer": "A", "explanation": "A Correct because conservatism bias is a bias in which people maintain their prior views or forecasts by inadequately incorporating new information.\nB Incorrect because overconfidence bias occurs when people demonstrate unwarranted faith in their own abilities.\nC Incorrect because representative bias refers to the tendency to classify information based on past experiences and known classifications."},
  {"num": 125, "subject": "财务报表", "question": "In the Porter's five forces framework, a company is most likely to have the greatest profitability if:", "options": {"A": "the threat of substitutes is low and the bargaining power of buyers is low.", "B": "the threat of substitutes is low and the bargaining power of buyers is high.", "C": "the threat of substitutes is high and the bargaining power of buyers is low."}, "answer": "A", "explanation": "A Correct because both a low availability of substitutes and low bargaining power of buyers would improve a company's pricing power.\nB Incorrect because a high degree of rivalry would offset the positive effect of a low threat of substitutes.\nC Incorrect because a high availability of substitutes would act to offset the positive effect of low bargaining power of buyers."},
  {"num": 1, "subject": "数量分析", "question": "An individual can invest $19,000 today and receive $20,000 in one year's time. If her required rate of return is 5%, the rate of return on the investment is:", "options": {"A": "less than the required rate of return.", "B": "equal to the required rate of return.", "C": "greater than the required rate of return."}, "answer": "C", "explanation": "A Incorrect because the return on the investment can be calculated as (20,000 – 19,000)/19,000 = 1,000/19,000 = 5.26%. Therefore, it is greater (not less) than the required return of 5%.\nB Incorrect because the return on the investment can be calculated as (20,000 – 19,000)/19,000 = 1,000/19,000 = 5.26%. Therefore, it exceeds (not is equal to) the required return of 5%.\nC Correct because the return on the investment can be calculated as (20,000 – 19,000)/19,000 = 1,000/19,000 = 5.26%. Therefore, it exceeds the required return of 5%."},
  {"num": 2, "subject": "数量分析", "question": "An analyst collects the following set of ten returns from previous years:\nThe geometric mean return is closest to:", "options": {"A": "9.62%.", "B": "10.80%.", "C": "10.89%."}, "answer": "B", "explanation": "A Incorrect because it uses the geometric mean formula, not the geometric mean return formula: = 9.62%\nB Correct because the geometric mean return is calculated as the Tth root of the product of T terms, where the terms are one plus the returns and T is the number of returns. After taking the Tth root, subtract one: where RG = the geometric mean return T = the number of returns Rt = the return in year t RG = = 10.80%\nC Incorrect because it is the arithmetic mean not the geometric mean return:"},
  {"num": 3, "subject": "数量分析", "question": "Over a period of 16 months, an investor has earned a return of 12%. The investor’s annualized return is closest to:", "options": {"A": "8.87%.", "B": "9.00%.", "C": "9.38%."}, "answer": "A", "explanation": "A Correct because the annualized return is calculated using the formula for annualized return, Rannual = (1+Rperiod)c, where: Rperiod = 12% c = 12/16, because one year contains 12/16th of a 16-month period. Plugging in the numbers: Rannual = 1.12(12/16) – 1 = 0.0887 or = 8.87%\nB Incorrect because the return is incorrectly calculated as 12% × 12/16 = 9.00%.\nC Incorrect because the return is incorrectly calculated as (1 + 0.12/16)12 – 1= 1.007512 – 1 = 9.38%."},
  {"num": 4, "subject": "数量分析", "question": "An investor observed the following hedge fund return data.\nThe money-weighted return is closest to:", "options": {"A": "–1.523%.", "B": "–0.749%.", "C": "–0.524%."}, "answer": "C", "explanation": "A Incorrect . It uses cash flows from the difference of new balance at the beginning of year: CF0 = –30, CF1 = –40 + 30 = –10, CF2 = –30 + 40 = +10, CF3 = +28.5; IRR = –1.523%.\nB Incorrect . It uses CF0 = –30, CF1 = –7, CF2 = +8 + 28.5 = +36.5; IRR = –0.749%.\nC Correct . Tabulate the annual returns and the investment amounts to determine the cash flows:"},
  {"num": 5, "subject": "数量分析", "question": "A pension fund needs to pay a lump sum $10,000,000 to its participants in 15 years. If the fund is expected to earn 5% per year compounded semi-annually, the amount needed today to meet its liability in 15 years is closest to:", "options": {"A": "$4,767,427.", "B": "$4,810,171.", "C": "$4,892,771."}, "answer": "A", "explanation": "A Correct because using the equation PV = FVN (1 + rs/m)-Nm where m = number of compounding periods per year rs = quoted annual interest rate N = number of years we compute PV = $10,000,000 × (1 + 0.05/2)–15×2 = $4,767,426.85 ≈ $4,767,427. In applying the equation, we use the periodic rate (in this case, the semi-annual rate) and the appropriate number of periods with semi-annual compounding. Alternative solution using a financial calculator in END mode: N = 30; I/Y = 0.025; PMT = 0; FV = 10,000,000; CPT PV = $4,767,426.852 ≈ $4,767,427\nB Incorrect because when computing present value, it uses 5% instead of EAR to get $10,000,000 × (1.05)–15 = $4,810,170.98 ≈ $4,810,171.\nC Incorrect because in the present value equation, it incorrectly accounts for compounding (multiplies by 2 instead of dividing) and does not use the appropriate number of periods for semi-annual compounding (divides by 2 instead of multiplying by 2); to incorrectly compute PV = 10,000,000 × (1 + 0.05×2)–15/2 = $4,892,770.68 ≈ $4,892,771."},
  {"num": 6, "subject": "数量分析", "question": "A company estimates its revenue will be 50% higher than today in four years' time. The compound annual growth rate is closest to:", "options": {"A": "10.7%.", "B": "11.8%.", "C": "12.5%."}, "answer": "A", "explanation": "A Correct because a growth rate (g) is calculated as g = (FVN/PV)1/N –1, where FV is the future value, PV is the present value and N is the number of periods. Here, g = (1.5/1)1/4 –1 = 0.10668 ≈ 10.7%.\nB Incorrect because it is calculated as ln(1+ 0.5/4)–1 = ln(1.125)–1 = 0.11778 ≈ 11.8%.\nC Incorrect because it is calculated as: 50%/4 = 12.5%."},
  {"num": 7, "subject": "数量分析", "question": "An investor considers the following certificates of deposit (CDs) available for purchase at face value:\nIf each CD has the same maturity and default risk, the opportunity cost of investing in CD 1 is closest to:", "options": {"A": "0.0%.", "B": "1.1%.", "C": "2.2%."}, "answer": "C", "explanation": "A Incorrect because the investor is foregoing higher rates of return by investing in the security with the lowest return.\nB Incorrect because 1.1% is not the most the investor is foregoing; however, it is the difference if incorrectly using the average return of the three securities.\nC Correct because all three securities have the same maturity and default risk so the investor is forgoing 2.2% (4.4% – 2.2%) by investing in CD 1 rather than investing in CD 3."},
  {"num": 8, "subject": "数量分析", "question": "A bank offers a savings account with a stated annual rate of 3% in the first year and 5% in the second year. If returns are compounded quarterly and €90,000 is deposited in the account at the beginning of the first year, the account's value at the end of the second year is closest to:", "options": {"A": "€97,200.", "B": "€97,335.", "C": "€97,455."}, "answer": "C", "explanation": "A Incorrect because it fails to account for any compounding; (3% + 5%) = 8%; 90,000(1.08) = 97,200.\nB Incorrect because it fails to account for quarterly compounding; 90,000(1.03)(1.05) = 97,335.\nC Correct because the returns are compounded quarterly;"},
  {"num": 9, "subject": "数量分析", "question": "An investor is considering two term deposits with the following characteristics:\nThe stated annual rate for Term Deposit 2 that should make the investor indifferent between the two term deposits is closest to:", "options": {"A": "3.92%.", "B": "3.98%.", "C": "4.06%."}, "answer": "B", "explanation": "A Incorrect because it takes the natural logarithm of Term Deposit 1's stated annual rate instead of its effective annual rate (EAR). Calculation: ln(1.04) = 0.039221 = 3.92%.\nB Correct because the investor will be indifferent if the EAR for both term deposits is the same. Therefore, we need to find the stated annual rate with continuous compounding that corresponds to the EAR of the quarterly compounded term deposit. Calculations: EAR of Term Deposit 1 = (1+0.04/4)4–1 = 0.040604. Hence, EAR of Term Deposit 2 = 0.040604 = er–1, leading to a stated annual rate for Term Deposit 2 of r = ln(1.040604) = 0.039801 = 3.98%.\nC Incorrect because it is the EAR of Term Deposit 1, not the stated annual rate of Term Deposit 2. EAR of Term Deposit 1 = (1+0.04/4)4–1 = 0.040604 = 4.06%. This answer is also closest to the calculations e0.04–1=0.040811 = 4.08% or e0.040604–1 = 0.041440 = 4.14%."},
  {"num": 10, "subject": "数量分析", "question": "An analyst gathers the following information about a portfolio:\nIf the equity weighting is 70%, the fixed-income weighting is 30% and the portfolio is rebalanced annually, the portfolio's annual geometric mean return is closest to:", "options": {"A": "0.60%.", "B": "0.83%.", "C": "1.82%."}, "answer": "A", "explanation": "A Correct because the first step is to calculate the portfolio’s annual returns as a weighted mean of the equity and fixed-income returns with 70% equity and 30% fixed-income weighting. Year 1: (0.7 ´ 0.072) + (0.3 ´ 0.021) = 0.0567 = 5.67% Year 2: (0.7 ´ 0.096) + (0.3 ´ –0.046) = 0.0534 = 5.34% Year 3: (0.7 ´ –0.142) + (0.3 ´ 0.047) = –0.0853 = –8.53% Next, the portfolio’s geometric mean annual return is calculated as: [(1 + 0.0567) ´ (1 + 0.0534) ´ (1 – 0.0853)]^(1/3) – 1 = [1.01818]^(1/3) – 1 = 0.00602 » 0.60%.\nB Incorrect because it reflects the incorrect decision to calculate the arithmetic mean return of the portfolio in the second step. Annual portfolio returns: Year 1: (0.7 ´ 0.072) + (0.3 ´ 0.021) = 0.0567 = 5.67% Year 2: (0.7 ´ 0.096) + (0.3 ´ –0.046) = 0.0534 = 5.34% Year 3: (0.7 ´ –0.142) + (0.3 ´ 0.047) = –0.0853 = –8.53% Next, the portfolio’s arithmetic mean annual return is calculated as: (0.0567 + 0.0534 – 0.0853)/3 = 0.00827 » 0.83%.\nC Incorrect because it reflects the error of not applying the cubed root when the three annual returns are linked geometrically in the second step."},
  {"num": 11, "subject": "数量分析", "question": "An investor purchased a stock for $450 and then sold the stock immediately after receiving a dividend of $2. If the holding period return is a loss of 10.2%, the investor sold the stock at a price closest to:", "options": {"A": "$402.", "B": "$404.", "C": "$406."}, "answer": "A", "explanation": "A Correct because a holding period return is the return earned from holding an asset for a single specified period of time. This return can be generalized and shown as a mathematical expression in which P is the price and I is the income: R = [(P1–P0) + I1]/P0. The subscript indicates the time of the price or income, (t=0), is the beginning of the period and (t=1) is the end of the period. Hence, P1 = R×P0 + P0–I1 =–10.2%×$450 + $450−$2 = $402.1 ≈ $402.\nB Incorrect because if the stock was sold for $404, the holding period return would be ($404–$450+$2)/$450 =–9.8%. The incorrect price of $404 ignores the impact of the dividend; holding period return (HPR) = (P1−P0)/P0; P1=HPR×P0+P0 =–10.2%×$450+$450 = $404.1 ≈ $404.\nC Incorrect because if the stock was sold for $406, the holding period return would be ($406–$450+$2)/$450 =–9.3%. The incorrect price of $406 incorrectly subtracts the dividend; holding period return (HPR)"},
  {"num": 12, "subject": "数量分析", "question": "An investor purchases a stock for $100. Immediately after receiving a dividend of $7, the investor sells the stock for $107. The holding period return of the investment is closest to:", "options": {"A": "0%.", "B": "7%.", "C": "14%."}, "answer": "C", "explanation": "A Incorrect because it incorrectly subtracts the dividend instead of adding it, and thus calculates HPR = ($107–$100–$7)/$100 = $0/$100 = 0%. The same result is obtained if the holding period return is calculated as R = ($100–$107+$7)/$107 = $0/$107 = 0%.\nB Incorrect because it omits the dividend and calculates R = ($107–$100)/$100 = $7/$100 = 7%. It is also the ratio of the dividend received over the initial investment; $7/$100 = 7%.\nC Correct because a holding period return is the return earned from holding an asset for a single specified period of time. This return can be generalized and shown as a mathematical expression in which P is the price and I is the income: R = (P1−P0+D1)/P0 Thus, R = ($107–$100+$7)/$100 = $14/$100 = 14%."},
  {"num": 13, "subject": "数量分析", "question": "Which of the following statements is most accurate? The money-weighted return:", "options": {"A": "ignores cash withdrawals and additional cash investments.", "B": "measures what the investor actually earned on the funds invested.", "C": "should be used to compare the performance of different investment managers."}, "answer": "B", "explanation": "A Incorrect because the money-weighted return and its calculation are similar to the internal rate of return and the yield to maturity. Just like the internal rate of return, amounts invested are cash outflows from the investor’s perspective and amounts returned or withdrawn by the investor, or the money that remains at the end of an investment cycle, is a cash inflow for the investor. That is, cash withdrawals and investments are included in the money-weighted return calculation; however, cash withdrawals and investments are ignored in the calculation of the arithmetic and geometric mean returns.\nB Correct because the money-weighted return is an accurate measure of what the investor actually earned on the money invested.\nC Incorrect because although the money-weighted return is an accurate measure of what the investor actually earned on the money invested, it is limited in its applicability to other situations. For example, it does not allow for return comparison between different individuals or different investment opportunities. Two investors in the same mutual fund may have different money-weighted returns because they invested different amounts in different years."},
  {"num": 14, "subject": "数量分析", "question": "Which of the following risk premiums compensates investors for the risk of loss relative to an investment’s fair value if the investment needs to be converted to cash quickly?", "options": {"A": "Liquidity premium", "B": "Inflation premium", "C": "Maturity premium"}, "answer": "A", "explanation": "A Correct because the liquidity premium compensates investors for the risk of loss relative to an investment’s fair value if the investment needs to be converted to cash quickly.\nB Incorrect because the inflation premium compensates investors for expected inflation and reflects the average inflation rate expected over the maturity of the debt.\nC Incorrect because the maturity premium compensates investors for the increased sensitivity of the market value of debt to a change in market interest rates as maturity is extended, in general (holding all else equal)."},
  {"num": 15, "subject": "数量分析", "question": "With respect to portfolio return measures, which of the following statements is most accurate?", "options": {"A": "The time-weighted return is sensitive to additions and withdrawals of funds.", "B": "The calculations of the money-weighted return and internal rate of return are similar.", "C": "The money-weighted return is the preferred measure when evaluating the performance of a portfolio manager."}, "answer": "B", "explanation": "A Incorrect because an investment measure that is not sensitive to the additions and withdrawals of funds is the time-weighted rate of return.\nB Correct because the money-weighted return accounts for the money invested and provides the investor with information on the return she earns on her actual investment. The money-weighted return and its calculation are similar to the internal rate of return and the yield to maturity.\nC Incorrect because, for the evaluation of portfolios of publicly traded securities, the time-weighted rate of return is the preferred performance measure as it neutralizes the effect of cash withdrawals or additions to the portfolio, which are generally outside of the control of the portfolio manager."},
  {"num": 16, "subject": "数量分析", "question": "An investor has three options for receiving payments from an investment:\nOption 1: a single payment of $136,000 today;\nOption 2: 30 annual payments of $12,000, beginning one year from today;\nOption 3: 20 annual payments of $13,000, beginning today.\nIf the annual discount rate is 8%, the option with the highest present value is:", "options": {"A": "Option 1.", "B": "Option 2.", "C": "Option 3."}, "answer": "C", "explanation": "A Incorrect because Option 3 (annuity due with 20 payments of $13,000 each) has the highest present value of $137,847. The PV of Option 1 is $136,000. If a candidate incorrectly calculated the present value of Option 3 as an ordinary annuity, the lump sum of $136,000 would have the highest present value. Incorrect calculator solution for Option 3: End mode; N = 20; I/Y = 8; PMT = –13,000; compute PV = 127,636.\nB Incorrect because Option 3 (annuity due with 20 payments of $13,000 each) has the highest present value of $137,847. The PV of Option 2 is $135,093. If a candidate ignored the discount rate, the option with the 30 payments of $12,000 each would have the highest value. That is, Option 2's 30 payments of $12,000 for a total of $360,000 is larger than Option 3's 20 payments of $13,000 for a total of $260,000 and the lump sum payment of $136,000.\nC Correct because Option 3 (annuity due with 20 payments of $13,000 each) has the highest present value of the annuities and the $136,000 lump sum."},
  {"num": 17, "subject": "数量分析", "question": "An investor needs to make the following payments to cover college tuition fees, starting 10 years from today:\nIf the investor’s annual discount rate is 3%, the minimum investment amount required today to fund all four years of college tuition is closest to:", "options": {"A": "$138,294.", "B": "$142,442.", "C": "$146,716."}, "answer": "B", "explanation": "A Incorrect because the annuity is taken as an ordinary annuity rather than an annuity due, leading to a PV 10 years from today of PV10 =$50,000×[1–1/(1.03)4]/0.03 = $50,000×3.717098 = $185,855. The PV of the annuity today would equal PV0 = $185,855/(1.03)10 = $138,294. Calculator solution: END mode; N = 4; I/Y = 3%; PMT = 50,000; solve for PV = 185,855. Discounted back 10 years: N = 10; I/Y = 3%; FV = 185,855; solve for PV = 138,294. This is also the result if the PV of the annuity due is discounted back 11 years instead of 10 years: $191,431/(1.03)11 = $138,294. Calculator solution: BEGIN mode; N = 4; I/Y = 3%; PMT = 50,000; solve for PV = 191,431. Discounted back 11 years: N = 11; I/Y = 3%; FV = 191,431; solve for PV = 138,294.\nB Correct because the present value (PV) of the annuity due 10 years from today equals PV10 = $50,000+$50,000×[1–1/(1.03)3]/0.03=$50,000+$50,000×2.828611 = $191,431. The PV of the annuity today equals PV0 = $191,431/(1.03)10 = $142,442. Calculator solution: BEGIN mode; N = 4; I/Y = 3%; PMT = 50,000; solve for PV = 191,431. Discounted back 10 years: N = 10; I/Y = 3%; FV = 191,431; solve for PV = 142,442. Alternatively, the annuity can be treated as an ordinary annuity, with a PV 9 years from today of PV9 = $50,000×[1–1/(1.03)4]/0.03=$50,000×3.717098 = $185,855. The PV of the annuity today equals PV0 = $185,855/(1.03)9 = $142,442. Calculator solution: END mode; N = 4; I/Y = 3%; PMT = 50,000; solve for PV = 185,855. Discounted back 9 years: N = 9; I/Y = 3%; FV = 185,855; solve for PV = 142,442.\nC Incorrect because the PV of the annuity due is discounted back 9 years instead of 10 years: $191,431/(1.03)9 = $146,716."},
  {"num": 18, "subject": "数量分析", "question": "An investment requires 10 equal annual payments, starting today, and will pay out a lump sum of $500,000 15 years from today. If the interest rate is 4% per year compounded annually, the required annual payment is closest to:", "options": {"A": "$32,913.", "B": "$34,230.", "C": "$40,044."}, "answer": "A", "explanation": "A Correct because the present value of the future lump sum payment is PV = FVN(1 + r)–N = $500,000(1 + 0.04)-15 = $277,632.25. The 10 annual payments form an annuity due (since the payments start today) whose present value equals the present value of an ordinary annuity with 9 annual payments plus the first payment, i.e. PV = A+A[1–1/(1+r)N]/r = A(1+[1–1/(1+0.04)9]/0.04) = 8.4353(A). Setting the PV of the cash outflows (the annuity) equal to the PV of the cash inflows (the return in 15 years), we can solve for the annual payment amount; A = $277,632.25/8.4353 ≈ $32,913. Calculator solution: BGN; N = 10; I/Y = 4; PV = 277,632.25; solve for PMT = 32,913.\nB Incorrect because it mistakes the required payments as an ordinary annuity, rather than an annuity due, calculating their present value as: PV = A[1–1/(1+r)N]/r = A([1–1/(1+0.04)10]/0.04) = 8.1109(A). The present value of the return at t = 15 is PV = FVN(1+r)–N = $500,000(1+0.04)-15 = $277,632.25. Setting these two values equal and solving for the annual payment thus yields: A = $277,632.25/8.1109 ≈ $34,230. Calculator solution: END; N=10; I/Y = 4; PV = 277,632.25; solve for PMT = 34,230.\nC Incorrect because it assumes the $500,000 return is paid at t = 10 instead of t = 15. The present value of this payment is therefore PV=FVN(1+r)–N= $500,000(1+0.04)-10 = $337,782.08. The 10 annual payments form an annuity due (since the payments start today) whose present value equals the present value of an ordinary annuity with 9 annual payments plus the first payment, i.e. PV = A + A[1–1/(1+r)N]/r = A(1+[1–1/(1+0.04)9]/0.04)=8.4353(A). Setting the PV of the cash outflows (the annuity) equal to the PV of the cash inflows (the return in 15 years), we can solve for the annual payment amount; A=$337,782/8.4353≈$40,044. Calculator solution: BGN; N = 10; I/Y = 4; FV = 500,000; solve for PMT = 40,044."},
  {"num": 19, "subject": "数量分析", "question": "An investment pays $1,000 annually for five years, with the first payment occurring three years from today. If the discount rate is 6% compounded annually, the present value of the investment today is closest to:", "options": {"A": "$3,537.", "B": "$3,749.", "C": "$4,212."}, "answer": "B", "explanation": "A Incorrect because it recognizes the investment as a delayed annuity, but it wrongly assumes that the first annuity payment for an ordinary annuity starts at t = 4 instead of t=3. Thus, it computes the present value of an ordinary annuity at t=3 as PV3 = A[1–1/(1+ r)N] / r = $1,000×[1–1/(1+0.06)5] / 0.06 = $4,212.36. Using the present value formula for a lump sum to bring the single cash flow from t = 3 to t = 0, PV0 = FVN(1+ r)–N = $4,212.36 (1 + 0.06)–3 ;= $3,536.78 ~ $3,537. Calculator solution: (1) END mode; N = 5; I = 6%; PMT = −1,000; FV = 0; solve for PV = 4,212.36. (1) END mode; N = 3; I = 6%; PMT = 0; FV = 4,212.36; solve for PV = 3,536.78 ~ 3,537.\nB Correct because by drawing a time line, the investment is recognized as a delayed annuity with the first payment starting at t = 3. The first step is to compute the present value of an ordinary annuity at t = 2 because the first annuity payment is then one period away, as PV2 = A[1–1/(1+r)N] / r = $1,000×[1–1/(1 + 0.06)5/0.06 = $4,212.36. Using the present value formula for a lump sum to bring the single cash flow from t = 2 to t = 0, PV0 = FVN(1 + r)–N = $4,212.36 (1+0.06)–2 = $3,748.99 ~ $3,749. Calculator solution: (1) END mode; N = 5; I = 6%; PMT = −1,000; FV = 0; solve for PV = 4,212.36. (2) END mode; N = 2; I = 6%; PMT = 0; FV = 4,212.36; solve for PV = 3,748.99 ~ 3,749. A second method to compute the present value of the investment is to recognize it as an annuity due with first payment at t = 3, and then discount back three periods using the present value formula for a lump sum. PV3 ;= {A[1–1/(1+r)N] / r}(1 + r) = $1,000×{[1–1/(1 + 0.06)5]/0.06}×(1 + 0.06) = $4,465.11. Using the present value formula for a lump sum to bring the single cash flow from t = 3 to t = 0, PV0 = FVN(1 + r)–N = $4,465.11 (1 + 0.06)–3 = $3,748.99 ~ $3,749. Calculator solution: (1) BGN mode; N = 5; I = 6%; PMT = −1,000; FV = 0; solve for PV = 4,465.11. (2) END mode; N = 3; I = 6%; PMT = 0; FV = 4,465.11; solve for PV = 3,748.99 ~ 3,749. Another method to compute the correct answer is to calculate the present value of a series of equal cash flows, with the first cash flow in the third year. Using a calculator with CF0=0, CF1=0, CF2=0, CF3=1000, CF4=1000, CF5=1000, CF6=1000, CF7=1000; I=6%; solve for NPV= 3,748.99 ~ 3,749.\nC Incorrect because it is the present value of the investment as t = 2 instead of t = 0, and it is an intermediate step in the correct calculation. It computes present value of an ordinary annuity at t = 3 as PV3 = A[1–1/(1 + r)N] / r = $1,000×[1–1/(1 + 0.06)5 / 0.06 = $4,212.36."},
  {"num": 20, "subject": "数量分析", "question": "A graphical depiction of a continuous distribution shows the left tail to be longer than the right tail. The distribution is best described as having:", "options": {"A": "leptokurtosis.", "B": "positive skewness.", "C": "negative skewness."}, "answer": "C", "explanation": "A Incorrect . Kurtosis refers to relative peakedness of a distribution; leptokurtosis means more peaked than normal.\nB Incorrect . A negatively skewed distribution appears as if the left tail has been pulled away from the mean.\nC Correct . A negatively skewed distribution appears as if the left tail has been pulled away from the mean. The average magnitude of negative deviations from the mean is larger than the average magnitude of positive deviations."},
  {"num": 21, "subject": "数量分析", "question": "An analyst gathers the following sample returns for a security:\nThe mean absolute deviation of the sample returns is:", "options": {"A": "less than the sample standard deviation.", "B": "equal to the sample standard deviation.", "C": "greater than the sample standard deviation."}, "answer": "A", "explanation": "A Correct because the mean absolute deviation of 1.5% is less than the sample standard deviation of 1.83%. The mean absolute deviation, MAD, is calculated as: where the sample mean, As the sample mean is: , the calculation of MAD is: =1.5000%, while the sample standard deviation of no bservations, , is , here: = 1.8257%.\nB Incorrect because the mean absolute deviation, MAD, is less than standard deviation of returns in the sample. The mean absolute deviation, MAD, is calculated as: , where the sample mean, , which results in MAD = 1.50% while sample standard deviation = 1.83% therefore MAD is less than standard deviation of sample returns.\nC Incorrect because the mean absolute deviation, MAD, is less than standard deviation of returns in the sample. The mean absolute deviation, MAD, is calculated as: , where the sample mean, , which results in MAD = 1.50% while sample standard deviation = 1.83% therefore MAD is less than standard deviation of sample returns."},
  {"num": 22, "subject": "数量分析", "question": "An analyst gathers the following returns for seven funds:\nThe second quartile return is:", "options": {"A": "4%.", "B": "5%.", "C": "6%."}, "answer": "B", "explanation": "A Incorrect because it confuses the location of the second quartile, which is calculated as Ly = (7 + 1)×50/100 = 4, with the value of the second quartile, which is the return of the 4th fund after placing the funds' returns in ascending order. 4% also corresponds to the return of the 4th fund (the middle fund) when the array has not been sorted in ascending order, which a candidate might interpret as the 50th percentile (the median).\nB Correct because the formula for the position of a percentile in an array with n entries sorted in ascending order is Ly = ( n+1)×y/100, where y is the percentage point at which we are dividing the distribution and Ly is the location ( L) of the percentile ( Py) in the array sorted in ascending order. With seven entries, the location of the second quartile, or 50th percentile, is: Ly = (7+1)×50/100 = 4. When placing the funds' returns in ascending order (3%; 3%; 4%; 5%; 7%; 8%; 12%), the return of the 4th fund is 5%. Alternatively, candidates might realize that the second quartile or 50th percentile is the median. The median is the value of the middle item of a set of items that has been sorted into ascending or descending order. In an odd-numbered sample of n items, the median occupies the ( n+1)/2 position. Hence, the median return is 5%.\nC Incorrect because the mean is mistaken as the 50th percentile or second quartile; mean return = (12% + 8% + 7% + 5% + 4% + 3% + 3%)/7 = 6%."},
  {"num": 23, "subject": "数量分析", "question": "An analyst observes the following EPS for four companies: –£0.50, £0.50, £2.50, and £5.50. The 50th percentile of the EPS values is closest to:", "options": {"A": "£1.50.", "B": "£2.00.", "C": "£2.50."}, "answer": "A", "explanation": "A Correct because the 50th percentile is the median, which is the average of the two middle items; (£0.50 + £2.50)/2 = £1.50. In an odd-numbered sample of n items, the median occupies the (n + 1)/2 position. In an even-numbered sample, we define the median as the mean of the values of items occupying the n/2 and (n + 2)/2 positions (the two middle items). Calculating the median may also be more complex; to do so, we need to order the observations from smallest to largest, determine whether the sample size is even or odd and, on that basis, apply one of two calculations. Alternatively, the 50th percentile when Ly is not a whole number or integer, Ly lies between the two closest integer numbers (one above and one below), and we use linear interpolation between those two places to determine Py. That is, Ly = (n + 1)(y/100) = (4 + 1)(50/100) = 2.5. Hence, 2 is the closest integer below the calculated location and 3 is the closest integer above the calculated location. Using linear interpolation, P50 = £0.50 + (£2.50–£0.50)×(2.5–2) = £1.50.\nB Incorrect because it is the location of the median; n/2 = 4/2. Alternatively, it is also the average EPS; (–£0.50 + £0.50 + £2.50 + £5.50)/4 = £2.00.\nC Incorrect because it is the position (or location) of the 50th percentile instead of the 50th percentile: (4 + 1)×50/100 = 2.5. The formula for the position (or location) of a percentile in an array with n entries sorted in ascending order is Ly = (n + 1)(y/100) where y is the percentage point at which we are dividing the distribution and Ly is the location (L) of the percentile (Py) in the array sorted in ascending order. The value of Ly may or may not be a whole number. When Ly is not a whole number or integer, Ly lies between the two closest integer numbers (one above and one below), and we use linear interpolation between those two places to determine Py."},
  {"num": 24, "subject": "数量分析", "question": "An analyst calculates the following statistics for a sample with 100 observations:\nThe interquartile range of the sample is equal to:", "options": {"A": "31.", "B": "82.", "C": "348."}, "answer": "B", "explanation": "A Incorrect because it is the difference between the third quartile and the second quartile, Q3−Q2 = 93−62 = 31. The interquartile range (IQR) is the difference between the third quartile and the first quartile.\nB Correct because the interquartile range (IQR) is the difference between the third quartile and the first quartile, or IQR = Q3 − Q1 = 93–11 = 82. Quartiles divide the distribution into quarters.\nC Incorrect because it is the range of the four numbers given, and not the interquartile range. Q4 − Q1 = 359−11 = 348."},
  {"num": 25, "subject": "数量分析", "question": "Which of the following measures best quantifies the amount of risk per unit of mean return?", "options": {"A": "Sharpe ratio.", "B": "Standard deviation.", "C": "Coefficient of variation."}, "answer": "C", "explanation": "A Incorrect because the Sharpe ratio is the average return in excess of the risk-free rate divided by the standard deviation of returns. This ratio measures the excess return earned per unit of standard deviation of return. Therefore, the Sharpe ratio does not quantify the amount of risk per unit of mean return.\nB Incorrect because the standard deviation measures risk, but it does not quantify the amount of risk per unit of mean return. Variance is defined as the average of the squared deviations around the mean. Standard deviation is the positive square root of the variance.\nC Correct because the coefficient of variation, CV, is the ratio of the standard deviation of a set of observations to their mean value. When the observations are returns, for example, the coefficient of variation measures the amount of risk (standard deviation) per unit of mean return."},
  {"num": 26, "subject": "数量分析", "question": "An analyst discards the lowest 2.5% and the highest 2.5% of values in a sample, and computes the mean of the remaining 95% of values. The resulting mean is best described as a:", "options": {"A": "trimmed mean.", "B": "harmonic mean.", "C": "winsorized mean."}, "answer": "A", "explanation": "A Correct because the trimmed mean is computed by excluding a stated small percentage of the lowest and highest values and then computing an arithmetic mean of the remaining values. For example, a 5% trimmed mean discards the lowest 2.5% and the highest 2.5% of values and computes the mean of the remaining 95% of values.\nB Incorrect because the harmonic mean is the value obtained by summing the reciprocals of the observations—terms of the form 1/Xi—then averaging that sum by dividing it by the number of observations n, and, finally, taking the reciprocal of the average. The harmonic mean may be viewed as a special type of weighted mean in which an observation's weight is inversely proportional to its magnitude. The harmonic mean does not exclude or replace any outliers.\nC Incorrect because the winsorized mean is calculated by assigning a stated percentage of the lowest values equal to one specified low value and a stated percentage of the highest values equal to one specified high value, and then it computes a mean from the restated data. For example, a 95% winsorized mean sets the bottom 2.5% of values equal to the value at or below which 2.5% of all the values lie (as will be seen shortly, this is called the '2.5th percentile' value) and the top 2.5% of values equal to the value at or below which 97.5% of all the values lie (the '97.5th percentile' value)."},
  {"num": 27, "subject": "数量分析", "question": "Ranked in ascending order, the 19th observation in a sample of 75 is in the second:", "options": {"A": "decile.", "B": "quintile.", "C": "quartile."}, "answer": "B", "explanation": "A Incorrect because the second decile includes observations that are above the 10th percentile and at or below the 20th percentile. The 19th observation is in the second group of ten observations, but it is not in the second decile because there are only 75 observations in the sample.\nB Correct because the 19th observation is located at the 25th percentile; Ly=(1+n)(); 19=(1+75)(); y=()=25.0, which is in the second quintile. The second quintile includes observations that are above the 20th percentile and at or below the 40th percentile.\nC Incorrect because the second quartile includes observations that are above the 25th percentile and at or below the 50th percentile. Because the 19th observation is at the 25th percentile, it is in the first quartile."},
  {"num": 28, "subject": "数量分析", "question": "If a unimodal return distribution is negatively skewed, which of the following most likely has the highest value?", "options": {"A": "Mean.", "B": "Mode.", "C": "Median."}, "answer": "B", "explanation": "A Incorrect because the mode, not the mean, is the measure with the highest value for a continuous negatively skewed unimodal distribution.\nB Correct because for the continuous negatively skewed unimodal distribution, the mean is less than the median, which is less than the mode. Therefore, the mode has the highest value.\nC Incorrect because the mode, not the median, is the measure with the highest value for a continuous negatively skewed unimodal distribution."},
  {"num": 29, "subject": "数量分析", "question": "For a continuous positively skewed unimodal distribution:", "options": {"A": "both the mode and the median are less than the mean.", "B": "both the mode and the median are greater than the mean.", "C": "the mode is less than the mean and the median is greater than the mean."}, "answer": "A", "explanation": "A Correct because for a continuous positively skewed unimodal distribution, the mode is less than the median, which is less than the mean.\nB Incorrect because for a continuous positively skewed unimodal distribution, the mode is less than the median, which is less than the mean. For the continuous negatively skewed unimodal distribution, the mean is less than the median, which is less than the mode.\nC Incorrect because for a continuous positively skewed unimodal distribution, the mode is less than the median, which is less than the mean."},
  {"num": 30, "subject": "数量分析", "question": "A portfolio has a mean return of 1.0% and a standard deviation of returns of 2.7%. If the specified minimum target return is 1.0%, the sample target semideviation is:", "options": {"A": "less than 2.7%.", "B": "equal to 2.7%.", "C": "greater than 2.7%."}, "answer": "A", "explanation": "A Correct because the target downside deviation =[Σ(Xi–B)2/(n–1)]0.5, where Xi are the periodic returns below the target return, B is the target return, and n is the total number of periods. Since the sample has a standard deviation of 2.7%, it will have values below and above its mean of 1.0%. Since the target downside deviation ignores the deviations above the mean, it will be less than the standard deviation.\nB Incorrect because the target downside deviation = [Σ(Xi–B)2/(n–1)]0.5, where Xi are the periodic returns below the target return, B is the target return, and n is the total number of periods. Since the sample has a standard deviation of 2.7%, it will have values below and above its mean of 1.0%. Since the target downside deviation ignores the deviations above the mean, it will be less than the standard deviation.\nC Incorrect because the target downside deviation = [Σ(Xi–B)2/(n–1)]0.5, where Xi are the periodic returns below the target return, B is the target return, and n is the total number of periods. Since the sample has a standard deviation of 2.7%, it will have values below and above its mean of 1.0%. Since the target downside deviation ignores the deviations above the mean, it will be less than the standard deviation."},
  {"num": 31, "subject": "数量分析", "question": "The correlation between two variables measures:", "options": {"A": "only their linear relationship.", "B": "only their non-linear relationship.", "C": "both their linear and non-linear relationships."}, "answer": "A", "explanation": "A Correct because the correlation coefficient is a measure of the linear association between two variables; it would not be appropriate to use the correlation coefficient to measure the non-linear relationship between variables.\nB Incorrect because the correlation coefficient is a measure of the linear association between two variables. It does not measure non-linear relationships between variables.\nC Incorrect because the correlation coefficient is a measure of the linear association between two variables. It does not measure non-linear relationships between variables."},
  {"num": 32, "subject": "数量分析", "question": "A portfolio has the following annual returns over five years:\nIf the portfolio manager has a target annual return of 6%, the portfolio's target downside deviation is closest to:", "options": {"A": "12%.", "B": "13%.", "C": "15%."}, "answer": "C", "explanation": "A Incorrect because it does not subtract the target return from the annual return. Observations for years 1, 3, and 5 are below the target; [((–23%)2 + (3%)2 + (–1%)2 )/4]½ = [(529%2 + 9%2 + 1%2)/4]½ = (539%2/4)½ = (134.75%2)½ = 11.61% ≈ 12%.\nB Incorrect because it uses the correct formula but instead of dividing by n – 1, the sum of squared negative deviations from the target is divided by n. Observations for years 1, 3, and 5 are below the target. Thus, target downside deviation = [((–23%–6%)2 + (3%–6%)2 + (–1%–6%)2)/4]½ = [((–29%)2 + (–3%)2 + (–7%)2)/5]½ = [(841%2 + 9%2 + 49%2)/5]½ = (899%2/5)½ = (179.8%2)½ = 13.41% ≈ 13%.\nC Correct because the target downside deviation, also referred to as the target semideviation, is a measure of dispersion of the observations (here, returns) below the target. To calculate a sample target semideviation, we first specify the target. After identifying observations below the target, we find the sum of the squared negative deviations from the target, divide that sum by the total number of observations in the sample minus 1, and, finally, take the square root."},
  {"num": 33, "subject": "数量分析", "question": "The coefficient of variation of a portfolio's monthly returns is best defined as the ratio of the:", "options": {"A": "standard deviation of the portfolio's returns to the mean return.", "B": "mean excess portfolio return to the standard deviation of returns.", "C": "standard deviation of the portfolio's returns to the mean excess return."}, "answer": "A", "explanation": "A Correct because the coefficient of variation is the ratio of the standard deviation of a set of observations to their mean value.\nB Incorrect because it defines the Sharpe ratio, not the coefficient of variation. The Sharpe ratio measures the reward, in terms of mean excess return, per unit of risk, as measured by standard deviation of return.\nC Incorrect because it is the inverse of the Sharpe ratio, not the coefficient of variation. The Sharpe ratio measures the reward, in terms of mean excess return, per unit of risk, as measured by standard deviation of return. The numerator of the Sharpe measure is the portfolio’s mean return minus the mean return on the risk-free asset over the sample period. We call this difference the mean excess return on a portfolio."},
  {"num": 34, "subject": "数量分析", "question": "A discrete random variable X has the following probability distribution:\nThe standard deviation of X is closest to:", "options": {"A": "18.73.", "B": "20.00.", "C": "22.91."}, "answer": "A", "explanation": "A Correct because the expected value E(X) =Xi = (0.20×35) + (0.30×50) + (0.50×80) = 62. The variance σ2(X) =E{[X–E(X)]2} =[X–E(X)]2 = 0.20×(35–62)2 + 0.30×(50–62)2 + 0.50×(80–62)2 = 351. Standard deviation is the positive square root of variance:σ= 3511/2 ≈ 18.73.\nB Incorrect because it uses the simple average of the outcomes instead of the expected value in the calculation. The simple average Xbar = (35+50+80)/3 = 55. Hence the variance becomes σ2(X) = [X–Xbar]2 = 0.20×(35–55)2 + 0.30×(50–55)2 + 0.50×(80–55)2 = 400. Then, the standard deviation is equal to σ= 4001/2 = 20.00.\nC Incorrect because it ignores that this is a random variable and just calculates the sample standard deviation instead for a sample with 3 observations. The sample mean Xbar = (35+50+80)/3 = 55. Hence the sample variance is equal toσ2 = ()/(n–1) = [(35–55)2 + (50–55)2 + (80–55)2]/(3–1) = 525. Then, the sample standard deviation is equal to σ= 5251/2 ≈ 22.91."},
  {"num": 35, "subject": "数量分析", "question": "An analyst assumes that a company's future EPS will be either $2.00, $2.20, or $2.40. If each scenario is equally likely, the variance [in $2] of the company's future EPS is closest to:", "options": {"A": "0.03.", "B": "0.16.", "C": "0.20."}, "answer": "A", "explanation": "A Correct because the variance of a random variable is the expected value (the probability-weighted average) of squared deviations from the random variable's expected value: σ2(X) = E[X–E(X)]2. Since each scenario is equally likely (probability = 1/3), E(X) = (2.0 + 2.2 + 2.4)/3 = 2.2, so σ2(X) = [(2.0–2.2)2 + (2.2–2.2)2 + (2.4–2.2)2]/3 = [0.04 + 0.04]/3 = 0.08/3 = 0.0267 ≈ 0.03 [in $2].\nB Incorrect because it is the standard deviation, not the variance. The variance of a random variable is the expected value (the probability-weighted average) of squared deviations from the random variable’s expected value: σ2(X) = E[X–E(X)]2. Since each scenario is equally likely (probability = 1/3), E(X) = (2.0 + 2.2 + 2.4)/3 = 2.2, so σ2(X) = [(2.0–2.2)2 + (2.2–2.2)2 + (2.4–2.2)2]/3 = [0.04 + 0.04]/3 = 0.08/3 = 0.0267 [in $2]. Standard deviation is the positive square root of variance. Therefore, σ(X) = (0.0267)0.5 = 0.1633 ≈ 0.16 [in $].\nC Incorrect because it is the difference between each pair of EPS values, not the variance: $2.40–$2.20 = $2.20–$2.00 = $0.20."},
  {"num": 36, "subject": "数量分析", "question": "A tree diagram contains the following information about the dividend per share payable by a company under two scenarios:\nThe expected dividend per share under the favorable scenario is closest to:", "options": {"A": "$1.14.", "B": "$1.37.", "C": "$1.90."}, "answer": "C", "explanation": "A Incorrect because it wrongly multiplies the expected dividend per share given the favorable scenario ($1.90) by the probability of the scenario (0.60): Probability of favorable scenario×E(Dividend | Favorable scenario) = 0.60×[(0.80×$2.00) + (0.20×$1.50)] = 0.60×$1.90 = $1.14.\nB Incorrect because it is the unconditional expected dividend per share based on the total probability rule for expected value: E(Dividend | Favorable scenario) = (0.80×$2.00) + (0.20×$1.50) = $1.90. E(Dividend | Unfavorable scenario) = (0.30×$0.75) + (0.70×$0.50) = $0.575. E(Dividend) = (0.60×$1.90) + (0.40×$0.575) = $1.37.\nC Correct because the expected value of a random variable X given an event or scenario S is denoted E(X | S). Suppose the random variable X can take on any one of n distinct outcomes X1, X2, …, Xn (these outcomes form a set of mutually exclusive and exhaustive events). The expected value of X conditional on S is the first outcome, X1, times the probability of the first outcome given S, P(X1 | S), plus the second outcome, X2, times the probability of the second outcome given S, P(X2 | S), and so forth. In our case, S = Favorable scenario, X1 = Dividend of $2.50, X2 = Dividend of $1.50, P(X1 | S) = 0.80, and P(X2 | S) = 0.20. Thus, the expected dividend given the favorable scenario = (0.80×$2.00) + (0.20×$1.50) = $1.90."},
  {"num": 37, "subject": "数量分析", "question": "An analyst examines the distribution of portfolio returns in bullish and bearish market scenarios. To calculate the expected return on the portfolio in a bearish market scenario, the most appropriate approach is to use:", "options": {"A": "the multiplication rule.", "B": "conditional expected values.", "C": "the total probability rule for expected value."}, "answer": "B", "explanation": "A Incorrect because the multiplication rule is the probability rule where the joint probability of A and B can be expressed as P(AB) = P(A | B)P(B).\nB Correct because in investments, we make use of any relevant information available in making our forecasts. When we refine our expectations or forecasts, we are typically making adjustments based on new information or events; in these cases, we are using conditional expected values.\nC Incorrect because parallel to the total probability rule for stating unconditional probabilities in terms of conditional probabilities, there is a principle for stating (unconditional) expected values in terms of conditional expected values. This principle is the total probability rule for expected value. Considering just one scenario (bearish market), the total probability rule for expected value would not be used."},
  {"num": 38, "subject": "数量分析", "question": "A portfolio manager considers the following joint probability function:\nThe covariance (in % squared) between the returns on the foreign portfolio and the foreign currency is closest to:", "options": {"A": "294.", "B": "378.", "C": "819."}, "answer": "B", "explanation": "A Incorrect because the variance of the foreign portfolio return is calculated as follows: Expected return on the foreign portfolio = 0.6(–10%) + 0.4(25%) = 4%. Variance of foreign portfolio return = 0.6(–10% – 4%)2 + 0.4(25% – 4%)2 = 294 (% squared).\nB Correct because the covariance is 378 and calculated as follows: Expected return on the foreign portfolio = 0.6(–10%) + 0.4(25%) = 4%. Expected return on the foreign currency = 0.6(–15%) + 0.4(30%) = 3%. Covariance = 0.6(–10% – 4%)(–15% – 3%) + 0.4(25% – 4%)(30% – 3%) = 378 (% squared).\nC Incorrect because the covariance is calculated without weighting the products of the deviations with the probabilities, as follows:"},
  {"num": 39, "subject": "数量分析", "question": "If a portfolio's safety-first ratio and coefficient of variation both equal 1.2, the portfolio's return threshold is:", "options": {"A": "negative.", "B": "zero.", "C": "positive."}, "answer": "A", "explanation": "A Correct because the safety-first ratio is: [E(RP) – RL]/σP, where RP is the portfolio return, RL is the return threshold (shortfall level), and σP is the portfolio standard deviation. The coefficient of variation (CV) is: σP/E(RP). When this ratio is greater than 1.0, risk is greater than return. With a CV greater than 1.0 (i.e., σP > RP), the only way for the SFRatio to be greater than 1.0 is if the shortfall level is negative.\nB Incorrect because the safety-first ratio is: [E(RP) – RL] / σP, where RP is the portfolio return, RL is the return threshold (shortfall level), and σP is the portfolio standard deviation. The coefficient of variation (CV) is: σP / RP. When this ratio is greater than 1.0, risk is greater than return. With a CV greater than 1.0 (i.e., σP > RP), the only way for the SFRatio to be greater than 1.0 is if the shortfall level is negative.\nC Incorrect because the safety-first ratio is: [E(RP) – RL] / σP, where RP is the portfolio return, RL is the return threshold (shortfall level), and σP is the portfolio standard deviation. The coefficient of variation (CV) is: σP / RP. When this ratio is greater than 1.0, risk is greater than return. With a CV greater than 1.0 (i.e., σP > RP), the only way for the SFRatio to be greater than 1.0 is if the shortfall level is negative."},
  {"num": 40, "subject": "数量分析", "question": "An analyst estimates the following correlation matrix of two securities' returns:\nIf the standard deviation of returns of each security is 9%, the covariance (in units of % squared) between the two securities is closest to:", "options": {"A": "20.3.", "B": "40.5.", "C": "61.7."}, "answer": "B", "explanation": "A Incorrect because it uses the wrong correlation value of 1; 0.5 × 0.5 × 9^2 = 20.25.\nB Correct because the covariance is Cov (R1, R2) = ρ(R1, R2) σ(R1)σ(R2) = (0.5)(9)(9) = 40.5.\nC Incorrect because it uses the correlation formula;"},
  {"num": 41, "subject": "数量分析", "question": "If the returns of two assets exhibit perfect positive correlation, the two-asset portfolio's standard deviation of returns is:", "options": {"A": "less than the weighted average standard deviation.", "B": "equal to the weighted average standard deviation.", "C": "greater than the weighted average standard deviation."}, "answer": "B", "explanation": "A Incorrect because when assets are perfectly positively correlated, no diversification benefit exists. Therefore, the portfolio standard deviation will not be less than the weighted average standard deviation.\nB Correct because correlation is a number between –1 and +1 for two random variables. Increasingly positive correlation indicates an increasingly strong positive linear relationship (up to 1, which indicates a perfect linear relationship). Thus, a perfectly positive linear relationship indicates correlation of 1.0. As long as security returns are not perfectly positively correlated, diversification benefits are possible. Since correlation equals 1.0, diversification benefits cannot be obtained and the portfolio standard deviation formula simplifies to a weighted average.\nC Incorrect because the portfolio standard deviation can never be greater than the weighted average standard deviation. This is a result of correlation having an upper limit of 1.0."},
  {"num": 42, "subject": "数量分析", "question": "Bootstrap resampling:", "options": {"A": "repeatedly draws samples without replacement.", "B": "can be used to estimate the standard error of a population median.", "C": "relies on an analytical formula to estimate the distribution of estimators."}, "answer": "B", "explanation": "A Incorrect because unlike bootstrap, which repeatedly draws samples with replacement, jackknife samples are selected by taking the original observed data sample and leaving out one observation at a time from the set (and not replacing it).\nB Correct because bootstrap, one of the most popular resampling methods, can be used to find the standard error or construct confidence intervals for the statistic of other population parameters, such as the median.\nC Incorrect because compared with conventional statistical methods, bootstrap does not rely on an analytical formula to estimate the distribution of the estimators."},
  {"num": 43, "subject": "数量分析", "question": "A random variable Y = exp(X) is lognormally distributed, where X is normally distributed. The distribution of Y:", "options": {"A": "is skewed to the left.", "B": "is often used to model stock prices.", "C": "has a mean equal to exp(µ), where µ is the mean of X."}, "answer": "B", "explanation": "A Incorrect because the lognormal distribution is skewed to the right, not the left.\nB Correct because the lognormal distribution has been found to be a usefully accurate description of the distribution of prices for many financial assets, which includes stocks.\nC Incorrect because, where μ and σ2 are the mean and variance of the associated normal distribution (i.e., the distribution of X), the mean (μL) of a lognormal random variable = exp(μ + 0.50σ2), not exp(µ)."},
  {"num": 44, "subject": "数量分析", "question": "The lognormal distribution is:", "options": {"A": "negatively skewed.", "B": "bounded below by zero.", "C": "widely used for modeling the probability distribution of asset returns."}, "answer": "B", "explanation": "A Incorrect because the two most noteworthy observations about the lognormal distribution are that it is bounded below by 0 and it is skewed to the right (it has a long right tail). The continuous positively skewed distribution has a long tail on its right side; the continuous negatively skewed distribution has a long tail on its left side.\nB Correct because the two most noteworthy observations about the lognormal distribution are that it is bounded below by 0 and it is skewed to the right (it has a long right tail).\nC Incorrect because the lognormal distribution is widely used for modeling the probability distribution of share and other asset prices, but not the returns. The lognormal distribution is bounded below by 0. Asset prices are bounded from below by 0. In practice, the lognormal distribution has been found to be a usefully accurate description of the distribution of prices for many financial assets. On the other hand, the normal distribution is often a good approximation for returns. Since asset returns can be negative, the lognormal distribution cannot be used for modeling asset returns."},
  {"num": 45, "subject": "数量分析", "question": "Both the normal distribution and the lognormal distribution:", "options": {"A": "are symmetrical.", "B": "are completely described by two parameters.", "C": "have a range of possible outcomes that includes all real numbers between −∞ and +∞."}, "answer": "B", "explanation": "A Incorrect because the lognormal distribution is skewed to the right. The normal distribution is symmetrical. Therefore, only the normal distribution is symmetrical.\nB Correct because like the normal distribution, the lognormal distribution is completely described by two parameters.\nC Incorrect because the lognormal distribution is bounded below by 0 whereas the range of possible outcomes of the normal distribution is the entire real line: all real numbers lying between −∞ and +∞."},
  {"num": 46, "subject": "数量分析", "question": "A researcher wants to measure the level of consumer confidence in a country by interviewing a simple random sample of ten consumers from three randomly selected cities. This method is an example of:", "options": {"A": "cluster sampling.", "B": "systematic sampling.", "C": "stratified random sampling."}, "answer": "A", "explanation": "A Correct because cluster sampling requires the division or classification of the population into subpopulation groups, called clusters. In this method, the population is divided into clusters, each of which is essentially a mini-representation of the entire populations. Then certain clusters are chosen as a whole using simple random sampling. If a subsample is randomly selected from each selected cluster, then the plan is referred as two-stage cluster sampling. In this case, each city represents a cluster, from which a sample of ten consumers is randomly selected, i.e. the researcher uses a two-stage cluster sampling.\nB Incorrect because with systematic sampling, we select every kth member until we have a sample of the desired size. Systematic sampling does not involve the division or classification of the population into subpopulation groups.\nC Incorrect because a major difference between cluster and stratified random samples is that in cluster sampling, a whole cluster is regarded as a sampling unit and only sampled clusters are included. In stratified random sampling, however, all the strata are included and only specific elements within each stratum are then selected as sampling unit. Also, in stratified random sampling, the population is divided into subpopulations (strata) based on one or more classification criteria. Simple random samples are then drawn from each stratum in sizes proportional to the relative size of each stratum in the population. This would have been a stratified random sampling if the researcher randomly selected consumers from each city based on the size of each city relative to the whole population."},
  {"num": 47, "subject": "数量分析", "question": "The central limit theorem is best described as stating that the sampling distribution of the sample mean will be approximately normal for large-size samples:", "options": {"A": "if the population distribution is normal.", "B": "if the population distribution is symmetrical.", "C": "for populations described by any probability distribution."}, "answer": "C", "explanation": "A Incorrect because the central limit theorem holds without regard for the distribution of the underlying population.\nB Incorrect because the central limit theorem holds without regard for the distribution of the underlying population.\nC Correct because the central limit theorem holds without regard for the distribution of the underlying population."},
  {"num": 48, "subject": "数量分析", "question": "An analyst gathered the following information about a stock index:\nIf the analyst takes a sample of 36 companies from the index, the standard error of the sample mean is closest to:", "options": {"A": "$88,889.", "B": "$400,000.", "C": "$533,333."}, "answer": "C", "explanation": "A Incorrect because it uses the following formula: $3,200,000/36 = $88,889.\nB Incorrect because it uses the following formula:\nC Correct because the standard error of the sample mean is equal to the population standard deviation (σ) divided by the square root of the number of observations in the sample (n):"},
  {"num": 49, "subject": "数量分析", "question": "An analyst studying the Sharpe ratios of mutual funds globally uses only the data from the standard internal database, which covers 12 mutual funds. This sampling method is best described as:", "options": {"A": "cluster sampling.", "B": "judgmental sampling.", "C": "convenience sampling."}, "answer": "C", "explanation": "A Incorrect because cluster sampling requires the division or classification of the population into subpopulation groups, called clusters. In this method, the population is divided into clusters, each of which is essentially a mini-representation of the entire populations. Then certain clusters are chosen as a whole using simple random sampling. However, in this situation, the analyst uses all the data from the database, without dividing them into clusters, which best describes convenience sampling, not cluster sampling.\nB Incorrect because this sampling process (judgmental sampling) involves selectively handpicking elements from the population based on a researcher’s knowledge and professional judgment. In circumstances where there is a time constraint, however, or when the specialty of researchers is critical to select a more representative sample than by using other probability or non-probability sampling methods, judgmental sampling allows researchers to go directly to the target population of interest. However, in this situation, the analyst uses all the data from the database, without selecting elements based on her knowledge, which best describes convenience sampling, not judgmental sampling.\nC Correct because in this method (convenience sampling), an element is selected from the population based on whether or not it is accessible to a researcher or on how easy it is for a researcher to access the element. Because the samples are selected conveniently, they are not necessarily representative of the entire population, and hence the level of the sampling accuracy could be limited. By choosing to use all the data from an internal database, the analyst is using convenience sampling."},
  {"num": 50, "subject": "数量分析", "question": "The sampling distribution of a statistic must be constructed from samples that are:", "options": {"A": "large.", "B": "of the same size.", "C": "from the same stratum."}, "answer": "B", "explanation": "A Incorrect because the sampling distribution of a statistic is the distribution of all the distinct possible values that the statistic can assume when computed from samples of the same size randomly drawn from the same population. Although the central limit theorem does require a large sample, the question is asking for the definition of a sampling distribution. The central limit theorem allows us to make quite precise probability statements about the population mean by using the sample mean, whatever the distribution of the population (so long as it has finite variance), because the sample mean follows an approximate normal distribution for large-size samples.\nB Correct because the sampling distribution of a statistic is the distribution of all the distinct possible values that the statistic can assume when computed from samples of the same size randomly drawn from the same population.\nC Incorrect because the sampling distribution of a statistic is the distribution of all the distinct possible values that the statistic can assume when computed from samples of the same size randomly drawn from the same population. In stratified random sampling, the population is divided into subpopulations (strata) based on one or more classification criteria. Drawing the sample 'from the same stratum' is not consistent with drawing the sample 'from the same population.' Further, a sampling distribution also requires the samples to be of the same size."},
  {"num": 51, "subject": "数量分析", "question": "A population has a lognormal distribution with a standard deviation of 50. Samples with a size of 100 are drawn from the population. The sampling distribution of the sample mean is most likely:", "options": {"A": "skewed to the right with a standard deviation of 50.", "B": "approximately symmetric with a standard deviation of 5.", "C": "approximately symmetric with a standard deviation of 0.5."}, "answer": "B", "explanation": "A Incorrect because the population distribution is skewed to the right, not the sampling distribution of the sample mean. The lognormal distribution is skewed to the right (it has a long right tail). The central limit theorem applies since the sample size is large (n = 100); therefore, the sampling distribution of the sample mean is approximately normal, or symmetric, not skewed to the right.\nB Correct because, according to the central limit theorem, given a population described by any probability distribution having mean µ and finite variance σ2, the sampling distribution of the sample mean X computed from samples of size n from this population will be approximately normal with mean µ (the population mean) and variance σ2/n (the population variance divided by n) when the sample size n is large. Since the sample size is large (n = 100), the sampling distribution of the sample mean is approximately normal, or symmetric, with a mean of 100 and standard deviation of 50/(100)1/2 = 5.\nC Incorrect because the sampling distribution of the sample mean has a standard deviation of σ/(n)1/2, not σ/n (50/100 = 0.5). According to the central limit theorem, given a population described by any probability distribution having mean µ and finite variance σ2, the sampling distribution of the sample mean X computed from samples of size n from this population will be approximately normal with mean µ (the population mean) and variance σ2/n (the population variance divided by n) when the sample size n is large. Since the sample size is large (n = 100), the sampling distribution of the sample mean is approximately normal, or symmetric, with a mean of 100 and standard deviation of 50/(100)1/2 = 5."},
  {"num": 52, "subject": "数量分析", "question": "When testing a hypothesis, the power of a test is best described as the:", "options": {"A": "same as the level of significance of the test.", "B": "probability of rejecting a true null hypothesis.", "C": "probability of correctly rejecting the null hypothesis."}, "answer": "C", "explanation": "A Incorrect because this is the definition of Type I error.\nB Incorrect because this is in fact a Type I error.\nC Correct because the power of a test is the probability of correctly rejecting the null hypothesis—that is, the probability of rejecting the null when it is false."},
  {"num": 53, "subject": "数量分析", "question": "A nonparametric test is most appropriate when:", "options": {"A": "comparing differences between means.", "B": "data are given in ranks.", "C": "data meet distributional assumptions."}, "answer": "B", "explanation": "A Incorrect . Tests related to differences between means concern a parameter. Nonparametric tests are used when the data do not concern a parameter or the data do not meet distributional assumptions.\nB Correct . A nonparametric test is used under three circumstances: 1. when the data do not meet distributional assumptions, 2. when the data are given in ranks, and 3. when the hypothesis does not concern a parameter.\nC Incorrect . When the data meet distributional assumptions, a parametric test is used instead of a nonparametric test."},
  {"num": 54, "subject": "数量分析", "question": "An analyst wants to test the mean difference between two normally distributed populations using dependent samples. If the population variances are unknown, the most appropriate hypothesis test is a:", "options": {"A": "chi-square test.", "B": "paired comparisons t-test.", "C": "t-test with a pooled estimator of the common variance."}, "answer": "B", "explanation": "A Incorrect because in tests concerning the variance of a single normally distributed population, we make use of a chi-square test statistic, denoted χ2.\nB Correct because when we want to conduct tests on two means based on samples that we believe are dependent, these methods apply. The t-test is based on data arranged in paired observations, and the test itself is sometimes called a paired comparisons test.\nC Incorrect because when it is reasonable to believe that the samples are from populations at least approximately normally distributed and that the samples are also independent of each other, these techniques apply. We discuss two t-tests for a test concerning differences between the means of two populations. The test of the difference between two population means, with population variances unknown but assumed equal, uses a pooled estimator of the common variance."},
  {"num": 55, "subject": "数量分析", "question": "Which of the following test statistics is used when testing the variance of a single normally distributed population?", "options": {"A": "z-statistic", "B": "F-statistic", "C": "Chi-square statistic"}, "answer": "C", "explanation": "A Incorrect because the z-statistic is used for tests of a population's mean when the variance is known. The z-statistic is not appropriate for tests concerning the variance of a single normally distributed population.\nB Incorrect because tests concerning the difference between the variances of two [normally distributed] populations make use of the F-distribution. The F-statistic is not appropriate for tests concerning a single population variance.\nC Correct because in tests concerning the variance of a single normally distributed population, we make use of a chi-square test statistic."},
  {"num": 56, "subject": "数量分析", "question": "All else being equal, if an analyst specifies a smaller significance level for a hypothesis test, the probability of a Type II error:", "options": {"A": "decreases.", "B": "remains the same.", "C": "increases."}, "answer": "C", "explanation": "A Incorrect because all else equal, if we decrease the probability of a Type I error by specifying a smaller significance level (say, 1% rather than 5%), we increase the probability of making a Type II error because we will reject the null less frequently, including when it is false. A Type II error occurs when we fail to reject a false null hypothesis.\nB Incorrect because all else equal, if we decrease the probability of a Type I error by specifying a smaller significance level (say, 1% rather than 5%), we increase the probability of making a Type II error because we will reject the null less frequently, including when it is false. A Type II error occurs when we fail to reject a false null hypothesis.\nC Correct because all else equal, if we decrease the probability of a Type I error by specifying a smaller significance level (say, 1% rather than 5%), we increase the probability of making a Type II error because we will reject the null less frequently, including when it is false. A Type II error occurs when we fail to reject a false null hypothesis."},
  {"num": 57, "subject": "数量分析", "question": "An analyst gathers the following information about a random sample of salaries:\nTo test the hypothesis that the mean salary of the underlying population is greater than $11,000, the appropriate test statistic is closest to:", "options": {"A": "1.8.", "B": "14.0.", "C": "21.3."}, "answer": "B", "explanation": "A Incorrect because it confuses the standard error (of the sample mean) with the sample standard deviation, i.e. it does not divide s by √n in the correct calculation; ($32,000 – $11,000)/$12,000 = $21,000/$12,000 = 1.75 ≈ 1.8.\nB Correct because the population variance is not given and so must be assumed to be unknown. Also, the sample size of 64 can be considered large. In general, a sample size of 30 or more usually can be treated as a large sample and a sample size of 29 or less is treated as a small sample. In this case, the test statistic for hypothesis tests concerning a single population mean, µ, is tn – 1 = (X – µ0)/(s/√n), where tn – 1 = t-statistic with n – 1 degrees of freedom (n is the sample size), X = the sample mean, µ0 = the hypothesized value of the population mean, s = the sample standard deviation. Thus, the appropriate test statistic to test if the mean salary is greater than $11,000 is t63 = ($32,000 – $11,000)/($12,000/√64) = $21,000/$1,500 = 14.0.\nC Incorrect because it does not subtract the hypothesized mean (µ0) from the sample mean (X) in the correct calculation; $32,000/($12,000/√64) = $32,000/$1,500 = 21.33 ≈ 21.3."},
  {"num": 58, "subject": "数量分析", "question": "Which of the following is best referred to as a nonparametric hypothesis test concerning correlation? A test using the:", "options": {"A": "Pearson correlation coefficient", "B": "bivariate correlation coefficient", "C": "Spearman rank correlation coefficient"}, "answer": "C", "explanation": "A Incorrect because the parametric pairwise correlation coefficient is often referred to as the Pearson correlation, the bivariate correlation, or simply the correlation, and thus the test using the Pearson correlation coefficient is a parametric test.\nB Incorrect because the parametric pairwise correlation coefficient is often referred to as the Pearson correlation, the bivariate correlation, or simply the correlation, and thus the test using the bivariate correlation coefficient is a parametric test.\nC Correct because when we believe that the population under consideration meaningfully departs from normality, we can use a test based on the Spearman rank correlation coefficient. The Spearman rank correlation coefficient is essentially equivalent to the usual correlation coefficient but is calculated on the ranks of the two variables within their respective samples, and thus it is a nonparametric test."},
  {"num": 59, "subject": "数量分析", "question": "An analyst tabulates the ranks of four paired observations of random variables X and Y as follows:\nThe Spearman rank correlation coefficient between X and Y is closest to:", "options": {"A": "–0.2.", "B": "0.8.", "C": "1.0."}, "answer": "A", "explanation": "A Correct because with n as the sample size, the Spearman rank correlation is given by: rs = 1 – (6 ∑di2)/(n(n2 – 1)) = 1 – 6(12)/(4(42 – 1)) = 1 – 6/5 = –1/5 = –0.2, where the sum of squared differences in ranks ∑di2 = (2 – 1)2 + (3 – 2)2 + (4 – 3)2 + (1 – 4)2 = 1 + 1 + 1 + 9 = 12.\nB Incorrect because this answer is calculated by erroneously omitting the multiple (of the sum of squared deviations) of 6, giving a rank correlation of 1 – 1/5 = 4/5 = 0.8.\nC Incorrect because instead of using the sum of squared differences in ranks, this answer erroneously uses the sum of unsquared differences in ranks (which, by definition, sums to zero), giving a rank correlation of 1."},
  {"num": 60, "subject": "数量分析", "question": "An analyst builds a contingency table of stocks with two classifications: market capitalization (small, medium, large) and beta (high, medium, low). To test the relationship between size and beta using a test of independence, the number of degrees of freedom for the chi-square test statistic is:", "options": {"A": "4.", "B": "6.", "C": "9."}, "answer": "A", "explanation": "A Correct because for a contingency table the independence test statistic has (r − 1)(c − 1) degrees of freedom, where r is the number of rows and c is the number of columns. For the contingency table in the stem, there are 3 rows and 3 columns as each classification has 3 groups. Hence, the number of degrees of freedom is equal to (r − 1)(c − 1) = (3 − 1)(3 − 1) = 4.\nB Incorrect because it wrongly assumes the number of degrees of freedom for the test of independence equals the sum of the number of groups in each classification: 3 + 3 = 6.\nC Incorrect because it wrongly assumes the number of degrees of freedom for the test of independence equals the product of the number of groups in each classification (= rc). For the contingency table in the stem, there are 3 rows and 3 columns as each classification has 3 groups. Hence, the number of degrees of freedom is incorrectly calculated as rc = 3 × 3 = 9."},
  {"num": 61, "subject": "数量分析", "question": "For a hypothesis test concerning the correlation between two normally distributed variables with sample size n each, the number of degrees of freedom is:", "options": {"A": "n – 2.", "B": "n – 1.", "C": "2n – 2."}, "answer": "A", "explanation": "A Correct because if the two variables are normally distributed, we can test to determine whether the null hypothesis (H0: ρ = 0) should be rejected. This test statistic is t-distributed with n − 2 degrees of freedom, where ρ represents the population correlation coefficient.\nB Incorrect because if the two variables are normally distributed, we can test to determine whether the null hypothesis (H0: ρ = 0) should be rejected. This test statistic is t-distributed with n − 2 degrees of freedom.\nC Incorrect because if the two variables are normally distributed, we can test to determine whether the null hypothesis (H0: ρ = 0) should be rejected. This test statistic is t-distributed with n − 2 degrees of freedom."},
  {"num": 62, "subject": "数量分析", "question": "In a parametric test of the correlation between two variables with a sample size of 51 and sample correlation of 0.6, the t-statistic is closest to:", "options": {"A": "0.07.", "B": "5.25.", "C": "6.64."}, "answer": "B", "explanation": "A Incorrect because this is the result if the positions of √(1 – r2) and √(n – 2) are swapped, i.e. the formula used is r√(1 – r2) / √(n – 2) = (0.6)√(1 – 0.36) / √(51 – 2) = (0.6)(0.8)/7 = 0.06857 ≈ 0.07.\nB Correct because for a Parametric Test of a Correlation if the two variables are normally distributed, we can test to determine whether the null hypothesis (H0: ρ = 0) should be rejected using the sample correlation, r. The formula for the t-test is r√(n – 2) / √(1 – r2) = (0.6)√(51 – 2) / √(1 – 0.36) = (0.6)(7)/0.8 = 5.25.\nC Incorrect because this is the result if the r in the denominator is not squared, i.e."},
  {"num": 63, "subject": "数量分析", "question": "Which of the following is an underlying assumption of the simple linear regression model? The regression residuals:", "options": {"A": "are normally distributed.", "B": "have high correlations across observations.", "C": "have different variances across observations."}, "answer": "A", "explanation": "A Correct because we need to make the following four key assumptions to be able to draw valid conclusions from a simple linear regression model. One of those assumptions is that regression residuals are normally distributed.\nB Incorrect because one of the four underlying assumptions for simple linear regression is Independence: The observations, pairs of Ys and Xs, are independent of one another. This implies the regression residuals are uncorrelated [and do not have high correlation] across observations.\nC Incorrect because one of the four underlying assumptions for simple linear regression is Homoskedasticity: The variance of the regression residuals is the same [and not different] for all observations."},
  {"num": 64, "subject": "数量分析", "question": "An analyst runs a simple linear regression to test whether the variation in the demand for corn explains the variation in the supply of wheat. In this model, the supply of wheat is a(n):", "options": {"A": "indicator variable.", "B": "explained variable.", "C": "independent variable."}, "answer": "B", "explanation": "A Incorrect because variation in the supply of wheat is a dependent variable not limited to values of 0 or 1. Suppose we want to examine whether a company's quarterly earnings announcements influence its monthly stock returns. In this case, we could use an indicator variable, or dummy variable, that takes on only the values 0 or 1 as the independent variable.\nB Correct because variation in the demand for corn is being used to explain the variation in the supply of wheat. Therefore the variation in the supply of wheat is the dependent variable, or explained variable. We refer to the variable whose variation is being explained as the dependent variable, or the explained variable; it is typically denoted by Y.\nC Incorrect because the variation in the demand for corn is being used to explain the variation in the supply of wheat. Therefore the variation in the demand for corn is the independent variable. We refer to the variable whose variation is being used to explain the variation of the dependent variable as the independent variable, or the explanatory variable; it is typically denoted by X."},
  {"num": 65, "subject": "数量分析", "question": "All else being equal, which of the following would most likely lead to a wider prediction interval for the dependent variable when re-estimating a linear regression model? An increase in the:", "options": {"A": "sample size.", "B": "level of significance.", "C": "standard error of the estimate."}, "answer": "C", "explanation": "A Incorrect because the prediction interval is equal to the predicted value of the dependent variable plus/minus the critical t-value times the standard error of the forecast. The larger the sample size (n) in the regression estimation, the smaller the standard error of the forecast. Meanwhile, when the sample size is larger, the critical t-value will be smaller. Both will lead to a narrower prediction interval if holding other things constant.\nB Incorrect because the prediction interval is equal to the predicted value of the dependent variable plus/minus the critical t-value times the standard error of the forecast. When the level of significance increases, the critical t-value will decrease, which will lead to a narrower prediction interval if holding other things constant.\nC Correct because the prediction interval is equal to the predicted value of the dependent variable plus/minus the critical t-value times the standard error of the forecast. The better the fit of the regression model, the smaller the standard error of the estimate (se) and, therefore, the smaller standard error of the forecast. When the standard error of the estimate increases, the standard error of the forecast will increase, which will lead to a wider prediction interval if holding other things constant."},
  {"num": 66, "subject": "数量分析", "question": "An analyst performs a simple linear regression of a stock's monthly return on the monthly return of a market index (both in %) and gathers the following information:\nThe 95% prediction interval for the stock's monthly return, given that the forecasted monthly return on the index is 3.5%, is closest to:", "options": {"A": "0.7% to 6.3%.", "B": "1.9% to 7.5%.", "C": "3.3% to 6.1%."}, "answer": "B", "explanation": "A Incorrect because it uses the forecasted value of the independent variable to construct the prediction interval rather than the predicted value of the dependent variable. In other words, it assumes that the interval is given by Xf±tcritical for α/2sf: 3.5%±2.032×1.4% ≈ (0.7%, 6.3%).\nB Correct because a forecasted value of the dependent variable, Yf, is determined using the estimated intercept and slope, as well as the expected or forecasted independent variable, Xf: Yf = b0 + b1Xf, where b0 and b1 are the estimated intercept and slope coefficients, respectively. Hence, Yf = 1.2% + 1.0×3.5% = 4.7%. Next, the prediction interval is Yf±tcritical for α/2sf, where sf denotes the standard error of the forecast. Hence, the prediction interval is given by: 4.7%±1.4%×2.032 ≈ (1.9%, 7.5%).\nC Incorrect because it neglects the critical t-values when constructing the prediction interval. In other words, it assumes that the interval is given by Yf±sf: 4.7%±1.4% = (3.3%, 6.1%)."},
  {"num": 67, "subject": "数量分析", "question": "In simple linear regression analysis, the total sum of squares best describes:", "options": {"A": "a scatter plot.", "B": "the variation of the dependent variable.", "C": "a paired observation between variables."}, "answer": "B", "explanation": "A Incorrect because a scatter plot (or scattergram) represents the two variables in two dimensions. The variation of Y (the dependent variable) is often referred to as the sum of squares total (SST), or the total sum of squares.\nB Correct because the variation of Y (the dependent variable) is often referred to as the sum of squares total (SST), or the total sum of squares.\nC Incorrect because Y (the dependent variable) is often referred to as the sum of squares total (SST), or the total sum of squares."},
  {"num": 68, "subject": "数量分析", "question": "The simple linear regression model in which only the independent variable is in logarithmic form is best described as the:", "options": {"A": "log-lin model.", "B": "lin-log model.", "C": "log-log model."}, "answer": "B", "explanation": "A Incorrect because in the log-lin model, the dependent variable is in logarithmic form and the independent variable is not.\nB Correct because the lin-log model is similar to the log-lin model, but only the independent variable is in logarithmic form.\nC Incorrect because the log-log model is one in which both the dependent variable and the independent variable are linear in their logarithmic forms. In the lin-log model only the independent variable is in logarithmic form."},
  {"num": 69, "subject": "数量分析", "question": "The null hypothesis for the F-distributed test statistic in a simple linear regression model tests whether the:", "options": {"A": "slope is equal to zero.", "B": "intercept is equal to zero.", "C": "slope is not equal to zero."}, "answer": "A", "explanation": "A Correct because in regression analysis, we can use an F-distributed test statistic to test whether the slopes in a regression are equal to zero, with the slopes designated as bi, against the alternative hypothesis that at least one slope is not equal to zero for simple linear regression, these hypotheses simplify to H0: b1 = 0. Ha: b1 ≠ 0.\nB Incorrect because in regression analysis, we can use an F-distributed test statistic to test whether the slopes in a regression are equal to zero, with the slopes designated as bi, against the alternative hypothesis that at least one slope is not equal to zero for simple linear regression, these hypotheses simplify to H0: b1 = 0. Ha: b1 ≠ 0.\nC Incorrect because in regression analysis, we can use an F-distributed test statistic to test whether the slopes in a regression are equal to zero, with the slopes designated as bi, against the alternative hypothesis that at least one slope is not equal to zero for simple linear regression, these hypotheses simplify to H0: b1 = 0. Ha: b1 ≠ 0."},
  {"num": 70, "subject": "数量分析", "question": "Which of the following best describes when a transformation of the data may be needed to enable the use of a simple linear regression model? When the:", "options": {"A": "dependent variable is non-normally distributed.", "B": "pairs of the dependent and independent variables are uncorrelated with one another.", "C": "relationship between the independent variable and the dependent variable is non-linear."}, "answer": "C", "explanation": "A Incorrect because the assumption of normality requires that the residuals be normally distributed. This does not mean that the dependent and independent variables must be normally distributed.\nB Incorrect because for simple linear regression we assume that the observations (Y and X pairs) are uncorrelated with one another, meaning they are independent. If there is correlation between observations (that is, autocorrelation), they are not independent and the residuals will be correlated. As the pairs are uncorrelated, a transformation is not needed because independence (uncorrelated pairs of observations) is an assumption of simple linear regression.\nC Correct because if the relationship between the independent variable and the dependent variable is not linear, we can often transform one or both of these variables to convert this relation to a linear form, which then allows the use of simple linear regression."},
  {"num": 71, "subject": "数量分析", "question": "With respect to simple linear regression, a residual is best described as the difference between the observed value of a dependent variable and:", "options": {"A": "its mean.", "B": "its estimated value using a fitted regression line based on the sample.", "C": "its expected value based on the true underlying population relationship."}, "answer": "B", "explanation": "A Incorrect because we look at the sum of squared deviations of the observations from the mean to capture [the variation of the dependent variable]. Our goal is to understand what explains the variation of Y. The variation of Y is often referred to as the sum of squares total (SST), or the total sum of squares. Therefore, the difference between an observation and the mean of the dependent variable is not the observation's residual.\nB Correct because the residual for the ith observation, ei, is how much the observed value of Yi differs from the estimated [value] using the regression line. Further, the residual refers to the fitted linear relation based on the sample.\nC Incorrect because the error term refers to the true underlying population relationship, whereas the residual refers to the fitted linear relation based on the sample. Further, the error term, or simply the error, represents the difference between the observed value of Y and that expected from the true underlying population relation between Y and X."},
  {"num": 72, "subject": "数量分析", "question": "An analyst estimates the following information from a simple linear regression:\nThe standard error of the estimate is closest to:", "options": {"A": "2.5.", "B": "3.2.", "C": "10.0."}, "answer": "B", "explanation": "A Incorrect because it is the F-statistic calculated as MSR / MSE; 25 / 10 = 2.5. For a simple linear regression, the F-Statistic is MSR divided by MSE, where the mean square regression (MSR) is the same as the sum of squares regression (SSR) and the mean square error (MSE) is calculated as the sum of squares error (SSE) adjusted by its degrees of freedom, SSE / (n–2); 280 / (30–2) = 10.\nB Correct because it is the standard error of the estimate calculated as the square root of the mean square error; (10)0.5 = 3.2. The mean square error (MSE) is calculated as SSE / (n–2); 280 / (30–2) = 10.0, where SSE is the sum of squares error.\nC Incorrect because it is the mean square error (MSE) calculated as SSE / (n–2), where SSE is the sum of squares error; 280 / (30–2) = 10.0."},
  {"num": 73, "subject": "数量分析", "question": "The standard error of the estimate in a simple linear regression is best described as:", "options": {"A": "a relative measure of fit for the regression.", "B": "the percentage of the variation of the dependent variable that is explained by the independent variable.", "C": "a measure of the distance between the observed values of the dependent variable and those predicted from the estimated regression."}, "answer": "C", "explanation": "A Incorrect because unlike the coefficient of determination and the F-statistic, which are relative measures of fit, the standard error of the estimate is an absolute measure of the distance of the observed dependent variable from the regression line.\nB Incorrect because it is the coefficient of determination, and not the standard error of estimate. The coefficient of determination, also referred to as the R-squared or R2, is the percentage of the variation of the dependent variable that is explained by the independent variable.\nC Correct because the standard error of the estimate is a measure of the distance between the observed values of the dependent variable and those predicted from the estimated regression."},
  {"num": 74, "subject": "数量分析", "question": "Which of the following is most likely used to detect sentiment shifts in an analyst's commentary?", "options": {"A": "Tokenization.", "B": "Data curation.", "C": "Natural language processing."}, "answer": "C", "explanation": "A Incorrect because tokenization is the process of representing ownership rights to physical assets on a blockchain or distributed ledger. It is not able to detect shifts in an analyst's sentiment.\nB Incorrect because data curation refers to the process of ensuring data quality and accuracy through a data cleaning exercise. This process consists of reviewing all data to detect and uncover data errors—bad or inaccurate data—and making adjustments for missing data when appropriate. While the data used for natural language processing may need to be curated, it is not, in of itself, able to detect shifts in an analyst's sentiment.\nC Correct because NLP [natural language processing] may be used to monitor analyst commentary to aid investment decision making. Since analysts tend not to change their buy, hold, and sell recommendations for a company frequently, they may instead offer nuanced commentary without making a change in their investment recommendation. NLP can, therefore, be used to detect, monitor, and tag shifts in sentiment, potentially ahead of an analyst's recommendation change."},
  {"num": 75, "subject": "数量分析", "question": "The failure of machine learning models to accurately predict outcomes can be the result of:", "options": {"A": "overfitting, but not underfitting.", "B": "underfitting, but not overfitting.", "C": "either overfitting or underfitting."}, "answer": "C", "explanation": "A Incorrect because underfitting also results in this problem. Underfitted models will typically fail to fully discover patterns that underlie the data and thus may not be able to accurately predict outcomes. ML involves splitting the dataset into three distinct subsets: a training dataset, a validation dataset, and a test dataset. Once an algorithm has been trained, validated, and tested, the ML model can be used to predict outcomes based on other datasets. ML models also require sufficiently large amounts of data and may not perform well where there may not be enough available data to train and validate the model.\nB Incorrect because overfitting also results in this problem. An ML model that has been overfitted is not able to accurately predict outcomes using a different dataset and may be too complex.\nC Correct because an ML model that has been overfitted is not able to accurately predict outcomes using a different dataset and may be too complex. Also, underfitted models will typically fail to fully discover patterns that underlie the data and thus may not be able to accurately predict outcomes."},
  {"num": 76, "subject": "数量分析", "question": "In its broadest sense, fintech is best described as:", "options": {"A": "the vast amount of data being generated by the financial services industry.", "B": "the execution of investment strategies through computer-generated algorithms.", "C": "technological innovation in the design and delivery of financial services and products."}, "answer": "C", "explanation": "A Incorrect because the term Big Data has been in use since the late 1990s and refers to the vast amount of data being generated by industry, governments, individuals, and electronic devices. The term fintech is much broader.\nB Incorrect because automated trading, not fintech, refers to executing investment decisions through computer algorithms or automated trading applications. The term fintech is much broader.\nC Correct because in its broadest sense, the term 'fintech' generally refers to technology-driven innovation occurring in the financial services industry. For the purposes of this reading, fintech refers to technological innovation in the design and delivery of financial services and products. Note, however, that in common usage, fintech can also refer to companies (often new, startup companies) involved in developing the new technologies and their applications, as well as the business sector that comprises such companies."},
  {"num": 77, "subject": "数量分析", "question": "With respect to Big Data, which of the following is most likely classified as alternative data?", "options": {"A": "Email communication data.", "B": "Corporate regulatory filings.", "C": "Data from derivative markets."}, "answer": "A", "explanation": "A Correct because Big Data includes data generated from traditional sources—such as stock exchanges, companies, and governments—as well as non-traditional data types, also known as alternative data, arising from the use of electronic device. As the internet and the presence of such networked devices have grown, the use of non-traditional data sources, or alternative data sources—including social media (posts, tweets, and blogs), email and text communications and other electronic information sources—has risen.\nB Incorrect because Big Data includes data generated from traditional sources—such as stock exchanges, companies, and governments—as well as non-traditional data types, also known as alternative data, arising from the use of electronic devices. Traditional data sources include corporate data in the form of regulatory filings.\nC Incorrect becausee Big Data includes data generated from traditional sources—such as stock exchanges, companies, and governments—as well as non-traditional data types, also known as alternative data, arising from the use of electronic devices. Traditional data sources include corporate data in the form of regulatory filings."},
  {"num": 78, "subject": "数量分析", "question": "Which of the following is the most recent advancement in fintech? Applications that can:", "options": {"A": "process data", "B": "automate tasks", "C": "make decisions"}, "answer": "C", "explanation": "A Incorrect because early forms of fintech included data processing and the automation of routine tasks. Fintech has since advanced into decision-making applications based on complex machine-learning logic, where computer programs are able to 'learn' how to complete tasks over time. Thus, it was earlier forms of fintech that included data processing, not advanced forms of fintech.\nB Incorrect because early forms of fintech included data processing and the automation of routine tasks. Fintech has since advanced into decision-making applications based on complex machine-learning logic, where computer programs are able to 'learn' how to complete tasks over time. Thus, it was earlier forms of fintech that included data processing, not advanced forms of fintech.\nC Correct because early forms of fintech included data processing and the automation of routine tasks. Fintech has since advanced into decision-making applications based on complex machine-learning logic, where computer programs are able to 'learn' how to complete tasks over time. Thus, advanced forms of fintech include applications that are capable of decision-making."},
  {"num": 1, "subject": "公司发行人", "question": "Owners have limited liability in a:", "options": {"A": "corporation.", "B": "sole proprietorship.", "C": "general partnership."}, "answer": "A", "explanation": "A Correct because owners in a corporation have limited liability.\nB Incorrect because in a sole proprietorship the owner has unlimited liability and retains all risk associated with the business, meaning she can be held financially responsible for all debt the business owes.\nC Incorrect because a general partnership has two or more owners called partners and all profits, losses, and risks of the business are collectively assumed and shared by the partners. If one partner is unable to pay their share of the business’s debts, the remaining partners are fully liable. Partners in a general partnership have unlimited liability."},
  {"num": 2, "subject": "公司发行人", "question": "Compared to those of public companies, share issuances of private companies most likely:", "options": {"A": "raise larger amounts of capital.", "B": "include a larger number of investors.", "C": "include investors with longer holding periods."}, "answer": "C", "explanation": "A Incorrect because private companies usually raise less cash compared to public companies. In contrast, private companies finance much smaller amounts in the primary market (private debt or equity) with far fewer investors who have much longer holding periods.\nB Incorrect because the number of investors that participate in offerings of private companies is lower. In contrast, private companies finance much smaller amounts in the primary market (private debt or equity) with far fewer investors who have much longer holding periods.\nC Correct because to raise more capital after listing, public companies may issue additional shares in the capital markets, typically raising very large amounts from many investors who may then actively trade shares among themselves in the secondary market. In contrast, private companies finance much smaller amounts in the primary market (private debt or equity) with far fewer investors who have much longer holding periods."},
  {"num": 3, "subject": "公司发行人", "question": "Double taxation of profits is most likely a concern for owners in:", "options": {"A": "corporations.", "B": "limited partnerships.", "C": "general partnerships."}, "answer": "A", "explanation": "A Correct because tax disadvantage for owners in countries with double taxation is a key feature of corporations. In most countries, corporations are taxed directly on their profits. In many countries, shareholders pay an additional tax on distributions (dividends) that are passed on to them. Economists refer to this as the double taxation of corporate profits.\nB Incorrect because profits of limited partnerships are taxed only at the personal level. A key feature of limited partnerships is that all partners share in return, with profits taxed as personal income.\nC Incorrect because profits of general partnerships are taxed only at the personal level. A key feature of general partnerships is that all partners share all return, with profits taxed as personal income."},
  {"num": 4, "subject": "公司发行人", "question": "In a limited partnership, business operations are the responsibility of:", "options": {"A": "the general partner only.", "B": "the limited partners only.", "C": "both the general partner and the limited partners."}, "answer": "A", "explanation": "A Correct because key features of limited partnerships include: • GP operates the business, having unlimited liability, • LPs have limited liability but lack control over business operations.\nB Incorrect because key features of limited partnerships include: • GP operates the business, having unlimited liability, • LPs have limited liability but lack control over business operations.\nC Incorrect because key features of limited partnerships include: • GP operates the business, having unlimited liability, • LPs have limited liability but lack control over business operations."},
  {"num": 5, "subject": "公司发行人", "question": "Compared to private corporations, which of the following is a typical characteristic of public corporations?", "options": {"A": "A government is a shareholder", "B": "Shares are listed on a stock exchange", "C": "Transfer of ownership between investors is more difficult"}, "answer": "B", "explanation": "A Incorrect because the word 'public' can be misleading because it typically implies government involvement. However, when it comes to corporations, 'public' and 'private' are typically defined by whether the company’s equity is listed on a stock exchange.\nB Correct because when it comes to corporations, 'public' and 'private' are typically defined by whether the company’s equity is listed on a stock exchange, although in some countries whether a company is considered public or not may depend on its number of shareholders, irrespective of whether it is listed.\nC Incorrect because these are private company shares do not trade on an exchange, so no visible valuation or price transparency exists for the company and shares are not easily bought and sold. This makes ownership transfers between seller and buyer much more difficult than for a public company."},
  {"num": 6, "subject": "公司发行人", "question": "The purchase of which of the following shares most likely requires investors to be accredited?", "options": {"A": "Public company shares only", "B": "Private company shares only", "C": "Both public company shares and private company shares"}, "answer": "B", "explanation": "A Incorrect because private company investors may be limited to qualified or so-called accredited investors or sophisticated investors, or those deemed to be able and willing by regulatory authorities to assume the greater risk of a non-public offering.\nB Correct because private company investors may be limited to qualified or so-called accredited investors or sophisticated investors, or those deemed to be able and willing by regulatory authorities to assume the greater risk of a non-public offering.\nC Incorrect because private company investors may be limited to qualified or so-called accredited investors or sophisticated investors, or those deemed to be able and willing by regulatory authorities to assume the greater risk of a non-public offering."},
  {"num": 7, "subject": "公司发行人", "question": "Which of the following statements about corporations is most accurate?", "options": {"A": "Upside return potential is unlimited for both equity holders and debtholders", "B": "Equity is riskier than debt from the perspective of both investors and issuers", "C": "Losses for both equity holders and debtholders are limited to their initial investment"}, "answer": "C", "explanation": "A Incorrect because upside return potential is capped for debtholders while it is unlimited for equity holders. If the corporation is successful, there is theoretically no limit to how much equity owners could make from their investment. No matter how profitable the company becomes, however, bondholders will never receive more than their interest and principal repayment.\nB Incorrect because from issuers' perspective debt is riskier than equity while the opposite is true for the investors. From an investor’s perspective, stocks are riskier than bonds because shareholders are residual claimants on the firm. From the issuer’s perspective, bonds are riskier than stocks for the same reason bonds are safer than stocks for investors. Bonds increase risk to the corporation by increasing leverage. If the company is struggling and cannot meet its promised obligations to bondholders, bondholders have the legal standing to force certain actions upon the corporation, such as bankruptcy and liquidation.\nC Correct because shareholder losses are limited to their initial investment. For both equity holders and debtholders, their initial investment represents their maximum possible loss."},
  {"num": 8, "subject": "公司发行人", "question": "Which of the following is most accurate?", "options": {"A": "Risk appetites are similar among private lenders", "B": "Staggered boards provide continuous implementation of strategy and oversight", "C": "A company's CEO is responsible for implementing the company’s strategy under the oversight of the company's shareholders"}, "answer": "B", "explanation": "A Incorrect because private debtholders have wide variation in risk appetites. With banks and private lenders, the general perspective of debtholders applies: less financial leverage implies less risk and is therefore preferred. Among private lenders, however, there is wide variation in their risk appetite, approach, behavior, and relationships with companies to whom they have provided capital.\nB Correct because the positive aspect of a staggered board is that it provides continuous implementation of strategy and oversight without constantly being reassessed by new board members, which otherwise risks bringing short-termism into company strategy.\nC Incorrect because a company's CEO is hired by the board and responsible for implementing the company’s strategy under the oversight of the board of directors. Managers, led by the chief executive officer of the company, are responsible for determining and implementing the corporation’s strategy under the oversight of the board of directors. In addition, a company’s board of directors is elected by shareholders to protect shareholders’ interests and provide strategic direction, taking into consideration the company’s risk appetite, which it defines for the company. The board is also responsible for hiring the CEO and monitoring the performance of the company and management."},
  {"num": 9, "subject": "公司发行人", "question": "A corporation's stakeholders most likely include:", "options": {"A": "shareholders only.", "B": "controlling shareholders only.", "C": "all shareholders and all employees."}, "answer": "C", "explanation": "A Incorrect because the primary stakeholder groups of a corporation consist of shareholders, creditors, managers (or executives), other employees, board of directors, customers, suppliers, and governments/regulators (and, by extension, affected individuals and community groups). Additionally, in some companies, a particular shareholder or block of shareholders may hold a percentage of shares that gives them sufficient voting power to control the election of the board of directors and to influence the approval or blockage of a company resolution; these shareholders are known as controlling shareholders. In contrast, non-controlling shareholders (minority shareholders) hold a much smaller proportion of a company’s outstanding shares, resulting in a more limited ability to exercise control in voting activities. Controlling and minority shareholders are stakeholders, and the only stakeholders who own shares. The full group of stakeholders is more inclusive.\nB Incorrect because the primary stakeholder groups of a corporation consist of shareholders, creditors, managers (or executives), other employees, board of directors, customers, suppliers, and governments/regulators (and, by extension, affected individuals and community groups). Additionally, in some companies, a particular shareholder or block of shareholders may hold a percentage of shares that gives them sufficient voting power to control the election of the board of directors and to influence the approval or blockage of a company resolution; these shareholders are known as controlling shareholders. In contrast, non-controlling shareholders (minority shareholders) hold a much smaller proportion of a company’s outstanding shares, resulting in a more limited ability to exercise control in voting activities. Controlling and minority shareholders are stakeholders, and the only stakeholders who own shares. The full group of stakeholders is more inclusive.\nC Correct because the primary stakeholder groups of a corporation consist of shareholders, creditors, managers (or executives), other employees, board of directors, customers, suppliers, and governments/regulators (and, by extension, affected individuals and community groups)."},
  {"num": 10, "subject": "公司发行人", "question": "Which of the following company stakeholders is most likely exposed to the greatest information asymmetry when compared to the company's management?", "options": {"A": "A bank lender", "B": "A public debtholder", "C": "A member of the board"}, "answer": "B", "explanation": "A Incorrect because banks and private lenders generally hold a company’s debt to maturity. They typically have direct access to company management and non-public information about the company; in principle, this reduces information asymmetries that exist between the company and these groups.\nB Correct because public debtholders do not have access to non-public information. Public debtholders (or bondholders) rely on public information and credit rating agency determinations to make their investment decisions. Unlike shareholders, debtholders do not hold voting power, and they typically have limited influence over a company’s day-to-day operations.\nC Incorrect because a member of the board of directors has significant influence and access to non-public information. A company’s board of directors is elected by shareholders to protect shareholders’ interests and provide strategic direction, taking into consideration the company’s risk appetite, which it defines for the company. The board is also responsible for hiring the CEO and monitoring the performance of the company and management."},
  {"num": 11, "subject": "公司发行人", "question": "With respect to ESG implementation, which of the following is most likely a social factor?", "options": {"A": "Board composition", "B": "Pollution prevention", "C": "Management of human capital"}, "answer": "C", "explanation": "A Incorrect because governance factors have long been recognized in investment analysis. Many performance indicators can help evaluate risks arising from governance issues such as ownership structure, board independence and composition. Thus, board composition is a matter of governance and not a social factor considered in ESG implementation.\nB Incorrect because environmental factors that are generally considered material in investment analysis include natural resource management and/or pollution prevention Thus, pollution prevention is an environmental consideration and not a social factor considered in ESG implementation.\nC Correct because social factors considered in ESG implementation generally pertain to the management of the human capital of a business, including human rights and welfare concerns in the workplace; product development; and, in some cases, community impact."},
  {"num": 12, "subject": "公司发行人", "question": "The interests of creditors are least likely aligned with the interests of:", "options": {"A": "suppliers.", "B": "shareholders.", "C": "long-term customers."}, "answer": "B", "explanation": "A Incorrect because there is no direct relationship between suppliers and creditors. Further, suppliers also have long-term interests in companies, as they seek to build and maintain mutually beneficial relationships. Supplier interest in a company’s long-term stability is important when products are specialized and one or both parties have invested in the relationship through product design, training, or customization. Thus, conflicting interests between suppliers and creditors are not very likely. Further, both customers and suppliers enter into contractual agreements with a company that specify the products and services underlying the relationship, the prices or fees and the payment terms, the rights and responsibilities of each party, the after-sale relationship, and any guarantees. Contracts also specify actions to be taken and recourse available if either party breaches the terms of the contract. Thus, it is not very likely that interests of customers and creditors conflict.\nB Correct because the difference in debt versus equity claims gives rise to potential conflicts of interest. For example, debtholders with a fixed claim tend to be risk averse and prefer that the corporation take actions to ensure sufficient cash flow to meet its debt obligations. For this reason, debtholders tend to prefer that a company raise more equity and limit shareholder distributions. Shareholders, however, tend to prefer greater leverage and shareholder distributions rather than dilutive equity issuance. This potential conflict is greater for long-term debt, as the passage of time exposes debtholders to changes in business conditions, strategy, and management behavior. As a result, long-term creditors are more likely to impose contractual limits on leverage and shareholder distributions.\nC Incorrect because there is no direct relationship between customers and creditors. Also, customers expect a company’s products or services to satisfy their needs at a reasonable price while meeting applicable quality and safety standards. Further, both customers and suppliers enter into contractual agreements with a company that specify the products and services underlying the relationship, the prices or fees and the payment terms, the rights and responsibilities of each party, the after-sale relationship, and any guarantees. Contracts also specify actions to be taken and recourse available if either party breaches the terms of the contract. Thus, it is not very likely that interests of customers and creditors conflict."},
  {"num": 13, "subject": "公司发行人", "question": "Which of the following is most likely a good corporate governance practice?", "options": {"A": "Disclosing related-party transactions", "B": "Rewarding managers for being more risk-averse than shareholders", "C": "Designing remuneration policies that encourage managers to focus on short-term stock performance"}, "answer": "A", "explanation": "A Correct because good corporate governance policies on conflicts of interest and related-party transactions require directors and managers to disclose any actual or potential conflict of interest related to the company, as well as any material interests in a transaction that may affect the company.\nB Incorrect because in practice, compensation is the principal tool used to align the interests of management and shareholders. While management compensation seeks to motivate managers to maximize shareholder value, manager and shareholder interests may diverge regarding inappropriate risk appetite. Compensation dominated by stock grants and options can motivate excessive management risk-taking, as option holders participate only in upside share price moves. Similarly, little or no use of stock grants and options in compensation plans can lead to unduly risk-averse corporate decision-making and the inability to attract talent. This misalignment may be at odds with the company’s value creation objective or shareholders’ desire for higher-risk, higher-reward endeavors. Since investors can hold diversified portfolios, they may have a higher risk tolerance than managers, whose reputation and time are concentrated in a single company. Therefore, good corporate governance seeks to align interests of managers and shareholders through effective compensation to avoid excessive or too little risk-taking that is not aligned with shareholder interests.\nC Incorrect because the compensation, or remuneration, committee develops and proposes remuneration policies for the directors and key executives, which often includes setting performance criteria and evaluating manager performance. Companies are increasingly designing incentive plans that discourage “short-termism” or excessive risk-taking by managers. Some incentive plans include granting shares, rather than options, to managers and restricting their vesting or sale for several years or until retirement. A long-term incentive plan delays compensation, either in part or in total, until a company’s strategic objectives (typically performance targets) are met. Therefore, good corporate governance combats short-termism through long-term incentive plans."},
  {"num": 14, "subject": "公司发行人", "question": "With respect to corporate governance, which of the following represents a principal–agent conflict?", "options": {"A": "Shareholders and creditors have different investment risk tolerances", "B": "Managers seek to maximize their benefits to the detriment of shareholders’ interests", "C": "Controlling shareholders place their interests ahead of minority shareholders’ interests"}, "answer": "B", "explanation": "A Incorrect because a different investment risk tolerance between shareholders and creditors is an example of conflict between stakeholders, not between managers and shareholders with a principal-agent relationship. From an investment perspective, shareholders would likely prefer riskier projects with a strong likelihood of higher return potential, whereas creditors would likely prefer stable performance and lower-risk activities. Conflicts among stakeholder groups do not involve principal-agent relationships.\nB Correct because a principal-agent relationship is created when a principal hires an agent to perform a particular task or service. The principal-agent relationship involves obligations, trust, and expectations of loyalty; the agent is expected to act in the best interests of the principal. In a company, principal-agent relationships often lead to conflicts when managers do not act in the best interests of shareholders. The central duty of directors and managers is to act in the best interest of shareholders. Managers may seek to maximize their personal benefits to the detriment of shareholders’ interests.\nC Incorrect because controlling shareholders placing their interests ahead of minority shareholders’ interest is an example of conflict between controlling and minority shareholders. Related-party transactions are another example for which controlling shareholders may place their interests ahead of minority shareholders’ interests. Conflicts among other stakeholder groups do not involve principal-agent relationships."},
  {"num": 15, "subject": "公司发行人", "question": "Which of the following board committees is most likely responsible for recommending the appointment of an external auditor and proposing its remuneration?", "options": {"A": "Audit committee", "B": "Nominating committee", "C": "Remuneration committee"}, "answer": "A", "explanation": "A Correct because the audit committee is also responsible for recommending the appointment of an independent external auditor and proposing its remuneration.\nB Incorrect because the nominating, or governance, committee appraises director and manager candidates and oversees the board election process. It is the audit committee that is responsible for recommending the appointment of an independent external auditor and proposing its remuneration.\nC Incorrect because the compensation, or remuneration, committee develops and proposes remuneration policies for the directors and key executives. It is the audit committee that is responsible for recommending the appointment of an independent external auditor and proposing its remuneration."},
  {"num": 16, "subject": "公司发行人", "question": "Managers seeking to retain their jobs by pursuing initiatives they are uniquely suited to manage is most likely an example of:", "options": {"A": "self-dealing.", "B": "entrenchment.", "C": "empire building."}, "answer": "B", "explanation": "A Incorrect because self dealing relates to managers that may exploit firm resources to maximize personal benefits, such as excessive perquisites (private airplanes, club memberships, personal security), or defraud investors by misappropriating assets. The smaller a manager's stake in the company, the less they bear these costs themselves, reducing their desire to maximize firm value.\nB Correct because entrenchment relates to directors and managers wanting to retain their jobs. Tactics to do so include copying competitors and peers, avoiding risks, and pursuing complicated transactions and restructurings that they are uniquely suited to manage. Directors may avoid speaking out against management, even if speaking out is in the interest of shareholders or other stakeholders.\nC Incorrect because empire building relates to management compensation and status that are typically tied to business size (e.g., total revenues, number of employees), which can incentivize managers to seek 'growth for growth’s sake,' such as acquisitions that do not increase shareholder value."},
  {"num": 17, "subject": "公司发行人", "question": "Which of the following stakeholder groups is most likely to have the highest risk tolerance with respect to the volatility of a company's performance?", "options": {"A": "Creditors", "B": "Suppliers", "C": "Shareholders"}, "answer": "C", "explanation": "A Incorrect because creditors usually do not participate in a company’s superior performance beyond receiving promised interest and principal payments. The company’s ability to generate cash flows, mainly through its operations, is the primary source of payments for creditors. Consequently, creditors generally prefer stability in company operations and performance, which contrasts with the interests of shareholders, who generally are inclined to tolerate higher risks in return for higher return potential from strong company performance.\nB Incorrect because suppliers have a primary interest in being paid as contracted or agreed on, and in a timely manner, for products or services delivered to the company. Suppliers, like creditors, are concerned with a company’s ability to generate sufficient cash flows to meet its financial obligations.\nC Correct because shareholders are the most junior class of capital providers; in case of a company bankruptcy, shareholders receive proceeds only after all creditors’ claims are paid. In contrast to creditors and suppliers, shareholders generally are inclined to tolerate higher risks in return for higher return potential from strong company performance."},
  {"num": 18, "subject": "公司发行人", "question": "Which of the following is most likely a primary role of a corporate board of directors?", "options": {"A": "Voting common shares", "B": "Implementing corporate strategy", "C": "Appointing the company’s top managers"}, "answer": "C", "explanation": "A Incorrect because shareholders elect a board of directors to provide broad oversight of the company. Shareholders monitor the board’s performance through exercise of voting power and participation in general meetings. Although both management and board members may also be voting shareholders, it is only by virtue of owning shares. The board of directors does not exercise corporate voting power in the absence of owning shares. The role of a board of directors is not voting common shares but rather appointing the top management of the company. The board is accountable primarily to shareholders and is responsible for the proper governance of the company. The board guides managers on the company’s strategic direction, oversees and monitors management’s actions in implementing the strategy, and evaluates and rewards or disciplines management performance and also supervises the company’s audit, control, and risk management functions.\nB Incorrect because a company’s management is responsible for implementing strategies, whereas the board guides managers on the company’s strategic direction, oversees and monitors management’s actions in implementing the strategy, and evaluates and rewards or disciplines management performance.\nC Correct because a corporate board has many roles including appointing the top management of the company. The board is accountable primarily to shareholders and is responsible for the proper governance of the company. The board guides managers on the company’s strategic direction, oversees and monitors management’s actions in implementing the strategy, and evaluates and rewards or disciplines management performance. The board also supervises the company’s audit, control, and risk management functions and ensures the adoption of proper governance systems and compliance with all applicable laws and regulations."},
  {"num": 19, "subject": "公司发行人", "question": "Which of the following features of an executive remuneration plan most likely indicates a misalignment of interests between executives and investors? Executive payouts that:", "options": {"A": "consist of only cash and no equity.", "B": "are consistent with those of similar companies in the same industry.", "C": "exhibit significant variation over time based on company performance."}, "answer": "A", "explanation": "A Correct because conflicts arise where the interests of a principal and an agent diverge. In practice, compensation is the main tool used to create alignment of interests between management and board directors on the one hand and shareholders on the other. In principle, management compensation (which may include grants of shares and options to purchase shares in the company) is intended to motivate managers to work hard to maximize shareholder value. However, the alignment of interests between managers and shareholders is rarely perfect. If we consider the typical elements of management compensation, we can identify common examples of misalignment or conflicts. If an executive remuneration plan offers cash only, the incentives between management and investors and other stakeholders may be misaligned.\nB Incorrect because an analyst would likely be concerned if a company’s executives were excessively compensated relative to competitors. Payouts that are consistent with similar companies do not raise a warning sign.\nC Incorrect because incentive plans increasingly include a variable component — typically profit sharing, stocks, or stock options — that is contingent on corporate or stock price performance. The granting of stock-based remuneration does not serve its purpose, however, if managers can improve their personal gains at the expense of the company while limiting their exposure to weak stock performance. A long-term incentive plan delays the payment of remuneration, either partially or in total, until company strategic objectives (typically performance targets) are met. Accordingly, executive payouts that exhibit significant variation over time based on company performance would not indicate a misalignment of interests between executives and investors."},
  {"num": 20, "subject": "公司发行人", "question": "Which of the following board committees is among the three most commonly recommended by corporate governance codes?", "options": {"A": "Risk committee", "B": "Creditor committee", "C": "Nominating committee"}, "answer": "C", "explanation": "A Incorrect because the three most common board committees (sometimes referred to as “core committees”), recommended by most corporate governance codes and required by some stock exchanges include Audit Committee, Nominating/Governance Committee and, Compensation/Remuneration Committee.\nB Incorrect because the three most common board committees (sometimes referred to as “core committees”), recommended by most corporate governance codes and required by some stock exchanges include Audit Committee, Nominating/Governance Committee and, Compensation/Remuneration Committee.\nC Correct because the three most common board committees (sometimes referred to as “core committees”), recommended by most corporate governance codes and required by some stock exchanges include Audit Committee, Nominating/Governance Committee and, Compensation/Remuneration Committee."},
  {"num": 21, "subject": "公司发行人", "question": "Information asymmetry between managers and shareholders is most likely higher if a company:", "options": {"A": "makes products of greater complexity.", "B": "has higher levels of institutional ownership.", "C": "provides more transparent accounting information."}, "answer": "A", "explanation": "A Correct because whereas all companies have a certain level of asymmetric information, companies with comparatively high asymmetry in information include those with complex products. These include high-tech companies, companies with little transparency in financial accounting information, and companies with lower levels of institutional ownership. So, companies producing more complex products are likely to have higher levels of information asymmetry between managers and shareholders.\nB Incorrect because whereas all companies have a certain level of asymmetric information, companies with comparatively high asymmetry in information include those with complex products. These include high-tech companies, companies with little transparency in financial accounting information, and companies with lower levels of institutional ownership. So, companies with higher levels of institutional ownership are likely to have lower levels of information asymmetry between managers and shareholders.\nC Incorrect because whereas all companies have a certain level of asymmetric information, companies with comparatively high asymmetry in information include those with complex products. These include high-tech companies, companies with little transparency in financial accounting information, and companies with lower levels of institutional ownership. So, companies with more transparency in accounting information are likely to have lower levels of information asymmetry between managers and shareholders."},
  {"num": 22, "subject": "公司发行人", "question": "Which of the following best reflects a misalignment of interests between managers/directors and shareholders?", "options": {"A": "A compensation package relying too little on stock options can motivate excessive risk-taking behavior by management", "B": "When the overall level of board director compensation is low, directors may avoid speaking out against management in the interest of shareholders", "C": "Management compensation which is high and tied to business size may lead to managers pursuing acquisitions that might not increase shareholder value"}, "answer": "C", "explanation": "A Incorrect because compensation dominated by stock grants and options can motivate excessive management risk-taking, as option holders participate only in upside share price moves.\nB Incorrect because directors typically want to retain their jobs, especially if compensation is high (not low). Tactics to do so include copying competitors and peers, avoiding risks, and pursuing complicated transactions and restructurings that they are uniquely suited to manage. Directors may avoid speaking out against management, even if speaking out is in the interest of shareholders or other stakeholders.\nC Correct because when management compensation are high and tied to the size of the business, it can incentivize managers to seek “growth for growth’s sake,” such as acquisitions that do not increase shareholder value."},
  {"num": 23, "subject": "公司发行人", "question": "An analyst gathers the following information (in £ millions) about a company:\nThe quick ratio of this company is closest to:", "options": {"A": "0.87.", "B": "1.02.", "C": "1.14."}, "answer": "B", "explanation": "A Incorrect because receivables are not included (in the numerator) when calculating the quick assets. Quick ratio ≠ (Cash + Short-term marketable investments)/Current liabilities = (50 + 37)/100 = 0.87.\nB Correct because the quick ratio (also known as the acid-test ratio) is the ratio of the quick assets to current liabilities. Quick assets are those assets that can be most readily converted to cash. Quick ratio = (Cash + Short-term marketable investments + Receivables)/Current liabilities\" = (50 + 37 + 15)/100 = 1.02.\nC Incorrect because the current ratio is calculated, not the quick ratio.\nA Incorrect because the quick ratio for the company, 0.9, is less favorable compared to its peer group at 1.1. The greater the current ratio or the quick ratio (that is, the greater the potential ability to cover current liabilities), the higher a company’s liquidity. Because for some liquidity measures a higher number indicates a better position and for some a lower number indicates a better position, the candidate must differentiate and apply that to each of these measures for the company versus the peer group. A candidate who applies the wrong evaluation may choose the wrong measure as being favorable.\nB Correct because based on the operating cycle, the company’s 70 days compares favorably to 73 days for its peer group. The operating cycle is a measure of the time needed to convert raw materials into cash from a sale. In general, the shorter these cycles the greater a company’s cash-generating ability and the less its need for liquid assets or outside finance. Of the three measures, the operating cycle is the only measure to which the company has a favorable comparison.\nC Incorrect because based on the cash conversion cycle, the company’s 40 days is less favorable compared to 38 days for its peer group. A company’s available cash flow is increased by deferring payment to suppliers. This deferral is considered in the net operating cycle, also called the cash conversion cycle, it is a measure of the time from paying suppliers for materials to collecting cash from the subsequent sale of goods produced from these supplies. In general, the shorter these cycles the greater a company’s cash-generating ability and the less its need for liquid assets or outside finance. Because for some liquidity measures a higher number indicates a better position and for some a lower number indicates a better position, the candidate must differentiate and apply that to each of these measures for the company versus the peer group. A candidate who applies the wrong evaluation may choose the wrong measure as being favorable."},
  {"num": 24, "subject": "公司发行人", "question": "An analyst gathers the following liquidity indicators for a company and its peer group:\nAll else being equal, the company’s liquidity compares favorably to the peer group based on the:", "options": {"A": "quick ratio.", "B": "operating cycle.", "C": "cash conversion cycle."}, "answer": "A", "explanation": "A Correct because a drag on liquidity is when receipts lag, creating pressure from the decreased available funds. Major drags on receipts involve pressures from credit management and deterioration in other assets such as tight credit. When economic conditions make capital scarcer, short-term debt becomes more expensive to arrange and use.\nB Incorrect because a pull on liquidity is when disbursements are paid too quickly or trade credit availability is limited, requiring companies to expend funds before they receive funds from sales that could cover the liability. If suppliers and other vendors who offer credit terms perceive a weakened financial position or are unfamiliar with a company, they may restrict payment terms so much that the company’s liquidity reserves are stretched thin. Major pulls on payments include reduced credit limits. If a company has a history of making late payments, suppliers may cut the amount of credit they will allow to be outstanding at any time, which can squeeze the company’s liquidity.\nC Incorrect because a pull on liquidity is when disbursements are paid too quickly or trade credit availability is limited, requiring companies to expend funds before they receive funds from sales that could cover the liability. If suppliers and other vendors who offer credit terms perceive a weakened financial position or are unfamiliar with a company, they may restrict payment terms"},
  {"num": 25, "subject": "公司发行人", "question": "Which of the following is most likely classified as a drag on liquidity?", "options": {"A": "Tight credit market conditions", "B": "Reduced trade credit availability", "C": "Limits on short-term lines of credit"}, "answer": "A", "explanation": "A Correct because the average time it took Company 1 to collect its accounts receivable decreased from 183 days in Year 1 to 168 days in Year 2. Number of days receivable = Accounts receivable / (Sales on credit / 365). In Year 1 number of days receivable = 2,500,000 / (5,000,000 / 365) = 183 days. In Year 2 number of days receivable = 3,000,000 / (6,500,000 / 365) = 168 days.\nB Incorrect because the average time taken by Company 2 to collect its accounts receivable increased from 122 days to 137 days. In Year 1 number of days receivable = 1,000,000 / (3,000,000 / 365) = 122 days. In Year 2 number of days receivable = 1,500,000 / (4,000,000 / 365) = 137 days.\nC Incorrect because the average time taken by Company 3 to collect its accounts receivable increased from 117 days to 122 days. In Year 1 number of days receivable = 800,000 / (2,500,000 / 365) = 117 days. In Year 2 number of days receivable = 1,000,000 / (3,000,000 / 365) = 122 days."},
  {"num": 26, "subject": "公司发行人", "question": "An analyst gathers the following information (in $ millions) about three peer companies:\nWhich company reduced the average time to collect accounts receivable between Year 1 and Year 2?", "options": {"A": "Company 1", "B": "Company 2", "C": "Company 3"}, "answer": "C", "explanation": "A Incorrect because bank lines of credit are a primary source of liquidity and not a secondary source of liquidity. Primary sources of liquidity represent the most readily accessible resources available. They may be held as cash or as near-cash securities. Primary sources include short-term funds, which may include items such as trade credit, bank lines of credit, and short-term investment portfolios.\nB Incorrect because cash flow management is a primary source of liquidity not a secondary source of liquidity. Primary sources of liquidity represent the most readily accessible resources available. They may be held as cash or as near-cash securities. Primary sources include cash flow management, which is the company's effectiveness in its cash management system and practices, and the degree of decentralization of the collections or payments processes.\nC Correct because the main difference between the primary and secondary sources of liquidity is that using a primary source is not likely to affect the normal operations of the company, whereas using a secondary source may result in a change in the company's financial and operating positions. Secondary sources include: negotiating debt contracts, relieving pressures from high interest payments or principal repayments."},
  {"num": 27, "subject": "公司发行人", "question": "Which of the following is best described as a secondary source of liquidity?", "options": {"A": "Bank line of credit", "B": "Cash flow management", "C": "Renegotiated debt contract"}, "answer": "B", "explanation": "A Incorrect because in Year 1, the cash conversion cycle was 85 + 136 – 29 = 192 days. In Year 2 the cash conversion cycle was 76 + 129 – 13 = 192 days. Thus, the cash conversion cycle was the same in Year 1 and Year 2.\nB Correct because the cash conversion cycle is the same for both years. The cash conversion cycle equals Days of inventory on hand + Days sales outstanding − Days payable outstanding. In Year 1 the cash conversion cycle was 85 + 136 – 29 = 192 days. In Year 2 the cash conversion cycle was 76 + 129 – 13 = 192 days.\nC Incorrect because the cash conversion cycles are the same."},
  {"num": 28, "subject": "公司发行人", "question": "An analyst gathers the following information about a company:\nThe company's cash conversion cycle in Year 2 is:", "options": {"A": "shorter than the cash conversion cycle in Year 1.", "B": "the same as the cash conversion cycle in Year 1.", "C": "longer than the cash conversion cycle in Year 1."}, "answer": "A", "explanation": "A Correct because it discounts all the cash flows at the required return and sums them as follows: NPV = t=1nΣCFt /(1 + r)t − Outlay, where CFt = After-tax cash flow at time t, r = Required rate of return for the investment, Outlay = Investment cash flow at time zero, NPV = 65/(1 + 15%) + 65/(1 + 15%)2 + 65/(1 + 15%)3 – 100 ≈ 56.52 + 49.15 + 42.74 – 100 = 148.41 ≈ 48.\nB Incorrect because it does not discount the cash flows. Calculated as follows: NPV = 65 + 65 + 65 – 100 = 95.\nC Incorrect because it fails to subtract the initial investment. Obtained as follows: NPV = 65/(1 + 15%) + 65/(1 + 15%)2 + 65/(1 + 15%)3 = 56.52 + 49.15 + 42.74 = 148.41 ≈ 148."},
  {"num": 29, "subject": "公司发行人", "question": "An analyst gathers the following information about a project:\nIf the required rate of return is 15%, the NPV is closest to:", "options": {"A": "€48 million.", "B": "€95 million.", "C": "€148 million."}, "answer": "A", "explanation": "A Correct because the NPV, including the real option, should be: Project NPV = NPV (based on DCF alone) – Cost of options + Value of options. Project NPV = –$0.2 million – $0.4 million + $0.8 million = $0.2 million.\nB Incorrect because the original NPV of the investment was not considered. Project NPV ≠ – Cost of options + Value of options. Project NPV ≠ – $0.4 million + $0.8 million = $0.4 million.\nC Incorrect because the cost of the option was added to the NPV (based on DCF alone) instead of being subtracted."},
  {"num": 30, "subject": "公司发行人", "question": "The NPV of a new project is expected to be –$0.20 million. An incremental investment of $0.40 million would give management the flexibility to switch to a lower cost input in the future. If this option has an estimated value of $0.80 million, the value of the project including the option is:", "options": {"A": "$0.20 million.", "B": "$0.40 million.", "C": "$1.00 million."}, "answer": "A", "explanation": "A Correct because when the choice is between two mutually exclusive projects and the NPV and IRR rank the two projects differently, the NPV criterion is strongly preferred. As a practical matter, once a corporation has the data to calculate the NPV, it is fairly trivial to then calculate the IRR and other capital allocation criteria. However, the most appropriate and theoretically sound criterion is the NPV.\nB Incorrect because when the choice is between two mutually exclusive projects and the NPV and IRR rank the two projects differently, the NPV (not IRR) criterion is strongly preferred.\nC Incorrect because when the choice is between two mutually exclusive projects and the NPV and IRR rank the two projects differently, the NPV criterion (not either one) is strongly preferred."},
  {"num": 31, "subject": "公司发行人", "question": "A company is deciding whether to invest in one of two mutually exclusive projects with positive NPVs. If Project 1 has a higher NPV but a lower IRR than Project 2, the company should:", "options": {"A": "prefer Project 1.", "B": "prefer Project 2.", "C": "be indifferent between Project 1 and Project 2."}, "answer": "A", "explanation": "A Correct because unlike going concern and expansion projects, for which management has discretion in deciding whether or not to invest, regulatory and compliance projects are required by third parties, such as government regulatory bodies, to meet safety and regulatory compliance standards.\nB Incorrect because unlike going concern and expansion projects, for which management has discretion in deciding whether or not to invest, regulatory and compliance projects are required by third parties, such as government regulatory bodies, to meet safety and regulatory compliance standards.\nC Incorrect because unlike going concern and expansion projects, for which management has discretion in deciding whether or not to invest, regulatory and compliance projects are required by third parties, such as government regulatory bodies, to meet safety and regulatory compliance standards."},
  {"num": 32, "subject": "公司发行人", "question": "Management most likely has the least amount of discretion when deciding to invest in a(n):", "options": {"A": "regulatory project.", "B": "expansion project.", "C": "going concern project."}, "answer": "A", "explanation": "A Correct because an abandonment option is a type of sizing option. If after investing the company can abandon the investment if the financial results are disappointing, it has an abandonment option. At some future date, if the cash flow from abandoning an investment exceeds the present value of the cash flows from continuing the investment, the company should exercise the abandonment option.\nB Incorrect because this is a type of sizing option, not a flexibility option. Regarding sizing options, if after investing the company can abandon the investment if the financial results are disappointing, it has an abandonment option while regarding flexibility options once an investment is made, operational flexibilities besides abandonment or expansion may be available.\nC Incorrect because this is a type of sizing option, not a fundamental option. Regarding fundamental options, in such cases as the aforementioned, i.e. timing options, sizing options, flexibility options, there are options embedded in a project that can raise its value. In other cases, the whole investment is essentially an option. The payoffs from the investment are contingent on an underlying asset, just like most financial options."},
  {"num": 33, "subject": "公司发行人", "question": "The ability to abandon an investment if it has produced disappointing financial results is most likely a type of:", "options": {"A": "sizing option.", "B": "flexibility option.", "C": "fundamental option."}, "answer": "C", "explanation": "A Incorrect because going concern projects, often known as maintenance capital expenditures, are investments to continue the company’s current operations and maintain the existing size of the business.\nB Incorrect because regulatory compliance projects often increase a firm’s expenses with no added revenue.\nC Correct because capital investments are also usually necessary if an established firm decides to extend its existing operations to adjacent products and services or expand to new regions or markets."},
  {"num": 34, "subject": "公司发行人", "question": "Which statement regarding capital investments is correct?", "options": {"A": "Going concern projects are investments to increase the size of the business", "B": "Regulatory compliance projects seldom increase a firm’s expenses with no added revenue", "C": "Capital investments are usually necessary if a firm extends its existing operations to adjacent products and services"}, "answer": "A", "explanation": "A Correct because continuous improvements of existing facilities are going concern projects. Going concern projects, often known as maintenance capital expenditures, are investments to continue the company’s current operations and maintain the existing size of the business. Common going concern projects include replacing assets nearing the end of their useful life, maintaining IT hardware and software, and continuous improvements of existing facilities.\nB Incorrect because anti-money-laundering training is a regulatory compliance project, not a going concern project. Unlike projects based on management discretion, regulatory compliance projects are required to meet rules and standards.\nC Incorrect because investing in solar panel production to benefit from government subsidies is a new line of business project, not a going concern project. A firm’s management may decide to invest in an activity completely outside or only minimally related to its existing business. Usually seen as a special situation offering unusual growth, investment, or innovation opportunities for a company’s business or business model, these projects are likely to be the riskiest capital investments."},
  {"num": 35, "subject": "公司发行人", "question": "Maintenance capital expenditures include:", "options": {"A": "continuous improvements of existing facilities.", "B": "anti-money-laundering training for employees.", "C": "investing in solar panel production to benefit from government subsidies."}, "answer": "B", "explanation": "A Incorrect because sunk costs should be ignored in capital allocation decisions. A sunk cost is one that has already been incurred. One cannot change a sunk cost. Management’s decisions should be based on current and future cash flows and should not be affected by prior, or sunk, costs.\nB Correct because this is often a sign of inertia, which is a common mistake in capital allocation. Inertia is the result of management anchoring their capital investment budgets to prior year amounts. If capital investment each year is static or increasing despite falling returns on investment, the analyst should question the issuer’s justification for its capital investment and whether management should be considering alternative uses.\nC Incorrect because failing to consider alternative states in capital allocation decisions is a common mistake. Many companies also fail to consider differing states of the world, which can and should be incorporated through breakeven, scenario, and simulation analyses. This pitfall could be in effect if an issuer has had limited capital investment activity, such as not making divestitures or acquisitions, or not having a failed investment; while failure is obviously undesirable, the lack of having any failed investments over time could indicate a management team that is not taking enough risk."},
  {"num": 36, "subject": "公司发行人", "question": "Which of the following is a common capital allocation pitfall?", "options": {"A": "Ignoring sunk costs", "B": "Anchoring capital investment budgets to prior year amounts", "C": "Considering different states of the world for investment alternatives"}, "answer": "B", "explanation": "A Incorrect because the IRR is compared to the required return to determine if a project is acceptable, but the interim cash flows are reinvested at the internal rate of return, not the hurdle rate.\nB Correct because the IRR assumes reinvestment at the IRR. Mathematically, whenever you discount a cash flow at a particular discount rate, you are implicitly assuming that you can reinvest a cash flow at that same discount rate.\nC Incorrect because the IRR is compared to the hurdle rate to determine if a project is acceptable. The weighted average cost of capital could be used as the hurdle rate if the project being evaluated has the same risk as the firm's average asset."},
  {"num": 37, "subject": "公司发行人", "question": "With respect to capital budgeting, which of the following statement is most\naccurate? The internal rate of return calculation assumes that a project's interim cash flows are reinvested at the project's:", "options": {"A": "hurdle rate.", "B": "internal rate of return.", "C": "weighted average cost of capital."}, "answer": "B", "explanation": "A Incorrect because the WACC, after adjusting for any project-specific risks, is what issuers use as r in NPV analysis and as the hurdle rate for IRR analysis.\nB Correct because the required rate of return for an investment is the rate of return that a corporate issuer’s investors could earn on a similarly risky investment.\nC Incorrect because the required return for an investment is the rate of return that a corporate issuer’s investors could earn on a similarly risky investment."},
  {"num": 38, "subject": "公司发行人", "question": "When evaluating potential capital investments, the most appropriate discount rate is the:", "options": {"A": "overall cost of capital for the company.", "B": "individual investment's required rate of return.", "C": "cost of debt or cost of equity, depending on the financing source."}, "answer": "B", "explanation": "A Incorrect because the decision rule for the NPV is: Invest if NPV > 0. In the case of mutually exclusive investment projects, a company should choose the one with the higher NPV.\nB Correct because the decision rule for the NPV is: Invest if NPV > 0. In the case of mutually exclusive investment projects, a company should choose the one with the higher NPV.\nC Incorrect because both projects have a negative NPV at this discount rate. The decision rule for the NPV is: Invest if NPV > 0. Do not invest if NPV < 0. Therefore, neither would be selected by the decision maker."},
  {"num": 39, "subject": "公司发行人", "question": "An analyst gathers the following information (in $ millions) about two mutually exclusive capital projects:\nProject 1 should be selected for investment if the required rate of return is:", "options": {"A": "9%.", "B": "12%.", "C": "15%."}, "answer": "A", "explanation": "A Correct because the IRR is the discount rate that makes the present value of the future after-tax cash flows equal the investment outlay or: ∑nt=1 CFt ÷ (1 + IRR)t = Outlay, where IRR is the internal rate of return. Solved using the following calculator inputs: CF0 = −150, CF1 = 8, CF2 = 175, Calculate IRR = 10.7119, rounded to 10.7%.\nB Incorrect because 12% is the company's required rate of return, not the expected IRR.\nC Incorrect because it inflates cash flows in Year 2 by 8 and represents an IRR calculation using the following calculator inputs:"},
  {"num": 40, "subject": "公司发行人", "question": "A company with a required rate of return of 12% is considering a capital project with the following cash flows (in millions):\nThe expected IRR for the project is closest to:", "options": {"A": "10.7%.", "B": "12.0%.", "C": "13.2%."}, "answer": "B", "explanation": "A Incorrect because, according to the MM Proposition I without taxes, the firm value is not affected by the company's capital structure. It is determined solely by the firm's expected future cash flows.\nB Correct because Modigliani and Miller proved that changing the capital structure does not affect firm value. The value of a firm is thus determined not by the securities it issues but, rather, by its expected future cash flows.\nC Incorrect because, according to the MM Proposition I without taxes, the firm value is not affected by the company's capital structure. It is determined solely by the firm's expected future cash flows."},
  {"num": 41, "subject": "公司发行人", "question": "According to the Modigliani–Miller Proposition I without taxes, when a firm increases the proportion of debt in its capital structure, the firm value:", "options": {"A": "decreases.", "B": "remains unchanged.", "C": "increases."}, "answer": "C", "explanation": "A Incorrect because an approach is to consider profit sensitivity by looking at the change in net income in relation to change in revenues to capture total leverage of the business.\nB Incorrect because financial leverage reflects the variability of profits introduced by interest charges—that is, the sensitivity of net profit to a change in operating profit.\nC Correct because operating leverage captures the sensitivity of operating profit, proxied by EBIT, to a change in revenues."},
  {"num": 42, "subject": "公司发行人", "question": "Which of the following is defined as the sensitivity of a firm’s operating profit to a change in its revenues?", "options": {"A": "Total leverage", "B": "Financial leverage", "C": "Operating leverage"}, "answer": "B", "explanation": "A Incorrect because this is the result generated if the company value is used rather than the equity value. Cost of equity ≠ 0.09 + (0.09 – 0.04)×(1 – 0.25)×(£15,000/£40,000) = 0.1041 ≈ 10.4%.\nB Correct because Modigliani and Miller also show that the cost of equity for the same company with debt is: re = r0 + (r0 – rd)(1 – t)(D/E), where: re = cost of equity ro = cost of capital for a company financed only with equity rd = cost of debt D = market value of debt E = market value of equity. Cost of equity = 0.09 + (0.09 – 0.04)×(1 – 0.25)×(£15,000/(£40,000 – 15,000)) = 0.1125 ≈ 11.3%.\nC Incorrect because this result reflects the cost of equity in the absence of corporate taxes. Cost of equity ≠ 0.09 + (0.09 – 0.04)×(£15,000/(£40,000 – £15,000)) = 0.1200 = 12.0%."},
  {"num": 43, "subject": "公司发行人", "question": "Consider the following information about a company:\nBased on the Modigliani-Miller propositions, the company's cost of equity is closest to:", "options": {"A": "10.4%.", "B": "11.3%.", "C": "12.0%."}, "answer": "B", "explanation": "A Incorrect because the Modigliani and Miller proposition implies that higher leverage raises the cost of equity but does not change firm value or WACC.\nB Correct because the Modigliani and Miller proposition implies that higher leverage raises the cost of equity but does not change firm value or WACC.\nC Incorrect because the Modigliani and Miller proposition implies that higher leverage raises the cost of equity but does not change firm value or WACC."},
  {"num": 44, "subject": "公司发行人", "question": "A company increases its debt from 20% to 60% of its capital structure. Based on the Modigliani and Miller proposition (without taxes) regarding capital structure, the WACC of the company:", "options": {"A": "decreases.", "B": "remains the same.", "C": "increases."}, "answer": "C", "explanation": "A Incorrect because it is a lower, not higher, current ratio that would indicate liquidity problems for a company, and hence a reduced debt capacity (i.e., ability to take additional debt). A starting point for determining a company’s debt capacity is its current ratio, equal to current assets divided by current liabilities. The current ratio provides an indication of the ability of the firm to meet its short-term debt obligations. The higher the ratio, the greater the ability of the company to repay its debt.\nB Incorrect because a higher, not lower, leverage ratio would indicate a reduced debt capacity (i.e., ability for a company to take additional debt). Firms with higher proportions of debt in their capital structures face a higher probability of default and have less ability to service additional debt than underleveraged firms.\nC Correct because interest coverage ratios are also commonly used to assess companies’ debt capacities. Generally, these ratios provide an estimate of how many times a company can cover its interest expense (or interest expense plus lease payments) with current earnings (usually measured as EBIT or EBITDA). In other words, interest coverage ratios provide an indication of a company’s financial cushion in meeting its debt service obligations. The larger the interest coverage ratio, the larger the financial cushion and the greater the company’s ability to service its debt obligations."},
  {"num": 45, "subject": "公司发行人", "question": "All else being equal, a company most likely has a reduced debt capacity when its:", "options": {"A": "current ratio increases.", "B": "leverage ratio decreases.", "C": "interest coverage ratio decreases."}, "answer": "B", "explanation": "A Incorrect because an increased ability to support debt is indicated by high revenue, low cash flow volatility, and greater (not lower) fungible assets.\nB Correct because an increased ability to support debt is indicated by high revenue, low operating leverage, and greater fungible assets.\nC Incorrect because an increased ability to support debt is indicated by low cash flow volatility, low operating leverage, and greater (not lower) fungible assets."},
  {"num": 46, "subject": "公司发行人", "question": "Which of the following combination of factors most likely increases a company's ability to support debt in its capital structure?", "options": {"A": "High revenue, low cash flow volatility, and a low level of fungible assets", "B": "High revenue, low operating leverage, and a high level of fungible assets", "C": "Low cash flow volatility, low operating leverage, and a low level of fungible assets"}, "answer": "C", "explanation": "A Incorrect because the pecking order theory suggests that managers choose methods of financing according to a hierarchy that gives first preference to methods with the least potential information content (internally generated funds) and lowest preference to the form with the greatest potential information content (public equity offerings).In brief, managers prefer internal financing. If internal financing is insufficient, managers next prefer debt, then equity.\nB Incorrect because the pecking order theory suggests that managers choose methods of financing according to a hierarchy that gives first preference to methods with the least potential information content (internally generated funds) and lowest preference to the form with the greatest potential information content (public equity offerings). In brief, managers prefer internal financing. If internal financing is insufficient, managers next prefer debt, then equity.\nC Correct because the pecking order theory suggests that managers choose methods of financing according to a hierarchy that gives first preference to methods with the least potential information content (internally generated funds) and lowest preference to the form with the greatest potential information content (public equity offerings). In brief, managers prefer internal financing. If internal financing is insufficient, managers next prefer debt, then equity."},
  {"num": 47, "subject": "公司发行人", "question": "According to the pecking order theory, company managers most likely prefer to:", "options": {"A": "issue debt as the last resort.", "B": "raise equity first to preserve cash-flow.", "C": "rely on internal financing over new equity."}, "answer": "A", "explanation": "A Correct because if interest can be deducted in full, the tax deductibility of debt reduces the effective marginal cost of debt to reflect the income shielded from taxation and the marginal cost of debt is rd(1 – t). The cost of debt capital is the only cost of capital that can benefit from a tax shield.\nB Incorrect because only debt benefits from a tax shield. The cost of equity calculation used in the WACC is simply the weight of equity times the cost of equity with no adjustments made for taxation. Taking the sources of capital to be common stock, preferred stock, and debt and allowing for the fact...that in some jurisdictions interest expense may be tax deductible, the expression for WACC is WACC = wdrd (1 – t) + wprp + were....we = the proportion of equity that the company uses when it raises funds and re = the marginal cost of equity.\nC Incorrect because unlike interest on debt, the dividend on preferred stock is not tax-deductible by the company; therefore, there is no adjustment to the cost of taxes. Therefore, raising capital by issuing preferred equity does not give rise to a tax shield to the company."},
  {"num": 48, "subject": "公司发行人", "question": "The source of capital that most likely benefits from a tax shield is:", "options": {"A": "debt.", "B": "equity.", "C": "preferred equity."}, "answer": "B", "explanation": "A Incorrect because with volatile revenue growth from a low base and no debt, this is most likely a company in its start-up phase.\nB Correct because since the company's revenue is growing steadily (20% in the first year and 22% subsequently) and there is already a small amount of debt in the capital structure, this company is most likely in its growth phase.\nC Incorrect because with negligible revenue growth and Debt/Capital already greater than 25%, this company is most likely a mature company."},
  {"num": 49, "subject": "公司发行人", "question": "An analyst gathers the following information about three companies in the same industry but at different stages of their life cycles:\nThe company in the growth phase of its lifecycle is most likely:", "options": {"A": "Company 1.", "B": "Company 2.", "C": "Company 3."}, "answer": "C", "explanation": "A Incorrect because debt is a negligible component of the capital structures of most start-up companies.\nB Incorrect because many growth companies use debt conservatively in order to preserve operational and financial flexibility and minimize the risk of financial distress. Equity remains the predominant source of capital.\nC Correct because at the maturity stage, the company becomes able to support low-cost debt, often on an unsecured basis. From the company’s perspective, debt financing is likely to be more attractive than higher-cost equity financing."},
  {"num": 50, "subject": "公司发行人", "question": "Debt as a proportion of total capital is most likely greatest in which of the following life-cycle stages of a company?", "options": {"A": "Start-up", "B": "Growth", "C": "Mature"}, "answer": "A", "explanation": "A Correct because a simple way of transforming a debt-to-equity ratio (D/E) into a weight–that is, D/(D + E)–is to divide D/E by 1 + D/E. While optimal capital structure is calculated using the market value of equity and debt, company capital structure targets often use book value. As such, the weight of debt in the company's target capital structure is most likely 0.52 / (1 + 0.52) = 34.21% ≈ 34%.\nB Incorrect because this is the debt-to-equity ratio based on market value, not the weight of debt based on book value.\nC Incorrect because this is the debt-to-equity ratio based on book value, not the weight of debt based on book value."},
  {"num": 51, "subject": "公司发行人", "question": "A corporate treasurer gathers the following information about her company:\nThe weight of debt in the company's target capital structure is closest to:", "options": {"A": "34%.", "B": "43%.", "C": "52%."}, "answer": "B", "explanation": "A Incorrect because it tax adjusts the preferred stock cost: 0.09 × (1 – 0.25): WACC = 0.458 × 0.07 × (1 – 0.25) + 0.167 × 0.09 × (1 – 0.25) + 0.375 × 0.12 = 0.024 + 0.0113 + 0.045 ≈ 0.08 = 8.0%.\nB Correct because the WACC is calculated as follows: WACC = wdrd (1 – t) + wprp + were Where: wd = proportion of debt = 550 / sum of total capital = 550 / (550 + 200 + 450) = 0.458 rd = before tax cost of debt = 7% t = tax rate = 25% wp = proportion of preferred stock = 200 / (550 + 200 + 450) = 0.167 rp = cost of preferred stock = 9% we = proportion of common stock = 450 / (550 + 200 + 450) = 0.375 re = cost of common stock = 12%. WACC = 0.458 × 0.07 × (1 – 0.25) + 0.167 × 0.09 + 0.375 × 0.12 = 0.024 + 0.0150 + 0.045 = 0.0840 =8.4%.\nC Incorrect because it fails to tax adjust the debt cost:"},
  {"num": 52, "subject": "公司发行人", "question": "An analyst gathers the following information about a US company:\nThe company's WACC is closest to:", "options": {"A": "8.0%.", "B": "8.4%.", "C": "9.2%."}, "answer": "C", "explanation": "A Incorrect because according to Modigliani–Miller Proposition I without taxes, the value of the levered company (VL) is equal to the value of the unlevered company (VU), and thus one cannot increase if the other decreases.\nB Incorrect because according to Modigliani–Miller Proposition I without taxes, the value of a company is determined solely by its expected future cash flows (not its relative use of debt versus equity capital).\nC Correct because according to Modigliani–Miller Proposition I without taxes, the value of a company is determined solely by its expected future cash flows (not its relative use of debt versus equity capital). It’s a firm’s future cash flows that are the primary driver of value, not capital structure."},
  {"num": 53, "subject": "公司发行人", "question": "According to Modigliani–Miller Proposition I without taxes, all else being equal, the value of a levered firm increases as its:", "options": {"A": "unlevered value decreases.", "B": "debt-to-equity ratio decreases.", "C": "expected future cash flows increase."}, "answer": "A", "explanation": "A Correct because in the Modigliani–Miller model, the cost of equity, re = r0 + (r0 – rd) × (1 – t) × (D/E). If the tax rate, t, increases, the product of the terms will decrease, decreasing the cost of equity. When t is not zero, the term (1 − t) is less than 1 and serves to reduce the cost of levered equity. The cost of equity still rises as the company increases the amount of debt in its capital structure, but it rises at a slower rate than in the no-tax case.\nB Incorrect because in the Modigliani–Miller model, the cost of equity, re = r0 + (r0 – rd) × (1 – t) × (D/E). If the tax rate, t, increases, the product of the terms will decrease, decreasing the cost of equity. The unlevered cost of equity, r0, will remain the same.\nC Incorrect because in the Modigliani–Miller model, the cost of equity, re = r0 + (r0 – rd) × (1 – t) × (D/E). If the tax rate, t, increases, the product of the terms will decrease, decreasing the cost of equity. However, as tax rates increase the value of the debt tax shield increases."},
  {"num": 54, "subject": "公司发行人", "question": "Based on Modigliani–Miller's Proposition II with taxes, if a firm has debt in its capital structure and the tax rate increases, the firm's cost of equity will:", "options": {"A": "decrease.", "B": "remain the same.", "C": "increase."}, "answer": "C", "explanation": "A Incorrect because the weighted average cost of capital is WACC = [(1 – Tax rate) × Pre-tax cost of debt × Weighting of debt] + (Cost of equity × Weighting of equity). Therefore, an increase in the weighting of equity increases [not decreases] the WACC.\nB Incorrect because the weighted average cost of capital is WACC = [(1 – Tax rate) × Pre-tax cost of debt × Weighting of debt] + (Cost of equity × Weighting of equity). Therefore, an increase in the pre-tax cost of debt increases [not decreases] the WACC.\nC Correct because the weighted average cost of capital is WACC = [(1 – Tax rate) × Pre-tax cost of debt × Weighting of debt] + (Cost of equity × Weighting of equity). Therefore, an increase in the tax rate decreases the pre-tax cost of debt which decreases the WACC."},
  {"num": 55, "subject": "公司发行人", "question": "A company's cost of equity capital exceeds its cost of debt capital. If interest expenses are tax deductible, which of the following most likely decreases the company’s weighted average cost of capital? An increase in the:", "options": {"A": "weighting of equity", "B": "pre-tax cost of debt", "C": "marginal corporate tax rate"}, "answer": "B", "explanation": "A Incorrect because it wrongly applies the tax deduction to the equity return: WACC = (Pre-tax Cost of debt × Weighting of debt) + [(1 – Tax rate) × Cost of equity × Weighting of equity] = 6% × 40% + (1 – 15%) × 10% × 60% = 7.50%.\nB Correct because WACC = [(1 – Tax rate) × Pre-tax cost of debt × Weighting of debt] + (Cost of equity × Weighting of equity) = (1 – 15%) × 6% × 40% + 10% × 60% = 8.04%.\nC Incorrect because it omits the tax deduction on the return of the debt: WACC = (Pre-tax Cost of debt × Weighting of debt) + (Cost of equity × Weighting of equity) = 6% × 40% + 10% × 60% = 8.40%."},
  {"num": 56, "subject": "公司发行人", "question": "An analyst gathers the following information about a corporation:\nIf the capital structure of the corporation is 40% debt and 60% equity, the WACC of the corporation is:", "options": {"A": "7.50%.", "B": "8.04%.", "C": "8.40%."}, "answer": "B", "explanation": "A Incorrect because an industry factor is a top-down (external) factor, whereas operating leverage is an an issuer-specific factor.\nB Correct because operating leverage is an issuer-specific factor. Debt and equity investors consider the risk and return profile of an issuer and adjust their required rates of return relative to base rates or broad averages by evaluating risk factors, including the following: 1. Sales risks 2. Profitability risks (operating leverage) 3. Financial leverage and interest coverage 4. Collateral/type of assets owned by the firm\nC Incorrect because a financial market factor is a top-down factor, whereas operating leverage is an issuer-specific factor."},
  {"num": 57, "subject": "公司发行人", "question": "With respect to capital structure, operating leverage is:", "options": {"A": "an industry factor.", "B": "an issuer-specific factor.", "C": "a financial market factor."}, "answer": "B", "explanation": "A Incorrect because capital structure policy is aligned to measures used by third parties.\nB Correct because market values can fluctuate substantially and seldom impact the appropriate level of borrowing.\nC Incorrect because for management, the primary concern is the amount and types of capital invested by the company, not in the company."},
  {"num": 58, "subject": "公司发行人", "question": "Target capital structure is often expressed using book values of equity and debt because:", "options": {"A": "capital structure policy is not aligned to measures used by third parties.", "B": "market values can fluctuate substantially and seldom impact the appropriate level of borrowing.", "C": "for management, the primary concern is the amount and types of capital invested in the company, not by the company."}, "answer": "B", "explanation": "A Incorrect because an IRR can be higher or lower than the required rate of return. The IRR decision rule is to invest if the IRR exceeds the required rate of return (r) for a capital investment. The WACC, after adjusting for any project-specific risks, is what issuers use as r in NPV analysis and as the hurdle rate for IRR analysis.\nB Correct because an issuer’s weighted-average cost of capital (WACC) blends its costs of debt and equity to obtain a single cost of capital. The WACC, after adjusting for any project-specific risks, is what issuers use as r in NPV analysis and as the hurdle rate for IRR analysis.\nC Incorrect because the cost of equity measures the return required by a company's equity investors, and ignores other sources of financing."},
  {"num": 59, "subject": "公司发行人", "question": "A company's required rate of return is its:", "options": {"A": "IRR.", "B": "WACC.", "C": "cost of equity."}, "answer": "A", "explanation": "A Correct because the debt level corresponding to D, which maximizes firm value, and the associated level of equity are referred to as the optimal capital structure.\nB Incorrect because the optimal capital structure optimizes firm value rather than equity value. Specifically, at low debt levels, the tax benefit of debt usually outweighs potential financial distress costs, resulting in a higher firm value. However, as debt increases, the possible financial distress costs rise substantially and equal the tax benefit of debt at D. Beyond this point, greater leverage reduces firm value, and the present value of financial distress costs outweighs the tax benefit. Because the tax shield from debt is less than the value of the debt itself, the difference is a reduction in equity value.\nC Incorrect because the optimal capital structure maximizes firm value, not the tax shield from debt. As debt increases, the possible financial distress costs rise substantially and equal the tax benefit of debt at D. Beyond this point, greater leverage reduces firm value. Note that the MM Propositions with taxes imply that the optimal capital structure is consistent with maximizing the tax shield from debt, as they ignore distress costs."},
  {"num": 60, "subject": "公司发行人", "question": "Under the static trade-off theory, the optimal capital structure maximizes:", "options": {"A": "firm value.", "B": "total equity value.", "C": "the tax shield from debt."}, "answer": "A", "explanation": "A Correct because in the case of capital structure decisions, savings in the agency costs of equity may arise with the increased use of debt. Similarly, the more financially leveraged a company, the less freedom for managers to either take on more debt or spend cash unwisely. This is the foundation of Michael Jensen’s (1986) free cash flow hypothesis.\nB Incorrect because the pecking order theory, developed by Stewart C. Myers and Nicholas S. Majluf in 1984, suggests that managers give first preference to financing methods with the least potential information content (internally generated funds) and last preference to methods with the most potential information content (public equity offerings).\nC Incorrect because the value-enhancing effect of the tax shield from leverage is offset by the value-reducing impact of the present value of expected (or probability-weighted) costs of financial distress or bankruptcy. We can show this trade-off by incorporating the potential cost of financial distress or bankruptcy into the value of a levered firm:"},
  {"num": 61, "subject": "公司发行人", "question": "An increased use of debt may result in a reduction in the agency costs of equity according to the:", "options": {"A": "free cash flow hypothesis.", "B": "pecking order theory of capital structure.", "C": "static trade-off theory of capital structure."}, "answer": "A", "explanation": "A Correct because using market value weights based on the current capital components is the baseline method recommended. Because the book value of the capital components based on historical values of the capital sources likely will be significantly different from market value, book value is not one of the three recommended approaches.\nB Incorrect because using market value weights from the current capital structure is the baseline method recommended. Individuals outside the company, however, such as analysts, typically do not know the target capital structure and must estimate it by assuming the company’s current capital structure, at market value weights for the components, represents the company’s target capital structure.\nC Incorrect because using management statements to infer capital structure is one of the recommended methods. Individuals outside the company, however, such as analysts, typically do not know the target capital structure and must estimate it by examining trends in the company’s capital structure or statements by management regarding capital structure policy to infer the target capital structure."},
  {"num": 62, "subject": "公司发行人", "question": "When a company's target capital structure is unknown to analysts, which of the following is the least appropriate method to estimate the capital structure weights?", "options": {"A": "Using the book values of capital components", "B": "Using current market values of capital components", "C": "Analyzing management's statements to infer the target capital structure"}, "answer": "A", "explanation": "A Correct because if interest can be deducted in full, the tax deductibility of debt reduces the effective marginal cost of debt to reflect the income shielded from taxation and the marginal cost of debt is rd(1 – t). A higher tax rate would result in an increase in the tax deductibility of interest and result in a lower cost of debt and WACC.\nB Incorrect because if interest can be deducted in full, the tax deductibility of debt reduces the effective marginal cost of debt to reflect the income shielded from taxation and the marginal cost of debt is rd(1 – t). A higher tax rate would result in an increase in the tax deductibility of interest and result in a lower cost of debt and WACC.\nC Incorrect because if interest can be deducted in full, the tax deductibility of debt reduces the effective marginal cost of debt to reflect the income shielded from taxation and the marginal cost of debt is rd(1 – t). A higher tax rate would result in an increase in the tax deductibility of interest and result in a lower cost of debt and WACC."},
  {"num": 63, "subject": "公司发行人", "question": "All else being equal, if interest on a company's debt is tax deductible, an increase in the tax rate will most likely:", "options": {"A": "decrease the WACC.", "B": "have no impact on the WACC.", "C": "increase the WACC."}, "answer": "A", "explanation": "A Correct because an increase in the marginal tax rate will cause the after-tax cost of debt to decrease (with no effect on the cost of preferred or common), all else being equal. WACC is calculated using the following formula: WACC = wd × rd × (1 – t) + wp × rp + we × re where wd = the proportion of debt the company uses when it raises new funds rd = the before-tax marginal cost of debt t = the company's marginal tax rate wp = the proportion of preferred stock the company uses when it raises new funds rp = the marginal cost of preferred stock we = the proportion of equity the company uses when it raises new funds re = the marginal cost of equity An increase in the tax rate causes the value of (1 – t) to decrease resulting in a decrease in both the after-tax cost of debt and the WACC.\nB Incorrect because an increase in the marginal tax rate will cause the after-tax cost of debt to decrease.\nC Incorrect because an increase in the marginal tax rate will cause the after-tax cost of debt to decrease."},
  {"num": 64, "subject": "公司发行人", "question": "All else being equal, if a US company's marginal tax rate increases, the company's WACC will most likely:", "options": {"A": "decrease.", "B": "remain unchanged.", "C": "increase."}, "answer": "B", "explanation": "A Incorrect because a firm’s value chain is the systems and processes within a firm that create value for its customers. Note that a firm’s value chain is different from a supply chain, which refers to the sequence of processes involved in the creation of a product, both within and external to a firm.\nB Correct because a supply chain refers to the sequence of processes involved in the creation of a product, both within and external to a firm. A supply chain includes all the steps involved in producing and delivering a physical product to the end customer, regardless of whether those steps are performed by a single firm.\nC Incorrect because there is no precise definition, but a business model essentially describes how a business is organized to deliver value to its customers. A business model makes it clear what the business does, how it operates, and how it generates revenue and profits, as well as how it differs in these respects from its competitors. A business model should have a value proposition and a value chain. So, business model is a broader concept, which includes value chain but also other business organization elements."},
  {"num": 65, "subject": "公司发行人", "question": "The sequence of processes involved in the creation of a product, both within and external to a firm, is best referred to as a:", "options": {"A": "value chain.", "B": "supply chain.", "C": "business model."}, "answer": "C", "explanation": "A Incorrect because a platform business is based on a network and can be distinguished from a traditional or 'linear' business that adds value to something that is sold to customers in a linear supply chain. Platform business models are not developed specifically to allow users to contribute directly to product, service, or online content.\nB Incorrect because marketplace businesses create networks of buyers and sellers without taking ownership of the goods during the process. Examples include: Alibaba, eBay, Mercado Libre, and Etsy. Marketplace business models are not developed specifically to allow users to contribute directly to product, service, or online content.\nC Correct because crowdsourcing business models enable users to contribute directly to a product, service, or online content. Examples include: contests and competitions; online gaming; product development, such as open source software; knowledge aggregation, such as Wikipedia and Waze/Google Maps; fan or hobbyist clubs; and networks of tradespersons or professionals."},
  {"num": 66, "subject": "公司发行人", "question": "The business model of a knowledge aggregation company that allows its users to contribute directly to online content is best referred to as a:", "options": {"A": "platform business model.", "B": "marketplace business model.", "C": "crowdsourcing business model."}, "answer": "C", "explanation": "A Incorrect because penetration pricing, rather than dynamic pricing, is used. Dynamic pricing charges different prices at different times. Specific examples include off-peak pricing (e.g., for hotel rooms, advertising, airline tickets, electricity, or matinee movie tickets), 'surge' pricing, and 'congestion' pricing (e.g., for ride sharing and toll roads).\nB Incorrect because penetration pricing, rather than freemium pricing, is used. Freemium pricing allows customers a certain level of usage or functionality at no charge—for example, with news content, a software application, or a game. This model is widely used in digital content and services, such as periodicals, video games, software/apps, and cloud storage, where the provider stands to benefit from wide adoption (often via network effects).\nC Correct because penetration pricing is an example of discount pricing and is used when a firm willingly sacrifices margins in order to build scale and market share."},
  {"num": 67, "subject": "公司发行人", "question": "Which of the following pricing models is most likely used when a firm willingly sacrifices margins to build market share?", "options": {"A": "Dynamic pricing", "B": "Freemium pricing", "C": "Penetration pricing"}, "answer": "C", "explanation": "A Incorrect because under a franchise model distributers or retailers have a tightly defined and often exclusive relationship with the parent company.\nB Incorrect because private label or contract manufacturers produce goods to be marketed by others.\nC Correct because a company will produce a product using someone else’s brand name in return for a royalty under a licensing arrangement."},
  {"num": 68, "subject": "公司发行人", "question": "A company manufacturing and selling a product using someone else's brand name in return for a royalty most likely operates:", "options": {"A": "under a franchise model.", "B": "as a contract manufacturer.", "C": "under a licensing arrangement."}, "answer": "C", "explanation": "A Incorrect because manufacturers [sometimes] employ a direct sales strategy, selling directly to the end customer. Direct sales to the end customer bypass ('disintermediate') the distributor or retailer. Typically, this involves the company's own sales force, which in some cases represents a significant business investment and carrying cost for the firm.\nB Incorrect because, with an omnichannel strategy, both digital and physical channels are used to complete a sale. For example, a customer might order an item online and pick it up in a store ('click and collect') or select an item in a store and have it delivered. Thus, an omnichannel strategy does not say anything about the flow of goods from manufacturer to wholesaler, retailer, and then end customer.\nC Correct because, for 'product' businesses, the traditional channel strategy is typically reflected in the flow of finished goods (e.g., from manufacturer to wholesaler, retailer, and end customer), each with its own physical facilities and with the product sold and purchased at each stage."},
  {"num": 69, "subject": "公司发行人", "question": "The flow of finished goods from manufacturer to wholesaler, retailer, and finally to the end customer best describes a(n):", "options": {"A": "direct sales strategy.", "B": "omnichannel strategy.", "C": "traditional channel strategy."}, "answer": "B", "explanation": "A Incorrect because a clearly described business model helps the analyst understand a business: how it operates, its strategy, target customers, key partners, prospects, risks, and financial profile.\nB Correct because a clearly described business model helps the analyst understand a business: how it operates, its strategy, target customers, key partners, prospects, risks, and financial profile. Rather than rely on management’s description of its business model, analysts should develop their own understanding.\nC Incorrect because rather than rely on management’s description of its business model, analysts should develop their own understanding."},
  {"num": 70, "subject": "公司发行人", "question": "When analyzing a company, analysts should:", "options": {"A": "ignore the company's business model.", "B": "develop their own understanding of the company's business model.", "C": "rely on management's description of the company's business model."}, "answer": "C", "explanation": "A Incorrect because an issuer’s income statement distinguishes between its financial income or net income once fixed obligations have been met and its 'economic' profit, or return to a firm’s owners in excess of what they could have earned elsewhere on different investments, known as their required rate of return on equity.\nB Incorrect because an issuer’s income statement distinguishes between its financial income or net income once fixed obligations have been met and its 'economic' profit, or return to a firm’s owners in excess of what they could have earned elsewhere on different investments, known as their required rate of return on equity.\nC Correct because an issuer’s income statement distinguishes between its financial income or net income once fixed obligations have been met and its 'economic' profit, or return to a firm’s owners in excess of what they could have earned elsewhere on different investments, known as their required rate of return on equity."},
  {"num": 71, "subject": "公司发行人", "question": "\"Economic\" profit is best described as the return to a firm's owners:", "options": {"A": "in the form of retained earnings and distributions to the owners.", "B": "after corporate taxes and taxes on distributions have been paid.", "C": "in excess of what they could have earned elsewhere on different investments."}, "answer": "A", "explanation": "A Correct because debt must be repaid on a pre-specified date in the future with interest.\nB Incorrect because equity investors (shareholders) have a right to receive any distributions of profits, known as dividends. However, while shareholder have the right to receive dividends, the corporation is not required to pay dividends.\nC Incorrect because equity investors (shareholders) have a right to receive any distributions of profits, known as dividends. However, while shareholder have the right to receive dividends, they corporation is not required to pay dividends."},
  {"num": 72, "subject": "公司发行人", "question": "If a corporation is financed with both debt and equity, which of the following must the corporation pay?", "options": {"A": "Interest only", "B": "Dividends only", "C": "Both interest and dividends"}, "answer": "A", "explanation": "A Correct because tiered pricing is charging different prices to different buyers, often based on volume purchased but also based on product features (e.g., base versus premium trims of vehicles).\nB Incorrect because dynamic pricing is charging different prices at different times and for different types of customers depending on such variables as available supply levels and demand.\nC Incorrect because value based pricing is setting prices based on the value received by the customer, which often involves estimating opportunity cost."},
  {"num": 73, "subject": "公司发行人", "question": "Charging prices that differ based on product features or volume purchased best describes:", "options": {"A": "tiered pricing.", "B": "dynamic pricing.", "C": "value-based pricing."}, "answer": "A", "explanation": "A Correct because short-term debt is included in a company's financial balance sheet.\nB Incorrect because contracts with customers and other intangible assets are excluded from a company's financial balance sheet but are included on the issuer's broader \"economic\" balance sheet.\nC Incorrect because agreements with suppliers and other intangible assets are excluded from a company's financial balance sheet but are included on the issuer's broader \"economic\" balance sheet."},
  {"num": 74, "subject": "公司发行人", "question": "Which of the following would most likely be included on a company's \"financial\" balance sheet?", "options": {"A": "Short-term debt obligations", "B": "Relationships with customers", "C": "Relationships with key suppliers"}, "answer": "C", "explanation": "A Incorrect because value added resellers not only distribute a product but also handle more complex aspects of product installation, customization or support.\nB Incorrect because licensing arrangements are business models in which a company will produce a product using someone else's brand name in return for a royalty.\nC Correct because contract manufacturers produce goods to be marketed by others."},
  {"num": 75, "subject": "公司发行人", "question": "A company that produces goods to be marketed by other firms is best described as having a:", "options": {"A": "value added reseller business model.", "B": "licensing arrangement business model.", "C": "contract manufacturer business model."}, "answer": "C", "explanation": "A Incorrect because key features of limited partnerships include the following: ● GP operates the business, having unlimited liability, ● LPs have limited liability but lack control over business operations. Due to multiple partners and partnership agreement, this structure is not as simple and flexible as a sole proprietorship. Key features of sole proprietorships include: Operational simplicity and flexibility.\nB Incorrect because a general partnership has two or more owners called partners whose roles and responsibilities in the business are outlined in a partnership agreement. As such, this structure is not as simple and flexible as a sole proprietorship. Key features of sole proprietorships include: Operational simplicity and flexibility.\nC Correct because the simplest business structure is the sole proprietorship, also called the sole trader. Key features of sole proprietorships include: Operational simplicity and flexibility."},
  {"num": 1, "subject": "股权投资", "question": "Which of the following financial intermediaries is most likely to provide liquidity service to its clients?", "options": {"A": "Brokers", "B": "Dealers", "C": "Exchanges"}, "answer": "B", "explanation": "A Incorrect . Brokers are agents who fill orders for their clients. They do not trade with their clients.\nB Correct . The service that dealers provide is liquidity. Liquidity is the ability to buy or sell with low transaction costs when investors want to trade. By allowing their clients to trade when they want to trade, dealers provide liquidity to them.\nC Incorrect . Exchanges provide places where traders and dealers can meet to arrange their trades."},
  {"num": 2, "subject": "股权投资", "question": "An investor writes a put option on FTSE 100 Index futures. Which of the following best describes the investor’s position with respect to the put contract and her exposure to the underlying index future, respectively?", "options": {"A": "Long, short", "B": "Short, long", "C": "Short, short"}, "answer": "B", "explanation": "A Incorrect . The investor has a short position in the put contract, not a long position, because she suffers a loss when the quoted price of the contract increases. The investor has a long exposure to the underlying index future, not a short position, because she benefits when its quoted price increases (or suffers a loss when its quoted price decreases).\nB Correct . The investor has written a put contract, which means she is short the option. She, therefore, must satisfy the obligation to purchase the asset if requested to do so by the put owner. The investor has a long exposure to the risk of the underlying index future because she benefits when its quoted price increases—that is, when the put declines in value (or suffers a loss when its quoted price decreases as the put increases in value).\nC Incorrect . The investor has a long exposure to the underlying index future, not a short position, because she benefits when its quoted price increases (or suffers a loss when its quoted price decreases)."},
  {"num": 3, "subject": "股权投资", "question": "If securities are purchased on margin with a maximum leverage ratio of 1.75, the minimum margin requirement is closest to:", "options": {"A": "43%.", "B": "57%.", "C": "75%."}, "answer": "B", "explanation": "A Incorrect because it is (1 – the minimum margin requirement): 1 – (1 / 1.75) = 43%.\nB Correct because the maximum leverage ratio associated with a position financed by the minimum margin requirement is one divided by the minimum margin requirement. Or, MLR = 1 / MMR and MMR = 1 / MLR. In this case: the minimum margin requirement (MMR) = 1 / 1.75 = 57%.\nC Incorrect because it is (the maximum leverage ratio – 1) = 1.75 – 1 = 75%."},
  {"num": 4, "subject": "股权投资", "question": "When a company raises common equity capital in the public market, the company most likely:", "options": {"A": "moves money from the present to the future.", "B": "agrees to make scheduled distributions in the future.", "C": "is required to meet regulatory reporting requirements."}, "answer": "C", "explanation": "A Incorrect because companies often raise money for projects by selling (issuing) ownership interests (e.g., corporate common stock or partnership interests). Although these equity instruments legally represent ownership in companies rather than loans to the companies, selling equity to raise capital is simply another mechanism for moving money from the future to the present.\nB Incorrect because when shareholders or partners contribute capital to a company, the company obtains money in the present in exchange for equity instruments that will be entitled to distributions in the future. The repayment of the money is not scheduled as it would be for loans.\nC Correct because when a company sells common stock to raise capital, regulatory reporting requirements and accounting standards attempt to ensure the production of meaningful financial disclosures."},
  {"num": 5, "subject": "股权投资", "question": "A trader reports the following information about an equity investment which was sold after 1 year:\nThe trader's equity value as a result of the trade is closest to:", "options": {"A": "$460.", "B": "$2,520.", "C": "$3,000."}, "answer": "B", "explanation": "A Incorrect because it uses the leverage ratio debt / equity invested instead of dividing the total equity investment by the leverage ratio. The incorrect answer is calculated as follows: Proceeds on sale – payoff amount borrowed – payoff loan interest Amount paid to purchase shares = $12 × 2,000 = $24,000 Equity investment = $24,000/4 = $6,000 Amount borrowed = $24,000 – $6,000 = $18,000 Interest on loan = $18,000 × 3% = $540 Therefore, remaining equity = 2,000 × $9.5 – $18,000 – 3% × $18,000 = $19,000 – $18,000 – $540 = $460.\nB Correct because the remaining equity can be calculated as: Proceeds on sale – payoff amount borrowed – payoff loan interest Amount paid to purchase shares = $12 × 2,000 = $24,000 Equity investment = $24,000/3 = $8,000 Amount borrowed = $24,000 - $8,000 = $16,000 Interest on loan = $16,000 × 3% = $480 Therefore, remaining equity = 2,000 × $9.5 – $16,000 – 3% × $16,000 = $19,000 – $16,000 – $480 = $2,520.\nC Incorrect because payoff loan interest is omitted from the calculation of the trader's remaining equity."},
  {"num": 6, "subject": "股权投资", "question": "Order matching rules in order-driven trading systems are used to:", "options": {"A": "match buy orders to sell orders.", "B": "determine the prices at which the orders submitted by dealers are matched.", "C": "determine the prices at which the orders submitted by customers are matched."}, "answer": "A", "explanation": "A Correct because the order matching rules match buy orders to sell orders.\nB Incorrect because the trade pricing rules (not the order matching rules) determine the prices at which the matched trades take place, regardless of who submits the order, the customer or dealer.\nC Incorrect because the trade pricing rules (not the order matching rules) determine the prices at which the matched trades take place, regardless of who submits the order, the customer or the dealer."},
  {"num": 7, "subject": "股权投资", "question": "A sell order that instructs the broker to obtain the best price immediately available without specifying a minimum price is a:", "options": {"A": "stop order.", "B": "limit order.", "C": "market order."}, "answer": "C", "explanation": "A Incorrect because a stop order is an order in which a trader has specified a stop price condition. The stop order may not be filled until the stop price condition has been satisfied. Stop-sell orders become valid when prices are falling and stop-buy orders become valid when prices are rising, in contrast with market orders which execute at the best price immediately available.\nB Incorrect because in the case of a limit order, its execution depends on where the order is placed relative to the market price, as the broker will obtain the best price immediately available, but in no event accept a price higher than a specified limit price when buying or accept a price lower than a specified limit price when selling.\nC Correct because a market order instructs the broker or exchange to obtain the best price immediately available when filling the order."},
  {"num": 8, "subject": "股权投资", "question": "Which of the following is an objective of market regulation?", "options": {"A": "Controlling agency problems only", "B": "Ensuring that long-term liabilities are funded only", "C": "Both controlling agency problems and ensuring that long-term liabilities are funded"}, "answer": "C", "explanation": "A Incorrect because the objectives of market regulation are to control agency problems and ensure that long-term liabilities are funded. Therefore, an objective of market regulation is not to control agency problems only.\nB Incorrect because the objectives of market regulation are to control agency problems and ensure that long-term liabilities are funded. Therefore, an objective of market regulation is not to ensure that long-term liabilities are funded only.\nC Correct because the objectives of market regulation include both controlling agency problems and ensuring that long-term liabilities are funded. In total, the objectives of market regulation are:"},
  {"num": 9, "subject": "股权投资", "question": "If a European investor believes the US equity market will decline in the next three months, the transaction most likely to allow the investor to profit from this view is the purchase of a:", "options": {"A": "put option.", "B": "call option.", "C": "currency swap."}, "answer": "A", "explanation": "A Correct because option holders generally will exercise call options if the strike price is below the market price of the underlying instrument, in which case, they will be able to buy at a lower price than the market price. Similarly, they will exercise put options if the strike price is above the underlying instrument price so that they will sell at a higher price than the market price. Therefore, if the investor purchases a put option and the US market declines, they will profit by buying at the lower market price and selling at the higher strike price.\nB Incorrect because option holders generally will exercise call options if the strike price is below the market price of the underlying instrument, in which case, they will be able to buy at a lower price than the market price. Similarly, they will exercise put options if the strike price is above the underlying instrument price so that they will sell at a higher price than the market price.\nC Incorrect because a currency swap is a swap in which parties exchange payments denominated in different currencies. A currency swap will most likely not allow a European investor to profit from the decline in the US equity market."},
  {"num": 10, "subject": "股权投资", "question": "When issuers sell securities to investors:", "options": {"A": "they trade in the primary market.", "B": "they trade in the secondary market.", "C": "funds flow between the primary and the secondary market."}, "answer": "A", "explanation": "A Correct because when issuers sell securities to investors, practitioners say that they trade in the primary market.\nB Incorrect because when issuers sell securities to investors, practitioners say that they trade in the primary market. When investors sell those securities to others, they trade in the secondary market.\nC Incorrect because when issuers sell securities to investors, practitioners say that they trade in the primary market. When investors sell those securities to others, they trade in the secondary market. In the primary market, funds flow to the issuer of the security from the purchaser. In the secondary market, funds flow between traders."},
  {"num": 11, "subject": "股权投资", "question": "If the price of a stock bought on 30% margin increases by 40%, the return on equity to the buyer is closest to:", "options": {"A": "52%.", "B": "75%.", "C": "133%."}, "answer": "C", "explanation": "A Incorrect because it calculates return on equity as unleveraged return × (1 + margin) = 40% × (1 + 30%) = 52%.\nB Incorrect because it calculates return on equity as margin / return = 30%/40% = 75%. In other words, it incorrectly swaps the numerator and denominator in the correct solution (40%/30% becomes 30%/40%).\nC Correct because the return on equity to a margin position is calculated by multiplying the unleveraged return by the financial leverage ratio. The financial leverage ratio is equal to 1/margin. In this case, financial leverage is 1/0.30 = 3.3333, so the return on equity = 40% × 3.3333 = 133.33%, which is closest to 133%."},
  {"num": 12, "subject": "股权投资", "question": "In which markets are government bills most likely traded?", "options": {"A": "Money markets", "B": "Capital markets", "C": "Alternative investment markets"}, "answer": "A", "explanation": "A Correct because money markets trade debt instruments maturing in one year or less. The most common such instruments are repurchase agreements, negotiable certificates of deposit, government bills.\nB Incorrect because capital markets trade instruments of longer duration, such as bonds and equities. Whereas government bills are a short-term debt instrument.\nC Incorrect because alternative investments include hedge funds, private equities (including venture capital), commodities, real estate securities and real estate properties, securitized debts, operating leases, machinery, collectibles, and precious gems."},
  {"num": 13, "subject": "股权投资", "question": "Financial intermediaries that help their clients arrange seasoned securities offerings are best known as:", "options": {"A": "investment banks.", "B": "commercial banks.", "C": "multi-lateral trading facilities."}, "answer": "A", "explanation": "A Correct because investment banks provide advice to their mostly corporate clients and help them arrange transactions such as initial and seasoned securities offerings. Additionally, a seasoned security is a security that an issuer has already issued. If the issuer wants to sell additional units of a previously issued security, it makes a seasoned offering (sometimes called a secondary offering).\nB Incorrect because depository institutions include commercial banks, savings and loan banks, credit unions, and similar institutions that raise funds from depositors and other investors and lend it to borrowers. The banks give their depositors interest and transaction services, such as check writing and check cashing, in exchange for using their money.\nC Incorrect because multilateral trading facilities (MTFs) are trading venues that function like exchanges but that do not exercise regulatory authority over their subscribers except with respect to the conduct of their trading in their trading systems."},
  {"num": 14, "subject": "股权投资", "question": "In the secondary market, funds flow from:", "options": {"A": "traders to traders.", "B": "issuers to investors.", "C": "investors to issuers."}, "answer": "A", "explanation": "A Correct because when investors sell securities to others, they trade in the secondary market. In the secondary market, funds flow between traders.\nB Incorrect because in the secondary market, funds flow between traders, while in the primary market, funds flow to the issuer of the security from the purchaser (not vice versa).\nC Incorrect because in the primary (not secondary) market, funds flow to the issuer of the security from the purchaser (investors)."},
  {"num": 15, "subject": "股权投资", "question": "Short sellers are most likely exposed to:", "options": {"A": "unlimited gains and limited losses.", "B": "limited gains and unlimited losses.", "C": "unlimited gains and unlimited losses."}, "answer": "B", "explanation": "A Incorrect because the potential gains on a short position are limited to no more than 100 percent whereas the potential losses are unbounded.\nB Correct because short sellers create short positions in securities by borrowing securities from security lenders who are long holders. The short sellers then sell the borrowed securities to other traders. The potential gains on a short position are limited to no more than 100 percent whereas the potential losses are unbounded.\nC Incorrect because the potential gains on a short position are limited to no more than 100 percent whereas the potential losses are unbounded."},
  {"num": 16, "subject": "股权投资", "question": "An instruction that indicates when an order may be filled is most likely a(n):", "options": {"A": "validity instruction.", "B": "clearing instruction.", "C": "execution instruction."}, "answer": "A", "explanation": "A Correct because validity instructions indicate when the order may be filled.\nB Incorrect because clearing instructions indicate how to arrange the final settlement of the trade, not when the order may be filled.\nC Incorrect because execution instructions indicate how to fill the order, not when the order may be filled."},
  {"num": 17, "subject": "股权投资", "question": "Broker 1 has a minimum margin requirement of 62.5% and Broker 2 has a maximum leverage ratio of 1.6. The maximum financial leverage possible with Broker 1 is:", "options": {"A": "less than the maximum financial leverage with Broker 2.", "B": "equal to the maximum financial leverage with Broker 2.", "C": "greater than the maximum financial leverage with Broker 2."}, "answer": "B", "explanation": "A Incorrect because the leverage ratios with the two brokers are the same at both firms given Broker 1's margin requirement and Broker 2's maximum leverage ratio. Leverage Ratio = 100% / margin requirement: Broker 1 leverage ratio = 100% / 62.5% = 1.6 = Broker 2's leverage ratio.\nB Correct because the maximum financial leverage is the same at both firms given Broker 1's margin requirement and Broker 2's maximum leverage ratio. Leverage Ratio = 100% / margin requirement: Broker 1 leverage ratio = 100% / 62.5% = 1.6 = Broker 2's leverage ratio.\nC Incorrect because the leverage ratios with the two brokers are the same at both firms given Broker 1's margin requirement and Broker 2's maximum leverage ratio. Leverage Ratio = 100% / margin requirement: Broker 1 leverage ratio = 100% / 62.5% = 1.6 = Broker 2's leverage ratio."},
  {"num": 18, "subject": "股权投资", "question": "Which of the following is most likely used to raise funds for a capital project?", "options": {"A": "Equity issuance only", "B": "A stock dividend only", "C": "Both equity issuance and a stock dividend"}, "answer": "A", "explanation": "A Correct because companies often raise money for projects by selling (issuing) ownership interests (e.g., corporate common stock or partnership interests). Although these equity instruments legally represent ownership in companies rather than loans to the companies, selling equity to raise capital is simply another mechanism for moving money from the future to the present.\nB Incorrect because issuing a stock dividend would not be an activity the company would do to fund a capital project. Stock dividends are a non-cash form of dividends and the company distributes additional shares of its common stock to shareholders instead of cash. Thus stock dividends will flow to shareholders, not the capital project.\nC Incorrect because issuing a stock dividend would not be an activity the company would do to fund a capital project. Stock dividends are a non-cash form of dividends and the company distributes additional shares of its common stock to shareholders instead of cash. Thus stock dividends will flow to shareholders, not the capital project."},
  {"num": 19, "subject": "股权投资", "question": "Clearing instructions for an order most likely indicate:", "options": {"A": "how to fill the order.", "B": "when the order may be filled.", "C": "how to arrange the settlement of the trade."}, "answer": "C", "explanation": "A Incorrect because execution instructions indicate how to fill the order.\nB Incorrect because validity instructions indicate when the order may be filled.\nC Correct because clearing instructions indicate how to arrange the final settlement of the trade."},
  {"num": 20, "subject": "股权投资", "question": "A trader observes the following limit order book for a stock:\nIf the trader submits an order to buy 20 shares at a limit price of $76.00, the trader's average price per share for this trade based on the current order book will be closest to:", "options": {"A": "$75.80.", "B": "$75.97.", "C": "$76.00."}, "answer": "B", "explanation": "A Incorrect because this would mistake a bid and an offer by incorrectly concluding that a size/order of 20 corresponds to $75.80.\nB Correct because a limit order conveys the instruction to obtain the best price immediately available, but in no event accept a price higher than a specified limit price ($76.00) when buying. That is, 15 units of the stock would trade or execute immediately based on the current order book: 5 units at $75.90 and 10 units at $76.00. The average trade price per unit = ((5 × $75.90) + (10 × $76.00)) / 15 ≈ $75.97.\nC Incorrect because this would neglect that the order is a limit order and calculates the average trade price per unit based on 20 units: (($75.90 × 5) + ($76.00 × 10) + ($76.10 × 5)) / 20 = $76.00."},
  {"num": 21, "subject": "股权投资", "question": "A trader buys a stock on margin with the following conditions:\nIf the share price declines, the highest price at which the trader will receive a margin call is closest to:", "options": {"A": "$12.50.", "B": "$33.33.", "C": "$37.50."}, "answer": "B", "explanation": "A Incorrect because at a share price of $12.50 and a margin loan of $25, equity will be negative. $12.50 is 25% of the current price of $50 per share.\nB Correct because the original equity of $25 indicates a margin loan of $25 ($50 ‒ $25). At a stock price of $33.33, equity will equal $33.33 less the $25 margin loan, or $8.33, which is 25% of the equity per share. $8.33 ⁄ $33.33 ≈ 25%. To reach this answer through calculation, determine where the equity per share equals the 25% margin requirement: Equity ⁄ Share = (P ‒ L) ⁄ P = maintenance margin; Where P = Share price and L = Loan amount; 0.25 = (P ‒ $25) ⁄ P; P ≈ $33.33.\nC Incorrect because (1 – maintenance margin) × price = (1 – 0.25) × $50 = $37.50."},
  {"num": 22, "subject": "股权投资", "question": "An investor buys a security on margin posting 50% of the initial price as equity. All else being equal, if the price declines 25%, the investor's new leverage ratio is closest to:", "options": {"A": "2.", "B": "3.", "C": "4."}, "answer": "B", "explanation": "A Incorrect because 2 is the starting leverage before the price change, 1/0.5 = 2.\nB Correct because the leverage ratio is defined as the ratio of the value of the position to the value of the equity investment in it. The leverage ratio indicates how many times larger a position is than the equity that supports it. The starting leverage = value ∕equity = 1 ∕ 0.5 = 2 The change in market value is given as 25% decline, implying a new market value of 75%. With leverage of 2, new equity reduces by 2 × 25% = 50%, 50% × 50% = remaining equity of 25%. New leverage = new value ∕ new equity = 0.75 ∕ 0.25 = 3. Expressed alternatively: New leverage = (1 ‒ 0.25) ∕ (0.5 ‒ 0.25) = 3.\nC Incorrect because the amount of the price decline is used instead of the margin to calculate the leverage ratio, 1 ∕ 0.25 = 4."},
  {"num": 23, "subject": "股权投资", "question": "When an investment bank guarantees the sale of an entire issue at a negotiated offering price, this best describes a(n):", "options": {"A": "rights offering.", "B": "best effort offering.", "C": "underwritten offering."}, "answer": "C", "explanation": "A Incorrect because corporations can issue new stock via a rights offering. In a rights offering, the corporation distributes rights to buy stock at a fixed price to existing shareholders in proportion to their holdings.\nB Incorrect because in a best effort offering, the investment bank acts only as broker. They do not guarantee the sale of the entire issue at a negotiated offering price.\nC Correct because in an underwritten offering—the most common type of offering—the investment bank guarantees the sale of the issue at an offering price that it negotiates with the issuer."},
  {"num": 24, "subject": "股权投资", "question": "In a well-functioning financial system, changes in asset prices primarily reflect changes in:", "options": {"A": "execution costs.", "B": "the demand for liquidity.", "C": "fundamental asset values."}, "answer": "C", "explanation": "A Incorrect because well functioning financial systems are characterized by liquid markets in which the costs of trading are low (operationally efficient markets) and therefore execution costs would not impact asset prices.\nB Incorrect because well functioning financial systems are characterized by prices that reflect fundamental values so that prices vary primarily in response to changes in fundamental values and not to demands for liquidity made by uninformed traders (informationally efficient markets).\nC Correct because well functioning financial systems are characterized by prices that reflect fundamental values so that prices vary primarily in response to changes in fundamental values and not to demands for liquidity made by uninformed traders (informationally efficient markets)."},
  {"num": 25, "subject": "股权投资", "question": "If the ability of clients to identify competent agents increases, the need for regulation most likely:", "options": {"A": "decreases.", "B": "remains the same.", "C": "increases."}, "answer": "A", "explanation": "A Correct because regulation would not be necessary if customers could identify competent agents and effectively measure their performance. Therefore an increase in client ability to identify competent agents would reduce the need for regulation.\nB Incorrect because the clients' difficulty in identifying competent agents results in a regulatory need. An increase in their ability to select competent agents would reduce this regulatory need.\nC Incorrect because the clients' difficulty in identifying competent agents results in a regulatory need. An increase in their ability to select competent agents would reduce, not increase, this regulatory need."},
  {"num": 26, "subject": "股权投资", "question": "If the cost to fill trades increases, the market's informational efficiency most likely:", "options": {"A": "decreases.", "B": "remains the same.", "C": "increases."}, "answer": "A", "explanation": "A Correct because how accurately prices reflect fundamental information depends on the costs of obtaining fundamental information and on the liquidity available to well-informed traders. If filling orders is very costly, informed trading may not be profitable. In that case, information-motivated traders will not commit resources to collect and analyze data and they will not trade. Without their research and their associated trading, prices would be less informative.\nB Incorrect because trading costs do impact informational efficiency: higher costs result in less informed trading and thereby a decrease in efficiency.\nC Incorrect because higher trading costs result in less informed trading and thereby a decrease in efficiency."},
  {"num": 27, "subject": "股权投资", "question": "If 1,000 shares of stock purchased at $30 per share on 75% margin are later sold at $26 per share, the return on equity is closest to:", "options": {"A": "–17.8%.", "B": "–13.3%.", "C": "–10.0%."}, "answer": "A", "explanation": "A Correct because it has correctly applied margin requirement and calculated the effect of leverage on the return calculation, accordingly: Cost of purchase = Shares purchased × Purchase price = 1,000 × $30 = $30,000 Initial investment = Equity invested = Cost of purchase × Margin requirement = $30,000 × 75% = $22,500 Proceeds from sale = Shares sold × Sales price = 1,000 × $26 = $26,000 Loss on the position = Proceeds from Sale – Cost of purchase = $26,000 – $30,000 = –$4,000 Return on investment = Loss on the position / Initial investment = –$4,000 / $22,500 = 0.1777… ≈ 17.78% Alternatively, it can also be calculated as Return on investment = Loss on the position / Cost of purchase / Margin requirement = (–$4,000 / $30,000) / 75% = –0.1777… ≈ –17.78%\nB Incorrect because it has omitted the margin requirement and the effect of leverage on the return calculation, consequently: Cost of purchase = Shares purchased × Purchase price = 1,000 × $30 = $30,000 Initial investment = Cost of purchase = $30,000 Proceeds from sale = Shares sold × Sales price = 1,000 × $26 = $26,000 Loss on the position = Proceeds from Sale – Cost of purchase = $26,000 – $30,000 = –$4,000 Return on investment = Loss on the position / Initial investment = –$4,000 / $30,000 = –0.1333… ≈ –13.33%\nC Incorrect because it has incorrectly applied margin requirement and miscalculated the effect of leverage on the return calculation, consequently:"},
  {"num": 28, "subject": "股权投资", "question": "The market structure that uses trade pricing rules to match buyers and sellers is most likely a(n):", "options": {"A": "brokered market.", "B": "order-driven market.", "C": "quote-driven market."}, "answer": "B", "explanation": "A Incorrect because in brokered markets, brokers arrange trades between their customers. Brokered markets are common for transactions of unique instruments, such as real estate. Furthermore, brokers help find traders who are willing to trade when dealers would not be willing to make markets and when traders would not be willing to post orders.\nB Correct because order-driven trading systems match buyers to sellers using rules that rank the buy orders and the sell orders based on price, and often along with other secondary criteria.\nC Incorrect because in quote-driven markets, customers trade at the prices quoted by dealers. This is a form of OTC trading. Dealers make markets and are available to supply liquidity."},
  {"num": 29, "subject": "股权投资", "question": "Which of the following financial intermediaries most likely buy and sell similar instruments at different prices in different markets?", "options": {"A": "Dealers", "B": "Brokers", "C": "Arbitrageurs"}, "answer": "C", "explanation": "A Incorrect because dealers connect a buyer who arrived at one point in time with a seller who arrived at another point in time and by trading with another client on the other side of the market, not buyers and sellers in different markets.\nB Incorrect because brokers are agents who fill orders for their clients. They do not trade with their clients. Instead, they search for traders who are willing to take the other side of their clients' orders. They do not buy and sell, but arrange trades.\nC Correct because arbitrageurs buy and sell identical or essentially similar instruments at different prices in different markets."},
  {"num": 30, "subject": "股权投资", "question": "An investor purchases a nondividend-paying stock using 35% margin. If the stock price rises by 7%, the total return on this leveraged position is closest to:", "options": {"A": "9.5%.", "B": "10.8%.", "C": "20.0%."}, "answer": "C", "explanation": "A Incorrect because the total return is incorrectly calculated as (1 + margin) × price increase = 1.35 × 7% = 9.45% ≈ 9.5%.\nB Incorrect because it uses the incorrect leverage ratio, (1 / (1 – 35%)). The incorrect leverage ratio × price increase = (1 / (1 – 35%)) × 7% = 10.76% ≈ 10.8%.\nC Correct because the leverage ratio is 1 / 35% = 2.86, and the leveraged position return is calculated as the leverage ratio × percentage increase (decrease) in equity = 2.86 × 7% = 20%."},
  {"num": 31, "subject": "股权投资", "question": "An investor purchases stock on margin by posting 25% as equity. If the purchase price was $40 and the sale price was $30, the total return on the leveraged position is closest to:", "options": {"A": "–100%.", "B": "–33%.", "C": "–25%."}, "answer": "A", "explanation": "A Correct because the maximum leverage ratio associated with a position financed by the minimum margin requirement is one divided by the minimum margin requirement. With a requirement of 25%, the maximum leverage ratio = 100% position / 25% equity = 4.0. The leverage ratio indicates how much more risky a leveraged position is relative to an unleveraged position. The investor's return on the equity investment will be equal to the maximum leverage ratio × change in the stock price. Change in stock price= ($30 – $40) / $40 = –0.25 = –25%. Return on investment = 4 × –25% = 100% loss. Alternatively, initial equity = $40 ×0.25 = $10 per share. With a price decline of $10 ($40 – $30), there is a 100% loss of equity.\nB Incorrect because it is the percentage change in price / (1 – margin used) = –0.25 / (1 – 0.25) ≈ –0.3333 ≈ –33.33%.\nC Incorrect because it is simply the price decline of the holding: ($30 – $40) / $40 = –0.25 = –25%. This does not account for the leverage of the position."},
  {"num": 32, "subject": "股权投资", "question": "The maximum initial leverage ratio associated with a position financed by margin is one divided by:", "options": {"A": "the minimum margin requirement.", "B": "one plus the minimum margin requirement.", "C": "one minus the minimum margin requirement."}, "answer": "A", "explanation": "A Correct because the maximum leverage ratio associated with a position financed by the minimum margin requirement is one divided by the minimum margin requirement.\nB Incorrect because the maximum leverage ratio associated with a position financed by the minimum margin requirement is one divided by the minimum margin requirement.\nC Incorrect because the maximum leverage ratio associated with a position financed by the minimum margin requirement is one divided by the minimum margin requirement."},
  {"num": 33, "subject": "股权投资", "question": "Management of a price-weighted index most likely entails:", "options": {"A": "rebalancing only.", "B": "reconstitution only.", "C": "both rebalancing and reconstitution."}, "answer": "B", "explanation": "A Incorrect because price-weighted indexes are not rebalanced because the weight of each constituent security is determined by its price.\nB Correct because price-weighted indexes are not rebalanced because the weight of each constituent security is determined by its price. Reconstitution is the process of changing the constituent securities in an index.\nC Incorrect because price-weighted indexes are not rebalanced because the weight of each constituent security is determined by its price."},
  {"num": 34, "subject": "股权投资", "question": "Which of the following statements best describes hedge fund indexes?", "options": {"A": "Index constituents are regulated entities", "B": "Potential survivorship bias is reduced by voluntary performance reporting", "C": "There may be little overlap in index constituents between different indexes offered by different index providers"}, "answer": "C", "explanation": "A Incorrect because as unregulated entities hedge funds are not required to report their performance. This means a hedge fund index is unlikely to be composed of regulated entities.\nB Incorrect because a consequence of the voluntary performance reporting is the potential for survivorship bias.\nC Correct because frequently, a hedge fund reports its performance to only one database. The result is little overlap of funds covered by the different indices. With little overlap between their constituents, different global hedge funds indices may reflect very different performance for the hedge fund industry over the same period of time."},
  {"num": 35, "subject": "股权投资", "question": "An analyst gathers the following information about a market-capitalization-weighted index and one of its four constituent stocks:\nIf the stock price is $30 per share and the index value is 100, the stock's weight in the index is closest to:", "options": {"A": "25%.", "B": "30%.", "C": "35%."}, "answer": "C", "explanation": "A Incorrect because 25% is the stock's weight using equal-weighted method: 1 stock / 4 stocks = 25%.\nB Incorrect because this is the stock's weight using the price-weighted method: stock's price / index value = $30 / 100 = 30%.\nC Correct because the stock's weight in a market-capitalization-weighted index = market capitalization of stock / market capitalization of index = $20 billion / $57 billion = 35.08%, which is closest to 35%."},
  {"num": 36, "subject": "股权投资", "question": "Security market indices most likely serve as proxies for:", "options": {"A": "nonsystematic risk.", "B": "asset classes in asset allocation models.", "C": "the fair value of assets in asset-based valuation models."}, "answer": "B", "explanation": "A Incorrect because security market indices do not serve as proxies for measuring nonsystematic risk. Nonsystematic risk is risk that is local or limited to a particular asset or industry that need not affect assets outside of that asset class. Investors are capable of avoiding nonsystematic risk through diversification by forming a portfolio of assets that are not highly correlated with one another. Security market indices are usually broad and well diversified. They do serve as market proxies when measuring risk-adjusted performance. The beta of an actively managed portfolio allows investors to form a passive alternative with the same level of systematic risk.\nB Correct because indices play a critical role as proxies for asset classes in asset allocation models.\nC Incorrect because asset-based valuation is a method for valuing individual companies, so a broad security market indices is not a useful proxy. Asset-based valuation of a company uses estimates of the market or fair value of the company's assets and liabilities. Asset-based valuation models are frequently used together with multiplier models to value private companies. As public companies increase reporting or disclosure of fair values, asset-based valuation may be increasingly used to supplement present value and multiplier models of valuation."},
  {"num": 37, "subject": "股权投资", "question": "A multi-market index is most appropriately used as a benchmark:", "options": {"A": "for a single country ETF.", "B": "for a small-capitalization growth stock manager.", "C": "to calculate beta for the portfolio of a global stock manager."}, "answer": "C", "explanation": "A Incorrect because multi-market indexes usually comprise indexes from different countries and are designed to represent multiple security markets. Multi-market indexes may represent multiple national markets, geographic regions, economic development groups, and, in some cases, the entire world. A multi-market index would not be used as a benchmark for a single country ETF.\nB Incorrect because a small cap growth index is a style index, not a multi-market index.\nC Correct because indexes also serve as market proxies when measuring risk-adjusted performance. The beta of an actively managed portfolio allows investors to form a passive alternative with the same level of systematic risk. In this case, multi-market indexes usually comprise indexes from different countries would serve as benchmarks to calculate beta for the portfolios of global stock managers."},
  {"num": 38, "subject": "股权投资", "question": "A world equity index is most likely considered a:", "options": {"A": "style index.", "B": "sector index.", "C": "multi-market index."}, "answer": "C", "explanation": "A Incorrect because style indexes represent groups of securities classified according to market capitalization, value, growth, or a combination of these characteristics. They are intended to reflect the investing styles of certain investors, such as the growth investor, value investor, and small-cap investor.\nB Incorrect because sector indexes represent and track different economic sectors—such as consumer goods, energy, finance, health care, and technology—on either a national, regional, or global basis. A world equity index most likely does not represent a specific economic sector.\nC Correct because multi-market indexes usually comprise indexes from different countries and regions and are designed to represent multiple security markets. Multi-market indexes may represent multiple national markets, geographic regions, economic development groups, and, in some cases, the entire world. World indexes are of importance to investors who take a global approach to equity investing without any particular bias toward a particular country or region."},
  {"num": 39, "subject": "股权投资", "question": "An analyst gathers the following information about a security index:\nIf the index's value is 100 at the beginning of Period 1, the index's value at the end of Period 3 is closest to:", "options": {"A": "103.", "B": "105.", "C": "106."}, "answer": "B", "explanation": "A Incorrect because the value of the index at the end of Period 2, not Period 3 = Beginning value × (1 + Period 1 return) × (1 + Period 2 return) = 100 × (100 + 12%) × (100 – 8%) = 103.04, which is closest to 103.\nB Correct because it is the value of the index at the end of Period 3 = Beginning value × (1+Period 1 return) × (1 + Period 2 return) × (1 + Period 3 return) = 100 × (100 + 12%) × (100 – 8%) × (1 + 2%) ≈ 105.10, which is closest to 105.\nC Incorrect because returns for the three periods are added, not compounded: Beginning value + (100 × Period 1 return) + (100 × Period 2 return) + (100 × Period 3 return) = 100 + (100 × 12%) + (100 × – 8%) + (100 × 2%) = 100 + 12 – 8 + 2 = 106."},
  {"num": 40, "subject": "股权投资", "question": "The beginning value for an index is 1540 and the ending value is 1575. If the income for the period is 55, the total return of the index is closest to:", "options": {"A": "1.3%.", "B": "2.2%.", "C": "5.8%."}, "answer": "C", "explanation": "A Incorrect because the beginning and ending index values were reversed in the calculation: (1540 – 1575 + 55) / 1575 = 20 / 1575 = 1.3%.\nB Incorrect because the income is not taken into account: (1575–1540) / 1540 = 35 / 1540 = 2.2%.\nC Correct because the total return of an index is the price appreciation, or change in the value of the price return index, plus income (dividends and/or interest) over the period, expressed as a percentage of the beginning value of the price return index. Total return = (ending index value – beginning index value + income) / beginning index value = (1575 – 1540 + 55) / 1540 = 90 / 1540 = 5.8%."},
  {"num": 41, "subject": "股权投资", "question": "Fixed-income indexes most likely:", "options": {"A": "are more easily replicated than equity indexes.", "B": "require the provider to estimate the prices of some constituent securities.", "C": "are created from a smaller universe of possible constituent securities than the universe of equity securities."}, "answer": "B", "explanation": "A Incorrect because it is difficult, compared with equity indexes, for investors to replicate fixed-income indexes and duplicate their performance.\nB Correct because compared to equity indexes, fixed-income index providers must contact dealers to obtain current prices on constituent securities to update the index or they must estimate the prices of constituent securities using the prices of traded fixed-income securities with similar characteristics.\nC Incorrect because the number of fixed-income securities is many times larger than the number of equity securities."},
  {"num": 42, "subject": "股权投资", "question": "As time passes after inception, the value of the price version of an index is:", "options": {"A": "less than the value of the total return version.", "B": "equal to the value of the total return version.", "C": "greater than the value of the total return version."}, "answer": "A", "explanation": "A Correct because at inception, the values of the price and total return versions of an index are equal. As time passes, however, the value of the total return index will exceed the value of the price return index.\nB Incorrect because at inception, the values of the price and total return versions of an index are equal. As time passes, however, the value of the total return index will exceed the value of the price return index.\nC Incorrect because at inception, the values of the price and total return versions of an index are equal. As time passes, however, the value of the total return index will exceed the value of the price return index."},
  {"num": 43, "subject": "股权投资", "question": "A disadvantage of an equal-weighted index is that:", "options": {"A": "maintaining equal weights requires frequent reconstitution of the index.", "B": "securities that represent a relatively large fraction of the target market value are underrepresented.", "C": "securities that represent a relatively small fraction of the target market value are underrepresented."}, "answer": "B", "explanation": "A Incorrect because an equal weighted index requires frequent rebalancing, not reconstitution, when its constituent securities’ prices change. Equal weighting has a number of disadvantages. After the index is constructed and the prices of constituent securities change, the index is no longer equally weighted. Therefore, maintaining equal weights requires frequent adjustments (rebalancing) to the index.\nB Correct because this is considered a disadvantage of an equal weighted index. Equal weighting has a number of disadvantages. Securities that constitute the largest fraction of the target market value are underrepresented, and securities that constitute a small fraction of the target market value are overrepresented.\nC Incorrect because smaller stocks are overrepresented in an equal weighted index. Equal weighting has a number of disadvantages. Securities that constitute the largest fraction of the target market value are underrepresented, and securities that constitute a small fraction of the target market value are overrepresented."},
  {"num": 44, "subject": "股权投资", "question": "An increase in shares held by controlling shareholders most likely impacts the constituent weightings of a(n):", "options": {"A": "price-weighted index.", "B": "equal-weighted index.", "C": "float-adjusted market-capitalization-weighted index."}, "answer": "C", "explanation": "A Incorrect because in price weighting, the weight on each constituent security is determined by dividing its price by the sum of all the prices of the constituent securities, which means the lower free float (due to increased weight of controlling shareholders) has no impact on constituent weights.\nB Incorrect because the equal weighting assigns an equal weight to each constituent security at inception, which means the lower free float (due to increased number of shares held by controlling shareholders) has no impact on constituent weights.\nC Correct because float-adjusted market-capitalization-weighted indexes reflect the shares available for public trading (excluding the ones held by controlling shareholders) by multiplying the market price per share by the number of shares available to the investing public (i.e., the float-adjusted market capitalization), which means constituent weights are impacted."},
  {"num": 45, "subject": "股权投资", "question": "Equity style indexes most likely represent groups of securities classified by:", "options": {"A": "geography and sector.", "B": "value and/or growth and market capitalization.", "C": "asset class and gross domestic product (GDP) weight."}, "answer": "B", "explanation": "A Incorrect because geography and sector might be combined in a sector index, but neither characteristic, either on its own or in combination, is likely to be used to construct a style index.\nB Correct because style indices represent groups of securities classified according to market capitalization, value, growth, or a combination of these characteristics. They are intended to reflect the investing styles of certain investors, such as the growth investor, value investor, and small-cap investor.\nC Incorrect because asset class and GDP weight might be combined in a multi-market index, but neither characteristic is likely to be used to construct a style index."},
  {"num": 46, "subject": "股权投资", "question": "An analyst gathers the following information about an equal-weighted index composed of three stocks:\nIf there is a 2% return from dividends for each of the three stocks, the total return of the index is:", "options": {"A": "0%.", "B": "2%.", "C": "6%."}, "answer": "B", "explanation": "A Incorrect because dividends are not accounted for. It is simply the price return of the index. Price return for Stock 1 = ($8 – $10) / $10 = –0.20 = –20%. Price return for Stock 2 = ($24 – $20) / $20 = 0.20 = 20%. Price return for Stock 3 = ($30 – $30) / $30 = 0.00 = 0%. The price return of the index = –20% + 20% + 0% = 0% / 3 = 0%.\nB Correct because total return measures price appreciation plus interest, dividends, and other distributions. Thus, the total return of an index is the price appreciation, or change in the value of the price return index, plus income (dividends and/or interest) over the period, expressed as a percentage of the beginning value of the price return index. Price return for Stock 1 = ($8 – $10) / $10 = –0.20 = –20%. Total return = price return + dividends = –20% + 2% = –18%. Price return for Stock 2 = ($24 – $20) / $20 = 0.20 = 20%. Total return = 20% + 2% = 22%. Price return for Stock 3 = ($30 – $30) / $30 = 0.00 = 0%. Total return = 0% + 2% = 2%. The total return of the index = (–18% + 22% + 2%) / 3 = 6% / 3 = 2%.\nC Incorrect because dividends are not accounted for. It is simply the price return of the index. Price return for Stock 1 = ($8 – $10) / $10 = –0.20 = –20%. Price return for Stock 2 = ($24 – $20) / $20 = 0.20 = 20%. Price return for Stock 3 = ($30 – $30) / $30 = 0.00 = 0%. The price return of the index = –20% + 20% + 0% = 0% / 3 = 0%."},
  {"num": 47, "subject": "股权投资", "question": "Over time, which of the following indexes most likely has portfolio weights that shift away from securities that have increased in relative value and toward securities that have fallen in relative value? A:", "options": {"A": "price-weighted index", "B": "fundamentally weighted index", "C": "market-capitalization-weighted index"}, "answer": "B", "explanation": "A Incorrect because the main disadvantage of price weighting is that it results in arbitrary weights for each security. It does not have a contrarian effect.\nB Correct because fundamentally weighted indexes generally will have a contrarian 'effect' in that the portfolio weights will shift away from securities that have increased in relative value and toward securities that have fallen in relative value whenever the portfolio is rebalanced.\nC Incorrect because a market capitalization weighting method leads to overweighting stocks that have risen in price (and may be overvalued) and underweighting stocks that have declined in price (and may be undervalued). The effect of this weighting method is similar to a momentum investment strategy in that over time, the securities that have risen in price the most will have the largest weights in the index."},
  {"num": 48, "subject": "股权投资", "question": "Which of the following indexes is composed of futures contracts?", "options": {"A": "Commodity index", "B": "Hedge fund index", "C": "Broad equity market index"}, "answer": "A", "explanation": "A Correct because commodity indexes consist of futures contracts on one or more commodities.\nB Incorrect because hedge fund indexes reflect the returns on hedge funds. Hedge funds are private investment vehicles that typically use leverage and long and short investment strategies. A number of research organizations maintain databases of hedge fund returns and summarize these returns into indexes. Although the underlying hedge funds may contain futures contracts, the indexes are not comprised of futures contracts.\nC Incorrect because a broad equity market index, as its name suggests, represents an entire given equity market and typically includes securities representing more than 90 percent of the selected market. Although the underlying securities may include contracts, the index is not comprised of futures contracts."},
  {"num": 49, "subject": "股权投资", "question": "An analyst gathers the following information about an index and one security in the index:\nWhich of the following index-weighting methods most likely gives this security the greatest weight in the index?", "options": {"A": "Price weighting", "B": "Equal weighting", "C": "Market capitalization weighting"}, "answer": "B", "explanation": "A Incorrect because equal weighting results in the largest weight: Equal weight = 1 / number of constituent securities = 1 / 18 = 5.6%. Price weight = price of security / sum of all prices of constituent securities = 38 / 808.50 = 4.7%. Market cap weight = price × shares outstanding / sum of all market caps of constituent securities = €38 × 540m / €420b = €20.52b / €420b ≈ 4.9%.\nB Correct because equal weighting results in the largest weight: Equal weight = 1 / number of constituent securities = 1 / 18 = 5.6%. Price weight = price of security / sum of all prices of constituent securities = 38 / 808.50 = 4.7%. Market cap weight = price × shares outstanding / sum of all market caps of constituent securities = €38 × 540m / €420b = €20.52b / €420b ≈ 4.9%. Alternatively, B is correct because the security's price is less than the average price of the securities in the index and the security's market cap is less than the average market cap of the securities in the index: Index's average price = sum of all prices of constituent securities / number of constituent securities = €808.50 / 18 ≈ €44.92 > security's price of €38.00. Index's average market cap = sum of all market caps of constituent securities / number of constituent securities =€420b / 18 = €23.3b > security's market cap of €20.52b (€38.00 × 540mm). The mathematical fact that both these averages are greater than the price and market cap of the individual security means equal weight must be the correct answer.\nC Incorrect because equal weighting results in the largest weight:"},
  {"num": 50, "subject": "股权投资", "question": "Reconstitution of a security index is best described as the process of changing the:", "options": {"A": "constituent securities in the index.", "B": "weights of the constituent securities in the index.", "C": "date on which the index provider reviews the constituent securities."}, "answer": "A", "explanation": "A Correct because reconstitution is the process of changing the constituent securities in an index.\nB Incorrect because rebalancing (not reconstitution) refers to adjusting the weights of the constituent securities in the index.\nC Incorrect because the reconstitution date (not the reconstitution process) is the date on which index providers review the constituent securities, re-apply the initial criteria for inclusion in the index, and select which securities to retain, remove, or add."},
  {"num": 51, "subject": "股权投资", "question": "A total return index reflects:", "options": {"A": "only the prices of constituent securities.", "B": "only the reinvestment of all income received since index inception.", "C": "both the prices of constituent securities and the reinvestment of all income received since index inception."}, "answer": "C", "explanation": "A Incorrect , because a total return index, in contrast, reflects not only the prices of the constituent securities but also the reinvestment of all income received since inception.\nB Incorrect , because a total return index, in contrast, reflects not only the prices of the constituent securities but also the reinvestment of all income received since inception.\nC Correct , because a total return index, in contrast, reflects not only the prices of the constituent securities but also the reinvestment of all income received since inception."},
  {"num": 52, "subject": "股权投资", "question": "With respect to behavioral finance, which of the following is least likely a behavioral bias used to explain pricing anomalies?", "options": {"A": "Risk aversion", "B": "Loss aversion", "C": "Overconfidence"}, "answer": "A", "explanation": "A Correct because behavioral finance allows for the possibility that the dislike for risk is not symmetrical, in contrast to the more general models where researchers assume that investors do not like risk (risk aversion), whether the risk is that returns are higher than expected or lower than expected.\nB Incorrect because behavioral finance research supports the phenomenon that investors are loss averse. Behavioral finance allows for the possibility that the dissatisfaction resulting from a loss exceeds the satisfaction resulting from a gain of the same magnitude. Some argue that behavioral theories of loss aversion can explain observed overreaction in markets.\nC Incorrect because behavioral finance research supports the phenomenon that investors are overconfident. Evidence has suggested that overconfidence results in mispricing for US, UK, German, French, and Japanese markets."},
  {"num": 53, "subject": "股权投资", "question": "In a highly efficient market, a passive investment strategy most likely has:", "options": {"A": "higher transaction costs than an active strategy.", "B": "lower information-seeking costs than an active strategy.", "C": "higher risk-adjusted returns before all expenses than an active strategy."}, "answer": "B", "explanation": "A Incorrect because in a highly efficient market, a passive investment strategy is preferred to an active investment strategy because of lower costs (for example, transaction and information-seeking costs).\nB Correct because in a highly efficient market, a passive investment strategy (i.e., buying and holding a broad market portfolio) that does not seek superior risk-adjusted returns is preferred to an active investment strategy because of lower costs (for example, transaction and information-seeking costs).\nC Incorrect because since there are no inefficiencies to exploit in a highly efficient market, an active investment strategy would most likely generate the same risk-adjusted returns as a passive investment strategy if expenses are not considered. Consistent, superior, risk- adjusted returns (net [not before] of all expenses) are not achievable in an efficient market. In a highly efficient market, a passive investment strategy (i.e., buying and holding a broad market portfolio) that does not seek superior risk-adjusted returns is preferred to an active investment strategy."},
  {"num": 54, "subject": "股权投资", "question": "The observation that a large-capitalization company's stock price is inflated after the company releases unexpected good news at year end is most likely related to the:", "options": {"A": "value effect.", "B": "overreaction effect.", "C": "turn-of-the-year effect."}, "answer": "B", "explanation": "A Incorrect because the value effect is a market anomaly that value stocks, which are generally referred to as stocks that have below-average price-to-earnings (P/E) and market-to-book (M/B) ratios, and above-average dividend yields, have consistently outperformed growth stocks over long periods of time. This is a cross-sectional anomaly and is not related to an information release.\nB Correct because the overreaction effect or anomaly is described as the propensity for investors to overreact to the release of unexpected public information. Therefore, stock prices will be inflated (depressed) for those companies releasing good (bad) information. In other words, inflated (depressed) here means the change of value that is overshooting (undershooting) the fair (intrinsic) value after incorporating the new information, rather than the price action that goes up (down) itself.\nC Incorrect because the turn-of-the-year effect is a calendar anomaly that stock market returns in January were significantly higher compared to the rest of the months of the year, with most of the abnormal returns reported during the first five trading days in January. This is a time-series anomaly related to the calendar but not an information release."},
  {"num": 55, "subject": "股权投资", "question": "A feature of an efficient market is that:", "options": {"A": "the market reflects all past and present information.", "B": "asset prices react to information that is fully anticipated.", "C": "an investor can earn consistent, superior, risk-adjusted returns."}, "answer": "A", "explanation": "A Correct because an efficient market is thus a market in which asset prices reflect all past and present information.\nB Incorrect because in an efficient market, prices should be expected to react only to the elements of information releases that are not anticipated fully by investors—that is, to the “unexpected” or “surprise” element of such releases.\nC Incorrect because consistent, superior, risk-adjusted returns (net of all expenses) are not achievable in an efficient market."},
  {"num": 56, "subject": "股权投资", "question": "A market where security prices fully reflect all publicly known and available information, but not private information, is:", "options": {"A": "weak-form efficient.", "B": "semi-strong-form efficient.", "C": "strong-form efficient."}, "answer": "B", "explanation": "A Incorrect because in the weak-form efficient market hypothesis, security prices fully reflect all past market data. It does not include all publicly known and available information.\nB Correct because in a semi-strong-form efficient market, prices reflect all publicly known and available information.\nC Incorrect because in a strong-form efficient market, security prices fully reflect both public and private information."},
  {"num": 57, "subject": "股权投资", "question": "In a weak-form efficient market, which of the following information is reflected in security prices?", "options": {"A": "Historical prices only", "B": "Historical prices and historical trading volumes only", "C": "Historical prices, historical trading volumes, and current earnings"}, "answer": "B", "explanation": "A Incorrect because in the weak-form efficient market hypothesis, security prices fully reflect all past market data, which refers to all historical price and trading volume information. This answer is incomplete as it does not include trading volume information.\nB Correct because in the weak-form efficient market hypothesis, security prices fully reflect all past market data, which refers to all historical price and trading volume information.\nC Incorrect because in the weak-form efficient market hypothesis, security prices fully reflect all past market data, which refers to all historical price and trading volume information but does not refer to current earnings information."},
  {"num": 58, "subject": "股权投资", "question": "With respect to behavioral biases, when investors tend to be slow to react to new information and continue to maintain their prior views, this is best described as:", "options": {"A": "conservatism.", "B": "herding behavior.", "C": "representativeness."}, "answer": "A", "explanation": "A Correct because conservative investors tend to be slow to react to new information and continue to maintain their prior views or forecasts.\nB Incorrect because herding behavior has been advanced as a possible explanation of under reaction and overreaction in financial markets when investors ignore their own private information and/or analysis and act as other investors do.\nC Incorrect because representative investors assess new information and probabilities of outcomes based on similarity to the current state or to a familiar classification."},
  {"num": 59, "subject": "股权投资", "question": "The size effect anomaly results when it is observed that on a risk-adjusted basis small cap companies tend to:", "options": {"A": "underperform equities of large-cap companies.", "B": "perform in line with equities of large-cap companies.", "C": "outperform equities of large-cap companies."}, "answer": "C", "explanation": "A Incorrect because the size effect results from the observation that equities of small-cap companies tend to outperform equities of large-cap companies on a risk-adjusted basis.\nB Incorrect because the size effect results from the observation that equities of small-cap companies tend to outperform equities of large-cap companies on a risk-adjusted basis.\nC Correct because the size effect results from the observation that equities of small-cap companies tend to outperform equities of large-cap companies on a risk-adjusted basis."},
  {"num": 60, "subject": "股权投资", "question": "Behavioral finance:", "options": {"A": "suggests that behavioral biases only affect novice investors.", "B": "provides a possible explanation for a number of pricing anomalies.", "C": "relies on the assumption that people consider all available information in decision-making."}, "answer": "B", "explanation": "A Incorrect because behavioral biases can affect all market participants, from the novice investor to the most experienced investment manager.\nB Correct because the focus of much of the work in this area is on the behavioral biases that affect investment decisions. The behavior of individuals, in particular their behavioral biases, has been offered as a possible explanation for a number of pricing anomalies.\nC Incorrect because behavioral finance does not assume that people consider all available information in decision-making."},
  {"num": 61, "subject": "股权投资", "question": "Trading by arbitrageurs most likely:", "options": {"A": "reduces liquidity.", "B": "increases pricing discrepancies.", "C": "contributes to market efficiency."}, "answer": "C", "explanation": "A Incorrect because arbitrageurs provide liquidity to buyers and sellers who arrive at different markets at the same time. They move liquidity across markets. Arbitrageurs provide liquidity to the markets because they make it easier for buyers and sellers to trade when and where they want to trade.\nB Incorrect because the presence of arbitrageurs helps pricing discrepancies disappear quickly.\nC Correct because arbitrageurs are traders who engage in such trades to benefit from pricing discrepancies (inefficiencies) in markets. Such trading activity contributes to market efficiency. The presence of these arbitrageurs helps pricing discrepancies disappear quickly."},
  {"num": 62, "subject": "股权投资", "question": "Decreased market efficiency is most likely associated with an increase in:", "options": {"A": "transaction costs.", "B": "financial disclosure.", "C": "the number of market participants."}, "answer": "A", "explanation": "A Correct because an increase in transaction costs will increase the price discrepancy between market price and efficient price. Higher transaction costs make it more expensive for traders to exploit market inefficiencies, thereby decreasing market efficiency. Inefficiencies may also be unexploitable if the amount of the transaction cost offsets the amount of the price discrepancy. A price discrepancy must be sufficiently large to leave the investor with a profit (adjusted for risk) after taking account of the transaction costs and information-acquisition costs to reach the conclusion that the discrepancy may represent a market inefficiency.\nB Incorrect because rules and regulations that promote fairness and efficiency in a market include those pertaining to the disclosure of information and illegal insider trading.\nC Incorrect because an increase in the number of market participants increases efficiency. If a large number of investors (individual and institutional) follow the major financial markets closely on a daily basis, and if mispricings exist in these markets, investors will act so that these mispricings disappear quickly."},
  {"num": 63, "subject": "股权投资", "question": "In contrast to the market value of an equity security, intrinsic value is most likely:", "options": {"A": "not known with certainty.", "B": "constant throughout the life of the security.", "C": "determined by the intersection of supply and demand."}, "answer": "A", "explanation": "A Correct because market value is the price at which an asset can currently be bought or sold. Intrinsic value (sometimes called fundamental value) is, broadly speaking, the value that would be placed on it by investors if they had a complete understanding of the asset's investment characteristics. Intrinsic value can be estimated but is not known for certain.\nB Incorrect because information relevant to valuation flows continually to investors, estimates of intrinsic value change, and hence, market values change. Neither market value or intrinsic value are constant.\nC Incorrect because the market value of an asset represents the intersection of supply and demand—the point that is low enough to induce at least one investor to buy while being high enough to induce at least one investor to sell. Intrinsic value is the present value of future cash flows as opposed to the intersection of supply and demand."},
  {"num": 64, "subject": "股权投资", "question": "The January effect is an example of:", "options": {"A": "loss aversion.", "B": "an earnings surprise.", "C": "a market pricing anomaly."}, "answer": "C", "explanation": "A Incorrect because loss aversion refers to the tendency of people to dislike losses more than they like comparable gains. Some argue that behavioral theories of loss aversion can explain observed overreaction in markets. Thus loss aversion is related to behavioral finance and is not a market anomaly.\nB Incorrect because earnings surprise, is the portion of earnings that is unanticipated by investors and, according to the efficient market hypothesis, merits a price adjustment. Earnings surprise is a type of market anomaly but is not the January effect.\nC Correct because the January effect, has been observed in most equity markets around the world. This anomaly is also known as the \"turn-of-the-year\" effect. The January effect is a time series anomaly and is an observed pricing anomaly."},
  {"num": 65, "subject": "股权投资", "question": "According to the efficient market hypothesis, if market prices reflect private information, the market is most likely:", "options": {"A": "strong-form efficient.", "B": "weak-form efficient only.", "C": "semi-strong-form efficient, but not strong-form efficient."}, "answer": "A", "explanation": "A Correct because in the case of a strong-form efficient market, insiders would not be able to earn abnormal returns from trading on the basis of private information. Market prices reflect private information under strong form market efficiency.\nB Incorrect because it is possible to earn abnormal profits from trading on private information when the market is weak-form efficient only. Market prices do not reflect private information under weak form market efficiency.\nC Incorrect because it is possible to earn abnormal profits from trading on private information when the market is semi-strong-form efficient only. Market prices do not reflect private information under semi-strong form market efficiency."},
  {"num": 66, "subject": "股权投资", "question": "Which of the following market anomalies is best described as a time-series anomaly?", "options": {"A": "Size effect", "B": "Momentum", "C": "Initial Public Offerings"}, "answer": "B", "explanation": "A Incorrect because the size effect is a cross-sectional anomaly, not a time-series anomaly. Two of the most researched cross-sectional anomalies in financial markets are the size effect and the value effect. The size effect results from the observation that equities of small-cap companies tend to outperform equities of large-cap companies on a risk-adjusted basis.\nB Correct because the momentum anomaly is best described as a time-series anomaly. Momentum anomalies relate to short-term share price patterns where past price moves continued through time to move in the same direction.\nC Incorrect because the Initial Public Offering (IPO) anomaly is best described as an “other” anomaly."},
  {"num": 67, "subject": "股权投资", "question": "Fundamental analysis most likely:", "options": {"A": "uses stock price patterns to trade.", "B": "is an input for passive portfolio management.", "C": "helps participants understand the value implications of information."}, "answer": "C", "explanation": "A Incorrect because fundamental analysis involves the estimation of an asset's value using company data, such as earnings and sales forecasts and not stock price patterns. Instead, technical analysis is the use of price patterns in attempt to profit from them.\nB Incorrect because fundamental analysis is an attempt to make active portfolio management decisions, not passive management. Passive management focuses on replicating indexes as investment vehicles.\nC Correct because fundamental analysis is necessary in a well-functioning market because this analysis helps the market participants understand the value implications of information."},
  {"num": 68, "subject": "股权投资", "question": "Over the long run, if a market is semi-strong-form efficient, which of the following investment strategies should result in the highest return to investors? A(n):", "options": {"A": "passive investment strategy", "B": "active trading strategy seeking to exploit price patterns", "C": "active trading strategy seeking to exploit public information"}, "answer": "A", "explanation": "A Correct because if securities markets are weak-form and semi-strong-form efficient, the implication is that active trading, whether attempting to exploit price patterns or public information, is not likely to generate abnormal returns. In other words, portfolio managers cannot beat the market on a consistent basis, so therefore, passive portfolio management should outperform active portfolio management.\nB Incorrect because if securities markets are semi-strong-form efficient, the implication is that active trading attempting to exploit price patterns is not likely to generate abnormal returns. In other words, portfolio managers cannot beat the market on a consistent basis, so therefore, passive portfolio management should outperform active portfolio management.\nC Incorrect because if securities markets are semi-strong-form efficient, the implication is that active trading attempting to exploit public information is not likely to generate abnormal returns. In other words, portfolio managers cannot beat the market on a consistent basis, so therefore, passive portfolio management should outperform active portfolio management."},
  {"num": 69, "subject": "股权投资", "question": "In which of the following forms of market efficiency are investors able to consistently outperform the market using fundamental analysis?", "options": {"A": "Weak-form market efficiency", "B": "Semi-strong-form market efficiency", "C": "Strong-form market efficiency"}, "answer": "A", "explanation": "A Correct because in the weak form of market efficiency, market prices reflect all past market data; however, it does not incorporate all public information. Therefore, investors may use fundamental analysis to outperform the market.\nB Incorrect because in a semi-strong market, all public information - past and present - is available making fundamental analysis less effective.\nC Incorrect because in a strong-form efficient market, security prices fully reflect both public and private information. In the case of a strong-form efficient market, insiders would not be able to earn abnormal returns from trading (even) on the basis of private information. Therefore, they cannot outperform the market using fundamental analysis."},
  {"num": 70, "subject": "股权投资", "question": "The voting method that allows shareholders to cast all their votes for a single candidate is best described as:", "options": {"A": "proxy voting.", "B": "statutory voting.", "C": "cumulative voting."}, "answer": "C", "explanation": "A Incorrect because proxy voting is defined as shareholders may vote by proxy, which allows a designated party—such as another shareholder, a shareholder representative, or management—to vote on the shareholders’ behalf.\nB Incorrect because cumulative voting allows shareholders to direct their total voting rights to specific candidates, as opposed to statutory voting having to allocate their voting rights evenly among all candidates.\nC Correct because cumulative voting allows shareholders to direct their total voting rights to specific candidates, as opposed to statutory voting having to allocate their voting rights evenly among all candidates."},
  {"num": 71, "subject": "股权投资", "question": "Management is more likely to focus on short-term results instead of long-term earnings growth if a company raises equity through:", "options": {"A": "venture capital.", "B": "a leveraged buyout.", "C": "an initial public offering."}, "answer": "C", "explanation": "A Incorrect because by going private, management can adopt a more long-term focus and can eliminate certain costs that are necessary to operate a publicly traded company. Whereas in operating a publicly traded company, management often feels pressured to focus on short-term results (e.g., meeting quarterly sales and earnings targets from analysts biased toward near-term price performance) instead of operating the company to obtain long-term sustainable revenue and earnings growth. There are three primary types of private equity investments: venture capital, leveraged buyouts, and private investment in public equity (or PIPE).\nB Incorrect because by going private, management can adopt a more long-term focus and can eliminate certain costs that are necessary to operate a publicly traded company. Whereas in operating a publicly traded company, management often feels pressured to focus on short-term results (e.g., meeting quarterly sales and earnings targets from analysts biased toward near-term price performance) instead of operating the company to obtain long-term sustainable revenue and earnings growth. There are three primary types of private equity investments: venture capital, leveraged buyouts, and private investment in public equity (or PIPE).\nC Correct because in operating a publicly traded company, management often feels pressured to focus on short-term results (e.g., meeting quarterly sales and earnings targets from analysts biased toward near-term price performance) instead of operating the company to obtain long-term sustainable revenue and earnings growth."},
  {"num": 72, "subject": "股权投资", "question": "Common shares that are tradeable on different stock exchanges in different currencies are best described as:", "options": {"A": "global registered shares.", "B": "global depository receipts.", "C": "a basket of listed depository receipts."}, "answer": "A", "explanation": "A Correct because a global registered share (GRS) is a common share that is traded on different stock exchanges around the world in different currencies.\nB Incorrect because a GDR is traded in the specified local stock exchange only. A depository receipt (DR) is a security that trades like an ordinary share on a local exchange and represents an economic interest in a foreign company. There are two types of depository receipts including Global depository receipts (GDRs).\nC Incorrect because a basket of listed depository receipts (BLDR), which is an exchange-traded fund (ETF) that represents a portfolio of depository receipts."},
  {"num": 73, "subject": "股权投资", "question": "The book value of a company's equity is:", "options": {"A": "the present value of its future cash flows.", "B": "the difference between its total assets and total liabilities.", "C": "its share price multiplied by the number of outstanding shares."}, "answer": "B", "explanation": "A Incorrect because intrinsic value is often defined as the present value of all expected future cash flows of the asset.\nB Correct because the book value of a company’s equity is the difference between its total assets and total liabilities.\nC Incorrect because this the total market value of equity (or market capitalization) computed as the number of shares outstanding multiplied by the market price per share."},
  {"num": 74, "subject": "股权投资", "question": "All else being equal, which of the following preference shares pays the lowest dividend?", "options": {"A": "Putable", "B": "Callable", "C": "Non-callable"}, "answer": "A", "explanation": "A Correct because from an investor's point of view, putable common or preference shares are less risky than their callable or non-callable counterparts because they give the investor the option to sell the shares to the issuer at a pre-determined price. As a result, putable shares generally pay a lower dividend than non-putable shares.\nB Incorrect because callable common or preference shares are riskier than their non-callable counterparts because the issuer has the option to redeem the shares at a pre-determined price. Callable shares generally pay a higher dividend to compensate investors for the risk that the shares could be called in the future.\nC Incorrect because from an investor's point of view, putable common or preference shares are less risky than their callable or non-callable counterparts because they give the investor the option to sell the shares to the issuer at a pre-determined price. The lower risk of putables shares results in a lower dividend than non-callable shares."},
  {"num": 75, "subject": "股权投资", "question": "Which of the following is least likely to directly affect a company's book value?", "options": {"A": "Changes in the company's net income", "B": "Purchases by the company of its own shares", "C": "Investor estimates of the company's future cash flows"}, "answer": "C", "explanation": "A Incorrect because changes in a company's net income directly affect the book value of the company.\nB Incorrect because purchases by the company of its own shares directly affect the book value of the company.\nC Correct because a company's book value is not directly affected by investor estimates."},
  {"num": 76, "subject": "股权投资", "question": "A company's ROE most likely decreases if shareholders' equity increases at:", "options": {"A": "a lower rate than net income.", "B": "the same rate as net income.", "C": "a higher rate than net income."}, "answer": "C", "explanation": "A Incorrect because ROE can increase if net income increases at a faster rate than shareholders' equity or if net income decreases at a slower rate than shareholders' equity. If shareholder equity increases at a faster rate than net income increases, then ROE will decrease, not increase.\nB Incorrect because ROE can increase if net income increases at a faster rate than shareholders' equity or if net income decreases at a slower rate than shareholders' equity. If shareholder equity increases at the same rate as net income, then ROE will remain the same and not increase.\nC Correct because ROE can increase if net income increases at a faster rate than shareholders' equity or if net income decreases at a slower rate than shareholders' equity."},
  {"num": 77, "subject": "股权投资", "question": "Global depository receipts are most likely:", "options": {"A": "issued outside the US.", "B": "listed on US exchanges.", "C": "denominated in the currency of the issuing company."}, "answer": "A", "explanation": "A Correct because a global depository receipt (GDR) is issued outside of the company's home country and outside of the United States.\nB Incorrect because GDRs cannot be listed on US exchanges.\nC Incorrect because the issuing company selects the exchange where the GDR is to be traded based on such factors as investors' familiarity with the company or the existence of a large international investor base. The majority of GDRs are denominated in US dollars, although the number of GDRs denominated in pound sterling and euros is increasing. While it is possible that the GDR is denominated in the currency of the issuing company, this is not the most likely case among the choices given."},
  {"num": 78, "subject": "股权投资", "question": "If investors believe a company has a large number of positive net present value investment opportunities, the company's book value will most likely be:", "options": {"A": "less than the market value.", "B": "equal to the market value.", "C": "greater than the market value."}, "answer": "A", "explanation": "A Correct because the market value of the company's equity reflects investor's collective assessment and expectations about the company's future cash flows generated by its positive net present value investment opportunities. If investors believe that the company has a large number of these future cash flow-generating investment opportunities, the market value of the company's equity will exceed its book value.\nB Incorrect because if investors believe that the company has a large number of these future cash flow-generating investment opportunities, the market value of the company's equity will exceed its book value; book value will not be the same or greater than market value.\nC Incorrect because if investors believe that the company has a large number of these future cash flow-generating investment opportunities, the market value of the company's equity will exceed its book value; book value will not be the same or greater than market value."},
  {"num": 79, "subject": "股权投资", "question": "Investors' minimum required rate of return on a company's stock is most directly measured by the:", "options": {"A": "CAPM.", "B": "company's ROE.", "C": "company's WACC."}, "answer": "A", "explanation": "A Correct because two models commonly used to estimate a company's cost of equity (or investors' minimum required rate of return) are the dividend discount model (DDM) and the capital asset pricing model (CAPM).\nB Incorrect because ROE is an accounting measure of how effectively a company earns profits on invested equity and is not used to measure investors' required return.\nC Incorrect because the WACC represents the minimum required rate of return that the company must earn on its long-term investments to satisfy all providers of capital. WACC would typically include the cost of debt and hence is not the minimum return on stock."},
  {"num": 80, "subject": "股权投资", "question": "Which of the following methods of raising capital most likely provides mezzanine financing to early-stage companies?", "options": {"A": "Venture capital", "B": "Initial public offering (IPO)", "C": "Private investment in public equity (PIPE)"}, "answer": "A", "explanation": "A Correct because venture capital investments provide ‘seed' or start-up capital, early-stage financing, or mezzanine financing to companies that are in the early stages of development and require additional capital for expansion.\nB Incorrect because an initial public offering (IPO) occurs when a start-up company first goes public. An IPO is the first issuance of common shares to the public by a formerly private corporation.\nC Incorrect because private investment in public equity (PIPE) is generally sought by a public company that is in need of additional capital quickly and is willing to sell a sizeable ownership position to a private investor or investor group. It is not a mechanism to provide financing to early-stage companies."},
  {"num": 81, "subject": "股权投资", "question": "Which of the following types of preference shares entitles shareholders to receive an additional dividend if the company's profits exceed a pre-specified level?", "options": {"A": "Cumulative", "B": "Convertible", "C": "Participating"}, "answer": "C", "explanation": "A Incorrect because cumulative preference shares have dividends that accrue if the company does not pay a dividend for a time and these dividends must be paid in full before common dividends are paid. They do not allow shareholders to get an additional dividend on higher profits.\nB Incorrect because convertible preference shares entitle shareholders to convert their shares into a specified number of common shares. They do not allow shareholders to get an additional dividend on higher profits.\nC Correct because participating preference shares entitle the shareholders to receive the standard preferred dividend plus the opportunity to receive an additional dividend if the company's profits exceed a pre- specified level."},
  {"num": 82, "subject": "股权投资", "question": "Management actions most directly affect a company's:", "options": {"A": "book value.", "B": "market value.", "C": "intrinsic value."}, "answer": "A", "explanation": "A Correct because management actions can directly affect the book value of the company (by increasing net income or by selling or purchasing its own shares).\nB Incorrect because management actions can only indirectly affect the market value of its equity. The market value reflects the collective and differing expectations of investors concerning the company's cash flows.\nC Incorrect because intrinsic value is an investor's subjective estimate of the discounted value of the cash that can be taken out of a business during its remaining life. It is not directly affected by management actions."},
  {"num": 83, "subject": "股权投资", "question": "The discounted value of a company's future projected cash flows is best described as its:", "options": {"A": "book value.", "B": "market value.", "C": "intrinsic value."}, "answer": "C", "explanation": "A Incorrect because a company's book value is the difference between its total assets and total liabilities, not the present value of future projected cash flows.\nB Incorrect because a company's market value is the market price per share times the number of outstanding shares, not the present value of future projected cash flows.\nC Correct because the company's intrinsic value is the present value of its future projected cash flows."},
  {"num": 84, "subject": "股权投资", "question": "Which of the following shareholder groups benefits the most by using cumulative voting?", "options": {"A": "Preference shareholders", "B": "Shareholders with a large number of shares", "C": "Shareholders with a small number of shares"}, "answer": "C", "explanation": "A Incorrect because preference shareholders do not share in the operating performance of the company and generally do not have voting rights. Furthermore, cumulative voting should not be confused with cumulative preference shares which are shares that accrue dividends that must be paid in full before dividends on common shares can be paid.\nB Incorrect because cumulative voting reduces the advantage held by shareholders with a large number of shares. Under cumulative voting, total voting rights are based on the number of shares owned multiplied by the number of board directors being elected. Shareholders can cast all votes in favor of a single candidate or spread them across the candidates in any proportion. While shareholders with a large number of shares still have more votes than shareholders with a small number of shares, their ability to control the board representation now depends on how their votes are proportionately distributed relative to the votes cast by shareholders with a small number of shares.\nC Correct because cumulative voting allows shareholders to direct their total voting rights to specific candidates, as opposed to having to allocate their voting rights evenly among all candidates. The key benefit to cumulative voting is that it allows shareholders with a small number of shares to apply all of their votes to one candidate, thus providing the opportunity for a higher level of representation on the board than would be allowed under statutory voting."},
  {"num": 85, "subject": "股权投资", "question": "In a management buyout transaction, a public company is most likely privatized through the:", "options": {"A": "issue of new shares to management.", "B": "issue of new shares by management.", "C": "purchase of publicly listed shares by management."}, "answer": "C", "explanation": "A Incorrect because an LBO most likely involves the purchase of publicly-listed shares, not the issue of new shares. A leveraged buyout (LBO) occurs when a group of investors (such as the company’s management or a private equity partnership) uses a large amount of debt to purchase all of the outstanding common shares of a publicly traded company. In cases where the group of investors acquiring the company is primarily comprised of the company’s existing management, the transaction is referred to as a management buyout (MBO).\nB Incorrect because in a management buyout, management is the purchaser of shares rather than the issuer of shares. In cases where the group of investors acquiring the company is primarily comprised of the company’s existing management, the transaction is referred to as a management buyout (MBO).\nC Correct because a leveraged buyout (LBO) occurs when a group of investors (such as the company’s management or a private equity partnership) uses a large amount of debt to purchase all of the outstanding common shares of a publicly traded company. In cases where the group of investors acquiring the company is primarily comprised of the company’s existing management, the transaction is referred to as a management buyout (MBO). After the shares are purchased, they cease to trade on an exchange and the investor group takes full control of the company. In other words, the company"},
  {"num": 86, "subject": "股权投资", "question": "If a company raises equity capital in order to continue as a going concern rather than fund revenue-generating activities, the capital is most likely used to:", "options": {"A": "acquire other companies.", "B": "purchase long-lived assets.", "C": "ensure that debt covenants are met."}, "answer": "C", "explanation": "A Incorrect because the primary goal of raising capital is to finance the company's revenue-generating activities. In most cases, the capital that is raised is used to finance the acquisition of other companies.\nB Incorrect because the primary goal of raising capital is to finance the company's revenue-generating activities. In most cases, the capital that is raised is used to finance the purchase of long-lived assets.\nC Correct because a company may be forced to raise capital to ensure that it continues to operate as a going concern. In these cases, capital is raised to fulfill regulatory requirements, improve capital adequacy ratios, or to ensure that debt covenants are met."},
  {"num": 87, "subject": "股权投资", "question": "Preference shares that provide the investor with an opportunity to share in the profits of the company are best described as:", "options": {"A": "cumulative.", "B": "convertible.", "C": "non-cumulative."}, "answer": "B", "explanation": "A Incorrect because neither non-cumulative nor cumulative preference shares do not share in the operating performance of the company and do not allow investors the opportunity to share in the profits of the company.\nB Correct because convertible preference shares allow investors the opportunity to share in the profits of the company.\nC Incorrect because neither non-cumulative nor cumulative preference shares do not share in the operating performance of the company and do not allow investors the opportunity to share in the profits of the company."},
  {"num": 88, "subject": "股权投资", "question": "Common shares most likely rank above preference shares with respect to:", "options": {"A": "voting rights.", "B": "the payment of dividends.", "C": "the distribution of the company's net assets upon liquidation."}, "answer": "A", "explanation": "A Correct because preference shareholders generally do not share in the operating performance of the company and do not have any voting rights.\nB Incorrect because preference shares (or preferred stock) rank above common shares with respect to the payment of dividends and the distribution of the company's net assets upon liquidation.\nC Incorrect because preference shares (or preferred stock) rank above common shares with respect to the payment of dividends and the distribution of the company's net assets upon liquidation."},
  {"num": 89, "subject": "股权投资", "question": "All else being equal, convertible preference shares most likely:", "options": {"A": "are more volatile than the underlying common shares.", "B": "pay lower dividends than the underlying common shares.", "C": "allow investors to share in the underlying company's profits after conversion."}, "answer": "C", "explanation": "A Incorrect because convertible preference shares are less volatile than the underlying common shares because the dividend payments are known and more stable.\nB Incorrect because convertible preference shares allow investors to earn a higher dividend than if they invested in the company's common shares.\nC Correct because convertible preference shares allow investors the opportunity to share in the profits of the company."},
  {"num": 90, "subject": "股权投资", "question": "Downside and upside risk factors are most likely included in:", "options": {"A": "an initial company research report only.", "B": "a subsequent company research report only.", "C": "both initial and subsequent company research reports."}, "answer": "C", "explanation": "A Incorrect because downside and upside risk factors are part of the company research report element \"Risks\" which is not only part of the initial company research report elements but also listed amongst the five elements for the subsequent company research report: 1. Front Matter, 2. Recommendation, 3. Analysis of New Information, 4. Valuation and 5. Risks.\nB Incorrect because downside and upside risk factors are part of the company research report element \"Risks\" which is in fact part of the initial company research report elements as well as listed amongst the five elements for the subsequent company research report: 1. Front Matter, 2. Recommendation, 3. Analysis of New Information, 4. Valuation and 5. Risks.\nC Correct because downside and upside risk factors are part of the company research report element \"Risks\" which is not only part of the initial company research report elements but also listed amongst the five elements for the subsequent company research report: 1. Front Matter, 2. Recommendation, 3. Analysis of New Information, 4. Valuation and 5. Risks."},
  {"num": 91, "subject": "股权投资", "question": "A natural resources company having access to cheap energy most likely will be able to sell its output:", "options": {"A": "at market price.", "B": "above market price.", "C": "at a price unilaterally set by management."}, "answer": "A", "explanation": "A Correct because in the most competitive markets, where firms are selling nearly identical products, firms are price takers—that is, price is dictated by the forces of supply and demand—and all firms generally sell at the same price, i.e. the prevailing market price. Other attributes of highly competitive markets include little to no product differentiation, low barriers to firm entry, available substitutes, a lack of customer loyalty, and low switching costs for customers. Many markets fit this description, including retail, oil and gas and other natural resources.\nB Incorrect because in the most competitive markets, where firms are selling nearly identical products, firms are price takers—that is, price is dictated by the forces of supply and demand—and all firms generally sell at the same price, i.e. the prevailing market price. Other attributes of highly competitive markets include little to no product differentiation, low barriers to firm entry, available substitutes, a lack of customer loyalty, and low switching costs for customers. Many markets fit this description, including retail, oil and gas and other natural resources.\nC Incorrect because this would apply to a company with pricing power which a natural resources company does not have."},
  {"num": 92, "subject": "股权投资", "question": "Which of the following is best described as a source of capital?", "options": {"A": "Debt issuances", "B": "Share repurchases", "C": "Positive net working capital"}, "answer": "A", "explanation": "A Correct because issuing debt will raise money for a company and so is a source of capital, not a use.\nB Incorrect because share repurchases are a use, not a source, of capital. In other words, a company will need to use its resources (capital) to repurchase the shares.\nC Incorrect because a positive net working capital is a use, not a source, of capital. If the net working capital was negative then it would be a source, however a positive net working capital means that a company's resources (capital) will be used to support a level of current assets higher than current liabilities."},
  {"num": 93, "subject": "股权投资", "question": "Within Porter’s five forces framework, the power of buyers within an industry is most likely influenced by the:", "options": {"A": "industry concentration.", "B": "availability of lower priced alternative brands.", "C": "number of customers for the industry’s products."}, "answer": "C", "explanation": "A Incorrect because the degree of industry concentration most likely explains the bargaining power of suppliers, which is a different Porter force.\nB Incorrect because the availability of lower priced alternative brands most likely explains the threat of substitution, a different Porter force.\nC Correct because the smaller the number of buyers, the more likely buyer power will increase. Bargaining Power of Customers. Affected by: size and concentration of customers, costs of switching to other suppliers, customers’ ability to produce the product or service themselves. Are customers able to force price reductions or better payment terms? This can affect the intensity of competition by exerting influence on suppliers regarding prices (and possibly other factors such as product quality). For example, auto parts companies generally sell to a small number of auto manufacturers, which allows those customers, the auto manufacturers, to be tough negotiators when it comes to setting prices."},
  {"num": 94, "subject": "股权投资", "question": "The Global Industry Classification Standard's broadest level of classification is a(n):", "options": {"A": "sector.", "B": "industry.", "C": "industry group."}, "answer": "A", "explanation": "A Correct because in the GICS each company is assigned to a sub-industry according to its principal business activity. Each sub-industry belongs to a particular industry; each industry belongs to an industry group; and each group belongs to a sector. In June 2009, the GICS classification structure comprised four levels of detail consisting of 154 sub- industries, 68 industries, 24 industry groups, and 10 sectors. Therefore, a sector is the broadest level of classification.\nB Incorrect because a sector is the broadest level of classification. Each industry belongs to an industry group; and each group belongs to a sector.\nC Incorrect because a sector is the broadest level of classification. Each industry belongs to an industry group; and each group belongs to a sector."},
  {"num": 95, "subject": "股权投资", "question": "External factors affecting an industry's growth most likely include:", "options": {"A": "cost structures.", "B": "economies of scale.", "C": "technological influences."}, "answer": "C", "explanation": "A Incorrect because external factors affecting an industry's growth include macroeconomic, technological, demographic, governmental, and social influences. In contrast, cost structures (or cost conditions) are internal factors.\nB Incorrect because external factors affecting an industry's growth include macroeconomic, technological, demographic, governmental, and social influences. In contrast, economies of scale is an internal factor.\nC Correct because external factors affecting an industry's growth include macroeconomic, technological, demographic, governmental, and social influences."},
  {"num": 96, "subject": "股权投资", "question": "Commercial industry classification systems are most likely updated:", "options": {"A": "less frequently than government classification systems.", "B": "as frequently as government classification systems.", "C": "more frequently than government classification systems."}, "answer": "C", "explanation": "A Incorrect because most government and commercial classification systems are reviewed and, if necessary, updated from time to time. Generally, commercial classification systems are adjusted more frequently than government classification systems, which may be updated only every five years or so.\nB Incorrect because most government and commercial classification systems are reviewed and, if necessary, updated from time to time. Generally, commercial classification systems are adjusted more frequently than government classification systems, which may be updated only every five years or so.\nC Correct because most government and commercial classification systems are reviewed and, if necessary, updated from time to time. Generally, commercial classification systems are adjusted more frequently than government classification systems, which may be updated only every five years or so."},
  {"num": 97, "subject": "股权投资", "question": "Porter's five determinants of the intensity of competition in an industry do not include the:", "options": {"A": "power of buyers.", "B": "threat of substitutes.", "C": "position of a company in its life-cycle stage."}, "answer": "C", "explanation": "A Incorrect because power of buyers is part of the five forces.\nB Incorrect because threat of substitutes is part of the five forces.\nC Correct because the position of a company in its life-cycle stage is not part of Porter's five forces. The five forces are: threat of entry, power of suppliers, power of buyers, threat of substitutes, and rivalry among existing competitors."},
  {"num": 98, "subject": "股权投资", "question": "Which of the following best describes an industry-level force in a thorough industry analysis?", "options": {"A": "Threat of new entrants", "B": "Demographic influences", "C": "Technological influences"}, "answer": "A", "explanation": "A Correct because industry-level forces driving industry competition include: threat of new entrants, substitution threats, customer and supplier bargaining forces, the competitive forces in the industry (rivalry), life-cycle issues, and business-cycle considerations.\nB Incorrect because macro forces (rather than industry forces) include macroeconomic, demographic, environmental, governmental, social, and technological influences affecting the industry.\nC Incorrect because macro forces (rather than industry forces) include macroeconomic, demographic, environmental, governmental, social, and technological influences affecting the industry."},
  {"num": 99, "subject": "股权投资", "question": "Which of the following industries or sectors is most likely classified as cyclical?", "options": {"A": "Utilities", "B": "Industrials", "C": "Health care"}, "answer": "B", "explanation": "A Incorrect because utilities are classified as non-cyclical. Examples of non-cyclical industries are food and beverage, household and personal care products, health care, and utilities.\nB Correct because examples of cyclical industries and broader sectors are autos, housing, basic materials, industrials, and technology.\nC Incorrect because health care is classified as non-cyclical. Examples of non-cyclical industries are food and beverage, household and personal care products, health care, and utilities."},
  {"num": 100, "subject": "股权投资", "question": "Industry classification systems are developed and used by:", "options": {"A": "commercial entities only.", "B": "governmental agencies only.", "C": "both commercial entities and governmental agencies."}, "answer": "C", "explanation": "A Incorrect because industry classification systems are developed and used by both commercial entities and various governmental agencies.\nB Incorrect because industry classification systems are developed and used by both commercial entities and various governmental agencies.\nC Correct because industry classification systems are developed and used by both commercial entities and various governmental agencies."},
  {"num": 101, "subject": "股权投资", "question": "Which of the following is considered an external influence on industry growth?", "options": {"A": "Social trends", "B": "Barriers to entry", "C": "Industry concentration"}, "answer": "A", "explanation": "A Correct because external factors affecting an industry’s growth include macroeconomic, technological, demographic, governmental, and social influences.\nB Incorrect because barriers to entry are considered internal factors affecting an industry, while external factors affecting an industry’s growth include macroeconomic, technological, demographic, governmental, and social influences.\nC Incorrect because industry concentration is considered an internal factor affecting an industry, while external factors affecting an industry’s growth include macroeconomic, technological, demographic, governmental, and social influences."},
  {"num": 102, "subject": "股权投资", "question": "Industries whose revenues and profits are least affected by fluctuations in the overall economy are most likely:", "options": {"A": "growth industries.", "B": "cyclical industries.", "C": "defensive industries."}, "answer": "C", "explanation": "A Incorrect because growth industries would include industries with specific demand dynamics that are so strong that they override the significance of broad economic or other external factors and generate growth regardless of overall economic conditions, although their rates of growth may slow during an economic downturn.\nB Incorrect because a cyclical industry is one whose profits are strongly correlated with the strength of the overall economy. Such companies experience wider-than-average fluctuations in demand—high demand during periods of economic expansion and low demand during periods of economic contraction—and/or are subject to greater-than-average profit variability related to high operating leverage (i.e., high fixed costs).\nC Correct because defensive industries and companies are those whose revenues and profits are least affected by fluctuations in overall economic activity. These industries/companies tend to produce staple consumer goods (e.g., bread), to provide basic services (grocery stores, drug stores, fast food outlets)."},
  {"num": 103, "subject": "股权投资", "question": "Which of the following is most likely a demographic influence on industry growth?", "options": {"A": "Lifestyle", "B": "Distribution of age", "C": "Spending behavior"}, "answer": "B", "explanation": "A Incorrect because changes in the lifestyle of people happen due to societal influences. Societal changes involving how people work, spend their money, enjoy their leisure time, and conduct other aspects of their lives can have significant effects on the sales of various industries.\nB Correct because changes in distribution of age happen due to demographic influence. Changes in population size, in the distributions of age and gender, and in other demographic characteristics may have significant effects on economic growth and on the amounts and types of goods and services consumed.\nC Incorrect because changes in spending behavior of the customers happen due to societal influences. Societal changes involving how people work, spend their money, enjoy their leisure time, and conduct other aspects of their lives can have significant effects on the sales of various industries."},
  {"num": 104, "subject": "股权投资", "question": "Which of the following statements about forecasting selling, general and administrative (SG&A) expenses is most accurate?", "options": {"A": "General corporate costs are mostly variable costs", "B": "Selling and distribution expenses can be modeled as a percentage of sales", "C": "Overall SG&A expenses have a more direct relationship with revenues than cost of goods sold"}, "answer": "B", "explanation": "A Incorrect because general corporate costs are more fixed costs and might be better modeled using a fixed growth rate based on expected wage inflation.\nB Correct because selling and distribution expenses often have a large variable component and can be modeled as a percentage of sales.\nC Incorrect because cost of sales (cost of goods sold, or COGS) is typically the single largest cost for companies that make and/or sell products. Because it has a direct link with sales, forecasting this item as a percentage of sales (or as a gross margin) is usually a good approach. SG&A expenses often have a less direct relationship with revenues. Although SG&A expenses overall are generally less closely linked to revenue than is cost of sales, certain SG&A expenses could be more variable than others."},
  {"num": 105, "subject": "股权投资", "question": "Which of the following statements about scenario analysis is most accurate?", "options": {"A": "Scenario analysis provides a point estimate forecast", "B": "Forecast scenarios can be compared to forecasts implied by current valuations", "C": "Generic risk factors in scenario analysis are assumed to affect all companies in the same way"}, "answer": "B", "explanation": "A Incorrect because rather than develop single point estimate forecasts, analysts make several forecast scenarios that vary based on different outcomes with respect of key risk factors.\nB Correct because investors compare these scenarios with other analysts’ (e.g., sell-side analysts) forecasts for a company, as well as forecasts implied by current valuations, to make investment decisions.\nC Incorrect because the final step in forecasting involves incorporating the possibility of different outcomes based on key risk factors as well as judging their likelihood of occurrence. Generic risk factors that affect all companies—but to varying degrees— include changes in the business cycle, competition, inflation and deflation, and technological developments."},
  {"num": 106, "subject": "股权投资", "question": "Which financial statement forecasting approach is best suited for companies in highly cyclical industries?", "options": {"A": "Historical results", "B": "Management guidance", "C": "Analyst's discretionary forecasts"}, "answer": "C", "explanation": "A Incorrect because historical results are best suited for companies' relative insensitivity to changes in macroeconomic factors. Using historical results may be appropriate for companies operating in industries where the analyst does not expect the industry structure (e.g., Porter’s Five Forces, PESTLE influences) to change, as well as for companies that have a low sensitivity to changes in the business cycle.\nB Incorrect because management does not have an informational advantage over investors at forecasting macroeconomic variables. Using guidance for forecasts is appropriate when it is provided and when management has demonstrated a track record of reliable estimates (analysts should analyze past guidance versus actuals). We caution against the use of guidance for companies that are highly sensitive to the business cycle, as management does not have an informational advantage over investors at forecasting macroeconomic variables like GDP or the prices of commodities.\nC Correct because analyst’s discretionary forecasts include those based on surveys, quantitative models, probability distributions, analogies to historical precedents that differ from comparable companies or industry averages, and other unobservable inputs. This approach is most common for companies in cyclical industries, companies that have no or few comparables, those that do not provide management guidance, and/or those undergoing a fundamental change like a shift in the competitive or regulatory environment."},
  {"num": 107, "subject": "股权投资", "question": "Which of the following forecast objects for a bank's revenue is best classified as a top-down driver?", "options": {"A": "Net interest income", "B": "Growth in market share", "C": "Growth in the number of branches"}, "answer": "B", "explanation": "A Incorrect because examples of bottom-up drivers for revenue forecasts include return- or yield-based measures. Forecasts based on account balances and revenue yields on them. For example, net interest income for a bank can be calculated as loans multiplied by the average interest rate minus the product of deposits and liabilities and their average interest rate.\nB Correct because forecast objects for revenues are typically either top-down or bottom-up drivers. Common top-down forecast objects include 'growth relative to GDP growth' and 'market growth and market share. The analyst first forecasts a growth rate for a company's product market, and then considers the company's current market share and how that share is likely to change over time.\nC Incorrect because examples of bottom-up drivers for revenue forecasts include capacity-based measures. Forecasts, for example, in retailing, based on the number of stores and sales per store. In the banking context, the number of branches, and the growth thereof, may be considered a capacity-based measure."},
  {"num": 108, "subject": "股权投资", "question": "Depreciation expense is best used in forecasting:", "options": {"A": "growth capital expenditure only.", "B": "maintenance capital expenditure only.", "C": "both growth capital expenditure and maintenance capital expenditure."}, "answer": "B", "explanation": "A Incorrect because depreciation expense can serve as the basis for maintenance capital expenditures, as it is management's estimate of the cost of fixed assets expensed on the income statement in a manner that tracks its use. Growth capital expenditure forecasts are more discretionary and are tied to management's expansion plans and revenue growth. Therefore, it is unlikely that depreciation expense will be used when forecasting this item.\nB Correct because depreciation expense can serve as the basis for maintenance capital expenditures, as it is management's estimate of the cost of fixed assets expensed on the income statement in a manner that tracks its use.\nC Incorrect because depreciation expense can serve as the basis for maintenance capital expenditures, as it is management's estimate of the cost of fixed assets expensed on the income statement in a manner that tracks its use. Growth capital expenditure forecasts are more discretionary and are tied to management's expansion plans and revenue growth. Therefore, it is unlikely that depreciation expense will be used when forecasting this growth capital expenditure."},
  {"num": 109, "subject": "股权投资", "question": "Asset-based valuation most likely uses estimates of the company's:", "options": {"A": "assets only.", "B": "assets and liabilities only.", "C": "assets, liabilities, and projected cash flow."}, "answer": "B", "explanation": "A Incorrect because an asset-based valuation of a company uses estimates of the market or fair value of the company’s assets and liabilities.\nB Correct because an asset-based valuation of a company uses estimates of the market or fair value of the company’s assets and liabilities.\nC Incorrect because an asset-based valuation of a company uses estimates of the market or fair value of the company’s assets and liabilities."},
  {"num": 110, "subject": "股权投资", "question": "A stock dividend:", "options": {"A": "is relevant for valuation of a company.", "B": "involves a reduction in the number of shares outstanding.", "C": "does not affect the shareholders' proportional ownership in the company."}, "answer": "C", "explanation": "A Incorrect because stock dividends are not relevant for valuation.\nB Incorrect because a stock dividend is a type of dividend in which a company distributes additional shares of its common stock (typically, 2%–10% of the shares then outstanding) to shareholders instead of cash. This results in an increase, not a reduction in the number of shares outstanding.\nC Correct because a stock dividend divides the “pie” (the market value of shareholders’ equity) into smaller pieces without affecting the value of the pie or any shareholder’s proportional ownership in the company."},
  {"num": 111, "subject": "股权投资", "question": "All else being equal, a reverse stock split results in:", "options": {"A": "a decrease in the number of shares and an increase in the share price.", "B": "an increase in the number of shares and a decrease in the share price.", "C": "an increase in the number of shares and an increase in the share price."}, "answer": "A", "explanation": "A Correct because a reverse stock split involves a reduction in the number of shares outstanding with a corresponding increase in share price.\nB Incorrect because this describes a stock split, not a reverse stock split. A stock split involves an increase in the number of shares outstanding with a consequent decrease in share price. A reverse stock split involves a reduction in the number of shares outstanding with a corresponding increase in share price.\nC Incorrect because a reverse stock split involves a reduction in the number of shares outstanding with a corresponding increase in share price."},
  {"num": 112, "subject": "股权投资", "question": "In dividend payment chronology, the ex-dividend date most likely comes after the:", "options": {"A": "record date.", "B": "payment date.", "C": "declaration date."}, "answer": "C", "explanation": "A Incorrect because ex-dividend date is followed closely (one or two business days later) by the holder-of-record date (also called the owner-of-record date, shareholder-of-record date, record date, date of record, or date of book closure), the date that a shareholder listed on the company’s books will be deemed to have ownership of the shares for purposes of receiving the upcoming dividend.\nB Incorrect because the final milestone in the dividend payment chronology is the payment date (or payable date), which is the day that the company actually mails out (or electronically transfers) a dividend payment to shareholders.\nC Correct because first is the declaration date, the day that the company issues a statement declaring a specific dividend. Next comes the ex-dividend date (or ex- date), the first date that a share trades without (i.e., “ex”) the dividend."},
  {"num": 113, "subject": "股权投资", "question": "All else being equal, which of the following are equivalent to stock dividends in terms of the economic effect on the company and shareholders?", "options": {"A": "Stock splits", "B": "Cash dividends", "C": "Share repurchases"}, "answer": "A", "explanation": "A Correct because a stock dividend divides the “pie” (the market value of shareholders’ equity) into smaller pieces without affecting the value of the pie or any shareholder’s proportional ownership in the company. Thus, stock dividends are not relevant for valuation. Stock splits and reverse stock splits are similar to stock dividends in that they have no economic effect on the company or shareholders.\nB Incorrect because a cash dividend is a cash distribution made to a company’s shareholders. No cash flow from the company to the shareholders happen in case of a stock dividend. A stock dividend divides the “pie” (the market value of shareholders’ equity) into smaller pieces without affecting the value of the pie or any shareholder’s proportional ownership in the company. Thus, stock dividends are not relevant for valuation.\nC Incorrect because a share repurchase (or buyback) is a transaction in which a company uses cash to buy back its own shares. A share repurchase is viewed as equivalent to the payment of cash dividends of equal value in terms of the effect on shareholders’ wealth, all other things being equal."},
  {"num": 114, "subject": "股权投资", "question": "A firm reports negative earnings for the year just ended. The price multiple of the firm’s stock that is least likely to be meaningful is:", "options": {"A": "price to cash flow.", "B": "trailing price to earnings.", "C": "leading price to earnings."}, "answer": "B", "explanation": "A Incorrect . Alternative to negative trailing price-to-earnings ratio, practitioners may use price-to-cash-flow ratio because it is possible cash flow would be positive in spite of a small loss.\nB Correct . Negative earnings in the last year result in a negative ratio of trailing price to earnings and are not meaningful. Practitioners may use the ratio of (1) current price to cash flow or (2) leading price to earnings by replacing last year’s loss with forecasted earnings.\nC Incorrect . Alternative to negative trailing price-to-earnings ratio, practitioners may use leading price-to-earnings ratio by replacing last year’s loss with forecasted earnings which may be positive."},
  {"num": 115, "subject": "股权投资", "question": "A $25 par value non-callable, non-convertible preferred share pays an annual dividend rate of 5%. If the required rate of return is 4%, the preferred share's intrinsic value is closest to:", "options": {"A": "$25.25.", "B": "$26.00.", "C": "$31.25."}, "answer": "C", "explanation": "A Incorrect because it is equal to the par value + 1% (the difference between the 5% dividend and the 4% required return). 25 × (1 + (0.05 – 0.04)) = $25.25. Also, if a candidate mistakenly calculates V0 = (25 × 0.04) / 0.05 = $20.00, which is closest to this answer choice.\nB Incorrect because it is the par value multiplied by the required return = 25 × (1 + 0.04) = $26.\nC Correct because the estimated intrinsic value (V0) is: , where D0 = dividend, and r = the required rate of return. The D0 = par value × annual dividend rate = $25 × 0.05 = $1.25. V0 = $1.25 / 0.04 = $31.25."},
  {"num": 116, "subject": "股权投资", "question": "An analyst gathers the following information about a company's shares:\nAll else being equal, at the beginning of trading on 20 August, the company's shares will most likely trade at:", "options": {"A": "$28.50.", "B": "$29.00.", "C": "$29.50."}, "answer": "A", "explanation": "A Correct because the ex-dividend date (or ex-date) is the first date that a share trades without (i.e., 'ex') the dividend. Because buyers of a company's shares on the ex-dividend date are no longer eligible to receive the upcoming dividend, all else being equal, on that day the company's share price immediately decreases by the amount of the foregone dividend. If the share trades at $29.00 on 19 August (the day before ex-date) and the upcoming dividend is $0.50, then all else being equal, the shares would trade at $28.50 ($29.00 - $0.50) on the ex-date.\nB Incorrect because $29.00 is the price of the share before the ex-date which is the last day purchasers will receive the upcoming dividend. All else being equal, the share price should trade below $29.00 and not at or above $29.00.\nC Incorrect because purchasers of shares on the ex-date or after the ex-date will not be entitled to the upcoming dividend and the share price should trade below $29.00 and not above $29.00. An uninformed candidate may confuse the dates and think that the share price on the ex-date should include dividends declared and inadvertently think that the 19 August share price doesn't include the dividend. Therefore the uninformed candidate adds $0.50 to the share price to arrive at $29.50."},
  {"num": 117, "subject": "股权投资", "question": "An analyst gathers the following information about a company and its common stock:\nUsing the Gordon growth model, the company's dividend payout ratio is closest to:", "options": {"A": "8%.", "B": "33%.", "C": "64%."}, "answer": "C", "explanation": "A Incorrect because it confuses the dividend payout ratio with the dividend yield in the Gordon growth model equation resulting in: D1/P0 = r – g = 0.12 – 0.04 = 0.08 = 8%.\nB Incorrect because it confuses the dividend payout ratio as the dividend growth rate divided by the required rate of return, resulting in p = 0.04/0.12 ≈ 0.333 = 33%. This is also closest to the product of the forward P/E and the dividend growth rate: 8.0 × 0.04 = 0.32 = 32%.\nC Correct because according to the Gordon growth model equations"},
  {"num": 118, "subject": "股权投资", "question": "An analyst gathers the following information about a company and the economy:\nThe best estimate of the company's dividend growth rate is:", "options": {"A": "5.8%.", "B": "6.7%.", "C": "7.4%."}, "answer": "B", "explanation": "A Incorrect because it uses the retention rate instead of the payout ratio; 22 = 0.60 / (0.085 – g) and g = 0.0577 or 5.8%.\nB Correct because justified forward P/E = p / (r – g), where p = payout ratio = (1 – retention rate) and r = required rate of return = nominal risk-free rate + risk premium. 22 = (1 – 0.60) / ((0.025 + 0.06) – g). 22 = 0.40 / (0.085 – g) and g = 0.0668 ≈ 6.7%.\nC Incorrect because it uses the current stock price instead of the P/E ratio to solve for g: 36 = 0.40 / (0.085 – g) and g = 0.0739 ≈ 7.4%."},
  {"num": 119, "subject": "股权投资", "question": "All else being equal, an increase in which of the following most likely increases a company's enterprise value?", "options": {"A": "Book value of debt", "B": "Market value of investments", "C": "Market value of preferred stock"}, "answer": "C", "explanation": "A Incorrect because enterprise value is most frequently determined as market capitalization plus market value of preferred stock plus market value of debt minus cash and investments (cash equivalents and short-term investments). Enterprise value increases with an increase in the market value, not book value, of debt.\nB Incorrect because enterprise value is most frequently determined as market capitalization plus market value of preferred stock plus market value of debt minus cash and investments (cash equivalents and short-term investments). Enterprise value increases with a decrease, not increase, in the market value of cash and investments.\nC Correct because enterprise value is most frequently determined as market capitalization plus market value of preferred stock plus market value of debt minus cash and investments (cash equivalents and short-term investments). Therefore, enterprise value increases with an increase in the market value of preferred stock."},
  {"num": 120, "subject": "股权投资", "question": "Enterprise value is most likely associated with:", "options": {"A": "multiplier models.", "B": "present value models.", "C": "asset-based valuation models."}, "answer": "A", "explanation": "A Correct because multiplier models are based chiefly on share price multiples or enterprise value multiples. Enterprise value (EV) multiples have the form (Enterprise value)/(Value of a fundamental variable). Two possible choices for the denominator are earnings before interest, taxes, depreciation, and amortization (EBITDA) and total revenue.\nB Incorrect because present value models estimate the intrinsic value of a security as the present value of the future benefits expected to be received from the security. In present value models, benefits are often defined in terms of cash expected to be distributed to shareholders (dividend discount models) or in terms of cash flows available to be distributed to shareholders after meeting capital expenditure and working capital needs (free-cash-flow-to-equity models).\nC Incorrect because asset-based valuation models estimate intrinsic value of a common share from the estimated value of the assets of a corporation minus the estimated value of its liabilities and preferred shares. The estimated market value of the assets is often determined by making adjustments to the book value (synonym: carrying value) of assets and liabilities. The theory underlying the asset-based approach is that the value of a business is equal to the sum of the value of the business's assets."},
  {"num": 121, "subject": "股权投资", "question": "An analyst gathers the following information about an industry and three comparable companies within the industry:\nBased only on this information, the most overvalued company is:", "options": {"A": "Company 1.", "B": "Company 2.", "C": "Company 3."}, "answer": "A", "explanation": "A Correct because Company 1's P/S and P/B are both the highest compared to those of its two peers and the industry average. All else being equal, high P/S and P/B multiples point to relatively expensive valuations. Therefore, in the absence of conflict between the indications given by P/S and P/B (as both measures are the highest for the same company), the company most likely to be overvalued is Company 1.\nB Incorrect because the P/S and P/B of Company 2 are lower than those of both Company 1 and the industry average.\nC Incorrect because the P/S and P/B of Company 3 are lower than those of both Company 1 and the industry average."},
  {"num": 122, "subject": "股权投资", "question": "An analyst gathers the following book value information about a company and its common shares:\nThe analyst estimates the market value of net fixed assets to be 125% of book value and the market value of inventories to be 90% of book value. If the stock is currently trading at €19.50 per share, the asset-based value per share is most likely:", "options": {"A": "less than the market price.", "B": "equal to the market price.", "C": "greater than the market price."}, "answer": "B", "explanation": "A Incorrect because the unadjusted, not adjusted, asset-based value per share is less than the market price: (Total assets – total liabilities) / shares outstanding = (150 – 90) / 4 = 15.00.\nB Correct because the asset-based per share value is: market value of assets less market value of liabilities = (Total assets + increase in net fixed assets – decrease in inventories – total liabilities) / shares outstanding = [(150 + ((80 × 1.25) – 80) + ((20 × 0.90) – 20) – 90)] / 4 = (150 + 20 – 2 – 90) / 4 = 19.50. This is the same as the market price.\nC Incorrect because it double counts net fixed assets and inventories by adding the adjusted net fixed assets and subtracts the adjusted inventories without removing the unadjusted values from total assets: (Total assets + adjusted net fixed assets – adjusted inventories – total liabilities) / shares outstanding = (150 + (80 × 1.25) – (0.90 × 20) – 90) / 4 = (150 + 100 – 18 – 90) / 4 = 35.50. 35.50 is greater than the market price of 19.50."},
  {"num": 123, "subject": "股权投资", "question": "All else being equal, which of the following has the same effect on shareholders' wealth as a cash dividend?", "options": {"A": "A stock split", "B": "A stock dividend", "C": "A share repurchase"}, "answer": "C", "explanation": "A Incorrect because in contrast to stock dividends and stock splits, share repurchases are an alternative to cash dividend payments.\nB Incorrect because in contrast to stock dividends and stock splits, share repurchases are an alternative to cash dividend payments.\nC Correct because a share repurchase is viewed as equivalent to the payment of cash dividends of equal value in terms of the effect on shareholders’ wealth, all other things being equal."},
  {"num": 124, "subject": "股权投资", "question": "Asset-based valuation models are most appropriate for companies with a high proportion of:", "options": {"A": "illiquid assets.", "B": "current assets.", "C": "intangible assets."}, "answer": "B", "explanation": "A Incorrect because illiquid assets would not have easily determinable market (fair) values and would be very difficult to analyze using asset valuation methods.\nB Correct because asset-based valuations work well for companies that do have a high proportion of current assets and current liabilities.\nC Incorrect because asset-based valuations work well for companies that do not have a high proportion of intangible or ‘off the books' assets."},
  {"num": 125, "subject": "股权投资", "question": "The dividend discount model assumes that dividends are paid:", "options": {"A": "quarterly.", "B": "half yearly.", "C": "at the end of each year."}, "answer": "C", "explanation": "A Incorrect because according to the dividend discount model, each year's dividend Dt is the expected dividend in year t, assumed to be paid at the end of the year, not at the beginning of each year.\nB Incorrect because according to the dividend discount model, each year's dividend Dt is the expected dividend in year t, assumed to be paid at the end of the year, not at the midpoint of each year.\nC Correct because according to the dividend discount model, each year's dividend Dt is the expected dividend in year t, assumed to be paid at the end of the year."},
  {"num": 126, "subject": "股权投资", "question": "When using a multiplier model, the fundamental variable is stated on:", "options": {"A": "a trailing basis only.", "B": "a forward basis only.", "C": "either a trailing basis or a forward basis."}, "answer": "C", "explanation": "A Incorrect because the fundamental variable may be stated on a forward basis (e.g., forecasted EPS for the next year) or a trailing basis (e.g., EPS for the past year), as long as the usage is consistent across companies being examined.\nB Incorrect because the fundamental variable may be stated on a forward basis (e.g., forecasted EPS for the next year) or a trailing basis (e.g., EPS for the past year), as long as the usage is consistent across companies being examined.\nC Correct because the fundamental variable may be stated on a forward basis (e.g., forecasted EPS for the next year) or a trailing basis (e.g., EPS for the past year), as long as the usage is consistent across companies being examined."},
  {"num": 127, "subject": "股权投资", "question": "A free-cash-flow-to-equity model is a(n):", "options": {"A": "multiplier model.", "B": "present value model.", "C": "asset-based valuation model."}, "answer": "B", "explanation": "A Incorrect because a FCFE model is an example of a present value model, while multiplier models are based chiefly on share price multiples or enterprise value multiples.\nB Correct because present value models include free-cash-flow-to-equity models.\nC Incorrect because a FCFE model is an example of a present value model, while asset-based valuation models estimate intrinsic value of a common share from the estimated value of the assets of a corporation minus the estimated value of its liabilities and preferred shares."},
  {"num": 128, "subject": "股权投资", "question": "An analyst gathers the following information about common shares:\nIf the investor's required rate of return is 9%, the company's justified forward P/E is:", "options": {"A": "less than the peer group's justified forward P/E.", "B": "the same as the peer group's justified forward P/E.", "C": "greater than the peer group's justified forward P/E."}, "answer": "B", "explanation": "A Incorrect because the company's justified forward P/E is not less than the peer group's justified forward P/E, but is the same. The company's justified forward P/E = p / (r – g) = 0.40 / (0.09 – 0.05) = 10.0. The peer group's justified forward P/E = 0.50 / (0.09 – 0.04) = 10.0. The candidate may select this response if they believe the company's lower payout ratio results in a lower P/E.\nB Correct because the company's justified forward P/E is the same as the peer group's justified forward P/E. The company's justified forward P/E = p / (r – g) = 0.40 / (0.09 – 0.05) = 10.0. The peer group's justified forward P/E = 0.50 / (0.09 – 0.04) = 10.0.\nC Incorrect because the company's justified forward P/E is not greater than the peer group's justified forward P/E, but is the same. The company's justified forward P/E = p / (r – g) = 0.40 / (0.09 – 0.05) = 10.00. The peer group's justified forward P/E = 0.50 / (0.09 – 0.04) = 10.00. The candidate may select this response if they believe that the company's higher future dividend growth rate results in a higher P/E."},
  {"num": 129, "subject": "股权投资", "question": "An analyst gathers the following information about a company and its historical price multiples:\nBased only on this information, if the share price is $30, the company's shares are most likely overvalued based on:", "options": {"A": "P/B.", "B": "P/E.", "C": "P/CF."}, "answer": "A", "explanation": "A Correct because the P/B value for the company is $30 ⁄ $40 = 0.75, which is above the benchmark ratio of 0.6, indicating the shares are overvalued based on P/B (i.e. the ratio is higher than the benchmark). Both the P/E and P/CF ratios for the company are below their benchmarks, and therefore are not overvalued on that basis.\nB Incorrect because the P/E value for the company is $30 ⁄ $3 = 10, which is below the benchmark ratio of 12, indicating the shares are undervalued based on P/E (i.e. the ratio is lower than the benchmark).\nC Incorrect because the P/CF value for the company is $30 ⁄ $4 = 7.5, which is below the benchmark ratio of 8, indicating the shares are undervalued based on P/CF (i.e. the ratio is lower than the benchmark)."},
  {"num": 130, "subject": "股权投资", "question": "A non-callable, non-convertible perpetual preferred share pays a level dividend of $1.20 with a current market price of $20. If an investor has a required rate of return of 6%, the preferred shares are most likely:", "options": {"A": "undervalued.", "B": "fairly valued.", "C": "overvalued."}, "answer": "B", "explanation": "A Incorrect because the market price equals the calculated intrinsic value, implying the shares are not undervalued.\nB Correct because the market price is equal to the calculated value based on the stated rate of return. Since the preferred share pays a perpetual level dividend, its value is V0 = D0/r = $1.20/0.06 = $20. If the estimated value equals the market price, the analyst infers the security is fairly valued.\nC Incorrect because the market price equals the calculated intrinsic value, implying the shares are not overvalued."},
  {"num": 131, "subject": "股权投资", "question": "An analyst gathers the following information about a company:\nIf the investor's required rate of return is 10%, the company's ROE is closest to:", "options": {"A": "6.9%.", "B": "8.0%.", "C": "9.7%."}, "answer": "A", "explanation": "A Correct because P0/E1 = p/(r – g), where g = b × ROE Restating the equation we arrive at: P0/E1 = p/(r – (b × ROE)) where: p = dividend payout ratio = (1 – retention rate) = (1 – b) r = required rate of return on the stock g = dividend growth rate = retention rate × ROE Therefore, P0/E1 = p/(r – (b × ROE)) is rearranged as: P0/E1 = (1 – b)/(r – (b × ROE)) Rearranging this equation we arrive at: ROE = (((1 – b)/(P0/E1)) – r)/–b ROE = (((1 – 45%)/8) – 10%)/–45% ≈ 6.9%.\nB Incorrect because the retention rate and the dividend payout ratio have been interchanged. That is, arriving at this answer incorrectly applies 45% as the dividend payout ratio and applies 55% as the retention rate in the rearranged ROE calculation of: ROE = (((1 – b)/(P0/E1)) – r)/–b. That is, ROE is incorrectly calculated as: ROE = (((1 – 55%)/8) – 10%)/–55% ≈ 8.0%.\nC Incorrect because instead of applying p, the dividend payout ratio, or (1 – b) in the numerator, the return ratio has been used in the numerator. That is, ROE was erroneously applied as, ROE = (((b)/(P0/E1)) – r)/–b. That is, ROE is mistakenly calculated as: ROE = (((45%)/8) – 10%)/–45% ≈ 9.7%."},
  {"num": 132, "subject": "股权投资", "question": "An analyst gathers the following data for three companies in the same industry (in millions):\nBased on enterprise value multiples, which of the three companies is likely the most undervalued?", "options": {"A": "Company 1", "B": "Company 2", "C": "Company 3"}, "answer": "A", "explanation": "A Correct because EV is often viewed as the cost of a takeover and EBITDA is a proxy for operating cash flow. Companies with relatively low EV/EBITDA multiples are likely to be undervalued. Company 1 has the lowest EV/EBITDA multiple among the three. Company 1: EV/EBITDA = 100,000,000 / 8,000,000 = 12.5; Company 2: EV/EBITDA = 150,000,000 / 10,000,000 = 15.0; Company 3: EV/EBITDA = 200,000,000 / 15,000,000 = 13.3.\nB Incorrect because Company 1's EV/EBITDA multiple is lower than either Company 2's or Company 3's multiple which indicates that Company 1 is likely the most undervalued of the three.\nC Incorrect because Company 1's EV/EBITDA multiple is lower than either Company 2's or Company 3's multiple which indicates that Company 1 is likely the most undervalued of the three."},
  {"num": 133, "subject": "股权投资", "question": "A company's perpetual preferred stock has a $100 par value and a $1.50 quarterly dividend. The required rate of return is 5%. The intrinsic value of the preferred stock is most likely:", "options": {"A": "less than the par value.", "B": "equal to the par value.", "C": "greater than the par value."}, "answer": "C", "explanation": "A Incorrect because for the preferred shares to be valued below par, the dividend yield must be lower than the required return.\nB Incorrect because for the preferred shares to be valued at par, the dividend yield must be equal to the required return.\nC Correct because the dividend yield is 6% ((4 × 1.50) / 100) which is higher than the required return (5%), so the preferred shares will be valued above par. Alternatively, the intrinsic value (V0) = D0 / r, where D0 is the preferred stock's constant annual dividend and r is the required rate of return. V0 = (4 × 1.50) / 0.05 = $120 which is higher than the par value."},
  {"num": 134, "subject": "股权投资", "question": "An analyst valuing a stock makes the following assumptions:\n• the required return does not change,\n• the dividend growth rate does not change,\n• the dividend growth rate is less than the required return.\nThe most appropriate model to value this stock is the:", "options": {"A": "Gordon growth model.", "B": "two-stage dividend discount model.", "C": "three-stage dividend discount model."}, "answer": "A", "explanation": "A Correct because the assumptions of the Gordon model are as follows: Dividends are the correct metric to use for valuation purposes; The dividend growth rate is forever: It is perpetual and never changes; The required rate of return is also constant over time; The dividend growth rate is strictly less than the required rate of return.\nB Incorrect because the two-stage DDM thus makes use of two growth rates: a high growth rate for an initial, finite period followed by a lower, sustainable growth rate into perpetuity.\nC Incorrect because a three-stage DDM, makes use of three growth rates: a high growth rate for an initial finite period, followed by a lower growth rate for a finite second period, followed by a lower, sustainable growth rate into perpetuity."},
  {"num": 135, "subject": "股权投资", "question": "An analyst gathers the following information about a company and its non-callable, non-convertible, perpetual preferred stock:\nIf the analyst estimates the intrinsic value to be €26.00 per share, the required rate of return is closest to:", "options": {"A": "5.96%.", "B": "6.20%.", "C": "6.32%."}, "answer": "A", "explanation": "A Correct because the intrinsic value of a non-callable, non-convertible, perpetual preferred share is: V0 = D0 / r. Solving for r = D0 / V0 = €1.55 / €26.00 ≈ 5.96%.\nB Incorrect because it uses the par value instead of the analyst's estimated intrinsic value: r = D0 / par value = €1.55 / €25.00 = 0.062 = 6.20%.\nC Incorrect because the dividend is increased by the EPS growth rate: D0 ×(1+g) / V0 = €1.55 × 1.06 / €26.00 = €1.643 / €26.00 ≈ 6.32%."},
  {"num": 136, "subject": "股权投资", "question": "An analyst gathers the following information about a common stock:\nThe stock's intrinsic value is closest to:", "options": {"A": "€33.90.", "B": "€34.22.", "C": "€35.17."}, "answer": "C", "explanation": "A Incorrect because D0 is used as the year 1 dividend instead of D1: V0 = D0 / (1 + r) + D1 / (1 + r)2 + P1 / (1 + r)2 V0 = D0 / (1 + r) + D1 / (1 + r)2 + (D2 / (r – gL)) / (1 + r)2 V0 = (1.10 / 1.07) + (1.10 × 1.15) / 1.072 + ((1.10 × 1.152) / (0.07 – 0.03)) / 1.072 V0= €33.90.\nB Incorrect because D2 is used instead of D3 in calculating P2. V0 = D1 / (1 + r) + D2 / (1 + r)2 + P1 / (1 + r)2 V0 = D1 / (1 + r) + D2 / (1 + r)2 + (D2 / (r – gL)) / (1 + r)2 V0 = (1.10 × 1.15) / 1.07 + (1.10 × 1.152) / 1.072 + ((1.10 × 1.152) / (0.07 – 0.03)) / 1.072 V0 = €34.22.\nC Correct because the stock's value based on the multistage dividend discount model is as follows:"},
  {"num": 137, "subject": "股权投资", "question": "An analyst gathers the following per share estimates for a company's stock:\nUsing the dividend discount model, if the required rate of return is 10% and the stock's current market price is $50.00, the stock is most likely:", "options": {"A": "undervalued.", "B": "fairly valued.", "C": "overvalued."}, "answer": "C", "explanation": "A Incorrect because the stock's intrinsic value ($48.60) is less than the current market price for the stock ($50.00). A candidate may mistake the relationship between value and price and incorrectly conclude that the stock is undervalued.\nB Incorrect because the stock's intrinsic value ($48.60) is less than the current market price for the stock ($50.00). A candidate may mistakenly select B on the basis that the stock price at the end of year 2 is the same as the stock's current market price.\nC Correct because using the dividend discount model, the stock's intrinsic value (V0) is given by: V0 = Where:"},
  {"num": 138, "subject": "股权投资", "question": "The free-cash-flow-to-equity model:", "options": {"A": "excludes net borrowings.", "B": "can be used to value non-dividend paying stocks.", "C": "requires an estimate of future dividend payments."}, "answer": "B", "explanation": "A Incorrect because net amounts borrowed (borrowings minus repayments) are considered to be available for distribution to common shareholders.\nB Correct because analysts may also use FCFE valuation models for a non-dividend-paying stock.\nC Incorrect because in practice, many analysts prefer to use a free-cash-flow-to-equity (FCFE) valuation model. These analysts assume that dividend-paying capacity should be reflected in the cash flow estimates rather than expected dividends. FCFE is a measure of dividend-paying capacity."},
  {"num": 139, "subject": "股权投资", "question": "At which of the following days does a buyer of a company's shares first become no longer eligible to receive a dividend?", "options": {"A": "Day before the ex-dividend date", "B": "Ex-dividend date", "C": "Day after the ex-dividend date"}, "answer": "B", "explanation": "A Incorrect because buyers of a company’s shares on the ex-dividend date are no longer eligible to receive the upcoming dividend, all else being equal, on that day the company’s share price immediately decreases by the amount of the foregone dividend.\nB Correct because buyers of a company’s shares on the ex-dividend date are no longer eligible to receive the upcoming dividend, all else being equal, on that day the company’s share price immediately decreases by the amount of the foregone dividend. C.e ex-dividend date are no longer eligible to receive the upcoming dividend, all else being equal, on that day the company’s share price immediately decreases by the amount of the foregone dividend."},
  {"num": 140, "subject": "股权投资", "question": "An advantage of using price multiples in valuation is most likely that multiples:", "options": {"A": "allow easy cross-sectional comparisons.", "B": "are not affected by differences in accounting rules.", "C": "for cyclical companies are relatively stable over the economic cycle."}, "answer": "A", "explanation": "A Correct because the major advantage of using price multiples is that they allow for relative comparisons, both cross-sectional (versus the market or another comparable) and in time series. The approach can be especially beneficial for analysts who are assigned to a particular industry or sector and need to identify the expected best performing stocks within that sector. Price multiples are popular with investors because the multiples can be calculated easily and many multiples are readily available from financial websites and newspapers.\nB Incorrect because differences in reporting rules among different markets and in chosen accounting methods can result in revenues, earnings, book values, and cash flows that are not easily comparable. These differences can, in turn, result in multiples that are not easily comparable.\nC Incorrect because the multiples for cyclical companies may be highly influenced by current economic conditions."},
  {"num": 1, "subject": "衍生品", "question": "Compared to over-the-counter (OTC) derivatives that are not cleared, the credit risk of exchange-traded derivatives is most likely:", "options": {"A": "lower.", "B": "the same.", "C": "higher."}, "answer": "A", "explanation": "A Correct because derivative exchanges require collateral on deposit upon inception and during the life of a trade in order to minimize counterparty credit risk. This deposit is paid by each counterparty via a financial intermediary to the exchange, which then provides a guarantee against counterparty default, whereas OTC (over-the-counter) instruments have less transparency, usually involve more counterparty risk. Therefore, compared to OTC derivatives that are not cleared, the credit risk of exchange-traded derivatives is lower.\nB Incorrect because derivative exchanges require collateral on deposit upon inception and during the life of a trade in order to minimize counterparty credit risk. This deposit is paid by each counterparty via a financial intermediary to the exchange, which then provides a guarantee against counterparty default, whereas OTC (over-the-counter) instruments have less transparency, usually involve more counterparty risk. Therefore, compared to OTC derivatives that are not cleared, the credit risk of exchange-traded derivatives is lower, not the same.\nC Incorrect because derivative exchanges require collateral on deposit upon inception and during the life of a trade in order to minimize counterparty credit risk. This deposit is paid by each counterparty via a financial intermediary to the exchange, which then provides a guarantee against counterparty default, whereas OTC (over-the-counter) instruments have less transparency, usually involve more counterparty risk. Therefore, compared to OTC derivatives that are not cleared, the credit risk of exchange-traded derivatives is lower, not higher."},
  {"num": 2, "subject": "衍生品", "question": "Which of the following statements is most accurate?", "options": {"A": "Longevity is an example of an underlying of a derivative", "B": "A convertible bond is an example of a stand-alone derivative", "C": "Derivatives directly pass through the returns of the underlying"}, "answer": "A", "explanation": "A Correct because other derivative underlyings include weather, cryptocurrencies, and longevity, all of which can influence the financial performance of various market participants. Therefore, longevity is an example of an underlying of a derivative.\nB Incorrect because a distinct derivative contract, such as a derivative on a stock or bond, is an example of a stand-alone derivative. An embedded derivative is a derivative within an underlying, such as a callable, puttable, or convertible bond. Therefore, convertible bond is not a stand-alone derivative, but an embedded derivative.\nC Incorrect because a derivative does not directly pass through the returns of the underlying but transforms the performance of the underlying."},
  {"num": 3, "subject": "衍生品", "question": "Derivatives derive their performance from:", "options": {"A": "the performance of the underlying asset.", "B": "eliminating the risk of counterparty default.", "C": "the straight pass-through performance of the underlying."}, "answer": "A", "explanation": "A Correct because the most common definition of a derivative is a financial instrument that derives its performance from the performance of the underlying asset.\nB Incorrect because derivatives are subject to the risk of default. Forward contracts are subject to default. This also applies to swaps, where either party can default but only one party can default at a particular time. While a credit derivative provides protection… against a specific credit loss, it does not eliminate the risk of default.\nC Incorrect because the transformation of performance for the case of derivatives is a critical, factor distinguishing derivatives from mutual funds and exchange-traded funds and some other straight pass-through instruments."},
  {"num": 4, "subject": "衍生品", "question": "Compared to over-the-counter (OTC) derivative markets, exchange-traded derivative markets most likely have greater:", "options": {"A": "flexibility.", "B": "transparency.", "C": "customization."}, "answer": "B", "explanation": "A Incorrect because the OTC markets for derivatives will remain considerably more flexible than the exchange-listed markets. Therefore, exchange-traded derivatives markets have lower level of flexibility than OTC derivatives markets.\nB Correct because many transactions in OTC markets will retain a degree of privacy with lower transparency. In contrast, exchange markets are said to have transparency, which means that full information on all transactions is disclosed to exchanges and regulatory bodies. Therefore, exchange-traded derivatives markets have greater transparency than OTC derivatives markets.\nC Incorrect because exchange-traded derivatives are standardized, whereas OTC derivatives are customized. Therefore, exchange-traded derivatives markets have lower customization than OTC derivatives markets."},
  {"num": 5, "subject": "衍生品", "question": "Which of the following derivative underlyings is an example of a soft commodity?", "options": {"A": "Gold", "B": "Crude oil", "C": "Soybeans"}, "answer": "C", "explanation": "A Incorrect because gold is a metal and hence a hard commodity. Soft commodities are agricultural products, such as cattle and corn, and hard commodities are natural resources, such as crude oil and metals. Also, crude oil, soybeans, copper, and gold are all commodities. Commodities are considered either 'hard' (those mined, such as copper, or extracted, such as oil) or 'soft' (those grown over a period of time, such as livestock, grains, and cash crops, such as coffee).\nB Incorrect because, despite its physical (liquid) nature, crude oil is categorized as a hard commodity since it is a natural resource. Soft commodities are agricultural products, such as cattle and corn, and hard commodities are natural resources, such as crude oil and metals.\nC Correct because soft commodities are agricultural products, such as cattle and corn, and hard commodities are natural resources, such as crude oil and metals. Also, crude oil, soybeans, copper, and gold are all commodities. Commodities are considered either 'hard' (those mined, such as copper, or extracted, such as oil) or 'soft' (those grown over a period of time, such as livestock, grains, and cash crops, such as coffee)."},
  {"num": 6, "subject": "衍生品", "question": "An investor buys a call for $5.75 that has a strike price of $130. If the value at expiration for this call is $17.80, the price of the underlying at expiration is closest to:", "options": {"A": "$112.20.", "B": "$142.05", "C": "$147.80."}, "answer": "C", "explanation": "A Incorrect because $112.20 is the value of the underlying assuming that this was a put option instead of a call option. The \"payoff to the put buyer\" at expiration is pT = Max(0, X – ST), where X is the exercise price and ST is the price of the underlying at expiration. Given the information in the stem we get $17.80 = Max(0,$130 – ST) which yields ST = $130 – $17.80 = $112.20. By contrast, the value or \"payoff to the call buyer\" at expiration is cT = Max(0,ST – X). Given the information in the stem we get $17.80 = Max(0,ST – $130). Hence, ST = 130 + 17.80 = 147.80, not $112.20.\nB Incorrect because $142.05 is the profit from the option position added to the strike price. It is computed as (cT – c0) + X where cT is the value of the option at expiration, c0 is the purchase price of the option and X is the strike price. Given the information in the stem we get ($17.80 – $5.75) + $130 = $142.05. By contrast, the value or \"payoff to the call buyer\" at expiration is cT = Max(0,ST – X) where X is the strike price, ST is the price of the underlying at expiration. Given the information in the stem we get $17.80 = Max(0,ST – $130). Hence, ST =$ 130 + $17.80 = $147.80, not $142.05.\nC Correct because the value or \"payoff to the call buyer\" at expiration is cT = Max(0,ST – X) where X is the strike price, ST is the price of the underlying at expiration. Given the information in the stem we get $17.80 = Max(0,ST – $130). Hence, ST =$ 130 + $17.80 = $147.80."},
  {"num": 7, "subject": "衍生品", "question": "A call option had the following characteristics on the date it was created:\nIf the price of the underlying is $17 at expiration, the profit to the option holder is closest to:", "options": {"A": "−$3.", "B": "$0.", "C": "$3."}, "answer": "A", "explanation": "A Correct because the profit on the call buyer is Π = Max(0,ST – X) – c0, where ST is the price of the underlying at expiration, X is the exercise price, and c0 is the call option premium paid. Hence, the profit to the call option buyer or holder is Max(0,$17 – $20) – $3 = – $3.\nB Incorrect because $0 is the profit on a long put position: the profit to the put buyer is Π = Max(0,X – ST) – p0, where ST is the price of the underlying at expiration, X is the exercise price, and p0 is the put option premium paid. Hence, the profit to the put buyer is Max(0,$20 – $17) – $3 = $3 – $3 = $0. Alternatively, this is the value or payoff to the call buyer at expiration, which is Max(0,ST – X) or Max(0,$17 - $20) = $0. By contrast, the profit to the call buyer is Π = Max(0,ST – X) – c0, where c0 is the call option premium paid. Hence, the profit to the call option buyer or holder is Max(0,$17 – $20) – $3 = – $3, not $0.\nC Incorrect because $3 is the value or payoff to the put buyer at expiration, which is pT = Max(0,X – ST), where ST is the price of the underlying at expiration and X is the exercise price. Hence the payoff to the put buyer is Max(0,$20 – $17) = $3. Alternatively, this is also the profit to the call seller which is Π = –Max(0,ST – X) + c0, where c0 is the call option premium received. Hence, the profit to the call seller is –Max(0,$17 – $20) + $3 = $0 + $3 = $3. By contrast, the profit to the call buyer is Π = Max(0,ST – X) – c0, where c0 is the call option premium paid. Hence, the profit to the call option buyer or holder is Max(0,$17 – $20) – $3 = – $3, not $3."},
  {"num": 8, "subject": "衍生品", "question": "If ST denotes the price of the underlying at the expiration date and X is the exercise price of the option, the payoff at expiration to a call seller is best described as:", "options": {"A": "–Max(0, ST – X).", "B": "–Max(0, X – ST).", "C": "Max(0, ST – X)."}, "answer": "A", "explanation": "A Correct because to the seller, the value of the option at that point is ‒Max(0, ST – X), which is negative to the seller if the option is in the money and zero otherwise.\nB Incorrect because –Max(0, X – ST) (payoff to the put seller). –Max denotes a short position and X – ST the inner value of a put option at expiration. Therefore, –Max(0, X – ST) describes the payoff to a put seller and not to a call seller.\nC Incorrect because Max(0, ST – X) (payoff to the call buyer). Max denotes a long position and ST – X the inner value of a call option at expiration. Therefore, Max(0, ST – X) describes the payoff to a call buyer and not to a call seller."},
  {"num": 9, "subject": "衍生品", "question": "A call option that is sold for $4 has an exercise price of $40. If the price of the underlying is $43 at expiration, the value of the option to the seller is closest to:", "options": {"A": "–$3, and the loss to the seller is $1.", "B": "–$3, and the profit to the seller is $1.", "C": "$3, and the loss to the seller is $1."}, "answer": "B", "explanation": "A Incorrect because the value or payoff to the call seller is equal to –cT = –Max(0,ST – X), where ST is the price of the underlying at expiration and X is the exercise price. Here the value or payoff of the call to the seller is –Max(0,$43 – $40) = –$3. Further, the profit to the call seller is equal to Π = –Max(0,ST – X) + c0, where c0 is the option price or premium paid by the call buyer to the call seller. Therefore, the profit to the call seller is –Max(0,$43 – $40) + $4 = –$3 + $4 = $1, not –$1, which is equal to a loss of $1.\nB Correct because the value or payoff to the call seller is equal to –cT = –Max(0,ST – X), where ST is the price of the underlying at expiration and X is the exercise price. Here the value or payoff of the call to the seller is –Max(0,$43 – $40) = –$3. Further, the profit to the call seller is equal to Π = –Max(0,ST – X) + c0, where c0 is the option price or premium paid by the call buyer to the call seller. Therefore, the profit to the call seller is –Max(0,$43 – $40) + $4 = –$3 + $4 = $1.\nC Incorrect because the value or payoff to the call seller is equal to –cT = –Max(0,ST – X), where ST is the price of the underlying at expiration and X is the exercise price. Here the value or payoff of the call to the seller is –Max(0,$43 – $40) = $–3, not $3. Further, the profit to the call seller is equal to Π = –Max(0,ST – X) + c0, where c0 is the option price or premium paid by the call buyer to the call seller. Therefore, the profit to the call seller is –Max(0,$43 – $40) + $4 = –$3 + $4 = $1, not –$1 which is equal to a loss of $1."},
  {"num": 10, "subject": "衍生品", "question": "An investor pays $5 for a European put option with an exercise price of $102. At expiration, if the price of the underlying is $100, the value of the put option is:", "options": {"A": "−$3.", "B": "$0.", "C": "$2."}, "answer": "C", "explanation": "A Incorrect because the value of the put option is not equal to the profit to the put buyer which is Π = Max(0,X – ST) – p0, where X is the exercise price, ST is the price of the underlying at expiration, and p0 is the put premium paid. Therefore, the profit is equal to Max(0,X – ST) – p0 = Max(0,$102 – $100) – $5 = –$3. Instead, the value of the put option at expiration is pT = Max(0,X – ST) or Max(0,$102 – 100) = $2.\nB Incorrect because it confuses the put option with a call option. The value to the call buyer at expiration is cT = Max(0,ST – X) or Max(0,$100 – 102) = $0, where ST is the price of the underlying at expiration and X is the exercise price. Instead, the value of the put option at expiration is pT = Max(0,X – ST) or Max(0,$102 – 100) = $2.\nC Correct because the payoff to the put holder is: pT = Max(0,X – ST) where ST is the price of the underlying at expiration, and X is the exercise price. Therefore, the value of the put at expiration when ST = $100 and X = $102 is pT = Max(0,$102 – $100) = $2."},
  {"num": 11, "subject": "衍生品", "question": "An American put has a strike price of ¥5,000 and expires in one year. The current price of the underlying is ¥4,200 and the risk-free rate is 2%. The maximum value of this put is:", "options": {"A": "¥800.", "B": "¥4,900.", "C": "¥5,000."}, "answer": "C", "explanation": "A Incorrect because this is the payoff of the option if the current price of the underlying did not change for the next year. The payoff to the put holder is: pT = Max(0,X – ST) where ST is the price of the underlying at expiration, and X is the exercise price. Therefore, the maximum payoff is when ST = 0 and pT = Max(0,¥5,000 – 0) = ¥5,000.\nB Incorrect because ¥4,900 is the present value of X, the strike price discounted at the risk-free rate of 2%. This is wrong because the payoff to the put holder is: pT = Max(0,X – ST) where ST is the price of the underlying at expiration, and X is the exercise price. Therefore, the maximum payoff is when ST = 0 and pT = Max(0,¥5,000 – 0) = ¥5,000.\nC Correct because the payoff to the put holder is: pT = Max(0,X – ST) where ST is the price of the underlying at expiration, and X is the exercise price. Therefore, the maximum payoff is when ST = 0 and pT = Max(0,¥5,000 – 0) = ¥5,000."},
  {"num": 12, "subject": "衍生品", "question": "The following information relates to a put option and the underlying stock:\nThe value of the put option to the option seller at expiration is:", "options": {"A": "–$7.", "B": "$0.", "C": "$7."}, "answer": "B", "explanation": "A Incorrect because pT = Max(0,X – ST). pT is put option value at expiration, X is European put strike price and ST is stock price at expiration. So, pT = Max($0,$78 – $85) ≠ -$7. Therefore, the value of the put option at expiration is not −$7.\nB Correct because pT = Max(0,X – ST). pT is put option value at expiration, X is European put strike price and ST is stock price at expiration. So, pT = Max($0,$78 – $85) = $0. Therefore, the value of the put option at expiration is $0.\nC Incorrect because pT = Max(0,X – ST). pT is put option value at expiration, X is European put strike price and ST is stock price at expiration. So, pT = Max($0,$78 – $85) ≠ $7. Therefore, the value of the put option at expiration is not $7."},
  {"num": 13, "subject": "衍生品", "question": "All else being equal, if the price of the underlying at expiration exceeds the exercise price, the option value at expiration for the seller of a put most likely is:", "options": {"A": "less than the option value at expiration for the seller of a call.", "B": "equal to the option value at expiration for the seller of a call.", "C": "greater than the option value at expiration for the seller of a call."}, "answer": "C", "explanation": "A Incorrect because the payoff or value at expiration to the put seller is defined as –Max(0,X – ST), where X is the exercise price and ST is the value of the underlying at expiration. If ST exceeds X, then the value to the put seller is zero. By contrast, the payoff or value to the call seller is defined as –Max(0,ST – X), in which case the value is negative. Therefore, for ST > X, the value to the put seller is zero, and therefore greater, not less than, the value to the call seller which is negative.\nB Incorrect because the payoff or value at expiration to the put seller is defined as –Max(0,X – ST), where X is the exercise price and ST is the value of the underlying at expiration. If ST exceeds X, then the value to the put seller is zero. By contrast, the payoff or value to the call seller is defined as –Max(0,ST – X), in which case the value is negative. Therefore, for ST > X, the value to the put seller is zero, and therefore greater, not equal to, the value to the call seller which is negative.\nC Correct because the payoff or value at expiration to the put seller is defined as –Max(0,X – ST), where X is the exercise price and ST is the value of the underlying at expiration. If ST exceeds X, then the value to the put seller is zero. By contrast, the payoff or value to the call seller is defined as –Max(0,ST – X), in which case the value is negative. Therefore, for ST > X, the value to the put seller is zero and, therefore, greater than the value to the call seller which is negative."},
  {"num": 14, "subject": "衍生品", "question": "An investor gathers the following information about a European put option and its underlying:\nIf the price of the underlying at expiration is $27, the profit for a buyer of the put is:", "options": {"A": "−$1.", "B": "$0.", "C": "$2."}, "answer": "B", "explanation": "A Incorrect because it represents the exercise price X minus the initial underlying price S0 minus the premium paid p0, or $29 – $28 – $2= –$1. This is not the profit, which is $0, as described in the response rationale for the correct answer.\nB Correct because the profit for a put buyer is Π = Max(0,X – ST) – p0, where X is the exercise price, ST is the price of the underlying at expiration, and p0 is the put premium paid. Therefore, the profit is equal to Max(0,$29 – $27) – $2 = $0.\nC Incorrect because it represents value or payoff at expiration to the put buyer, not profit for the put buyer. The value of payoff is pT = Max(0, X – ST), where pT is the value of the put option at expiration, X is the exercise price of the option, and ST is the price of the underlying at expiration. Therefore, pT = Max(0, $29 – $27) = $2. This is not the profit, which is $0, as described in the response rationale for the correct answer."},
  {"num": 15, "subject": "衍生品", "question": "A call option has the following characteristics:\nThe profit to the call seller is closest to:", "options": {"A": "−$80.", "B": "$0.", "C": "$80."}, "answer": "C", "explanation": "A Incorrect because –$80 represents the profit to the call buyer which is Π = Max(0,ST – X) – c0, where ST is the price of the underlying at expiration, X is the exercise price, and c0 is the call option premium. Hence, Max(0,$2,020 – $2,100) – $80 = –$80. By contrast, the profit to call seller is Π = –Max(0,ST – X) + c0. Hence, –Max(0,$2,020 – $2,100) + $80 = $80, not –$80.\nB Incorrect because $0 represents the value or payoff to the call seller which is –cT = –Max(0,ST – X), where ST is the price of the underlying at expiration and X is the exercise price. Hence, –Max(0,$2,020 – $2,100) = $0. By contrast, the profit to call seller is Π = –Max(0,ST – X) + c0, where c0 is the call option premium. Hence, –Max(0,$2,020 – $2,100) + $80 = $80, not $0.\nC Correct because the profit to call seller is Π = –Max(0,ST – X) + c0, where ST is the price of the underlying at expiration, X is the exercise price, and c0 is the call option premium received. Hence, –Max(0,$2,020 – $2,100) + $80 = $0 + $80 = $80."},
  {"num": 16, "subject": "衍生品", "question": "Which of the following is most likely an example of a contingent claim? A(n):", "options": {"A": "swap contract", "B": "option contract", "C": "futures contract"}, "answer": "B", "explanation": "A Incorrect because there are two general classes of derivatives. Some provide the ability to lock in a price at which one might buy or sell the underlying. Because they force the two parties to transact in the future at a previously agreed-on price, these instruments are called forward commitments. The various types of forward commitments are called forward contracts, futures contracts, and swaps. Therefore, a swap contract is a forward commitment, not a contingent claim.\nB Correct because another class of derivatives provides the right but not the obligation to buy or sell the underlying at a pre-determined price. Because the choice of buying or selling versus doing nothing depends on a particular random outcome, these derivatives are called contingent claims. The primary contingent claim is called an option.\nC Incorrect because there are two general classes of derivatives. Some provide the ability to lock in a price at which one might buy or sell the underlying. Because they force the two parties to transact in the future at a previously agreed-on price, these instruments are called forward commitments. The various types of forward commitments are called forward contracts, futures contracts, and swaps. Therefore, a futures contract is a forward commitment, not a contingent claim."},
  {"num": 17, "subject": "衍生品", "question": "Forward contracts have:", "options": {"A": "less counter-party risk than futures.", "B": "the same level of counter-party risk as futures.", "C": "more counter-party risk than futures."}, "answer": "C", "explanation": "A Incorrect because futures contracts are forward contracts with standardized sizes, dates, and underlyings that trade on futures exchanges. Futures markets offer both greater liquidity and protection against loss by default (compared to forwards) by combining contract uniformity with an organized market with rules, regulations, and a central clearing facility. Also a forward contract is an over-the-counter (OTC) derivative in which two counterparties agree that one counterparty, the buyer, will purchase an underlying from the other counterparty, the seller, in the future at a pre-agreed fixed price. As noted earlier, OTC derivatives offer greater flexibility and customization than exchange-traded derivatives (ETD), but also usually involve more counterparty risk. Therefore, forwards have more, not less, counterparty risk than futures.\nB Incorrect because futures contracts are forward contracts with standardized sizes, dates, and underlyings that trade on futures exchanges. Futures markets offer both greater liquidity and protection against loss by default (compared to forwards) by combining contract uniformity with an organized market with rules, regulations, and a central clearing facility. Also a forward contract is an over-the-counter (OTC) derivative in which two counterparties agree that one counterparty, the buyer, will purchase an underlying from the other counterparty, the seller, in the future at a pre-agreed fixed price. As noted earlier, OTC derivatives offer greater flexibility and customization than exchange-traded derivatives (ETD), but also usually involve more counterparty risk. Therefore, forwards have more, not the same level, of counterparty risk than futures.\nC Correct because futures contracts are forward contracts with standardized sizes, dates, and underlyings that trade on futures exchanges. Futures markets offer both greater liquidity and protection against loss by default (compared to forwards)] by combining contract uniformity with an organized market with rules, regulations, and a central clearing facility. Also a forward contract is an over-the-counter (OTC) derivative in which two counterparties agree that one counterparty, the buyer, will purchase an underlying from the other counterparty, the seller, in the future at a pre-agreed fixed price. As noted earlier, OTC derivatives offer greater flexibility and customization than exchange-traded derivatives (ETD), but also usually involve more counterparty risk. Therefore, forwards have more counterparty risk than futures."},
  {"num": 18, "subject": "衍生品", "question": "The payoff to the seller of a forward contract at expiration is defined as the:", "options": {"A": "forward price plus the value of the underlying at expiration.", "B": "forward price minus the value of the underlying at expiration.", "C": "value of the underlying at expiration minus the forward price."}, "answer": "B", "explanation": "A Incorrect because the long is obligated to pay F0(T) for which he receives an asset worth ST. The short has the mirror image of the long. He is required to deliver the asset worth ST and accept a smaller amount, F0(T). Therefore, the payoff to the seller at expiration is F0(T) − ST, not F0(T) + ST.\nB Correct because the long is obligated to pay F0(T), for which he receives an asset worth ST. The short has the mirror image of the long. He is required to deliver the asset worth ST and accept a smaller amount, F0(T). Here F0(T) is the forward price agreed at contract initiation with T denoting the time of expiry, and ST is the value of the underlying at expiry. Therefore, the payoff to the forward seller at expiration is F0(T) − ST.\nC Incorrect because it represents ST − F0(T) which is the payoff for the buyer of the contract. This is not the payoff to the seller at expiration, as described in the response rationale for the correct answer."},
  {"num": 19, "subject": "衍生品", "question": "Which of the following characteristics is most likely common to both forwards and swaps?", "options": {"A": "Customization of contract terms", "B": "Marked to the settlement price on a daily basis", "C": "Multiple payments over the life of the contract"}, "answer": "A", "explanation": "A Correct because both forward contracts and swaps are traded over-the-counter (OTC), allowing the counterparties to negotiate and agree upon specific features for each contract. Exchange-traded derivatives are standardized, whereas OTC derivatives are customized. Further, a forward contract is an over-the-counter derivative contract. Also, a swap is an over-the-counter derivative contract. Therefore, both forward contracts and swaps can be customized as they both are OTC derivative products.\nB Incorrect because it describes a characteristic of futures but not forward contracts or swaps. Probably the most important distinctive characteristic of futures contracts (compared to forwards and swaps) is the daily settlement of gains and losses and the associated credit guarantee provided by the exchange through its clearinghouse. In addition, at the end of each day, the clearinghouse engages in a practice called marked to market, also known as the daily settlement. The clearinghouse determines an average of the final futures trades of the day and designates that price as the settlement price. All contracts are then said to be marked to the settlement price. Therefore, both forwards and swaps are not marked to the settlement price on a daily basis.\nC Incorrect because this describes a swap but not a forward contract. The concept of a swap is that two parties exchange (swap) a series of cash flows. Whereas in a forward contract the buyer will purchase an underlying asset from the other party, the seller, at a later date at a fixed price they agree on when the contract is signed."},
  {"num": 20, "subject": "衍生品", "question": "A forward commitment:", "options": {"A": "has a linear payoff in relation to the underlying.", "B": "involves an exchange of cash at contract initiation.", "C": "provides one party the right to transact at a later date."}, "answer": "A", "explanation": "A Correct because forwards, futures, and swaps represent firm commitments. Further, the symmetric payoff profile is a common feature of firm commitments. Since the derivative price is a linear function of the underlying, firm commitments are also referred to as linear derivatives.\nB Incorrect because as with futures and forward contracts, no money is exchanged when a swap contract is initiated. Also, forward commitments require no cash outlay at inception. Therefore, for forwards, futures, and swaps, no money is exchanged at contract initiation.\nC Incorrect because forwards, futures, and swaps represent firm commitments, or derivative contracts that require counterparties to exchange an underlying in the future based on an agreed-on price. Also, forwards, futures, and swaps are the most common derivative contracts which represent a firm commitment. This firm commitment is an obligation of both counterparties to perform under the terms of the derivative contract. Therefore, forward commitments do not provide rights to the contract parties, they require the forward parties to exchange an underlying in the future based on an agreed-on price."},
  {"num": 21, "subject": "衍生品", "question": "Which of the following types of derivatives has a non-linear payoff?", "options": {"A": "Swaps", "B": "Options", "C": "Forwards"}, "answer": "B", "explanation": "A Incorrect because given that the holder of the contingent claim has a choice, the term contingent claim has become synonymous with the term option. The holder has a choice of whether or not to exercise the option. This choice creates a payoff that transforms the underlying payoff in a more pronounced manner than does a forward, futures, or swap. Those instruments provide linear payoffs: As the underlying goes up (down), the derivative gains (loses). The further up (down) the underlying goes, the more the derivative gains (loses). Options are different in that they limit losses in one direction.\nB Correct because given that the holder of the contingent claim has a choice, the term contingent claim has become synonymous with the term option. The holder has a choice of whether or not to exercise the option. This choice creates a payoff that transforms the underlying payoff in a more pronounced manner than does a forward, futures, or swap. Those instruments provide linear payoffs: As the underlying goes up (down), the derivative gains (loses). The further up (down) the underlying goes, the more the derivative gains (loses). Options are different in that they limit losses in one direction.\nC Incorrect because given that the holder of the contingent claim has a choice, the term contingent claim has become synonymous with the term option. The holder has a choice of whether or not to exercise the option. This choice creates a payoff that transforms the underlying payoff in a more pronounced manner than does a forward, futures, or swap. Those instruments provide linear payoffs: As the underlying goes up (down), the derivative gains (loses). The further up (down) the underlying goes, the more the derivative gains (loses). Options are different in that they limit losses in one direction."},
  {"num": 22, "subject": "衍生品", "question": "The potential divergence between the cash flow timing of a derivative instrument versus its underlying best describes:", "options": {"A": "basis risk.", "B": "liquidity risk.", "C": "systemic risk."}, "answer": "B", "explanation": "A Incorrect because basis risk is described as the potential divergence between the expected value of a derivative instrument versus an underlying or hedged transaction.\nB Correct because liquidity risk is described as potential divergence between the cash flow timing of a derivative instrument versus an underlying or hedged transaction.\nC Incorrect because systemic risk results from excessive risk taking and use of leverage in derivative markets that may contribute to market stress."},
  {"num": 23, "subject": "衍生品", "question": "The potential divergence between the expected value of a derivative instrument versus an underlying or hedged transaction best describes:", "options": {"A": "basis risk.", "B": "liquidity risk.", "C": "systemic risk."}, "answer": "A", "explanation": "A Correct because basis risk is the potential divergence between the expected value of a derivative instrument versus an underlying or hedged transaction.\nB Incorrect because liquidity risk is the potential divergence between the cash flow timing of a derivative instrument versus an underlying or hedged transaction.\nC Incorrect because systemic risk relates to excessive risk taking and use of leverage in derivative markets."},
  {"num": 24, "subject": "衍生品", "question": "A commodities producer selling its inventory forward in anticipation of lower prices in the future is an example of a:", "options": {"A": "fair value hedge.", "B": "cash flow hedge.", "C": "net investment hedge."}, "answer": "A", "explanation": "A Correct because a fair value hedge designation applies when a derivative is deemed to offset the fluctuation in fair value of an asset or liability. A commodities producer might sell its inventory forward in anticipation of lower future prices.\nB Incorrect because derivatives designated as absorbing the variable cash flow of a floating-rate asset or liability such as foreign exchange, interest rates, or commodities are referred to as cash flow hedges. A swap to a fixed rate for a floating-rate debt liability is another example of a cash flow hedge.\nC Incorrect because net investment hedges occur when either a foreign currency bond or a derivative such as an FX swap or forward is used to offset the exchange rate risk of the equity of a foreign operation."},
  {"num": 25, "subject": "衍生品", "question": "Basis risk is best described as a(n):", "options": {"A": "investor's inability to meet a margin call due to a lack of funds.", "B": "potential divergence between the expected value of a derivative and its underlying.", "C": "divergence in the cash flow timing of a derivative versus that of an underlying transaction."}, "answer": "B", "explanation": "A Incorrect because a related risk that can arise for both hedgers and risk takers is liquidity risk, or a divergence in the cash flow timing of a derivative versus that of an underlying transaction. The daily settlement of gains and losses in the futures market can give rise to liquidity risk. If an investor or issuer using a futures contract to hedge an underlying transaction is unable to meet a margin call due to a lack of funds, the counterparty’s position is closed out and the investor or issuer must cover any losses on the derivative trade.\nB Correct because basis risk is the potential divergence between the expected value of a derivative instrument versus an underlying or hedged transaction.\nC Incorrect because a related risk that can arise for both hedgers and risk takers is liquidity risk, or a divergence in the cash flow timing of a derivative versus that of an underlying transaction."},
  {"num": 26, "subject": "衍生品", "question": "WIth respect to hedge accounting designation types, a:", "options": {"A": "foreign exchange forward to hedge forecasted sales is an example of a fair value hedge.", "B": "commodity futures contract used to hedge inventory is an example of a cash flow hedge.", "C": "currency forward to offset the foreign exchange risk of equity of a foreign operation is an example of a net investment hedge."}, "answer": "C", "explanation": "A Incorrect because FX forward to hedge forecasted sales absorbs variable cash flow of floating-rate asset or liability (forecasted transaction) and is an example of a cash flow hedge.\nB Incorrect because commodity futures used to hedge inventory offsets fluctuation in fair value of an asset or liability and is an example of a fair value hedge.\nC Correct because currency forward designated as offsetting the FX risk of the equity of a foreign operation is an example of a net investment hedge."},
  {"num": 27, "subject": "衍生品", "question": "A principal argument against using derivatives is that they:", "options": {"A": "destabilize the financial system.", "B": "are ineffective in transferring risk between parties.", "C": "prevent price discovery of underlying assets in spot markets."}, "answer": "A", "explanation": "A Correct because the two principal arguments against derivatives are that they are such speculative devices that they effectively permit legalized gambling and that they destabilize the financial system.\nB Incorrect because derivatives provide an effective method of transferring risk from parties who do not want the risk to parties who do.\nC Incorrect because one of the advantages of futures markets has been described as price discovery. Derivative markets can convey information not impounded in spot markets. Therefore, it is not a principal argument against derivatives that they prevent price discovery of the underlying assets in spot markets."},
  {"num": 28, "subject": "衍生品", "question": "If the net cost of carry is zero, the forward price of a commodity is most likely:", "options": {"A": "less than the commodity's spot price compounded at the risk-free rate over the life of the contract.", "B": "equal to the commodity's spot price compounded at the risk-free rate over the life of the contract.", "C": "greater than the commodity's spot price compounded at the risk-free rate over the life of the contract."}, "answer": "B", "explanation": "A Incorrect because when benefits exceed the costs, then the forward transaction would return less than the spot transaction. The formula adjusts the forward price downward by the expression – (γ – θ)(1 + r)T to reflect this net loss over the spot transaction. In other words, acquiring the asset in the forward market would be cheaper because it forgoes benefits that exceed the costs. Therefore, forward price of a commodity will be less than the commodity's spot price compounded at the risk-free rate over the life of the contract when net cost of carry, (γ –θ), is positive, not when it is zero.\nB Correct because the forward price of an asset with benefits and/or costs is the spot price compounded at the risk-free rate over the life of the contract minus the future value of those benefits and costs. That is, F0(T) = S0(1+r)T – (γ – θ)(1+r)T, where the net cost of carry consists of the benefits, denoted as γ (dividends or interest plus convenience yield), minus the costs, denoted as θ. When net cost of carry is zero, the term (γ – θ) is zero, resulting in (γ – θ)(1+r)T being zero. Then, F0(T) = S0(1+r)T. Hence, the forward price of a commodity is equal to the commodity's spot price compounded at the risk-free rate over the life of the contract when the net cost of carry is zero.\nC Incorrect because if the costs exceeded the benefits, the forward price would be higher because the forward contract avoids the costs at the expense of the lesser benefits. Then, the term (γ – θ)(1+r)T will be negative, adding to S0(1+r)T in absolute terms (due to preceding negative sign), resulting in a forward price that is higher than the spot price compounded at the risk-free rate. Therefore, the forward price of a commodity will be greater than the commodity's spot price compounded at the risk-free rate over the life of the contract when the net cost of carry, (γ – θ), is negative, not when it is zero."},
  {"num": 29, "subject": "衍生品", "question": "A stock with a dividend yield of 3% is trading in the spot market at $50. If the annual risk-free rate is 5%, the 6-month forward price of the stock is closest to:", "options": {"A": "$49.50.", "B": "$50.50.", "C": "$51.27."}, "answer": "B", "explanation": "A Incorrect because the risk-free rate and the dividend yield were reversed. ≠ F0(T) = $50e(0.03 – 0.05)0.5 = $49.50249 ≈ $49.50.\nB Correct because the forward price is: F0(T) = S0e(r – i)T where r is the risk-free rate, i is the dividend yield, and T is the time period. F0(T) = $50e(0.05 – 0.03)0.5 = $50.50251 ≈ $50.50.\nC Incorrect because the dividend was excluded from the calculation."},
  {"num": 30, "subject": "衍生品", "question": "All else being equal, the cost of carry on a dividend-paying stock is:", "options": {"A": "lower than the cost of carry on a stock with no dividends.", "B": "the same as the cost of carry on a stock with no dividends.", "C": "higher than the cost of carry on a stock with no dividends."}, "answer": "A", "explanation": "A Correct because the benefit of the dividend reduces the costs associated with carrying the stock. The cost of carry is the net of the costs and benefits related to owning an underlying asset for a specific period. The cost of carry is the opportunity cost plus other costs of ownership less benefits of ownership, and stock dividends or bond coupons are examples of cash flow benefits.\nB Incorrect because the benefit of the dividend reduces the costs associated with carrying the stock. The cost of carry is the net of the costs and benefits related to owning an underlying asset for a specific period. The cost of carry is the opportunity cost plus other costs of ownership less benefits of ownership, and stock dividends or bond coupons are examples of cash flow benefits.\nC Incorrect because the benefit of the dividend reduces the costs associated with carrying the stock. The cost of carry is the net of the costs and benefits related to owning an underlying asset for a specific period. The cost of carry is the opportunity cost plus other costs of ownership less benefits of ownership, and stock dividends or bond coupons are examples of cash flow benefits."},
  {"num": 31, "subject": "衍生品", "question": "Which of the following asset classes is most likely to have a convenience yield?", "options": {"A": "Commodities", "B": "Interest rates", "C": "Foreign exchange"}, "answer": "A", "explanation": "A Correct because convenience yield is a non-cash benefit associated with physical assets. In contrast to securities or cash stored electronically, commodities usually involve known costs associated with the storage, insurance, transportation, and potential spoilage (in the case of soft commodities) of these physical assets. A non-cash benefit of holding a physical commodity versus a derivative is known as a convenience yield.\nB Incorrect because a convenience yield is a non-cash benefit associated with physical assets. In contrast to securities or cash stored electronically, commodities usually involve known costs associated with the storage, insurance, transportation, and potential spoilage (in the case of soft commodities) of these physical assets. A non-cash benefit of holding a physical commodity versus a derivative is known as a convenience yield.\nC Incorrect because a convenience yield is a non-cash benefit associated with physical assets. In contrast to securities or cash stored electronically, commodities usually involve known costs associated with the storage, insurance, transportation, and potential spoilage (in the case of soft commodities) of these physical assets. A non-cash benefit of holding a physical commodity versus a derivative is known as a convenience yield."},
  {"num": 32, "subject": "衍生品", "question": "The risk-free rate is 3% and the risk premium for an asset is 2%. If an investor creates a perfect hedge by combining the asset with a derivative, the combined position should earn:", "options": {"A": "0%.", "B": "3%.", "C": "5%."}, "answer": "B", "explanation": "A Incorrect because when a long position in the underlying is combined with a short position in the derivative to produce a perfect hedge, all of the risk is eliminated and the position should earn the risk-free rate not zero percent.\nB Correct because when a long position in the underlying is combined with a short position in the derivative to produce a perfect hedge, all of the risk is eliminated and the position should earn the risk-free rate which is 3% in this case.\nC Incorrect because when a long position in the underlying is combined with a short position in the derivative to produce a perfect hedge, all of the risk is eliminated and the position should earn the risk-free rate not 5% percent. This incorrect answer choice is equal to the risk-free rate of 3% plus the risk premium of 2%."},
  {"num": 33, "subject": "衍生品", "question": "The rate typically used in derivative pricing models to discount expected payoffs is the:", "options": {"A": "risk-free rate.", "B": "risk-free rate plus a risk premium.", "C": "risk-free rate multiplied by the risk-neutral probability."}, "answer": "A", "explanation": "A Correct because virtually all derivative pricing models ultimately take this form: discounting the expected payoff of the derivative at the risk-free rate.\nB Incorrect because because the risk aversion of the investor is not relevant to pricing the derivative, one can just as easily obtain the derivative price by assuming that the investor is risk neutral. That means that the expected payoff of the derivative can be discounted at the risk-free rate rather than the risk-free rate plus a risk premium. Virtually all derivative pricing models ultimately take this form: discounting the expected payoff of the derivative at the risk- free rate. Therefore, the rate used in derivative pricing models to discount expected payoffs is not described as the risk-free rate plus a risk premium.\nC Incorrect because in the process of derivative pricing, there is an intermediate step, which entails altering the probabilities of the outcomes from the true probabilities to something called risk-neutral probabilities. Therefore, risk-neutral probabilities are used to determine the likelihood of expected outcomes and are not the rate used in derivative pricing models to discount expected payoffs."},
  {"num": 34, "subject": "衍生品", "question": "Two-year and three-year government benchmark zero-coupon bonds are priced at 96 and 93 (per 100 face value), respectively. The implied one-year forward rate in two years’ time is closest to:", "options": {"A": "3.00%.", "B": "3.23%.", "C": "3.36%."}, "answer": "B", "explanation": "A Incorrect because it calculates the equivalent zero rate as: z2 = (100 – DF2) / 2; or = (100 – 96) / 2 = 2.0000% z3 = (100 – DF3) / 3; or = (100 – 93) / 3 = 2.3333% Accordingly, (1.020000)2 × (1 + IFR2,1)1 = (1.023333)3 (1 + IFR2,1) = (1.023333)3 / (1.020000)2 (1 + IFR2,1) = (1.071646 / 1.04040) 1 + IFR2,1 = 1.030033 IFR2,1 = 1.030033 – 1 = 3.0033% ≈ 3.00%.\nB Correct because a discount factor may also be interpreted as the price of a zero-coupon cash flow or bond. The price equivalent of a zero rate is the present value of a currency unit on a future date, known as a discount factor. The discount factor for period i (DFi) is: DFi = 1 / (1+zi). Accordingly, the equivalent zero rate is: DF2 = 0.96 = 1 / (1 + z2)2; and z2 = 2.0621% DF3 = 0.93 = 1 / (1 + z3)3; and z3 = 2.4485% The implied forward rate between period A and period B is denoted as IFRA,B–A. It is a forward rate on a bond that starts in period A and ends in period B a general formula for the relationship between the two spot rates (zA, zB) and the implied forward rate (IFRA,B–A): (1 + zA)A × (1 + IFRA,B–A)B–A = (1 + zB)B. (1.020621)2 × (1 + IFR2,3–2)3–2 = (1.024485)3 (1 + IFR2,1) = (1.024485)3 / (1.020621)2 (1 + IFR2,1) = (1.075269 / 1.041667) 1 + IFR2,1 = 1.032258 IFR2,1 = 1.032258 – 1 = 3.2258% ≈ 3.23%.\nC Incorrect because the implied forward rate is calculated as follows:"},
  {"num": 35, "subject": "衍生品", "question": "A forward agreement has the following terms:\nAt expiration, if the spot price is $282, the value to the seller is:", "options": {"A": "–$6,000.", "B": "$6,000.", "C": "$14,000."}, "answer": "B", "explanation": "A Incorrect because this is the value at expiration for the buyer: = ST – F0(T) = $282 – $285 = –$3. Hence total value is –$3 × 2,000 shares = –$6,000.\nB Correct because the value at expiration for the seller: = F0(T) – ST = $285 – $282 = $3. Hence the total value is $3 × 2,000 shares = $6,000.\nC Incorrect because the spot price at inception is used instead of at settlement:"},
  {"num": 36, "subject": "衍生品", "question": "An investor observes that the price of an underlying asset is $20. The investor immediately enters into forward contract to purchase the underlying asset in one year at a price of $10. At contract initiation, the value of the forward contract is closest to:", "options": {"A": "$0.", "B": "$10.", "C": "$30."}, "answer": "A", "explanation": "A Correct because when a forward contract is initiated, neither party pays anything to the other. It is a valueless contract, neither an asset nor a liability. Therefore, its value at initiation is zero.\nB Incorrect because the value of a forward contract at expiration is the spot price of the underlying minus the forward price agreed to in the contract. Therefore, this answer choice represents the value of the forward contract at expiration, not at initiation, i.e., $20 - $10 = $10. By contrast, the value of the forward at initiation is zero, as described in the response rationale for the correct answer.\nC Incorrect because this answer choice incorrectly assumes that the forward value at contract initiation is the sum of spot price at contract initiation plus forward price at contract initiation, i.e., $20 + $10 = $30. By contrast, the value of the forward at initiation is zero, as described in the response rationale for the correct answer."},
  {"num": 37, "subject": "衍生品", "question": "The spot price of an asset is $70.00. If the annual risk-free rate is 2.50%, the 9-month forward price is closest to:", "options": {"A": "$68.72.", "B": "$71.31.", "C": "$71.75."}, "answer": "B", "explanation": "A Incorrect because the forward price is the spot price compounded at the risk-free rate over the life of the contract or F0(T) = S0 (1+ r)T where S0 is the current spot price, r is the risk-free rate and T is time. Therefore, the 9-month forward price is not equal to the spot price divided by (1+ r)Tor £70.00 / (1+.025)0.75 = £68.72.\nB Correct because the forward price is the spot price compounded at the risk-free rate over the life of the contract or F0(T) = S0 (1+ r)T where S0 is the current spot price, r is the risk-free rate and T is time. Therefore, the 9-month forward price is equal to £70.00 (1+.025)0.75 = £71.31.\nC Incorrect because the forward price is the spot price compounded at the risk-free rate over the life of the contract or F0(T) = S0 (1+ r)T where S0 is the current spot price, r is the risk-free rate and T is time. Therefore, the 9-month forward price is not equal to the spot price multiplied by (1+ r) (omitting time) or £70.00 (1+.025) = £71.75."},
  {"num": 38, "subject": "衍生品", "question": "Which of the following derivatives realize a gain as the market reference rate rises above the initial fixed rate?", "options": {"A": "Long forward rate agreements only", "B": "Short interest rate futures contracts only", "C": "Both long forward rate agreements and short interest rate futures contracts"}, "answer": "C", "explanation": "A Incorrect because short interest rate futures contracts also gain from a rising market reference rate.\nB Incorrect because long forward rate agreements also gain from a rising market reference rate.\nC Correct because realizing a gain on the FRA contract as rates rise. Note that this would be equivalent to taking a short position on a CNY MRR futures contract if one were available. A long FRA (i.e., FRA floating-rate receiver (fixed-rate payer) position realizes a gain as MRR rises. A short futures contract price is based on (100 − yield), which gains as yield-to-maturity (MRR) rises."},
  {"num": 39, "subject": "衍生品", "question": "An analyst gathers the following information:\nThe current spot price of crude oil is $120 per barrel.\nThe risk-free rate is 3% with annual compounding.", "options": {"A": "$126.78.", "B": "$126.86.", "C": "$126.93."}, "answer": "A", "explanation": "A Correct because the futures price for a commodity with known storage cost amounts may be determined as: f0(T) = [S0 + PV0(C)] × (1 + r)T. PV0(C) = $5×(1 + 3%)-182/365. f0(T) = [$120 + $5×(1 + 3%)-182/365]×(1 + 3%)182/365 = $126.781768 ≈ $126.78.\nB Incorrect because it doesn't discount the storage cost from settlement day to today to find its present value since the futures price for a commodity with known storage cost amounts may be determined as: f0(T) = [S0 + PV0(C)] × (1 + r)T. If no discounting is applied to the storage cost, it would be incorrectly assumed to be PV0(C) = $5. f0(T) = [$120 + $5] × (1 + 3%)182/365 = $126.856008 ≈ $126.86.\nC Incorrect because it compounds the storage cost from today to settlement instead of discounting to find its present value since the futures price for a commodity with known storage cost amounts may be determined as: f0(T) = [S0 + PV0(C)] × (1 + r)T."},
  {"num": 40, "subject": "衍生品", "question": "Which of the following interest rate derivatives most likely has the largest convexity bias?", "options": {"A": "Forward rate agreement on a 1-month market reference rate", "B": "Forward rate agreement on a 3-month market reference rate", "C": "Interest rate futures contract on a 3-month market reference rate"}, "answer": "B", "explanation": "A Incorrect because the discounting feature of the FRA, which is not present in the futures contract, leads to a convexity bias that is greater for longer discounting periods. Since the length of the discounting period depends on the maturity of the underlying market reference rate, 1-month market reference rate results in a shorter discounting period than the 3-month rate. Therefore, it will suffer from a smaller convexity bias.\nB Correct because the discounting feature of the FRA, which is not present in the futures contract, leads to a convexity bias that is greater for longer discounting periods. Since the length of the discounting period depends on the maturity of the underlying market reference rate, 3-month market reference rate results in a longer discounting period than the 1-month rate.\nC Incorrect because convexity bias does not exist in interest rate futures contracts since their prices are not based on discounting. The futures contract has a fixed linear payoff profile for a given basis point change. On the other hand, the discounting feature of the FRA, which is not present in the futures contract, leads to a convexity bias that is greater for longer discounting periods."},
  {"num": 41, "subject": "衍生品", "question": "A futures contract’s:", "options": {"A": "mark-to-market is not settled until maturity.", "B": "price remains fixed until the contract matures.", "C": "variation margin reduces counterparty credit risk."}, "answer": "C", "explanation": "A Incorrect because forward (not future) contract MTM is not settled until maturity.\nB Incorrect because the forward price, F0(T), is constant until the contract matures, whereas the futures price, f0(T), fluctuates daily based upon market changes.\nC Correct because the daily settlement mechanism resets the futures MTM to zero, and variation margin is exchanged to settle the difference, reducing counterparty credit risk."},
  {"num": 42, "subject": "衍生品", "question": "The differential between forward and futures prices is determined by which of the following?", "options": {"A": "Interest rate volatility only", "B": "The correlation between futures prices and interest rates only", "C": "Both interest rate volatility and the correlation between futures prices and interest rates"}, "answer": "C", "explanation": "A Incorrect because the differential between forward and futures prices is determined by both the correlation between futures prices and interest rates, and by interest rate volatility, as described in the response rationale for the correct answer.\nB Incorrect because the differential between forward and futures prices is determined by both the correlation between futures prices and interest rates, and by interest rate volatility, as described in the response rationale for the correct answer.\nC Correct because the different patterns of cash flows for forwards and futures can lead to a difference in the pricing of forwards versus futures. Forward and futures prices are identical under certain conditions, namely:"},
  {"num": 43, "subject": "衍生品", "question": "All else being equal, the price of a forward contract is most likely higher than the price of a futures contract if interest rates are:", "options": {"A": "negatively correlated with futures prices.", "B": "uncorrelated with futures prices.", "C": "positively correlated with futures prices."}, "answer": "A", "explanation": "A Correct because a negative correlation between futures prices and interest rates leads to forwards being more desirable than futures to the long position. The reason is that rising prices lead to futures profits that are reinvested in periods of falling interest rates, and falling prices lead to losses that occur in periods of rising interest rates. It is far better to receive all cash flows at expiration under such conditions than to receive them in the interim periods. This condition makes forwards more attractive than futures. The more desirable contract will tend to have the higher price. Therefore, the price of the forward contract is higher than the price of the futures contract on the same underlying when interest rates are negatively correlated with futures prices.\nB Incorrect because if futures prices and interest rates are uncorrelated, forwards and futures prices will be the same. Therefore, the price of the forward contract is not higher than the price of the futures contract if interest rates are uncorrelated with futures prices.\nC Incorrect because if futures prices are positively correlated with interest rates, futures contracts are more desirable to holders of long positions than are forwards. The more desirable contract will tend to have the higher price. Therefore, the price of the futures contract is higher than the price of the forward contract, and not the other way around, if interest rates are positively correlated with futures prices."},
  {"num": 44, "subject": "衍生品", "question": "A $10 million interest rate swap with annual payments has a fixed swap rate of 1.95%. The implied forward rates are:\nThe periodic settlement value in Year 3 for the fixed-rate payer is expected to be closest to:", "options": {"A": "–$95,000.", "B": "–$60,000.", "C": "$60,000."}, "answer": "B", "explanation": "A Incorrect because an average of the first 3 yearly settlement values is used: = (MRR – sN) × Notional amount × Period ≠ ([0.0050 + 0.0115 + 0.0135]/3 – 0.0195) × $10,000,000 × 1 = (0.0100 – 0.0195) × $10,000,000 × 1 = –$95,000.\nB Correct because the periodic settlement value = (MRR – sN) × Notional amount × Period. The market reference rate (MMR) for Year 3 is 1.35%, thus: = (0.0135 – 0.0195) × $10,000,000 × 1 = –$60,000.\nC Incorrect because this is the periodic settlement value for the floating-rate payer, not the fixed-rate payer:"},
  {"num": 45, "subject": "衍生品", "question": "A series of forward rate agreements and an interest rate swap contract covering the same periods and using the same market reference rate will most likely have the same:", "options": {"A": "fixed rates.", "B": "cash flows upfront.", "C": "settlement cash flows."}, "answer": "B", "explanation": "A Incorrect because different FRA fixed rates usually exist for different times to maturity. In contrast, a standard interest rate swap has a constant fixed rate over its life, which includes multiple periods.\nB Correct because similarities between interest rate forwards and swaps include the symmetric payoff profile and the fact that no cash flow is exchanged upfront.\nC Incorrect because different FRA fixed rates usually exist for different times to maturity. In contrast, a standard interest rate swap has a constant fixed rate over its life, which includes multiple periods and the FRA has a single settlement, which occurs at the beginning of an interest period, while a standard swap has periodic settlements, which occur at the end of each respective period."},
  {"num": 46, "subject": "衍生品", "question": "From the fixed-rate receiver's perspective, if the market reference rate increases, the value of a swap contract:", "options": {"A": "decreases.", "B": "stays the same.", "C": "increases."}, "answer": "A", "explanation": "A Correct because the fixed-rate receiver pays the market reference rate and receives the par swap par rate. If the market reference rate increases, they are paying more and the value of the contract decreases to them. Another interpretation of an interest rate swap is that the fixed-rate payer (floating-rate receiver) is long a floating-rate note (FRN) priced at the MRR and short a fixed-rate bond with a coupon equal to the fixed swap rate. Similarly, the fixed-rate receiver (floating-rate payer) is long a fixed-rate bond with a coupon equal to the swap rate and short a floating-rate note priced at the MRR. A rise in the expected forward rates after inception will increase the present value of floating payments, while the fixed-swap rate will remain the same.\nB Incorrect because the fixed-rate receiver pays the market reference rate and receives the swap par rate. If the market reference rate increases, they are paying more and the value of the contract decreases to them, not stays the same. Another interpretation of an interest rate swap is that the fixed-rate payer (floating-rate receiver) is long a floating-rate note (FRN) priced at the MRR and short a fixed-rate bond with a coupon equal to the fixed swap rate. Similarly, the fixed-rate receiver (floating rate payer) is long a fixed-rate bond with a coupon equal to the swap rate and short a floating-rate note priced at the MRR. A rise in the expected forward rates after inception will increase the present value of floating payments, while the fixed-swap rate will remain the same.\nC Incorrect because the fixed-rate receiver pays the market reference rate and receives the swap par rate. If the market reference rate increases, they are paying more and the value of the contract decreases, not increases, to them. Another interpretation of an interest rate swap is that the fixed-rate payer (floating-rate receiver) is long a floating-rate note (FRN) priced at the MRR and short a fixed-rate bond with a coupon equal to the fixed swap rate. Similarly, the fixed-rate receiver (floating rate payer) is long a fixed-rate bond with a coupon equal to the swap rate and short a floating-rate note priced at the MRR. A rise in the expected forward rates after inception will increase the present value of floating payments, while the fixed-swap rate will remain the same."},
  {"num": 47, "subject": "衍生品", "question": "A swap is most likely similar to a series of forward contracts when:", "options": {"A": "all forward contracts are created with the combined value equal to zero.", "B": "all forward contracts are entered into at the price created in the forward market.", "C": "the value of the long forward contracts are matched with the value of the short forward contracts at each swap payment date."}, "answer": "A", "explanation": "A Correct because, in a swap, each forward contract will be created at the fixed price that corresponds to the fixed price of a swap of the same maturity with payments made at the same dates as the series of forward contracts. That means that some of the forward contracts would have positive values and some would have negative values, but their combined values would equal zero.\nB Incorrect because, in a swap, each implicit forward contract is said to be off-market, because it is created at the swap price, not the appropriate forward price, which would be the price created in the forward market. Therefore, the forward contracts are created at the swap price, not at the price created in the forward market.\nC Incorrect because, in a swap, each forward contract will be created at the fixed price that corresponds to the fixed price of a swap of the same maturity with payments made at the same dates as the series of forward contracts. That means that some of the forward contracts would have positive values and some would have negative values, but their combined values would equal zero. Therefore, a swap contract is similar to a series of long forward contracts of which some have positive values and some have negative values, but the long forward contracts are not matched with the short forward contracts at each swap payment date."},
  {"num": 48, "subject": "衍生品", "question": "All, else held equal, the value of a European call option is best characterized as having a:", "options": {"A": "negative relationship with the price of the underlying.", "B": "negative relationship with the volatility of the underlying.", "C": "positive relationship with the time to expiration."}, "answer": "C", "explanation": "A Incorrect . The value of a European call option is directly related to the price of the underlying.\nB Incorrect . The value of a European call option is directly related to the volatility of the underlying.\nC Correct . The value of a European call option is directly related to the time to expiration. That is, all else held equal, the value of a European call option is higher the longer the time to expiration."},
  {"num": 49, "subject": "衍生品", "question": "The upper bound of a call value is the:", "options": {"A": "underlying's price.", "B": "underlying’s price plus the present value of its exercise price or zero, whichever is greater.", "C": "underlying’s price minus the present value of its exercise price or zero, whichever is greater."}, "answer": "A", "explanation": "A Correct because the upper no-arbitrage bound of a call value is the underlying's spot price.\nB Incorrect because the lower (not upper) bound of a call price is the underlying’s price minus (not plus) the present value of its exercise price or zero, whichever is greater. Instead, the upper no-arbitrage bound of a call price is the underlying's spot price.\nC Incorrect because the lower (not upper) bound of a call price is the underlying’s price minus the present value of its exercise price or zero, whichever is greater. Instead, the upper no-arbitrage bound of a call price is the underlying's spot price."},
  {"num": 50, "subject": "衍生品", "question": "If the price of the underlying is $57, which of the following long option positions is out of the money? A:", "options": {"A": "put with a strike price of $60", "B": "put with a strike price of $50", "C": "call with a strike price of $50"}, "answer": "B", "explanation": "A Incorrect because when the underlying is beyond the exercise price in the appropriate direction (higher for a call, lower for a put), the option is said to be in-the-money. As the underlying price of $57 is lower than the strike price of $60, the put is in the money, not out of the money.\nB Correct because when the underlying has not reached the exercise price (currently lower for a call, higher for a put), the option is said to be out-of-the-money. In this case, as the underlying price of $57 is higher than the strike price of $50, the put is out of the money.\nC Incorrect because when the underlying is beyond the exercise price in the appropriate direction (higher for a call, lower for a put), the option is said to be in-the-money. In this case, as the underlying price of $57 is higher than the strike price of $50, the call is in the money, not out of the money."},
  {"num": 51, "subject": "衍生品", "question": "A put option with the greatest moneyness has a strike price:", "options": {"A": "less than the price of the underlying.", "B": "equal to the price of the underlying.", "C": "greater than the price of the underlying."}, "answer": "C", "explanation": "A Incorrect because when the underlying has not reached the exercise price (currently lower for a call, higher for a put), the option is said to be out-of-the-money. Only in-the-money puts have moneyness.\nB Incorrect because when the underlying is precisely at the exercise price, the option is said to be at-the-money. Only in-the-money put options have moneyness.\nC Correct because hen the underlying is beyond the exercise price in the appropriate direction (higher for a call, lower for a put), the option is said to be in-the-money. In addition, for puts to expire in-the-money, the value of the underlying must fall below the exercise price. The higher the exercise price, the better chance the underlying has of getting below it. Likewise, if the value of the underlying does fall below the exercise price, the higher the exercise price, the greater the payoff. So, if X is higher, ST will be below it more often, and if ST is less than X, the payoff of X – ST is greater, the higher is X for whatever value of ST occurs. Therefore, a put option with the greatest moneyness has a strike price greater than the price of the underlying."},
  {"num": 52, "subject": "衍生品", "question": "Which of the following European options has the greatest value at expiration? A:", "options": {"A": "call with an exercise price of 72 and an underlying priced at 83", "B": "call with an exercise price of 83 and an underlying priced at 70", "C": "put with an exercise price of 70 and an underlying priced at 83"}, "answer": "A", "explanation": "A Correct because the value of the call option at expiration is the greater of either zero or the underlying price at expiration minus the exercise price, which is typically written as: cT = Max(0,ST – X), where cT= call option price at expiration and ST= underlying price at expiration. Therefore, a call option with an exercise price of 72 and an underlying priced at 83 will have a value: cT = Max(0, 83 – 72)= 11.\nB Incorrect because, as described in the response rationale for the correct answer, the value of the call option at expiration is: cT = Max(0,ST – X). Therefore, a call option with an exercise price of 83 and an underlying priced at 70 will have a value: cT = Max(0, 70 – 83)= 0, which is less than 11 for the case of the correct answer.\nC Incorrect because the put is worth the greater of either zero or the exercise price minus the price of the underlying at expiration. That is, pT = Max(0,X – ST). Therefore, a European put with an exercise price of 70 and an underlying priced at 83 will have a value: pT = Max (0,70 – 83)= 0, which is less than 11 for the case of the correct answer."},
  {"num": 53, "subject": "衍生品", "question": "All else being equal, if the exercise values of a European call option and a European put option on the same underlying are equal, both options must be:", "options": {"A": "in-the-money options.", "B": "at-the-money options.", "C": "out-of-the-money options."}, "answer": "B", "explanation": "A Incorrect because the exercise value of a European call is the greater of zero or the value of the underlying minus the exercise price. And the exercise value of a European put is the greater of zero or the exercise price minus the value of the underlying. This means if the call option is in-the-money (out-of-money), the put option on the same strike will be out-of-the money (in-the-money). That is, if the exercise value of a call (put) option is positive, the exercise value of a put (call) option will be zero. Therefore, all else being equal, if the exercise values of a European call option and a European put option are the same, then the European call and the European put cannot both be in-the-money options.\nB Correct because the value of a European call at expiration is the exercise value, which is the greater of zero or the value of the underlying minus the exercise price. And the value of a European put at expiration is the exercise value, which is the greater of zero or the exercise price minus the value of the underlying. This means if the call option is in-the-money (out-of-the-money), the put option of the same strike will be out-of-the-money (in-the-money). That is, if the exercise value of a call (put) option is positive, the exercise value of a put (call) option will be zero. But when the underlying is precisely at the exercise price (the option is said to be at-the-money), the exercise value of a European call and a European put will the same, which is zero. Therefore, all else being equal, if the exercise values of a European call option and a European put option are the same, then the European call and the European put must be both at-the-money options.\nC Incorrect because the exercise value of a European call is the greater of zero or the value of the underlying minus the exercise price. And the exercise value of a European put is the greater of zero or the exercise price minus the value of the underlying. This means if the call option is in-the-money (out-of-money), the put option on the same strike will be out-of-the money (in-the-money). That is, if the exercise value of a call (put) option is positive, the exercise value of a put (call) option will be zero. Therefore, all else being equal, if the exercise values of a European call option and a European put option are the same, then the European call and the European put cannot both be out-of-the money options."},
  {"num": 54, "subject": "衍生品", "question": "The value of a long position in a European put option is directly related to the:", "options": {"A": "exercise price.", "B": "risk-free interest rate.", "C": "value of the underlying."}, "answer": "A", "explanation": "A Correct because the value of a European put option is directly related to the exercise price.\nB Incorrect because the value of a European put is inversely related to the risk-free interest rate, not directly related.\nC Incorrect because the value of a European put option is inversely related to the value of the underlying, not directly related."},
  {"num": 55, "subject": "衍生品", "question": "The current price of the underlying is $7.40 and the annual risk-free rate is 6%. The minimum price for a 6-month call option with a strike price of $7.50 is closest to:", "options": {"A": "$0.00.", "B": "$0.12.", "C": "$0.31."}, "answer": "B", "explanation": "A Incorrect because the price for a European call option is known to satisfy the formula c0 ≥ Max[0, S0 – X/(1 + r)T] where c0 is the current price of the European call option, S0 is the current stock price, X is the strike price, r is the risk-free interest rate and T is time. The minimum price is therefore not equal to Max [0,S0 – X] = Max[0,$7.40 – $7.50] = Max[0,−$0.10] = $0.00.\nB Correct because the price for a European call option is known to satisfy the formula c0 ≥ Max[0,S0 – X/(1 + r)T] where c0 is the current price of the European call option, S0 is the current stock price, X is the strike price, r is the risk-free interest rate and T is time. Therefore the minimum price is equal to Max[0,$7.40 – $7.50/(1.06)6/12] = Max[0,$7.40 – $7.28] = Max[0,$0.12] = $0.12.\nC Incorrect because the price for a European call option is known to satisfy the formula c0 ≥ Max[0, S0 – X/(1 + r)T] where c0 is the current price of the European call option, S0 is the current stock price, X is the strike price, r is the risk-free interest rate and T is time. The minimum price therefore is not equal to Max[0, X – (S0/(1 + r)T)] = Max[0,$7.50 – ($7.40/(1.06)6/12)] = Max[0,$7.50 – $7.19] = $0.31."},
  {"num": 56, "subject": "衍生品", "question": "The upper bound of a put value is the:", "options": {"A": "exercise price.", "B": "price of the underlying.", "C": "present value of the exercise price minus the spot price."}, "answer": "A", "explanation": "A Correct because the exercise price, X, therefore represents the upper bound on the put value.\nB Incorrect because this is the upper bound of a call price, not a put value. The call buyer will not pay more for the right to purchase an underlying than the price of that underlying, which is the upper bound.\nC Incorrect because this distractor represents the lower bound of a put value and not the upper bound, as the lower bound is the present value of the exercise price minus the spot price or zero, whichever is greater."},
  {"num": 57, "subject": "衍生品", "question": "The value of a European call option is inversely related to the:", "options": {"A": "exercise price.", "B": "time to expiration.", "C": "risk-free interest rate."}, "answer": "A", "explanation": "A Correct because the value of a European call option is inversely related to the exercise price.\nB Incorrect because the value of a European call option is directly related to the time to expiration. Therefore, a European call option is not inversely related to the time to expiration.\nC Incorrect because the value of a European call is directly related to the risk-free interest rate. Therefore, a European call option is not inversely related to the risk-free interest rate."},
  {"num": 58, "subject": "衍生品", "question": "All else being equal, if the risk-free rate increases, the value of a European put option:", "options": {"A": "decreases.", "B": "remains the same.", "C": "increases."}, "answer": "A", "explanation": "A Correct because the value of a European put is inversely related to the risk-free interest rate. Therefore, an increase in the risk-free rate decreases the value of a European put option.\nB Incorrect because the value of a European put option does not remain the same if the risk-free rate increases; its value decreases, as described in the response rationale for the correct answer.\nC Incorrect because the value of a European put option does not increase if the risk-free rate increases; its value decreases, as described in the response rationale for the correct answer."},
  {"num": 59, "subject": "衍生品", "question": "For a European call option with one month until expiration, if the spot price is below the exercise price, the call option most likely has:", "options": {"A": "positive time value only.", "B": "positive intrinsic value only.", "C": "both positive time value and positive intrinsic value."}, "answer": "A", "explanation": "A Correct because a European call option with two months until expiration will typically have positive time value, where time value reflects the value of the uncertainty that arises from the volatility in the underlying. In addition, cT = Max (0, ST – X) or intrinsic value equals the greater of zero or the value of the underlying minus exercise price. The call option is out-of-the-money and therefore, has zero intrinsic value.\nB Incorrect because the option has zero intrinsic value, as explained in the correct answer.\nC Incorrect because the option has zero intrinsic value, as explained in the correct answer."},
  {"num": 60, "subject": "衍生品", "question": "An analyst gathers the following information:\nAccording to put-call parity, the price of the put is closest to:", "options": {"A": "$28.25.", "B": "$30.00.", "C": "$108.25."}, "answer": "A", "explanation": "A Correct because S0 + p0 = c0 + X / (1+r)T. This relationship is known as put-call parity. Here S0 is the spot price, p0 is the put premium, X is the strike price and r is the interest rate. S0 + p0 = c0 + X / (1+r)T 40 + p0 = 10 + 60 / 1.03 p0 = 10 + 60 / 1.03 - 40 = 28.25242718 = 28.25\nB Incorrect because S0 + p0 = c0 + X / (1+r)T. This relationship is known as put-call parity. In this response, X was not divided by (1+r)T. Here S0 is the spot price, p0 is the put premium, X is the strike price and r is the interest rate. S0 + p0 = c0 + X / (1+r)T 40 + p0 = 10 + 60 p0 = 10 + 60 - 40 = 30.00\nC Incorrect because S0 + p0 = c0 + X / (1+r)T. This relationship is known as put-call parity. In this response, S0 was incorrectly added instead of subtracted from c0 + X / (1+r)T to arrive at P0. Here S0 is the spot price, p0 is the put premium, X is the strike price and r is the interest rate."},
  {"num": 61, "subject": "衍生品", "question": "All else being equal, the cost of a fiduciary call must be:", "options": {"A": "less than the cost of a synthetic protective put.", "B": "equal to the cost of a synthetic protective put.", "C": "greater than the cost of a synthetic protective put."}, "answer": "B", "explanation": "A Incorrect because the cost of the fiduciary call must equal the cost of the synthetic protective put, giving us what is referred to as put–call–forward parity.\nB Correct because the cost of the fiduciary call must equal the cost of the synthetic protective put, giving us what is referred to as put–call–forward parity.\nC Incorrect because the cost of the fiduciary call must equal the cost of the synthetic protective put, giving us what is referred to as put–call–forward parity."},
  {"num": 62, "subject": "衍生品", "question": "Based on put-call parity, the payoff on a short underlying position is equivalent to the payoff on a portfolio consisting of a:", "options": {"A": "short call, a long put, and a long bond.", "B": "short call, a long put, and a short bond.", "C": "long call, a short put, and a short bond."}, "answer": "B", "explanation": "A Incorrect because the put-call parity relationship implies that a long underlying can be mimicked as follows: S0 = c0 – p0 + X/(1 + r)T. This implies that a short underlying position is equivalent to: –S0 = –c0 + p0 – X/(1 + r)T, that is, a short call, a long put, and a short (not long) bond.\nB Correct because the put-call parity relationship implies that a long underlying can be mimicked as follows: S0 = c0 – p0 + X/(1 + r)T. This implies that a short underlying position is equivalent to: –S0 = –c0 + p0 – X/(1 + r)T, that is, a short call, a long put, and a short bond.\nC Incorrect because the put-call parity relationship implies that a long underlying can be mimicked as follows: S0 = c0 – p0 + X/(1 + r)T. This implies that a short underlying position is equivalent to: –S0 = –c0 + p0 – X/(1 + r)T, that is, a short (not long) call, a long (not short) put, and a short bond."},
  {"num": 63, "subject": "衍生品", "question": "According to put-call-forward parity, a trader can create a synthetic short position in a risk-free bond by setting up a long position in a call option along with a:", "options": {"A": "short position in a forward contract and a long position in a put.", "B": "long position in a forward contract and a short position in a put.", "C": "short position in a forward contract and a short position in a put."}, "answer": "C", "explanation": "A Incorrect because combining the synthetic asset with the put–call Equation l parity relationship—so, substituting the present value of F0(T) for S0 —we have what is referred to as put–call forward parity: F0(T)(1+r)-T + p0 = c0 + X(1 + r)-T ,where F0(T)(1+r)-Ts the the present value of F0(T) discounted at the risk-free rate, p0 is the price of the put option on the underlying at t=0, c0 is the price of the call option on the underlying at t=0, X(1 + r)-T is a risk free bond that pays the amount of the exercise price X at t=T. In other words, under put–call parity, at t = 0 the price of the long underlying asset plus the long put must equal the price of the long call plus the risk-free asset. Rearranging the formula yields: -X(1 + r)-T = c0 - p0 - F0(T)(1+r)-T In other words, one can create a synthetic short position in a risk–free bond by going long a call, short (not long) a put, and short a forward contract.\nB Incorrect because combining the synthetic asset with the put–call parity relationship—so, substituting the present value of F0(T) for S0 —we have what is referred to as put–call forward parity: F0(T)(1+r)-T + p0 = c0 + X(1 + r)-T ,where F0(T)(1+r)-Ts the present value of F0(T) discounted at the risk-free rate, p0 is the price of the put option on the underlying at t=0, c0 is the price of the call option on the underlying at t=0, X(1 + r)-T is a risk free bond that pays the amount of the exercise price X at t=T. In other words, under put–call parity, at t = 0 the price of the long underlying asset plus the long put must equal the price of the long call plus the risk-free asset. Rearranging the formula yields: -X(1 + r)-T = c0 - p0 - F0(T)(1+r)-T In other words, one can create a synthetic short position in a risk–free bond by going long a call, short a put, and short (not long) a forward contract.\nC Correct because combining the synthetic asset with the put–call parity relationship—so, substituting the present value of F0(T) for S0 —we have what is referred to as put–call forward parity:"},
  {"num": 64, "subject": "衍生品", "question": "According to put-call-forward parity, the payoff on a synthetic protective put is equivalent to the payoff on a portfolio consisting of:", "options": {"A": "a long call and a long risk-free bond.", "B": "a long call, a short forward contract and a long risk-free bond.", "C": "a long put, a short forward contract and a short risk-free bond."}, "answer": "A", "explanation": "A Correct because recall our put–call parity discussion and assume that Investor A creates his protective put in a slightly different manner. Instead of buying the asset, he buys a forward contract and a risk-free bond in which the face value is the forward price. This strategy is a synthetic protective put. Because we showed that the fiduciary call is equivalent to the protective put, a fiduciary call has to be equivalent to a protective put with a forward contract. Therefore, the payoff on a synthetic protective put = the payoff on a fiduciary call, synthetic protective put = long risk-free bond + long forward contract + long put = long call + long risk-free bond.\nB Incorrect because recall our put–call parity discussion and assume that Investor A creates his protective put in a slightly different manner. Instead of buying the asset, he buys a forward contract and a risk-free bond in which the face value is the forward price. This strategy is a synthetic protective put. Because we showed that the fiduciary call is equivalent to the protective put, a fiduciary call has to be equivalent to a protective put with a forward contract. Therefore, the payoff on a synthetic protective put is not equal to the payoff on a portfolio consisting of a long call, a short forward contract and a long risk-free bond.\nC Incorrect because recall our put–call parity discussion and assume that Investor A creates his protective put in a slightly different manner. Instead of buying the asset, he buys a forward contract and a risk-free bond in which the face value is the forward price. This strategy is a synthetic protective put. Because we showed that the fiduciary call is equivalent to the protective put, a fiduciary call has to be equivalent to a protective put with a forward contract. Therefore, the payoff on a synthetic protective put is not equal to the payoff on a portfolio consisting of a long put, a short forward contract and a short risk-free bond."},
  {"num": 65, "subject": "衍生品", "question": "According to put-call parity, the payoff of a long risk-free bond can be replicated synthetically by going:", "options": {"A": "long an asset, long a put and long a call.", "B": "long an asset, long a put and short a call.", "C": "long an asset, short a put and short a call."}, "answer": "B", "explanation": "A Incorrect because according to put-call parity, X/(1 + r)T = S0 + p0 – co, long bond = long asset, long put, short call. Therefore, the payoff of a long risk-free bond cannot be synthetically created by going long an asset, long a put and long a call.\nB Correct because according to put-call parity, X/(1 + r)T = S0 + p0 – co, long bond = long asset, long put, short call. Therefore, the payoff of a long risk-free bond can be synthetically created by going long an asset, long a put and short a call.\nC Incorrect because according to put-call parity, X/(1 + r)T = S0 + p0 – co, long bond = long asset, long put, short call. Therefore, the payoff of a long risk-free bond cannot be synthetically created by going long an asset, short a put and short a call."},
  {"num": 66, "subject": "衍生品", "question": "A fiduciary call is a strategy in which a trader purchases a call option:", "options": {"A": "and takes a short position in the underlying asset.", "B": "with funds received from selling short a zero coupon bond of the same maturity as the call option.", "C": "along with a zero coupon bond of the same maturity as the call option and with a face value equal to the exercise price of the option."}, "answer": "C", "explanation": "A Incorrect because in a fiduciary call the investor, buys a call option on this asset with an exercise price of X that expires at T and a risk-free zero-coupon bond with a face value of X that matures at T. This strategy is sometimes known as a fiduciary call.\nB Incorrect because in a fiduciary call the investor, buys a call option on this asset with an exercise price of X that expires at T and a risk-free zero-coupon bond with a face value of X that matures at T. This strategy is sometimes known as a fiduciary call.\nC Correct because this combination of instruments is the precise definition of a fiduciary call. At time 0, this investor buys a call option on this asset with an exercise price of X that expires at T and a risk-free zero-coupon bond with a face value of X that matures at T. This strategy is sometimes known as a fiduciary call."},
  {"num": 67, "subject": "衍生品", "question": "Which of the following is most accurate? Put-call-forward parity:", "options": {"A": "assumes that the strike of the options is equal to the forward price of the underlying.", "B": "is derived by equating the price of an at the money put to the price of an at the money call.", "C": "assumes that the maturity of the put option, the call option, the forward and the bond are the same."}, "answer": "C", "explanation": "A Incorrect because the put-call-forward parity equation is valid for all strikes. P0 - Co = [X - F0(T)]/(1 + r)T X is the strike and can take any value.\nB Incorrect because the put-call-forward parity equation is formed by comparing the maturity payoffs of synthetic protective put and a fiduciary call. Because we showed that the fiduciary call is equivalent to the protective put, a fiduciary call has to be equivalent to a protective put with a forward contract. It follows that the cost of the fiduciary call must equal the cost of the synthetic protective put, giving us what is referred to as put–call–forward parity.\nC Correct because the put-call-forward parity equation is formed by comparing the maturity payoffs of synthetic protective put and a fiduciary call. It follows that maturity of all the components have to be the same. Because we showed that the fiduciary call is equivalent to the protective put, a fiduciary call has to be equivalent to a protective put with a forward contract. It follows that the cost of the fiduciary call must equal the cost of the synthetic protective put, giving us what is referred to as put–call–forward parity."},
  {"num": 68, "subject": "衍生品", "question": "All else being equal, based on put-call–forward parity, the price of a put is higher than the price of a call when:", "options": {"A": "the forward price of the underlying is lower than the exercise price.", "B": "the forward price of the underlying is equal to the exercise price.", "C": "the forward price of the underlying is higher than the exercise price."}, "answer": "A", "explanation": "A Correct because it follows that the cost of the fiduciary call must equal the cost of the synthetic protective put, giving us what is referred to as put–call–forward parity, F0(T)/(1 + r)T + p0 = c0 + X/(1 + r)T. Rearranging this equation results in: p0 - c0 = [X – F0(T)]/(1 + r)T. Based on this parity equation, p0 > c0 when X > F0(T).\nB Incorrect because, according to put–call–forward parity, the price of a put is higher than the price of a call when when the forward price is lower, not equal to, than the exercise price. The put–call–forward parity is presented as: p0 - c0 = [X – F0(T)]/(1 + r)T.\nC Incorrect because, according to put–call–forward parity, the price of a put is higher than the price of a call when the forward price is lower, not higher, than the exercise price. The put–call–forward parity is presented as: p0 - c0 = [X – F0(T)]/(1 + r)T."},
  {"num": 69, "subject": "衍生品", "question": "An analyst gathers the following information:\nAccording to put-call-forward parity, the price of the call is closest to:", "options": {"A": "$127.84.", "B": "$129.80.", "C": "$131.96."}, "answer": "B", "explanation": "A Incorrect because the cost of the fiduciary call must equal the cost of the synthetic protective put, giving us what is referred to as put–call–forward parity, F0(T)/ (1+r)T + p0 = c0 + X / (1+r)T In this response, X was not divided by (1+r)T. Here F0(T) is the forward price at expiration, X is the strike price and r is the interest rate, p0 is the put premium and c0 is the call premium. F0(T)/ (1+r)T + p0 = c0 + X 110/1.02 + 120 = c0 + 100 110/1.02 + 120 - 100 = c0 c0 = 127.843137 = 127.84\nB Correct because the cost of the fiduciary call must equal the cost of the synthetic protective put, giving us what is referred to as put–call–forward parity, F0(T)/ (1+r)T + p0 = c0 + X / (1+r)T Here F0(T) is the forward price at expiration, X is the strike price and r is the interest rate, p0 is the put premium and c0 is the call premium. F0(T)/ (1+r)T + p0 = c0 + X / (1+r)TT 110/1.02 + 120 = c0 + 100 / 1.02 110/1.02 + 120 - 100 / 1.02 = c0 c0 = 129.803922 = 129.80\nC Incorrect because the cost of the fiduciary call must equal the cost of the synthetic protective put, giving us what is referred to as put–call–forward parity, F0(T)/ (1+r)T + p0 = c0 + X / (1+r)T In this response, F0(T) was not divided by (1+r)T. Here F0(T) is the forward price at expiration, X is the strike price and r is the interest rate, p0 is the put premium and c0 is the call premium."},
  {"num": 70, "subject": "衍生品", "question": "According to put–call parity, a long put option is equivalent to being:", "options": {"A": "long a call, short the underlying asset, and long a risk-free bond.", "B": "long a call, long the underlying asset, and short a risk-free bond.", "C": "short a call, long the underlying asset, and long a risk-free bond."}, "answer": "A", "explanation": "A Correct because the formula for put–call parity is S0 + p0 = c0 + X/(1 + r)T, where S0 is the stock price at time zero, p0 is the price of a put option at time zero, c0 is the price of a call option at time zero, X is the strike price, r is the risk-free rate, and T is time. By using the symbols and the signs in these versions of put–call parity, we can see several important interpretations. In the equations below, plus signs mean long and minus signs mean short: p0 = c0 − S0 + X/(1 + r)T ⇒ long put = long call, short asset, long bond.\nB Incorrect because a long put option is not equivalent to being long a call, long the underlying asset, and short a risk-free bond. By using the symbols and the signs in these versions of put–call parity, we can see several important interpretations. In the equations below, plus signs mean long and minus signs mean short: p0 = c0 − S0 + X/(1 + r)T ⇒ long put = long call, short asset, long bond.\nC Incorrect because a long put option is not equivalent to being short a call, long the underlying asset, and long a risk-free bond. By using the symbols and the signs in these versions of put–call parity, we can see several important interpretations. In the equations below, plus signs mean long and minus signs mean short: p0 = c0 − S0 + X/(1 + r)T ⇒ long put = long call, short asset, long bond."},
  {"num": 71, "subject": "衍生品", "question": "Which of the following factors affects the option price when using a binomial model? The:", "options": {"A": "risk-free rate.", "B": "level of investors' risk aversion.", "C": "expected return of the underlying."}, "answer": "A", "explanation": "A Correct because the value of the call option today, c0, is computed as the expected value of the option at expiration, c1u and c1d, discounted at the risk-free rate, r. Also, this no-arbitrage derivative value established separately from investor views on risk is referred to as risk-neutral pricing.\nB Incorrect because the value of the call option today, c0, is computed as the expected value of the option at expiration, c1u and c1d, discounted at the risk-free rate, r. Also, this no-arbitrage derivative value established separately from investor views on risk is referred to as risk-neutral pricing.\nC Incorrect because the value of the call option today, c0, is computed as the expected value of the option at expiration, c1u and c1d, discounted at the risk-free rate, r. Also, only the expected volatility—that is, gross returns Ru and Rd—and not the expected return are required to price an option."},
  {"num": 72, "subject": "衍生品", "question": "An analyst gathers the following information about an underlying:\nUsing a one-period binomial model, the risk-neutral probability of a price increase is closest to:", "options": {"A": "0.38.", "B": "0.46.", "C": "0.54."}, "answer": "B", "explanation": "A Incorrect because this is the expected return of an upward price move, i.e. S1u / S0 – 1 = $22/$16 – 1 = 1.375 – 1 = 0.375 ≈ 0.38. Instead, the risk neutral probability is equal to 0.46, as described in the response rationale for the correct answer.\nB Correct because the risk-neutral probability (π) is the computed probability used in binomial option pricing by which the discounted weighted sum of expected values of the underlying, S1u = RuS0 and S1d = RdS0, equal the current option price. Specifically, this probability is computed using the risk-free rate and assumed up gross return and down gross return of the underlying as in Equation 7. π = 1 + r – Rd / Ru – Rd More specifically, π, is the risk-neutral probability of an increase in the underlying price to S1u = RuS0, and (1 − π) is that of a decrease, S1d = RdS0. Thus, An increase from $16 to $22 or a decrease from $16 to $12 corresponds to: Ru = $22/$16 = 1.375 and Rd = $12/$16 = 0.75. Using the risk-neutral probability (π) of a price increase: π = 1 + r – Rd / Ru – Rd = (1 + 0.04 – 0.75) / (1.375 – 0.75) = 0.29/0.625 = 0.464 ≈ 0.46.\nC Incorrect because this is the risk-neutral probability of a price decrease (1 − π) = 1 − 0.46 = 0.54. Instead, the risk neutral probability is equal to 0.46, as described in the response rationale for the correct answer."},
  {"num": 73, "subject": "衍生品", "question": "All else being equal, if the up gross return increases in a one-period binomial model, the risk-neutral probability of an upward price movement of the asset will:", "options": {"A": "decrease.", "B": "remain the same.", "C": "increase."}, "answer": "A", "explanation": "A Correct because the risk-neutral probability (π) is the computed probability used in binomial option pricing by which the discounted weighted sum of expected values of the underlying, S1u = RuS0 and S1d = RdS0, equal the current option price. Specifically, this probability is computed using the risk-free rate and assumed up gross return and down gross return of the underlying as in π= (1+r-Rd)/(Ru-Rd). So, if the up gross return increases in a one-period binomial model, the denominator will increase. Therefore, the risk-neutral probability of an upward price movement of the asset, (π), decreases.\nB Incorrect because the risk-neutral probability (π) is the computed probability used in binomial option pricing by which the discounted weighted sum of expected values of the underlying, S1u = RuS0 and S1d = RdS0, equal the current option price. Specifically, this probability is computed using the risk-free rate and assumed up gross return and down gross return of the underlying as in π= (1+r-Rd)/(Ru-Rd). So, if the up gross return increases in a one-period binomial model, the denominator will increase. Therefore, the risk-neutral probability of an upward price movement of the asset, (π), decreases.\nC Incorrect because the risk-neutral probability (π) is the computed probability used in binomial option pricing by which the discounted weighted sum of expected values of the underlying, S1u = RuS0 and S1d = RdS0, equal the current option price. Specifically, this probability is computed using the risk-free rate and assumed up gross return and down gross return of the underlying as in π= (1+r-Rd)/(Ru-Rd). So, if the up gross return increases in a one-period binomial model, the denominator will increase. Therefore, the risk-neutral probability of an upward price movement of the asset, (π), decreases."},
  {"num": 74, "subject": "衍生品", "question": "An analyst collects the following information:\nBased on a one-period binomial pricing model, which of the following has the largest payoff?", "options": {"A": "Put option following an up move.", "B": "Put option following a down move.", "C": "Call option following a down move."}, "answer": "B", "explanation": "A Incorrect because the payoff of a put option following an up move is p1u = Max (0, X – S1u) where X is the exercise price and S1u is the price after an up move. In this case, S1u = €26(1.10) = €28.60. So, p1u = Max(0, €22 - €28.60) = €0, which is less than the payoff of a put option following a down move, as described in the response rationale for the correct answer.\nB Correct because the payoff of a put option following a down move is p1d = Max (0, X – S1d) where X is the exercise price and S1d is the price after a down move. In this case, S1d = €26(0.75) = €19.50. So, p1d = Max (0, €22 - €19.50) = €2.50, which is greater than the payoffs of other two responses.\nC Incorrect because the payoff of a call option following an a down move is c1d = Max (0, S1d - X) where X is the exercise price and S1d is the price after a down move. In this case, S1d = €26(0.75) = €19.50. So, c1d = Max (0,€19.50 - €22) = €0, which is less than the payoff of a put option following a down move, as described in the response rationale for the correct answer."},
  {"num": 75, "subject": "衍生品", "question": "Risk-neutral pricing establishes no-arbitrage option values independent of the:", "options": {"A": "spot price of the underlying.", "B": "investor's views on the volatility of the underlying.", "C": "future price of the underlying following an up or down move."}, "answer": "B", "explanation": "A Incorrect because the use of risk-neutral pricing may be applied to any model that uses future underlying asset price movements. Therefore, risk-neutral pricing is not independent of the underlying's spot price.\nB Correct because this no-arbitrage derivative value established separately from investor views on risk is referred to as risk-neutral pricing. Volatility generally means risk because the expected price risk of the underlying, is known as implied volatility. Therefore, risk-neutral pricing establishes no-arbitrage option values independent of the investor views on the underlying's volatility.\nC Incorrect because the use of risk-neutral pricing may be applied to any model that uses future underlying asset price movements. Therefore, risk-neutral pricing is not independent of the future price of the underlying following an up or down move."},
  {"num": 1, "subject": "组合管理", "question": "An equally weighted portfolio is composed of two risky assets. If the correlation of asset returns is equal to zero, the portfolio standard deviation is:", "options": {"A": "equal to zero.", "B": "equal to the weighted average of the assets' standard deviations.", "C": "less than the weighted average of the assets' standard deviations."}, "answer": "C", "explanation": "A Incorrect because the portfolio risk is less than the weighted average of risks when the correlation of asset returns is less than one. For an equally weighted portfolio, the standard deviation can only be equal to zero when the two assets are perfectly negatively correlated (ρ = –1) and the two assets have the same standard deviation. For an extreme case in which ρ12 = –1 (that is, the two asset returns move in opposite directions), the portfolio can be made risk free.\nB Incorrect because the portfolio's standard deviation is simply a weighted average of the standard deviations of the two assets when the correlation of asset returns is equal to one.\nC Correct because the portfolio risk is less than the weighted average of risks when the correlation of asset returns is less than one."},
  {"num": 2, "subject": "组合管理", "question": "When creating a long-only portfolio, which of the following correlation coefficients between assets would be most effective at reducing portfolio risk?", "options": {"A": "–0.5.", "B": "0.", "C": "0.5."}, "answer": "A", "explanation": "A Correct because –0.5 is the smallest of the three correlations and the closer the correlation coefficient is to –1, the greater the reduction in portfolio risk. The correlation coefficient between two assets determines the effect on portfolio risk when the two assets are combined. You will find that portfolio risk is unaffected when the two assets are perfectly correlated (ρ12 = +1). In other words, the portfolio's standard deviation is simply a weighted average of the standard deviations of the two assets and as such a portfolio's risk is unchanged with the addition of assets with the same risk parameters. Portfolio risk falls, however, when the two assets are not perfectly correlated (ρ12 < +1). Sufficiently low values of the correlation coefficient can make the portfolio riskless under certain conditions. For an extreme case in which ρ12 = –1 (that is, the two asset returns move in opposite directions), the portfolio can be made risk free. Analytically, the standard deviation risk of a two asset portfolio is given by the square root of the portfolio's variance: σP = (w12σ12 + w22σ22 + 2w1w2ρ12σ1σ2)1/2, which is a strictly increasing function of ρ12. Hence, –0.5, the smallest of the three correlations, has the lowest risk.\nB Incorrect because the correlation coefficient is not the lowest of the three options. The closer the correlation coefficient is to –1, the greater the reduction in portfolio risk. Portfolio risk falls when the two assets are not perfectly correlated (ρ12 < +1). Sufficiently low values of the correlation coefficient can make the portfolio riskless under certain conditions. For an extreme case in which ρ12 = –1 (that is, the two asset returns move in opposite directions), the portfolio can be made risk free.\nC Incorrect because the correlation coefficient is not the lowest of the three options. The closer the correlation coefficient is to –1, the greater the reduction in portfolio risk. \"Portfolio risk falls when the two assets are not perfectly correlated (ρ12 < +1). Sufficiently low values of the correlation coefficient can make the portfolio riskless under certain conditions. For an extreme case in which ρ12 = –1 (that is, the two asset returns move in opposite directions), the portfolio can be made risk free."},
  {"num": 3, "subject": "组合管理", "question": "For a risk-seeking investor, an investment in a risk-free asset generates utility that is:", "options": {"A": "less than the utility generated for a risk-averse investor.", "B": "equal to the utility generated for a risk-averse investor.", "C": "greater than the utility generated for a risk-averse investor."}, "answer": "B", "explanation": "A Incorrect because a risk-free asset (σ2 = 0) generates the same utility for all individuals.\nB Correct because a risk-free asset (σ2 = 0) generates the same utility for all individuals. If σ2 = 0, then U = E(r) - 1/2(A)(σ2 ) = E(r) for all individuals.\nC Incorrect because a risk-free asset (σ2 = 0) generates the same utility for all individuals."},
  {"num": 4, "subject": "组合管理", "question": "The Markowitz efficient frontier is best described as a curve that:", "options": {"A": "lies above and to the left of the minimum-variance frontier.", "B": "connects the minimum-variance portfolios for all possible returns.", "C": "contains all portfolios of risky assets that rational, risk-averse investors will choose."}, "answer": "C", "explanation": "A Incorrect because the curve that lies above and to the right of the global minimum-variance portfolio is referred to as the Markowitz efficient frontier because it contains all portfolios of risky assets that rational, risk-averse investors will choose. The efficient frontier is the upper part of the minimum-variance frontier, it does not lie above and to the left of it.\nB Incorrect because the entire collection of minimum-variance portfolios for all possible returns is referred to as the minimum-variance frontier, not the efficient frontier (which is only the upper arm of the minimum-variance frontier). Compared to the investment opportunity set, the minimum-variance frontier defines the smaller set of portfolios in which investors would want to invest. Note that no risk-averse investor will choose to invest in a portfolio to the right of the minimum-variance frontier because a portfolio on the minimum-variance frontier can give the same return but at a lower risk.\nC Correct because the Markowitz efficient frontier contains all portfolios of risky assets that rational, risk-averse investors will choose."},
  {"num": 5, "subject": "组合管理", "question": "Long-term historical data on the risk–return trade-off of securities show that investors are most likely:", "options": {"A": "risk averse.", "B": "risk neutral.", "C": "risk seeking."}, "answer": "A", "explanation": "A Correct because the expression 'risk–return trade-off' refers to the positive relationship between expected risk and return. In other words, a higher return is not possible to attain in efficient markets and over long periods of time without accepting higher risk. Expected returns should be greater for assets with greater risk. Over long periods of time, we observe that higher risk does result in higher mean returns. Thus, it is reasonable to claim that, over the long term, market prices reward higher risk with higher returns, which is a characteristic of a risk-averse investor.\nB Incorrect because long-term historical data on securities suggest that investors are risk averse, not risk neutral.\nC Incorrect because because long-term historical data on securities suggest that investors are risk averse, not risk seeking."},
  {"num": 6, "subject": "组合管理", "question": "When evaluating the return distribution of an asset class, the probability of extreme returns is best assessed by the distribution's:", "options": {"A": "kurtosis.", "B": "variance.", "C": "skewness."}, "answer": "A", "explanation": "A Correct because in evaluating investments using only the mean (expected return) and variance (risk), we are implicitly making two important assumptions: 1) that the returns are normally distributed and can be fully characterized by their means and variances and 2) that markets are not only informationally efficient but that they are also operationally efficient. To the extent that these assumptions are violated, we need to consider additional investment characteristics. One of them is kurtosis. Kurtosis refers to fat tails or higher than normal probabilities for extreme returns and has the effect of increasing an asset’s risk that is not captured in a mean–variance framework. This applies to asset returns as several market participants note that the probability and the magnitude of extreme events is underappreciated and was a primary contributing factor to the financial crisis of 2008.\nB Incorrect because using only mean and variance would be appropriate to evaluate investments if returns were distributed normally. Returns, however, are not normally distributed...because the probability of extreme events is significantly greater than what a normal distribution would suggest. The latter deviation is referred to as kurtosis.\nC Incorrect because skewness refers to asymmetry of the return distribution, that is, returns are not symmetric around the mean. Skewness does not refer specifically to the probability of extreme events (and does not measure it) even though a negatively skewed distribution would have a longer left tail relative to the normal distribution."},
  {"num": 7, "subject": "组合管理", "question": "With respect to capital market theory, which of the following statements is most accurate?", "options": {"A": "The optimal risky portfolio is dependent on the risk-free rate.", "B": "The optimal risky portfolio is dependent on the investor's risk profile.", "C": "The investor's optimal portfolio must lie on the Markowitz efficient frontier."}, "answer": "A", "explanation": "A Correct because, for a given Markowitz efficient frontier, a different risk-free rate will result in a different tangent to the frontier, hence a different optimal risky portfolio. CAL(P) is the optimal capital allocation line and Portfolio P is the optimal risky portfolio. Thus, with the addition of the risk-free asset, we are able to narrow our selection of risky portfolios to a single optimal risky portfolio, P, which is at the tangent of CAL(P) and the efficient frontier of risky assets.\nB Incorrect because the optimal risky portfolio is selected from numerous risky portfolios without considering the investor’s preferences.\nC Incorrect because all investors regardless of taste, risk preferences, and initial wealth will hold a combination of two portfolios or funds: a risk-free asset and an optimal portfolio of risky assets. The investor's optimal portfolio thus lies on the capital allocation line (CAL), not on the Markowitz efficient frontier. If it is optimal for an investor to allocate no wealth to the risk-free asset, the investor's optimal portfolio will lie on the Markowitz efficient frontier. However, this is not 'always' the case."},
  {"num": 8, "subject": "组合管理", "question": "Two investors have indifference curves that are tangent to the same capital allocation line (CAL). If Investor 1 is more risk averse than Investor 2, Investor 1's optimal portfolio is:", "options": {"A": "to the left of Investor 2's optimal portfolio on the CAL.", "B": "at the same point on the CAL as Investor 2's optimal portfolio.", "C": "to the right of Investor 2's optimal portfolio on the CAL."}, "answer": "A", "explanation": "A Correct because the optimal portfolio maximizes the return per unit of risk (as it is on the capital allocation line), and it simultaneously supplies the investor with the most satisfaction (utility).\nB Incorrect because, as the investors have different degrees of risk aversion, they will not have the same optimal portfolio. The optimal portfolio maximizes the return per unit of risk (as it is on the capital allocation line), and it simultaneously supplies the investor with the most satisfaction (utility).\nC Incorrect because the less risk-averse investor is willing to accept the additional risk."},
  {"num": 9, "subject": "组合管理", "question": "As the number of assets in an equally weighted portfolio becomes large, the portfolio's variance of returns most likely approaches:", "options": {"A": "zero.", "B": "the average variance of the individual assets' returns.", "C": "the average covariance between the individual assets' returns."}, "answer": "C", "explanation": "A Incorrect because for portfolios with a large number of assets, covariance among the assets accounts for almost all of the portfolio's risk. A candidate may select this answer choice if they extrapolate the fact that portfolio variance is reduced when more assets are added to a portfolio. This argument however fails to acknowledge the limits of diversification.\nB Incorrect because the contribution of the average variance of the individual assets to the total portfolio variance becomes negligible as the number of assets becomes large. Furthermore, for portfolios with a large number of assets, covariance among the assets accounts for almost all of the portfolio's risk.\nC Correct because, given equal weights and average variance/covariance [denoted σ2 and Cov, respectively], we can rewrite the portfolio variance as σP2 = σ2/N + [(N – 1)/N]Cov. The equation shows that as N becomes large, the first term on the right side with the denominator of N becomes smaller and smaller, implying that the contribution of one asset's variance to portfolio variance gradually becomes negligible. The second term, however, approaches the average covariance as N increases. It is reasonable to say that for portfolios with a large number of assets, covariance among the assets accounts for almost all of the portfolio's risk."},
  {"num": 10, "subject": "组合管理", "question": "The global minimum-variance portfolio is a portfolio that lies:", "options": {"A": "anywhere along the minimum-variance frontier.", "B": "at the left-most point of the minimum-variance frontier.", "C": "at the upper right-most point of the minimum-variance frontier."}, "answer": "B", "explanation": "A Incorrect because the entire collection of these minimum-variance portfolios is referred to as the minimum-variance frontier. This describes the minimum variance portfolio, but not the global minimum-variance portfolio.\nB Correct because the left-most point on the minimum-variance frontier is the portfolio with the minimum variance among all portfolios of risky assets, and is referred to as the global minimum-variance portfolio.\nC Incorrect because the upper right-most point of the minimum-variance frontier is the opposite position of the global minimum-variance portfolio, it is actually the maximum variance on the curve of risky portfolios."},
  {"num": 11, "subject": "组合管理", "question": "The correlation of returns between two securities with equal standard deviation of returns is 0.75. If the covariance of returns is 5.5%2, the standard deviation of returns for each security is closest to:", "options": {"A": "2.7%.", "B": "3.7%.", "C": "7.3%."}, "answer": "A", "explanation": "A Correct because the correlation between the returns of the two securities is Since the two securities have equal risk, σi = σj, , σi = 2.7%.\nB Incorrect because it is a miscalculation and mistakes σiσj as 2 × σi; 2 × σi = 7.33%; σi = 3.67% ≈ 3.7%.\nC Incorrect because it is an intermediate step in the correct calculation;"},
  {"num": 12, "subject": "组合管理", "question": "A portfolio consisting of two securities has the following characteristics:\nIf the correlation of returns between the two securities is 0.20, the portfolio's standard deviation of returns is closest to:", "options": {"A": "1.8%.", "B": "9.1%.", "C": "13.4%."}, "answer": "C", "explanation": "A Incorrect because it is portfolio variance instead of standard deviation:: w12σ12+w22σ22+2w1w2ρ1,2σ1σ2 = (0.4)2(0.15)2 + (0.6)2(0.18)2 + 2(0.4)(0.6)(0.2)(0.15)(0.18) = (0.16)(0.0225) + (0.36)(0.0324) + (0.002592) = 0.017856 ≈ 1.8%.\nB Incorrect because it uses standard deviations instead of variances in the formula for the portfolio standard deviation: w12σ1+w22σ2+2w1w2σ1σ2ρ1,2 = (0.4)2(0.15) + (0.6)2(0.18) + 2(0.4)(0.6)(0.20)(0.15)(0.18) = (0.024) + (0.0648) + (0.002592) = 0.091392 ≈ 9.1%.\nC Correct because"},
  {"num": 13, "subject": "组合管理", "question": "A risk-neutral investor most likely seeks to maximize:", "options": {"A": "both risk and return.", "B": "return irrespective of risk.", "C": "return for a given level of risk."}, "answer": "B", "explanation": "A Incorrect because a risk-seeking investor would maximize both risk and return. A risk-neutral investor maximizes return irrespective of risk. That is, a risk-neutral investor deliberately seeks to maximize only return, not risk. It is possible that a risk-neutral investor could end up maximizing risk by maximizing return, but he only seeks to maximize return and risk is not a consideration.\nB Correct because a risk-neutral investor would maximize return irrespective of risk. This is because such an investor cares only about return and not about risk, so higher return investments are more desirable even if they come with higher risk.\nC Incorrect because only risk-averse investors want to minimize their risk for the same amount of return, and maximize their return for the same amount of risk. A risk-neutral investor seeks to maximize return irrespective of risk, not for a given level of risk."},
  {"num": 14, "subject": "组合管理", "question": "Two assets have the following characteristics:\nThe variance of returns for an equally weighted portfolio of the two assets is closest to:", "options": {"A": "0.038.", "B": "0.048.", "C": "0.055."}, "answer": "B", "explanation": "A Incorrect because the last term has not been doubled, leading to: σ2p = (0.5)2(0.05) + (0.5)2(0.06) + (0.5)(0.5)(0.75)(0.05)0.5(0.06)0.5 = 0.0125 + 0.015 + 0.0102698 = 0.03777 ≈ 0.038.\nB Correct because for a two asset portfolio, the expression for portfolio variance simplifies to the following using correlation: σ2p = w12σ12 + w22σ22 + 2w1w2ρ12σ1σ2, where wi is the weight of asset i in the portfolio, σi2 is the variance of asset i, and ρij is the correlation between the returns of assets i and j. Here, σ2p = (0.5)2(0.05) + (0.5)2(0.06) + 2(0.5)(0.5)(0.75)(0.05)0.5(0.06)0.5 = 0.0125 + 0.015 + 0.0205396 = 0.04804 ≈ 0.048.\nC Incorrect because it is the weighted average of the asset variances: (0.5)(0.05) + (0.5)(0.06) = 0.025 + 0.03 = 0.055. However, a weighted average calculation is only appropriate for the portfolio standard deviation (not variance) when the correlation among assets is 1."},
  {"num": 15, "subject": "组合管理", "question": "An analyst gathers the following information:\nThe covariance between the returns of the asset and the market is closest to:", "options": {"A": "0.22.", "B": "0.40.", "C": "0.90."}, "answer": "A", "explanation": "A Correct because, given the beta of an asset (βi), the covariance between the asset returns (Ri) and the market portfolio returns (Rm) is given by: Cov(Ri,Rm) = βi × σm2 = 1.8 × 0.352 = 0.22.\nB Incorrect because it is the systematic variance of the portfolio; βi2 × σm2 = 1.82 × 0.352 = 0.40.\nC Incorrect because it is the correlation coefficient, not the covariance, between the asset returns and the market portfolio returns; ρi,m = βi × σm/σi = 1.8 × 0.35/0.70 = 0.90. It is also the closest answer if the asset return variance is used in the correct formula instead of the market return variance; 1.8 × 0.702 = 0.88."},
  {"num": 16, "subject": "组合管理", "question": "The capital market line most likely consists of portfolios that:", "options": {"A": "are fully diversified.", "B": "have zero systematic risk.", "C": "have nonsystematic risk equal to beta."}, "answer": "A", "explanation": "A Correct because the capital market line (CML) does not apply to all securities or assets but only to portfolios on the efficient frontier. The efficient frontier gives optimal combinations of expected return and total risk. Total risk and systematic risk are equal only for efficient portfolios because those portfolios have no diversifiable risk remaining. Thus, the CML holds only for well-diversified portfolios.\nB Incorrect because the nonsystematic risk of the market portfolio is zero, but not its systematic risk. Because nonsystematic risk is zero for well-diversified portfolios, such as the market portfolio, the total risk of a market portfolio and other similar portfolios is only systematic risk, which is βiσm. Therefore, portfolios on the CML have zero nonsystematic (not systematic) risk.\nC Incorrect because the total risk of a market portfolio and other similar portfolios is only systematic risk, which is βiσm. Therefore, portfolios on the CML have nonsystematic risk equal to zero, not beta."},
  {"num": 17, "subject": "组合管理", "question": "An investor gathers the following information about a security and the market:\nThe correlation between the security's returns and the market's returns is closest to:", "options": {"A": "0.2.", "B": "0.5.", "C": "0.8."}, "answer": "B", "explanation": "A Incorrect because it confuses σi and σm and calculates ρi,m = βi × σi/σm = 0.35 × 0.12/0.18 = 0.233 ≈ 0.2. This answer is also obtained if, as an additional mistake, variances are used; ρi,m = βi × σi2/σm2 = 0.35 × (0.12)2/(0.18)2 = 0.156 ≈ 0.2.\nB Correct because βi = ρi,m × σi/σm, where ρi,m denotes the correlation between the asset returns and the market returns, and σi and σm denote the standard deviation of the asset returns and the market returns, respectively. Thus, correlation ρi,m = βi × σm/σi = 0.35 × 0.18/0.12 = 0.525 ≈ 0.5.\nC Incorrect because it uses variances instead of standard deviations in the correct formula; ρi,m = βi × σm2/σi2 = 0.35 × (0.18)2/(0.12)2 = 0.788 ≈ 0.8."},
  {"num": 18, "subject": "组合管理", "question": "An investor gathers the following information about a portfolio and the market:\nIf the risk-free rate is 3%, Jensen's alpha for the portfolio is:", "options": {"A": "–4.0%.", "B": "–0.4%.", "C": "0.4%."}, "answer": "B", "explanation": "A Incorrect because the market return is used instead of the market risk premium and Jensen's alpha is incorrectly calculated as: αp = Rp – [Rf + βp (Rm)] αp = 11% – [3% + 1.2 × (10%)] αp = 11% – 15% = –4%.\nB Correct because Jensen's alpha is calculated as: αp = Rp – [Rf + βp (Rm – Rf)] αp = 11% – [3% + 1.2 × (10% – 3%)] αp = 11% – 11.4% = –0.4%.\nC Incorrect because the portfolio's actual return and required return are reversed and Jensen's alpha is incorrectly calculated as:"},
  {"num": 19, "subject": "组合管理", "question": "An analyst estimates the standard deviation of returns for the market portfolio to be 15% and the standard deviation of returns for a stock to be 25%. If the correlation of returns between the stock and the market portfolio is 0.6, the stock has:", "options": {"A": "less systematic risk than the market portfolio.", "B": "the same systematic risk as the market portfolio.", "C": "more systematic risk than the market portfolio."}, "answer": "B", "explanation": "A Incorrect because the company has a beta equal to one, which is the same as the beta of the market portfolio.\nB Correct because the amount of systematic risk for a company is measured by the stock's beta. β = ρi,m × σi / σm = 0.60 × 0.25 / 0.15 = 0.15 / 0.15 = 1. Since the company's beta equals the market portfolio's beta (the market portfolio's beta with itself equals 1), the company has the same level of systematic risk as the market portfolio.\nC Incorrect because the company has a beta equal to one, which is the same as the beta of the market portfolio."},
  {"num": 20, "subject": "组合管理", "question": "The intercept on the y-axis of the security characteristic line is:", "options": {"A": "beta.", "B": "Jensen's alpha.", "C": "the risk-free rate of return."}, "answer": "B", "explanation": "A Incorrect because beta is the slope of the security characteristic line (SCL), not the intercept.\nB Correct because the SCL is a plot of the excess return of the security on the excess return of the market. Jensen's alpha is the intercept and the beta is the slope.\nC Incorrect because the risk-free rate of return is the intercept on the y-axis of the security market line, whereas Jensen's alpha is the intercept on the y-axis of the security characteristic line."},
  {"num": 21, "subject": "组合管理", "question": "An analyst gathers the following information:\nAccording to the CAPM, the security's beta is closest to:", "options": {"A": "0.21.", "B": "0.30.", "C": "0.50."}, "answer": "B", "explanation": "A Incorrect because it uses the expected return on the market, not the market risk premium, in the calculation. Namely, it uses: [E(Ri) – Rf]/[E(Rm)] = [7% – 4%]/14% = 0.21.\nB Correct because, according to the CAPM, the expected return [E(Ri)] for an asset is given by: E(Ri) = Rf + βi[E(Rm) – Rf]. The beta [βi] is then calculated using: βi = [E(Ri) – Rf]/[E(Rm) – Rf] = [7% – 4%]/[14% – 4%] = 0.30.\nC Incorrect because it is simply the expected return for the security divided by the expected return for the market; 7%/14% = 0.50."},
  {"num": 22, "subject": "组合管理", "question": "A security with a beta of 1.5 has an expected return of 11% according to the CAPM. If the risk-free rate is 2%, the market risk premium is closest to:", "options": {"A": "4.0%.", "B": "6.0%.", "C": "7.3%."}, "answer": "B", "explanation": "A Incorrect because it uses an incorrect CAPM equation to calculate the expected return of a security as E(Ri) = Rf + βi × E(Rm), such that E(Rm) = [E(Ri) – Rf]/βi = (0.11 – 0.02)/1.5 = 0.06 = 6%. Since the market risk premium is Rm – Rf, it follows that the market risk premium is calculated as 6% – 2% = 4%.\nB Correct because, according to the CAPM, the expected return of a security is E(Ri) = Rf + βi[E(Rm) – Rf], such that [E(Rm) – Rf ]= [E(Ri) – Rf]/βi = (0.11 – 0.02)/1.5 = 0.06 = 6%. The market risk premium is E(Rm) – Rf = 6%.\nC Incorrect because it uses an incorrect CAPM equation to calculate the expected return of a security as E(Ri) = βi × [E(Rm) – Rf], such that [E(Rm) – Rf ] = E(Ri)/βi = 0.11/1.5 = 0.0733 ≈ 7.3%. The market risk premium is incorrectly calculated as 7.3%."},
  {"num": 23, "subject": "组合管理", "question": "An analyst gathers the following information:\nAccording to the CAPM, the expected return of the security is closest to:", "options": {"A": "5.7%.", "B": "13.2%.", "C": "16.0%."}, "answer": "B", "explanation": "A Incorrect because the security beta is wrongly calculated due to the reversal of the standard deviations of the security and the market portfolio. Therefore, the beta is calculated as β = (0.8 × 20%)/35% = 0.457. Next, using the CAPM equation, E(Ri) = Rf + β[E(Rm – Rf)], the expected return of the security is calculated as E(Ri) = 2% + 0.457 × (10% − 2%) = 5.66% ≈ 5.7%.\nB Correct because the expected return of the security can be calculated using the CAPM equation: E(Ri) = Rf + β[E(Rm) – Rf]. The beta of the security can be calculated using the equation β = (ρi,m × σi)/σm. Therefore, β = (0.8 × 35%)/20% = 1.4. Beta is the product of the asset’s correlation with the market with a ratio of standard deviations of return (i.e., the ratio of the asset’s standard deviation to the market’s). Therefore, using the CAPM equation: E(Ri) = 2% + 1.4 × (10% − 2%) = 13.2%.\nC Incorrect because the risk-free rate is not included in the calculation of the market risk premium. Beta is calculated as β = (0.8 × 35%)/20% = 1.4. Therefore, using the CAPM equation: E(Ri) = 2% + 1.4 × (10%) = 16.0%."},
  {"num": 24, "subject": "组合管理", "question": "The correlation between the risk-free asset and the optimal risky portfolio is expected to be:", "options": {"A": "negative.", "B": "zero.", "C": "positive."}, "answer": "B", "explanation": "A Incorrect because a combination of the risk-free asset and a risky asset can result in a better risk–return trade-off than an investment in only one type of asset because the risk-free asset has zero correlation with the risky asset. The optimal risky portfolio is a risky asset, and thus has zero correlation with the risk-free asset.\nB Correct because a combination of the risk-free asset and a risky asset can result in a better risk–return trade-off than an investment in only one type of asset because the risk-free asset has zero correlation with the risky asset. The optimal risky portfolio is a risky asset, and thus has zero correlation with the risk-free asset.\nC Incorrect because a combination of the risk-free asset and a risky asset can result in a better risk–return trade-off than an investment in only one type of asset because the risk-free asset has zero correlation with the risky asset. The optimal risky portfolio is a risky asset, and thus has zero correlation with the risk-free asset."},
  {"num": 25, "subject": "组合管理", "question": "Which of the following performance measures is equal to the slope of the capital allocation line?", "options": {"A": "M2", "B": "Sharpe ratio", "C": "Treynor ratio"}, "answer": "B", "explanation": "A Incorrect because M2 provides a measure of portfolio return that is adjusted for the total risk of the portfolio relative to that of some benchmark. While M2 is related to the Sharpe ratio, it is calculated in a different way and is measured in different units, therefore it does not represent the slope of the capital allocation line.\nB Correct because the Sharpe ratio, also called the reward-to-variability ratio, is simply the slope of the capital allocation line.\nC Incorrect because the Treynor ratio corresponds to the slope of the security market line, not the capital allocation line. The Treynor ratio is a simple extension of the Sharpe ratio and resolves the Sharpe ratio's first limitation by substituting beta (systematic risk) for total risk."},
  {"num": 26, "subject": "组合管理", "question": "An analyst gathers the following information about a portfolio and the market:\nThe portfolio's Treynor ratio is closest to:", "options": {"A": "0.060.", "B": "0.114.", "C": "0.413."}, "answer": "B", "explanation": "A Incorrect because 0.060 = SR × (σp/βp') = 0.8 × (0.19/2.527), where βp' = incorrectly calculated portfolio beta = ρpm(σp2/σm2) = 0.7 × (0.192/0.12) = 2.527.\nB Correct because TR = (Rp – Rf)/βp = [(Rp – Rf)/σp] × (σp/<βp) = SR × (σp/βp) = 0.8 × (0.19/1.33) = 0.114, where σm = standard deviation of market returns = 0.10 (given); σp = standard deviation of portfolio returns = 0.19 (given); ρp,m = correlation between market and portfolio = 0.7 (given); βp = portfolio beta = ρp,m(σp/σm) = 0.7 × (0.19/0.1) = 1.33 (per βi = ρi,m(σi/σm)); Rp = portfolio's return; Rf = risk-free rate of interest; TR = Treynor ratio; SR = Sharpe ratio, where SR = (Rp – Rf)/σp.\nC Incorrect because"},
  {"num": 27, "subject": "组合管理", "question": "Which of the following lines is plotted on a graph with the excess return of a security on the y-axis and the excess return of the market on the x-axis?", "options": {"A": "Capital market line", "B": "Security market line", "C": "Security characteristic line"}, "answer": "C", "explanation": "A Incorrect because the capital market line is a special case of the capital allocation line, where the risky portfolio is the market portfolio. The capital market line is shown in Exhibit 3, where the standard deviation (σp), or total risk, is on the x-axis and expected portfolio return, E(Rp), is on the y-axis.\nB Incorrect because the security market line represents a graph of the capital asset pricing model. The security market line (SML) is a graphical representation of the capital asset pricing model with beta, reflecting systematic risk, on the x-axis and expected return on the y-axis. Using the same concept as the capital market line, the SML intersects the y-axis at the risk-free rate of return, and the slope of this line is the market risk premium, Rm – Rf.\nC Correct because similar to the SML (security market line), we can draw a security characteristic line (SCL) for a security. The SCL is a plot of the excess return of the security on the excess return of the market. The security characteristic line can also be estimated by regressing the excess security return, Ri – Rf, on the excess market return, Rm – Rf."},
  {"num": 28, "subject": "组合管理", "question": "An analyst gathers the following information about the security market line (SML) and a stock:\nAccording to capital market theory, if the analyst believes the stock will have a return of 7%, the stock is:", "options": {"A": "undervalued.", "B": "properly valued.", "C": "overvalued."}, "answer": "C", "explanation": "A Incorrect because the analyst forecasts the return of the asset to be 7%, which is lower than the expected return of 8.5% according to the CAPM. Thus, the security plots below the SML and should be considered overvalued. This response would be chosen if the expected return of the asset was wrongly computed as 0.02 + 1.3 × (0.05 – 0.02) = 0.059 = 5.9%, which would imply that the asset plots above the SML.\nB Incorrect because the analyst forecasts the return of the asset to be 7%, which is lower than the expected return of 8.5% according to the CAPM. Thus, the security does not plot on the SML and it is not properly valued according to the CAPM. This response would be chosen if beta was omitted in the CAPM equation and the expected return of the asset was wrongly computed as 0.02 + 0.05 = 0.07 = 7.0%, which would imply that the asset plots on the SML.\nC Correct because the security market line (SML) is a graphical representation of the capital asset pricing model with beta, reflecting systematic risk, on the x-axis and expected return on the y-axis. Using the same concept as the capital market line, the SML intersects the y-axis at the risk-free rate of return, and the slope of this line is the market risk premium, Rm – Rf . Potential investors can plot a security’s expected return and beta against the SML and use this relationship to decide whether the security is overvalued or undervalued in the market. All securities that reflect the consensus market view are points directly on the SML (i.e., properly valued). If a point representing the estimated return of an asset is above the SML, the asset has a low level of risk relative to the amount of expected return and would be a good choice for investment. In contrast, if the point representing a particular asset is below the SML, the stock is considered overvalued. The asset will be on the SML if the forecasted return equals the expected return of 0.02 + 1.3 × 0.05 = 0.085 = 8.5%. Since the analyst forecasts the return of the asset to be 7%, which is lower than the expected return according to the CAPM, the security plots below the SML and should be considered overvalued."},
  {"num": 29, "subject": "组合管理", "question": "The security market line applies:", "options": {"A": "to all securities.", "B": "only to efficient securities.", "C": "only to securities that have idiosyncratic risk."}, "answer": "A", "explanation": "A Correct because the security market line applies to any security, efficient or not. The security market line (SML) is a graphical representation of the capital asset pricing model with beta, reflecting systematic risk, on the x-axis and expected return on the y-axis.\nB Incorrect because the security market line applies to any security, efficient or not, as opposed to the capital market line, which does not apply to all securities or assets but only to portfolios on the efficient frontier.\nC Incorrect because the security market line applies to any security, efficient or not. Total risk and systematic risk are equal only for efficient portfolios because those portfolios have no diversifiable risk remaining. The latter risk is also called idiosyncratic risk."},
  {"num": 30, "subject": "组合管理", "question": "The market has a return of 8% and a standard deviation of returns of 12%. The risk-free rate is 2%. If a portfolio has a Sharpe ratio of 0.8, the portfolio's M2 alpha is closest to:", "options": {"A": "3.6%.", "B": "5.6%.", "C": "11.6%."}, "answer": "A", "explanation": "A Correct because M2 provides a measure of portfolio return that is adjusted for the total risk of the portfolio and is computed as M2 = [E(Rp) − Rf](σm/σp) + Rf = SR × σm + Rf , where SR = Sharpe ratio, σm = market standard deviation of returns, and Rf = risk-free rate. Thus, M2 = 0.8 × 0.12 + 0.02 = 0.116. The difference between the risk-adjusted performance of the portfolio and the performance of the market is frequently referred to as M2 alpha. Thus, M2 alpha = 0.116 – 0.08 = 0.036 = 3.6%.\nB Incorrect because it computes M2 = 0.02 + 0.8 × 0.12 = 0.116. M2 alpha is wrongly calculated as 0.116 – (0.08 – 0.02) = 0.056 = 5.6%.\nC Incorrect because it computes M2 instead of M2 alpha, which is an intermediate step in the correct calculation; M2 = 0.02 + 0.8 × 0.12 = 0.116 = 11.6%."},
  {"num": 31, "subject": "组合管理", "question": "Which of the following measures is most appropriate to evaluate the performance of a portfolio that is not fully diversified?", "options": {"A": "Sharpe ratio", "B": "Treynor ratio", "C": "Jensen's alpha"}, "answer": "A", "explanation": "A Correct because total risk is relevant for an investor when he or she holds a portfolio that is not fully diversified, which is not a desirable portfolio. In such cases, the Sharpe ratio and M2 are appropriate performance measures. The Sharpe ratio uses total risk as a measure of risk.\nB Incorrect because performance measures relative to beta risk—Treynor ratio and Jensen’s alpha—are relevant when the investor holds a well-diversified portfolio with negligible diversifiable risk.\nC Incorrect because performance measures relative to beta risk—Treynor ratio and Jensen’s alpha—are relevant when the investor holds a well-diversified portfolio with negligible diversifiable risk."},
  {"num": 32, "subject": "组合管理", "question": "Which of the following measures uses only systematic risk to evaluate portfolio performance?", "options": {"A": "M2", "B": "Sharpe ratio", "C": "Jensen's alpha"}, "answer": "C", "explanation": "A Incorrect because M2 provides a measure of portfolio return that is adjusted for the total risk of the portfolio relative to that of some benchmark.\nB Incorrect because the Sharpe ratio measure is based on total risk. Total risk is relevant for an investor when he or she holds a portfolio that is not fully diversified, which is not a desirable portfolio. In such cases, the Sharpe ratio and M2 are appropriate performance measures.\nC Correct because Jensen’s alpha is based on systematic risk. The difference between the actual portfolio return and the calculated risk-adjusted return is a measure of the portfolio’s performance relative to the market portfolio and is called Jensen’s alpha."},
  {"num": 33, "subject": "组合管理", "question": "An analyst gathers the following information about a portfolio and the market:\nJensen’s alpha for the portfolio is:", "options": {"A": "0.0%.", "B": "1.2%.", "C": "2.2%."}, "answer": "B", "explanation": "A Incorrect because the market return is used instead of the market risk premium. Therefore, Jensen's alpha = Rp – [Rf + (βp × Rm)] = 7% – (1% + 1.2 × 5%) = 0.0%.\nB Correct because Jensen’s alpha is defined as the portfolio return less (the risk-free rate plus the portfolio beta times (the market return minus the risk-free rate)). Therefore, Jensen's alpha = Rp – [Rf + βp(Rm – Rf)] = 7% – (1% + 1.2 × (5% – 1%)) = 7.0% – 5.8% = 1.2%.\nC Incorrect because this omits the initial risk-free rate in the equation. Therefore, Jensen's alpha = Rp – βp[Rm – Rf] = 7% – (1.2 × (5% – 1%)) = 7.0% – 4.8% = 2.2%."},
  {"num": 34, "subject": "组合管理", "question": "If all investors have homogeneous expectations, the total risk and expected return of portfolios consisting of the risk-free asset and the optimal risky portfolio are plotted on the:", "options": {"A": "capital market line.", "B": "security market line.", "C": "security characteristic line."}, "answer": "A", "explanation": "A Correct because the risk-free asset could be combined with a risky portfolio to create a capital allocation line (CAL). A specific CAL that uses the market portfolio as the optimal risky portfolio is known as the capital market line. When assuming homogeneous expectations, only one optimal portfolio exists. The capital market line is shown in Exhibit 3, where the standard deviation (σp), or total risk, is on the x-axis and expected portfolio return, E(Rp), is on the y-axis.\nB Incorrect because the security market line (SML) is a graphical representation of the capital asset pricing model with beta, reflecting systematic risk, on the x-axis and expected return on the y-axis. Using the same concept as the capital market line, the SML intersects the y-axis at the risk-free rate of return, and the slope of this line is the market risk premium, Rm – Rf.\nC Incorrect because a security characteristic line (SCL) for a security is a plot of the excess return of the security on the excess return of the market."},
  {"num": 35, "subject": "组合管理", "question": "An investor who can lend and borrow at the risk-free rate builds a portfolio using the risk-free asset and the market portfolio. The risk-free rate is 3% and the expected market return is 15%. If the expected portfolio return is 18%, the investor's portfolio is:", "options": {"A": "a lending portfolio.", "B": "a leveraged portfolio.", "C": "the optimal risky portfolio."}, "answer": "B", "explanation": "A Incorrect because a lending portfolio is a portfolio that has a positive investment in the risk-free asset. A portfolio's expected return, E(Rp), is calculated as: E(Rp) = w1Rf + (1 – w1)E(Rm), where w1 is the proportion invested in the risk-free asset, returning Rf, and E(Rm) is the expected return on the market portfolio. Thus, 0.18 = w1 × 0.03 + (1 – w1) × 0.15 0.18 – 0.15 = w1 × (0.03 – 0.15) 0.03 = w1 × (–0.12) w1 = 0.03/(–0.12) w1 = –0.25 A negative proportion invested in the risk-free rate implies a leveraged, not a lending, portfolio.\nB Correct because a leveraged portfolio is a portfolio that has a negative investment in the risk-free asset. A portfolio's expected return, E(Rp), is calculated as: E(Rp) = w1Rf + (1 – w1)E(Rm), where w1 is the proportion invested in the risk-free asset, returning Rf, and E(Rm) is the expected return on the market portfolio. Thus, 0.18 = w1 × 0.03 + (1 – w1) × 0.15 0.18 – 0.15 = w1 × (0.03 – 0.15) 0.03 = w1 × (–0.12) w1 = 0.03/(–0.12) w1 = –0.25 A negative proportion invested in the risk-free rate implies a leveraged portfolio.\nC Incorrect because the expected market return is 15%, while the expected portfolio return is 18%. Since the two returns are different, the investor's portfolio is different from the optimal risky (market) portfolio."},
  {"num": 36, "subject": "组合管理", "question": "An analyst gathers the following information about three securities:\nAccording to capital market theory, which security has the highest expected return?", "options": {"A": "Security 1", "B": "Security 2", "C": "Security 3"}, "answer": "A", "explanation": "A Correct because according to the capital market theory investors should not be compensated for taking on nonsystematic risk. In contrast, investors must be compensated for accepting systematic risk because that risk cannot be diversified away. In summary, systematic or non-diversifiable risk is priced and investors are compensated for holding assets or portfolios based only on that investment's systematic risk. Also, Total variance = Systematic variance + Nonsystematic variance. Thus, Security 1 has systematic variance = 0.20 – 0.05 = 0.15; Security 2 has systematic variance = 0.30 – 0.25 = 0.05; Security 3 has systematic variance = 0.35 – 0.22 = 0.13. Since only systematic variance (risk) is compensated with a higher expected return, Security 1 has the highest expected return.\nB Incorrect because Security 2 has the highest nonsystematic variance (risk) but the lowest systematic variance (risk), and investors should not be compensated for taking on nonsystematic risk. Since only systematic variance (risk) is compensated with a higher expected return, Security 2 has the lowest expected return.\nC Incorrect because Security 3 has the highest total variance (risk) but not the highest systematic variance (risk), and investors should not be compensated for taking on nonsystematic risk. Since only systematic risk is compensated with a higher expected return, Security 3 does not have the highest expected return."},
  {"num": 37, "subject": "组合管理", "question": "The risk–return trade-off of a portfolio of only risky assets most likely improves when a risk-free asset is added to the portfolio because:", "options": {"A": "the risk-free asset is uncorrelated with the other assets in the portfolio.", "B": "the lower return on the risk-free asset provides a diversification effect.", "C": "the correlations among the risky assets decrease, providing a diversification effect."}, "answer": "A", "explanation": "A Correct because an investor's portfolio improves if a risk-free asset is added to the mix. In other words, a combination of the risk-free asset and a risky asset can result in a better risk–return trade-off than an investment in only one type of asset because the risk-free asset has zero correlation with the risky asset.\nB Incorrect because the risk–return trade-off is improved by lower risk not a lower return. It is the zero correlation of the risk-free asset with the risky assets in the portfolio that lowers the risk level.\nC Incorrect because the correlations among the risky assets are unaffected by the addition of a risk-free asset to the portfolio. The risk–return trade-off is improved by the zero correlation of the risk-free asset with the risky assets in the portfolio, not a change in correlations among the risky assets."},
  {"num": 38, "subject": "组合管理", "question": "An analyst gathers the following information about an asset and the market:\nBased on the CAPM, the asset's beta is closest to:", "options": {"A": "0.80.", "B": "1.00.", "C": "1.25."}, "answer": "A", "explanation": "A Correct because the expected return of an asset is E(Ri) = Rf + βi[E(Rm) – Rf], where Ri, Rm, and Rf denote the return on the asset, the market, and the risk-free asset, respectively, βi is the asset's beta, and [E(Rm) – Rf ] is the market risk premium. Thus, βi = [E(Ri) – Rf] / [E(Rm) – Rf] = [5% – 1%] / 5% = 4%/5% = 0.8.\nB Incorrect because it does not subtract the risk-free rate in the numerator and calculates βi = E(Ri) / [E(Rm) – Rf] = 5%/5% = 1.0. It is also the answer if the market risk premium is confused with the market return, thus βi = [E>(Ri) – Rf] / [market risk premium – Rf] = [5% – 1%] / [5% – 1%] = 4%/4% = 1.0.\nC Incorrect because it is the inverse of beta, 1/βi> = [E(Rm) – Rf] / [E(Ri) – Rf] = market risk premium / [E(Ri) – Rf] = 5% / [5% – 1%] = 5%/4% = 1.25. It is also the answer if two mistakes are made: The risk-free rate is not subtracted from the expected return in the numerator and the market risk premium is confused with the market return. Thus, βi = E(Ri) / [market risk premium – Rf] = 5% / [5% – 1%] = 5%/4% = 1.25."},
  {"num": 39, "subject": "组合管理", "question": "The slope of the security market line is most likely the:", "options": {"A": "security's beta.", "B": "market risk premium.", "C": "market risk premium divided by the market standard deviation."}, "answer": "B", "explanation": "A Incorrect because the security's beta is the slope of the security characteristic line (SCL), not the security market line. The SCL is a plot of the excess return of the security on the excess return of the market. The beta is the slope.\nB Correct because the security market line (SML) is a graphical representation of the capital asset pricing model with beta, reflecting systematic risk, on the x-axis and expected return on the y-axis. The slope of this line is the market risk premium, Rm – Rf.\nC Incorrect because it is the slope of the capital market line (CML), E(Rm) – Rf /σm not the security market line. Since the market standard deviation is unlikely to be 1, the slope of the CML is most likely not the slope of the SML."},
  {"num": 40, "subject": "组合管理", "question": "The market model is most likely used to estimate:", "options": {"A": "market returns.", "B": "risk-free returns.", "C": "abnormal returns."}, "answer": "C", "explanation": "A Incorrect because the market model takes the expected market return as given rather than predicting it.\nB Incorrect because the market model does not explicitly consider the risk-free rate of return (unlike the single-index model).\nC Correct because the market model is normally used for estimating beta risk and computing abnormal returns. These parameter estimates are then used to predict company-specific returns that a security may earn in a future period."},
  {"num": 41, "subject": "组合管理", "question": "Unsystematic risk is best described as:", "options": {"A": "total risk.", "B": "diversifiable risk.", "C": "the variability in all risky assets caused by macroeconomic variables."}, "answer": "B", "explanation": "A Incorrect because total risk includes both systematic and nonsystematic risk.\nB Correct because unsystematic (nonsystematic) risk can be diversified away.\nC Incorrect because the variability caused by macroeconomic variables is systematic (market) risk."},
  {"num": 42, "subject": "组合管理", "question": "An analyst estimates the market model for an asset and obtains the following parameters:\nIf the market's expected return is 2%, the asset's expected return is:", "options": {"A": "1.0%.", "B": "1.5%.", "C": "2.0%."}, "answer": "C", "explanation": "A Incorrect because it neglects the constant term α in the correct calculation; 0.5 × 2% = 1%. It is also the expected market return minus the asset's alpha; 2% – 1% = 1%.\nB Incorrect because it mistakes α for the risk-free rate in the CAPM expected return calculation; 1% + 0.5 × (2% – 1%) = 1.5%. It is also the result of the incorrect calculation: β × [α +E(Rm)] = 0.5 × (1% + 2%) = 1.5%.\nC Correct because the expected return of an asset according to the market model is calculated as E(Ri) = α + β × E(Rm), where E(Rm) denotes the expected market return; 1% + 0.5 × 2% = 2%."},
  {"num": 43, "subject": "组合管理", "question": "With respect to multi-factor return-generating models, a company's earnings are best classified as a:", "options": {"A": "statistical factor.", "B": "fundamental factor.", "C": "macroeconomic factor."}, "answer": "B", "explanation": "A Incorrect because, in a statistical factor model, historical and cross-sectional return data are analyzed to identify factors that explain variance or covariance in observed returns. Earnings is not a statistical factor but a fundamental factor. Fundamental factor models analyze and use relationships between security returns and the company’s underlying fundamentals, such as, for example, earnings.\nB Correct because a multi-factor model allows more than one variable to be considered in estimating returns and can be built using different kinds of factors, such as macroeconomic, fundamental, and statistical factors. Fundamental factor models analyze and use relationships between security returns and the company’s underlying fundamentals, such as, for example, earnings.\nC Incorrect because macroeconomic factor models use economic factors that are correlated with security returns. These factors may include economic growth, the interest rate, the inflation rate, productivity, employment, and consumer confidence. Earnings is not a macroeconomic factor but a fundamental factor. Fundamental factor models analyze and use relationships between security returns and the company’s underlying fundamentals, such as, for example, earnings."},
  {"num": 44, "subject": "组合管理", "question": "The market portfolio's level of systematic risk is most likely:", "options": {"A": "less than its level of nonsystematic risk.", "B": "equal to its level of nonsystematic risk.", "C": "greater than its level of nonsystematic risk."}, "answer": "C", "explanation": "A Incorrect because nonsystematic risk is diversified away; therefore, systematic risk is greater than nonsystematic risk.\nB Incorrect because nonsystematic risk is diversified away; therefore, systematic risk is greater than nonsystematic risk.\nC Correct because systematic or non-diversifiable risk is priced and investors are compensated for holding assets or portfolios based only on that investment's systematic risk. Investors do not receive any return for accepting nonsystematic or diversifiable risk. Also, investors are capable of avoiding nonsystematic risk through diversification by forming a portfolio of assets that are not highly correlated with one another. Thus, for a market portfolio, there is only systematic risk because nonsystematic risk is diversified away."},
  {"num": 45, "subject": "组合管理", "question": "In an equally weighted portfolio, the diversification ratio is best described as a measure of the:", "options": {"A": "relative level of risk between any two individual assets.", "B": "amount of risk an asset contributes to the portfolio's risk.", "C": "risk reduction benefit of investing in the portfolio versus a security from the portfolio."}, "answer": "C", "explanation": "A Incorrect because the diversification ratio compares volatility between a portfolio and a single asset, not between two single assets. A simple measure of the value of diversification is calculated as the ratio of the standard deviation of the equally weighted portfolio to the standard deviation of the randomly selected security.\nB Incorrect because the diversification ratio compares the risk of an overall portfolio relative to a single security; it does not measure the amount of risk an asset contributes to the portfolio's risk.\nC Correct because the level of risk reduction from the portfolio approach to investing, relative to the risk of investing in a single security, can be measured by the diversification ratio. A simple measure of the value of diversification is calculated as the ratio of the standard deviation of the equally weighted portfolio to the standard deviation of the randomly selected security. This ratio may be referred to as the diversification ratio. The diversification ratio of the portfolio's standard deviation to the individual asset's standard deviation measures the risk reduction benefits of a simple portfolio construction method, equal weighting."},
  {"num": 46, "subject": "组合管理", "question": "Which of the following is most likely part of the feedback step in the portfolio management process?", "options": {"A": "Portfolio construction", "B": "Performance measurement", "C": "Developing the investment policy statement"}, "answer": "B", "explanation": "A Incorrect because portfolio construction is part of the execution step.\nB Correct because performance measurement, along with portfolio monitoring and rebalancing, is part of the feedback step.\nC Incorrect because developing the investment policy statement is part of the planning step."},
  {"num": 47, "subject": "组合管理", "question": "The diversification ratio of a portfolio is best described as the ratio of the:", "options": {"A": "standard deviation of the equally weighted portfolio's returns to the average standard deviation of the individual securities' returns.", "B": "standard deviation of the market-capitalization-weighted portfolio's returns to the standard deviation of the equally weighted portfolio's returns.", "C": "average standard deviation of the individual securities' returns to the standard deviation of the market-capitalization-weighted portfolio's returns."}, "answer": "A", "explanation": "A Correct because a simple measure of the value of diversification is calculated as the ratio of the standard deviation of the equally weighted portfolio to the standard deviation of the randomly selected security. This ratio may be referred to as the diversification ratio. In the example of the 5-stock portfolio given, the equally weighted portfolio’s standard deviation is approximately 71 percent of the average standard deviation of the 5 stocks (24.9%); i.e., the denominator is the average standard deviation of all individual securities in the portfolio and the numerator is the standard deviation of the equally weighted portfolio.\nB Incorrect because the standard deviation of the equally weighted portfolio should be the numerator (not the denominator) and the denominator should be the average standard deviation of all individual securities in the portfolio.\nC Incorrect because the average standard deviation of all individual securities in the portfolio should be the denominator (not the numerator) and the numerator should be the standard deviation of the equally weighted portfolio."},
  {"num": 48, "subject": "组合管理", "question": "The portfolio approach to investing most likely:", "options": {"A": "prevents portfolio losses during market downturns.", "B": "reduces the systematic risk of individual assets in a portfolio.", "C": "helps avoid disastrous investment outcomes during normal market conditions."}, "answer": "C", "explanation": "A Incorrect because, although the portfolio approach helps avoid disasters by way of diversification, it does not necessarily provide downside protection (prevent losses) during market downturns. A major reason that portfolios can effectively reduce risk is that combining securities whose returns do not move together provides diversification. However, an important issue is that the co-movement or correlation pattern of the securities' returns in the portfolio can change in a manner unfavorable to the investor. Despite diversification, a portfolio is unlikely to preserve its value during market downturns.\nB Incorrect because an asset's risk should be measured in relation to the remaining systematic or non-diversifiable risk, which should be the only risk that affects the asset's price. Systematic risk is risk that cannot be avoided and is inherent in the overall market. It is non-diversifiable because it includes risk factors that are innate within the market and affect the market as a whole. Therefore, portfolio diversification does not reduce the systematic risk of individual assets in a portfolio.\nC Correct because portfolio diversification helps investors avoid disastrous investment outcomes. A main tenet of the portfolio approach to investing is diversification. A disastrous outcome can result from ‘putting all your eggs into one basket' or investing everything into one stock whose value could then go to zero. A diversified portfolio holding many securities is likely to avoid this outcome. Although diversification may not prevent losses during market downturns, it does help avoid disastrous investment outcomes during normal market conditions."},
  {"num": 49, "subject": "组合管理", "question": "Which of the following statements about pension plans is most accurate?", "options": {"A": "Defined benefit plans typically have a low risk tolerance.", "B": "Defined contribution plans typically have a low risk tolerance.", "C": "The sponsor of a defined benefit plan specifies the obligation owed to participants."}, "answer": "C", "explanation": "A Incorrect because the risk tolerance for defined benefit pension plans will vary with the maturity of the plan, but is typically quite high.\nB Incorrect because defined contribution pension plans are managed for individual investors, therefore the risk tolerance of each plan varies with the individual. Some individuals will be investing for growth and will therefore seek assets that have the potential for capital gains. Others, such as retirees, may need to draw an income from their assets and may therefore choose to invest more in fixed-income and dividend-paying shares. The investment needs of individuals will depend in part on their broader financial circumstances, such as their employment prospects and whether or not they own their own residence. They may also need to consider such issues as building up a cash reserve and the purchase of appropriate insurance policies before undertaking longer-term investments. The risk tolerance of an individual investor varies by individual.\nC Correct because defined benefit pension plans (DB plans) are company-sponsored plans that offer employees a predefined benefit on retirement. The future benefit is defined because the DB plan requires the plan sponsor to specify the obligation stated in terms of the retirement income benefits owed to participants."},
  {"num": 50, "subject": "组合管理", "question": "Open-end mutual funds typically:", "options": {"A": "are priced intraday.", "B": "have a fixed number of shares outstanding.", "C": "have a larger required minimum investment than ETFs."}, "answer": "C", "explanation": "A Incorrect because it is an ETF that is priced intraday, not a mutual fund. The value of a mutual fund is referred to as the 'net asset value'. It is computed daily based on the closing price of the securities in the portfolio. Because they are traded on exchanges, ETFs can be transacted (and are priced) intraday. In contrast, mutual funds typically can be purchased or sold only once a day.\nB Incorrect because closed-end, not open-end, mutual funds have a fixed number of shares outstanding. An alternative to setting the fund up as an open-end fund would be to create a closed-end fund in which no new investment money is accepted into the fund. New investors invest by buying existing shares, and investors in the fund liquidate by selling their shares to other investors. Hence, the number of outstanding shares does not change. One consequence of this fixed share base is that, unlike open-end funds in which new shares are created and sold at the current net asset value per share, closed-end funds can sell for a premium or discount to net asset value depending on the demand for the shares.\nC Correct because the minimum required investment in ETFs is usually smaller than that of mutual funds."},
  {"num": 51, "subject": "组合管理", "question": "Robo-advisers most likely:", "options": {"A": "face high barriers to entry.", "B": "cater to the demand from investors with lower levels of investable assets.", "C": "prefer actively managed funds to index funds when constructing client portfolios."}, "answer": "B", "explanation": "A Incorrect because reflecting low barriers to entry, large wealth management firms have introduced robo-adviser solutions to service certain customer segments and appeal to a new generation of investors.\nB Correct because rapid growth in robo-advisory assets is based on several industry trends including growing demand from 'mass affluent' and younger investors. Traditional investment advice has often underserved younger and 'mass affluent' investors with lower relative levels of investable assets.\nC Incorrect because robo-advisers often rely on lower fee underlying portfolio investment options, such as index funds or ETFs, when constructing portfolios for clients."},
  {"num": 52, "subject": "组合管理", "question": "In regard to the asset allocation process, a top-down analysis most likely begins with an examination of:", "options": {"A": "macroeconomic growth.", "B": "a company's board of directors.", "C": "the expected growth of a company's competitors."}, "answer": "A", "explanation": "A Correct because a top-down analysis begins with consideration of macroeconomic conditions. Based on the current and forecasted economic environment, analysts evaluate markets and industries with the purpose of investing in those that are expected to perform well. Finally, specific companies within these industries are considered for investment.\nB Incorrect because a top-down analysis begins with consideration of macroeconomic conditions. Bottom-up analysis focuses on company specifics. Rather than emphasizing economic cycles or industry analysis, a bottom-up analysis focuses on company-specific circumstances, such as management quality and business prospects.\nC Incorrect because a top-down analysis begins with consideration of macroeconomic conditions. Bottom-up analysis focuses on company specifics. Rather than emphasizing economic cycles or industry analysis, a bottom-up analysis focuses on company-specific circumstances, such as management quality and business prospects."},
  {"num": 53, "subject": "组合管理", "question": "Which of the following best describes a characteristic of defined contribution pension plans?", "options": {"A": "The employee accepts the investment and inflation risk.", "B": "The employer is responsible for adequately funding the plan.", "C": "Defined contribution plans typically have a higher cost to the company than defined benefit plans."}, "answer": "A", "explanation": "A Correct because the key to a defined contribution (DC) plan is that the employee accepts the investment and inflation risk and is responsible for ensuring that there are enough assets in the plan to meet their needs upon retirement.\nB Incorrect because this applies for defined benefit (DB) plans, as generally, employers are responsible for the contributions made to a DB plan and bear the risk associated with adequately funding the benefits offered to employees.\nC Incorrect because defined contribution (DC) plans typically have lower costs/risk to the company."},
  {"num": 54, "subject": "组合管理", "question": "Which of the following statements about different types of investors is most accurate?", "options": {"A": "For banks, the liquidity of their investments is a paramount concern.", "B": "For endowments, investment horizons are short due to their short-term spending needs.", "C": "For insurance companies, the risk tolerance of their general and surplus accounts is typically the same."}, "answer": "A", "explanation": "A Correct because liquidity is a paramount concern for banks that stand ready to meet depositor requests for withdrawals.\nB Incorrect because most foundations and endowments are established with the intent of having perpetual lives. The large allocation to alternative investments primarily reflects the typically long time horizon of endowments and foundations.\nC Incorrect because an insurance company’s general account is typically invested conservatively in a diverse allocation of fixed-income securities, while an insurer’s surplus account typically targets a higher return than the general account and thus often invests in less-conservative asset classes."},
  {"num": 55, "subject": "组合管理", "question": "Relative to passive market-cap-weighted strategies, smart beta strategies typically have:", "options": {"A": "lower management fees and higher portfolio turnover.", "B": "higher management fees and lower portfolio turnover.", "C": "higher management fees and higher portfolio turnover."}, "answer": "C", "explanation": "A Incorrect because typically, smart beta strategies feature somewhat higher [not lower] management fees and higher portfolio turnover relative to passive market-cap weighted strategies.\nB Incorrect because typically, smart beta strategies feature somewhat higher management fees and higher [not lower] portfolio turnover relative to passive market-cap weighted strategies.\nC Correct because typically, smart beta strategies feature somewhat higher management fees and higher portfolio turnover relative to passive market-cap weighted strategies."},
  {"num": 56, "subject": "组合管理", "question": "Exchange-traded funds (ETFs):", "options": {"A": "are priced once a trading day.", "B": "usually pay out dividends to shareholders.", "C": "are generally structured as closed-end funds."}, "answer": "B", "explanation": "A Incorrect because ETFs can be transacted (and are priced) intraday.\nB Correct because dividends on ETFs are paid out to the shareholders whereas mutual funds usually reinvest the dividends.\nC Incorrect because exchange-traded funds (ETFs) are generally structured as open-end funds."},
  {"num": 57, "subject": "组合管理", "question": "Sovereign wealth funds are best described as investment funds:", "options": {"A": "owned by governments.", "B": "traded as closed-end country funds.", "C": "restricted from investing in foreign securities."}, "answer": "A", "explanation": "A Correct because sovereign wealth funds (SWFs) are government-owned investment funds.\nB Incorrect because sovereign wealth funds (SWFs) are government-owned investment funds. Closed-end funds are mutual funds in which no new investment money is accepted into the fund. New investors invest by buying existing shares, and investors in the fund liquidate by selling their shares to other investors. A mutual fund is a comingled investment pool in which investors in the fund each have a pro-rata claim on the income and value of the fund. SWFs do not pool investment money from individual investors and institutions, and they are not traded.\nC Incorrect because sovereign wealth funds (SWFs) are government-owned investment funds or entities that invest in financial or real assets. In order to meet their long-term return objectives, SWFs invest in a wide range of real and financial assets or in alternative investments. The name \"sovereign\" wealth funds refers to the funds' ownership rather than their permitted investments."},
  {"num": 58, "subject": "组合管理", "question": "Which of the following funds is most likely to trade at a price furthest from its net asset value?", "options": {"A": "Exchange-traded fund", "B": "Open-end mutual fund", "C": "Closed-end mutual fund"}, "answer": "C", "explanation": "A Incorrect because in practice, the market price of the ETF is likely to be close to the net asset value of the underlying investments.\nB Incorrect because in an open-end mutual fund new shares are created and sold at the current net asset value per share.\nC Correct because in a closed-end mutual fund the number of outstanding shares does not change. One consequence of this fixed share base is that, unlike open-end funds in which new shares are created and sold at the current net asset value per share, closed-end funds can sell for a premium or discount to net asset value depending on the demand for the shares."},
  {"num": 59, "subject": "组合管理", "question": "Which of the following sections of an investment policy statement (IPS) most likely explains how and when the IPS should be reviewed?", "options": {"A": "Procedures", "B": "Investment Guidelines", "C": "Statement of Duties and Responsibilities"}, "answer": "A", "explanation": "A Correct because the IPS should be reviewed on a regular basis to ensure that it remains consistent with the client's circumstances and requirements. The IPS should also be reviewed if the manager becomes aware of a material change in the client's circumstances, or on the initiative of the client when his or her objectives, time horizon, or liquidity needs change. The major components of an IPS include the following section: Procedures. This section explains the steps to take to keep the IPS current and the procedures to follow to respond to various contingencies.\nB Incorrect because the Investment Guidelines section of the investment policy statement (IPS) provides information about how policy should be executed (e.g., on the permissible use of leverage and derivatives) and on specific types of assets excluded from investment, if any. Information about how and when the IPS should be reviewed can be found in the Procedures section.\nC Incorrect because the Statement of Duties and Responsibilities section of the investment policy statement (IPS) details the duties and responsibilities of the client, the custodian of the client's assets, and the investment managers. While this section may outline who is responsible for reviewing the IPS, information about how and when the IPS should be reviewed is more likely to be found in the Procedures section."},
  {"num": 60, "subject": "组合管理", "question": "Which of the following is most likely a legal and regulatory constraint in an investment policy statement?", "options": {"A": "A pension fund's decision to limit investments in real estate", "B": "A taxable investor's requirement to avoid investments in securities generating interest income", "C": "A public company director's restriction on trading the company's stock shortly before the publication of financial results"}, "answer": "C", "explanation": "A Incorrect because there is no indication that the pension fund's decision to constrain investments in real estate is driven by legal and regulatory factors. Moreover, the word 'decision' highlights that it is not an external requirement, which would be the case if it was required by law or regulation.\nB Incorrect because this constraint is driven by economic considerations of the client, and thus would be reflected in the tax concerns section of the IPS, and not in the legal and regulatory constraints. In many cases, the portfolio should reflect the tax status of the client. For example, a taxable investor may wish to hold a portfolio that emphasizes capital gains and receives little income.\nC Correct because when an individual has access to material nonpublic information about a particular security, this situation may also form a [legal and regulatory] constraint. For example, the directors of a public company may need to refrain from trading the company's stock at certain points of the year before financial results are published. The IPS should note this constraint so that the portfolio manager does not inadvertently trade the stock on the client's behalf."},
  {"num": 61, "subject": "组合管理", "question": "Which of the following sections of an investment policy statement most likely provides guidance on obtaining feedback on investment results?", "options": {"A": "Investment Guidelines", "B": "Evaluation and Review", "C": "Statement of Duties and Responsibilities"}, "answer": "B", "explanation": "A Incorrect because the Investment Guidelines section provides information about how policy should be executed (e.g., on the permissible use of leverage and derivatives) and on specific types of assets excluded from investment, if any.\nB Correct because the Evaluation and Review section provides guidance on obtaining feedback on investment results.\nC Incorrect because the Statement of Duties and Responsibilities details the duties and responsibilities of the client, the custodian of the client’s assets, and the investment managers."},
  {"num": 62, "subject": "组合管理", "question": "With respect to an investment policy statement, which of the following is most closely linked to the client’s distinctive needs?", "options": {"A": "The evaluation and review section", "B": "The objectives and constraints sections", "C": "The statement of duties and responsibilities"}, "answer": "B", "explanation": "A Incorrect because the Evaluation and Review section provides guidance on obtaining feedback on investment results.\nB Correct because the sections that are most closely linked to the client’s distinctive needs, and probably the most important from a planning perspective, are those dealing with investment objectives and constraints. An IPS [investment policy statement] focusing on these two elements has been called an IPS in an ‘objectives and constraints’ format.\nC Incorrect because the Statement of Duties and Responsibilities details the duties and responsibilities of the client, the custodian of the client’s assets, and the investment managers."},
  {"num": 63, "subject": "组合管理", "question": "Which of the following most likely affects a client’s ability to take risk? The client’s:", "options": {"A": "utility function", "B": "degree of risk aversion", "C": "level of wealth relative to liabilities"}, "answer": "C", "explanation": "A Incorrect because the client’s utility function affects their willingness, not ability, to take risk. Utility is a measure of relative satisfaction from consumption of various goods and services or in the case of investments, the satisfaction that an investor derives from different portfolios.\nB Incorrect because the client’s degree of risk aversion affects their willingness, not ability, to take risk. Risk attitude, or willingness to take risk, is a more subjective factor based on the client’s psychology.\nC Correct because the ability to bear risk is measured mainly in terms of objective factors, such as time horizon, expected income, and the level of wealth relative to liabilities."},
  {"num": 64, "subject": "组合管理", "question": "The risk–return profile of a portfolio's strategic asset allocation is most likely determined by the expected returns and risks of the individual asset classes and the:", "options": {"A": "correlations between those asset classes.", "B": "use of security selection for each of those asset classes.", "C": "allowable deviation of portfolio weights from policy weights for those asset classes."}, "answer": "A", "explanation": "A Correct because the risk–return profile of the strategic asset allocation depends on the expected returns and risks of the individual asset classes, as well as the correlation between those asset classes.\nB Incorrect because the risk–return profile of the strategic asset allocation depends on the expected returns and risks of the individual asset classes, as well as the correlation between those asset classes. Deciding to deviate from policy weights or to select securities aiming to beat the benchmark creates additional uncertainty about returns. This risk is over and above the risk inherent in the policy portfolio. Hence, an investment policy should set risk limits and desired payoffs for each of these activities. Risk budgeting implies that the portfolio manager has to choose, for every asset class, whether to deploy security selection as a return generator. Although security selection could impact the returns of a portfolio, the risk–return profile of a portfolio's strategic asset allocation is based on expected returns for the asset classes and the correlation between those asset classes rather than the additional risk associated with the use of security selection.\nC Incorrect because the risk–return profile of the strategic asset allocation depends on the expected returns and risks of the individual asset classes, as well as the correlation between those asset classes. As the portfolio is constructed and its value changes with the returns of the asset classes and securities in which it is invested, the weights of the asset classes will gradually deviate from the policy weights in the strategic asset allocation. This process is referred to as drift. Periodically, or when a certain threshold deviation from the policy weight (the bandwidth) has been breached, the portfolio should be rebalanced back to the policy weights. The set of rules that guide the process of restoring the portfolio's original exposures to systematic risk factors is known as the rebalancing policy. Deciding to deviate from policy weights or to select securities aiming to beat the benchmark creates additional uncertainty about returns. This risk is over and above the risk inherent in the policy portfolio. Although the weights of asset classes will deviate over time, the risk–return profile of a portfolio's strategic asset allocation is not determined by the rebalancing policy."},
  {"num": 65, "subject": "组合管理", "question": "When defining asset classes for a strategic asset allocation, which of the following pairwise correlations between asset class returns is most preferable?", "options": {"A": "0.0", "B": "0.5", "C": "1.0"}, "answer": "A", "explanation": "A Correct because when defining asset classes, a number of criteria apply. Intuitively, an asset class should contain relatively homogeneous assets while providing diversification relative to other asset classes. In statistical terms, risk and return expectations should be similar and paired correlations of assets should be relatively high within an asset class but should be lower versus assets in other asset classes. A between asset class correlation of zero would indicate better defined asset classes than higher correlations would.\nB Incorrect because when defining asset classes, a number of criteria apply. Intuitively, an asset class should contain relatively homogeneous assets while providing diversification relative to other asset classes. In statistical terms, risk and return expectations should be similar and paired correlations of assets should be relatively high within an asset class but should be lower versus assets in other asset classes. A between asset class correlation of 0.5 would indicate less well defined asset classes than a zero correlation would.\nC Incorrect because when defining asset classes, a number of criteria apply. Intuitively, an asset class should contain relatively homogeneous assets while providing diversification relative to other asset classes. In statistical terms, risk and return expectations should be similar and paired correlations of assets should be relatively high within an asset class but should be lower versus assets in other asset classes. A between asset class correlation of 1.0 would indicate less well defined asset classes than a zero correlation would. A candidate may choose this response if they confuse the criteria for correlation across asset classes with the criteria for correlation within each asset class (which should be high)."},
  {"num": 66, "subject": "组合管理", "question": "Which of the following sections of an investment policy statement for a pension plan most likely specifies the discretion that portfolio managers have with respect to executing the investment strategy?", "options": {"A": "Procedures", "B": "Investment Constraints", "C": "Statement of Duties and Responsibilities"}, "answer": "C", "explanation": "A Incorrect because the Procedures section explains the steps to take to keep the IPS current and the procedures to follow to respond to various contingencies.\nB Incorrect because the Investment Constraints section presents the factors that constrain the client in seeking to achieve the investment objectives. The constraints section covers factors that need to be taken into account when constructing a portfolio for the client that meets the objectives. The typical categories are liquidity requirements, time horizon, regulatory requirements, tax status, and unique needs. The constraints may be internal (i.e., set by the client), or external (i.e., set by law or regulation).\nC Correct because the Statement of Duties and Responsibilities section details the duties and responsibilities of the client, the custodian of the client’s assets, and the investment managers. In the case of an institution, such as a pension plan or university endowment, the IPS may set out the governance arrangements that apply to the investment funds. For example, this information could cover the investment committee’s approach to appointing and reviewing investment managers for the portfolio, and the discretion that those managers have."},
  {"num": 67, "subject": "组合管理", "question": "Information regarding the permissible use of derivatives in a portfolio is most likely found in which of the following sections of an investment policy statement?", "options": {"A": "Procedures", "B": "Investment Guidelines", "C": "Statement of Duties and Responsibilities"}, "answer": "B", "explanation": "A Incorrect because the Procedures section of an Investment Policy Statement (IPS) explains the steps to take to keep the IPS current and the procedures to follow to respond to various contingencies. Information regarding the permissible use of derivatives is included under Investment Guidelines.\nB Correct because the Investment Guidelines section of an Investment Policy Statement (IPS) provides information about how policy should be executed (e.g., on the permissible use of leverage and derivatives) and on specific types of assets excluded from investment, if any.\nC Incorrect because the Statement of Duties and Responsibilities section of an Investment Policy Statement (IPS) details the duties and responsibilities of the client, the custodian of the client's assets, and the investment managers. Information regarding the permissible use of derivatives is included under Investment Guidelines."},
  {"num": 68, "subject": "组合管理", "question": "A client's time horizon is most appropriately used by an investment adviser to determine the client's:", "options": {"A": "risk attitude.", "B": "ability to take risk.", "C": "willingness to take risk."}, "answer": "B", "explanation": "A Incorrect because the willingness to take risk, or risk attitude, is a more subjective factor based on the client’s psychology and perhaps also his or her current circumstances.\nB Correct because the ability to bear risk is measured mainly in terms of objective factors, such as time horizon, expected income, and the level of wealth relative to liabilities.\nC Incorrect because the willingness to take risk, or risk attitude, is a more subjective factor based on the client’s psychology and perhaps also his or her current circumstances."},
  {"num": 69, "subject": "组合管理", "question": "Which of the following is most accurate regarding an investment policy statement (IPS)?", "options": {"A": "Policies on sustainable investing require a separate IPS.", "B": "Investment constraints can be determined by the client or by the law.", "C": "Clients can specify different spending goals, but each goal must have the same risk tolerance and return objective."}, "answer": "B", "explanation": "A Incorrect because although the IPS is sometimes complemented by a document outlining policy on sustainable investing policies on sustainable investing may also be integrated within the IPS itself. In the remainder of this reading, the integration of sustainable investing within the IPS will be our working assumption.\nB Correct because the constraints may be internal (i.e., set by the client), or external (i.e., set by law or regulation).\nC Incorrect because as part of their financial planning, clients may specify specific spending goals, each of which could have different risk tolerance and return objectives."},
  {"num": 70, "subject": "组合管理", "question": "When defining asset classes, the paired correlations of assets within an asset class should be:", "options": {"A": "negative.", "B": "zero.", "C": "positive."}, "answer": "C", "explanation": "A Incorrect because when defining asset classes paired correlations of assets should be relatively high within an asset class.\nB Incorrect because when defining asset classes paired correlations of assets should be relatively high within an asset class.\nC Correct because when defining asset classes an asset class should contain relatively homogeneous assets and paired correlations of assets should be relatively high within an asset class."},
  {"num": 71, "subject": "组合管理", "question": "Which of the following statements about asset allocation is most accurate?", "options": {"A": "Investors should diversify their wealth between asset classes in order to eliminate systematic risk.", "B": "Investors with a below-average risk tolerance should have an above-average weight in alternative investments.", "C": "Adding asset classes with a low correlation to existing asset classes improves an investor's risk–return trade-off."}, "answer": "C", "explanation": "A Incorrect because systematic risk is risk related to the economic system (e.g., risk related to business cycle) that cannot be eliminated by holding a diversified portfolio. Thus, dividing wealth between asset classes cannot eliminate the systematic risk.\nB Incorrect because investors with below-average risk tolerance should have below-average weights in alternative investments. Typically, the strategic asset allocation for risk-averse investors will have a large weight in government bonds and cash, whereas those with more willingness and ability to take risk will have more of their assets in risky asset classes, such as equities and many types of alternative investments.\nC Correct because in general, adding assets classes with low correlation improves the risk–return trade-off (more return for similar risk)."},
  {"num": 72, "subject": "组合管理", "question": "An adviser gathers the following information about a client's retirement income needs:\nThe current balance of the client's retirement fund is $150,000.\nThe client plans to retire in 15 years' time.\n$500,000 in today's money is needed to fund retirement.\nNo further retirement fund contributions will be made.\nInflation is expected to average 2% per year over the next 15 years. Based only on the above information and ignoring taxes, the minimum annual rate of return required to meet the client's retirement income objective is closest to:", "options": {"A": "6.2%.", "B": "8.4%.", "C": "10.5%."}, "answer": "C", "explanation": "A Incorrect because it adjusts for inflation in the wrong direction, i.e. it assumes that, in order to reach $500,000 in 15 years' time, we must equate $500,000 to $150,000 × 1.0215 × (1 + r)15, which yields: r = [$500,000/($150,000 × 1.0215)]1/15 – 1 = 0.062 = 6.2%. Alternatively, after calculating the nominal return via $150,000(1 + r)15 = $500,000, it then adjusts for inflation by subtracting, rather than adding, the expected inflation rate from the nominal rate; [$500,000/$150,000]1/15 – 1 – 0.02 = 8.4% – 2.0% = 6.4%, which is closest to this response.\nB Incorrect because it does not take into account the effect of inflation on the individual's retirement income needs. In other words, it assumes that the portfolio needs to grow to at least $500,000 in 15 years' time, rather than to this amount adjusted upward for inflation. Hence, the minimum required rate of return, r, satisfies $150,000(1 + r)15 = $500,000, giving r = [$500,000/$150,000]1/15 – 1 = 0.084 = 8.4%. Calculator solution: N = 15; PV = –150,000; FV = 500,000; compute I/Y = 8.4%.\nC Correct because, at 2% annual inflation, $500,000 in today's money equates to $500,00(1.02)15 = $672,934 in 15 years' time. Since no further contributions to the retirement fund will be made, the current savings of $150,000 must grow to at least $672,934 in 15 years' time to meet the individual's retirement income objective. Hence, the minimum required rate of return, r, satisfies $150,000(1 + r)15 = $672,934, giving r = [$672,934/$150,000]1/15 – 1 = 0.105 = 10.5%. Calculator solution: (1) N = 15; I/Y = 2%; PV = –500,000; compute FV = 672,934. (2) N = 15; PV = –150,000; FV = 672,934; compute I/Y = 10.5%."},
  {"num": 73, "subject": "组合管理", "question": "An investor has a 15-year time horizon but needs to withdraw funds from her portfolio in one year's time to pay for tuition fees. Which of the following investments is most suitable to cover the investor's liquidity requirement due to the tuition fees?", "options": {"A": "Commercial paper", "B": "Private equity securities", "C": "Large-capitalization stocks"}, "answer": "A", "explanation": "A Correct because, although the investor has a time horizon of 15 years, she has liquidity needs in one year. When the client does have such a requirement, the manager should allocate part of the portfolio to cover the liability. This part of the portfolio will be invested in assets that are liquid—that is, easily converted to cash—and low risk at the point in time the liquidity need is actually present (e.g., a bond maturing at the time when private education expenses will be incurred), so that their value is known with reasonable certainty. Commercial paper is a short-term, negotiable, unsecured promissory note that represents a debt obligation of the issuer. Thus, commercial paper being a short-term investment, it is more suitable compared to private equity and large-capitalization stocks to be included in the portion of the investor's portfolio that has the short-term liquidity need.\nB Incorrect because, although the investor has a time horizon of 15 years, she has liquidity needs in one year. When the client does have such a requirement, the manager should allocate part of the portfolio to cover the liability. This part of the portfolio will be invested in assets that are liquid—that is, easily converted to cash—and low risk at the point in time the liquidity need is actually present (e.g., a bond maturing at the time when private education expenses will be incurred), so that their value is known with reasonable certainty. Private equity securities are not listed on public exchanges and have no active secondary market. They are issued primarily to institutional investors via non-public offerings, such as private placements. Being illiquid, they are not suitable to be included in the portion of the client's portfolio that has the short-term liquidity need.\nC Incorrect because, although the investor has a time horizon of 15 years, she has liquidity needs in one year. When the client does have such a requirement, the manager should allocate part of the portfolio to cover the liability. This part of the portfolio will be invested in assets that are liquid—that is, easily converted to cash—and low risk at the point in time the liquidity need is actually present (e.g., a bond maturing at the time when private education expenses will be incurred), so that their value is known with reasonable certainty. Thus, large-capitalization stocks, being a more volatile investment than commercial paper, would be less suitable to be included in the portion of the investor's portfolio that has the short-term liquidity need."},
  {"num": 74, "subject": "组合管理", "question": "Which of the following characteristics is most likely used to determine an investor's ability to take risk? The investor's:", "options": {"A": "risk attitude.", "B": "self-confidence.", "C": "years until retirement."}, "answer": "C", "explanation": "A Incorrect because risk attitude, or willingness to take risk, is a more subjective factor based on the client's psychology and perhaps also his or her current circumstances. Risk attitude is an investor's willingness to take risk, not the investor's ability to take risk.\nB Incorrect because risk attitude, or willingness to take risk, is a more subjective factor based on the client's psychology and perhaps also his or her current circumstances. Although the list of factors that are related to an individual's risk attitude remains open to debate, it is believed that some psychological factors, such as personality type, self-esteem, and inclination to independent thinking, are correlated with risk attitude. Self-confidence is therefore associated with an investor's willingness to take risk, not the investor's ability to take risk.\nC Correct because the ability to bear risk is measured mainly in terms of objective factors, such as time horizon, For example, an investor with a 20-year time horizon can be considered to have a greater ability to bear risk, other things being equal, than an investor with a 2-year horizon."},
  {"num": 75, "subject": "组合管理", "question": "With regard to an investment policy statement, which of the following statements about return objectives is most accurate?", "options": {"A": "A return objective cannot be a required rate of return.", "B": "Return objectives must be set independent of risk objectives.", "C": "When setting a relative return objective, a good benchmark should be investable."}, "answer": "C", "explanation": "A Incorrect because a return objective can be a required rate of return. The return objective could be a required return—that is, the amount the investor needs to earn to meet a particular future goal—such as a certain level of retirement income.\nB Incorrect because the return objective must be consistent with the client's risk objective (high expected returns are unlikely to be possible without high levels of risk).\nC Correct because a benchmark is used as a relative return objective and a good benchmark should be investable."},
  {"num": 76, "subject": "组合管理", "question": "Which of the following actions best describes tactical asset allocation?", "options": {"A": "Providing exposure to different asset classes to meet long-term objectives", "B": "Underweighting an asset class relative to the policy weight for that asset class", "C": "Overweighting specific securities with higher expected returns than the benchmark"}, "answer": "B", "explanation": "A Incorrect because tactical asset allocation refers to the decision to deliberately deviate from the policy exposure to systematic risk factors. It does not refer to investing in various asset classes as a way of meeting long-term objectives. Tactical asset allocation is the decision to deliberately deviate from the policy exposure to systematic risk factors (i.e., the policy weights of asset classes) with the intent to add value based on forecasts of the near-term returns of those asset classes.\nB Correct because tactical asset allocation is the decision to deliberately deviate from the policy exposure to systematic risk factors (i.e., the policy weights of asset classes) with the intent to add value based on forecasts of the near-term returns of those asset classes. Investing less in one asset class, for example, compared to the policy weight for that asset class is, therefore, a tactical asset allocation decision.\nC Incorrect because the decision to invest more in securities with higher expected return than the asset class benchmark is called security selection, not tactical asset allocation. Security selection is an attempt to generate higher returns than the asset class benchmark by selecting securities with a higher expected return."},
  {"num": 77, "subject": "组合管理", "question": "With respect to portfolio construction, the decision to deliberately deviate from the policy exposures to systematic risk factors with the intent to add value based on forecasts of near-term returns of asset classes best describes:", "options": {"A": "risk budgeting.", "B": "security selection.", "C": "tactical asset allocation."}, "answer": "C", "explanation": "A Incorrect because risk budgeting is the process of deciding on the amount of risk to assume in a portfolio (the overall risk budget), and subdividing that risk over the sources of investment return (e.g., strategic asset allocation, tactical asset allocation, and security selection).\nB Incorrect because security selection is an attempt to generate higher returns than the asset class benchmark by selecting securities with a higher expected return.\nC Correct because tactical asset allocation is the decision to deliberately deviate from the policy exposures to systematic risk factors (i.e., the policy weights of asset classes) with the intent to add value based on forecasts of the near-term returns of those asset classes."},
  {"num": 78, "subject": "组合管理", "question": "A change in an investor's risk aversion most likely results in a change in the investor's:", "options": {"A": "efficient frontier only.", "B": "indifference curves only.", "C": "efficient frontier and indifference curves."}, "answer": "B", "explanation": "A Incorrect because capital market expectations, specified in asset classes' expected returns, standard deviations of return, and correlations, translate into an efficient frontier of portfolios. As long as capital market expectations do not change, the efficient frontier does not move.\nB Correct because both the efficient frontier and a range of indifference curves can be plotted in the risk–return space. The point where the efficient frontier intersects with the indifference curve with the highest utility attainable (i.e., the point of tangency) represents the optimal asset allocation for the client/investor. Should investment objectives or constraints change, the indifference curves will change their shape and location. This change will move the point of tangency, and hence change the asset allocation. An investor's level of risk aversion determines the slope of the indifference curves. The most risk-averse investor has an indifference curve with the greatest slope. The least risk-averse investor has an indifference curve with the least slope.\nC Incorrect because capital market expectations, specified in asset classes' expected returns, standard deviations of return, and correlations, translate into an efficient frontier of portfolios. As long as capital market expectations do not change, the efficient frontier does not move."},
  {"num": 79, "subject": "组合管理", "question": "If the weights of the asset classes in a portfolio deviate from the policy weights over time due to changes in market value, this is best described as:", "options": {"A": "drift.", "B": "value at risk.", "C": "tracking error."}, "answer": "A", "explanation": "A Correct because as the portfolio is constructed and its value changes with the return of the asset classes and securities in which it is invested, the weights of the asset classes will gradually deviate from the policy weights in the strategic asset allocation. This process is referred to as drift.\nB Incorrect because value at risk is a money measure of the minimum value of losses expected during a specified time period at a given level of probability.\nC Incorrect because tracking risk (sometimes called tracking error) is the standard deviation of the differences between a portfolio's returns and its benchmark's returns."},
  {"num": 80, "subject": "组合管理", "question": "An IPS most likely specifies:", "options": {"A": "only the tactical asset allocation target.", "B": "only the strategic asset allocation target.", "C": "both the tactical and the strategic asset allocation targets."}, "answer": "B", "explanation": "A Incorrect because tactical asset allocation is the decision to deliberately deviate from the policy exposures to systematic risk factors (i.e., the policy weights of asset classes) with the intent to add value based on forecasts of the near- term returns of those asset classes. Thus, tactical asset allocation is a deviation from the set of exposures to asset classes expected to achieve the investor's long-term objectives (strategic asset allocation) in an attempt to add value on a short-term basis. Although an IPS may allow for the use of tactical asset allocation by providing ranges of asset class exposure, the tactical asset allocation, by definition, is a deviation from the specified asset allocation target, not the target itself.\nB Correct because once the IPS has been compiled, the investment manager can construct a suitable portfolio. Strategic asset allocation is a traditional focus of the first steps in portfolio construction. The strategic asset allocation (SAA) is the set of exposures to IPS-permissible asset classes that is expected to achieve the client's long-term objectives given the client's investment constraints. Said differently, the investment policy statement (IPS) permits investments in targeted proportions of the portfolio in various asset classes (set of exposures to IPS-permissible asset classes). Investment in these asset classes in the set proportions are expected to achieve the long-term risk and return objectives of the portfolio.\nC Incorrect because tactical asset allocation is the decision to deliberately deviate from the policy exposures to systematic risk factors (i.e., the policy weights of asset classes) with the intent to add value based on forecasts of the near- term returns of those asset classes. Thus, tactical asset allocation is a deviation from the set of exposures to asset classes expected to achieve the investor's long-term objectives (strategic asset allocation) in an attempt to add value on a short-term basis. Although an IPS may allow for the use of tactical asset allocation by providing ranges of asset class exposure, the tactical asset allocation, by definition, is a deviation from the specified asset allocation target, not the target itself."},
  {"num": 81, "subject": "组合管理", "question": "A portfolio manager's decision to temporarily invest more in equities than the policy weights prescribe is best described as:", "options": {"A": "security selection.", "B": "tactical asset allocation.", "C": "strategic asset allocation."}, "answer": "B", "explanation": "A Incorrect because security selection is an attempt to generate higher returns than the asset class benchmark by selecting securities with a higher expected return. For example, an investment manager may decide to add more IBM stock in his portfolio than the weight in his equity benchmark if he expects this stock to do better than the benchmark. Hence, security selection corresponds to deviations from weights of securities within an asset class, not deviations from the policy weight of the entire asset class.\nB Correct because tactical asset allocation is the decision to deliberately deviate from the policy exposures to systematic risk factors (i.e., the policy weights of asset classes) with the intent to add value based on forecasts of the near-term returns of those asset classes. For instance, an investor may decide to temporarily invest more of the portfolio in equities than the SAA (strategic asset allocation) prescribes if the investor anticipates that equities will deliver a higher return over the short term than other asset classes.\nC Incorrect because a strategic asset allocation (SAA) is the set of exposures to IPS-permissible asset classes that is expected to achieve the client's long-term objectives given the client's investment constraints. The SAA effectively defines the policy weights of a portfolio, and deliberate deviations from these weights would be classed as tactical, not strategic, asset allocation."},
  {"num": 82, "subject": "组合管理", "question": "An asset manager evaluates the risk tolerance of three investors:\nWhich investor most likely has the highest overall risk tolerance?", "options": {"A": "Investor 1", "B": "Investor 2", "C": "Investor 3"}, "answer": "A", "explanation": "A Correct because the prudent approach is to reach a conclusion about risk tolerance consistent with the lower of the two factors (ability and willingness). Therefore, Investor 1 has average risk tolerance, while the other two investors have below-average risk tolerance.\nB Incorrect because a client's overall risk tolerance is a function of the client's ability to bear (accept) risk and his or her ‘risk attitude,' which might be considered as the client's willingness to take risk. Risk tolerance is not determined by the ability to take risk alone, which is highest for Investor 2.\nC Incorrect because a client's overall risk tolerance is a function of the client's ability to bear (accept) risk and his or her ‘risk attitude,' which might be considered as the client's willingness to take risk. Risk tolerance is not determined by the willingness to take risk alone, which is highest for Investor 3."},
  {"num": 83, "subject": "组合管理", "question": "Which of the following is most likely a consequence of the illusion of control bias?", "options": {"A": "An investor's portfolio turnover is too low.", "B": "The investor's portfolio contains concentrated positions in companies.", "C": "An investor uses a simple forecasting model for portfolio construction."}, "answer": "B", "explanation": "A Incorrect because as a result of illusion of control bias, FMPs [financial market participants] may trade more than is prudent. Researchers have found that portfolio turnover is negatively correlated with investment returns.\nB Correct because as a result of illusion of control bias, FMPs [financial market participants] may inadequately diversify portfolios. Research has found that some investors prefer to invest in companies that they feel they have control over, such as the companies they work for, leading them to hold concentrated positions.\nC Incorrect because as a result of illusion of control bias, FMPs [financial market participants] may construct financial models and forecasts that are overly detailed. FMPs may require detailed models before making an investment decision, believing that forecasts from these models control uncertainty. Although a greater understanding of an investment, issuer, or industry is often useful, increased model complexity does not control the inherent risk and uncertainty of investment outcomes."},
  {"num": 84, "subject": "组合管理", "question": "Which of the following best describes a potential consequence of the regret-aversion bias for financial market participants?", "options": {"A": "Engaging in herding behaviour", "B": "Borrowing excessively to finance present consumption", "C": "Misidentifying risk tolerances because of how questions about risk tolerance were framed"}, "answer": "A", "explanation": "A Correct because as a result of regret-aversion bias, FMPs [financial market participants] may engage in herding behavior. FMPs may feel safer in popular investments in order to limit potential future regret. Regret-aversion bias is an emotional bias in which people tend to avoid making decisions out of fear that the decision will turn out poorly.\nB Incorrect because it is a likely consequence of the self-control bias, and not the regret-aversion bias. As a result of self-control bias, FMPs [financial market participants] may borrow excessively to finance present consumption.\nC Incorrect because it is a likely consequence of the framing bias, and not the regret-aversion bias. As a result of framing bias, FMPs [financial market participants] may misidentify risk tolerances because of how questions about risk tolerance were framed, becoming more risk-averse when presented with a gain frame of reference and more risk-seeking when presented with a loss frame of reference."},
  {"num": 85, "subject": "组合管理", "question": "Which of the following is most likely a consequence of overconfidence bias? Investors:", "options": {"A": "holding poorly diversified portfolios.", "B": "continuing to hold classes of assets with which they are familiar.", "C": "holding investments in a loss position longer than justified, in the hope that they will return to breakeven."}, "answer": "A", "explanation": "A Correct because overconfidence bias is a bias in which people demonstrate unwarranted faith in their own abilities. As a result of overconfidence bias, FMPs [financial market participants] may hold poorly diversified portfolios, which may result in significant downside risk.\nB Incorrect because this is a potential consequence of endowment bias, not overconfidence bias. Endowment bias is an emotional bias in which people value an asset more when they own it than when they do not. Endowment bias may lead FMPs [financial market participants] to continue to hold classes of assets with which they are familiar. FMPs may believe they understand the characteristics of the investments they already own and may be reluctant to purchase assets with which they have less experience. Familiarity adds to owners’ perceived value of a security.\nC Incorrect because this is a potential consequence of loss-aversion bias, not overconfidence. As a result of loss-aversion bias, FMPs [financial market participants] may hold investments in a loss position longer than justified by fundamental analysis, in the hope that they will return to breakeven."},
  {"num": 86, "subject": "组合管理", "question": "Which of the following can best be explained by overconfidence when predicting companies' earnings growth rates?", "options": {"A": "Base-rate neglect", "B": "The value anomaly", "C": "The disposition effect"}, "answer": "B", "explanation": "A Incorrect because, in base-rate neglect, a phenomenon's rate of incidence in a larger population—its base rate—is neglected in favor of specific information. The specific, individual information may be misleading relative to the more appropriate base rate or general information. Base-rate neglect is connected to representativeness bias and not overconfidence, nor does it relate to earnings growth rates.\nB Correct because a number of other studies have offered behavioral explanations for value anomalies, presenting the anomalies as mispricing rather than compensation for increased risk. These studies recognize the emotional factors involved in appraising stocks. Overconfidence can also be involved in predicting growth rates, potentially leading growth stocks to be overvalued, leading to the value anomaly.\nC Incorrect because an important concept embedded in this utility representation is what has been termed the disposition effect: the holding of investments that have experienced losses too long, and the selling of investments that have experienced gains too quickly (i.e., holding on to losers and selling winners). The disposition effect does not relate to prediction errors, nor to earnings growth rates."},
  {"num": 87, "subject": "组合管理", "question": "Holding on to losers for too long and selling winners too quickly best characterizes which of the following?", "options": {"A": "Hindsight bias", "B": "Disposition effect", "C": "Anchoring and adjustment bias"}, "answer": "B", "explanation": "A Incorrect because hindsight bias refers to the belief that past actions were predictable rather than a current fear of accepting losses. Hindsight bias refers to believing past events as having been predictable and reasonable to expect. This behavior results from the obvious fact that outcomes that did occur are more readily evident than outcomes that did not. Similarly, people tend to remember their own predictions of the future as more accurate than they actually were because they are biased by the knowledge of what actually occurred. Poorly reasoned decisions with positive results may be remembered as brilliant tactical moves, and poor results of well-reasoned decisions may be described as avoidable mistakes.\nB Correct because the disposition effect pertains to loss-aversion bias. Loss-aversion bias refers to the tendency to strongly prefer avoiding losses to achieving gains. Rational FMPs (financial market participants) should accept more risk to increase gains, not to mitigate losses. Loss aversion leads FMPs to hold their losers to avoid recognizing losses and sell their winners to lock in profits. An important concept is what has been termed the disposition effect: the holding of investments that have experienced losses too long, and the selling of investments that have experienced gains too quickly (i.e., holding on to losers and selling winners).\nC Incorrect because anchoring and adjustment bias pertains to rigidity to an original estimate, not a fear of accepting losses. Anchoring and adjustment bias refers to relying on an initial piece of information to make subsequent estimates, judgments, and decisions. When required to estimate a value with unknown magnitude, people generally begin with some initial default number—an 'anchor'—which they then adjust up or down. Regardless of how the initial anchor was chosen, people tend to adjust their anchors insufficiently and produce end approximations that are, consequently, biased. Anchoring and adjustment bias is closely related to conservatism bias."},
  {"num": 88, "subject": "组合管理", "question": "Which of the following tendencies of financial market participants is most likely a consequence of endowment bias?", "options": {"A": "Engaging in herding behavior", "B": "Saving insufficiently for the future", "C": "Continuing to hold classes of assets with which they are familiar"}, "answer": "C", "explanation": "A Incorrect because it is a consequence of regret-aversion bias, not endowment bias. FMPs (financial market participants) may engage in herding behavior. FMPs may feel safer in popular investments in order to limit potential future regret. It seems safe to be with the crowd, and a reduction in potential emotional pain is perceived. Regret aversion may lead to preference for stocks of well-known companies even in the face of equal risk and return expectations. Choosing the stocks of less-familiar companies is perceived as riskier and involves more personal responsibility and greater potential for regret.\nB Incorrect because it is a consequence of self-control bias, not endowment bias. As a result of self-control bias, FMPs (financial market participants) may save insufficiently for the future, which may, in turn, result in accepting too much risk in portfolios in an attempt to generate higher returns.\nC Correct because endowment bias may lead FMPs (financial market participants) to do the following: Continue to hold classes of assets with which they are familiar. FMPs may believe they understand the characteristics of the investments they already own and may be reluctant to purchase assets with which they have less experience. Familiarity adds to owners’ perceived value of a security."},
  {"num": 89, "subject": "组合管理", "question": "Which of the following biases most likely contributes to the momentum effect in financial markets?", "options": {"A": "Availability", "B": "Status quo", "C": "Prediction overconfidence"}, "answer": "A", "explanation": "A Correct because momentum can be partly explained by availability, hindsight, and loss aversion biases. Studies have identified faulty learning models within traders, in which reasoning is based on their recent experience. Behaviorally, this is availability bias. In this context, availability bias is also called the recency effect, which is the tendency to recall recent events more vividly and give them undue weight. In such models, if the price of an asset rises for a period of time, investors may simply extrapolate this rise to the future.\nB Incorrect because status quo bias is an emotional bias in which people choose to do nothing (i.e., maintain the 'status quo') instead of making a change, even when change is warranted. However, momentum can be partly explained by availability, hindsight, and loss aversion biases.\nC Incorrect because overconfidence bias has two forms: prediction overconfidence and certainty overconfidence. Both types demonstrate faulty reasoning combined with “gut feel” and hope. Prediction overconfidence occurs when the confidence intervals that FMPs (Financial Market Participants) assign to their investment predictions are too narrow. For example, when estimating the future value of a stock, overconfident FMPs will incorporate far too little variation—using a narrower range of expected payoffs and a lower standard deviation of returns—than justified by historical results and fundamental analysis. However, momentum can be partly explained by availability, hindsight, and loss aversion biases."},
  {"num": 90, "subject": "组合管理", "question": "Which of the following statements about emotional biases is most accurate?", "options": {"A": "They arise through conscious effort", "B": "They are caused by faulty cognitive reasoning", "C": "They are more difficult to correct than cognitive biases"}, "answer": "C", "explanation": "A Incorrect because emotional biases arise spontaneously rather than through conscious effort and may even be undesired to the individual feeling them.\nB Incorrect because in general, behavioral biases come in two forms: faulty cognitive reasoning, known as cognitive errors, and those based on feelings or emotions, known as emotional biases.\nC Correct because cognitive errors can often be corrected or eliminated through better information, education, and advice. Emotional biases, on the other hand, are harder to correct because they stem from impulses and intuitions."},
  {"num": 91, "subject": "组合管理", "question": "Which of the following is best classified as a non-financial risk?", "options": {"A": "Credit risk", "B": "Liquidity risk", "C": "Accounting risk"}, "answer": "C", "explanation": "A Incorrect because the second primary financial risk is credit risk. Credit risk is the risk of loss if one party fails to pay an amount owed on an obligation, such as a bond, loan, or derivative, to another party.\nB Incorrect because liquidity risk is a financial risk and defined as the risk of a significant downward valuation adjustment when selling a financial asset.\nC Correct because although most risks have monetary consequences, there are a number of risks that are typically classified as non-financial in nature. These risks arise from a variety of sources, such as the relationship between the entity and counterparties, regulators, governments, the environment, suppliers, customers, and employees. The following three non-financial risks are related: regulatory risk, accounting risk, and tax risk. They could even be collectively referred to as compliance risk because they all deal with the matter of conforming to policies, laws, rules, and regulations as set forth by governments and authoritative bodies, such as accounting governing boards."},
  {"num": 92, "subject": "组合管理", "question": "In risk management, which of the following should be taken into account when determining an enterprise’s risk tolerance?", "options": {"A": "Management compensation", "B": "The enterprise’s value at risk (VaR)", "C": "The government and regulatory landscape"}, "answer": "C", "explanation": "A Incorrect because, in the context of risk management, certain factors should not determine risk tolerance, but in many cases they do. Personal motivations, beliefs, and agendas of board members (the agency problem); company size; whether the market environment seems stable; short-term pressures; and management compensation often affect risk tolerance in ways that might not be in line with the owners’ best interests.\nB Incorrect because, in the context of risk management, risk budgeting picks up where risk tolerance leaves off. Whereas risk tolerance focuses on the appetite for risk and what is and is not acceptable, risk budgeting has a more specific focus on how that risk is taken. Risk budgeting quantifies and allocates the tolerable risk by specific metrics; it extends and guides implementation of the risk tolerance decision.\nC Correct because, in the context of risk management, factors such as a company’s goals, its expertise in certain areas, and its strategies will help a board determine which risks the company may pursue and with how much intensity. The government and regulatory landscape is important too, both in their ex ante demands on how companies approach risk and in the likely ex post reaction in the event of disasters."},
  {"num": 93, "subject": "组合管理", "question": "The risk management measure that captures the sensitivity of a derivative’s delta to a change in the value of the underlying best describes:", "options": {"A": "rho.", "B": "vega.", "C": "gamma."}, "answer": "C", "explanation": "A Incorrect because derivatives are also sensitive to changes in interest rates, which are reflected in a measure called rho.\nB Incorrect because vega is a first-order measure of the change in the derivative price for a change in the volatility of the underlying.\nC Correct because the sensitivity of the derivative price to a small change in the value of the underlying asset is called the delta. Large changes are captured by the concept of gamma. Whereas delta is a first-order risk, gamma is considered a second-order risk because it reflects the risk of changes in delta. Gamma is a numerical measure of how sensitive an option’s delta is to a change in the value of the underlying."},
  {"num": 94, "subject": "组合管理", "question": "A good risk management process should:", "options": {"A": "predict when a crisis will occur.", "B": "consider the balance between expected returns and losses.", "C": "only consider losses occurring from events that have a high likelihood."}, "answer": "B", "explanation": "A Incorrect because risk management is not even about predicting risks. 'The Doctrine of No Surprises' is a key mantra among many risk managers, but it does not mean they are expected to predict what will happen. For example, a risk manager of a bank would not have been expected to know that a real estate crisis was going to occur and cause significant defaults on the bank's real estate securities.\nB Correct because a good risk management process would include a deep discussion at the governance level about the balance between the likely returns and the unlikely—but sizable—losses and whether such losses are tolerable.\nC Incorrect because a poor risk management process would have ignored the possibility, though small, of such a significant market event and not quantified the potential loss."},
  {"num": 95, "subject": "组合管理", "question": "A bank determines that its value at risk (VaR) is £5 million at 5% for one day. The bank is expecting a minimum loss of £5 million once every:", "options": {"A": "5 business days.", "B": "13 business days.", "C": "20 business days."}, "answer": "C", "explanation": "A Incorrect because with a probability of 5% and a measurement period of one day, we can interpret the bank’s VaR as expecting a minimum loss of £5 million once every 20 business days.\nB Incorrect because with a probability of 5% and a measurement period of one day, we can interpret the bank’s VaR as expecting a minimum loss of £5 million once every 20 business days. Based on a year with 250 to 260 business days, this should occur 12.5 to 13 times per year (roughly once per month).\nC Correct because with a probability of 5% and a measurement period of one day, we can interpret the bank’s VaR as expecting a minimum loss of £5 million once every 20 business days."},
  {"num": 96, "subject": "组合管理", "question": "Which of the following metrics is most appropriate to estimate a bond's average extreme loss?", "options": {"A": "VaR of loss", "B": "Standard deviation of loss", "C": "Expected loss given default"}, "answer": "C", "explanation": "A Incorrect because in a VaR measure, there is no ultimate maximum that one can state. VaR is thus a minimum extreme loss metric. Thus, the average loss cannot be provided by the VaR.\nB Incorrect because a standard deviation may not exist for return distributions with fat tails. Thus, the use of standard deviation is not appropriate when estimating extreme losses.\nC Correct because the statistics used to estimate VaR can be used to gauge average extreme losses. Conditional VaR or CVaR is a common tail loss measure, defined as the weighted average of all loss outcomes in the statistical distribution that exceed the VaR loss. Another tail risk metric in the credit risk space that is analogous to CVaR is expected loss given default, which answers the question for a debt security, If the underlying company or asset defaults, how much do we lose on average?"},
  {"num": 97, "subject": "组合管理", "question": "The process of risk management is best described as the set of decisions that maximizes a company's value while:", "options": {"A": "minimizing the risk taken.", "B": "bearing a tolerable level of risk.", "C": "predicting the potential risk correctly."}, "answer": "B", "explanation": "A Incorrect because risk management is not about minimizing risk; it is about actively understanding and embracing those risks that best balance the achievement of goals with an acceptable chance of failure, quantifying the exposure, and continually monitoring and modifying it.\nB Correct because risk management is the process by which an organization or individual defines the level of risk to be taken, measures the level of risk being taken, and adjusts the latter toward the former, with the goal of maximizing the company’s or portfolio’s value.Said differently, risk management comprises all the decisions and actions needed to best achieve organizational or personal objectives while bearing a tolerable level of risk.\nC Incorrect because risk management is not even about predicting risks. 'The Doctrine of No Surprises' is a key mantra among many risk managers, but it does not mean they are expected to predict what will happen."},
  {"num": 98, "subject": "组合管理", "question": "Which of the following is best classified as a financial risk?", "options": {"A": "Tax risk", "B": "Credit risk", "C": "Accounting risk"}, "answer": "B", "explanation": "A Incorrect because tax risk is a non-financial risk as the following three non-financial risks are related: regulatory risk, accounting risk, and tax risk.\nB Correct because the risk management industry has come to classify three types of risks as primarily financial in nature and the second primary financial risk is credit risk.\nC Incorrect because accounting risk is a non-financial risk as the following three non-financial risks are related: regulatory risk, accounting risk, and tax risk."},
  {"num": 99, "subject": "组合管理", "question": "Which of the following is least consistent with effective risk governance?", "options": {"A": "Taking an enterprise-wide view", "B": "Defining the enterprise's risk tolerance", "C": "Following a bottom-up process to direct risk management activities"}, "answer": "C", "explanation": "A Incorrect because to achieve the best results for an organization, risk governance should take an enterprise-wide view.\nB Incorrect because good governance should include defining an organization’s risk tolerance and providing risk oversight.\nC Correct because risk governance is the top-down [not bottom-up] process and guidance that directs risk management activities to align with and support the overall enterprise."},
  {"num": 100, "subject": "组合管理", "question": "A benefit of risk budgeting is that it:", "options": {"A": "forces risk trade-offs.", "B": "provides risk oversight.", "C": "defines an organization’s risk tolerance."}, "answer": "A", "explanation": "A Correct because one major benefit of even the most basic risk budgeting is that it forces risk trade-offs and supports a culture in which risk is considered as a part of all key decisions.\nB Incorrect because it refers to risk governance, not risk budgeting. Good risk governance should include defining an organization’s risk tolerance and providing risk oversight. Risk budgeting picks up where risk tolerance leaves off. Whereas risk tolerance focuses on the appetite for risk and what is and is not acceptable, risk budgeting has a more specific focus on how that risk is taken.\nC Incorrect because it refers to risk governance, not risk budgeting. Good risk governance should include defining an organization’s risk tolerance and providing risk oversight. Risk budgeting picks up where risk tolerance leaves off. Whereas risk tolerance focuses on the appetite for risk and what is and is not acceptable, risk budgeting has a more specific focus on how that risk is taken."},
  {"num": 1, "subject": "职业道德", "question": "A profession is most likely described as a group of people that:", "options": {"A": "has a common level of basic knowledge about a particular subject.", "B": "monitors its members based on an agreed-on code of ethics.", "C": "puts the interests of its members first."}, "answer": "B", "explanation": "A Incorrect . A profession is based on a specialized knowledge and skills, not basic knowledge.\nB Correct . A profession is practiced by members who share and agree to adhere to a common code of ethics, and a profession is based on a specialized knowledge and skills and service to others.\nC Incorrect . A profession is based on service to others that may not necessarily mean the interests of its members come first."},
  {"num": 2, "subject": "职业道德", "question": "Most societies would least likely consider ethical principles to include:", "options": {"A": "justice.", "B": "duplicity.", "C": "diligence."}, "answer": "B", "explanation": "A Incorrect . Justice is often considered an ethical principle in most societies.\nB Correct . Most societies acknowledge the ethical principles of honesty, fairness or justice, diligence, and respect for the rights of others. Duplicity or deception would be in violation of most ethical principles.\nC Incorrect . Diligence is often considered an ethical principle in most societies."},
  {"num": 3, "subject": "职业道德", "question": "Oversight of the Professional Conduct Program is the responsibility of the:", "options": {"A": "Professional Conduct staff.", "B": "Disciplinary Review Committee.", "C": "CFA Institute Board of Governors."}, "answer": "C", "explanation": "A Incorrect because the CFA Institute Board of Governors maintains oversight and responsibility for the Professional Conduct Program (PCP), which, in conjunction with the Disciplinary Review Committee (DRC), is responsible for enforcement of the Code and Standards. The DRC is a volunteer committee of CFA charterholders who serve on panels to review conduct and partner with Professional Conduct staff to establish and review professional conduct policies.\nB Incorrect because the CFA Institute Board of Governors maintains oversight and responsibility for the Professional Conduct Program (PCP), which, in conjunction with the Disciplinary Review Committee (DRC), is responsible for enforcement of the Code and Standards. The DRC is a volunteer committee of CFA charterholders who serve on panels to review conduct and partner with Professional Conduct staff to establish and review professional conduct policies.\nC Correct because the CFA Institute Board of Governors maintains oversight and responsibility for the Professional Conduct Program (PCP), which, in conjunction with the Disciplinary Review Committee (DRC), is responsible for enforcement of the Code and Standards."},
  {"num": 4, "subject": "职业道德", "question": "Which of the following is one of the seven CFA Institute Standards of Professional Conduct?", "options": {"A": "Duties to Employers", "B": "Performance Integrity", "C": "Disclosure of Transactions"}, "answer": "A", "explanation": "A Correct because Duties to Employers is Standard IV.\nB Incorrect because Standard II is Integrity of Capital Markets not performance integrity.\nC Incorrect because Standard VI is Conflicts of Interest. It has sub-sections A. Disclosure of Conflicts and B. Priority of Transactions. Disclosure of Transactions is an incorrect combination of the two."},
  {"num": 5, "subject": "职业道德", "question": "The CFA Institute Code of Ethics (the Code) and Standards of Professional Conduct (the Standards) require members to:", "options": {"A": "encourage others to practice in a professional and ethical manner only.", "B": "promote the integrity and viability of the global capital markets for the ultimate benefit of the investment profession only.", "C": "both encourage others to practice in a professional and ethical manner and promote the integrity and viability of the global capital markets for the ultimate benefit of the investment profession."}, "answer": "A", "explanation": "A Correct because the Code of Ethics and Standards of Professional Conduct states that members of CFA Institute (including CFA charterholders) and candidates for the CFA designation (Members and Candidates) must practice and encourage others to practice in a professional and ethical manner that will reflect credit on themselves and the profession.\nB Incorrect because the Code of Ethics and Standards of Professional Conduct states that members of CFA Institute (including CFA charterholders) and candidates for the CFA designation (Members and Candidates) must promote the integrity and viability of the global capital markets for the ultimate benefit of society. Therefore, the Code of Ethics requires members to promote the integrity and viability of the global capital markets for the ultimate benefit of society, not the investment profession.\nC Incorrect because the reading on the Code of Ethics and Standards of Professional Conduct states that members and candidates must only practice and encourage others to practice in a professional and ethical manner, as described in the response rationale for the correct answer."},
  {"num": 6, "subject": "职业道德", "question": "Robin Herring, CFA, is a government bond research analyst at an independent credit rating agency. A competitor credit rating agency just downgraded the bonds of a government Herring follows. Herring notes that all of the information in the competitor’s report was covered in his analysis published last week. In the past, Herring has been slow to downgrade bonds, so he starts to doubt his own analysis after seeing the competitor’s report. Herring decides to reissue his credit rating of this government bond and match the competitor’s downgrade. In his revised report, Herring states that new information has been made available to justify the downgrade. Herring posts the revision on the credit rating agency’s website and provides it by email to all clients who received the original. Herring’s rating change least likely violated which of the following Standards?", "options": {"A": "Fair dealing", "B": "Diligence and reasonable basis", "C": "Communication with clients and prospective clients"}, "answer": "A", "explanation": "A Correct because the analyst has dealt fairly with all clients by sending them an email and posting his rating change on the credit rating agency’s website when making material changes to his prior investment recommendation; therefore, he has not violated the Standard relating to fair dealing. Clients should be treated fairly when material changes in a member’s or candidate’s prior investment recommendations are disseminated, which has been done.\nB Incorrect because the analyst does not have a reasonable or adequate basis for his downgrade, as required by the Standard relating to diligence and reasonable basis.\nC Incorrect because the analyst has used the release of a competitor’s report, contrary to his own previously published report, as a reason to revise his recommendation and has not used reasonable judgment in identifying which factors are important to his investment analyses, recommendations, or actions, as required by Standard relating to communication with clients and prospective clients."},
  {"num": 7, "subject": "职业道德", "question": "Thomas Huang, CFA, is an investment advisor for Newline Partners (NP). NP has an agreement with brokerage firm Ridge Capital (RC). Huang refers clients to RC in exchange for compensation. RC pays a cash fee to NP for referrals. Before entering into formal agreements for services, Huang makes the following disclosure to NP's clients: \"Please note that Newline Partners receives an annual cash percentage fee from Ridge Capital for the referral of clients.\" Huang omits disclosure of the estimated dollar value of the referrals. Has Huang violated the Standards?", "options": {"A": "No", "B": "Yes, by accepting a cash fee for referral of clients", "C": "Yes, by not disclosing the estimated dollar value of the fee"}, "answer": "C", "explanation": "A Incorrect because according to Standard VI(C), Referral Fees, Huang must disclose the estimated dollar value of the fee as described in the correct response rationale.\nB Incorrect because Standard VI(C), Referral Fees, allows members to accept client referral fees under certain conditions as described in the correct response rationale.\nC Correct because according to Standard VI(C), Referral Fees, members must disclose both the nature of the consideration and the estimated dollar value. Appropriate disclosure means that members and candidates must advise the client or prospective client, before entry into any formal agreement for services, of any benefit given or received for the recommendation of any services provided by the member or candidate. In addition, the member or candidate must disclose the nature of the consideration or benefit—for example, flat fee or percentage basis, one-time or continuing benefit, based on performance, benefit in the form of provision of research or other noncash benefit—together with the estimated dollar value. Consideration includes all fees, whether paid in cash, in soft dollars, or in kind."},
  {"num": 8, "subject": "职业道德", "question": "Marianne Lynn is registered for the CFA Level I exam. A few weeks after registration, she realizes that she is unable to prepare for the exam due to work commitments, so she informs CFA Institute that she declines to sit for the exam. Afterwards, shortly before the exam date, she posts on social media that she is a CFA candidate. Separately, Thomas Petrov, CFA, posts his investment views anonymously on social media and tags his post using \"#CFAcharter.\" Who has violated the Standards?", "options": {"A": "Lynn only", "B": "Petrov only", "C": "Both Lynn and Petrov"}, "answer": "C", "explanation": "A Incorrect because according to Standard VII(B), Reference to CFA Institute, the CFA Designation and the CFA Program, both have violated the Standard, as described in the response rationale of the correct answer.\nB Incorrect because according to Standard VII(B), Reference to CFA Institute, the CFA Designation and the CFA Program, both have violated the Standard, as described in the response rationale of the correct answer.\nC Correct because according to Standard VII(B), Reference to CFA Institute, the CFA Designation and the CFA Program, Petrov violates Standard VII(B) because where individuals may anonymously express their opinions, pseudonyms or online profile names created to hide a member’s identity should not be tagged with the CFA designation. Lynn violates Standard VII(B) because if an individual is registered for the CFA Program but declines to sit for an exam or otherwise does not meet the definition of a candidate as described in the CFA Institute Bylaws, then that individual is no longer considered an active candidate."},
  {"num": 9, "subject": "职业道德", "question": "Jan Loots, CFA, quit his job as a portfolio manager at an investment firm with which he had a non-solicitation agreement he signed several years ago. Loots received permission to take his investment performance history with him and also took a copy of the firm’s software-trading platform. Subsequently, Loots sent out messages on social media sites announcing he was looking for clients for his new investment management firm. Access to Loots’ social media sites is restricted to friends, family, and former clients. Loots least likely violated the CFA Institute Standards of Professional Conduct concerning his:", "options": {"A": "trading software.", "B": "non-solicitation agreement.", "C": "investment performance history."}, "answer": "C", "explanation": "A Incorrect because the portfolio manager took property of his former employer, proprietary trading software, and violated Standard IV(A)–Loyalty. Although the manager created the software himself, it was during a period of time when the large money manager employed him and the software is not his property to take.\nB Incorrect because the member violated Standard IV(A)–Loyalty as he did not act for the benefit of his former employer. In this case, the member may cause harm to his former employer if his weekend messages result in clients moving to his new business.\nC Correct because the portfolio manager received permission to use his investment performance history from his prior employer. The member violated his non-solicitation agreement by indicating his availability to new clients on several social media sites accessible by clients of his former employer. This is a violation of Standard IV(A)–Loyalty because he did not act for the benefit of his former employer. In this case, the member may cause harm to his former employer if his weekend messages result in clients moving to his new business from his former employer. The member also violated this standard by taking his employer’s property, trading software."},
  {"num": 10, "subject": "职业道德", "question": "Lisa Hajak, CFA, specialized in research on real estate companies at Cornerstone Country Bank for the past twenty years. Hajak recently started her own investment research firm, Hajak Investment Advisory. One of her former clients at Cornerstone asks Hajak to update a research report she wrote on a real estate company when she was at Cornerstone. Hajak updates the report, which she had copied to her personal computer without the bank’s knowledge, and replaces references to the bank with her new firm, Hajak Investment Advisory. Hajak also incorporates the conclusions of a real estate study conducted by the Realtors Association that appeared in the Wall Street Journal. She references the Journal as her source in her report. She provides the revised report free of charge along with a cover letter for the bank’s client to become a client of her firm. Concerning the reissued research report, Hajak least likely violated the CFA Institute Standards of Professional Conduct because she:", "options": {"A": "solicited the bank’s client.", "B": "did not obtain consent to use the bank report.", "C": "did not cite the actual source of the real estate study."}, "answer": "A", "explanation": "A Correct as soliciting the bank’s client did not violate Standard IV(A)–Loyalty because the manager is no longer an employee of the bank and there is no indication she obtained the client information from bank sources. The member, however, has violated Standard V(C)–Record Retention, because when she left the bank she took the property of the bank without express permission to do so. In addition, the analyst violated Standard I(C)–Misrepresentation by creating research materials without attribution, which is demonstrated when the manager adds to the new report a real estate study she saw in the Wall Street Journal, referencing the Journal only. In all instances, a member or candidate must cite the actual source of the information. If she does not obtain the report and review the information, the manager runs the risk of relying on second‐hand information that may misstate facts. Best practice would be either to obtain the complete study from its original author and cite only that author or to use the information provided by the intermediary and cite both sources.\nB Incorrect because according to Standard V(C)–Record Retention, when a member or candidate leaves a firm to seek other employment, the member or candidate cannot take the property of the firm, including originals or copies of supporting records of the member’s or candidate’s work, to the new employer without the express consent of the previous employer.\nC Incorrect because the analyst violated Standard I(C)–Misrepresentation by creating research materials without attribution, which is demonstrated when the manager adds to the new report a real estate study she saw in the Wall Street Journal, referencing the Journal only. In all instances, a member or candidate must cite the actual source of the information. If she does not obtain the report and review the information, the manager runs the risk of relying on second‐hand information that may misstate facts. Best practice would be to either obtain the complete study from its original author and cite only that author or to use the information provided by the intermediary and cite both sources."},
  {"num": 11, "subject": "职业道德", "question": "Amanda Covington, CFA, works for McJan Investment Management. McJan employees must receive prior clearance of their personal investments in accordance with McJan’s compliance procedures. To obtain prior clearance, McJan employees must provide a written request identifying the security, the quantity of the security to be purchased, and the name of the broker through which the transaction will be made. Pre-cleared transactions are approved only for that trading day. As indicated below, Covington received prior clearance.\nTwo days after she received prior clearance, the price of Stock B had decreased, so Covington decided to purchase 250 shares of Stock B only. In her decision to purchase 250 shares of Stock B only, did Covington violate any CFA Institute Standards of Professional Conduct?", "options": {"A": "No", "B": "Yes, relating to diligence and reasonable basis", "C": "Yes, relating to her employer’s compliance procedures"}, "answer": "C", "explanation": "A Incorrect because Covington did violate the Standards in that she did not follow her employer’s compliance procedures, Standard VI(B).\nB Incorrect as there is nothing to indicate she violated Standard V(A)–Diligence and Reasonable Basis.\nC Correct because prior clearance processes guard against potential and actual conflicts of interest; members are required to abide by their employer’s compliance procedures, Standard VI(B)."},
  {"num": 12, "subject": "职业道德", "question": "Wang Dazong, CFA, is a sole proprietor investment advisor. Dazong believes in putting his money at risk along with his clients and trades the same securities as his clients. In order to ensure fair treatment of all accounts, he rotates trade allocations so that each account has an equal likelihood of receiving a fill on their orders. This allocation procedure also applies to Dazong's own account. According to the CFA Institute Code of Ethics and Standards of Professional Conduct, the allocation procedure used by Dazong:", "options": {"A": "complies with the Standards", "B": "requires revision to ensure client trades take precedence", "C": "should be disclosed and written approval received from clients"}, "answer": "B", "explanation": "A Incorrect because the trade allocation procedure does not meet the requirements of Standard VI(B), which requires client transactions to be given precedence over transactions made on behalf of the member's or candidate's firm or personal transactions.\nB Correct because Standard VI(B)–requires client transactions to be given precedence over transactions made on behalf of the member’s or candidate’s firm or personal transactions. Because the advisor trades alongside his clients and allocates trades on a rotating basis, there are times when the advisor’s trades will receive priority over his clients in violation of the Code and Standards. A member or candidate having the same investment positions or being co-invested with clients does not always create a conflict. Some clients in certain investment situations require members or candidates to have aligned interests. Personal investment positions or transactions of members or candidates or their firms should never, however, adversely affect client investments.\nC Incorrect because even though trade allocation procedures should be disclosed to clients, in this case the procedure fails to meet the requirement of the Code and Standards, so disclosure is not sufficient and the procedures should be revised."},
  {"num": 13, "subject": "职业道德", "question": "Which of the following member actions most likely violates the Standard relating to market manipulation?", "options": {"A": "Selling one security and buying another to minimize tax liability", "B": "Writing misleading posts on social media about the development of a new product", "C": "Dividing a large block order into a series of smaller orders to achieve better execution"}, "answer": "B", "explanation": "A Incorrect because Standard II(B), Market Manipulation, requires members to uphold market integrity by prohibiting market manipulation. Market manipulation includes practices that distort security prices or trading volume with the intent to deceive people or entities that rely on information in the market. The intent here is to minimize tax liability and not to deceive.\nB Correct because Standard II(B), Market Manipulation, requires members to uphold market integrity by prohibiting market manipulation. Market manipulation includes practices that distort security prices or trading volume with the intent to deceive people or entities that rely on information in the market. This is an example of information-base manipulation as misleading fake information affects other market participants.\nC Incorrect because Standard II(B), Market Manipulation requires members to uphold market integrity by prohibiting market manipulation. Market manipulation includes practices that distort security prices or trading volume with the intent to deceive people or entities that rely on information in the market. Order splitting is legitimate for optimal trade executions."},
  {"num": 14, "subject": "职业道德", "question": "Linda Barr, CFA, a portfolio manager, receives an unsolicited stock order from a client. She discusses the order with her firm's analysts to determine how it will impact that client's portfolio. The analysts determine the stock to be highly undervalued and suitable for many of Barr's clients. Barr calls clients for whom the stock is suitable to recommend the stock. She then executes a single block trade for the original client as well as other clients for whom the stock is suitable. Barr most likely violated the Standards:", "options": {"A": "only by executing the single block trade.", "B": "only by discussing unsolicited client orders with her analysts.", "C": "both by executing the single block trade and by discussing unsolicited client orders with her analysts."}, "answer": "A", "explanation": "A Correct because Standard III (E), Preservation of Confidentiality, requires that members and candidates preserve the confidentiality of information communicated to them by their clients, prospective clients, and former clients. Further, if a client or former client expressly authorizes the member or candidate to disclose information, however, the member or candidate may follow the terms of the authorization and provide the information. The unsolicited stock order from the client is confidential. So, Barr must obtain the original client's authorization before recommending the stock to other clients. Therefore, Barr has violated Standard III (E) by executing without the original's client authorization, a single block trade for the original client as well as other clients for whom the stock is suitable.\nB Incorrect because according to the recommended procedures for compliance with Standard III (E), Preservation of Confidentiality, the simplest, most conservative, and most effective way to comply with Standard III (E) is to avoid disclosing any information received from a client except to authorized fellow employees who are also working for the client. Barr discusses the order with her firm's analysts to determine how the unsolicited stock order will impact the client's portfolio. As analysts work for the clients, Barr has not violated Standard III (E) by discussing unsolicited client orders with her analysts.\nC Incorrect because Barr has violated Standard III (E), Preservation of Confidentiality, only by executing a single block trade for the original client as well as other clients for whom the stock is suitable, as described in the response rationale for the correct answer."},
  {"num": 15, "subject": "职业道德", "question": "Which of the following is a recommended procedure for compliance with the Standard relating to knowledge of the law? Members should encourage their firms to:", "options": {"A": "distribute summaries of applicable security laws to clients at least annually.", "B": "provide written protocols for reporting suspected legal or regulatory violations.", "C": "seek the advice of a regulatory agency when in doubt about which action to take regarding potential violations."}, "answer": "B", "explanation": "A Incorrect because recommended procedures for compliance with Standard I (A), Knowledge of the Law, state that pertinent information that highlights applicable laws and regulations might be distributed to employees or made available in a central location. Thus, the recommended procedure is to provide such information to employees and not to clients.\nB Correct because recommended procedures for compliance with Standard I (A), Knowledge of the Law, state: Establish procedures for reporting violations: Firms might provide written protocols for reporting suspected violations of laws, regulations, or company policies.\nC Incorrect because recommended procedures for compliance with Standard I (A), Knowledge of the Law, state that when in doubt about the appropriate action to undertake, it is recommended that a member or candidate seek the advice of compliance personnel or legal counsel concerning legal requirements. If a potential violation is being committed by a fellow employee, it may also be prudent for the member or candidate to seek the advice of the firm's compliance department or legal counsel. The recommended procedures for compliance with Standard I (A) do not suggest seeking advice of regulatory agency personnel."},
  {"num": 16, "subject": "职业道德", "question": "Applying standardized criteria for the selection of external managers is a requirement of the Standard relating to:", "options": {"A": "suitability.", "B": "independence and objectivity.", "C": "diligence and reasonable basis."}, "answer": "C", "explanation": "A Incorrect because Standard V (A), Diligence and Reasonable Basis, states members and candidates who are directly involved with the use of external advisers need to ensure that their firms have standardized criteria for reviewing these selected external advisers and managers. This is not a requirement of Standard III (C), Suitability.\nB Incorrect because Standard V (A), Diligence and Reasonable Basis, states members and candidates who are directly involved with the use of external advisers need to ensure that their firms have standardized criteria for reviewing these selected external advisers and managers. This is not a requirement of Standard I (B), Independence and Objectivity.\nC Correct because Standard V (A), Diligence and Reasonable Basis, states members and candidates who are directly involved with the use of external advisers need to ensure that their firms have standardized criteria for reviewing these selected external advisers and managers. Such criteria would include, but would not be limited to, the following:"},
  {"num": 17, "subject": "职业道德", "question": "A member most likely violates the Standard relating to knowledge of the law if she fails to:", "options": {"A": "dissociate from unethical conduct.", "B": "report illegal activity to the appropriate regulatory organization.", "C": "have detailed knowledge of all the laws potentially governing her professional activities."}, "answer": "A", "explanation": "A Correct because under Standard I(A), Knowledge of the Law, members and candidates have a responsibility to step away and dissociate from the unethical activity. Inaction combined with continuing association with those involved in illegal or unethical conduct may be construed as participation or assistance in the illegal or unethical conduct.\nB Incorrect because under Standard I(A), Knowledge of the Law, a failure to report is less likely to be construed as a violation than a failure to dissociate from unethical conduct, the impact of inactivity on the integrity of capital market can be significant. Although the Code and Standards do not compel members and candidates to report violations to their governmental or regulatory organizations, such disclosure may be prudent under certain circumstances.\nC Incorrect because under Standard I(A), Knowledge of the Law, while members and candidates must understand the applicable laws and regulations of the countries and jurisdictions where they engage in professional activities, members and candidates are not required to have detailed knowledge of or be experts on all the laws that could potentially govern their activities."},
  {"num": 18, "subject": "职业道德", "question": "Which of the following member actions most likely violates the Standard relating to material nonpublic information?\nAction 1: An analyst buys call options on a stock after learning from the company's CEO that the company will report earnings exceeding analyst expectations\nAction 2: An analyst buys an oil company stock after speaking to a well-known industry expert who believes oil prices will rise due to geopolitical risk", "options": {"A": "Action 1 only", "B": "Action 2 only", "C": "both Action 1 and Action 2"}, "answer": "A", "explanation": "A Correct because Standard II(A), Material Nonpublic Information, states that Members and Candidates who possess material nonpublic information that could affect the value of an investment must not act or cause others to act on the information. Also, Members and candidates must not use material nonpublic information to influence their investment actions related to derivatives. Therefore, a member analyst buying call option on a company stock after learning from its CEO that the company will report earnings exceeding analyst expectation is a violation of Standard II(A). In contrast, a member analyst buying an oil company stock after speaking to a well-known industry expert who believes oil prices will rise due to geopolitical risk is not a violation of Standard II(A). This is because a well-known industry expert's view is unlikely to be nonpublic information. Therefore, only Action 1 violates Standard II(A).\nB Incorrect because only Action 1 violates Standard II(A), Material Nonpublic Information as described in the response rationale of the correct answer.\nC Incorrect because only Action 1 violates Standard II(A), Material Nonpublic Information as described in the response rationale of the correct answer."},
  {"num": 19, "subject": "职业道德", "question": "Iris Hadid, CFA, works as an investment banking analyst. She builds a financial model to value Ski Mountain Lodge (SML). Hadid's friend, Peter Jackson, CFA, works for a different advisory firm. Hadid shares with Jackson details about her analysis to receive his feedback on her valuation of SML. Based on this information, Jackson buys call options on SML. Who has violated the Standards?", "options": {"A": "Hadid only", "B": "Jackson only", "C": "Both Hadid and Jackson"}, "answer": "C", "explanation": "A Incorrect because Standard II(A), Material Nonpublic Information, has been violated by both Hadid and Jackson as described in the response rationale of the correct answer.\nB Incorrect because Standard II(A), Material Nonpublic Information, has been violated by both Hadid and Jackson as described in the response rationale of the correct answer.\nC Correct because Standard II(A), Material Nonpublic Information, states that Members and Candidates who possess material nonpublic information that could affect the value of an investment must not act or cause others to act on the information. Also, Members and candidates must not use material nonpublic information to influence their investment actions related to derivatives. Hadid caused Jackson to act by telling Jackson about her work on SML. Jackson acts on the information and buys call options on SML. Therefore, both Hadid and Jackson violate Standard II(A)."},
  {"num": 20, "subject": "职业道德", "question": "Amy Joy, CFA, works at Parklane Investments Ltd. (PIL). When presenting to PIL’s prospective clients, Joy uses a brief investment performance summary and makes available detailed supporting information only upon request. Has Joy violated the Standards?", "options": {"A": "No", "B": "Yes, the Standard relating to fair dealing", "C": "Yes, the Standard relating to performance presentation"}, "answer": "A", "explanation": "A Correct because according to Standard III(D), Performance Presentation, if the presentation is brief, the member or candidate must make available to clients and prospects, on request, the detailed information supporting that communication. By making available detailed supporting information on request, Joy does not violate Standard III(D). In addition, Joy does not violate Standard III(B), Fair Dealing, which states that members and Candidates must deal fairly and objectively with all clients when providing investment analysis, making investment recommendations, taking investment action, or engaging in other professional activities.\nB Incorrect because Standard III(B), Fair Dealing, has not been violated as described in the response rationale of the correct answer.\nC Incorrect because Standard III(D), Performance Presentation, has not been violated as described in the response rationale of the correct answer."},
  {"num": 21, "subject": "职业道德", "question": "Sue Yong, CFA, is an analyst at a large investment firm. After thorough research, she issues a \"buy\" rating on a company and submits her report to her firm's investment committee for review. The committee disagrees with Yong's assumptions in the report. As a result, the report is changed to a \"neutral\" rating. The final report is issued and Yong agrees to leave her name on the report. Has Yong violated the Standards?", "options": {"A": "No", "B": "Yes, the Standard relating to loyalty, prudence, and care", "C": "Yes, the Standard relating to diligence and reasonable basis"}, "answer": "A", "explanation": "A Correct because according to Standard V (A), Diligence and Reasonable basis, Members and Candidates must: 1. Exercise diligence, independence, and thoroughness in analyzing investments, making investment recommendations, and taking investment actions. 2. Have a reasonable and adequate basis, supported by appropriate research and investigation, for any investment analysis, recommendation, or action. Additionally, the results of research are not always clear, and different people may have different opinions based on the same factual evidence. In this case, the committee may have valid reasons for issuing a report that differs from the analyst’s original research. The firm can issue a report that is different from the original report of an analyst as long as there is a reasonable and adequate basis for its conclusions. Generally, analysts must write research reports that reflect their own opinion and can ask the firm not to put their name on reports that ultimately differ from that opinion. When the work is a group effort, however, not all members of the team may agree with all aspects of the report. Ultimately, members and candidates can ask to have their names removed from the report, but if they are satisfied that the process has produced results or conclusions that have a reasonable and adequate basis, members and candidates do not have to dissociate from the report even when they do not agree with its contents. Yong was thorough in her research and There is no evidence to assume that she did not have a reasonable and adequate basis for her recommendation. Additionally there is no violation of the standard relating to loyalty, prudence and care.\nB Incorrect because according to Standard III (A), Loyalty, Prudence, and Care Members and Candidates have a duty of loyalty to their clients and must act with reasonable care and exercise prudent judgment. Members and Candidates must act for the benefit of their clients and place their clients’ interests before their employer’s or their own interests. By contrast, this case is about whether Yong was thorough in her analysis. This case does not pertain to Standard III (A). Therefore, Standard III (A) has not been violated.\nC Incorrect because Yong has not violated this Standard as described in the rationale to the correct response."},
  {"num": 22, "subject": "职业道德", "question": "Rita Melmo, CFA, is an analyst at Greensky Investment (GI). On weekends, she works as a paid employee of a local charity where she negotiates purchase agreements. Melmo does not disclose the charity employment to GI. Melmo is asked to purchase a new truck for the charity and she negotiates a purchase agreement with a local truck dealership. In the purchase agreement, the charity is charged $500 more than the truck's normal sale price. In return, Melmo receives retail vouchers worth $500 from the dealership for her private use. Melmo has most likely violated the Standards:", "options": {"A": "only by failing to disclose the charity employment to GI.", "B": "only by negotiating a purchase agreement in which the charity is charged more than the truck's normal sale price.", "C": "both by failing to disclose the charity employment to GI and by negotiating a purchase agreement in which the charity is charged more than the truck's normal sale price."}, "answer": "B", "explanation": "A Incorrect because according to Standard IV (A), Loyalty, in matters related to their employment, Members and Candidates must act for the benefit of their employer and not deprive their employer of the advantage of their skills and abilities, divulge confidential information, or otherwise cause harm to their employer. Working on weekends for a charity to do tasks that do not compete with her investment role employer does not violate this Standard.\nB Correct because according to Standard I (D), Misconduct, Members and Candidates must not engage in any professional conduct involving dishonesty, fraud, or deceit or commit any act that reflects adversely on their professional reputation, integrity, or competence. Overcharging the charity by any amount is fraud and reflects adversely on Melmo as an investment professional and potentially on her employer and and the investment profession.\nC Incorrect because according to Standard I (D), Misconduct, Members and Candidates must not engage in any professional conduct involving dishonesty, fraud, or deceit or commit any act that reflects adversely on their professional reputation, integrity, or competence. Further, and according to Standard IV (A), Loyalty, in matters related to their employment, Members and Candidates must act for the benefit of their employer and not deprive their employer of the advantage of their skills and abilities, divulge confidential information, or otherwise cause harm to their employer. Working on weekends for a charity does not violate either Standard. However, overcharging the charity is fraud and reflects adversely on Melmo as an investment professional and potentially on her employer and on the investment profession."},
  {"num": 23, "subject": "职业道德", "question": "A member believes a colleague is participating in unethical activities at work. The member does not disassociate himself from the activities of his colleague. The member has most likely violated:", "options": {"A": "only the Standard relating to knowledge of the law.", "B": "only the Standard relating to avoid or disclose conflicts.", "C": "both the Standard relating to knowledge of the law and the Standard relating to avoid or disclose conflicts."}, "answer": "A", "explanation": "A Correct because according to Standard I(A) Knowledge of the Law, if a member or candidate has reasonable grounds to believe that imminent or ongoing client or employer activities are illegal or unethical, the member or candidate must disassociate, or separate, from the activity. Inaction combined with continuing association with those involved in illegal or unethical conduct may be constructed as participation or assistance in the illegal or unethical conduct.\nB Incorrect because according to Standard VI(A), Avoid or Disclose Conflicts, Members and Candidates must make full and fair disclosure of all matters that could reasonably be expected to impair their independence and objectivity or interfere with respective duties to their clients, prospective clients, and employer. Members and Candidates must ensure that such disclosures are prominent, are delivered in plain language, and communicate the relevant information effectively. This Standard does not apply to guiding a member's behavior for cases in which the member believes that a colleague participates in unethical behavior. Here, the member has not violated Standard VI (A).\nC Incorrect because according to Standard VI(A), Avoid or Disclose Conflicts, Members and Candidates must make full and fair disclosure of all matters that could reasonably be expected to impair their independence and objectivity or interfere with respective duties to their clients, prospective clients, and employer. Members and Candidates must ensure that such disclosures are prominent, are delivered in plain language, and communicate the relevant information effectively. This Standard does not apply to guiding a member's behavior for cases in which the member believes that a colleague participates in unethical behavior. Here, the member has not violated Standard VI (A)."},
  {"num": 24, "subject": "职业道德", "question": "According to the Standard relating to independence and objectivity, which of the following is accurate?\nStatement 1: A member should encourage her firm to remove a covered company from a restricted list if the firm is unwilling to permit dissemination of an adverse opinion about the company\nStatement 2: A member is prohibited from accepting benefits from corporate issuers in the form of allocation of shares in oversubscribed IPOs suitable for firm's clients", "options": {"A": "Statement 1 only", "B": "Statement 2 only", "C": "Both Statement 1 and Statement 2"}, "answer": "B", "explanation": "A Incorrect because according to the recommended procedures for compliance with Standard I (B), Independence and Objectivity, if the firm is unwilling to permit dissemination of adverse opinions about a corporate client, members and candidates should encourage the firm to remove the controversial company from the research universe and put it on a restricted list so that the firm disseminates only factual information about the company. Therefore, a member should encourage her firm to place a company on (not remove a company from) a restricted list if the firm is unwilling to permit dissemination of adverse opinion about the company. So, Statement 1 is not accurate.\nB Correct because according to Standard I (B), Independence and Objectivity, one type of benefit is the allocation of shares in oversubscribed IPOs to investment managers for their personal accounts. This practice affords managers the opportunity to make quick profits that may not be available to their clients. Such a practice is prohibited under Standard I (B). Therefore, a member is prohibited from accepting benefits from corporate issuers in the form of allocation of shares in oversubscribed IPOs that are suitable for firm's clients. So, Statement 2 is accurate.\nC Incorrect because according to the recommended procedures for compliance with Standard I (B), Independence and Objectivity, if the firm is unwilling to permit dissemination of adverse opinions about a corporate client, members and candidates should encourage the firm to remove the controversial company from the research universe and put it on a restricted list so that the firm disseminates only factual information about the company. Therefore, a member should encourage her firm to place a company on (not remove a company from) a restricted list if the firm is unwilling to permit dissemination of adverse opinion about the company. So, Statement 1 is not accurate."},
  {"num": 25, "subject": "职业道德", "question": "Anita Delgado is a candidate in the CFA Program. After taking the Level II examination, Delgado posts on a social networking website that she found the exam to be very difficult and that in her opinion, the CFA Program and CFA Institute were losing credibility with the public. Has Delgado most likely violated the Standards?", "options": {"A": "No", "B": "Yes, by posting information about the exam on a public website", "C": "Yes, by compromising the reputation or integrity of CFA Institute"}, "answer": "A", "explanation": "A Correct because Delgado did not violate Standard VII (A), Responsibilities as a CFA Institute Member of CFA Candidate. Candidates are prohibited from disclosing confidential material gained during the exam process but are free to discuss the examination in a general manner, such as the fact that she found the exam difficult. Regarding her opinion about the CFA Institute, a member must not engage in any conduct that compromises the reputation or integrity of CFA Institute. However, Standard VII (A) does not cover expressing opinions regarding the CFA Program or CFA Institute. Therefore, Delgado's voicing her opinion is not a conduct that compromises the reputation or integrity of CFA Institute.\nB Incorrect because Delgado did not violate the Standards by posting information about the exam on a public website, as described in the Response Rationale for the correct answer.\nC Incorrect because Delgado did not violate the Standards by expressing her opinion that the CFA Program and CFA Institute were losing credibility with the public, as described in the Response Rationale for the correct answer."},
  {"num": 26, "subject": "职业道德", "question": "According to the Standard relating to independence and objectivity:", "options": {"A": "a gift from a client could be considered supplementary compensation.", "B": "compensation arrangements should link analyst remuneration to investment banking assignments.", "C": "portfolio managers may report sell-side analysts to covered companies if analysts' changes in recommendation adversely affect client portfolios."}, "answer": "A", "explanation": "A Correct because receiving a gift, benefit, or consideration from a client can be distinguished from gifts given by entities seeking to influence a member or candidate to the detriment of other clients. In a client relationship, the client has already entered some type of compensation arrangement with the member, candidate, or his or her firm. A gift from a client could be considered supplementary compensation.\nB Incorrect because compensation arrangements should not link analyst remuneration directly to investment banking assignments in which the analyst may participate as a team member.\nC Incorrect because portfolio managers have a responsibility to respect and foster the intellectual honesty of sell-side research. Therefore, it is improper for portfolio managers to threaten or engage in retaliatory practices, such as reporting sell-side analysts to the covered company in order to instigate negative corporate reactions."},
  {"num": 27, "subject": "职业道德", "question": "Which of the following is a recommended procedure for compliance with the Standard relating to independence and objectivity? Members should encourage their firms to:", "options": {"A": "prohibit any employee participation in equity-related IPOs.", "B": "remove a corporate client company from the research universe and put it on a restricted list if the firm is unwilling to disseminate adverse opinions about the company.", "C": "provide every client with the procedures and policies for reporting potentially unethical behaviour, violations of regulations, or other activities that may harm the firm’s reputation."}, "answer": "B", "explanation": "A Incorrect because according to the recommended procedures for compliance with Standard I (B), Independence and Objectivity, Members and candidates should encourage their investment firms to develop formal policies related to employee purchases of equity or equity-related IPOs. Firms should require prior approval for employee participation in IPOs, with prompt disclosure of investment actions taken following the offering. So, the recommendation is to have regulation around IPOs, but not explicitly prohibit them.\nB Correct because according to the recommended procedures for compliance with Standard I (B), Independence and Objectivity, Create a restricted list: If the firm is unwilling to permit dissemination of adverse opinions about a corporate client, members and candidates should encourage the firm to remove the controversial company from the research universe and put it on a restricted list so that the firm disseminates only factual information about the company.\nC Incorrect because according to the recommended procedures for compliance with Standard I (B), Independence and Objectivity, Firms should provide every employee with the procedures and policies for reporting potentially unethical behavior, violations of regulations, or other activities that may harm the firm’s reputation. So, firms should provide to every employee, not every client."},
  {"num": 28, "subject": "职业道德", "question": "To comply with the Standards, if applicable law requires members to maintain confidentiality of client information, confidentiality must be maintained unless:", "options": {"A": "the client has died.", "B": "the client's information involves illegal activities.", "C": "the client permits the disclosure of the information."}, "answer": "C", "explanation": "A Incorrect because Standard III (E), Preservation of Confidentiality, states that this standard protects the confidentiality of client information even if the person or entity is no longer a client of the member or candidate.\nB Incorrect because Standard III (E), Preservation of Confidentiality, states that if applicable law requires members and candidates to maintain confidentiality, even if the information concerns illegal activities on the part of the client, members and candidates should not disclose such information.\nC Correct because Standard III (E), Preservation of Confidentiality, states that members must keep information about current, former, and prospective clients confidential unless: the client or prospective client permits disclosure of the information."},
  {"num": 29, "subject": "职业道德", "question": "Which of the following most likely violates the Standard relating to preservation of confidentiality?", "options": {"A": "Recommending a former client as a potential donor for a local charity", "B": "Disclosing details of client activity to the CFA Institute Professional Conduct Program", "C": "Providing confidential information about a prospective client when permitted by the prospective client"}, "answer": "A", "explanation": "A Correct because Standard III (E), Preservation of Confidentiality, requires Members and Candidates must keep information about current, former, and prospective clients confidential. Also, this standard protects the confidentiality of client information even if the person or entity is no longer a client of the member or candidate.\nB Incorrect because the requirements of Standard III (E) are not intended to prevent members and candidates from cooperating with an investigation by the CFA Institute Professional Conduct Program (PCP).\nC Incorrect because Members and Candidates must keep information about current, former, and prospective clients confidential unless the client or prospective client permits disclosure of the information."},
  {"num": 30, "subject": "职业道德", "question": "Which of the following is a recommended procedure for compliance with the Standard relating to priority of transactions? Investment personnel should:", "options": {"A": "examine all personal trades for possible conflicts immediately after execution of the trades.", "B": "direct their brokers to supply their firms with duplicate confirmations of all their personal securities transactions.", "C": "make a one-time disclosure of holdings in which they have a beneficial interest to their firm upon commencement of the employment relationship."}, "answer": "B", "explanation": "A Incorrect because the recommended procedures for compliance with Standard VI (B), Priority of Transactions, recommend that investment personnel should examine all planned personal trades to identify possible conflicts prior to the execution of the trades. Therefore, a recommended procedure for compliance with the Standard is to examine all planned personal trades prior to (not immediately after) the execution of the trade.\nB Correct because the recommended procedures for compliance with Standard VI (B), Priority of Transactions, recommend that investment personnel should be required to direct their brokers to supply to firms duplicate copies or confirmations of all their personal securities transactions and copies of periodic statements for all securities accounts.\nC Incorrect because the recommended procedures for compliance with Standard VI (B), Priority of Transactions, recommend that disclosure by investment personnel to the firm should be made upon commencement of the employment relationship and at least annually thereafter. Therefore, a recommended procedure for compliance with the Standard is to disclose upon commencement of the employment relationship and at least annually thereafter (not a one off disclosure on commencement of employment only)."},
  {"num": 31, "subject": "职业道德", "question": "Which of the following individuals can refer to themselves as a candidate in the CFA Program?\n• Individual 1: Has passed Level II and expects to register for Level III in a couple of months\n• Individual 2: Has failed Level I and expects to retake the exam in its next administration\n• Individual 3: Is awaiting results of the Level III exam", "options": {"A": "Individual 1", "B": "Individual 2", "C": "Individual 3"}, "answer": "C", "explanation": "A Incorrect because according to Standard VII(B), Reference to CFA Institute, the CFA Designation, and the CFA Program, a person is a candidate in the CFA Program if the person’s application for registration in the CFA Program has been accepted by CFA Institute, as evidenced by issuance of a notice of acceptance, and the person is enrolled to sit for a specified examination. As this individual has not registered for the Level III exam the individual cannot refer to himself/herself as a CFA candidate.\nB Incorrect because according to Standard VII(B), Reference to CFA Institute, the CFA Designation, and the CFA Program, a person is a candidate in the CFA Program if the person’s application for registration in the CFA Program has been accepted by CFA Institute, as evidenced by issuance of a notice of acceptance, and the person is enrolled to sit for a specified examination. As this individual has not registered for the Level III exam the individual cannot refer to himself/herself as a CFA candidate.\nC Correct because according to Standard VII(B), Reference to CFA Institute, the CFA Designation, and the CFA Program, a person is a candidate in the CFA Program if the registered person has sat for a specified examination but exam results have not yet been received."},
  {"num": 32, "subject": "职业道德", "question": "Which of the following is a recommended procedure for compliance with the Standard relating to priority of transactions?\nProcedure 1: Members should disclose personal transactions relating to shares in their firm's research universe to clients upon request\nProcedure 2: Members should establish blackout periods prior to trades for clients\nProcedure 3: Members should treat fee-paying family accounts in which they have beneficial ownership in the same manner as they would treat their personal accounts", "options": {"A": "Procedure 1", "B": "Procedure 2", "C": "Procedure 3"}, "answer": "B", "explanation": "A Incorrect because according to Standard VI(B), Priority of Transactions, members and candidates should fully disclose to investors their firm’s policies regarding personal investing. The information about employees’ personal investment activities and policies will foster an atmosphere of full and complete disclosure and calm the public’s legitimate concerns about the conflicts of interest posed by investment personnel’s personal trading.\nB Correct because according to Standard VI(B), Priority of Transactions, investment personnel involved in the investment decision-making process should establish blackout periods prior to trades for clients so that managers cannot take advantage of their knowledge of client activity by “front-running” client trades (trading for one’s personal account before trading for client accounts).\nC Incorrect because according to Standard VI(B), Priority of Transactions, members or candidates may undertake transactions in accounts for which they are a beneficial owner only after their clients and employers have had adequate opportunity to act on a recommendation. Family accounts that are client accounts should be treated like any other firm account and should neither be given special treatment nor be disadvantaged because of the family relationship."},
  {"num": 33, "subject": "职业道德", "question": "According to the Standard related to independence and objectivity, a member must:", "options": {"A": "refuse all business-related gifts.", "B": "adhere to strict standards of conduct that govern how issuer-paid research is conducted.", "C": "pay for transportation, hotel and meal expenses when attending meetings at an issuer’s headquarters."}, "answer": "B", "explanation": "A Incorrect because according to Standard I(B), Independence and Objectivity, members are permitted to accept token business-related gifts. Per the Standard, members and candidates must limit the acceptance of gratuities and/or gifts to token items. Firms should consider a strict value limit for acceptable gifts that is based on the local or regional customs and should address whether the limit is per gift or an aggregate annual value.\nB Correct because this is a requirement of Standard I(B), Independence and Objectivity. Issuer-paid research conducted by independent analysts, however, is fraught with potential conflicts. Members must adhere to strict standards of conduct that govern how the research is to be conducted and what disclosures must be made in the report. Analysts must engage in thorough, independent, and unbiased analysis and must fully disclose potential conflicts of interest, including the nature of their compensation.\nC Incorrect because according to Standard I(B), Independence and Objectivity, it is recommended (not required) that members pay for commercial transportation and hotel charges, not meals, when attending meetings at an issuer's headquarters."},
  {"num": 34, "subject": "职业道德", "question": "Which statement regarding market manipulation is consistent with the Standards? Members must refrain from:", "options": {"A": "inducing trading by disseminating verifiable information.", "B": "engaging in practices which exploit perceived market inefficiencies.", "C": "securing a dominant position in a financial instrument to exploit the price of the underlying asset."}, "answer": "C", "explanation": "A Incorrect because according to Standard II(B), Market Manipulation, members are prohibited from disseminating false, not verifiable, information to induce trading by others. Market manipulation includes the dissemination of false or misleading information and Information-based manipulation includes spreading false rumors to induce trading by others.\nB Incorrect because Standard II(B) Market Manipulation allows trading strategies based on perceived market inefficiencies. Standard II(B) is not intended to preclude transactions undertaken on legitimate trading strategies based on perceived market inefficiencies.\nC Correct because Standard II(B), Market Manipulation, prohibits such activity. Transaction-based manipulation includes, but is not limited to securing a controlling, dominant position in a financial instrument to exploit the price of the underlying asset."},
  {"num": 35, "subject": "职业道德", "question": "According to the Standard related to communication with clients and prospective clients, members must:", "options": {"A": "only distinguish between fact and opinion in the presentation of investment analyses.", "B": "only promptly disclose material and nonmaterial changes in the investment processes they use to select securities.", "C": "both distinguish between fact and opinion in the presentation of investment analyses and promptly disclose material and nonmaterial changes in the investment processes they use to select securities."}, "answer": "A", "explanation": "A Correct because according to Standard V(B), Communication with Clients and Prospective Clients, members must distinguish between fact and opinion in the presentation of investment analyses and recommendations.\nB Incorrect because according to Standard V(B), Communication with Clients and Prospective Clients, members must promptly disclose any material, not nonmaterial, changes affecting the investment process. Disclose to clients and prospective clients the basic format and general principles of the investment processes they use to analyze investments, select securities, and construct portfolios and must promptly disclose any changes that might materially affect those processes.\nC Incorrect because according to Standard V(B), Communication with Clients and Prospective Clients, members must promptly disclose any material, not nonmaterial, changes affecting the investment process. Disclose to clients and prospective clients the basic format and general principles of the investment processes they use to analyze investments, select securities, and construct portfolios and must promptly disclose any changes that might materially affect those processes."},
  {"num": 36, "subject": "职业道德", "question": "According to the recommended procedures for compliance with the Standard relating to priority of transactions, members should:", "options": {"A": "discourage clients from trading during blackout periods.", "B": "supply copies of their personal securities transactions to clients upon request.", "C": "preclear their participation in IPOs even if there is no conflict of interest between their participation in an IPO and the client’s interests."}, "answer": "C", "explanation": "A Incorrect because Standard VI(B), Priority of Transactions, recommends blackout/restricted periods to prohibit members from early personal trading (\"front-running\"), not to discourage clients from trading. According to the recommended procedures for compliance with Standard VI(B), investment personnel involved in the investment decision-making process should establish blackout periods prior to trades for clients so that managers cannot take advantage of their knowledge of client activity by “front-running” client trades (trading for one’s personal account before trading for client accounts).\nB Incorrect because Standard VI(B), Priority of Transactions, makes no recommendation with respect to members supplying clients with copies of personal securities transactions. According to the recommended procedures for compliance with Standard VI(B), investment personnel should be required to direct their brokers to supply to firms duplicate copies or confirmations of all their personal securities transactions and copies of periodic statements for all securities accounts.\nC Correct because according to the recommended procedures for compliance with Standard VI(B), Priority of Transactions, members and candidates should preclear their participation in IPOs, even in situations without any conflict of interest between a member's or candidate's participation in an IPO and the client's interest."},
  {"num": 37, "subject": "职业道德", "question": "Sharon Chan, CFA, is an analyst at an investment firm. Chan issues a \"buy\" rating on a company in which her brother holds shares. Chan does not disclose her brother's holdings in her report as she has no beneficial ownership in her brother's account. Has Chan violated the Standards?", "options": {"A": "No", "B": "Yes, the Standard relating to avoid or disclose conflicts", "C": "Yes, the Standard relating to communication with clients and prospective clients"}, "answer": "A", "explanation": "A Correct because according to Standard VI(A), Avoid or Disclose Conflicts, Members and Candidates must make full and fair disclosure of all matters that could reasonably be expected to impair their independence and objectivity or interfere with respective duties to their clients, prospective clients, and employer. In addition, sell-side members and candidates should disclose any materially beneficial ownership interest in a security or other investment that the member or candidate is recommending. Chan has no beneficial ownership in her brother's account, so she is not required to disclose it. Therefore, Chan has not violated the Standard VI(A). In addition, Standard V(B), Communication with Clients and Prospective Clients, states that members and candidates should communicate in a recommendation the factors that were instrumental in making the investment recommendation. A critical part of this requirement is to distinguish clearly between opinions and facts. In preparing a research report, the member or candidate must present the basic characteristics of the securities being analyzed, which will allow the reader to evaluate the report and incorporate information the reader deems relevant to his or her investment decision-making process. Standard V(B) is addressing the investment process communication with clients. Chan has not violated the Standard V(B).\nB Incorrect because according to Standard VI(A), Avoid or Disclose Conflicts, Members and Candidates must make full and fair disclosure of all matters that could reasonably be expected to impair their independence and objectivity or interfere with respective duties to their clients, prospective clients, and employer. In addition, sell-side members and candidates should disclose any materially beneficial ownership interest in a security or other investment that the member or candidate is recommending. Chan has no beneficial ownership in her brother's account, so she is not required to disclose it. Therefore, Chan has not violated the Standard VI(A).\nC Incorrect because Standard V(B), Communication with Clients and Prospective Clients, states that members and candidates should communicate in a recommendation the factors that were instrumental in making the investment recommendation. A critical part of this requirement is to distinguish clearly between opinions and facts. In preparing a research report, the member or candidate must present the basic characteristics of the security(ies) being analyzed, which will allow the reader to evaluate the report and incorporate information the reader deems relevant to his or her investment decision-making process. Standard V(B) is addressing the investment process communication with clients. Chan has not violated the Standard V(B)."},
  {"num": 38, "subject": "职业道德", "question": "Michael Mak, CFA, is a portfolio manager at an investment firm. After comprehensive research, Mak buys Advance One Tech's (AOT) stock for all his clients for whom the investment is suitable. He then buys AOT shares for his brother's fee-paying account, in which Mak has beneficial ownership. AOT's stock price declines significantly after a month, resulting in substantial losses for all his clients. Are Mak's actions consistent with the Standards?", "options": {"A": "Yes", "B": "No, Mak's actions are not consistent with the Standard relating to priority of transactions", "C": "No, Mak's actions are not consistent with the Standard relating to diligence and reasonable basis"}, "answer": "B", "explanation": "A Incorrect because according to Standard VI(B), Priority of Transactions, family accounts that are client accounts should be treated like any other firm account and should neither be given special treatment nor be disadvantaged because of the family relationship. If a member or candidate has a beneficial ownership in the account, however, the member or candidate may be subject to preclearance or reporting requirements of the employer or applicable law. Mak should treat his brother's fee paying account like any other firm account and should not be disadvantaged. Therefore, Mak's actions are not consistent with the Standard relating to priority of transactions.\nB Correct because according to Standard VI(B), Priority of Transactions, family accounts that are client accounts should be treated like any other firm account and should neither be given special treatment nor be disadvantaged because of the family relationship. If a member or candidate has a beneficial ownership in the account, however, the member or candidate may be subject to preclearance or reporting requirements of the employer or applicable law. Mak should treat his brother's fee paying account like any other firm account and should not be disadvantaged. Therefore, Mak's actions are not consistent with the Standard relating to priority of transactions.\nC Incorrect because according to Standard V(A), Diligence and Reasonable Basis, Members and Candidates must: 1. Exercise diligence, independence, and thoroughness in analyzing investments, making investment recommendations, and taking investment actions. 2. Have a reasonable and adequate basis, supported by appropriate research and investigation, for any investment analysis, recommendation, or action. Mak has completed a comprehensive research before buying AOT's stock for his clients. Therefore, Mak's actions are consistent with the Standard relating to diligence and reasonable basis."},
  {"num": 39, "subject": "职业道德", "question": "Kelvin Lee, CFA, is a portfolio manager at an investment firm. His social media profile reads: \"Kelvin Lee passed all three CFA examinations in three consecutive years. As a CFA charterholder, Lee achieves better investment performance results.\" Has Lee violated the Standards?", "options": {"A": "No", "B": "Yes, by stating that he passed all three CFA Program examinations in three consecutive years", "C": "Yes, by stating that he achieves better investment performance results as a CFA charterholder"}, "answer": "C", "explanation": "A Incorrect because according to Standard VII(B), Reference to CFA Institute, the CFA Designation, and the CFA Program, those who have earned the right to use the Chartered Financial Analyst designation are encouraged to do so but only in a manner that does not misrepresent or exaggerate the meaning or implications of the designation. In addition, if the candidate then goes on to claim or imply superior ability by obtaining the designation in only three years, however, he or she is in violation of Standard VII(B). Lee states that as a CFA charterholder, he achieves better investment performance results. Therefore, he has violated the Standard VII(B).\nB Incorrect because according to Standard VII(B), Reference to CFA Institute, the CFA Designation, and the CFA Program, if a candidate passes each level of the exam in consecutive years and wants to state that he or she did so, that is not a violation of Standard VII(B) because it is a statement of fact. Lee only states the fact that he passed all three CFA Program examinations in three consecutive years. Therefore, he has not violated the Standard VII(B).\nC Correct because according to Standard VII(B), Reference to CFA Institute, the CFA Designation, and the CFA Program, those who have earned the right to use the Chartered Financial Analyst designation are encouraged to do so but only in a manner that does not misrepresent or exaggerate the meaning or implications of the designation. In addition, if the candidate then goes on to claim or imply superior ability by obtaining the designation in only three years, however, he or she is in violation of Standard VII(B). Lee states that as a CFA charterholder, he achieves better investment performance results. Therefore, he has violated the Standard VII(B)."},
  {"num": 40, "subject": "职业道德", "question": "A member manages two fee-paying family accounts at her firm. The member has the power to vote on the shares held in Account 1 and the discretion to sell shares held in Account 2. According to the Standards, is the member considered a beneficial owner of the shares held in her family accounts?", "options": {"A": "No", "B": "Yes, for Account 1 only", "C": "Yes, for both Account 1 and Account 2"}, "answer": "C", "explanation": "A Incorrect because for the purposes of Standard VI(A), Avoid or Disclose Conflicts, members and candidates beneficially own securities or other investments if they have a direct or indirect pecuniary interest in the securities, have the power to vote or direct the voting of the shares of the securities or investments, or have the power to dispose or direct the disposition of the security or investment. Therefore, the member is considered a beneficial owner for shares held in both Account 1 and Account 2.\nB Incorrect because for the purposes of Standard VI(A), Avoid or Disclose Conflicts, members and candidates beneficially own securities or other investments if they have a direct or indirect pecuniary interest in the securities, have the power to vote or direct the voting of the shares of the securities or investments, or have the power to dispose or direct the disposition of the security or investment. Therefore, the member is considered a beneficial owner for shares held in both Account 1 and Account 2.\nC Correct because for the purposes of Standard VI(A), Avoid or Disclose Conflicts, members and candidates beneficially own securities or other investments if they have a direct or indirect pecuniary interest in the securities, have the power to vote or direct the voting of the shares of the securities or investments, or have the power to dispose or direct the disposition of the security or investment. Therefore, the member is considered a beneficial owner for shares held in both Account 1 and Account 2."},
  {"num": 41, "subject": "职业道德", "question": "According to the Standard relating to diligence and reasonable basis, a member is required to:", "options": {"A": "exercise diligence, independence, and thoroughness in analyzing investments.", "B": "become an expert in the technical aspects of the models used for investment recommendations.", "C": "dissociate and remove her name from a company group report if the report does not reflect her opinion."}, "answer": "A", "explanation": "A Correct because according to Standard V(A) Investment Analysis, Recommendations, and Actions - Diligence and Reasonable Basis, Members and Candidates must: Exercise diligence, independence, and thoroughness in analyzing investments, making investment recommendations, and taking investment actions.\nB Incorrect because the guidance for Standard V(A) Diligence and Reasonable Basis states that although they are not required to become experts in every technical aspect of the models, they must understand the assumptions and limitations inherent in any model and how the results were used in the decision-making process.\nC Incorrect because the guidance for Standard V(A) Diligence and Reasonable Basis states that in some instances, a member or candidate will not agree with the view of the group. If, however, the member or candidate believes that the consensus opinion has a reasonable and adequate basis and is independent and objective, the member or candidate need not decline to be identified with the report. If the member or candidate is confident in the process, the member or candidate does not need to dissociate from the report even if it does not reflect his or her opinion."},
  {"num": 42, "subject": "职业道德", "question": "According to the Standard relating to avoid or disclose conflicts, a member should:", "options": {"A": "reject a board position in a company on which the member's firm is planning to initiate a research report.", "B": "ensure that her firm discloses to clients any rebates received from the service fee some classes of mutual funds charge to investors.", "C": "place a company on a restricted list and issue factual information about the company if the member's firm holds options on the company's shares."}, "answer": "B", "explanation": "A Incorrect because according to Standard VI(A), Avoid or Disclose Conflicts, when members or candidates providing investment services also serve as directors, they should be isolated from those making investment decisions by the use of firewalls or similar restrictions. Standard VI(A) protects investors and employers by requiring members and candidates to fully disclose to clients, potential clients, and employers all actual and potential conflicts of interest. Once a member or candidate has made full disclosure, the member’s or candidate’s employer, clients, and prospective clients will have the information needed to evaluate the objectivity of the investment advice or action taken on their behalf. Therefore, with disclosure, accepting the board position is acceptable.\nB Correct because according to Standard VI(A), Avoid or Disclose Conflicts, equally important is the disclosure of arrangements in which the firm benefits directly from investment recommendations. An obvious conflict of interest is the rebate of a portion of the service fee some classes of mutual funds charge to investors. Members and candidates should ensure that their firms disclose such relationships so clients can fully understand the costs of their investments and the benefits received by their investment manager’s employer.\nC Incorrect because according to the recommended procedure for compliance with Standard VI(A), Avoid or Disclose Conflicts, if a member, a candidate, or a member’s or candidate’s firm has outstanding agent options to buy stock as part of the compensation package for corporate financing activities, the amount and expiration date of these options should be disclosed as a footnote to any research report published by the member’s or candidate’s firm. Therefore, a member need not place the company on a restricted list and issue factual information about the company if the member's firm holds options on the company's shares."},
  {"num": 43, "subject": "职业道德", "question": "According to the Standards, a member who is asked to produce an issuer-paid research report is required to:", "options": {"A": "avoid cash compensation.", "B": "disclose the nature of their compensation in the report.", "C": "decline to write the report if the member's firm provides investment banking services to the issuer."}, "answer": "B", "explanation": "A Incorrect because according to Standard I (B), Independence and Objectivity, authors of issuer-paid research can accept cash compensation but need to avoid compensation that could influence its research, such as equity. Independent analysts must also strictly limit the type of compensation that they accept for conducting issuer-paid research. Otherwise, the content and conclusions of the reports could reasonably be expected to be determined or affected by compensation from the sponsoring companies. Compensation that might influence the research report could be direct, such as payment based on the conclusions of the report, or indirect, such as stock warrants or other equity instruments that could increase in value on the basis of positive coverage in the report.\nB Correct because according to Standard I (B), Independence and Objectivity, members are required to disclose their compensation. Members and candidates must adhere to strict standards of conduct that govern how the research is to be conducted and what disclosures must be made in the report. Analysts must engage in thorough, independent, and unbiased analysis and must fully disclose potential conflicts of interest, including the nature of their compensation.\nC Incorrect because according to Standard I (B), Independence and Objectivity, members are not required to decline to write the report if their firm provides investment banking services to the company. Members and candidates must adhere to strict standards of conduct that govern how the research is to be conducted and what disclosures must be made in the report. Analysts must engage in thorough, independent, and unbiased analysis and must fully disclose potential conflicts of interest. So, members need not decline to write the report if a potential conflict of interest exists (such as their firm providing investment banking services), although they do need to disclose such conflicts."},
  {"num": 44, "subject": "职业道德", "question": "Shirin Regali, CFA, is a well-respected, sell-side analyst covering the biotech sector. While researching the market prospects for a drug being trialed by BioHeal Inc., Regali interviews industry experts who are not affiliated with the trials or BioHeal. These experts express confidence that the drug will pass the trials and be a market success. After thorough analysis and based on these experts' insights, Regali issues a \"buy\" recommendation for BioHeal and distributes it to her clients and not to the public. Has Regali most likely violated the Standard relating to material nonpublic information?", "options": {"A": "No", "B": "Yes, by distributing the recommendation to her clients and not to the public", "C": "Yes, by issuing a \"buy\" recommendation for BioHeal based on insights from industry experts"}, "answer": "A", "explanation": "A Correct because Regali did not violate Standard II (A), Nonpublic Material Information. The Standards permit the use of industry experts. Members and candidates may provide compensation to individuals (industry experts) for their insights without violating this standard. In this case, the industry experts are unaffiliated with the trials and thus do not have access to inside information on the trials, so their insights can be used to make investment decisions. The Standards also permit the sell-side analysts to distribute material information to only clients. Simply because the public in general would find the conclusions material does not require that the analyst make his or her work public.\nB Incorrect because distributing the report to only her clients (and not making it public) is not a violation of Standard II (A), Nonpublic Material Information. The Standards permit the sell-side analysts to distribute material information only to clients. Simply because the public in general would find the conclusions material does not require that the analyst make his or her work public.\nC Incorrect because Regali did not violate Standard II (A), Nonpublic Material Information. The Standards permit the use of industry experts. Members and candidates may provide compensation to individuals (industry experts) for their insights without violating this standard. In this case, the industry experts are unaffiliated with the trials and thus do not have access to inside information on the trials, so their opinions can be used to make investment decisions."},
  {"num": 45, "subject": "职业道德", "question": "Meera Doka, CFA, manages an equity fund for clients. One day, the fund experiences a large loss due to an event unforeseen by all market participants. Prior to the event, Doka failed to disclose the risk of this event occurring to her clients. One month later, Doka decides to outsource 5% of the fund's assets to an external manager. She does not inform her clients of this change because the external manager follows an investment process that is very similar to her fund's process. Are Doka's actions consistent with the Standard relating to communication with clients and prospective clients?", "options": {"A": "Yes", "B": "No, because she failed to disclose the risk that resulted in the large loss", "C": "No, because she failed to inform her clients about outsourcing 5% of the fund's assets"}, "answer": "C", "explanation": "A Incorrect because Doka's actions were inconsistent with Standard V (B), Communications with Clients and Prospective Clients, as described in the Response Rationale of the correct answer.\nB Incorrect because it is consistent with Standard V (B), Communications with Clients and Prospective Clients, to fail to disclose a risk unforeseen by all market participants. The appropriateness of risk disclosure should be assessed on the basis of what was known at the time the investment action was taken (often called an ex ante basis). Members and candidates must disclose significant risks known to them at the time of the disclosure. Members and candidates cannot be expected to disclose risks they are unaware of at the time recommendations or investment actions are made.\nC Correct because it is not consistent with Standard V (B), Communications with Clients and Prospective Clients, to fail to inform clients about the use of an outside manager. A firm’s investment policy may include the use of outside advisers to manage various portions of clients’ assets under management. Members and candidates should inform the clients about the specialization or diversification expertise provided by the external adviser(s). This information allows clients to understand the full mix of products and strategies being applied that may affect their investment objectives."},
  {"num": 46, "subject": "职业道德", "question": "A member employed by an investment firm carries out research at the request of a client. The records of that research are the property of the:", "options": {"A": "client.", "B": "member.", "C": "investment firm."}, "answer": "C", "explanation": "A Incorrect because, according to Standard V (C), Record Retention, records created as part of a member’s or candidate’s professional activity on behalf of his or her employer are the property of the firm, not the client.\nB Incorrect because, according to Standard V (C), Record Retention, records created as part of a member’s or candidate’s professional activity on behalf of his or her employer are the property of the firm, not the member.\nC Correct because, according to Standard V (C), Record Retention, records created as part of a member’s or candidate’s professional activity on behalf of his or her employer are the property of the firm."},
  {"num": 47, "subject": "职业道德", "question": "Which of the following is a recommended procedure for complying with the Standard relating to preservation of confidentiality?\nProcedure 1: Disclose to authorized fellow employees only information that will improve service to the client\nProcedure 2: Encourage the adoption of standard confidentiality procedures utilized by leading firms in the industry", "options": {"A": "Procedure 1 only", "B": "Procedure 2 only", "C": "Both Procedure 1 and Procedure 2"}, "answer": "A", "explanation": "A Correct because according to the recommended procedures for compliance with Standard II (E), Preservation of Confidentiality, avoid disclosing any information received from a client except to authorized fellow employees who are also working for the client. Is the information background material that, if disclosed, will enable the member or candidate to improve service to the client?\nB Incorrect because according to the recommended procedures for compliance with Standard II (E), Preservation of Confidentiality, members should encourage the development of procedures that appropriately reflect the firm’s size and business operations and not only large firm's standard models.\nC Incorrect because according to the recommended procedures for compliance with Standard II (E), Preservation of Confidentiality, members should encourage the development of procedures that appropriately reflect the firm’s size and business operations and not only large firm's standard models."},
  {"num": 48, "subject": "职业道德", "question": "Hannah Hostettler, CFA, is a portfolio manager at a wealth management firm. Hostettler has an arrangement with a lawyer, whereby she refers clients who need legal advice to the lawyer, who in turn refers clients to Hostettler. Because no referral fees are involved, Hostettler does not disclose this arrangement to her existing or prospective clients. Has Hostettler most likely violated the Standards?", "options": {"A": "No", "B": "Yes, only by failing to disclose the arrangement to existing clients", "C": "Yes, both by failing to disclose the arrangement to existing clients and to prospective clients"}, "answer": "C", "explanation": "A Incorrect because Hostettler violated the Standards as described in the justification for the correct answer.\nB Incorrect because Hostettler would need to disclose the referral arrangement to both existing and prospective clients as described in the justification for the correct answer.\nC Correct because according to Standard VI (C), Referral Fees, members must disclose to clients and potential clients any referral arrangements and must disclose all consideration. Consideration includes all fees, whether paid in cash, in soft dollars, or in-kind. Thus, Hostettler would need to disclose the full bi-lateral referral arrangement to both clients and prospective clients."},
  {"num": 49, "subject": "职业道德", "question": "To use a quantitative model in her investment research, a member is required by the Standards to:", "options": {"A": "have developed or co-developed the model.", "B": "become an expert in every technical aspect of the model developed by others.", "C": "understand the assumptions and limitations inherent in the model developed by others."}, "answer": "C", "explanation": "A Incorrect because according to Standard V (A), Diligence and Reasonable Basis, to use quantitative models in her investment research, a member is not required to personally develop or co-develop the model. The Standard requires a member to understand the assumptions and limitations inherent in the model developed by others, as described in the response rationale for the correct answer.\nB Incorrect because according to Standard V (A), Diligence and Reasonable Basis. Although members are not required to become experts in every technical aspect of the models, they must understand the assumptions and limitations inherent in any model and how the results were used in the decision-making process. Therefore, to use quantitative models in her investment research, a member is only required to understand the assumptions and limitations inherent in the model developed by others, as described in the response rationale for the correct answer.\nC Correct because according to Standard V (A), Diligence and Reasonable Basis, Members and candidates need to have an understanding of the parameters used in models and quantitative research that are incorporated into their investment recommendations. Although they are not required to become experts in every technical aspect of the models, they must understand the assumptions and limitations inherent in any model and how the results were used in the decision-making process. Therefore, to use quantitative models in her investment research, a member is required to understand the assumptions and limitations inherent in the model developed by others."},
  {"num": 50, "subject": "职业道德", "question": "Emma Berkstein, CFA, uses third-party data to prepare a report on a company. Berkstein does not check the validity of this data herself, but instead relies on her senior colleagues to conduct due diligence. Another analyst at the same firm, Jimmy Brooks, CFA, prepares an industry report with a group of colleagues. After thorough research, the group agrees to issue a report with a positive outlook for the industry. Brooks disagrees with this conclusion, but leaves his name in the report. Has the Standard relating to diligence and reasonable basis most likely been violated?", "options": {"A": "No", "B": "Yes, by Brooks", "C": "Yes, by Berkstein"}, "answer": "A", "explanation": "A Correct because according to Standard V (A), Diligence and Reasonable Basis, A member or candidate may rely on others in his or her firm to determine whether secondary or third-party research is sound and use the information in good faith unless the member or candidate has reason to question its validity or the processes and procedures used by those responsible for the research. Berkstein relied on her senior colleague's due diligence, and there is nothing in the case to suggest she has reason to question it, hence no violation. Nor did Brooks violate the Standard by leaving his name on the group report: The conclusions or recommendations of the group report represent the consensus of the group and are not necessarily the views of the member or candidate, even though the name of the member or candidate is included on the report. In some instances, a member or candidate will not agree with the view of the group. If, however, the member or candidate believes that the consensus opinion has a reasonable and adequate basis and is independent and objective, the member or candidate need not decline to be identified with the report. If the member or candidate is confident in the process, the member or candidate does not need to dissociate from the report even if it does not reflect his or her opinion.\nB Incorrect because according to Standard V (A), Diligence and Reasonable Basis, Brooks can leave his name in the report even if he disagrees with the conclusion, as described in the response rationale for the correct answer.\nC Incorrect because according to Standard V (A), Diligence and Reasonable Basis, Berkstein can rely on her colleagues to do the due diligence, as described in the response rationale for the correct answer."},
  {"num": 51, "subject": "职业道德", "question": "According to the guidance for the Standards, which of the following statements are accurate?\nStatement 1: Employees must place employer interests ahead of personal interests in all matters\nStatement 2: Senior management of a member's firm should create financial compensation structures that do not drive unethical behavior", "options": {"A": "Statement 1 only.", "B": "Statement 2 only.", "C": "Both Statement 1 and Statement 2."}, "answer": "B", "explanation": "A Incorrect because according to Standard IV (A), Loyalty, employers must recognize the duties and responsibilities that they owe to their employees if they expect to have content and productive employees. Further, this standard is not meant to be a blanket requirement to place employer interests ahead of personal interests in all matters. Therefore, Statement 1 - employees must place employer interests ahead of personal interests in all matters - is not accurate.\nB Correct because according to Standard IV (A), Loyalty, the employer is responsible for a positive working environment, which includes an ethical workplace. Senior management has the additional responsibility to devise compensation structures and incentive arrangements that do not encourage unethical behavior. Therefore, Statement 2 is accurate.\nC Incorrect because according to Standard IV (A), Loyalty, employers must recognize the duties and responsibilities that they owe to their employees if they expect to have content and productive employees. Further, this standard is not meant to be a blanket requirement to place employer interests ahead of personal interests in all matters. Therefore, Statement 1 - employees must place employer interests ahead of personal interests in all matters - is not accurate."},
  {"num": 52, "subject": "职业道德", "question": "According to the Standards, which of the following is most likely considered material nonpublic information?", "options": {"A": "The recent execution of a large buy order from a hedge fund", "B": "Significant legal challenges revealed at an internal meeting of the company's management", "C": "Recent increases in a company's board remuneration discussed at the annual general meeting"}, "answer": "B", "explanation": "A Incorrect because according to Standard II(A) Material Nonpublic Information, information regarding orders before execution may be material, but not after execution. Material information may include, but is not limited to, information on the following: orders for large trades before they are executed.\nB Correct because according to Standard II(A) Material Nonpublic Information, material information may include, but is not limited to, information on the following: significant legal disputes.\nC Incorrect because according to Standard II(A) Material Nonpublic Information, information discussed at an annual general meeting is not nonpublic since the information is widely available. Information is 'nonpublic' until it has been disseminated or is available to the marketplace in general (as opposed to a select group of investors)."},
  {"num": 53, "subject": "职业道德", "question": "Susana Garcia, CFA, is a widely respected analyst covering the transportation sector. She completes a new recommendation for a company. The next morning, she emails the recommendation to her firm's largest client. After lunch, she emails the recommendation to all other firm clients. One hour later, she calls the largest client to discuss the recommendation in detail. Garcia has violated the Standard relating to fair dealing:​​​​​​", "options": {"A": "only by calling the largest client to discuss the recommendation in detail.", "B": "only by emailing the recommendation to the largest client prior to sending it to all other clients.", "C": "both by calling the largest client to discuss the recommendation in detail and by emailing the recommendation to the largest client prior to sending it to all other clients."}, "answer": "B", "explanation": "A Incorrect because Garcia has not violated Standard III (B), Fair Dealing, by calling her largest client, since she widely disseminated the recommendation and provided the information to all her clients prior to discussing it with her largest client. Members and candidates should establish procedures for the timing of dissemination of investment recommendations so that all clients are treated fairly—that is, are informed at approximately the same time. Once this distribution has occurred, the member or candidate may follow up separately with individual clients, but members and candidates should not give favored clients advance information when such advance notification may disadvantage other clients.\nB Correct because Garcia has violated Standard III (B), Fair Dealing, by disseminating the sell recommendation to her largest client before the recommendation is sent to all clients. Each member or candidate is obligated to ensure that information is disseminated in such a manner that all clients have a fair opportunity to act on every recommendation. Garcia has not violated Standard III (B) by calling her largest client, since she widely disseminated the recommendation and provided the information to all her clients prior to discussing it with her largest client. Members and candidates should establish procedures for the timing of dissemination of investment recommendations so that all clients are treated fairly—that is, are informed at approximately the same time. Once this distribution has occurred, the member or candidate may follow up separately with individual clients, but members and candidates should not give favored clients advance information when such advance notification may disadvantage other clients.\nC Incorrect because Garcia has not violated Standard III (B), Fair Dealing, by calling her largest client, since she widely disseminated the recommendation and provided the information to all her clients prior to discussing it with her largest client. Members and candidates should establish procedures for the timing of dissemination of investment recommendations so that all clients are treated fairly—that is, are informed at approximately the same time. Once this distribution has occurred, the member or candidate may follow up separately with individual clients, but members and candidates should not give favored clients advance information when such advance notification may disadvantage other clients."},
  {"num": 54, "subject": "职业道德", "question": "According to the Standard relating to loyalty, members must:", "options": {"A": "place their employer's interest above their personal interests in all matters.", "B": "notify their employer before engaging in an independent practice while still employed.", "C": "never act against their employer’s interests when complying with their duties to clients."}, "answer": "B", "explanation": "A Incorrect because according to Standard IV (A), Loyalty, this standard is not meant to be a blanket requirement to place employer interests ahead of personal interests in all matters. The standard does not require members and candidates to subordinate important personal and family obligations to their work.\nB Correct because although Standard IV (A), Loyalty, does not preclude members or candidates from entering into an independent business while still employed, members and candidates who plan to engage in independent practice for compensation must notify their employer and describe the types of services they will render to prospective independent clients, the expected duration of the services, and the compensation for the services. Members and candidates should not render services until they receive consent from their employer to all of the terms of the arrangement.\nC Incorrect because according to Standard IV (A), Loyalty, circumstances may arise (e.g., when an employer is engaged in illegal or unethical activity) in which members and candidates must act contrary to their employer’s interests in order to comply with their duties to the market and clients. In such instances, activities that would normally violate a member’s or candidate’s duty to his or her employer (such as contradicting employer instructions, violating certain policies and procedures, or preserving a record by copying employer records) may be justified."},
  {"num": 55, "subject": "职业道德", "question": "According to the Standard relating to loyalty, in the absence of a noncompete agreement and without employer consent, a member is permitted to:", "options": {"A": "email himself a list of his clients when leaving his employer.", "B": "enter into an independent competitive business while still employed.", "C": "contact clients from his previous employer using public information to solicit business at his new firm."}, "answer": "C", "explanation": "A Incorrect because according to Standard IV(A), Loyalty, in matters related to their employment, Members and Candidates must act for the benefit of their employer and not deprive their employer of the advantage of their skills and abilities, divulge confidential information, or otherwise cause harm to their employer. Activities that might constitute a violation, especially in combination, include the following: misappropriation of clients or client lists. Therefore, emailing himself a list of his clients when leaving his employer is not permitted by Standard IV(A).\nB Incorrect because according to Standard IV(A), Loyalty, Included in Standard IV(A) is the requirement that members and candidates abstain from independent competitive activity that could conflict with the interests of their employer. Although Standard IV(A) does not preclude members or candidates from entering into an independent business while still employed, members and candidates who plan to engage in independent practice for compensation must notify their employer and describe the types of services they will render to prospective independent clients, the expected duration of the services, and the compensation for the services. Members and candidates should not render competitive services until they receive consent from their employer to all of the terms of the arrangement.\nC Correct because according to Standard IV(A), Loyalty, the standard does not prohibit former employees from contacting clients of their previous firm as long as the contact information does not come from the records of the former employer or violate an applicable 'noncompete agreement'. Members and candidates are free to use public information after departing to contact former clients without violating Standard IV(A) as long as there is no specific agreement not to do so."},
  {"num": 56, "subject": "职业道德", "question": "Andrew Milton, CFA, is an advisor working with individual clients. Milton is careful to recommend investments for his clients that are consistent with their overall objectives and risk tolerance. His firm gives its advisors a bonus for recommending the firm's proprietary products. If all other variables are equal in an investment choice, Milton uses the proprietary products. Milton does not inform the clients of this bonus. Has Milton most likely violated the Standards?", "options": {"A": "No", "B": "Yes, the Standard relating to suitability", "C": "Yes, the Standard relating to avoid or disclose conflicts"}, "answer": "C", "explanation": "A Incorrect because Milton must disclose that he receives a bonus for using the firm's proprietary funds to the client, so he is in violation of Standard III (A), Loyalty, Prudence, and Care, as described in the rationale for the correct answer.\nB Incorrect because Standard III (C), Suitability, requires that members and candidates who are in an investment advisory relationship with clients consider carefully the needs, circumstances, and objectives of the clients when determining the appropriateness and suitability of a given investment or course of investment action. Milton is making his investment decisions for his clients based on their objectives and risk tolerance, and suitability, and therefore is not in violation of this Standard.\nC Correct because according to Standard VI (A), Avoid or Disclose Conflicts, Members and Candidates must avoid or make full and fair disclosure of all matters that could reasonably be expected to impair their independence and objectivity or interfere with respective duties to their clients, prospective clients, and employer. Members and candidates must maintain their objectivity when rendering investment advice or taking investment action. Requiring members and candidates to disclose all matters that reasonably could be expected to impair the member’s or candidate’s objectivity when a conflict exists mitigates the conflict and allows clients and prospective clients to judge motives and possible biases for themselves. Therefore, for Milton, the bonus represented a conflict of interest, which he needs to disclose to clients."},
  {"num": 57, "subject": "职业道德", "question": "According to the recommended procedure for compliance with the Standard relating to fair dealing, a member who works in a large firm should:", "options": {"A": "offer different levels of service to clients selectively based on the clients' investment needs.", "B": "disclose to clients and prospective clients how she selects accounts to participate in an order.", "C": "inform all firm staff of the content of upcoming investment recommendations to assure that all clients' investment needs are met."}, "answer": "B", "explanation": "A Incorrect because according to Standard III (B), Fair Dealing, Members and candidates should disclose to all clients whether the organization offers different levels of service to clients for the same fee or different fees. Different levels of service should not be offered to clients selectively.\nB Correct because according to Standard III (B), Fair Dealing, Members and candidates should disclose to clients and prospective clients how they select accounts to participate in an order.\nC Incorrect because Members and candidates should make reasonable efforts to limit the number of people who are privy to the fact that a recommendation is going to be disseminated. All staff should not be informed to avoid risk of leakage of recommendations before dissemination."},
  {"num": 58, "subject": "职业道德", "question": "According to the recommended procedures for compliance with the Standard relating to diligence and reasonable basis, members should encourage their firms to:", "options": {"A": "evaluate the adequacy of external advisors by customizing the evaluation criteria for each advisor.", "B": "establish maximum levels of scenario testing of all computer-based models used in evaluating financial instruments.", "C": "appoint a supervisory analyst to determine whether research reports have a reasonable and adequate basis prior to external circulation."}, "answer": "C", "explanation": "A Incorrect because according to the recommended procedures for compliance with Standard V (A), Diligence and Reasonable Basis, members and candidates should encourage their firms to adopt a standardized set of criteria for evaluating the adequacy of external advisers. Therefore, customizing the evaluation criteria for each external advisor is not a recommended procedure for compliance with Standard V (A).\nB Incorrect because according to the recommended procedures for compliance with Standard V (A), Diligence and Reasonable Basis, members and candidates should encourage their firms to develop detailed, written guidance that establishes minimum levels of scenario testing of all computer-based models used in developing, rating, and evaluating financial instruments. Therefore, establishing maximum levels of scenario testing is incorrect.\nC Correct because according to the recommended procedures for compliance with Standard V (A), Diligence and Reasonable Basis, members and candidates should encourage their firms to establish a policy requiring that research reports, credit ratings, and investment recommendations have a basis that can be substantiated as reasonable and adequate. An individual employee (a supervisory analyst) or a group of employees (a review committee) should be appointed to review and approve such items prior to external circulation to determine whether the criteria established in the policy have been met. Therefore, appointing a supervisory analyst to determine whether research reports have a reasonable and adequate basis, before circulating the reports externally, is a recommended procedure for compliance with Standard V (A)."},
  {"num": 59, "subject": "职业道德", "question": "Dennis Kim, CFA, works at Century Growth Partners (CGP) where he manages an investment account for his client Amelia Frost. Frost tells Kim to invest one percent of her portfolio in biotech stocks. Kim believes such an investment is inconsistent with Frost's investment policy statement. CGP has no policy regarding execution of unsolicited trading requests. Kim discusses his concerns with Frost, but she does not change her instruction. Without amending Frost's investment policy statement, Kim executes the trade afterward. Has Kim violated the Standards?", "options": {"A": "No", "B": "Yes, because Kim executes an unsuitable trade for Frost", "C": "Yes, because Kim does not change Frost's investment policy statement before executing the trade"}, "answer": "A", "explanation": "A Correct because (1) Kim discusses his concerns with Frost before executing the trade, (2) Frost acknowledges this discussion and accepts the conditions of unsuitability, (3) Kim's firm does not require approval for unsuitable trades since it has no policy on the subject, and (4) the request does not have a material impact on Frost's portfolio since it represents only one percent of its value, hence no modification of the IPS is required. According to Standard III(C), Suitability, in cases of unsolicited trade requests that a member or candidate knows are unsuitable for a client, the member or candidate should refrain from making the trade until he or she discusses the concerns with the client. Following the discussion, the member or candidate may follow his or her firm’s policies regarding the necessary client approval for executing unsuitable trades. At a minimum, the client should acknowledge the discussion and accept the conditions that make the recommendation unsuitable. Should the unsolicited request be expected to have a material impact on the portfolio, the member or candidate should use this opportunity to update the investment policy statement.\nB Incorrect because according to Standard III(C), Suitability, members may execute unsuitable trades for clients under certain conditions, which Kim fulfills, as described in the response rationale for the correct answer.\nC Incorrect because according to Standard III(C), Suitability, Kim is not required to update Frost's IPS since the trade size is immaterial, as described in the response rationale for the correct answer."},
  {"num": 60, "subject": "职业道德", "question": "Tom Dixon, CFA, provides a brief summary of his investment performance to his clients. He indicates that further information is available upon request. He tells his clients they can expect a return of 5% in the next three years based on his strong track record. Has Dixon most likely violated the Standards?", "options": {"A": "No", "B": "Yes, by indicating that further information is available upon request", "C": "Yes, by telling his clients they can expect a return of 5% in the next three years"}, "answer": "C", "explanation": "A Incorrect because Dixon violates Standard III(D), Performance Presentation, by telling his clients they can expect a return of 5% in the next three years as described in the response rationale of the correct answer.\nB Incorrect because Dixon violates Standard III(D), Performance Presentation, by telling his clients they can expect a return of 5% in the next three years as described in the response rationale of the correct answer.\nC Correct because according to Standard III(D), Performance Presentation, members and candidates should not state or imply that clients will obtain or benefit from a rate of return that was generated in the past. Also, If the presentation is brief, the member or candidate must make available to clients and prospects, on request, the detailed information supporting that communication."},
  {"num": 61, "subject": "职业道德", "question": "Which of the following are among the recommended procedures for compliance with the Standard relating to independence and objectivity?\nProcedure 1: Impose limits on investment personnel acquiring securities in private placements\nProcedure 2: Prohibit employees from receiving reimbursement from corporate issuers for air transportation when attending meetings at the issuers' headquarters\nProcedure 3: Remove a company from the restricted list if the firm is unwilling to permit dissemination of adverse opinions about the company", "options": {"A": "Procedure 1 and Procedure 2", "B": "Procedure 1 and Procedure 3", "C": "Procedure 2 and Procedure 3"}, "answer": "A", "explanation": "A Correct because according to Standard I(B), Independence and Objectivity, members and Candidates must use reasonable care and judgment to achieve and maintain independence and objectivity in their professional activities. As for Procedure 1, restrict investments: Members and candidates should encourage their investment firms to develop formal policies related to employee purchases of equity or equity-related IPOs. Firms should require prior approval for employee participation in IPOs, with prompt disclosure of investment actions taken following the offering. Strict limits should be imposed on investment personnel acquiring securities in private placements. As for Procedure 2, restrict special cost arrangements: When attending meetings at an issuer’s headquarters, members and candidates should pay for commercial transportation and hotel charges. No corporate issuer should reimburse members or candidates for air transportation.\nB Incorrect because Procedure 1 is among the recommended procedures for compliance with the Standard relating to independence and objectivity, but Procedure 3 is not. As for Procedure 3, create a restricted list: If the firm is unwilling to permit dissemination of adverse opinions about a corporate client, members and candidates should encourage the firm to remove the controversial company from the research universe and put it on a restricted list so that the firm disseminates only factual information about the company. Thus, putting the company on the restricted list is among the recommended procedures.\nC Incorrect because Procedure 2 is among the recommended procedures for compliance with the Standard relating to independence and objectivity, but Procedure 3 is not."},
  {"num": 62, "subject": "职业道德", "question": "Brigid O'Rourke, CFA, serves as a CFA Institute volunteer and grades Level III CFA exams. After grading, O'Rourke shares her experience with work colleagues, none of whom are CFA candidates. She says, “The Level III exam is very tough.” She also states, “I was surprised how few candidates could remember the Black–Scholes equation.” Has O'Rourke most likely violated the Standards?", "options": {"A": "No", "B": "Yes, only by saying “I was surprised how few candidates could remember the Black–Scholes equation”", "C": "Yes, both by saying “I was surprised how few candidates could remember the Black–Scholes equation” and by stating “The Level III exam is very tough”"}, "answer": "B", "explanation": "A Incorrect because, as described in the response rationale for the correct answer, Rourke has violated Standard VII (A), Conduct as Participants in CFA Institute Programs, by stating “I was surprised how few candidates could remember the Black–Scholes equation.”\nB Correct because Standard VII (A), Conduct as Participants in CFA Institute Programs, prohibits members from disclosing and/or soliciting confidential material gained prior to or during the exam and grading processes with those outside the CFA exam development process. Examples of information that cannot be shared by members involved in developing, administering, or grading the exams include but are not limited to questions appearing on the exam or under consideration. Therefore, Rourke has violated Standard VII (A) by stating “I was surprised how few candidates could remember the Black–Scholes equation.”\nC Incorrect because Standard VII (A,) Conduct as Participants in CFA Institute Programs, does not cover expressing opinions regarding CFA Institute, the CFA Program, or other CFA Institute programs. Therefore, Rourke has not violated Standard VII (A) by stating that “The Level III exam is very tough.”"},
  {"num": 63, "subject": "职业道德", "question": "Which of the following statements are consistent with the Standard relating to conduct as participants in CFA Institute programs?\nStatement I: Questions that appear on the CFA examinations cannot be disclosed by candidates even after they are notified of their exam results\nStatement II: Broad topic areas and formulas not tested on the exam cannot be publicly discussed by the candidates after the exam", "options": {"A": "Statement I only", "B": "Statement II only", "C": "Both Statement I and Statement II"}, "answer": "C", "explanation": "A Incorrect because according to Standard VII(A), Conduct as Participants in CFA Institute Programs, candidates sitting for an exam are not permitted to disclose all aspects of the exam, including questions, broad topical areas, and formulas, tested or not tested, until such time as CFA Institute elects to release them publicly. Therefore, both Statement I and Statement II are consistent with Standard VII(A).\nB Incorrect because according to Standard VII(A), Conduct as Participants in CFA Institute Programs, candidates sitting for an exam are not permitted to disclose all aspects of the exam, including questions, broad topical areas, and formulas, tested or not tested, until such time as CFA Institute elects to release them publicly. Therefore, both Statement I and Statement II are consistent with Standard VII(A).\nC Correct because according to Standard VII(A), Conduct as Participants in CFA Institute Programs, all aspects of the exam, including questions, broad topical areas, and formulas, tested or not tested, are considered confidential until such time as CFA Institute elects to release them publicly. This confidentiality requirement allows CFA Institute to maintain the integrity and rigor of exams for future candidates. Therefore, both Statements I and II are consistent with Standard VII(A)."},
  {"num": 64, "subject": "职业道德", "question": "Max Cohen, CFA, is offered a gift by one of his premium-fee-paying clients. Prior to accepting the gift, he obtains written consent from his supervisor and the client offering the gift. He does not disclose the gift to his regular-fee-paying clients. Has Cohen violated the Standards?", "options": {"A": "No", "B": "Yes, the Standard relating to independence and objectivity", "C": "Yes, the Standard relating to additional compensation arrangements"}, "answer": "A", "explanation": "A Correct because according to Standard I(B), Independence and Objectivity, members and candidates must use reasonable care and judgment to achieve and maintain independence and objectivity in their professional activities. When possible, prior to accepting “bonuses” or gifts from clients, members and candidates should disclose to their employers such benefits offered by clients. Also, according to Standard IV(B), Additional Compensation Arrangements, Members and Candidates must not accept gifts, benefits, compensation, or consideration that competes with or might reasonably be expected to create a conflict of interest with their employer’s interest unless they obtain written consent from all parties involved. Standard IV(B) does not require Cohen to disclose the gift to all of his other clients. Thus, Cohen has not violated either Standard I(B) or Standard IV(B).\nB Incorrect because Cohen has not violated Standard I(B), Independence and Objectivity, which requires members to use reasonable care and judgment to achieve and maintain independence and objectivity in their professional activities. A gift from a client could be considered supplementary compensation. The potential for obtaining influence to the detriment of other clients, although present, is not as great as in situations where no compensation arrangement exists. When possible, prior to accepting “bonuses” or gifts from clients, members and candidates should disclose to their employers such benefits offered by clients. Therefore, by obtaining written consent prior to accepting the gift, Cohen has complied with Standard I(B).\nC Incorrect because according to Standard IV(B), Additional Compensation Arrangements, Members and Candidates must not accept gifts, benefits, compensation, or consideration that competes with or might reasonably be expected to create a conflict of interest with their employer’s interest unless they obtain written consent from all parties involved. Standard IV(B) does not require Cohen to disclose the gift to all of his other clients. Therefore, Cohen has not violated Standard IV (B) because he obtained prior written consent from his supervisor and the client offering the gift."},
  {"num": 65, "subject": "职业道德", "question": "A member resides in Adovia, a country with securities laws and regulations that are less strict than the Code and Standards. She does business in Batavia, a country with securities laws and regulations that are less strict than those of Adovia. Which of the following statements is accurate? The member must most likely adhere to:", "options": {"A": "the Code and Standards.", "B": "the laws and regulations of Adovia.", "C": "the laws and regulations of Batavia."}, "answer": "A", "explanation": "A Correct because if applicable law is stricter than the requirements of the Code and Standards, members and candidates must adhere to the applicable law; otherwise, they must adhere to the Code and Standards. Since the laws and regulations of Adovia and Batavia are less strict than the Code and Standards, the member must adhere to the Code and Standards.\nB Incorrect because if applicable law is stricter than the requirements of the Code and Standards, members and candidates must adhere to the applicable law; otherwise they must adhere to the Code and Standards.\nC Incorrect because if applicable law is stricter than the requirements of the Code and Standards, members and candidates must adhere to the applicable law; otherwise they must adhere to the Code and Standards."},
  {"num": 66, "subject": "职业道德", "question": "Agnes Boucault belongs to an online forum of candidates studying for the Level II exam. Boucault writes on the forum: “Hello, I am a Level II candidate in the CFA Program. A friend who took the Level II exam last month tells me that it's very difficult. Let's focus more study time on the fixed income and derivatives areas, which I think are the hardest.” Has Boucault most likely violated the Standards?", "options": {"A": "No", "B": "Yes, by improperly referencing the CFA Program", "C": "Yes, by revealing confidential information about the CFA exam"}, "answer": "A", "explanation": "A Correct because Boucault has not revealed any information about questions or specific topic areas tested or not tested on the prior Level II exam. Therefore, she complied with Standard VII (A), Conduct as Participants in CFA Institute Programs, which does not prohibit candidates from discussing nonconfidential information or curriculum material with others or in study groups in preparation for the exam. Boucault has also used an approved format for referencing her candidacy in the CFA Program, by describing herself as \"a Level II candidate in the CFA Program\". Therefore, Boucault did not violate Standard VII (B), Reference to CFA Institute, the CFA Designation, and the CFA Program.\nB Incorrect because Boucault has used an approved format for referencing her candidacy in the CFA Program.\nC Incorrect because Boucault has not revealed confidential information about the examination."},
  {"num": 67, "subject": "职业道德", "question": "Bertram Kendall, CFA, is an investment advisor at a bank. Kendall plans to teach an economics course at a local university in his spare time, for which he will be paid a fee by the university. In addition, Kendall plans to serve as an investment advisor for the endowment fund of a community center. Kendall will not be paid by the community center but will be given free access to its athletic facilities, which normally charge fees, in return for his services. According to the Standards, Kendall is required to obtain written consent from his employer:", "options": {"A": "only for teaching the economics course.", "B": "only for serving as an advisor for the community center endowment.", "C": "both for teaching the economics course and for serving as an advisor for the community center endowment."}, "answer": "B", "explanation": "A Incorrect because Standard IV (B), Additional Compensation Arrangements, requires members and candidates to obtain permission from their employer before accepting compensation or other benefits from third parties for the services rendered to the employer or for any services that might create a conflict with their employer's interest. Teaching an economics course during non-work hours creates no conflict for an investment advisor.\nB Correct because Standard IV (B), Additional Compensation Arrangements, requires members and candidates to obtain permission from their employer before accepting compensation or other benefits from third parties for the services rendered to the employer or for any services that might create a conflict with their employer's interest. Compensation and benefits include direct compensation by the client and any indirect compensation or other benefits received from third parties. Kendall performs an investment service as an advisor to the endowment that conflicts with his employer's interest. Further, free access to the athletic facilities amounts to indirect compensation from third parties. Therefore, Kendall must obtain written consent from his employer for serving as a consultant for the endowment of a community center.\nC Incorrect because Kendall is required to obtain written consent only for serving as an advisor for the community center endowment, as explained above."},
  {"num": 68, "subject": "职业道德", "question": "Mark Monroe, CFA, is an equity analyst at an investment firm. In his spare time, he performs accounting work for his local sports club in return for the club waiving his membership fees and paying his expenses to attend club social events. Monroe does not disclose either the work or the compensation to his employer. Has Monroe most likely violated the Standards?", "options": {"A": "No", "B": "Yes, the Standard relating to loyalty", "C": "Yes, the Standard relating to additional compensation agreements"}, "answer": "A", "explanation": "A Correct because Monroe did not violate the Standards. Standard IV (A), Loyalty, requires members and candidates to protect the interests of their firms by refraining from any conduct that would injure the firm, deprive it of profit, or deprive it of the member's or candidate's skills and ability. The Standard also requires that members and candidates abstain from independent competitive activity that could conflict with the interests of their employer. Working as an accountant for his sports club does not represent competitive activity, and Monroe does this work in his spare time, so it does not deprive his employer of his skills and abilities. Thus, Monroe has not violated this Standard. Standard IV (B), Additional Compensation Arrangements, states that members and candidates must not accept gifts, benefits, compensation, or consideration that competes with or might reasonably be expected to create a conflict of interest with their employer's interest unless they obtain written consent from all parties involved. Because Monroe's outside work is for a local sports club, and not a competitor, there is no conflict of interest with his employer. Therefore, Monroe is not required to disclose it or receive consent from his employer for the compensation. Thus, there is no violation of Standard IV (B).\nB Incorrect because Monroe did not violate Standard IV (A), as described in the Response Rationale for the correct answer.\nC Incorrect because Monroe did not violate Standard IV (B), as described in the Response Rationale for the correct answer."},
  {"num": 69, "subject": "职业道德", "question": "With respect to the Standard relating to suitability, members who are portfolio managers for a mutual fund are required to:", "options": {"A": "consider clients' circumstances and objectives before investing.", "B": "manage the fund in a manner consistent with the fund's mandate.", "C": "gather information related to investors' taxes and other investment constraints."}, "answer": "B", "explanation": "A Incorrect because according to Standard III (C), Suitability, Members and Candidates who manage pooled assets to a specific mandate are not responsible for determining the suitability of the fund as an investment for investors who may be purchasing shares in the fund. The responsibility for determining the suitability of an investment for clients can be conferred only on members and candidates who have an advisory relationship with clients. Therefore, members who are portfolio managers for a mutual fund are not required to consider clients' circumstances before investing.\nB Correct because Standard III (C), Suitability, states that some Members and Candidates do not manage money for individuals but are responsible for managing a fund to an index or an expected mandate. The responsibility of these members and candidates is to invest in a manner consistent with the stated mandate. For example, a member or candidate who serves as the fund manager for a large-cap income fund would not be following the fund mandate by investing heavily in small-cap or start-up companies whose stock is speculative in nature. Therefore, members who are portfolio managers for a mutual fund are required to manage the fund in a manner consistent with the fund's mandate.\nC Incorrect because according to Standard III (C), Suitability, Members and Candidates who manage pooled assets to a specific mandate are not responsible for determining the suitability of the fund as an investment for investors who may be purchasing shares in the fund. The responsibility for determining the suitability of an investment for clients can be conferred only on members and candidates who have an advisory relationship with clients. Therefore, members who are portfolio managers for a mutual fund are not required to gather information related to investors' taxes and other investment constraints."},
  {"num": 70, "subject": "职业道德", "question": "Kate Clark, CFA, and Tom Matt, CFA, have a referral arrangement between them. Clark directs equity clients to Matt. In return, Matt refers fixed income clients to Clark. Matt and Clark both disclose the details of the arrangement to their existing clients. However, only Clark discloses the referral arrangement to her prospective clients. Have the Standards most likely been violated?", "options": {"A": "No", "B": "Yes, by Matt", "C": "Yes, by Clark"}, "answer": "B", "explanation": "A Incorrect because Standard VI (C), Referral Fees, is violated by Matt, as described in the response rationale for the correct answer.\nB Correct because Standard VI (C), Referral Fees, states that Members and Candidates must disclose to their employer, clients and prospective clients, as appropriate, any compensation, consideration, or benefit received from or paid to others for the recommendation of products or services. Only Matt has violated the Standard because he fails to disclose the referral arrangement to his prospective client.\nC Incorrect because Standard VI (C), Referral Fees, is violated by Matt only, as described in the response rationale for the correct answer. Clark does not violate the Standard because she discloses the referral arrangement to both her current and prospective client."},
  {"num": 71, "subject": "职业道德", "question": "Anna Schulz, CFA, works for an investment firm. She enters into an arrangement with an independent tax advisor to prepare Schulz’s personal tax returns free of charge in exchange for Schulz referring her clients to the tax advisor. According to the Standards, Schulz is required to disclose her arrangement with the tax advisor to:", "options": {"A": "her clients only.", "B": "her employer only.", "C": "both her clients and her employer."}, "answer": "C", "explanation": "A Incorrect because according to Standard VI (C) Referral Fees, Schultz must disclose the referral fee arrangement to her clients and her employer, as described in the response rationale for the correct answer.\nB Incorrect because according to Standard VI (C) Referral Fees, Schultz must disclose the referral fee arrangement to her employer and her clients, as described in the response rationale for the correct answer.\nC Correct because according to Standard VI (C) Referral Fees, Members and Candidates must disclose to their employer, clients, and prospective clients, as appropriate, any compensation, consideration, or benefit received from or paid to others for the recommendation of products or services. Preparing a tax return free of charge falls within the scope of “any compensation, consideration, or benefit.” Therefore, Schultz must disclose the referral fee arrangement to her clients and her employer."},
  {"num": 72, "subject": "职业道德", "question": "Vikram Shah, CFA, is a wealth manager with AZ Bank (AZ). Shah refers his client, Sean Tan, to the investment banking division of AZ as Tan is considering taking his company public. AZ's policy is to pay its employees a fee for referrals. According to the Standards, Shah is:", "options": {"A": "required to decline the referral fees because Tan is an existing client of AZ.", "B": "not required to disclose the referral fee arrangement to Tan because the referral fee is an interdepartmental incentive payment.", "C": "required to disclose the referral fee arrangement to Tan at the time of referral to allow Tan to evaluate the full cost of the investment banking service."}, "answer": "C", "explanation": "A Incorrect because Standard VI(C), Referral Fees, does not specify that a candidate or member must not accept a referral fee. Instead, Standard VI(C) states the responsibility of members and candidates to inform their employer, clients, and prospective clients of any benefit received for referrals of customers and clients. As described in the rationale for the correct answer, Shah can accept the fee but must disclose the fee arrangement at the time of the referral.\nB Incorrect because Standard VI(C), Referral Fees, states the responsibility of members and candidates to inform their employer, clients, and prospective clients of any benefit received for referrals of customers and clients. Further, Standard VI (C) does not distinguish between referral payments paid by a third party for referring clients to the third party and internal payments paid within the firm to attract new business to a subsidiary. Members and candidates must disclose all such referral fees at the time of referral. Therefore, Shah must disclose the fee arrangement to Tan even though it is an interdepartmental referral arrangement.\nC Correct because according to Standard VI(C), Referral Fees, Members and Candidates must disclose to their employer, clients, and prospective clients, as appropriate, any compensation, consideration, or benefit received from or paid to others for the recommendation of products or services. Such disclosures allow clients to evaluate (1) any partiality shown in any recommendation of services and (2) the full cost of the services. Appropriate disclosure means that members must advise the client or prospective client, before entry into any formal agreement for services, of any benefit received for the recommendation of any services provided by the member."},
  {"num": 73, "subject": "职业道德", "question": "According to the Standard relating to suitability, a member is required to do which of the following?", "options": {"A": "Judge the suitability of an investment in the context of the client's total portfolio", "B": "Update a client's investment policy statement as soon as possible after making any changes to recommendations for the client", "C": "Both judge the suitability of an investment in the context of the client's total portfolio and make a reasonable inquiry into a client's investment experience only after taking investment action."}, "answer": "A", "explanation": "A Correct because Standard III (C), Suitability, states that when members and candidates are in an advisory relationship with a client, they must judge the suitability of an investment in the context of the client's total portfolio.\nB Incorrect because Standard III (C), Suitability, states that when members and candidates are in an advisory relationship with a client, they must make a reasonable inquiry into a client's or prospective client's investment experience, risk and return objectives, and financial constraints prior to [not after] making any investment recommendation.\nC Incorrect because it is a violation of Standard III (C), Suitability, to update a client's investment policy statement after making any changes to recommendations for the client."},
  {"num": 74, "subject": "职业道德", "question": "Chris Taylor, CFA, is an investment advisor with Zenith Advisors (ZA). ZA maintains a list of recommended equity securities and purchases newly rated securities for all clients in block transactions. Taylor has just gained a new client who has an existing equity portfolio. Before their first meeting, Taylor reallocates the portfolio in accordance with the firm's recommended equity list without gathering additional information from the client. Taylor most likely violated the Standard(s) relating:", "options": {"A": "only to suitability.", "B": "only to fair dealing.", "C": "both to suitability and to fair dealing."}, "answer": "A", "explanation": "A Correct because Standard III (C), Suitability, requires members to make a reasonable inquiry into a client's or prospective client's investment experience, risk and return objectives, and financial constraints prior to making any investment recommendation or taking investment action and must reassess and update this information regularly. Also, members must determine that an investment is suitable to the client's financial situation and consistent with the client's written objectives, mandates, and constraints before making an investment recommendation or taking investment action. The fact that the client brought an all-equity portfolio to the relationship is not enough to indicate suitability for the client, thus Taylor violated the Standard.\nB Incorrect because Standard III (B), Fair Dealing, requires members to treat all clients fairly when providing investment analysis, making investment recommendations, taking investment action, or engaging in other professional activities. Because the client is new, there is no evidence that investment action was taken unfairly.\nC Incorrect because Taylor violated the Standard relating to suitability but not the Standard relating to fair dealing."},
  {"num": 75, "subject": "职业道德", "question": "Martha Ray, CFA, manages a portfolio based on an \"Environment Social Governance\" (ESG) style of investing. Ray is also an environmental activist. She is arrested for civil disobedience while participating in a government-authorized nonviolent protest against a company that is accused of damaging the environment. Has Ray most likely violated the Standards?", "options": {"A": "No", "B": "Yes, the Standard relating to misconduct", "C": "Yes, the Standard relating to loyalty, prudence, and care"}, "answer": "A", "explanation": "A Correct because Standard I (D), Misconduct, is not meant to cover legal transgressions resulting from acts of civil disobedience in support of personal beliefs because such conduct does not reflect poorly on the member's or candidate's professional reputation, integrity, or competence. Ray is arrested for civil disobedience in a government-authorized nonviolent protest. Therefore, Ray has not violated Standard I (D). Further, according to Standard III (A), Loyalty, Prudence, and Care, a member's or candidate's responsibility to a client includes a duty of loyalty and a duty to exercise reasonable care. Investment actions must be carried out for the sole benefit of the client and in a manner the member or candidate believes, given the known facts and circumstances, to be in the best interest of the client. There is no reason to believe that Ray has not exercised reasonable care while taking investment actions for her clients. Therefore, Ray has not violated either Standard I (D) or Standard III (A).\nB Incorrect because being arrested for an act of civil disobedience does not reflect poorly on a member's professional reputation, integrity, or competence. Therefore, Ray has not violated Standard I (D), Misconduct.\nC Incorrect because Ray has not violated Standard III (A), Loyalty, Prudence, and Care, as there is no reason to believe that Ray has not exercised reasonable care while taking investment actions for her clients."},
  {"num": 76, "subject": "职业道德", "question": "According to the Standards, when presenting performance results, members should encourage their firms to:", "options": {"A": "disclose whether the results are before or after tax.", "B": "exclude terminated accounts as part of performance history.", "C": "present the results using the most representative single account."}, "answer": "A", "explanation": "A Correct because according to the recommended procedures for compliance with Standard III (D), Performance Presentation, Members and candidates can also meet their obligations under Standard III (D) by including disclosures that fully explain the performance results being reported (for example, disclosing whether the performance is gross of fees, net of fees, or after tax). Therefore, Standard III (D) recommends that members encourage their firms to disclose whether the performance results are before or after tax.\nB Incorrect because according to the recommended procedures for compliance with Standard III (D), Performance Presentation, Members and candidates can also meet their obligations under Standard III (D) by including terminated accounts as part of performance history with a clear indication of when the accounts were terminated. Therefore, Standard III (D) recommends that members encourage their firms to include, not exclude, terminated accounts as part of performance history.\nC Incorrect because according to the recommended procedures for compliance with Standard III (D), Performance Presentation, Members and candidates can also meet their obligations under Standard III (D) by presenting the performance of the weighted composite of similar portfolios rather than using a single representative account. Therefore, Standard III (D) recommends that members encourage their firms to present the results using weighted composite, not the most representative single account."},
  {"num": 77, "subject": "职业道德", "question": "A member is in violation of the Standard relating to market manipulation if he:", "options": {"A": "frequently trades two stocks to exploit market inefficiencies.", "B": "secures a controlling position in a company's stock to exploit a potential acquisition of the company.", "C": "issues a report exaggerating negative aspects of a company with the intent to drive down its share price."}, "answer": "C", "explanation": "A Incorrect because Standard II (B), Market Manipulation, is not intended to preclude transactions undertaken on legitimate trading strategies based on perceived market inefficiencies.\nB Incorrect because according to Standard II (B), Market Manipulation, transaction-based manipulation includes securing a controlling, dominant position in a financial instrument to exploit and manipulate the price of a related derivative and/or the underlying asset. The intent of the action is critical to determining whether it is a violation of this Standard. In this instance, the member's intent is not to exploit or manipulate the stock price, but merely to exploit a business development in the form of a potential acquisition of the company. Thus, his actions are not in violation of Standard II (B).\nC Correct because according to Standard II (B), Market Manipulation, Members and Candidates must not engage in practices that distort prices or artificially inflate trading volume with the intent to mislead market participants. The member engages in information-based manipulation by issuing a misleading report—one that exaggerates negative aspects of a company, to artificially distort (drive down) the company's share price. He has thus violated Standard II (B)."},
  {"num": 78, "subject": "职业道德", "question": "Several years ago, a member purchased a large position in a small-cap stock for her own account. The member is unable to sell the entire position due to the stock’s limited liquidity. To improve liquidity, the member trades the stock between two client accounts before selling her own position. The member has engaged in:", "options": {"A": "transaction-based manipulation only.", "B": "information-based manipulation only.", "C": "both transaction-based manipulation and information-based manipulation."}, "answer": "A", "explanation": "A Correct because according to Standard II (B), Market Manipulation, transaction-based manipulation includes artificially affecting prices or volume to give the impression of activity or price movement, which the member did.\nB Incorrect because information-based manipulation entails spreading false rumors to induce trading by others, which the member did not do.\nC Incorrect because the member engaged in transaction-based manipulation, but not information based."},
  {"num": 79, "subject": "职业道德", "question": "To comply with the Standards, if a member is offered a paid position in addition to his current position that may conflict with his employer's interests, he is most likely required to:", "options": {"A": "decline the position.", "B": "notify his employer in writing before accepting the position.", "C": "obtain written consent from all parties involved before accepting the position."}, "answer": "C", "explanation": "A Incorrect because according to Standard IV (B), Additional Compensation Arrangements, a member may accept a position that competes with, or is in conflict with, his employer's interest for compensation as long as there is written consent from all parties involved, as described in the Response Rationale for the correct answer. The member is not required to decline the position.\nB Incorrect because according to Standard IV (B), Additional Compensation Arrangements, written notification to the employer is not enough to comply with the Standards before accepting a paid position in potential conflict with the interest of the member's employer. In order to comply, the member is required to obtain written permission from all parties involved.\nC Correct because according to Standard IV (B), Additional Compensation Arrangements, Members and Candidates must not accept gifts, benefits, compensation, or consideration that competes with or might reasonably be expected to create a conflict of interest with their employer's interest unless they obtain written consent from all parties involved."},
  {"num": 80, "subject": "职业道德", "question": "A member receives an offer of compensation from a third party that might create a conflict of interest with the member's employer. According to the Standard relating to additional compensation arrangements, the member is most likely required to:", "options": {"A": "refuse the offer.", "B": "only disclose the offer to the employer.", "C": "obtain written consent from all parties involved prior to accepting the offer."}, "answer": "C", "explanation": "A Incorrect because according to Standard IV (B), Additional Compensation Arrangements, if a member receives an offer of compensation from a third party that might create a conflict of interest with the member's employer, the member must obtain written consent from all parties involved, as described in the response rationale for the correct answer. The member need not refuse the offer.\nB Incorrect because according to Standard IV (B), Additional Compensation Arrangements, if a member receives an offer of compensation from a third party that might create a conflict of interest with the member's employer, the member must obtain written consent from all parties involved, as described in the response rationale for the correct answer. Therefore, the member should not only disclose the offer to the employer, but should also obtain written consent from the third party making such offer.\nC Correct because according to Standard IV (B), Additional Compensation Arrangements, Members and Candidates must not accept gifts, benefits, compensation, or consideration that competes with or might reasonably be expected to create a conflict of interest with their employer's interest unless they obtain written consent from all parties involved."},
  {"num": 81, "subject": "职业道德", "question": "Tom Oak, CFA, is an advisor to high-net-worth individuals. The risk tolerances of Oak's clients range from conservative to aggressive. He recommends an equity mutual fund which the prospectus describes as a “high-growth and high-risk vehicle.” Oak observes that the volatility of the fund's price has been very low over the past three quarters. He therefore recommends investing a large proportion of each client's portfolio in the fund, citing the low volatility and excellent return potential. Oak has most likely violated the Standard(s) relating:", "options": {"A": "only to suitability.", "B": "only to misrepresentation.", "C": "both to suitability and to misrepresentation."}, "answer": "C", "explanation": "A Incorrect because both the Standard relating to suitability and the Standard relating to misrepresentation are violated, as described in the Response Rationale for the correct answer.\nB Incorrect because both the Standard relating to suitability and the Standard relating to misrepresentation are violated, as described in the Response Rationale for the correct answer.\nC Correct because according to Standard III (C), Suitability, When Members and Candidates are in an advisory relationship with a client, they must make a reasonable inquiry into a client's or prospective client's investment experience, risk and return objectives, and they must determine that an investment is suitable to the client's financial situation and consistent with the client's written objectives, mandates, and constraints. By recommending to invest a large portion of the portfolio in this high-risk investment vehicle to clients with varying degrees of risk tolerance, and not only to clients with a high degree of risk tolerance, Oak violated Standard III (C). According to Standard I (C), Misrepresentation, Members and Candidates must not knowingly make any misrepresentations relating to investment analysis, recommendations, actions, or other professional activities. Even though the recent history of the fund shows risk lower than described in the investment policy of the fund, lacking a change in the fund's policy, it is neither accurate, nor appropriate, to represent the fund as having a lower-risk profile than specified by the fund's policy. By representing the fund in this manner and misrepresenting the investment, Oak has violated Standard I (C)."},
  {"num": 82, "subject": "职业道德", "question": "Venture Energy Exchange (VEE) launches a new derivatives product on crude oil. The exchange's CEO, Adam Jaafar, CFA, enters into a confidential agreement with VEE's ten largest members, who commit to trading substantial minimum volumes of the new product in the first six months after its launch. The product's liquidity improves over the next five months. Jaafar is satisfied with the results and decides not to extend the confidential agreement once it expires. Has Jaafar violated the Standards?", "options": {"A": "No", "B": "Yes, the Standard relating to fair dealing", "C": "Yes, the Standard relating to market manipulation"}, "answer": "C", "explanation": "A Incorrect because Jaafar has violated Standard II (B), Market Manipulation, by entering into a confidential agreement with VEE's 10 largest members and not disclosing the strategy to all members, as described in the rationale for the correct answer.\nB Incorrect because according to Standard III (B), Fair dealing, Members and Candidates must deal fairly and objectively with all clients when providing investment analysis, making investment recommendations, taking investment action, or engaging in other professional activities. There is no information in the vignette to suggest that Jaafar has violated Standard III (B).\nC Correct because Jaafar's \"pump-priming\" strategy violates Standard II (B), Market Manipulation, which states that Members and Candidates must not engage in practices that distort prices or artificially inflate trading volume with the intent to mislead market participants. The formal liquidity of a market is determined by the obligations set on market makers, but the actual liquidity of a market is better estimated by the actual trading volume and bid–ask spreads. Attempts to mislead participants about the actual liquidity of the market constitute a violation of Standard II (B). In this example, investors have been intentionally misled to believe they chose the most liquid instrument for some specific purpose, but they could eventually see the actual liquidity of the contract significantly reduced after the term of the agreement expires. If Jaafar were to fully discloses its agreement with members to boost transactions over some initial launch period, he would not violate Standard II (B). Jaafar's intent is not to harm investors but, on the contrary, to give them a better service. For that purpose, he may engage in a liquidity-pumping strategy, but the strategy must be disclosed."},
  {"num": 83, "subject": "职业道德", "question": "Which of the following is a recommended procedure for compliance with the Standard relating to performance presentation? Members should encourage their firms to:", "options": {"A": "state, when applicable, that performance results are simulated.", "B": "use a representative account to present composite performance.", "C": "use identical performance presentation reports for all types of clients."}, "answer": "A", "explanation": "A Correct because recommended procedures for compliance with Standard III (D), Performance Presentation, include disclosures that fully explain the performance results being reported (for example, stating, when appropriate, that results are simulated when model results are used).\nB Incorrect because it contradicts recommended procedures for compliance with Standard III (D), Performance Presentation, which include presenting the performance of the weighted composite of similar portfolios rather than using a single representative account.\nC Incorrect because it contradicts recommended procedures for compliance with Standard III (D), Performance Presentation, which include considering the knowledge and sophistication of the audience to whom a performance presentation is addressed. Thus, the recommendation is not to use identical performance presentation reports for all types of clients but to use different reports for different types of clients."},
  {"num": 84, "subject": "职业道德", "question": "Adam Johnson, CFA, works at a large investment firm. After losing his taxi receipt for a business meeting, he uses his colleague’s taxi receipt of a slightly higher value to submit his monthly expense claim to his employer. Recently, Johnson declared personal bankruptcy due to large medical bills for a family member. Has Johnson violated the Standard relating to misconduct?", "options": {"A": "No", "B": "Yes, by submitting the expense claim", "C": "Yes, by declaring personal bankruptcy"}, "answer": "B", "explanation": "A Incorrect because Johnson has violated Standard I (D), Misconduct, as described in the response rationale for the correct answer.\nB Correct because Standard I (D), Misconduct, states that Members must not engage in any professional conduct involving dishonestly, fraud, or receipt or commit any act that reflects adversely on their professional reputation, integrity, or competence. By using a colleague’s taxi receipt of a higher value, Johnson engages in intentional conduct involving fraud and deceit in the work place that adversely reflects on his integrity.\nC Incorrect because the guidance under Standard I (D), Misconduct, states that personal bankruptcy may not reflect on the integrity or trustworthiness of the person declaring bankruptcy. Declaring personal bankruptcy due to large medical bills for a family member, which does not involve any fraudulent or deceitful business conduct, is not a Standard violation relating to misconduct."},
  {"num": 85, "subject": "职业道德", "question": "Michael Butcher, CFA, has recently joined Patriot Investments (PI) as an investment manager. With information gathered from public sources, Butcher re-creates supporting records from his former firm for investment recommendations at PI. Butcher also reviews client positions and routinely deletes records of the reviews that do not result in a change. Butcher has most likely violated the Standards:", "options": {"A": "only by deleting the reviews that do not result in a change.", "B": "only by re-creating supporting records for investment recommendations.", "C": "both by deleting the reviews that do not result in a change and by re-creating supporting records for investment recommendations."}, "answer": "A", "explanation": "A Correct because Standard V (C), Record Retention, states that the retention requirement applies to decisions to buy and sell a security as well as reviews undertaken that do not lead to a change in position.\nB Incorrect because Standard V (C), Record Retention, states that the member or candidate must re-create the supporting records at the new firm with information gathered through public sources or directly from the covered company and not from memory or sources obtained at the previous employer.\nC Incorrect because while Standard V (C), Record Retention, indicates that while failing to retain records of position reviews resulting in no change is a violation, as described in the rationale for the correct answer, re-creating supporting records from public sources is not a violation. The member or candidate must re-create the supporting records at the new firm with information gathered through public sources or directly from the covered company and not from memory or sources obtained at the previous employer."},
  {"num": 86, "subject": "职业道德", "question": "Ming Xu, CFA, is an investment advisor at Topnotch Advisors (TNA). Xu plans to leave TNA and start an independent advisory practice that would compete with TNA. Without notifying TNA of his plans, Xu makes preparations during non-working hours to start his independent practice. Has Xu most likely violated the Standards?", "options": {"A": "No", "B": "Yes, the Standard relating to loyalty", "C": "Yes, the Standard relating to disclosure of conflicts"}, "answer": "A", "explanation": "A Correct because Xu has not violated the Standards. According to Standard IV (A) Loyalty, a departing employee is generally free to make arrangements or preparations to go into a competitive business before terminating the relationship with his or her employer as long as such preparations do not breach the employee’s duty of loyalty. There is no evidence to believe that Xu’s action breaches her employer’s duty of loyalty. Therefore, Xu she has not violated the Standard IV (A). Further, according to Standard VI (A) Disclosure of Conflicts, Members and Candidates must make full and fair disclosure of all matters that could reasonably be expected to impair their independence and objectivity or interfere with respective duties to their clients, prospective clients, and employer. Reportable situations include conflicts that would interfere with rendering unbiased investment advice and conflicts that would cause a member or candidate to act not in the employer’s best interest. Xu only makes preparations during non-working hours to start her independent practice. Therefore, Xu has also not violated Standard VI (A).\nB Incorrect because Xu has not violated Standard IV (A), Loyalty, as described in the response rationale for the correct answer.\nC Incorrect because Xu has not violated Standard VI (A), Disclosure of Conflicts, as described in the response rationale for the correct answer."},
  {"num": 87, "subject": "职业道德", "question": "According to the Standards, members who are supervisors are most likely required to:", "options": {"A": "have in-depth knowledge of the Standards.", "B": "personally evaluate the conduct of all of their employees on a continuing basis.", "C": "report violations of the Standards by any employee under their supervision to CFA Institute."}, "answer": "A", "explanation": "A Correct because according to Standard IV (C), Responsibilities of Supervisors, Members and candidates acting as supervisors must also have in-depth knowledge of the Code and Standards so that they can apply this knowledge in discharging their supervisory responsibilities.\nB Incorrect because according to Standard IV (C), the conduct that constitutes reasonable supervision in a particular case depends on the number of employees supervised and the work performed by those employees. Members and candidates with oversight responsibilities for large numbers of employees may not be able to personally evaluate the conduct of these employees on a continuing basis. These members and candidates may delegate supervisory duties to subordinates who directly oversee the other employees. Members who are supervisors may delegate supervisory duties and are not required to personally evaluate each employee on a continuing basis.\nC Incorrect because according to Standard I (A), Knowledge of the Law, CFA Institute encourages members, nonmembers, clients, and the investing public to report violations of the Code and Standards by CFA Institute members or CFA candidates by submitting a complaint in writing to the CFA Institute Professional Conduct Program. Members are encouraged to report violations of the Code and Standard by members to CFA Institute, but it is not mandatory for supervisors."},
  {"num": 88, "subject": "职业道德", "question": "Anna Yeung, CFA, is a research analyst with TL Securities (TLS). TLS does not have a policy on record retention, and applicable law does not require retaining records. Yeung only retains her work records electronically and deletes records older than three years. Are Yeung’s actions consistent with the recommendations for compliance with the Standard relating to record retention?", "options": {"A": "Yes", "B": "No, because she only retains her work records electronically", "C": "No, because she deletes her records that are older than three years"}, "answer": "C", "explanation": "A Incorrect because Standard V (C), Record Retention, in the absence of regulatory guidance or firm policies, CFA Institute recommends maintaining records for at least seven years. Thus, she should have kept the records longer.\nB Incorrect because according to Standard V (C), Record Retention, records may be maintained either in hard copy or electronic form.\nC Correct because according to Standard V (C), Record Retention, in the absence of regulatory guidance or firm policies, CFA Institute recommends maintaining records for at least seven years. Since she deletes records that are older than three years she is not consistent with the Standard relating to record retention."},
  {"num": 89, "subject": "职业道德", "question": "Patrick Tam, CFA, is a chemicals industry analyst for an investment firm. The president of Naxos Chemicals (Naxos) asks Tam to provide customized reports on global industry trends in return for free travel and accommodations for the Naxos annual shareholder meeting. To comply with the Standards, Tam is most likely required:", "options": {"A": "only to fully disclose the arrangement with Naxos to all of the firm's clients.", "B": "only to obtain written permission from his employer before accepting the offer from Naxos.", "C": "both to fully disclose the arrangement with Naxos to all of the firm's clients and to obtain written permission from his employer before accepting the offer from Naxos."}, "answer": "C", "explanation": "A Incorrect because Tam is also required to obtain written permission from his employer before accepting the offer from Naxos, as described in the Response Rationale for the correct answer.\nB Incorrect because Tam is also required to fully disclose arrangement with Naxos to all of the firm's clients, as described in the Response Rationale for the correct answer.\nC Correct because according to Standard VI (A), Avoid or Disclose Conflicts, the most obvious conflicts of interest, which should always be disclosed, are relationships between an issuer and the member, the candidate, or his or her firm (such as a directorship or consultancy by a member. Although the compensation Tam would receive for the industry reports is relatively meager, there would be a separate relationship with a firm he covers, which must be disclosed. In addition, according to Standard IV (B), Additional Compensation Arrangements, Members and candidates must not accept gifts, benefits, compensation, or consideration that competes with or might reasonably be expected to create a conflict of interest with their employer's interest unless they obtain written consent from all parties involved. Writing special reports for a company the analyst is following would reasonably be construed as creating a conflict of interest with the employer because Tam would be expected to write industry reports for his employer as the chemicals industry analyst."},
  {"num": 90, "subject": "职业道德", "question": "To be consistent with the Standard relating to record retention, a member should maintain records of which of the following?\nItem 1: A change in recommendation posted on social media.\nItem 2: Reviews of materials that do not lead to a change in recommendation.", "options": {"A": "Item 1 only", "B": "Item 2 only", "C": "Both Item 1 and Item 2"}, "answer": "C", "explanation": "A Incorrect because according to Standard V (C), Record Retention, reviews that do not lead to a change in recommendation also should be maintained as records, as described in the response rationale for the correct answer.\nB Incorrect because according to Standard V (C), Record Retention, recommendations posted on social media should be maintained as records, as described in the response rationale for the correct answer.\nC Correct because according to Standard V (C), Record Retention, the nature or format of the information does not remove a member's or candidate's responsibility to maintain a record of information used in his or her analysis or communicated to clients. Examples of nonprint media formats that should be retained include, but are not limited to blog posts and Twitter posts. The retention requirement applies to decisions to buy or sell a security as well as reviews undertaken that do not lead to a change in position."},
  {"num": 91, "subject": "职业道德", "question": "According to the recommended procedures for compliance with the Standard relating to responsibilities of supervisors, members should encourage their firms to:", "options": {"A": "continually educate personnel regarding all of the firm's compliance procedures.", "B": "separate employees' professional conduct evaluations from their performance reviews.", "C": "integrate the firm's compliance procedures into its code of ethics to provide a comprehensive document."}, "answer": "A", "explanation": "A Correct because recommended procedures for compliance with Standard IV (C), Responsibilities of Supervisors, state that once a compliance program is in place, a supervisor should continually educate personnel regarding the compliance procedures.\nB Incorrect because recommended procedures for compliance with Standard IV (C), Responsibilities of Supervisors, state that once a compliance program is in place, a supervisor should incorporate a professional conduct evaluation as part of an employee's performance review. Thus the recommendation is to integrate rather than separate employees' professional conduct evaluations and their performance reviews.\nC Incorrect because recommended procedures for compliance with Standard IV (C), Responsibilities of Supervisors, state that mingling compliance procedures in the firm's code of ethics goes against the goal of reinforcing the ethical obligations of employees. Thus the recommendation is to keep the firm's code of ethics and its compliance procedures separate rather than to integrate them into one document."},
  {"num": 92, "subject": "职业道德", "question": "In the absence of regulations or firm policies, the Standards recommend retaining investment-related records for a minimum of:", "options": {"A": "five years.", "B": "seven years.", "C": "ten years."}, "answer": "B", "explanation": "A Incorrect because Standard V (C), Record Retention, states that in the absence of regulatory guidance or firm policies, CFA Institute recommends maintaining records for at least seven years, not five years.\nB Correct because Standard V (C), Record Retention, states that in the absence of regulatory guidance or firm policies, CFA Institute recommends maintaining records for at least seven years.\nC Incorrect because Standard V (C), Record Retention, states that in the absence of regulatory guidance or firm policies, CFA Institute recommends maintaining records for at least seven years, not ten years."},
  {"num": 93, "subject": "职业道德", "question": "A candidate taking the CFA Level II exam develops an analytical model while working as an unpaid intern at a brokerage firm. Before completing her internship, the candidate copies supporting documents used to create the model with an intention to recreate the model at a new firm she expects to join soon. Has the candidate violated the Standards?", "options": {"A": "No", "B": "Yes, the Standard relating to record retention only", "C": "Yes, the Standard relating to record retention and the Standard relating to loyalty"}, "answer": "C", "explanation": "A Incorrect because the candidate violated the Standard relating to record retention and the Standard relating to loyalty, as described below in the Response Rationale for the correct answer.\nB Incorrect because the candidate violated the Standard relating to record retention and the Standard relating to loyalty, as described below in the Response Rationale for the correct answer.\nC Correct because Standard V(C), Record Retention, states that as a general matter, records created as part of a member’s or candidate’s professional activity on behalf of his or her employer are the property of the firm. When a member or candidate leaves a firm to seek other employment, the member or candidate cannot take the property of the firm, including original forms or copies of supporting records of the member’s or candidate’s work, to the new employer without the express consent of the previous employer. The candidate cannot copy the supporting documents without the consent of the current employer. Therefore, the candidate has violated the Standard V(C)."},
  {"num": 94, "subject": "职业道德", "question": "Disclosures about the use of leverage, sector or industry risk, and security-specific risk are most likely included in the Standard relating to:", "options": {"A": "independence and objectivity.", "B": "responsibilities of supervisors.", "C": "communication with clients and prospective clients."}, "answer": "C", "explanation": "A Incorrect because discussions about leverage, sector or industry risk, and security-specific risk are not included in the guidance for Standard I (B), Independence and Objectivity, which states that Members must use reasonable care and judgment to achieve and maintain independence and objectivity in their professional activities. Members and Candidates must not offer, solicit, or accept any gift, benefit, compensation, or consideration that reasonably could be expected to compromise their own or another’s independence and objectivity.\nB Incorrect because discussions about leverage, sector or industry risk, and security-specific risk are not included in the guidance for Standard IV (C), Responsibilities of Supervisors, which requires that Members must make reasonable efforts to ensure that anyone subject to their supervision or authority complies with applicable laws, rules, regulations, and the Code and Standards.\nC Correct because discussions about leverage, sector or industry risk, and security-specific risk are included in the guidance for Standard V (B), Communication with Clients and Prospective Clients. This Standard states that Members must outline to clients and prospective clients significant risks and limitations of the analysis contained in their investment products or recommendations. This includes but is not limited to the use of leverage, sector or industry risk, and security-specific risk. The type and nature of significant risks will depend on the investment process that members are following and on the personal circumstances of the client. In general, the use of leverage constitutes a significant risk and should be disclosed."},
  {"num": 95, "subject": "职业道德", "question": "Agnes Dupy, CFA, manages discretionary accounts at a large brokerage firm. She finds a suitable set of the firm's proprietary equity mutual funds for one of her clients. Dupy's firm is awarding a special quarterly bonus to managers who use one of the highest-fee funds on the list of suitable funds, so she invests in that fund for her client without contacting the client. Dupy has most likely violated the Standard(s) relating:", "options": {"A": "only to fair dealing.", "B": "only to avoid or disclose conflicts.", "C": "both to fair dealing and to avoid or disclose conflicts."}, "answer": "B", "explanation": "A Incorrect because Standard III (B), Fair Dealing, addresses fair dealing of securities allocations, investments and trades among a CFA charterholder's clients as well as seeking to ensure that the charterholder does not take advantage of their position in the industry to the detriment of clients in terms of allocations of trades or initial public offerings. There is no indication in this scenario that Dupy has favored another client or herself in allocating trades.\nB Correct because Standard VI (A), Avoid or Disclose Conflicts, states that the Standard protects investors and employers by requiring members and candidates to fully disclose to clients, potential clients, and employers all actual and potential conflicts of interest. Dupy violated the standard by not disclosing the special bonus for the chosen fund.\nC Incorrect because Dupy did not violate Standard III (B), Fair Dealing, as she did not take advantage of her position to the detriment of clients. She violated only Standard VI (A), Avoid or Disclose Conflicts, by not disclosing the special bonus."},
  {"num": 96, "subject": "职业道德", "question": "Which of the following examples is most likely a violation of the Standards? A member who is a supervisor:", "options": {"A": "delegates supervisory duties to subordinates who oversee other employees.", "B": "relies on an employee's statement that previous wrongdoing will not reoccur and takes no additional steps.", "C": "fails to detect all violations, although the member has taken reasonable steps to implement an effective compliance program."}, "answer": "B", "explanation": "A Incorrect because according to Standard IV (C), members may delegate supervisory duties to subordinates who directly oversee the other employees. A supervisor, depending on the circumstances, may not be able to personally monitor all his subordinates. In such cases, he may delegate his supervisory duty to subordinates who directly oversee other employees without violating the Standard.\nB Correct because according to Standard IV (C), Responsibilities of Supervisors, once a supervisor learns that an employee has violated or may have violated the law or the Code and Standards, the supervisor must promptly initiate an assessment to determine the extent of the wrongdoing. Relying on an employee's statements about the extent of the violation or assurances that the wrongdoing will not reoccur is not enough. A supervisor should take steps to ensure that the violation will not be repeated. A supervisor must make sure that such violation will not reoccur.\nC Incorrect because according to Standard IV (C), if a member has adopted reasonable procedures and taken steps to institute an effective compliance program, then the member may not be in violation of Standard IV(C) if he or she does not detect violations that occur despite these efforts."},
  {"num": 97, "subject": "职业道德", "question": "A candidate posts questions from the most recent CFA exam in an online forum. This action is a violation of the Standard(s) relating:", "options": {"A": "to preservation of confidentiality only.", "B": "to conduct as participants in CFA Institute programs only.", "C": "both to preservation of confidentiality and to conduct as participants in CFA Institute programs."}, "answer": "B", "explanation": "A Incorrect because Standard III(E), Preservation of Confidentiality, requires that members and candidates preserve the confidentiality of information communicated to them by their clients, prospective clients, and former clients. This Standard does not apply to the confidentiality of the CFA exam.\nB Correct because Standard VII(A), Conduct as Participants in CFA Institute Programs, states CFA Institute program rules, regulations, and policies prohibit candidates from disclosing confidential material gained during the exam process. Examples of information that cannot be disclosed by candidates sitting for an exam include but are not limited to specific details of questions appearing on the exam.\nC Incorrect because only Standard VII(A), Conduct as Participants in CFA Institute Programs, requires the member to keep information from the exam process confidential, as stated in the rationale for the correct answer."},
  {"num": 98, "subject": "职业道德", "question": "According to the Standard relating to responsibilities of supervisors, a member who cannot discharge supervisory responsibilities due to his firm’s inadequate compliance system should:", "options": {"A": "decline in writing to accept supervisory responsibility only.", "B": "report the inadequate compliance system to the CFA Institute only.", "C": "both decline in writing to accept supervisory responsibility and report the inadequate compliance system to the CFA Institute."}, "answer": "A", "explanation": "A Correct because according to Standard IV(C), responsibilities of supervisors, if the member or candidate clearly cannot discharge supervisory responsibilities because of the absence of a compliance system or because of an inadequate compliance system, the member or candidate should decline in writing to accept supervisory responsibility until the firm adopts reasonable procedures to allow adequate exercise of supervisory responsibility.\nB Incorrect because Standard IV(C), responsibilities of supervisors, does not require a member to report his firm’s inadequate compliance system to the CFA Institute. In particular, the CFA Institute requires that CFA Institute members and candidates enrolled in the CFA Program are required to comply with the Code and Standards.\nC Incorrect because Standard IV(C), responsibilities of supervisors, does not require a member to report his firm’s inadequate compliance system to the CFA Institute."},
  {"num": 99, "subject": "职业道德", "question": "Which of the following Standards states that members must not commit any act that reflects adversely on their professional reputation, integrity, or competence? The Standard relating to:", "options": {"A": "fair dealing", "B": "misconduct", "C": "loyalty, prudence, and care"}, "answer": "B", "explanation": "A Incorrect because according to Standard III (B), Fair Dealing, Members and Candidates must deal fairly and objectively with all clients when providing investment analysis, making investment recommendations, taking investment actions, or engaging in other professional activities. Standard III (B) does not address members’ responsibility to not commit any act that reflects adversely on their professional reputation, integrity, or competence.\nB Correct because according to Standard I (D), Misconduct, Members and Candidates must not engage in any professional conduct involving dishonesty, fraud, or deceit or commit any act that reflects adversely on their professional reputation, integrity, or competence.\nC Incorrect because according to Standard III (A), Loyalty, Prudence, and Care, Members and Candidates have a duty of loyalty to their clients and must act with reasonable care and exercise prudent judgment. Members and Candidates must act for the benefit of their clients and place their clients’ interests before their employer’s or their own interests. Standard III (A) does not address members’ responsibility to not commit any act that reflects adversely on their professional reputation, integrity, or competence."},
  {"num": 100, "subject": "职业道德", "question": "Anna Schulz, CFA, is a securities analyst. When she joined her firm, Schulz's manager, Zhang Feng, CFA, informed her only that “the CFA Institute Code and Standards pretty much cover the company's compliance rules.” In her personal account, Schulz holds a large position in a company that she recommends for purchase to clients. Schulz does not report this holding to her firm or clients. The Standards were most likely violated:", "options": {"A": "only by Zhang.", "B": "only by Schulz.", "C": "both by Zhang and by Schulz."}, "answer": "C", "explanation": "A Incorrect because both Zhang and Schulz violated the Standards, as described in the Response Rationale for the correct answer.\nB Incorrect because both Zhang and Schulz violated the Standards, as described in the Response Rationale for the correct answer.\nC Correct because according to Standard IV (C), Responsibilities of Supervisors, Members and Candidates must promote actions by all employees under their supervision and authority to comply with applicable laws, rules, regulations, and firm policies and the Code and Standards. At a minimum, Standard IV(C) requires that members and candidates with supervisory responsibility make reasonable efforts to prevent and detect violations by ensuring the establishment of effective compliance systems. To be effective supervisors, members and candidates should implement education and training programs on a recurring or regular basis for employees under their supervision. Such programs will assist the employees with meeting their professional obligations to practice in an ethical manner within the applicable legal system. Therefore, by not thoroughly explaining to Schulz or training Schulz in requirements for compliance with applicable laws, rules, regulations, and firm policies, and by not employing/ implementing an effective compliance system, Zhang violated this Standard. In addition, Schulz violated Standard VI (A), Avoid or Disclose Conflicts, which protects investors and employers by requiring members and candidates to fully disclose to clients, potential clients, and employers all actual and potential conflicts of interest. Also, sell-side members and candidates must disclose any materially beneficial ownership interest in a security or other investment that the member or candidate is recommending. By not disclosing that Schulz holds a large position in a company that she recommends for purchase to clients, Schulz is in violation of Standard VI (A)"},
  {"num": 101, "subject": "职业道德", "question": "Rayan Tengku, CFA, manages an equity fund. When talking to potential investors, Tengku presents the fund's average historical performance as the minimum performance investors can expect over the next year. After releasing the most recent quarterly fund report, Tengku finds an error in the report. He immediately sends the corrected report to all clients by e-mail and then calls only those clients who pay for premium services to discuss the report. Tengku has most likely violated the Standard(s) relating:", "options": {"A": "only to fair dealing.", "B": "only to performance presentation.", "C": "both to fair dealing and to performance presentation."}, "answer": "B", "explanation": "A Incorrect because according to Standard III (B), Fair Dealing, the term ‘fairly' implies that the member or candidate must take care not to discriminate against any clients when disseminating investment recommendations or taking investment action. Standard III(B) does not state ‘equally' because members and candidates could not possibly reach all clients at exactly the same time. In addition, members and candidates may provide more personal, specialized, or in-depth service to clients who are willing to pay for premium services through higher management fees or higher levels of brokerage. Therefore, Tengku has not violated Standard III (B) by additionally calling premium clients who pay higher fees since he had already distributed the corrected report to all clients by e-mail before calling his premium clients.\nB Correct because Standard III (D), Performance Presentation, prohibits misrepresentations of past performance or reasonably expected performance. A member or candidate must give a fair and complete presentation of performance information. Furthermore, members and candidates should not state or imply that clients will obtain or benefit from a rate of return that was generated in the past. Therefore, by stating that the fund's average historic performance is representative of investors' minimum future performance, Tengku has violated Standard III (D).\nC Incorrect because Tengku has only violated Standard III (D) and not Standard III (B), as described above."},
  {"num": 102, "subject": "职业道德", "question": "Emilio Torro, CFA, owns a small investment firm. He sends a brochure to potential clients which states: “As a CFA charterholder, Emilio Torro will deliver better investment performance compared to the competition. Over the past 6 years, Torro has beaten the market in every single year and will continue to do so in the future.” Torro has most likely violated the Standard(s) relating to:", "options": {"A": "performance presentation only.", "B": "reference to the CFA Institute, the CFA Designation, and the CFA Program only.", "C": "both performance presentation and reference to the CFA Institute, the CFA Designation, and the CFA Program."}, "answer": "C", "explanation": "A Incorrect because, as described in the Response Rationale for the correct answer, Torro has violated both Standard III (D), Performance Presentation, as well as Standard VII (B), Reference to CFA Institute, the CFA Designation, and the CFA Program.\nB Incorrect because, as described in the Response Rationale for the correct answer, Torro has violated both Standard III (D), Performance Presentation, as well as Standard VII (B), Reference to CFA Institute, the CFA Designation, and the CFA Program.\nC Correct because according to Standard III (D), Performance Presentation, members and candidates should not state or imply that clients will obtain or benefit from a rate of return that was generated in the past. This standard also prohibits misrepresentations of past performance or reasonably expected performance. By stating \"Over the past 6 years, Torro has beaten the market in every single year and will continue to do so in the future\", Torro has violated Standard III (D) because he misrepresents reasonably expected performance."},
  {"num": 103, "subject": "职业道德", "question": "Herman Standish, CFA, is a top analyst in the semiconductor industry. Standish issues a report on International Chips (IC) to clients of his firm that highlights a change in his recommendation from “hold” to “strong buy.” He writes in the report: “Just as it has in the past two years, IC will double its earnings and its dividend.” After three business days, Standish releases the report to the business press. Which of the following Standards has Standish most likely violated?", "options": {"A": "Only the Standard relating to material nonpublic information", "B": "Only the Standard relating to communication with clients and prospective clients", "C": "Both the Standard relating to material nonpublic information and the Standard relating to communication with clients and prospective clients"}, "answer": "B", "explanation": "A Incorrect because Standish has not violated Standard II (A), Material Nonpublic Information, which states that simply because the public in general would find the conclusions material does not require that the analyst make his or her work public. Therefore, Standish has not violated this Standard by distributing his report to his clients before making it public.\nB Correct because Standard V (B), Communication with Clients and Prospective Clients, requires that opinion be separated from fact. Violations often occur when reports fail to separate the past from the future by not indicating that earnings estimates, changes in the outlook for dividends, or future market price information are opinions subject to future circumstances. Standish violated the Standard by writing IC will double its earnings and its dividend in his report.\nC Incorrect because Standish has not violated Standard II (A), Material Nonpublic Information."},
  {"num": 104, "subject": "职业道德", "question": "Member violations of the Standard relating to misconduct must involve a(n):", "options": {"A": "illegal act.", "B": "violation of one of the other Standards.", "C": "act that reflects adversely on the member's professional reputation."}, "answer": "C", "explanation": "A Incorrect because Standard I (D), Misconduct, states that conduct that damages trustworthiness or competence may include behavior that, although not illegal, nevertheless negatively affects a member’s or candidate’s ability to perform his or her responsibilities. Thus, a member can violate the Standard without committing an illegal act.\nB Incorrect because Standard I (D), Misconduct, states that conduct that damages trustworthiness or competence may include behavior that, although not illegal, nevertheless negatively affects a member’s or candidate’s ability to perform his or her responsibilities. Though violations of Standard I (D) often involve violations of other Standards, Standard I (D) does not require that another Standard be violated for this Standard to apply.\nC Correct because Standard I (D), Misconduct, states that Members and Candidates must not engage in any professional conduct involving dishonesty, fraud, or deceit or commit any act that reflects adversely on their professional reputation, integrity, or competence."},
  {"num": 105, "subject": "职业道德", "question": "Hemant Sampath, CFA, is a wealth manager. He is contacted by a charity requesting donations. Sampath refuses to share information about existing clients to protect client confidentiality. While communicating with existing clients, Sampath shares contact details of the charity. He also shares contact details of former clients with the charity. Has Sampath violated the Standards?", "options": {"A": "No", "B": "Yes, the Standard relating to preservation of confidentiality", "C": "Yes, the Standard relating to communication with clients and prospective clients"}, "answer": "B", "explanation": "A Incorrect because Standard III(E), Preservation of Confidentiality, requires that members and candidates preserve the confidentiality of information communicated to them by their clients, prospective clients, and former clients. Sampath breaches Standard III(E) by sharing contact details of former clients with the charity.\nB Correct because Standard III(E), Preservation of Confidentiality, requires that members and candidates preserve the confidentiality of information communicated to them by their clients, prospective clients, and former clients. Sampath breaches Standard III(E) by sharing contact details of former clients with the charity.\nC Incorrect because Standard V(B), Communication with Clients and Prospective Clients, entails communication information related to investments and the investment process. Sharing contact details of a charity with existing clients is not a violation of Standard V(B)."},
  {"num": 106, "subject": "职业道德", "question": "CFA Institute encourages members to report other members' violations of the Code and Standards in writing to the CFA Institute:", "options": {"A": "Board of Governors.", "B": "Professional Conduct Program.", "C": "Disciplinary Review Committee."}, "answer": "B", "explanation": "A Incorrect because the CFA Institute encourages members to report violations to the Professional Conduct Program, not the Board of Governors.\nB Correct because CFA Institute encourages members, nonmembers, clients, and the investing public to report violations of the Code and Standards by CFA Institute members or CFA candidates by submitting a complaint in writing to the CFA Institute Professional Conduct Program.\nC Incorrect because the CFA Institute encourages members to report violations to the Professional Conduct Program, not the Disciplinary Review Committee."},
  {"num": 107, "subject": "职业道德", "question": "Which of the following is among the recommended procedures for compliance with the Standard relating to preservation of confidentiality?\n• Procedure 1: Convey to clients that not all firm-sponsored resources may be appropriate for confidential communications.\n• Procedure 2: Ensure that firm-supported communications follow practices designed to prevent the accidental distribution of confidential information.", "options": {"A": "Only Procedure 1", "B": "Only Procedure 2", "C": "Both Procedure 1 and Procedure 2"}, "answer": "C", "explanation": "A Incorrect because, as described below in the Response Rationale to the correct answer, both Procedure 1 and Procedure 2 comply with Standard III(E), Preservation of Confidentiality.\nB Incorrect because, as described below in the Response Rationale to the correct answer, both Procedure 1 and Procedure 2 comply with Standard III(E), Preservation of Confidentiality.\nC Correct because according to Standard III(E), Preservation of Confidentiality, members and candidates should be diligent in discussing with clients the appropriate methods for providing confidential information. It is important to convey to clients that not all firm-sponsored resources may be appropriate for such communications. So, Procedure 1 is correct. The standard also states that members and candidates need to understand and follow their firm’s electronic information communication and storage procedures. If the firm does not have procedures in place, members and candidates should encourage the development of procedures that appropriately reflect the firm’s size and business operations. So, Procedure 2 is also correct."},
  {"num": 108, "subject": "职业道德", "question": "A member has a client who pays higher fees for premium services. The Standards most likely allow the member to provide that client with:", "options": {"A": "larger allocations of oversubscribed IPOs.", "B": "earlier access to investment recommendations and rating changes.", "C": "direct access to research analysts to discuss published investment ratings in greater detail."}, "answer": "C", "explanation": "A Incorrect because Standard III (B), Fair Dealing, requires that members or candidates treat all clients fairly in light of their investment objectives and circumstances. For example, when making investments in new offerings or in secondary financings, members and candidates should distribute the issues to all customers for whom the investments are appropriate in a manner consistent with the policies of the firm for allocating blocks of stock. If the issue is oversubscribed, then the issue should be prorated to all subscribers. Therefore, a member is not permitted to provide larger allocations of oversubscribed IPOs to a client who pays higher fees for premium services.\nB Incorrect because Standard III (B), Fair Dealing, addresses the manner in which investment recommendations or changes in prior recommendations are disseminated to clients. Each member or candidate is obligated to ensure that information is disseminated in such a manner that all clients have a fair opportunity to act on every recommendation. Further, members and candidates may differentiate their services to clients, but different levels of service must not disadvantage or negatively affect clients. Therefore, a member is not permitted to provide earlier access to investment recommendations and rating changes to a client who pays higher fees for premium services.\nC Correct because according to Standard III (B), Fair Dealing, members and candidates may provide more personal, specialized, or in-depth service to clients who are willing to pay for premium services through higher management fees or higher levels of brokerage. Members and candidates may differentiate their services to clients, but different levels of service must not disadvantage or negatively affect clients. Therefore, a member is permitted to provide direct access to research analysts to discuss published investment ratings in greater detail for a client who pays higher fees for premium services."},
  {"num": 109, "subject": "职业道德", "question": "Jong Byun, CFA, is a broker who recommends various investments to his clients, but is not legally charged with a fiduciary responsibility. Byun finds two similar and appropriate mutual funds. One of the funds has a higher fee-sharing arrangement with the broker so he recommends that fund to his clients over the fund with lower fees. Has Byun most likely violated the Standards?", "options": {"A": "No", "B": "Yes, the Standard relating to suitability", "C": "Yes, the Standard relating to loyalty, prudence, and care"}, "answer": "C", "explanation": "A Incorrect because Byun violated Standard III (A), as described in the justification for the correct answer.\nB Incorrect because Standard III (C), Suitability, requires that members and candidates who are in an investment advisory relationship with clients consider carefully the needs, circumstances, and objectives of the clients when determining the appropriateness and suitability of a given investment or course of investment action. There is no indication that the fund is not suitable for the clients, only that a similar lower-fee alternative is available and not being recommended.\nC Correct because according to Standard III (A) Loyalty, Prudence and Care, members and Candidates must act for the benefit of their clients and place their clients' interests before their employer's or their own interest. By recommending the fund with the higher fee-sharing when another lower-fee alternative is available, Byun is putting his own interests before those of his clients. Even though he does not have a legal fiduciary requirement, Byun, as a member and has the responsibility to put his clients' needs before his own."},
  {"num": 110, "subject": "职业道德", "question": "Maria Estefan, CFA, recently founded Inversiones Unidas (IU). Estefan has a 5-year fund management track record as part of a team with her previous firm, Alto Investments (AI). Estefan advertises her past 5-year track record as her performance at IU without reference to AI or her role on the team at AI. Estefan most likely violates the Standards:", "options": {"A": "only by advertising her performance without reference to AI.", "B": "only by advertising her performance without reference to her role on the team at AI.", "C": "both by advertising her performance without reference to AI and by advertising her performance without reference to her role on the team at AI."}, "answer": "C", "explanation": "A Incorrect because Estefan has violated Standard III (D), Performance Presentation, not only because she advertised her performance without reference to AI but also because she advertising her performance without reference to her role on the team at AI.\nB Incorrect because Estefan has violated Standard III (D), Performance Presentation, not only because she advertised her performance without reference to her role on the team at AI but also because she advertised her performance without reference to AI.\nC Correct because according to Standard III (D), Performance Presentation, when communicating investment performance information, members and candidates must make reasonable efforts to ensure that it is fair, accurate, and complete. Further, as a general matter, this standard does not prohibit showing past performance of funds managed at a prior firm as part of a performance track record as long as showing that record is accompanied by appropriate disclosures about where the performance took place and the person's specific role in achieving that performance. So, Estefan is permitted to advertise her past five-year track record with AI provided she makes adequate disclosures in the advertisement relating to the IU's performance presentation. Therefore, Estefan has violated Standard III (D) because she advertised her performance without reference to AI and also failed to make reference to her role on the team at AI."},
  {"num": 111, "subject": "职业道德", "question": "Jan Ho, CFA, is an advisor who manages portfolios for endowment funds that share a similar goal of conservative growth. He has thoroughly researched and recommended the purchase of a thinly-traded stock for his clients' portfolios. To execute the trades, Ho follows his policy of prioritizing purchases for his largest clients first. Ho has most likely violated the Standard relating to:", "options": {"A": "suitability.", "B": "fair dealing.", "C": "priority of transactions."}, "answer": "B", "explanation": "A Incorrect because Standard III(C), Suitability, requires that members and candidates who are in an investment advisory relationship with clients consider carefully the needs, circumstances, and objectives of the clients when determining the appropriateness and suitability of a given investment or course of investment action. Ho's clients share a similar goal of conservative growth. So, if the stock is appropriate for one client, it is likely appropriate for all other clients. Moreover, there is no reason to believe that the investment is not suitable for Ho's clients. Therefore, Ho has not violated Standard III(C).\nB Correct because Standard III(B), Fair Dealing, requires members and candidates to treat all clients fairly when disseminating investment recommendations or making material changes to prior investment recommendations or when taking investment action with regard to general purchases, new issues, or secondary offerings. Further, the term “fairly” implies that the member or candidate must take care not to discriminate against any clients when disseminating investment recommendations or taking investment action. Therefore, Ho cannot discriminate between his largest clients and other clients by prioritizing trades for the former group first. By doing do, Ho has violated Standard III(B).\nC Incorrect because Standard VI(B), Priority of Transactions, states: Standard VI(B) reinforces the responsibility of members and candidates to give the interests of their clients and employers priority over their personal financial interests. The Standard does not relate to how members should prioritize trades among their clients. Moreover, there is no reason to believe that Ho placed his personal financial interests above that of his clients and employer. Therefore, Ho has not violated Standard VI(B)."},
  {"num": 112, "subject": "职业道德", "question": "Alicia Garcia, CFA, is a broker. Her firm's analyst changes a prior \"Buy\" recommendation on Ajax Data (AD) to \"Sell\" and Garcia publishes the recommendation change on the firm's website. Later that day, one of Garcia's clients contacts her with an order directing Garcia to buy shares of AD for the client's non-discretionary account. According to the Standard relating to fair dealing, Garcia should:", "options": {"A": "refuse to execute the order.", "B": "advise the client of the recommendation change before accepting the order.", "C": "accept and immediately execute the order because the client's account is non-discretionary."}, "answer": "B", "explanation": "A Incorrect because Standard III (B), Fair Dealing, does not state that Garcia should refuse the order. Rather, the Standard states that Garcia should advise the client of the change before accepting the order, as explained in the response rationale for the correct answer.\nB Correct because Standard III (B), Fair Dealing, addresses the manner in which investment recommendations or changes in prior recommendations are disseminated to clients. Clients who do not know that the member or candidate has changed a recommendation and who, therefore, place orders contrary to a current recommendation should be advised of the changed recommendation before the order is accepted. Therefore, Garcia should advise the client of the recommendation change before accepting the order.\nC Incorrect because Standard III (B), Fair Dealing, states that Garcia should advise the client of the changed recommendation before accepting the order, as explained in the response rationale for the correct answer."},
  {"num": 113, "subject": "职业道德", "question": "Ria Preston, CFA, works for an investment firm. Her brother is a fee-paying client of the firm. Preston allocates shares in an oversubscribed IPO that she considers suitable for all of her firm's clients. To avoid potential conflicts of interest, Preston does not allocate shares from the IPO to herself or to her brother. Has Preston most likely violated the Standards?", "options": {"A": "No", "B": "Yes, the Standard relating to fair dealing", "C": "Yes, the Standard relating to diligence and reasonable basis"}, "answer": "B", "explanation": "A Incorrect because Preston has violated Standard III (B), Fair Dealing, by not allocating shares to her brother's account, as described in the response rationale for the correct answer.\nB Correct because according to Standard III (B), Fair Dealing, if the issue is oversubscribed, members and candidates should forgo any sales to themselves or their immediate families in order to free up additional shares for clients. If the investment professional's family-member accounts are managed similarly to the accounts of other clients of the firm, however, the family-member accounts should not be excluded from buying such shares. In addition, Standard III (B) requires members and candidates to treat all clients fairly when disseminating investment recommendations or making material changes to prior investment recommendations or when taking investment action with regard to general purchases, new issues, or secondary offerings. As a fee-paying client, Preston's brother's account must be treated like as any other client account and allocated shares accordingly. Therefore, Preston has violated Standard III (B) because she failed to allocate shares to her brother's account.\nC Incorrect because according to Standard V (A), Diligence and Reasonable Basis, members and candidates must exercise diligence, independence, and thoroughness in analyzing investments, making investment recommendations, and taking investment actions. Standard V (A) does not discuss about how members must treat their clients. Also, there is no evidence to suggest that Preston lacked diligence and reasonable basis while arriving at the decision to invest in the IPO. Therefore, Preston has not violated Standard V (A)."},
  {"num": 114, "subject": "职业道德", "question": "Judy Naden, CFA, is an analyst covering the aerospace sector. Naden's recommendations often impact stock prices within the sector. Naden finalizes an investment recommendation on a company using published financial data and nonmaterial, nonpublic information gathered from industry experts and competitors. She distributes the report only to her firm's clients by email. Her firm's clients trade on this information before her report is made available to the general public a few days later. Has Naden most likely violated the Standards?", "options": {"A": "No", "B": "Yes, by using the information gathered from industry experts and competitors in her report", "C": "Yes, by failing to make her recommendation available to her firm's clients and the public at the same time"}, "answer": "A", "explanation": "A Correct because according to Standard II (A), Material Nonpublic Information, a financial analyst gathers and interprets large quantities of information from many sources. The analyst may use significant conclusions derived from the analysis of public and nonmaterial nonpublic information as the basis for investment recommendations and decisions even if those conclusions would have been material inside information had they been communicated directly to the analyst by a company. Under the “mosaic theory,” financial analysts are free to act on this collection, or mosaic, of information without risking violation. Therefore, Naden is permitted to use published financial data and nonmaterial, nonpublic information gathered from industry experts and competitor to arrive at his investment recommendation. Further, Standard II (A) states, when a particularly well-known or respected analyst issues a report or makes changes to his or her recommendation, that information alone may have an effect on the market and thus may be considered material. Theoretically, under Standard II(A), such a report would have to be made public at the time it was distributed to clients. The analyst is not a company insider, however, and does not have access to inside information. In addition, simply because the public in general would find the conclusions material does not require that the analyst make his or her work public. So, Naden is not required to make her recommendation available to her clients and the public at the same time. Therefore, Naden has not violated Standard II (A) either by using the information gathered from industry experts and competitors in her report or by failing to make her recommendation available to her clients and the public at the same time.\nB Incorrect because according to Standard II (A), Material Nonpublic Information, Naden is permitted to use the information gathered from industry experts and competitors in her report. Therefore, Naden has not violated Standard II (A), as described in the response rationale for the correct answer.\nC Incorrect because according to Standard II (A), Material Nonpublic Information, Naden is not required to make her recommendation available to her clients and the public at the same time, as described in the response rationale for the correct answer."},
  {"num": 115, "subject": "职业道德", "question": "According to the guidance provided by the Code and Standards, which of the following is not a recommended procedure for compliance with the Standard relating to material nonpublic information?", "options": {"A": "Physical separation of departments", "B": "Adopt disclosure procedures for material nonpublic information", "C": "Avoid public dissemination of material nonpublic information received"}, "answer": "C", "explanation": "A Incorrect because according to Standard II (A), a recommended procedure for compliance is physical separation of departments. Firms should consider the physical separation of departments and files to prevent the communication of sensitive information that should not be shared. For example, the investment banking and corporate finance areas of a brokerage firm should be separated from the sales and research departments, and a bank's commercial lending department should be segregated from its trust and research departments.\nB Incorrect because according to Standard II (A), a recommended procedure for compliance is to adopt disclosure procedures. Members and candidates should encourage their firms to develop and follow disclosure policies designed to ensure that information is disseminated to the marketplace in an equitable manner.\nC Correct because this is not a recommended procedure for compliance with Standard II (A), Material Non-Public Information. The recommended procedure is in fact the opposite, the member should make reasonable efforts to achieve public dissemination of the information."},
  {"num": 116, "subject": "职业道德", "question": "A member works for an investment firm and implements policies to ensure that the use of soft dollars benefits clients. These policies are most likely put in place to comply with the Standard relating to:", "options": {"A": "referral fees.", "B": "loyalty, prudence, and care.", "C": "additional compensation arrangements."}, "answer": "B", "explanation": "A Incorrect because Standard VI (C), Referral Fees, states the responsibility of members and candidates to inform their employer, clients, and prospective clients of any benefit received for referrals of customers and clients. Standard VI (C) does not discuss members' responsibility relating to soft dollars or soft commissions.\nB Correct because, according to Standard III (A), Loyalty, Prudence, and Care, conflicts may arise when an investment manager uses client brokerage to purchase research services, a practice commonly called 'soft dollars' or 'soft commissions.' A member or candidate who pays a higher brokerage commission than he or she would normally pay to allow for the purchase of goods or services, without corresponding benefit to the client, violates the duty of loyalty to the client. Therefore, a member who implements policies to ensure that the use of soft dollars benefits clients complies with the Standard relating to loyalty, prudence, and care.\nC Incorrect because Standard IV (B), Additional Compensation Arrangements, requires members and candidates to obtain permission from their employer before accepting compensation or other benefits from third parties for the services rendered to the employer or for any services that might create a conflict with their employer's interest. Standard IV (B) does not discuss members' responsibility relating to soft dollars or soft commissions."},
  {"num": 117, "subject": "职业道德", "question": "According to the recommended procedures for compliance with the Standard relating to loyalty, prudence, and care, a member who has control of client assets should:", "options": {"A": "vote proxies in the best interests of her firm.", "B": "submit quarterly itemized account statements to her clients.", "C": "combine her clients’ assets with other parties’ assets to reduce administrative costs."}, "answer": "B", "explanation": "A Incorrect because according to recommended procedures for compliance with Standard III (A), Loyalty, Prudence, and Care, in most cases, members and candidates should determine who is authorized to vote shares and vote proxies in the best interests of the clients and ultimate beneficiaries. It is not a recommended procedure for members to vote proxies in the best interests of their firm.\nB Correct because according to recommended procedures for compliance with Standard III (A), Loyalty, Prudence, and Care, a member should submit to each client, at least quarterly, an itemized statement showing the funds and securities in the custody or possession of the member or candidate plus all debits, credits, and transactions that occurred during the period.\nC Incorrect because according to recommended procedures for compliance with Standard III (A), Loyalty, Prudence, and Care, a member should separate the client’s assets from any other party’s assets, including the member’s or candidate’s own assets. Therefore, the recommended procedures for compliance with Standard III (A) are to separate client assets from other parties’ assets, not to combine them."},
  {"num": 118, "subject": "职业道德", "question": "Mark Joy, CFA, manages the pension fund for Bank Ltd. (BL). Joy believes that BL stock is overvalued. BL’s CEO requests Joy purchase BL stock for BL’s pension fund to help prevent a hostile takeover of BL. Joy complies and his purchase of BL stock for the pension fund helps prevent the takeover. Subsequently, BL’s stock price increases, which also increases the value of BL’s pension fund. Has Joy most likely violated the Standard relating to loyalty, prudence, and care?", "options": {"A": "No", "B": "Yes, because BL stock subsequently increased", "C": "Yes, because Joy complies with the CEO’s request"}, "answer": "C", "explanation": "A Incorrect because Joy would not be permitted to purchase the stock given his duty is owed to the Bank pension fund beneficiaries, as described in the response rationale for the correct answer.\nB Incorrect because Joy would not be permitted to purchase the stock given his duty is owed to the Bank pension fund beneficiaries. However, the subsequent price increase does not change the fact that it is a violation.\nC Correct because Standard III (A), Loyalty, Prudence, and Care, states that members have a duty of loyalty to their clients. When the manager is responsible for the portfolios of pension plans, the client is not the person or entity who hires the manager but, rather, the beneficiaries of the plan or trust. The duty of loyalty is owed to the ultimate beneficiaries. Joy should not have complied with the CEO’s request to buy the stock when he believes the stock is overvalued, because his duty is not owed to BL nor to the CEO. His duty is owed to the BL pension fund beneficiaries. Therefore, Joy would not be permitted to purchase the stock, and this is the correct answer."},
  {"num": 119, "subject": "职业道德", "question": "According to the Standard relating to loyalty, prudence, and care, a member who is hired to manage an equity mutual fund:", "options": {"A": "is required to vote proxies in all instances.", "B": "owes the duty of loyalty, prudence, and care to the firm who hired her to serve as fund manager.", "C": "owes the duty of loyalty, prudence, and care to invest in a manner consistent with the stated mandate."}, "answer": "C", "explanation": "A Incorrect because according to Standard III (A), Loyalty, Prudence, and Care, a cost–benefit analysis may show that voting all proxies may not benefit the client, so voting proxies may not be necessary in all instances.\nB Incorrect because according to Standard III (A), Loyalty, Prudence, and Care, in the context of an investment manager managing the personal assets of an individual, the client is easily identified. When the manager is responsible for the portfolios of pension plans or trusts, however, the client is not the person or entity who hires the manager but, rather, the beneficiaries of the plan or trust. The duty of loyalty is owed to the ultimate beneficiaries. Members and candidates managing a fund to an index or an expected mandate owe the duty of loyalty, prudence, and care to invest in a manner consistent with the stated mandate. Thus, the duty is not owed to the firm who hired the manager but to fund beneficiaries.\nC Correct because according to the guidance for Standard III (A), Loyalty, Prudence and Care: Members and candidates managing a fund to an index or an expected mandate owe the duty of loyalty, prudence, and care to invest in a manner consistent with the stated mandate."},
  {"num": 120, "subject": "职业道德", "question": "Rebecca Chen, CFA, is a portfolio manager at an investment firm. Chen has been specializing in the technology sector. She recently expanded her coverage to the oil sector. Chen attends training to ensure that she has sufficient knowledge of the oil sector before taking the new role. After comprehensive research, Chen concludes that First Oil Company (FOC) is undervalued and buys FOC shares for her clients for whom the investment is suitable. Two months later, FOC's price declines by 20%. Has Chen violated the Standards?", "options": {"A": "No", "B": "Yes, the Standard relating to competence", "C": "Yes, the Standard relating to diligence and reasonable basis"}, "answer": "A", "explanation": "A Correct because Standard I(E), Competence, states that to be competent in your role and meet your duties under this standard means having sufficient knowledge, skills, and abilities suitable for a professional to work in that specific role with success. These attributes govern the expertise, experience, and accomplishments that professionals need to perform at the highest level. While competence allows members and candidates the opportunity to undertake an activity successfully, lack of competence cannot necessarily be determined by an unsuccessful or a negative outcome. Many competent investment professionals have experienced failure or loss in their professional lives. Chen has obtained the knowledge in new area and completed a comprehensive research before buying the shares to her clients for whom the investment is suitable. Therefore, Chen has not violated Standard I(E) even though the stock price declined by 20%. In addition, Standard V(A), Diligence and Reasonable Basis, states that members and candidates must exercise diligence, independence, and thoroughness in analyzing investments, making investment recommendations, and taking investment actions. Chen has completed comprehensive research before buying the shares to her clients for whom the investment is suitable. Therefore, she has also not violated the Standard V(A).\nB Incorrect because Standard I(E), Competence, states that to be competent in your role and meet your duties under this standard means having sufficient knowledge, skills, and abilities suitable for a professional to work in that specific role with success. These attributes govern the expertise, experience, and accomplishments that professionals need to perform at the highest level. While competence allows members and candidates the opportunity to undertake an activity successfully, lack of competence cannot necessarily be determined by an unsuccessful or a negative outcome. Many competent investment professionals have experienced failure or loss in their professional lives. Chen has obtained the knowledge in new area and completed a comprehensive research before buying the shares to her clients for whom the investment is suitable. Therefore, Chen has not violated Standard I(E) even though the stock price declined by 20%.\nC Incorrect because Standard V(A), Diligence and Reasonable Basis, states that members and candidates must exercise diligence, independence, and thoroughness in analyzing investments, making investment recommendations, and taking investment actions. Chen has completed comprehensive research before buying the shares to her clients for whom the investment is suitable. Therefore, she has not violated the Standard V(A)."},
  {"num": 121, "subject": "职业道德", "question": "Which of the following is among the recommended procedures for compliance with the Standard relating to misrepresentation?\nProcedure 1: Each member should prepare for client distribution a list of services that the member is capable of performing.\nProcedure 2: Members should cite specific quotations as attributable to 'investment experts' when confidentiality of the sources has to be preserved.", "options": {"A": "Procedure 1 only", "B": "Procedure 2 only", "C": "Both Procedure 1 and Procedure 2"}, "answer": "A", "explanation": "A Correct because the recommended procedures for compliance with Standard I (C), Misrepresentation, state that to ensure accurate presentations to clients, each member and candidate should prepare a summary of his or her own qualifications and experience and a list of the services the member or candidate is capable of performing.\nB Incorrect because Standard I (C), Misrepresentation, states that misrepresentation through plagiarism in investment management can take various forms. Other practices include citing specific quotations as attributable to 'leading analysts' and 'investment experts' without naming the specific references. It is therefore not a recommended procedure for compliance to cite specific quotations as attributable to 'investment experts' without naming the sources to preserve confidentiality.\nC Incorrect because Standard I (C), Misrepresentation, states that misrepresentation through plagiarism in investment management can take various forms. Other practices include citing specific quotations as attributable to 'leading analysts' and 'investment experts' without naming the specific references. It is therefore not a recommended procedure for compliance to cite specific quotations as attributable to 'investment experts' without naming the sources to preserve confidentiality."},
  {"num": 122, "subject": "职业道德", "question": "According to the recommended procedures for compliance with the Standard relating to misrepresentation, a member should:", "options": {"A": "refrain from using information received from a third party.", "B": "update a summary of her professional qualifications at least quarterly.", "C": "keep copies of the materials that the member relied on in preparing each research report."}, "answer": "C", "explanation": "A Incorrect because there is no recommended procedure for compliance with Standard I (C), Misrepresentation, that suggests avoiding using third-party information. Rather, members and candidates should encourage their employers to develop procedures for verifying information of third-party firms.\nB Incorrect because according to the recommended procedures for compliance with Standard I (C), Misrepresentation, to ensure accurate presentations to clients, each member and candidate should prepare a summary of his or her own qualifications and experience and a list of the services the member or candidate is capable of performing. There is no recommendation to update qualifications at least quarterly.\nC Correct because according to recommended procedures for compliance with Standard I (C), Misrepresentation, to avoid plagiarism members should keep copies of all research reports, articles containing research ideas, material with new statistical methodologies, and other materials that were relied on in preparing the research report."},
  {"num": 123, "subject": "职业道德", "question": "A member most likely violates the Standard relating to misrepresentation if he:", "options": {"A": "distributes a research report written by another firm to his clients.", "B": "attributes a quotation to \"a leading analyst\" without naming the analyst.", "C": "uses research done by an analyst who no longer works for the firm without providing attribution to that analyst."}, "answer": "B", "explanation": "A Incorrect because according to Standard I (C), Misrepresentation, in the case of distributing third-party, outsourced research, members and candidates may use and distribute such reports as long as they do not represent themselves as the report’s authors. Indeed, the member or candidate may add value for the client by sifting through research and repackaging it for clients.\nB Correct because according to Standard I (C), Misrepresentation, misrepresentation through plagiarism in investment management can take various forms including citing specific quotations as attributable to 'leading analysts' and 'investment experts' without naming the specific references.\nC Incorrect because according to Standard I (C), Misrepresentation, in some situations, however, members or candidates may use research conducted or models developed by others within the same firm without committing a violation. The most common example relates to the situation in which one (or more) of the original analysts is no longer with the firm. Research and models developed while employed by a firm are the property of the firm. The firm retains the right to continue using the work completed after a member or candidate has left the organization. The firm may issue future reports without providing attribution to the prior analysts."},
  {"num": 124, "subject": "职业道德", "question": "Donovan Jones, CFA, works at Grae Investments (GI). GI invests in commodities, stocks, and bonds. Prices for its illiquid holdings are determined by an independent valuation firm. Jones markets performance using a small-cap equity index as a benchmark. Jones switches to a different valuation firm due to its better customer service and lower cost. The switch results in a marginal increase to the current estimated value of its illiquid assets. Jones has most likely violated the Standard relating to misrepresentation:", "options": {"A": "only by switching valuation firms.", "B": "only by using the small-cap equity index as a benchmark.", "C": "both by switching valuation firms and by using the small-cap equity index as a benchmark."}, "answer": "B", "explanation": "A Incorrect because according to Standard I (C), Misrepresentation, changing pricing providers should not be based solely on the justification that the new provider reports a higher current value of a security. In this case, there are several valid reasons justifying a change to a new valuation firm, and receiving higher valuations is not a driver of the decision.\nB Correct because according to Standard I (C), Misrepresentation, members and candidates may misrepresent the success of their performance record through presenting benchmarks that are not comparable to their strategies. The small-cap equity index is not comparable to the described strategy which includes ownership of a mix of commodities, stocks, and bonds.\nC Incorrect because according to Standard I (C), Misrepresentation, changing pricing providers should not be based solely on the justification that the new provider reports a higher current value of a security. In this case, there are several valid reasons justifying a change to a new valuation firm, and receiving higher valuations is not a driver of the decision. Therefore, switching valuation firms is unlikely to be a violation of the Standard."},
  {"num": 125, "subject": "职业道德", "question": "Fred Berkam, CFA, makes the following two statements in his communication to clients regarding his equity-based hedge fund:\nStatement 1: \"The fund has reported seven consecutive years of gains, so investors are assured of avoiding losses next year.\"\nStatement 2: \"The fund's complex strategy does not fit well with any standard benchmark; therefore no performance benchmark is provided.\"\nBerkam has most likely violated the Standards with:", "options": {"A": "Statement 1 only.", "B": "Statement 2 only.", "C": "both Statement 1 and Statement 2."}, "answer": "A", "explanation": "A Correct because Standard I (C), Misrepresentation, prohibits members and candidates from guaranteeing clients any specific return on volatile investments. Stating that an equity-based fund can guarantee against a potential loss is a violation.\nB Incorrect because Standard I (C), Misrepresentation, states that Standard I(C) does not require that a benchmark always be provided in order to comply. Some investment strategies may not lend themselves to displaying an appropriate benchmark because of the complexity or diversity of the investments included.\nC Incorrect because Berkam has violated Standard I (C), Misrepresentation, only with Statement 1, as described in the rationale for the correct answer. Statement 2 does not violate the Standard because the Standard does not require benchmarks always to be provided especially when the fund in question uses a complex strategy."},
  {"num": 126, "subject": "职业道德", "question": "Alesha Alsagoff, CFA, is hired by Acacia Papermill to manage its pension plan. She must report annual performance results to the plan trustees. Alsagoff's duty of loyalty, prudence, and care is primarily owed to:", "options": {"A": "Acacia Papermill.", "B": "the pension plan trustees.", "C": "the beneficiaries of the pension plan."}, "answer": "C", "explanation": "A Incorrect because when the manager is responsible for the portfolios of pension plans or trusts, however, the client is not the person or entity who hires the manager, but, rather, the beneficiaries of the plan or trust. The duty of loyalty is owed to the ultimate beneficiaries.\nB Incorrect because when the manager is responsible for the portfolios of pension plans or trusts, however, the client is not the person or entity who hires the manager, but, rather, the beneficiaries of the plan or trust. The duty of loyalty is owed to the ultimate beneficiaries.\nC Correct because when the manager is responsible for the portfolios of pension plans or trusts, however, the client is not the person or entity who hires the manager, but, rather, the beneficiaries of the plan or trust. The duty of loyalty is owed to the ultimate beneficiaries."},
  {"num": 127, "subject": "职业道德", "question": "Which of the following statements regarding the GIPS standards is accurate?", "options": {"A": "All fee-paying client portfolios must be included in at least one composite", "B": "All portfolios with the same investment mandate are aggregated into a composite", "C": "Aggregation of portfolios into composites is based on the actual performance of the portfolios every year"}, "answer": "B", "explanation": "A Incorrect because according to the GIPS standards, a claim of compliance requires that all fee-paying discretionary accounts managed by the firm be included in at least one composite. Non-discretionary portfolios must not be included in a firm’s composites. Fee-paying non-discretionary portfolios do not have to be included.\nB Correct because according to the GIPS standards, A composite is an aggregation of one or more portfolios managed according to a similar investment mandate, objective, or strategy.\nC Incorrect because according to the GIPS standards, the determination of which portfolios to include in the Composite should be done according to pre-established criteria (i.e., on an ex-ante basis), not after the fact. Basing it on actual performance would require the aggregation to be done after the fact which is incorrect."},
  {"num": 128, "subject": "职业道德", "question": "Which of the following comments concerning composites meeting the requirements of the GIPS standards is correct?", "options": {"A": "A firm's claim of compliance requires all fee-paying accounts managed by the firm be included in at least one composite", "B": "The requirement to create, use and maintain composites is designed to prevent firms using the best-performing accounts to represent an investment strategy", "C": "A composite must include all actual, fee-paying, discretionary and non-discretionary portfolios managed in accordance with the same investment mandate, objective, or strategy"}, "answer": "B", "explanation": "A Incorrect because a claim of compliance requires that all fee-paying discretionary accounts be included in at least one composite. It does not include all accounts which could include non-discretionary accounts.\nB Correct because one of the key concepts of the standards is the required use of composites. A composite is an aggregation of one or more portfolios managed according to a similar investment mandate, objective, or strategy. The requirement to create, use and maintain composites is designed to prevent firms from cherry-picking—using the best-performing accounts to represent the performance of an investment strategy.\nC Incorrect because a composite must include all actual, fee-paying, discretionary portfolios managed in accordance with the same investment mandate, objective, or strategy. It does not include non-discretionary accounts."},
  {"num": 129, "subject": "职业道德", "question": "Which of the following statements describe the key concepts of the GIPS standards?\nStatement 1: The GIPS standards are ethical standards to ensure full disclosure of investment performance\nStatement 2: The GIPS standards require firms to maintain composites for all strategies for which the firm manages discretionary and nondiscretionary accounts\nStatement 3: The GIPS standards address all aspects of performance measurement", "options": {"A": "Statement 1", "B": "Statement 2", "C": "Statement 3"}, "answer": "A", "explanation": "A Correct GIPS standards are ethical standards for investment performance presentation to ensure fair representation and full disclosure of investment performance. So, Statement 1 is a key concept of the GIPS standards.\nB Incorrect because, the GIPS standards require firms to create and maintain composites for all strategies for which the firm manages segregated accounts or markets to segregated accounts. Firms must include all actual, fee-paying, discretionary segregated accounts in at least one composite defined by investment mandate, objective, or strategy. So, Statement 2 is not a key concept of the GIPS standards.\nC Incorrect because the GIPS standards do not address every aspect of performance measurement and will continue to evolve over time to address additional areas of investment performance. So, Statement 3 is not a key concept of the GIPS standards."},
  {"num": 130, "subject": "职业道德", "question": "A firm claiming compliance with GIPS standards is required to:", "options": {"A": "perform verification of the firm's claim of compliance.", "B": "maintain its compliance even after the firm has been verified by an independent third party.", "C": "determine selection criteria regarding which existing portfolios to include in a composite at the end of the reporting period."}, "answer": "B", "explanation": "A Incorrect because once a firm claims compliance with the Standards, they may voluntarily hire an independent third party to perform a verification in order to increase confidence in the firm's claim of compliance. Therefore, the firm is not required to but may elect an independent third party to perform verification of the firm's claim of compliance.\nB Correct because firms that claim compliance with the GIPS standards are responsible for their claim of compliance and for maintaining that compliance. That is, firms self-regulate their claim of compliance. Therefore, including when compliance is verified by an independent third party, the firm is always responsible for maintaining that compliance.\nC Incorrect because the determination of which portfolios to include in the Composite should be done according to pre-established criteria (i.e., on an ex-ante basis), not after the fact."},
  {"num": 131, "subject": "职业道德", "question": "With respect to the GIPS standards, which of the following statements is most accurate? Verification:", "options": {"A": "of GIPS compliance is mandatory if the firm claims GIPS compliance.", "B": "is performed by the firm when self-regulating and certifying its claim of compliance.", "C": "tests whether the firm's processes are designed to present performance results in compliance with the GIPS standards."}, "answer": "C", "explanation": "A Incorrect because once a firm claims compliance with the Standards, they may voluntarily hire an independent third party to perform a verification in order to increase confidence in the firm’s claim of compliance. Therefore, verification is voluntary, not mandatory.\nB Incorrect because firms self-regulate their claim of compliance and once a firm claims compliance with the Standards, they may voluntarily hire an independent third party to perform a verification in order to increase confidence in the firm’s claim of compliance. Therefore, a firm cannot certify its own claim of compliance.\nC Correct because according to GIPS, Verification is a process by which an independent verification firm (verifier) conducts testing of a firm on a firm-wide basis in accordance with the required verification procedures of the GIPS standards. Verification provides assurance on whether the firm’s policies and procedures related to composite and pooled fund maintenance, as well as the calculation, presentation, and distribution of performance, have been designed in compliance with the GIPS standards and have been implemented on a firm-wide basis."},
  {"num": 132, "subject": "职业道德", "question": "According to the GIPS standards, verification is:", "options": {"A": "performed with respect to an entire firm.", "B": "performed by a firm's compliance department.", "C": "mandatory for firms that claim compliance with the GIPS standards."}, "answer": "A", "explanation": "A Correct because according to the GIPS standards, verification is performed with respect to an entire firm, not on specific composites or pooled funds.\nB Incorrect because according to the GIPS standards, Verification is a process by which an independent verification firm (verifier) conducts testing of a firm on a firm-wide basis in accordance with the required verification procedures of the GIPS standards.\nC Incorrect because according to the GIPS standards, Once a firm claims compliance with the GIPS standards, it may voluntarily hire an independent third party to perform a verification in order to increase confidence in the firm’s claim of compliance."},
  {"num": 133, "subject": "职业道德", "question": "The objectives of the GIPS standards include:", "options": {"A": "promoting financial regulators' interests.", "B": "promoting industry self-regulation on a global basis.", "C": "obtaining acceptance of multiple local standards for accurate performance presentation."}, "answer": "B", "explanation": "A Incorrect because one of the objectives of the GIPS standards is to promote investor interests and instill investor confidence, and not to promote financial regulator interests.\nB Correct because one of the objectives of the GIPS standards is to promote industry self-regulation on a global basis.\nC Incorrect because one the objectives of the GIPS standards is to obtain worldwide acceptance of a single standard [not diverse standards] for calculating and presenting performance."},
  {"num": 134, "subject": "职业道德", "question": "According to the GIPS standards, verification must be performed:", "options": {"A": "with respect to an entire firm.", "B": "on specific composites of a firm.", "C": "by a firm’s compliance department."}, "answer": "A", "explanation": "A Correct because verification is performed with respect to an entire firm, not on specific composites or pooled funds.\nB Incorrect because verification is performed with respect to an entire firm, not on specific composites or pooled funds.\nC Incorrect because verification must be performed by an independent third party. A firm cannot perform its own verification."},
  {"num": 135, "subject": "职业道德", "question": "Asset managers are most likely required to do which of the following as part of their adherence to the GIPS standards?", "options": {"A": "Adhere to certain calculation methodologies", "B": "Only follow the minimum GIPS requirements at the time of composite creation", "C": "Include all non-discretionary funds in at least one composite reflecting the investment mandate"}, "answer": "A", "explanation": "A Correct , because the GIPS standards rely on the integrity of input data, the quality of which is critical to creating accurate performance presentations. The underlying valuations of portfolio holdings drive performance. It is essential for these and other inputs to be accurate. The GIPS standards require firms to adhere to certain calculation methodologies to allow for comparability across firms.\nB Incorrect , because meeting the objectives of fair representation and full disclosure is likely to require more than simply adhering to the minimum requirements of the GIPS standards. Firms should also adhere to the recommendations to achieve best practice in the calculation and presentation of performance. In addition, GIPS standards will continue to evolve over time to address additional areas of investment performance and firms will be required to keep up with the updated standards.\nC Incorrect , because the GIPS standards require firms to create and maintain composites for all strategies for which the firm manages segregated accounts or markets to segregated accounts. Firms must include all actual, fee-paying, discretionary segregated accounts in at least one composite defined by investment mandate, objective, or strategy. Non-discretionary accounts must not be included in composites."},
  {"num": 136, "subject": "职业道德", "question": "Which of the following statements is most accurate? Compliance with the GIPS standards:", "options": {"A": "by firms eliminates the need for in-depth due diligence by investors.", "B": "enables firms to participate in competitive bids against other GIPS-compliant firms.", "C": "is mandatory for firms conducting business in countries that do not have regulations relating to investment performance presentation."}, "answer": "B", "explanation": "A Incorrect because the GIPS standards certainly do not eliminate the need for in-depth due diligence on the part of the client or investor, but compliance with the Standards enhances the credibility of investment management firms that have chosen to undertake this responsibility.\nB Correct because compliance enables the GIPS-compliant firm to participate in competitive bids against other compliant firms throughout the world.\nC Incorrect because complying with the GIPS standards is voluntary. Compliance with the GIPS standards is not typically required by legal or regulatory authorities."},
  {"num": 137, "subject": "职业道德", "question": "Which of the following is not a key concept of the GIPS standards? The GIPS standards for firms:", "options": {"A": "require the use of composites.", "B": "rely on the integrity of input data.", "C": "address every aspect of performance measurement."}, "answer": "C", "explanation": "A Incorrect because according to the GIPS standards one of the key concepts of the standards is the required uses of composites. A composite is an aggregation of one or more portfolios managed according to a similar investment mandate, objective, or strategy. Therefore, it is a key concept that the GIPS standards require to aggregate one or more portfolios managed according to similar investment strategies in a composite.\nB Incorrect because according to the GIPS standards, the GIPS standards rely on the integrity of input data, the quality of which is critical to creating accurate performance presentations. Therefore, it is a key concept to rely on the integrity of input data.\nC Correct because according to the GIPS standards, the GIPS standards do not address every aspect of performance measurement. Therefore, it is not a key concept of the GIPS standards to address every aspect of performance measurement."},
  {"num": 138, "subject": "职业道德", "question": "Verification provides assurance that which of the following have been designed in compliance with the GIPS standards?", "options": {"A": "Only the calculation and presentation of the firm's performance", "B": "Only the firm's policies related to composite and pooled fund maintenance", "C": "Both the calculation and presentation of the firm's performance, and the firm's policies related to composite and pooled fund maintenance"}, "answer": "C", "explanation": "A Incorrect because the design of both performance calculation and firm policies related to pooled fund maintenance are assured by a GIPS verifier: verification provides assurance on whether the firm’s policies and procedures related to composite and pooled fund maintenance, as well as the calculation, presentation, and distribution of performance, have been designed in compliance with the GIPS standards and have been implemented on a firm-wide basis.\nB Incorrect because the design of both performance calculation and firm policies related to pooled fund maintenance are assured by a GIPS verifier: verification provides assurance on whether the firm’s policies and procedures related to composite and pooled fund maintenance, as well as the calculation, presentation, and distribution of performance, have been designed in compliance with the GIPS standards and have been implemented on a firm-wide basis.\nC Correct because verification provides assurance on whether the firm’s policies and procedures related to composite and pooled fund maintenance, as well as the calculation, presentation, and distribution of performance, have been designed in compliance with the GIPS standards and have been implemented on a firm-wide basis."},
  {"num": 139, "subject": "职业道德", "question": "According to the GIPS standards, verification:", "options": {"A": "is performed on a firm-wide basis.", "B": "must be performed by a firm's compliance department.", "C": "ensures the accuracy of specific composite presentations."}, "answer": "A", "explanation": "A Correct because verification is performed with respect to an entire firm, not on specific composites.\nB Incorrect because verification of GIPS standards must be conducted by a third party, not the firm itself: verification must be performed by an independent third party. A firm cannot perform its own verification.\nC Incorrect because verification does not ensure the accuracy of any specific composite presentation."},
  {"num": 140, "subject": "职业道德", "question": "A firm claiming compliance with the GIPS standards must:", "options": {"A": "state that its calculation methodology is in accordance with the GIPS standards.", "B": "disclose for which firm assets only partial compliance with the GIPS standards is achieved.", "C": "document policies and procedures used in establishing compliance with the GIPS standards."}, "answer": "C", "explanation": "A Incorrect because according to the Fundamentals of Compliance of the GIPS standards, statements referring to the calculation methodology as being 'in accordance,' 'in compliance,' or 'consistent' with the Global Investment Performance Standards, or similar statements, are prohibited.\nB Incorrect because the Fundamentals of Compliance of the GIPS standards state that if the FIRM does not meet all the applicable REQUIREMENTS of the GIPS standards, the FIRM MUST NOT represent or state that it is in compliance with the Global Investment Performance Standards or make any other statements that may indicate compliance or partial compliance with the GIPS standards.\nC Correct because the Fundamentals of Compliance of the GIPS standards state that the FIRM MUST document its policies and procedures used in establishing and maintaining compliance with the REQUIREMENTS of the GIPS standards, as well as any RECOMMENDATIONS it has chosen to adopt, and apply them consistently."},
  {"num": 141, "subject": "职业道德", "question": "According to the GIPS standards, which of the following statements is correct?\n• Statement 1: When local regulations conflict with the GIPS standards, firms are required to comply with the GIPS standards if the conflict relates to composite construction.\n• Statement 2: When local regulations conflict with the GIPS standards for performance presentation, firms are required to comply with local regulation.", "options": {"A": "Statement 1 only", "B": "Statement 2 only", "C": "Both Statement 1 and Statement 2"}, "answer": "B", "explanation": "A Incorrect because according to the GIPS standards, in cases in which laws and/or regulations conflict with the GIPS standards, firms are required to comply with the laws and regulations and make full disclosure of the conflict in the GIPS Report. Thus, Statement 1 is not consistent with the GIPS standards.\nB Correct because according to the GIPS standards, in cases in which laws and/or regulations conflict with the GIPS standards, firms are required to comply with the laws and regulations and make full disclosure of the conflict in the GIPS Report.\nC Incorrect because according to the GIPS standards, in cases in which laws and/or regulations conflict with the GIPS standards, firms are required to comply with the laws and regulations and make full disclosure of the conflict in the GIPS Report. Thus, Statement 1 is not consistent with the GIPS standards (and incorrect), and so only Statement 2 is correct."},
  {"num": 142, "subject": "职业道德", "question": "A firm has been in existence for seven years. In order to comply with the GIPS standards, the minimum number of years of GIPS-compliant performance data the firm is initially required to present is:", "options": {"A": "three years.", "B": "five years.", "C": "seven years."}, "answer": "B", "explanation": "A Incorrect because the minimum requirement for presentation of performance is five years.\nB Correct because the GIPS standards state that a ﬁrm is required to initially present, at a minimum, ﬁve years of annual investment performance that is compliant with the GIPS standards. If the composite or pooled fund has been in existence less than ﬁve years, the ﬁrm must present performance since the composite or pooled fund inception date. Prospectively, the ﬁrm must present an additional year of performance each year, building up to a minimum of 10 years of GIPS-compliant performance.\nC Incorrect because the minimum requirement for presentation of performance is five years."},
  {"num": 143, "subject": "职业道德", "question": "The GIPS standards most likely:", "options": {"A": "assure prospective clients of the accuracy of a firm's reported investment performance.", "B": "help prospective clients consider all relevant information in order to evaluate a firm's past investment performance.", "C": "require investment firms to disclose to prospective clients in a standardized form their own methodologies for calculating performance."}, "answer": "B", "explanation": "A Incorrect because the GIPS standards ensure fair representation and full disclosure of investment performance. However, even if there is a third-party verification, the verification does not ensure the accuracy of any specific composite presentation.\nB Correct because according to GIPS standards, institutions and individuals are constantly scrutinizing past investment performance returns in search of the best manager to achieve their investment objectives. Further, the GIPS standards ensure fair representation and full disclosure of investment performance. In other words, the GIPS standards lead investment management firms to avoid misrepresentations of performance and to communicate all relevant information that prospective clients should know in order to evaluate past results. Therefore, the GIPS standards help prospective clients consider all relevant information in order to evaluate a firm's past investment performance.\nC Incorrect because the GIPS standards establish a standardized, industry-wide approach for investment firms to follow in calculating and presenting their historical investment results to prospective clients. Achieving comparability among investment management firms' performance presentations requires uniformity in methods used to calculate returns. The GIPS standards mandate the use of certain calculation methodologies to facilitate comparability. Therefore, GIPS standards do not require investment firms to disclose to prospective clients in a standardized form their own methodologies for calculating performance."},
  {"num": 144, "subject": "职业道德", "question": "Which of the following can claim compliance with the GIPS standards?", "options": {"A": "Only asset owners", "B": "Only software vendors that assist firms in claiming compliance with the GIPS standards", "C": "Both asset owners and software vendors that assist firms in claiming compliance with the GIPS standards"}, "answer": "A", "explanation": "A Correct because asset owners may comply with the GIPS standards in the same way as firms if they compete for business. If they don’t compete for business but report their performance to an oversight body, asset owners may choose to comply with the GIPS standards for asset owners. Therefore, asset owners can claim compliance with the GIPS standards.\nB Incorrect because software (and the vendors who supply software) cannot be “compliant.” Software can assist firms in achieving compliance with the GIPS standards (e.g., by calculating performance in a manner consistent with the calculation requirements of the Standards), but only a firm managing assets can claim compliance once the firm has satisfied all requirements of the standards.\nC Incorrect because software vendors who assist firms in claiming compliance with the GIPS standards cannot claim compliance with the GIPS standards."},
  {"num": 145, "subject": "职业道德", "question": "Which of the following statements is accurate?\nStatement 1: Compliance with the GIPS standards eliminates the need for an investor to conduct in-depth due diligence of an investment management firm\nStatement 2: Compliance with the GIPS standards by external managers facilitates understanding of risk and return sources of funds supervised by an asset owner", "options": {"A": "Statement 1 only", "B": "Statement 2 only", "C": "Both Statement 1 and Statement 2"}, "answer": "B", "explanation": "A Incorrect because the GIPS standards certainly do not eliminate the need for in-depth due diligence on the part of the investor, but compliance with the Standards enhances the credibility of investment management firms that have chosen to undertake this responsibility. Therefore, Statement 1 is not accurate.\nB Correct because the GIPS standards benefit asset managers and their prospective clients and asset owners and their oversight bodies. Particularly, where asset owners require their external managers to comply with the GIPS standards, reporting to the oversight body using the same principles facilitates the understanding of the sources of risk and excess return in the funds under supervision. Therefore, Statement 2 is accurate.\nC Incorrect because Statement 1 is not accurate, as described above."},
  {"num": 146, "subject": "职业道德", "question": "After a 3-year-old firm has presented a minimum of three years of GIPS-compliant performance, the GIPS standards require the firm to present an additional year of performance each year until the firm reports a minimum of:", "options": {"A": "five years.", "B": "seven years.", "C": "ten years."}, "answer": "C", "explanation": "A Incorrect because the GIPS standards state that firms must build up to a minimum of ten years, not five years, of GIPS-compliant performance.\nB Incorrect because the GIPS standards state that firms must build up to a minimum of ten years, not seven years, of GIPS-compliant performance.\nC Correct because the GIPS standards state that a ﬁrm is required to initially present, at a minimum, ﬁve years of annual investment performance that is compliant with the GIPS standards. If the composite or pooled fund has been in existence less than ﬁve years, the ﬁrm must present performance since the composite or pooled fund inception date. Prospectively, the ﬁrm must present an additional year of performance each year, building up to a minimum of ten years of GIPS-compliant performance."},
  {"num": 147, "subject": "职业道德", "question": "An investment firm manages a $200 million composite to a small-cap growth style. The firm sells $50 million of these managed assets to a competing money manager. In order to remain in compliance with the GIPS standards, the firm must:", "options": {"A": "exclude the $50 million from the firm's historical performance.", "B": "continue to include the $50 million in the firm's historical performance until the assets were sold.", "C": "show the historical performance of the $50 million separately from the firm's historical performance of the remaining $150 million."}, "answer": "B", "explanation": "A Incorrect because according to GIPS standards, changes in the FIRM'S organization must not lead to alteration of historical performance. Therefore, excluding the $50 million from the firm's historical performance is a violation of the GIPS standards.\nB Correct because according to GIPS standards, changes in the FIRM'S organization must not lead to alteration of historical performance. Therefore, the firm must continue to include the $50 million in the firm's historical performance.\nC Incorrect because according to GIPS standards, changes in the FIRM'S organization must not lead to alteration of historical performance. Therefore, showing the historical performance of the $50 million separately from the firm's historical performance of the remaining $150 million is a violation of the GIPS standards."},
  {"num": 148, "subject": "职业道德", "question": "Elana Paralova, a Level I CFA candidate working at an asset management firm, wants to make a good impression on a prospective client. She tells the prospect: \"Getting the CFA Charter will show I am serious about protecting the interests of my clients and it will boost my reputation. Once I get the Charter, I also hope to make more money by getting promoted!\" Her colleague, Jacob Klemmer, CFA, tells Paralova: \"Study all subjects for each exam, you never know what will be included. The three exams will be the most difficult exams you will ever take. Any promotion and pay raise will reflect your enhanced skills.\" Did either Paralova or Klemmer violate the Standards?", "options": {"A": "No.", "B": "Only Paralova violates the Standards.", "C": "Only Klemmer violates the Standards."}, "answer": "A", "explanation": "A Correct because neither Paralova or Klemmer violated CFA Standards through their statements. Paralova did not violate Standard VII(B) Reference to CFA Institute, the CFA Designation, and the CFA Program when she made her comments about what getting the Charter will reflect and the hope for a pay raise. The Standard states, When referring to CFA Institute, CFA Institute membership, the CFA designation, or candidacy in the CFA Program, Members and Candidates must not misrepresent or exaggerate the meaning or implications of membership in CFA Institute, holding the CFA designation, or candidacy in the CFA program. Klemmer did not violate Standard VII (B) Reference to CFA Institute, the CFA Designation, and the CFA Program when he expressed his opinion that Paralova's potential pay raise will reflect her enhanced skills. Klemmer also complied with Standard VII(A) Responsibilities as a CFA Institute Member or CFA Candidate, Conduct as Participants in CFA Institute Programs when stating an opinion about the difficulty of the exam without revealing any specific details or the need to study all subjects. The Standard states that candidates must not engage in any conduct that compromises the integrity, validity, or security of CFA Institute programs.\nB Incorrect as Paralova did not violate Standard VII (B) Reference to CFA Institute, the CFA Designation, and the CFA Program when she made her comments about what getting the Charter will reflect and the hope for a pay raise. The Standard states, When referring to CFA Institute, CFA Institute membership, the CFA designation, or candidacy in the CFA Program, Members and Candidates must not misrepresent or exaggerate the meaning or implications of membership in CFA Institute, holding the CFA designation, or candidacy in the CFA program.\nC Incorrect as Klemmer did not violate Standard VII (B) Reference to CFA Institute, the CFA Designation, and the CFA Program when he expressed his opinion that Paralova's potential pay raise will reflect her enhanced skills. Klemmer also complied with Standard VII(A): Responsibilities as a CFA Institute Member or CFA Candidate, Conduct as Participants in CFA Institute Programs when stating an opinion about the difficulty of the exam without revealing any specific details or the need to study all subjects. The Standard states that candidates must not engage in any conduct that compromises the integrity, validity, or security of CFA Institute programs."},
  {"num": 149, "subject": "职业道德", "question": "Jayson Kite, CFA, a senior analyst, is preparing a research report on a shipping company. Kite concludes that the stock of a company is a good investment and decides to put a \"buy\" recommendation on the stock. According to the recommended procedures for compliance, Kite should communicate the recommendation:", "options": {"A": "within the firm first and then to customers.", "B": "to customers first and then within the firm.", "C": "simultaneously within the firm and to customers."}, "answer": "C", "explanation": "A Incorrect because according to the recommended procedures for compliance with Standard III (B), Fair Dealing, a common practice to assure fair dealing is to communicate recommendations simultaneously within the firm and to customers.\nB Incorrect because according to the recommended procedures for compliance with Standard III (B), Fair Dealing, a common practice to assure fair dealing is to communicate recommendations simultaneously within the firm and to customers.\nC Correct because according to the recommended procedures for compliance with Standard III (B), Fair Dealing, a common practice to assure fair dealing is to communicate recommendations simultaneously within the firm and to customers. Members and candidates should encourage firms to develop guidelines that prohibit personnel who have prior knowledge of an investment recommendation from discussing or taking any action on the pending recommendation. Members and candidates should encourage firms to develop guidelines that prohibit personnel who have prior knowledge of an investment recommendation from discussing or taking any action on the pending recommendation."},
  {"num": 150, "subject": "职业道德", "question": "Tim Howley, CFA, “pumps up” the price of a security by spreading misleading information and later “dumps” the security after the price reaches an artificially high level. Howley has most likely violated the Standard relating to:", "options": {"A": "market manipulation.", "B": "independence and objectivity.", "C": "material nonpublic information."}, "answer": "A", "explanation": "A Correct because according to the Standard II(B), market manipulation includes (1) the dissemination of false or misleading information. Also, information-based manipulation includes, but is not limited to, spreading false rumors to induce trading by others. For example, members and candidates must refrain from “pumping up” the price of an investment by issuing misleading positive information or overly optimistic projections of a security’s worth only to later “dump” the investment (i.e., sell it) once the price, fueled by the misleading information’s effect on other market participants, reaches an artificially high level.\nB Incorrect because according to Standard I(B), independence and objectivity, Members and Candidates must use reasonable care and judgment to achieve and maintain independence and objectivity in their professional activities. Members and Candidates must not offer, solicit, or accept any gift, benefit, compensation, or consideration that reasonably could be expected to compromise their own or another’s independence and objectivity.\nC Incorrect because according to Standard II(A), material nonpublic information, Members and Candidates who possess material nonpublic information that could affect the value of an investment must not act or cause others to act on the information."},
  {"num": 1, "subject": "另类投资", "question": "Venture capital is best classified as a sub-category of:", "options": {"A": "real estate.", "B": "hedge funds.", "C": "private equity."}, "answer": "C", "explanation": "A Incorrect because real estate investments are made in buildings or land, either directly or indirectly. Although some venture capital investments may have a real estate component, venture capital is broadly considered a type of private equity investing, and is best classified as such.\nB Incorrect because hedge funds are private investment vehicles that manage portfolios of securities and/or derivative positions using a variety of strategies. Although venture capital investments may be included in some hedge funds, venture capital is broadly considered a type of private equity investing, and is best classified as such.\nC Correct because venture capital funds, a specialized form of private equity that typically involves investing in or providing financing to startup or early-stage companies with high growth potential, represent a small portion of the private equity market."},
  {"num": 2, "subject": "另类投资", "question": "Management fees are most likely based on assets under management for:", "options": {"A": "hedge funds only.", "B": "private equity funds only.", "C": "both hedge funds and private equity funds."}, "answer": "A", "explanation": "A Correct because funds are generally structured with a management fee typically ranging from 1% to 2% of assets under management (e.g. for hedge funds) or committed capital (e.g. private equity funds), which is how much money in total that LP's have committed to the fund's future investments.\nB Incorrect because funds are generally structured with a management fee typically ranging from 1% to 2% of assets under management (e.g. for hedge funds) or committed capital (e.g. private equity funds), which is how much money in total that LP's have committed to the fund's future investments.\nC Incorrect because funds are generally structured with a management fee typically ranging from 1% to 2% of assets under management (e.g. for hedge funds) or committed capital (e.g. private equity funds), which is how much money in total that LP's have committed to the fund's future investments."},
  {"num": 3, "subject": "另类投资", "question": "A feature that protects hedge fund clients from paying twice for the same performance is most likely a:", "options": {"A": "discount.", "B": "hurdle rate.", "C": "high-water mark."}, "answer": "C", "explanation": "A Incorrect because hedge fund managers may discount their fees for larger investors or for placement agents who introduced these investors. However, a rebate does not, in isolation, protect clients from paying twice for the same performance.\nB Incorrect because the partnership agreement usually specifies that the performance fee is earned only after the fund achieves a return known as a hurdle rate. The hurdle rate is a minimum rate of return, typically 8%, that the GP must exceed in order to earn the performance fee. GPs typically receive 20% of the total profit of the private equity fund net of any hard hurdle rate, in which case the GP earns fees on annual returns in excess of the hurdle rate, or net of the soft hurdle rate, in which case the fee is calculated on the entire annual gross return as long as the set hurdle is exceeded.\nC Correct because in hedge funds, fee calculations also take into account a high-water mark, which reﬂects the highest value used to calculate an incentive fee. A high-water mark is the highest value of the fund investment ever achieved at a performance fee crystallization date, net of fees, by the individual LP. A high-water mark clause states that a hedge fund manager must recuperate declines in value from the high-water mark before performance fees can be charged on newly generated profits. The use of high-water marks protects clients from paying twice for the same performance."},
  {"num": 4, "subject": "另类投资", "question": "In co-investing, the investor invests in alternative assets indirectly through a fund but also has the:", "options": {"A": "right to invest directly in the same assets alongside the fund.", "B": "obligation to invest directly in the same assets alongside the fund.", "C": "right to invest in the general partner's fund management company."}, "answer": "A", "explanation": "A Correct because in co-investing, the investor invests in assets indirectly through the fund but also possesses rights (known as co-investment rights) to invest directly in the same assets. Through co-investing, an investor is able to make an investment alongside a fund when the fund identifies deals; the investor is not limited to participating in the deal solely by investing in the fund.\nB Incorrect because in co-investing, the investor invests in assets indirectly through the fund but also possesses rights (known as co-investment rights) to invest directly in the same assets. However, there is no obligation to invest.\nC Incorrect because in co-investing, the investor invests in assets indirectly through the fund but also possesses rights (known as co-investment rights) to invest directly in the same assets, not in the general partner's fund management company."},
  {"num": 5, "subject": "另类投资", "question": "Which of the following methods of investing in alternative investments provides the most flexibility to the investor?", "options": {"A": "Co-investing", "B": "Fund investing", "C": "Direct investing"}, "answer": "C", "explanation": "A Incorrect because direct investing provides the greatest amount of flexibility for the investor and grants the highest level of control over how the asset is managed.\nB Incorrect because direct investing provides the greatest amount of flexibility for the investor and grants the highest level of control over how the asset is managed.\nC Correct because direct investing allows the investor to build a portfolio of investments to her exact requirements. Direct investing provides the greatest amount of flexibility for the investor and grants the highest level of control over how the asset is managed."},
  {"num": 6, "subject": "另类投资", "question": "Compared with fund investing in alternative investments, the co-investing method most likely has:", "options": {"A": "lower management fees.", "B": "the same level of management fees.", "C": "higher management fees."}, "answer": "A", "explanation": "A Correct because one of the advantages of co-investing is that it has reduced management fees. In co-investing, investors co-invest an additional amount into that same investment often without paying management fees on the capital they used for the direct investment (a co-investment, in this case).\nB Incorrect because one of the advantages of co-investing is that it has reduced management fees compared with the fund investing method.\nC Incorrect because one of the advantages of co-investing is that it has reduced management fees compared with the fund investing method."},
  {"num": 7, "subject": "另类投资", "question": "Compared with co-investing, direct investing in alternative investments most likely offers:", "options": {"A": "reduced control over the investment selection process.", "B": "the same level of control over the investment selection process.", "C": "higher control over the investment selection process."}, "answer": "C", "explanation": "A Incorrect because co-investing offers reduced control over the investment selection process compared with direct investing. Hence, direct investing offers higher control over the investment selection process.\nB Incorrect because co-investing offers reduced control over the investment selection process compared with direct investing. Hence, direct investing offers higher control over the investment selection process.\nC Correct because co-investing offers reduced control over the investment selection process compared with direct investing. Hence, direct investing offers higher control over the investment selection process."},
  {"num": 8, "subject": "另类投资", "question": "Alternative investments:", "options": {"A": "include tangible assets only.", "B": "include intangible assets only.", "C": "may include both tangible and intangible assets."}, "answer": "C", "explanation": "A Incorrect because alternative Investments into three categories and several subcategories as follows: 1. Private Capital 2. Real Assets 3. Hedge Funds. Other “real asset” investments may include tangible assets, such as fine wine, art, antique furniture and automobiles, stamps, coins, and other collectibles, and intangible assets, such as patents and litigation actions.\nB Incorrect because alternative Investments into three categories and several subcategories as follows: 1. Private Capital 2. Real Assets 3. Hedge Funds. Other “real asset” investments may include tangible assets, such as fine wine, art, antique furniture and automobiles, stamps, coins, and other collectibles, and intangible assets, such as patents and litigation actions.\nC Correct because alternative Investments into three categories and several subcategories as follows: 1. Private Capital 2. Real Assets 3. Hedge Funds. Other “real asset” investments may include tangible assets, such as fine wine, art, antique furniture and automobiles, stamps, coins, and other collectibles, and intangible assets, such as patents and litigation actions."},
  {"num": 9, "subject": "另类投资", "question": "Which of the following is most appropriately categorized as a traditional investment?", "options": {"A": "Gold", "B": "Cash", "C": "Real estate"}, "answer": "B", "explanation": "A Incorrect because alternative investments include such assets as real estate and commodities (including gold), which are arguably two of the oldest types of investments.\nB Correct because alternative investments' is a label for a disparate group of investments that are distinguished from long-only, publicly traded investments in stocks, bonds, and cash (often referred to as traditional investments).\nC Incorrect because alternative investments include such assets as real estate and commodities, which are arguably two of the oldest types of investments."},
  {"num": 10, "subject": "另类投资", "question": "Which of the following statements is most accurate? Alternative investments:", "options": {"A": "tend to be more efficiently priced than traditional investments.", "B": "fall outside of the definition of long-only positions in stocks, bonds, and cash.", "C": "have relatively high correlation of returns with those of traditional investments."}, "answer": "B", "explanation": "A Incorrect because alternative assets, by their very nature, tend to be less efficiently priced than traditional marketable securities, providing an opportunity to exploit market inefficiencies through active management.\nB Correct because investing in alternative assets can require handling illiquidity, transacting on private markets, operating sophisticated investment strategies, or risk–return profiles that are very different from those of traditional long-only investments.\nC Incorrect because alternative investments often have relatively low correlation of returns with those of traditional investments."},
  {"num": 11, "subject": "另类投资", "question": "Institutional investors typically begin investing in alternative investments via:", "options": {"A": "co-investing.", "B": "fund investing.", "C": "direct investing."}, "answer": "B", "explanation": "A Incorrect because institutional investors typically begin investing in alternative investments via funds. Then, as they gain experience, they can begin to invest via co-investing and direct investing.\nB Correct because institutional investors typically begin investing in alternative investments via funds. Then, as they gain experience, they can begin to invest via co-investing and direct investing. The largest and most sophisticated direct investors (such as some sovereign wealth funds) compete with fund managers for access to the best investment opportunities.\nC Incorrect because institutional investors typically begin investing in alternative investments via funds. Then, as they gain experience, they can begin to invest via co-investing and direct investing."},
  {"num": 12, "subject": "另类投资", "question": "Investors in alternative assets who seek liquidity are most likely to invest in:", "options": {"A": "hedge funds.", "B": "private equity.", "C": "real estate investment trusts."}, "answer": "C", "explanation": "A Incorrect because investors in modern hedge funds are subject to extended holding periods (known as lockup periods) and subsequent notice periods before an investment redemption is possible.\nB Incorrect because private equity funds may have long lockup periods. Typically, a private equity fund has an investment period of approximately five years and a subsequent harvesting period when exit occurs and the valuation environment becomes more relevant. Moreover, private equity fund investments are not made in one single payment but are spread over time using committed capital over several years.\nC Correct because real estate investment trusts are publicly traded and thus provide liquidity."},
  {"num": 13, "subject": "另类投资", "question": "Within a limited partnership structure, the limited partner is most likely to:", "options": {"A": "jointly control the operations and decisions of the fund.", "B": "have total commitments to the fund limited to the upfront cash outflows.", "C": "be expected to understand and be able to assume the risks associated with the investments."}, "answer": "C", "explanation": "A Incorrect because the operations and decisions of the fund are controlled solely by the GP.\nB Incorrect because LPs commit to future investments, and the upfront cash outflow can be a small portion of their total commitment to the fund.\nC Correct because in limited partnerships, the fund manager is the general partner (GP) and investors are the limited partners (LPs). LPs, who are generally accredited investors (owing to legal restrictions on the fund), are expected to understand and be able to assume the risks associated with the investments, which are less regulated than offerings to the general public."},
  {"num": 14, "subject": "另类投资", "question": "Which of the following statements about limited partnerships is most accurate? Limited partners:", "options": {"A": "play passive roles in the partnership.", "B": "are involved in the management of the partnership.", "C": "make only limited decisions related to the operations of the partnership."}, "answer": "A", "explanation": "A Correct because LPs play passive roles and are not involved with the management of the fund.\nB Incorrect because the GP (not LPs) runs the business. LPs play passive roles and are not involved with the management of the fund.\nC Incorrect because LPs are not involved in the operations of the partnership. LPs play passive roles and are not involved with the management of the fund; the operations and decisions of the fund are controlled solely by the GP."},
  {"num": 15, "subject": "另类投资", "question": "In alternative investments, the American waterfall distribution method is more advantageous to the:", "options": {"A": "limited partners because performance fees are collected on a per-deal basis.", "B": "general partner because performance fees are collected on a per-deal basis.", "C": "limited partners because the general partner does not participate in any profits until the hurdle rate has been met."}, "answer": "B", "explanation": "A Incorrect because deal-by-deal waterfalls are more advantageous to general partners (GPs), not limited partners (LPs). This allows the GP to get paid before LPs receive both their initial investment and their preferred rate of return on the entire fund. There are two types of waterfalls: deal-by-deal (or American) waterfalls and whole-of-fund (or European) waterfalls. Deal-by-deal waterfalls are more advantageous to the GP because performance fees are collected on a per-deal basis, allowing the GP to get paid before LPs receive both their initial investment and their preferred rate of return (i.e., the hurdle rate) on the entire fund.\nB Correct because this allows the general partner (GP) to get paid before limited partners (LPs) receive both their initial investment and their preferred rate of return on the entire fund. There are two types of waterfalls: deal-by-deal (or American) waterfalls and whole-of-fund (or European) waterfalls. Deal-by-deal waterfalls are more advantageous to the GP because performance fees are collected on a per-deal basis, allowing the GP to get paid before LPs receive both their initial investment and their preferred rate of return (i.e., the hurdle rate) on the entire fund.\nC Incorrect because this describes an advantage of whole-of-fund (European) waterfalls for limited partners (LPs), not deal-by-deal (American) waterfalls. There are two types of waterfalls: deal-by-deal (or American) waterfalls and whole-of-fund (or European) waterfalls. Deal-by-deal waterfalls are more advantageous to the GP because performance fees are collected on a per-deal basis, allowing the GP to get paid before LPs receive both their initial investment and their preferred rate of return (i.e., the hurdle rate) on the entire fund. In whole-of-fund waterfalls, all distributions go to the LPs as deals are exited and the GP does not participate in any profits until the LPs receive their initial investment and the hurdle rate has been met. In contrast to deal-by-deal waterfalls, whole-of-fund waterfalls occur at the aggregate fund level and are more advantageous to the LPs."},
  {"num": 16, "subject": "另类投资", "question": "The clawback provision of a private equity fund most likely benefits the:", "options": {"A": "broker.", "B": "investors.", "C": "general partner."}, "answer": "B", "explanation": "A Incorrect because a clawback is a provision in the limited partnership agreement between investors and the fund manager(s), and not related to brokers.\nB Correct because a clawback provision reﬂects the right of LPs to reclaim part of the GP’s performance fee. Along either waterfall path, if a GP ever accrues (or actually pays itself) an incentive fee on gains that are not yet fully realized and then subsequently gives back these gains, an investor is typically able to claw back prior incentive fee accruals and payments.\nC Incorrect because a clawback provision is specifically designed to protect investors, not the GPs."},
  {"num": 17, "subject": "另类投资", "question": "A private equity fund structured as a partnership is managed by:", "options": {"A": "the general partner only.", "B": "the limited partners only.", "C": "both the general partner and the limited partners."}, "answer": "A", "explanation": "A Correct because in the world of alternative investments, partnership structures are common. In limited partnerships, the fund manager is the general partner (GP) and investors are the limited partners (LPs). LPs, who are generally accredited investors (owing to legal restrictions on the fund), are expected to understand and be able to assume the risks associated with the investments, which are less regulated than offerings to the general public. The GP runs the business and theoretically bears unlimited liability for anything that goes wrong. The GP may also run multiple funds at a time.\nB Incorrect because in the world of alternative investments, partnership structures are common. In limited partnerships, the fund manager is the general partner (GP) and investors are the limited partners (LPs). LPs, who are generally accredited investors (owing to legal restrictions on the fund), are expected to understand and be able to assume the risks associated with the investments, which are less regulated than offerings to the general public. The GP runs the business and theoretically bears unlimited liability for anything that goes wrong. The GP may also run multiple funds at a time. Limited partners are outside investors who own a fractional interest in the partnership based on the amount of their initial investment and the terms set out in the partnership documentation.\nC Incorrect because in the world of alternative investments, partnership structures are common. In limited partnerships, the fund manager is the general partner (GP) and investors are the limited partners (LPs). LPs, who are generally accredited investors (owing to legal restrictions on the fund), are expected to understand and be able to assume the risks associated with the investments, which are less regulated than offerings to the general public. The GP runs the business and theoretically bears unlimited liability for anything that goes wrong. The GP may also run multiple funds at a time. Limited partners are outside investors who own a fractional interest in the partnership based on the amount of their initial investment and the terms set out in the partnership documentation."},
  {"num": 18, "subject": "另类投资", "question": "Until drawdown of capital is complete, the management fee on a private equity fund is most likely based on:", "options": {"A": "drawn capital.", "B": "invested capital.", "C": "committed capital."}, "answer": "C", "explanation": "A Incorrect because management fees for private equity are typically based on committed capital, not capital that is drawn down.\nB Incorrect because management fees for private equity are typically based on committed capital, not capital that is invested.\nC Correct because private equity funds raise committed capital and draw down on those commitments, generally over three to five years, when they have a specific investment to make. Note that the management fee is typically based on committed capital, not invested capital; the committed-capital basis for management fees is an important distinction from hedge funds, whose management fees are based on assets under management (AUM)."},
  {"num": 19, "subject": "另类投资", "question": "A hedge fund's lockup period is best defined as the required period of time before:", "options": {"A": "incentive fees are earned.", "B": "redemptions are permitted.", "C": "committed capital is drawn down."}, "answer": "B", "explanation": "A Incorrect because funds are generally structured with a management fee typically ranging from 1% to 2% of assets under management (e.g., for hedge funds) or committed capital (e.g., for private equity funds), which is how much money in total that LPs have committed to the fund’s future investments. On top of the management fee, a performance fee (also referred to as an incentive fee or carried interest) is applied based on excess returns. Although performance or incentive fees may be calculated over multiple periods, or limited in some periods to account for high water marks or hurdle rates, those time periods are not referred to as lockup periods.\nB Correct because investors in modern hedge funds are subject to extended holding periods (known as lockup periods) and subsequent notice periods before an investment redemption is possible. As noted previously, restrictions on redemptions are typically imposed. Investors may be required to keep their money in the hedge fund for a minimum period (referred to as a lockup period) before they are allowed to make withdrawals or redeem shares.\nC Incorrect because it describes a draw-down period for private equity funds, not a lockup period. Funds are generally structured with a management fee typically ranging from 1% to 2% of assets under management (e.g., for hedge funds) or committed capital (e.g., for private equity funds), which is how much money in total that LPs have committed to the fund’s future investments. On top of the management fee, a performance fee (also referred to as an incentive fee or carried interest) is applied based on excess returns. Private equity funds raise committed capital and draw down on those commitments, generally over three to five years, when they have a specific investment to make."},
  {"num": 20, "subject": "另类投资", "question": "A hedge fund feature that allows an incentive fee to be earned only after the fund exceeds a specified return best defines a:", "options": {"A": "lockup.", "B": "hurdle rate.", "C": "high-water mark."}, "answer": "B", "explanation": "A Incorrect because investors in modern hedge funds are subject to extended holding periods (known as lockup periods) and subsequent notice periods before an investment redemption is possible. As noted previously, restrictions on redemptions are typically imposed. Investors may be required to keep their money in the hedge fund for a minimum period (referred to as a lockup period) before they are allowed to make withdrawals or redeem shares.\nB Correct because the hurdle rate is a minimum rate of return, typically 8%, that the GP must exceed in order to earn the performance fee. GPs typically receive 20% of the total profit of the private equity fund net of any hard hurdle rate, in which case the GP earns fees on annual returns in excess of the hurdle rate, or net of the soft hurdle rate, in which case the fee is calculated on the entire annual gross return as long as the set hurdle is exceeded.\nC Incorrect because in hedge funds, fee calculations also take into account a high-water mark, which reflects the highest value used to calculate an incentive fee. A high-water mark is the highest value of the fund investment ever achieved at a performance fee crystallization date, net of fees, by the individual LP. A high-water mark clause states that a hedge fund manager must recuperate declines in value from the high-water mark before performance fees can be charged on newly generated profits. The use of high-water marks protects clients from paying twice for the same performance."},
  {"num": 21, "subject": "另类投资", "question": "An analyst gathers the following information about a hedge fund:\n$200 million in assets under management at the beginning of year", "options": {"A": "$11 million.", "B": "$14 million.", "C": "$15 million."}, "answer": "B", "explanation": "A Incorrect because it is the amount if the sum of the incentive and management fees based on the dollar returns for the year ($250 million less $200 million). That is, the sum of the management fee of $1 million ($50 million times 0.02) and the incentive fee of $10 million ($50 million times 0.20), which is $11 million.\nB Correct because it calculates the incentive fee net of the management fee. That is, the total fee is the sum of the management fee of $5 million ($250 million AUM times 0.02) and the incentive fee of $9 million ($250 million less $200 million less the $5 million incentive times 0.20), which is $14 million.\nC Incorrect because it is the amount if the incentive and management fees are calculated independently (rather than if the incentive fee is calculated net of the management fee). That is, the sum of the management fee of $5 million ($250 million AUM times 0.02) and the incentive fee of $10 million ($250 million less $200 million for at profit of $50 million times 0.20), which is $15 million."},
  {"num": 22, "subject": "另类投资", "question": "A hedge fund has the following characteristics:\nIf the performance fee is calculated net of the management fee and there were no capital contributions or withdrawals, the net annual return to the investor is closest to:", "options": {"A": "16.3%.", "B": "16.4%.", "C": "16.5%."}, "answer": "B", "explanation": "A Incorrect because the performance fee is not calculated net of the management fee: Management fee = $100 million × 120% × 1% = $1.200 million. Performance fee = [($100 million × 20%) – ($100 million × 3%)] × 15% = $2.550 million. Total fee = $1.200 million + $2.550 million = $3.750 million. Investor return = ($20 – $3.750) / $100 = 16.250% ≈ 16.3%.\nB Correct because the hurdle rate is a minimum rate of return, typically 8%, that the GP must exceed in order to earn the performance fee. GPs typically receive 20% of the total profit of the private equity fund net of any hard hurdle rate, in which case the GP earns fees on annual returns in excess of the hurdle rate, or net of the soft hurdle rate, in which case the fee is calculated on the entire annual gross return as long as the set hurdle is exceeded. Management fee = $100 million × 120% × 1% = $1.200 million. Performance fee = [($100 million × 20%) – ($100 million × 3%) − $1.200 million)] × 15% = $2.370 million. Total fee = $1.200 million + $2.370 million = $3.570 million. Investor return = ($20 – $3.570) / $100 = 16.430% ≈ 16.4%.\nC Incorrect because the hurdle rate is deducted from the performance fee rate rather than the rate of return:"},
  {"num": 23, "subject": "另类投资", "question": "An analyst collects the following information about a hedge fund:\nIf the incentive fee is calculated on returns in excess of a 6% hurdle rate, total annual fees earned by the fund manager are closest to:", "options": {"A": "$34,800,000.", "B": "$70,800,000.", "C": "$78,000,000."}, "answer": "B", "explanation": "A Incorrect because it fails to add the management fee to the incentive fee. The incentive fee is calculated as [$1,800,000,000 − $1,500,000,000 – ($1,500,000,000 × 6%) − $36,000,000] × 20% = $34,800,000.\nB Correct because the hurdle rate is a minimum rate of return, typically 8%, that the GP must exceed in order to earn the performance fee. GPs typically receive 20% of the total profit of the private equity fund net of any hard hurdle rate, in which case the GP earns fees on annual returns in excess of the hurdle rate, or net of the soft hurdle rate, in which case the fee is calculated on the entire annual gross return as long as the set hurdle is exceeded. The management fee is calculated as $1,500,000,000 × (1 + 20%) × 2% = $36,000,000 and the incentive fee is calculated as [$1,800,000,000 − $1,500,000,000 – ($1,500,000,000 × 6%) − $36,000,000] × 20% = $34,800,000. Therefore, the total fees earned by the manager are $36,000,000 + $34,800,000 = $70,800,000.\nC Incorrect because it fails to net the management fee from the incentive fee. The incentive fee is calculated as [$1,800,000,000 − $1,500,000,000 − ($1,500,000,000 × 6%)] × 20% = $42,000,000. Therefore, the total fees earned by the manager are $36,000,000 + $42,000,000 = $78,000,000."},
  {"num": 24, "subject": "另类投资", "question": "Which of the following has most likely been designed to provide an opportunity for a hedge fund manager to liquidate positions in an orderly fashion without magnifying the losses?", "options": {"A": "Notice periods", "B": "Lockup periods", "C": "Redemption fees"}, "answer": "A", "explanation": "A Correct because notice periods provide an opportunity for the hedge fund manager to liquidate a position in an orderly fashion without magnifying the losses.\nB Incorrect because lockup periods—time periods when investors cannot withdraw their capital—provide the hedge fund manager the required time to implement and potentially realize a strategy’s expected results.\nC Incorrect because funds sometimes charge redemption fees (typically payable to the remaining investors) to discourage redemption and to offset the transaction costs for remaining investors."},
  {"num": 25, "subject": "另类投资", "question": "The lag in marking private equity investments to market most likely makes private equity appear:", "options": {"A": "less volatile than it really is.", "B": "less resilient than it really is.", "C": "more correlated with traditional assets than it really is."}, "answer": "A", "explanation": "A Correct because the lagging impact of shorter-term economic events on the interim accounting valuations of these strategies makes them appear more resilient and less correlated than they really are. A more realistic picture may emerge when premature portfolio liquidations are forced on managers. The lack of transparency around such investments and the slowness to mark them to market can be incorrectly construed by investors as an overall lack of volatility.\nB Incorrect because the lagging impact of shorter-term economic events on the interim accounting valuations of these strategies makes them appear more resilient and less correlated than they really are. The lack of transparency around such investments and the slowness to mark them to market can be incorrectly construed by investors as an overall lack of volatility.\nC Incorrect because the lagging impact of shorter-term economic events on the interim accounting valuations of these strategies makes them appear more resilient and less correlated than they really are. The lack of transparency around such investments and the slowness to mark them to market can be incorrectly construed by investors as an overall lack of volatility."},
  {"num": 26, "subject": "另类投资", "question": "A hedge fund has the following characteristics:\nInitial investment capital of $200 million;\n2% management fee, based on assets under management at the end of the year;\n20% incentive fee, calculated independent of the management fee and based on returns in excess of a 7% hurdle rate.\nIf the fund's return is 18% at the end of the first year, the fund's investors' net return is closest to:", "options": {"A": "12.0%.", "B": "13.4%.", "C": "13.9%."}, "answer": "B", "explanation": "A Incorrect because the incentive fee ignores the hurdle rate (in $ millions): Management fee: 236 × 0.02 = 4.72 Incentive fee: (236 – 200) × 0.20 = 7.20 Total fees paid to the hedge fund manager: 4.72 + 7.20 = 11.92 Investor's return: (236 – 200 – 11.92) ÷ 200 = 12.04% ≈ 12.0%.\nB Correct because the partnership agreement usually specifies that the performance fee is earned only after the fund achieves a return known as a hurdle rate. The hurdle rate is a minimum rate of return, typically 8%, that the GP must exceed in order to earn the performance fee. GPs typically receive 20% of the total profit of the private equity fund net of any hard hurdle rate, in which case the GP earns fees on annual returns in excess of the hurdle rate, or net of the soft hurdle rate, in which case the fee is calculated on the entire annual gross return as long as the set hurdle is exceeded. Accordingly, (in $ millions): AUM at the beginning of the year: 200 AUM at the end of the year: 200 × (1 + 0.18) = 236 Management fee: 236 × 0.02 = 4.72 Incentive fee: [236 – 200 – (200 × 0.07)] × 0.20 = 4.40 Total fees paid to the hedge fund manager: 4.72 + 4.40 = 9.12 Investor's return: (236 – 200 – 9.12) ÷ 200 = 13.44% ≈ 13.4%.\nC Incorrect because the incentive fee is calculated net of the management fee (in $ millions):"},
  {"num": 27, "subject": "另类投资", "question": "A hedge fund has assets under management of $20 million at the beginning of the year and $24 million at the end of the year. The fund charges a 2% management fee based on year-end assets under management and a 20% incentive fee. If the incentive fee is calculated net of the management fee, the total fee charged for the year is closest to:", "options": {"A": "$0.88 million.", "B": "$1.18 million.", "C": "$1.28 million."}, "answer": "B", "explanation": "A Incorrect because it adds the management and incentive fee together and calculates them on the amount of the return only: ($24 – $20) million × 22% = $880,000 Total fees ≠ $880,000.\nB Correct because: $24 million × 2% = $480,000 management fee ($24 million – $20 million – $480,000) × 20% = $704,000 incentive fee Total fees = $480,000 + $704,000 = $1,184,000.\nC Incorrect because it calculates the incentive fee gross of the management fee:"},
  {"num": 28, "subject": "另类投资", "question": "An analyst collects the following information about a hedge fund:\nThe management fee and incentive fee are based on the year-end value. If the fund generates a gross return of 10%, the net return is closest to:", "options": {"A": "6.2%.", "B": "6.8%.", "C": "7.2%."}, "answer": "C", "explanation": "A Incorrect because the incentive fee is not calculated in excess of the hurdle rate: AUM at period end = $200 million × 110% = $220 million Management fee = $220 million × 2% = $4.4 million Incentive fee = ($220 − $200 − $4.4) × 20% = $3.12 million Total fees = $7.52 million Investor return = ($20 − $7.52) / $200 = 0.0624 ≈ 6.2%.\nB Incorrect because the incentive fee is not calculated net of the management fee: AUM at year end = $200 million × 110% = $220 million Management fee = $220 million × 2% = $4.4 million Incentive fee = ($220 − $200 − $10) × 20% = $2 million Total fees = $6.4 million Investor return = ($20 − $6.4) / $200 = 0.068 = 6.8%.\nC Correct because the hurdle rate is a minimum rate of return, typically 8%, that the GP must exceed in order to earn the performance fee. GPs typically receive 20% of the total profit of the private equity fund net of any hard hurdle rate, in which case the GP earns fees on annual returns in excess of the hurdle rate, or net of the soft hurdle rate, in which case the fee is calculated on the entire annual gross return as long as the set hurdle is exceeded."},
  {"num": 29, "subject": "另类投资", "question": "When market prices are used to value underlying positions held by a hedge fund, the most conservative approach uses:", "options": {"A": "bid prices only.", "B": "the average of bid and ask prices.", "C": "bid prices for longs and ask prices for shorts."}, "answer": "C", "explanation": "A Incorrect because using bid prices only will underestimate the values of short positions, which can only be closed at ask prices.\nB Incorrect because when market prices or quotes are used for valuation, funds may diﬀer in which price or quote they use (bid price, ask price, average quote, or median quote). A common practice is to use an average of the bid and the ask. A more conservative and theoretically more accurate approach is to use bid prices for long positions and ask prices for short positions because these are more realistic prices at which the positions could be closed.\nC Correct because when market prices or quotes are used for valuation, funds may diﬀer in which price or quote they use (bid price, ask price, average quote, or median quote). A common practice is to use an average of the bid and the ask. A more conservative and theoretically more accurate approach is to use bid prices for long positions and ask prices for short positions because these are more realistic prices at which the positions could be closed."},
  {"num": 30, "subject": "另类投资", "question": "A hedge fund has the following fee structure based on year-end assets under management:\nThe incentive fee is calculated net of the management fee. If the gross annual return is 15%, the net-of-fees return to investors is closest to:", "options": {"A": "8.8%.", "B": "10.2%.", "C": "11.7%."}, "answer": "B", "explanation": "A Incorrect because it uses the ending assets rather than the beginning assets in the divisor: AUM at period end = $10 million × 115% = $11.5 million Management fee = $11.5 million × 2% = $230,000 Incentive fee =11.5 million − $10.0 million − $230,000) × 20% = $254,000 Total fee = $230,000+254,000 = $484,000 Investor return ≠ ($11.5 million − $10.0 million − $484,000) / $11.5 million =8.8%.\nB Correct because: AUM at period end = $10 million × 115% = $11.5 million Management fee = $11.5 million × 2% = $230,000 Incentive fee = ($11.5 million − $10.0 million − $230,000) × 20% = $254,000 Total fee = $230,000 + $254,000 = $484,000 Investor return = ($11.5 million − $10.0 million − $484,000) / $10.0 million = 10.16%.\nC Incorrect because the return is calculated by combining the fees on the return, not the full amount of AUM on the management fee:"},
  {"num": 31, "subject": "另类投资", "question": "A hedge fund has the following characteristics:\nIf the management and incentive fees are calculated independently and there were no capital contributions or withdrawals, total fees for Year 2 are closest to:", "options": {"A": "$37.8 million.", "B": "$39.7 million.", "C": "$41.6 million."}, "answer": "C", "explanation": "A Incorrect because the incentive fee is not calculated independent of the management fee: Management fee = $960 million × 0.02 = $19.2 million Hard hurdle = $800 million × 0.06 = $48 million Incentive fee = ($960 million – $800 million – $48 million – $19.2 million) × 0.2 = $18.56 million Total fees = $19.2 million + $18.56 million = $37.76 million ≈ $37.8 million.\nB Incorrect because the hurdle rate is calculated on the basis of ending assets under management (AUM) instead of beginning AUM: Management fee = $960 million × 0.02 = $19.2 million Hard hurdle = $960 million × 0.06 = $57.6 million Incentive fee = ($960 million – $800 million – $57.6 million) × 0.2 = $20.48 million Total fees = $19.2 million + $20.48 million = $39.68 million ≈ $39.7 million.\nC Correct because the hurdle rate is a minimum rate of return, typically 8%, that the GP must exceed in order to earn the performance fee. GPs typically receive 20% of the total profit of the private equity fund net of any hard hurdle rate, in which case the GP earns fees on annual returns in excess of the hurdle rate, or net of the soft hurdle rate, in which case the fee is calculated on the entire annual gross return as long as the set hurdle is exceeded. Total fees are calculated as follows:"},
  {"num": 32, "subject": "另类投资", "question": "A perceived benefit of adding alternative assets to a portfolio of traditional assets is most likely the higher:", "options": {"A": "risk-adjusted return profile of the resulting portfolio.", "B": "regulation and transparency of alternative assets relative to traditional assets.", "C": "expected correlation of returns between alternative assets and traditional assets."}, "answer": "A", "explanation": "A Correct because alternative investments offer broader diversification (because of their lower correlation with traditional asset classes), opportunities for enhanced returns (by increasing the portfolio’s risk–return profile), and potentially increased income through higher yields (particularly compared with traditional investments in low–interest rate periods). Alternative investments’ diversifying potential is part of the motivation for investing in them: Investors perceive an opportunity to improve the risk–return relationship in the portfolio context. Given the historical return, volatility, and correlation profiles of alternative investments, combining a portfolio of alternative investments with a portfolio of traditional investments should improve the overall portfolio’s risk–return profile. Doing so can increase the risk-adjusted return of the overall portfolio because of potentially higher returns to the portfolio and a less-than-perfect correlation with traditional investments.\nB Incorrect because alternative investments often have the characteristic of less regulation and less transparency than traditional investments.\nC Incorrect because alternative investments offer broader diversification (because of their lower correlation with traditional asset classes), opportunities for enhanced returns (by increasing the portfolio’s risk–return profile), and potentially increased income through higher yields (particularly compared with traditional investments in low–interest rate periods). Given the historical return, volatility, and correlation profiles of alternative investments, combining a portfolio of alternative investments with a portfolio of traditional investments should improve the overall portfolio’s risk–return profile. Doing so can increase the risk-adjusted return of the overall portfolio because of potentially higher returns to the portfolio and a less-than-perfect correlation with traditional investments. The better risk-return profile of an investment portfolio gained by diversifying into alternative assets is due to the lower correlation of returns, not higher correlation of returns."},
  {"num": 33, "subject": "另类投资", "question": "Hedge fund mark-to-model valuations most likely reflect a:", "options": {"A": "liquidation value.", "B": "theoretical value.", "C": "publicly traded price."}, "answer": "B", "explanation": "A Incorrect because the very nature of assets that can be valued only on a mark-to-model basis can and should be a concern for the alternative asset investor. A model may reflect an imperfect theoretical valuation and not a true liquidation value.\nB Correct because the very nature of assets that can be valued only on a mark-to-model basis can and should be a concern for the alternative asset investor. A model may reflect an imperfect theoretical valuation and not a true liquidation value.\nC Incorrect because Level 1 assets involve situations where an exchange-traded, publicly traded price is available and is mandated to be used for valuation purposes. When such pricing is not available, outside broker quotes, or Level 2 values, may be relied on. As a final recourse, when such broker quotes are deemed either unavailable or unreliable, assets may be computed using only internal models—a process referred to as Level 3 asset pricing. Mark-to-model valuation is Level 3 asset pricing when a publicly traded price and outside broker quotes are not available."},
  {"num": 34, "subject": "另类投资", "question": "An investor gathers the following information about a hedge fund:\nIf the incentive fee is based on returns net of management fees and the fee structure includes the use of a high-water mark, the investor's net return for the year is closest to:", "options": {"A": "6.24%.", "B": "6.96%.", "C": "7.57%."}, "answer": "C", "explanation": "A Incorrect because it ignores the current high-water mark and computes the incentive fee based on returns net of management fees. Accordingly, End-of-year AUM = Beginning-of-year AUM × (1 + Annual return before fees) = $300,000,000 × (1 + 10%) = $330,000,000. Management fee = Management fee based on end-of-year AUM × End-of-year AUM = 2% × $330,000,000 = $6,600,000. Return net of management fee = End-of-year AUM – Beginning-of-year AUM – Management fee = $330,000,000 – $300,000,000 – $6,600,000 = $23,400,000. Incentive fee = 20% × Return net of management fee = 20% × $23,400,000 = $4,680,000. Total fees = Management fee + Incentive fee = $6,600,000 + $4,680,000 = $11,280,000. Net return = (End-of-year AUM – Beginning-of-year AUM – Total fees) / Beginning-of-year AUM = ($330,000,000 – $300,000,000 – $11,280,000) / $300,000,000 = $18,720,000 / $300,000,000 = 6.24%.\nB Incorrect because the current high-water mark is used as a cap for management fee and incentive fee (instead of the threshold representing the highest cumulative return above which an incentive fee is calculated). Accordingly, Management fee = Management fee based on end-of-year AUM × Current high-water mark = 2% × $320,000,000 = $6,400,000. Return net of management fee and capped by current high-water mark = Current high-water mark – Beginning-of-year AUM – Management fee = $320,000,000 – $300,000,000 – $6,400,000 = $13,600,000. Incentive fee = 20% × Return net of management fee = 20% × $13,600,000 = $2,720,000. Total fees = Management fee + Incentive fee = $6,400,000 + $2,720,000 = $9,120,000. Net return = (End-of-year AUM – Beginning-of-year AUM – Total fees) / Beginning-of-year AUM = ($330,000,000 – $300,000,000 – $9,120,000) / $300,000,000 = $20,880,000 / $300,000,000 = 6.96%.\nC Correct because in hedge funds, fee calculations also take into account a high-water mark, which reﬂects the highest value used to calculate an incentive fee. A high-water mark is the highest value of the fund investment ever achieved at a performance fee crystallization date, net of fees, by the individual LP. A high-water mark clause states that a hedge fund manager must recuperate declines in value from the high-water mark before performance fees can be charged on newly generated profits."},
  {"num": 35, "subject": "另类投资", "question": "Which of the following statements about private debt is most accurate? Mezzanine debt is:", "options": {"A": "funding provided to start-up or early-stage companies generating negative cash flow.", "B": "subordinated to senior secured debt but senior to equity in the borrower’s capital structure.", "C": "a hybrid loan structure that combines different tranches of secured and unsecured debt into a single loan."}, "answer": "B", "explanation": "A Incorrect as this describes venture debt rather than mezzanine debt. Venture debt is private debt funding that provides venture capital backing to start-up or early-stage companies that may be generating little or negative cash flow.\nB Correct because mezzanine debt refers to private credit subordinated to senior secured debt but senior to equity in the borrower’s capital structure.\nC Incorrect as this describes unitranche debt rather than mezzanine debt. Unitranche debt consists of a hybrid or blended loan structure combining different tranches of secured and unsecured debt into a single loan with a single, blended interest rate."},
  {"num": 36, "subject": "另类投资", "question": "Which of the following is most likely a primary exit strategy for a company held by a private equity fund's portfolio?", "options": {"A": "IPO", "B": "Management buy-in", "C": "Management buyout"}, "answer": "A", "explanation": "A Correct because key private equity investment strategies include leveraged buyouts (e.g., MBOs and MBIs) and venture capital. Primary exit strategies include trade sale, IPO, and recapitalization.\nB Incorrect because key private equity investment strategies include leveraged buyouts (e.g., MBOs and MBIs) and venture capital. Primary exit strategies include trade sale, IPO, and recapitalization.\nC Incorrect because key private equity investment strategies include leveraged buyouts (e.g., MBOs and MBIs) and venture capital. Primary exit strategies include trade sale, IPO, and recapitalization."},
  {"num": 37, "subject": "另类投资", "question": "From the perspective of a private equity firm, an advantage of exiting a portfolio company through a special purpose acquisition company (SPAC) most likely include:", "options": {"A": "floating valuation.", "B": "flexibility of the transaction structure.", "C": "lower deal risk due to restrictions on redemptions."}, "answer": "B", "explanation": "A Incorrect because advantages of a SPAC exit include fixed valuation with lower volatility of share pricing.\nB Correct because advantages of a SPAC exit include: a. extended time for public disclosure on company prospects to build investor interest, b. fixed valuation with lower volatility of share pricing, c. flexibility of transaction structure to best suit the company’s context, and d. association with potentially high-profile and seasoned sponsors and their extensive investor network.\nC Incorrect because redemptions are allowed and increase the deal risk. Also, disadvantages include"},
  {"num": 38, "subject": "另类投资", "question": "With respect to private equity, the growth capital strategy is also known as:", "options": {"A": "venture capital.", "B": "recapitalization.", "C": "minority equity investing."}, "answer": "C", "explanation": "A Incorrect because venture capital is a different private equity strategy from growth capital. Venture capital (VC) entails investing in or providing financing to private companies with high growth potential. Typically these are start-ups or young companies, but venture capital can be provided at a variety of stages, ranging from the inception of an idea for a company to the point when the company is about to launch an IPO (initial public offering) or be acquired. Growth capital generally refers to minority equity investments, whereby the firm takes a less-than-controlling interest in more mature companies that are looking for capital to expand or restructure operations, enter new markets, or finance major acquisitions.\nB Incorrect because it is an exit strategy. Recapitalization in the context of private equity describes the steps a firm takes to increase or introduce leverage to its portfolio company and pay itself a dividend out of the new capital structure.\nC Correct because among several other specialties, some private equity firms specialize in growth capital, also known as growth equity or minority equity investing. Growth capital generally refers to minority equity investments, whereby the firm takes a less-than-controlling interest in more mature companies that are looking for capital to expand or restructure operations, enter new markets, or finance major acquisitions."},
  {"num": 39, "subject": "另类投资", "question": "In the private debt market, venture debt:", "options": {"A": "entails buying the debt of mature companies in financial difficulty.", "B": "provides capital to early-stage companies that may be generating little cash flow.", "C": "entails buying the debt of mature companies in financial difficulty and provides capital to early-stage companies that may be generating little cash flow."}, "answer": "B", "explanation": "A Incorrect because this refers to distressed debt. Involvement in distressed debt typically entails buying the debt of mature companies in financial difficulty.\nB Correct because this is the definition of venture debt. Venture debt is private debt funding that provides venture capital backing to start-up or early-stage companies that may be generating little or negative cash flow.\nC Incorrect because the first part of the answer is not correct; as indicated in the correct response, venture debt provides funding to start-up or early-stage companies not mature companies."},
  {"num": 40, "subject": "另类投资", "question": "Which of the following sources of private debt financing may provide equity participation to lenders or investors?", "options": {"A": "Venture debt only", "B": "Mezzanine debt only", "C": "Both venture debt and mezzanine debt"}, "answer": "C", "explanation": "A Incorrect because both venture debt and mezzanine debt might provide equity participation to lenders or investors.\nB Incorrect because both venture debt and mezzanine debt might provide equity participation to lenders or investors.\nC Correct because mezzanine debt often comes with additional features, such as warrants or conversion rights. These provide equity participation to lenders/investors, conveying the option to convert their debt into equity or purchasing the equity of the underlying borrower under certain circumstances. Similar to mezzanine debt, venture debt may carry additional features that compensate the investor/lender for the increased risk of default or for the start-up and early-stage companies that lack substantial assets for debt collateral. One such feature could grant the lender rights to purchase equity in the borrowing company under certain circumstances."},
  {"num": 41, "subject": "另类投资", "question": "Private equity indexes most likely overestimate:", "options": {"A": "volatility.", "B": "performance.", "C": "correlation with traditional assets."}, "answer": "B", "explanation": "A Incorrect because published private equity indexes may be an unreliable measure of performance. Moreover, prior to the global financial crisis of 2008–2009, in the absence of a liquidity event, private equity firms did not necessarily mark their investments to market. Failure to mark to market combined with the lag to mark investments due to inherent illiquidity will understate measures of volatility and correlations with other investments.\nB Correct because published private equity indexes may be an unreliable measure of performance. Measuring historical private equity performance is challenging; as with hedge funds, which will be discussed later, private equity return indexes typically rely on self-reporting and are subject to survivorship, backfill, and other biases. This typically leads to an overstatement of returns.\nC Incorrect because published private equity indexes may be an unreliable measure of performance. Moreover, prior to the global financial crisis of 2008–2009, in the absence of a liquidity event, private equity firms did not necessarily mark their investments to market. Failure to mark to market combined with the lag to mark investments due to inherent illiquidity will understate measures of volatility and correlations with other investments."},
  {"num": 42, "subject": "另类投资", "question": "An exit strategy where a private equity manager sells a company to a strategic buyer in the same industry best describes a:", "options": {"A": "trade sale.", "B": "secondary sale.", "C": "recapitalization."}, "answer": "A", "explanation": "A Correct because in a trade sale, a portion or a division of the private company is sold either via direct sale or auction to a strategic buyer interested in increasing the scale and scope of the existing business.\nB Incorrect because this approach represents a sale of the company to another private equity firm or group of financial buyers.\nC Incorrect because a recapitalization is not a true exit strategy, because the private equity firm typically maintains control; however, it does allow the private equity investor to extract money from the company to pay its investors and improve its internal rate of return (IRR)."},
  {"num": 43, "subject": "另类投资", "question": "Which of the following entails buying the debt of mature companies in financial difficulty?", "options": {"A": "Venture debt", "B": "Distressed debt", "C": "Unitranche debt"}, "answer": "B", "explanation": "A Incorrect because venture debt is private debt funding that provides venture capital backing to start-up or early-stage companies that may be generating little or negative cash flow. Venture debt does not entail buying the debt of mature companies in financial difficulty.\nB Correct because involvement in distressed debt entails buying the debt of mature companies in financial difficulty.\nC Incorrect because unitranche debt consists of a hybrid or blended loan structure combining different tranches of secured and unsecured debt into a single loan with a single, blended interest rate. Unitranche debt does not entail buying the debt of mature companies in financial difficulty."},
  {"num": 44, "subject": "另类投资", "question": "Compared to unsecured debt, unitranche debt most likely features:", "options": {"A": "lower borrowing costs.", "B": "the same borrowing costs.", "C": "higher borrowing costs."}, "answer": "A", "explanation": "A Correct because since unitranche debt is a blend of secured and unsecured debt, its interest rate will generally fall in between the interest rates often demanded on secured and unsecured debt. That is, unitranche loans will most likely be less costly than unsecured loans.\nB Incorrect because since unitranche debt is a blend of secured and unsecured debt, its interest rate will generally fall in between the interest rates often demanded on secured and unsecured debt. That is, unitranche loans will most likely be less costly than, not equally as costly as, unsecured loans.\nC Incorrect because since unitranche debt is a blend of secured and unsecured debt, its interest rate will generally fall in between the interest rates often demanded on secured and unsecured debt. That is, unitranche loans will most likely be less costly than, not more costly than, unsecured loans."},
  {"num": 45, "subject": "另类投资", "question": "Which of the following are best categorized as social infrastructure assets?", "options": {"A": "Airports", "B": "Correctional facilities", "C": "Telecommunication towers"}, "answer": "B", "explanation": "A Incorrect because infrastructure investments are frequently categorized on the basis of the underlying assets. The broadest categorization organizes investments into economic and social infrastructure assets. Economic infrastructure assets support economic activity and include three broad types of assets: transportation assets, information and communication technology (ICT) assets, and utility and energy assets. Transportation assets include roads, bridges, tunnels, airports, seaports, and heavy and light/urban railway systems.\nB Correct because infrastructure investments are frequently categorized on the basis of the underlying assets. The broadest categorization organizes investments into economic and social infrastructure assets. Social infrastructure assets are directed toward human activities and include such assets as educational, health care, social housing, and correctional facilities, with the focus on providing, operating, and maintaining the asset infrastructure.\nC Incorrect because infrastructure investments are frequently categorized on the basis of the underlying assets. The broadest categorization organizes investments into economic and social infrastructure assets. Economic infrastructure assets support economic activity and include three broad types of assets: transportation assets, information and communication technology (ICT) assets, and utility and energy assets. ICT assets include infrastructure that stores, broadcasts, and transmits information or data, such as telecommunication towers and data centers."},
  {"num": 46, "subject": "另类投资", "question": "Which of the following infrastructure investments most likely have the highest risk?", "options": {"A": "Brownfield investments with the majority of their return from current yield.", "B": "Brownfield investments with the majority of their return from capital appreciation.", "C": "Greenfield investments with the majority of their return from capital appreciation."}, "answer": "C", "explanation": "A Incorrect because infrastructure funds with a lower-risk profile invest in Brownfield assets with mitigated risks and with high weighting to current yield. Investing in existing infrastructure assets may be referred to as brownfield investment.\nB Incorrect because infrastructure funds with a medium-risk profile invest in mostly brownfield assets (with some capital expenditure requirements) and with a mix of yield and capital appreciation. Investing in existing infrastructure assets may be referred to as brownfield investment. Even if a brownfield investment had the majority of its return derived from capital appreciation, it would still be less risky than a greenfield investment. Brownfield investments are mid-stage or late-stage investments, still delivering prospects for return through capital gain & yield (albeit generally at relatively lower level than early stage investments).\nC Correct because infrastructure funds with a higher-risk profile invest in Greenfield projects without guarantees of demand upon completion and with high weighting to capital appreciation. Investing in infrastructure assets that are to be constructed is generally referred to as greenfield investment. Greenfield investments are early-stage investments with a higher-risk profile."},
  {"num": 47, "subject": "另类投资", "question": "Which of the following is most likely a characteristic of private real estate markets?", "options": {"A": "Transaction costs are high", "B": "Private market indexes are investable", "C": "It is easy for small investors to establish a diversified portfolio of wholly owned properties"}, "answer": "A", "explanation": "A Correct because, for private real estate markets, transaction costs are high.\nB Incorrect because private market indexes are not investable, and property typically requires professional operational management.\nC Incorrect because it may be difficult for small investors to establish a diversified portfolio of wholly owned properties."},
  {"num": 48, "subject": "另类投资", "question": "Which of the following statements about real estate assets is most accurate?", "options": {"A": "Real estate assets are heterogeneous", "B": "Commercial property represents the majority of real estate assets by value", "C": "Private real estate has historically had high correlations with other asset classes"}, "answer": "A", "explanation": "A Correct because real estate property has some unique features, including heterogeneity (no two properties are identical) and fixed location.\nB Incorrect because real estate includes two major sectors: residential and commercial. Residential (not commercial) real estate is the largest sector, totaling 75% of the global market.\nC Incorrect because the key reasons for investing in real estate include the following potential benefits: Historically low (not high) correlations with other asset classes."},
  {"num": 49, "subject": "另类投资", "question": "Investors in greenfield infrastructure projects typically:", "options": {"A": "rely on the assets' financial and operating history.", "B": "invest alongside strategic investors or developers.", "C": "have lower development risk than investors in brownfield projects."}, "answer": "B", "explanation": "A Incorrect because it is for brownfield, not greenfield, investors that, typically, some of the assets' financial and operating history is available.\nB Correct because greenfield investors typically invest alongside strategic investors or developers who specialize in developing the underlying assets.\nC Incorrect because investing in infrastructure assets that are to be constructed is generally referred to as greenfield investment. Thus, greenfield investors face higher development and construction risks compared to brownfield investors, and may expect capital appreciation to reflect the construction and commissioning risk."},
  {"num": 50, "subject": "另类投资", "question": "A disadvantage of direct real estate investing is:", "options": {"A": "a lack of control.", "B": "unfavorable tax rules.", "C": "the time required to manage the property."}, "answer": "C", "explanation": "A Incorrect because this is a benefit of direct investing. There are distinct benefits to owning real estate directly. Control: Only the owner decides when to buy or sell, when and how much to spend on capital projects (subject to lease terms and regulatory requirements), whom to select as tenants based on credit quality preference and tenant mix, and what types of lease terms to offer.\nB Incorrect because this is a benefit of direct investing. Tax benefits: Property investors in many developed markets can use non-cash property depreciation expenses and interest expense, with some limitations, to reduce taxable income and lower their income tax bills.\nC Correct because major disadvantages to investing directly in real estate include extensive time required to manage the property. The owner may choose to handle all aspects of investing in and operating the property, including property selection, asset management, property management, leasing, and administration."},
  {"num": 51, "subject": "另类投资", "question": "Which of the following real estate investing strategies is most likely to focus on modest redevelopment or upgrades, the leasing of vacant space, and the repositioning of underlying properties to earn a higher return?", "options": {"A": "Core-plus", "B": "Value-add", "C": "Opportunistic"}, "answer": "B", "explanation": "A Incorrect because core-plus strategies will also accept slightly higher risks derived from non-core markets and sectors or properties with slightly more leasing risk. Non-core properties include large sectors with different risk profiles, such as hotels and nursing homes. Assets in secondary and tertiary markets and such niches as student housing, self-storage, and data centers are also considered non-core.\nB Correct because value-add investments may require modest redevelopment or upgrades, the leasing of vacant space, or repositioning the underlying properties to earn a higher return than core properties.\nC Incorrect because opportunistic investing accepts the much higher risks of development, major redevelopment, repurposing of assets, taking on large vacancies, and speculating on significant improvement in market conditions."},
  {"num": 52, "subject": "另类投资", "question": "With respect to infrastructure investments, a take-or-pay arrangement is most likely used to mitigate:", "options": {"A": "demand risk.", "B": "operational risk.", "C": "construction risk."}, "answer": "A", "explanation": "A Correct because take-or-pay arrangements, which obligate buyers to pay a minimum purchase price to sellers for a pre-agreed volume, are used to mitigate demand/volume risk.\nB Incorrect because take-or-pay arrangements, which obligate buyers to pay a minimum purchase price to sellers for a pre-agreed volume, are used to mitigate demand/volume risk, not operational risk.\nC Incorrect because take-or-pay arrangements, which obligate buyers to pay a minimum purchase price to sellers for a pre-agreed volume, are used to mitigate demand/volume risk, not construction risk."},
  {"num": 53, "subject": "另类投资", "question": "Which of the following is best categorized as core real estate?", "options": {"A": "A high-quality office building in a rural area", "B": "A low-quality office building in a major urban center", "C": "A high-quality office building in a major urban center"}, "answer": "C", "explanation": "A Incorrect because core real estate is characterized by well-leased, high-quality institutional real estate in the best markets.\nB Incorrect because core real estate is characterized by well-leased, high-quality institutional real estate in the best markets.\nC Correct because open-end funds generally offer exposure to core real estate, characterized by well-leased, high-quality institutional real estate in the best markets. Investors expect core real estate to deliver stable returns, primarily from income."},
  {"num": 54, "subject": "另类投资", "question": "The benefits of adding investments in infrastructure assets to a portfolio most likely include:", "options": {"A": "inflation protection only.", "B": "low correlation with existing portfolio assets only.", "C": "both inflation protection and low correlation with existing portfolio assets."}, "answer": "C", "explanation": "A Incorrect because investing in infrastructure may add an income stream, increase portfolio diversification by adding an asset class with typically low correlation with existing investments, and offer some protection against inflation. Low exposure to short-term GDP growth issues may also be a factor.\nB Incorrect because investing in infrastructure may add an income stream, increase portfolio diversification by adding an asset class with typically low correlation with existing investments, and offer some protection against inflation. Low exposure to short-term GDP growth issues may also be a factor.\nC Correct because investing in infrastructure may add an income stream, increase portfolio diversification by adding an asset class with typically low correlation with existing investments, and offer some protection against inflation. Low exposure to short-term GDP growth issues may also be a factor."},
  {"num": 55, "subject": "另类投资", "question": "All else being equal, when a commodity futures market is in contango, the forward curve is most likely:", "options": {"A": "downward sloping.", "B": "flat.", "C": "upward sloping."}, "answer": "C", "explanation": "A Incorrect because when the futures market is trading in backwardation, the futures prices are lower than the spot price, and the commodity forward curve is downward sloping. A market in contango assumes futures prices are higher than the spot price.\nB Incorrect because when futures prices are higher than the spot price, the commodity forward curve is upward sloping, and the prices are referred to as being in contango. A flat forward curve can't be associated with a market in contango because a flat curve implies that all future prices are equal to the spot price while a market in contango assumes futures prices are higher than the spot price.\nC Correct because when futures prices are higher than the spot price, the commodity forward curve is upward sloping, and the prices are referred to as being in contango."},
  {"num": 56, "subject": "另类投资", "question": "If a commodity's storage cost is equal to its convenience yield, its futures prices will be greater than its spot price if the risk-free rate is:", "options": {"A": "negative.", "B": "zero.", "C": "positive."}, "answer": "C", "explanation": "A Incorrect because the futures price can be formalized in the following form: Futures price ≈ Spot price(1 + r) + Storage costs − Convenience yield, where r is the period's short-term risk-free interest rate. Thus, if Storage costs = Convenience yield, then Futures price ≈ Spot price(1 + r). If r < 0, then Futures price < Spot price, not Futures price > Spot price.\nB Incorrect because the futures price can be formalized in the following form: Futures price ≈ Spot price(1 + r) + Storage costs − Convenience yield, where r is the period's short-term risk-free interest rate. Thus, if Storage costs = Convenience yield, then Futures price ≈ Spot price(1 + r). If r = 0, then Futures price ≈ Spot price, not Futures price > Spot price.\nC Correct because the futures price can be formalized in the following form: Futures price ≈ Spot price(1 + r) + Storage costs − Convenience yield, where r is the period's short-term risk-free interest rate. Thus, if Storage costs = Convenience yield, then Futures price ≈ Spot price(1 + r), from which Futures price > Spot price if r > 0."},
  {"num": 57, "subject": "另类投资", "question": "Which of the following is best classified as a commodity?", "options": {"A": "Livestock", "B": "Timberland", "C": "Agricultural land"}, "answer": "A", "explanation": "A Correct because commodity investments may involve investing in actual physical commodities or in producers of commodities. Commodities are considered either 'hard' (those mined, such as copper, or extracted, such as oil) or 'soft' (those grown over a period of time, such as livestock, grains, and cash crops, such as coffee).\nB Incorrect because timberland is a separate component of natural resources, not a commodity. Natural resources include commodities (hard and soft), agricultural land (farmland), and timberland.\nC Incorrect because agricultural land is a separate component of natural resources, not a commodity. Natural resources include commodities (hard and soft), agricultural land (farmland), and timberland."},
  {"num": 58, "subject": "另类投资", "question": "Timberland investments offer:", "options": {"A": "an income stream only.", "B": "the potential for capital gain only.", "C": "both an income stream and the potential for capital gain."}, "answer": "C", "explanation": "A Incorrect because timberland investment involves ownership of raw land and the harvesting of its trees for lumber, thus generating an income stream and the potential for capital gain.\nB Incorrect because timberland investment involves ownership of raw land and the harvesting of its trees for lumber, thus generating an income stream and the potential for capital gain.\nC Correct because timberland investment involves ownership of raw land and the harvesting of its trees for lumber, thus generating an income stream and the potential for capital gain."},
  {"num": 59, "subject": "另类投资", "question": "Crude oil is categorized as:", "options": {"A": "a soft commodity.", "B": "a hard commodity.", "C": "neither a soft commodity nor a hard commodity."}, "answer": "B", "explanation": "A Incorrect because oil is categorized as a hard, not a soft, commodity. Commodities are considered either 'hard' (those mined, such as copper, or extracted, such as oil) or 'soft' (those grown over a period of time, such as livestock, grains, and cash crops, such as coffee).\nB Correct because commodities are considered either 'hard' (those mined, such as copper, or extracted, such as oil) or 'soft' (those grown over a period of time, such as livestock, grains, and cash crops, such as coffee).\nC Incorrect because oil is categorized as a hard, not a soft, commodity. Commodities are considered either 'hard' (those mined, such as copper, or extracted, such as oil) or 'soft' (those grown over a period of time, such as livestock, grains, and cash crops, such as coffee)."},
  {"num": 60, "subject": "另类投资", "question": "Which of the following hedge funds most likely have a beta close to zero?", "options": {"A": "Short-biased funds", "B": "Market-neutral funds", "C": "Fundamental long/short growth funds"}, "answer": "B", "explanation": "A Incorrect because the beta in these types of funds is most often negative given the short bias. These strategies use quantitative (technical) and fundamental analysis to focus the bulk of their portfolio on shorting overvalued equity securities (against limited or no long-side exposures).\nB Correct because the hedge fund takes long positions in securities identified as undervalued and short positions in overvalued securities. The hedge fund tries to maintain a net position that is neutral with respect to market risk and other risk factors (size, industry, momentum, value, etc.). Ideally, the portfolio has an overall beta of approximately zero.\nC Incorrect because, although these funds do hedge long positions with short positions, market neutrality is not necessarily a goal. The hedge fund takes long positions in these companies while shorting companies with business models being disintermediated or under downward pressure—where continued revenue growth is deemed unlikely. Portfolios tend to end up long biased."},
  {"num": 61, "subject": "另类投资", "question": "Which of the following statements is most accurate? Hedge funds:", "options": {"A": "may be invested entirely in traditional assets.", "B": "typically invest in early-stage companies with high growth potential.", "C": "typically pursue leveraged buyouts of established profitable and cash-generating companies."}, "answer": "A", "explanation": "A Correct because hedge funds are private investment vehicles that may invest in public equities or publicly traded fixed-income assets, private capital, and/or real assets, but they are distinguished by their investment approach rather than by the investments themselves. Hedge funds make frequent use of leverage, derivatives, short selling, and other investment strategies/ Alternative investments are investments other than ownership of public equity securities, fixed-income instruments, or cash that represent the more traditional asset classes. Even though the investments might be just in traditional assets, like public equities or publicly traded fixed-income assets, the investment approach distinguishes the hedge fund.\nB Incorrect because venture capital is a specialized form of private equity whereby ownership capital is used for non-public companies in the early life cycle or startup phase, where often an idea or business plan exists with a limited operation or customer base.\nC Incorrect because private equity refers to investment in privately owned companies or in public companies with the intent to take them private. In general, private equity is used in the mature life cycle stage or for firms in decline, with leveraged buyouts being a key approach."},
  {"num": 62, "subject": "另类投资", "question": "An activist hedge fund strategy is most likely:", "options": {"A": "based on top-down analysis.", "B": "classified as a relative value strategy.", "C": "implemented in the public equity market."}, "answer": "C", "explanation": "A Incorrect because event-driven strategies (such as activist strategies) seek to profit from defined catalyst events, typically those that involve changes in corporate structure, such as an acquisition or restructuring. This strategy is considered to be underpinned by bottom-up security-specific analysis, as opposed to top-down analysis. Investments may include long and short positions in common and preferred stocks, debt securities, and options.\nB Incorrect because activist strategies are typically categorized as event-driven, as opposed to relative value strategies, which seek to profit from a pricing discrepancy, an unusual short-term relationship, between related securities. The expectation is that the pricing discrepancy will be resolved over time.\nC Correct because the term “activist” is short for “activist shareholder.” Here, managers secure sufficient equity holdings to allow them to inﬂuence a company’s policies or direction. The hedge fund manager thus tries to create his or her own catalyst, inﬂuencing the investment’s ultimate destiny by creating a desired corporate outcome. For example, the activist hedge fund may advocate for divestitures, restructuring, capital distributions to shareholders, or changes in management and company strategy that will aﬀect their equity holdings. Such hedge funds are distinct from private equity because they operate primarily in the public equity market."},
  {"num": 63, "subject": "另类投资", "question": "In contrast to a fund of hedge funds, a single hedge fund is most likely to:", "options": {"A": "charge lower total fees.", "B": "offer better redemption terms.", "C": "make a diversified portfolio of hedge funds accessible to smaller investors."}, "answer": "A", "explanation": "A Correct because single hedge funds come with a lower fee structure than fund of hedge funds. For the investor, fund of funds comes with a higher fee structure—often an additional 1%—because the manager of the fund of funds adds its own fees on top of the hedge fund management fees. Fund-of-funds investors often face a 10% incentive fee in addition to those fees charged by underlying hedge funds.\nB Incorrect because the fund-of-hedge-fund managers are often able to negotiate better redemption or fee terms than individual investors can.\nC Incorrect because funds of hedge funds pool funds from investors and invest the proceeds in a diversified portfolio of hedge fund investments across a variety of hedge funds. Also, funds of funds allow smaller investors to make investments in hedge funds for which the minimum investment and research requirements would otherwise be overly burdensome."},
  {"num": 64, "subject": "另类投资", "question": "Convertible bond arbitrage is best classified as a(n):", "options": {"A": "macro hedge fund strategy.", "B": "event-driven hedge fund strategy.", "C": "relative value hedge fund strategy."}, "answer": "C", "explanation": "A Incorrect because convertible bond arbitrage strategies are classified as relative value strategies. Macro hedge funds emphasize a top-down approach to identify economic trends. Trades are made on the basis of expected movements in economic variables. Generally, these funds trade opportunistically in fixed-income, equity, currency, and commodity markets. Macro hedge funds use long and short positions to profit from a view on the overall direction of the market as it is inﬂuenced by major economic trends and events.\nB Incorrect because convertible bond arbitrage strategies are classified as relative value strategies. Event-driven strategies seek to profit from defined catalyst events, typically those that involve changes in corporate structure, such as an acquisition or restructuring. This strategy is considered to be underpinned by bottom-up security-specific analysis, as opposed to top-down analysis. Investments may include long and short positions in common and preferred stocks, debt securities, and options.\nC Correct because relative value funds seek to profit from a pricing discrepancy, an unusual short-term relationship, between related securities. The expectation is that the pricing discrepancy will be resolved over time. Examples of relative value strategies include the following: Convertible bond arbitrage. Tis conceptually market-neutral investment strategy seeks to exploit a perceived mispricing between a convertible bond and its component parts—namely, the underlying bond and the embedded stock option—relative to the pricing of a reference equity into which the bond may someday convert. The strategy typically involves buying convertible debt securities and simultaneously selling a certain amount of the same issuer’s common stock. Residual bankruptcy risks can be further hedged using equity put options or credit default swap derivative hedges on the credit of the issuer."},
  {"num": 65, "subject": "另类投资", "question": "A hedge fund is most likely characterized by:", "options": {"A": "the ability to use derivatives.", "B": "a prohibition against short positions.", "C": "an absence of restrictions on redemptions."}, "answer": "A", "explanation": "A Correct because a contemporary hedge fund generally has the following characteristics: It is a creatively managed portfolio of investments involved in one or more asset classes (equities, credit, fixed income, commodities, futures, foreign exchange, and sometimes even hard assets, such as real estate), sometimes trading in different geographic regions, that is often leveraged, generally takes both long and short positions (when possible), and quite often uses derivatives to express a view or establish a hedge.\nB Incorrect because a contemporary hedge fund generally has the following characteristics: It is a creatively managed portfolio of investments involved in one or more asset classes (equities, credit, fixed income, commodities, futures, foreign exchange, and sometimes even hard assets, such as real estate), sometimes trading in different geographic regions, that is often leveraged, generally takes both long and short positions (when possible), and quite often uses derivatives to express a view or establish a hedge.\nC Incorrect because investors in modern hedge funds are subject to extended holding periods (known as lockup periods) and subsequent notice periods before an investment redemption is possible."},
  {"num": 66, "subject": "另类投资", "question": "Compared to traditional financial assets, digital assets:", "options": {"A": "can be invested in through indirect investment vehicles such as ETFs.", "B": "are generally recorded in private ledgers maintained by central intermediaries.", "C": "do not have an inherent value based on underlying assets or on potential cash flows."}, "answer": "C", "explanation": "A Incorrect because the main similarity (not difference) between these asset types is the emergence of indirect investment vehicles such as exchange-traded funds (ETFs) and hedge funds that invest both in traditional financial assets and in digital assets.\nB Incorrect because one key difference between digital assets and traditional financial instruments is that traditional (not digital) assets are generally recorded in private ledgers maintained by central intermediaries.\nC Correct because, unlike financial assets, most digital assets do not have an inherent value based on underlying assets or on the potential cash flow."},
  {"num": 67, "subject": "另类投资", "question": "Which of the following forms of digital asset investment most likely involves the use of a cryptocurrency wallet?", "options": {"A": "Direct investment", "B": "Indirect investment via ETFs", "C": "Indirect investment via coin trusts"}, "answer": "A", "explanation": "A Correct because digital asset investment can take the form of direct investment on the blockchain or indirect investments. Direct ownership of bitcoin and other cryptocurrencies involves the use of a cryptocurrency wallet, which stores the (public and private) digital codes required to access the asset on a computer website or mobile device application.\nB Incorrect because an increasing number of exchange-traded products, such as ETFs, seek to replicate digital asset investment returns. These ETFs typically do not directly invest in cryptocurrencies and gain exposure to the value of cryptocurrencies using cash and cryptocurrency derivatives. Since no direct investment is made, a cryptocurrency wallet is not required.\nC Incorrect because cryptocurrency coin trusts allow investors to trade shares in trusts holding large pools of a cryptocurrency and that trade over the counter (OTC) and behave like closed-end funds. For an investor in a coin trust, there is no need to create a digital wallet and use encryption keys to invest in cryptocurrencies."},
  {"num": 68, "subject": "另类投资", "question": "Compared to centralized cryptocurrency exchanges, decentralized exchanges are:", "options": {"A": "less likely to be regulated and less susceptible to attacks from hackers.", "B": "less likely to be regulated and more susceptible to attacks from hackers.", "C": "more likely to be regulated and less susceptible to attacks from hackers."}, "answer": "A", "explanation": "A Correct because decentralized exchanges lack a centralized control mechanism and operate on a distributed platform without central coordination or control. This comes with the benefit that should one of the computers on the network be attacked, the exchange remains operational since there are numerous other computers that continue to operate on the network. That is why attacking decentralized exchanges is substantially more difficult, rendering such attacks almost certain to fail. However, for a centralized exchange, trading is hosted on private servers, exposing the centralized exchanges and their clients to security vulnerabilities. Should the exchange's servers become compromised, the entire system may become paralyzed, halting trade, and leaking vital user information. Hence, decentralized exchanges are less susceptible to attacks from hackers. Moreover, decentralized exchanges are difficult to regulate because no single individual, organization, or group controls the system. This means that those trading on decentralized exchanges are generally free to transact without any regulatory scrutiny. However, some centralized exchanges are regulated, and depending on jurisdiction, these exchanges may be regulated as financial exchanges or other types of financial intermediaries. Hence, decentralized exchanges are less likely to be regulated.\nB Incorrect because decentralized exchanges lack a centralized control mechanism and operate on a distributed platform without central coordination or control. This comes with the benefit that should one of the computers on the network be attacked, the exchange remains operational since there are numerous other computers that continue to operate on the network. That is why attacking decentralized exchanges is substantially more difficult, rendering such attacks almost certain to fail. However, for a centralized exchange, trading is hosted on private servers, exposing the centralized exchanges and their clients to security vulnerabilities. Should the exchange's servers become compromised, the entire system may become paralyzed, halting trade, and leaking vital user information. Hence, decentralized exchanges are less (not more) susceptible to attacks from hackers.\nC Incorrect because decentralized exchanges are difficult to regulate because no single individual, organization, or group controls the system. This means that those trading on decentralized exchanges are generally free to transact without any regulatory scrutiny. However, some centralized exchanges are regulated, and depending on jurisdiction, these exchanges may be regulated as financial exchanges or other types of financial intermediaries. Hence, decentralized exchanges are less (not more) likely to be regulated."},
  {"num": 69, "subject": "另类投资", "question": "Cryptocurrency prices are driven by:", "options": {"A": "regulatory development only.", "B": "technological advancement only.", "C": "both regulatory development and technological advancement."}, "answer": "C", "explanation": "A Incorrect because among other drivers, prices (or returns) of cryptocurrencies are driven more by technological advancement and regulatory development.\nB Incorrect because among other drivers, prices (or returns) of cryptocurrencies are driven more by technological advancement and regulatory development.\nC Correct because among other drivers, prices (or returns) of cryptocurrencies are driven more by technological advancement and regulatory development."},
  {"num": 70, "subject": "另类投资", "question": "The process of representing ownership rights to physical assets on a distributed ledger best describes:", "options": {"A": "tokenization.", "B": "a blockchain.", "C": "an initial coin offering."}, "answer": "A", "explanation": "A Correct because tokenization is the process of representing ownership rights to physical assets on a blockchain or distributed ledger.\nB Incorrect because a blockchain is a type of digital ledger in which information, such as changes in ownership, is recorded sequentially within blocks that are then linked or 'chained' together and secured using cryptographic methods. However, the process of representing ownership on such a blockchain is called tokenization so this answer choice is not the best description.\nC Incorrect because an initial coin offering (ICO) is an unregulated process whereby companies sell their crypto tokens to investors in exchange for fiat money or for another agreed upon cryptocurrency. An ICO is typically structured to issue digital tokens to investors that can be used to purchase future products or services being developed by the issuer."},
  {"num": 1, "subject": "固定收益", "question": "Which of the following is most likely a negative covenant?", "options": {"A": "The issuer must comply with all laws and regulations.", "B": "The issuance of new debt must be junior to existing bondholder debt.", "C": "New debt obligations are treated the same as the borrower’s other senior debt instruments."}, "answer": "B", "explanation": "A Incorrect because affirmative covenants are typically administrative in nature. For example, frequently used affirmative covenants include what the issuer will do with the proceeds from the bond issue and the promise of making the contractual payments. The issuer may also promise to comply with all laws and regulations.\nB Correct because negative pledges prevent the issuance of debt that would be senior to or rank in priority ahead of the existing bondholders’ debt. This is a negative covenant.\nC Incorrect because affirmative covenants are typically administrative in nature. For example, a pari passu (or “equal footing”) clause, which ensures that a debt obligation is treated the same as the borrower’s other senior debt instruments."},
  {"num": 2, "subject": "固定收益", "question": "A 2-year treasury note is best classified as a(n):", "options": {"A": "asset-backed security.", "B": "capital market security.", "C": "money market security."}, "answer": "B", "explanation": "A Incorrect because asset-backed securities (ABS) are created from a process called securitization, which involves moving assets from the owner of the assets into a special legal entity. This special legal entity then uses the securitized assets as guarantees to back (secure) a bond issue, leading to the creation of ABS. Treasury notes are not asset-backed securities.\nB Correct because fixed-income securities with original maturities that are longer than one year are called capital market securities.\nC Incorrect because fixed-income securities with maturities at issuance (original maturity) of one year or less are known as money market securities. A two-year treasury note is not a money market security."},
  {"num": 3, "subject": "固定收益", "question": "Which of the following is most likely a zero-coupon bond? A bond with a par value of £1,000 that was issued in a positive yield market at:", "options": {"A": "£920.", "B": "£1,000.", "C": "£1,100."}, "answer": "A", "explanation": "A Correct because zero-coupon bonds do not pay interest, hence their name. Instead, they are issued at a discount to par value and redeemed at par. Out of all the answer choices, this is the only bond that is issued at a discount to its redemption value, therefore it is the most likely to be a zero-coupon bond.\nB Incorrect because zero-coupon bonds do not pay interest, hence their name. Instead, they are issued at a discount to par value and redeemed at par. This bond is issued at the same price as (and not at a discount to) the redemption value, therefore it is unlikely to be a zero-coupon bond.\nC Incorrect because zero-coupon bonds do not pay interest, hence their name. Instead, they are issued at a discount to par value and redeemed at par. This bond is issued at a premium (and not at a discount) to the redemption value, therefore it is unlikely to be a zero-coupon bond."},
  {"num": 4, "subject": "固定收益", "question": "Bonds issued in the Eurobond market are most likely:", "options": {"A": "denominated only in euros.", "B": "in the form of registered bonds.", "C": "issued within the jurisdiction of the issuer's home country."}, "answer": "B", "explanation": "A Incorrect because bonds issued and traded on the Eurobond market are called Eurobonds, and they are named after the currency in which they are denominated. For example, Eurodollar and Euroyen bonds are denominated in US dollars and Japanese yens, respectively. Bonds that are denominated in euros are called euro-denominated Eurobonds.\nB Correct because Eurobonds, domestic, and foreign bonds are now registered bonds for which ownership is recorded by either name or serial number.\nC Incorrect because Eurobonds are issued outside the jurisdiction of any single country, are usually unsecured, and may be denominated in any currency, including the issuer’s domestic currency.\nB Correct because the currency denomination of a bond’s cash flows influences which country’s interest rates affect a bond’s price. The price of a bond issued by a US-based company and denominated in British pounds will be affected by British interest rates.\nC Incorrect because the currency denomination of a bond’s cash flows influences which country’s interest rates affect a bond’s price. The price of a bond issued by a US-based company and denominated in British pounds will be affected by British interest rates."},
  {"num": 5, "subject": "固定收益", "question": "The price of a bond issued in the United Kingdom by a US-based company and denominated in British pounds most likely changes when:", "options": {"A": "US interest rates change only.", "B": "British interest rates change only.", "C": "both US and British interest rates change."}, "answer": "A", "explanation": "A Correct because the conversion ratio is the number of common shares that each bond can be converted into.\nB Incorrect because the conversion price is the price per share at which the convertible bond can be converted into shares.\nC Incorrect because the conversion value, sometimes called the parity value, is the current share price multiplied by the conversion ratio."},
  {"num": 6, "subject": "固定收益", "question": "The number of common shares a convertible bond can be converted into is the:", "options": {"A": "conversion ratio.", "B": "conversion price.", "C": "conversion value."}, "answer": "C", "explanation": "A Incorrect because the coupon of a step-up coupon bond, which may be fixed or floating, increases by specified margins at specified dates. It does not allow the issuer to pay interest in the form of additional amounts of the bond issue in lieu of a cash payment.\nB Incorrect because a deferred coupon bond, sometimes called a split coupon bond, pays no coupons for its first few years but then pays a higher coupon than it otherwise normally would for the remainder of its life. It does not allow the issuer to pay interest in the form of additional amounts of the bond issue in lieu of a cash payment.\nC Correct because a payment-in-kind (PIK) coupon bond typically allows the issuer to pay interest in the form of additional amounts of the bond issue rather than as a cash payment."},
  {"num": 7, "subject": "固定收益", "question": "A bond that allows the issuer to pay interest in the form of additional amounts of the existing bond issue rather than a cash payment best describes a:", "options": {"A": "step-up coupon bond.", "B": "deferred coupon bond.", "C": "payment-in-kind coupon bond."}, "answer": "B", "explanation": "A Incorrect because putable bonds are beneficial for the bondholder by guaranteeing a pre-specified selling price at the redemption dates. If interest rates rise after the issue date, thus depressing the bond's price, the bondholders can put the bond back to the issuer and get cash. This cash can be reinvested in bonds that offer higher yields, in line with the higher market interest rates. Thus reinvestment risk is lower for a putable bond than for a callable bond, all else being equal.\nB Correct because callable bonds present investors with a higher level of reinvestment risk than non-callable bonds; that is, if the bonds are called, bondholders have to reinvest funds in a lower interest rate environment.\nC Incorrect because a convertible bond can be viewed as the combination of a straight bond (option-free bond) plus an embedded equity call option. Convertible bonds can also include additional provisions, the most common being a call provision. As there is no call provision applicable in this instance, reinvestment risk will be lower than for an equivalent bond with a call provision: callable bonds present investors with a higher level of reinvestment risk than non-callable bonds; that is, if the bonds are called, bondholders have to reinvest funds in a lower interest rate environment."},
  {"num": 8, "subject": "固定收益", "question": "All else being equal, reinvestment risk is greatest for:", "options": {"A": "putable bonds.", "B": "callable bonds.", "C": "non-callable convertible bonds."}, "answer": "B", "explanation": "A Incorrect because the put provision is a valuable option for the bondholders, therefore putable bonds offer a lower yield (and thus have a higher price) than otherwise similar non-putable bonds.\nB Correct because the call provision is a valuable option for the issuer. Thus, other things equal, investors require a higher yield (and thus pay a lower price) for a callable bond than for an otherwise similar non-callable bond.\nC Incorrect because a convertible bond gives the bondholder the right to convert the bond into common shares of the issuing company. Because this option favors the bondholder, convertible bonds offer a lower yield and sell at a higher price than otherwise similar non-convertible bonds."},
  {"num": 9, "subject": "固定收益", "question": "Compared to an otherwise similar option-free bond, investors require a higher yield for a corporate bond with a:", "options": {"A": "put provision.", "B": "call provision.", "C": "conversion provision."}, "answer": "C", "explanation": "A Incorrect because a bond that is currently callable may be retired by the issuer, but the issuer is not required to do so.\nB Incorrect because a step-up note has a coupon rate that increases over time according to a predetermined schedule.\nC Correct . A sinking fund provision requires retirement of a portion of the bond’s principal every year, rather than retirement of the entire issue at maturity."},
  {"num": 10, "subject": "固定收益", "question": "If an issuer is required to retire a specified portion of the bond’s principal each year, the bond most likely:", "options": {"A": "is callable.", "B": "is a step-up note.", "C": "has a sinking fund provision."}, "answer": "C", "explanation": "A Incorrect because bonds rated Baa3 or higher by Moody's and BBB– or higher by Standard & Poor's and Fitch are considered investment grade.\nB Incorrect because bonds rated Baa3 or higher by Moody's and BBB– or higher by Standard & Poor's and Fitch are considered investment grade.\nC Correct because bonds rated Baa3 or higher by Moody's and BBB– or higher by Standard & Poor's and Fitch are considered investment grade."},
  {"num": 11, "subject": "固定收益", "question": "Using the rating scale from Moody's, the lowest rating for an investment-grade bond is:", "options": {"A": "Baa1.", "B": "Baa2.", "C": "Baa3."}, "answer": "A", "explanation": "A Correct because in addition to the high quality of underlying securities, repos include features designed to reduce the risk of a collateral shortfall over the contract life. One such feature is the provision of collateral in excess of the cash exchanged, known as initial margin. A 100% initial margin indicates a fully collateralized loan, while a higher margin indicates even greater initial collateral protection. This is alternatively considered a reduction or haircut of the underlying loan relative to the initial collateral value. The repo margin allows for some worsening in market value, and thus provides the cash lender a margin of safety if the collateral’s market value declines.\nB Incorrect because in addition to the high quality of underlying securities, repos include features designed to reduce the risk of a collateral shortfall over the contract life. One such feature is the provision of collateral in excess of the cash exchanged, known as initial margin. The repo margin allows for some worsening in market value, and thus provides the cash lender, not the cash borrower, a margin of safety if the collateral’s market value declines.\nC Incorrect because in addition to the high quality of underlying securities, repos include features designed to reduce the risk of a collateral shortfall over the contract life. One such feature is the provision of collateral in excess of the cash exchanged, known as initial margin. The repo margin allows for some worsening in market value, and thus provides only to the cash lender a margin of safety if the collateral’s market value declines."},
  {"num": 12, "subject": "固定收益", "question": "In a repurchase agreement, the initial margin protects:", "options": {"A": "the cash lender only.", "B": "the cash borrower only.", "C": "both the cash lender and the cash borrower."}, "answer": "B", "explanation": "A Incorrect because government agencies are quasi-government entities that issue debt in order to fund the government-sponsored provision of specific public goods or services based on sovereign or local law. This may involve the financing of specific activities promoted by the government or the operation of necessary infrastructure as mandated by law. The bonds issued by these agencies are known as quasi-government bonds or agency bonds\nB Correct because the main types of non-sovereign government issuers include agencies, public banks, supranationals, and regional governments. Regional Government Issuers. These include provincial, state, and local governments, referred to as municipal bonds in the US and most often as local authority bonds elsewhere, within a specific sovereign jurisdiction.\nC Incorrect because government agencies are quasi-government entities that issue debt in order to fund the government-sponsored provision of specific public goods or services based on sovereign or local law. This may involve the financing of specific activities promoted by the government or the operation of necessary infrastructure as mandated by law. The bonds issued by these agencies are known as quasi-government bonds or agency bonds."},
  {"num": 13, "subject": "固定收益", "question": "US municipal bonds are best described as:", "options": {"A": "agency bonds.", "B": "non-sovereign bonds.", "C": "quasi-government bonds."}, "answer": "C", "explanation": "A Incorrect because it is the flat price that is affected by a market discount rate change.\nB Incorrect because it is the flat price that is affected by a market discount rate change, and if the flat price is affected by the market discount rate so is the full price (as full price equals flat price plus accrued interest).\nC Correct because the accrued interest part of the full price does not depend on the yield-to-maturity."},
  {"num": 14, "subject": "固定收益", "question": "Which of the following does not depend on the market discount rate? A bond's:", "options": {"A": "flat price", "B": "full price", "C": "accrued interest"}, "answer": "C", "explanation": "A Incorrect because the opposite is true due to the convexity effect. For the same coupon rate and time-to-maturity, the percentage price change is greater (in absolute value, meaning without regard to the sign of the change) when the market discount rate goes down than when it goes up (the convexity effect).\nB Incorrect because it ignores the convexity effect of most option-free bonds. For the same coupon rate and time-to-maturity, the percentage price change is greater (in absolute value, meaning without regard to the sign of the change) when the market discount rate goes down than when it goes up (the convexity effect).\nC Correct because for the same coupon rate and time-to-maturity, the percentage price change is greater (in absolute value, meaning without regard to the sign of the change) when the market discount rate goes down than when it goes up (the convexity effect)."},
  {"num": 15, "subject": "固定收益", "question": "All else being equal, the absolute value of the percentage price change for an option-free bond is most likely:", "options": {"A": "less when the market discount rate decreases than when it increases by the same amount.", "B": "the same whether the market discount rate decreases or increases by the same amount.", "C": "greater when the market discount rate decreases than when it increases by the same amount."}, "answer": "A", "explanation": "A Correct because the value of a bond is calculated as: PV = [PMT ÷ (1+r)1] + [PMT ÷(1+r)2] +...+ [(PMT + FV) ÷(1+r)N) where: PV = present value, or the price of the bond PMT = coupon payment per period FV = future value paid at maturity, or the par value of the bond r = market discount rate, or required rate of return per period N = number of evenly spaced periods to maturity Using calculator inputs, N = (3 × 2) = 6, PMT = (5% ÷ 2) × 100 = $2.5, FV = $100, PV = $108, Solve for I, is equal to 1.114% semi-annually, or 2.228% on an annual basis. If the yield to maturity decreases by 100 bps, the price of the bond after one year is computed as: N = 4, PMT = $2.5, FV = $100, I = [(2.228% − 1%) ÷ 2] = 0.614%, Solve PV, is equal to $107.43. Therefore, the change in value of the bond = $108.00 − $107.43 = $0.57.\nB Incorrect because fails to annualize the interest rate before computing the change in value. Using calculator inputs, the yield of the bond: N = 6, PMT = $2.5, FV = $100, Solve I is equal to 1.114%. If the yield declines by 100 bps, the price of the bond after one year is computed as: N = 4, PMT = $2.5, FV = 100, I = (1.114% − 1%) = 0.114%, Solve for PV =$109.52. Therefore, the change in value = $108 − 109.52 = -$1.52, or a change in value of $1.52.\nC Incorrect because incorrectly uses the same time to maturity when calculating the new value rather than adjusting the term for the passage of one year in value."},
  {"num": 16, "subject": "固定收益", "question": "A three-year, semiannual-pay bond with a $100 par value and a 5% coupon rate is purchased for $108. One year later, if the yield to maturity has decreased by 100 basis points, the change in the value of this bond is closest to:", "options": {"A": "$0.57.", "B": "$1.52.", "C": "$3.08."}, "answer": "B", "explanation": "A Incorrect because both the coupon payment and discount rate used are annual: PV = + + = 122.2007 ≈ 122.20\nB Correct because PV = + + + + + = 122.4057 ≈ 122.41\nC Incorrect because the coupon payment and discount rate are annual, similar to the other distractor. The difference between this and other distractor is that payment is made at the beginning of the period, not at the end. =122.53"},
  {"num": 17, "subject": "固定收益", "question": "A bond has the following characteristics:\nFor a yield to maturity of 4%, the price of the bond per 100 of par value is closest to:", "options": {"A": "122.20.", "B": "122.41.", "C": "122.53."}, "answer": "B", "explanation": "A Incorrect because as per the justification for the correct answer, the price of the bond is closest to $97,277. This incorrect answer is arrived at by ignoring the coupon payments for year 1 & 2: Price of bond ≠ 104,000/(1+5%)3 = 89,839.11025 ≈ 89,839.\nB Correct because the price of the bond is the present value of the promised cash flows and is calculated as follows: Price of bond = 4,000/(1 +5%)1 + 4,000/(1+5%)2 + 104,000/(1+5%)3 = 3,809.5238 + 3,628.1179 + 89,839.1102 = 97,276.7520 ≈ 97,277. Calculator inputs: FV = 100,000, I = 0.05, N = 3, PMT = 4,000, PV = 97,276.75 ≈ 97.277.\nC Incorrect because as per the justification for the correct answer, the price of the bond is closest to $97,277. This incorrect answer is arrived at by switching the coupon rate and the market discount rate."},
  {"num": 18, "subject": "固定收益", "question": "An analyst gathers the following information about a bond that pays interest annually:\nIf the market discount rate is 5%, the market value of this bond is closest to:", "options": {"A": "$89,839.", "B": "$97,277.", "C": "$102,775."}, "answer": "A", "explanation": "A Correct because some fixed-rate bonds are not actively traded. Therefore, there is no market price available to calculate the rate of return required by investors. In these situations, it is common to estimate the market discount rate and price based on the quoted or flat prices of more frequently traded comparable bonds. These comparable bonds have similar times-to-maturity, coupon rates, and credit quality. This estimation process is called matrix pricing. The estimated market discount rate can be obtained with linear interpolation. Using linear interpolation between the two given bonds, we have: 0.034 + (5 – 3) / (8 – 3) × (0.054 – 0.034) = 0.034 + 2 / 5 × 0.02 = 0.042 = 4.2%.\nB Incorrect because the simple average is used instead of linear interpolation in matrix pricing. Some fixed-rate bonds are not actively traded. Therefore, there is no market price available to calculate the rate of return required by investors. In these situations, it is common to estimate the market discount rate and price based on the quoted or flat prices of more frequently traded comparable bonds. These comparable bonds have similar times-to-maturity, coupon rates, and credit quality. This estimation process is called matrix pricing. The estimated market discount rate can be obtained with linear interpolation. Using the simple average of the two given bonds, we have: (0.034 + 0.054) / 2 = 0.088 / 2 = 0.044 = 4.4%.\nC Incorrect because the linear interpolation for matrix pricing is implemented from the wrong end of the interval. Some fixed-rate bonds are not actively traded. Therefore, there is no market price available to calculate the rate of return required by investors. In these situations, it is common to estimate the market discount rate and price based on the quoted or flat prices of more frequently traded comparable bonds. These comparable bonds have similar times-to-maturity, coupon rates, and credit quality. This estimation process is called matrix pricing. The estimated market discount rate can be obtained with linear interpolation. Using linear interpolation from the wrong end between the two given bonds, we have: 0.034 + (8 – 5) / (8 – 3) × (0.054 – 0.034) = 0.034 + 3 / 5 × 0.02 = 0.046 = 4.6%."},
  {"num": 19, "subject": "固定收益", "question": "An analyst gathers the following information:\nBased only on this information, the estimated market discount rate for a 5-year bond with similar credit quality is:", "options": {"A": "4.2%.", "B": "4.4%.", "C": "4.6%."}, "answer": "B", "explanation": "A Incorrect because some fixed-rate bonds are not actively traded it is common to estimate the market discount rate and price based on the quoted or flat prices of more frequently traded comparable bonds. These comparable bonds have similar times-to-maturity, coupon rates, and credit quality. This estimation process is called matrix pricing. Highly liquid bonds are priced based on actual market pricing rather than matrix pricing.\nB Correct because for bonds that are not yet issued it is common to estimate the market discount rate and price based on the quoted or flat prices of more frequently traded comparable bonds. These comparable bonds have similar times-to-maturity, coupon rates, and credit quality. This estimation process is called matrix pricing.\nC Incorrect because for comparable bonds that have similar times-to-maturity, coupon rates, and credit quality the estimation process is called matrix pricing. Bonds with uncertain credit quality are not good candidates for matrix pricing."},
  {"num": 20, "subject": "固定收益", "question": "Matrix pricing is most likely used to estimate the price of a bond that:", "options": {"A": "is highly liquid.", "B": "is not yet issued.", "C": "has unknown credit quality."}, "answer": "C", "explanation": "A Incorrect because for the same coupon rate and time-to-maturity, the percentage price change is greater (in absolute value, meaning without regard to the sign of the change) when the market discount rate goes down than when it goes up (the convexity effect).\nB Incorrect because for the same coupon rate and time-to-maturity, the percentage price change is greater (in absolute value, meaning without regard to the sign of the change) when the market discount rate goes down than when it goes up (the convexity effect).\nC Correct because for the same coupon rate and time-to-maturity, the percentage price change is greater (in absolute value, meaning without regard to the sign of the change) when the market discount rate goes down than when it goes up (the convexity effect)."},
  {"num": 21, "subject": "固定收益", "question": "The price of an option-free bond increases by 7% when the yield to maturity decreases by 100 basis points. If the price of this bond decreases by 7%, the yield to maturity most likely increases by:", "options": {"A": "less than 100 basis points.", "B": "100 basis points.", "C": "more than 100 basis points."}, "answer": "C", "explanation": "A Incorrect because for the same time-to-maturity, a lower-coupon bond has a greater percentage price change than a higher-coupon bond when their market discount rates change by the same amount (the coupon effect). Bond 1 has the same time-to-maturity as Bond 3 but a higher coupon, thus Bond 1 would experience a smaller percentage price change compared to Bond 3.\nB Incorrect because generally, for the same coupon rate, a longer-term bond has a greater percentage price change than a shorter-term bond when their market discount rates change by the same amount (the maturity effect). Bond 2 has the same coupon rate as Bond 3 but a shorter maturity, thus Bond 2 would experience a smaller percentage price change compared to Bond 3.\nC Correct because for the same time-to-maturity, a lower-coupon bond has a greater percentage price change than a higher-coupon bond when their market discount rates change by the same amount (the coupon effect). Bond 3 has the same time-to-maturity as Bond 1 but a lower coupon, thus Bond 3 would experience a greater percentage price change compared to Bond 1. Also, generally, for the same coupon rate, a longer-term bond has a greater percentage price change than a shorter-term bond when their market discount rates change by the same amount (the maturity effect). Bond 3 has the same coupon rate as Bond 2 but a longer maturity, thus Bond 3 would experience a greater percentage price change compared to Bond 2."},
  {"num": 22, "subject": "固定收益", "question": "An analyst gathers the following information about three option-free bonds:\nAll else being equal, if the market discount rate decreases by 50 basis points, the bond most likely to experience the greatest percentage price change is:", "options": {"A": "Bond 1.", "B": "Bond 2.", "C": "Bond 3."}, "answer": "B", "explanation": "A Incorrect because the full price is referred to as the \"dirty\" price. The flat price, which is the full price minus the accrued interest, is also called the quoted or 'clean' price.\nB Correct because it is the flat price that is 'pulled to par' along the constant-yield price trajectory.\nC Incorrect because the statement refers to the full price. If a trade takes place, the accrued interest is added to the flat price to obtain the full price paid by the buyer and received by the seller on the settlement date."},
  {"num": 23, "subject": "固定收益", "question": "The flat price of a bond:", "options": {"A": "is also referred to as the \"dirty\" price.", "B": "is \"pulled to par\" along the constant-yield price trajectory.", "C": "includes interest which is received by the seller on the settlement date."}, "answer": "A", "explanation": "A Correct because compounding more frequently within the year results in a lower (more negative) yield-to-maturity.\nB Incorrect because compounding more frequently within the year results in a lower (more negative) yield-to-maturity. Converting the annualized yield-to-maturity to quarterly and monthly compounding results in the same rates of return.\nC Incorrect because compounding more frequently within the year results in a lower (more negative) yield-to-maturity."},
  {"num": 24, "subject": "固定收益", "question": "For a coupon bond with a negative yield, compounding more frequently within the year results in a yield-to-maturity that is:", "options": {"A": "more negative.", "B": "the same.", "C": "less negative."}, "answer": "B", "explanation": "A Incorrect because the yield spread of a specific bond over the standard swap rate in that currency of the same tenor is known as the I- spread.\nB Correct because the yield spread in basis points over an actual or interpolated government bond is known as the G-spread. The spread over a government bond is the return for bearing greater credit, liquidity, and other risks relative to the sovereign bond.\nC Incorrect because the yield spread over a specific benchmark is referred to as the benchmark spread. A constant yield spread over a government (or interest rate swap) spot curve is known as the zero-volatility spread (Z-spread) of a bond over the benchmark rate."},
  {"num": 25, "subject": "固定收益", "question": "The yield spread over an interpolated sovereign bond is best described as a(n):", "options": {"A": "I-spread.", "B": "G-spread.", "C": "Z-spread."}, "answer": "C", "explanation": "A Incorrect because the yield-to-maturity, rytm is: 105 = 4/(1 + rytm)1 + 4/(1 + rytm)2 + 4/(1 + rytm)3 + 104/(1 + rytm)4 Using a financial calculator with N = 4, PV = –105, FV = 100, PMT = 4 and solving for I, rytm = 2.6656% ≈ 2.7%. Although less than the yield to first call of 2.9%, the YTM is greater (better) than the yield to second call of 2.6%, making the latter the yield to worst.\nB Incorrect because the yield-to-first-call, r1 is: 105 = 4/(1 + r1)1 + (4+103)/(1 + r1)2 Using a financial calculator with N = 2, PV = –105, FV = 103, PMT = 4 and solving for I, r1 = 2.8706% ≈ 2.9%. This yield is greater (better) than both the yield to second call of 2.6% (which is the lowest, or worst) and the YTM of 2.7%.\nC Correct because the lowest of the sequence of yields-to-call and the yield-to-maturity is known as the yield-to-worst. The sequence of yields for the bond is as follows:"},
  {"num": 26, "subject": "固定收益", "question": "An analyst gathers the following information about a callable bond that pays interest annually:\nThis bond's yield to worst is the:", "options": {"A": "yield to maturity.", "B": "yield to first call.", "C": "yield to second call."}, "answer": "B", "explanation": "A Incorrect because the formula converts from an effective annual yield to a semiannual-pay yield: ≠ ((1 + yield)0.5 – 1) × 2 = ((1 + 0.0366)0.5 – 1) × 2= (1.018136 – 1) × 2 = .036272 ≈ 3.63%.\nB Correct because an effective annual rate has a periodicity of one because there is just one compounding period in the year. No calculations are required based on the intuitive idea that due to semi-annual compounding, the effective annual yield must be slightly higher. The formula to calculate the effective annual yield of a semi-annual pay bond is: = (1 + yield/2)2 – 1 = (1 + 0.0366/2)2 – 1 = 1.036935 – 1 = .036935 ≈ 3.69%.\nC Incorrect because the the yield is not divided by 2. The formula used to calculate the effective annual yield of a semi-annual pay bond:"},
  {"num": 27, "subject": "固定收益", "question": "The stated annual yield to maturity on a semiannual bond basis is 3.66%. The effective annual yield is closest to:", "options": {"A": "3.63%.", "B": "3.69%.", "C": "7.45%."}, "answer": "C", "explanation": "A Incorrect because the APR converted to a quarterly periodicity should be expressed in annual terms just like the semiannual APR: for bonds maturing in more than one year, investors want an annualized and compounded yield-to-maturity. The formula for converting m periods to n periods per year is (1 + APRm/m)m = (1 + APRn/n)n. Thus, (1 + 0.08/2)2 = (1 + APR4/4)4 ⇔ APR4/4 = 1.98% ≠ APR4.\nB Incorrect because the APR converted to a quarterly periodicity cannot be calculated by simply scaling the APR with a periodicity that is twice longer: APR4 ≠ (1+APR2)1/2 – 1 = 1.081/2 – 1 = 3.92%. The correct formula for converting m periods to n periods per year is (1 + APRm/m)m = (1 + APRn/n)n.\nC Correct because (1 + APR2/2)2 = (1 + APR4/4)4 for annual percentage rates using semiannual and quarterly periodicity (APR2 and APR4, respectively). This gives (1 + 0.08/2)2 = (1 + APR4/4)4 ⇔ APR4/4 = 1.98% and APR4 = 4 × 1.98% = 7.92%."},
  {"num": 28, "subject": "固定收益", "question": "A five-year semiannual bond has an annual percentage rate (APR) of 8%. Converted to a quarterly periodicity, the APR is closest to:", "options": {"A": "1.98%.", "B": "3.92%.", "C": "7.92%."}, "answer": "A", "explanation": "A Correct because the yield spread of a specific bond over the standard swap rate in that currency of the same tenor is known as the I-spread or interpolated spread to the swap curve.\nB Incorrect because another approach is to calculate a constant yield spread over a government (or interest rate swap) spot curve instead. This spread is known as the zero volatility spread (Z-spread) of a bond over the benchmark rate. Sometimes, the Z-spread is called the static spread because it is constant (and has zero volatility).\nC Incorrect because the Z-spread is also used to calculate the option-adjusted spread (OAS) on a callable bond. The OAS, like the option-adjusted yield, is based on an option- pricing model and an assumption about future interest rate volatility."},
  {"num": 29, "subject": "固定收益", "question": "The yield spread of a specific bond over the standard swap rate in that currency of the same tenor best describes the:", "options": {"A": "I-spread.", "B": "Z-spread.", "C": "option-adjusted spread."}, "answer": "B", "explanation": "A Incorrect because it is the coupon of the bond.\nB Correct because current yield is calculated as ($4.5/$85.70) = 5.25%.\nC Incorrect because it is calculated as follows:"},
  {"num": 30, "subject": "固定收益", "question": "The current yield for a 4.5% coupon, 10-year bond, with a maturity par value of $100 and currently priced at $85.70 is closest to:", "options": {"A": "4.50%.", "B": "5.25%.", "C": "5.93%."}, "answer": "C", "explanation": "A Incorrect because bond yields-to-maturity are annualized and compounded. Yield measures in the money market are annualized but not compounded.\nB Incorrect because money market instruments having different times-to-maturity have different periodicities for the annual rate.\nC Correct because the rate of return on a money market instrument is stated on a simple interest basis."},
  {"num": 31, "subject": "固定收益", "question": "Money market yields are:", "options": {"A": "annualized and compounded.", "B": "stated for a common periodicity.", "C": "stated on a simple interest basis."}, "answer": "B", "explanation": "A Incorrect because a specified yield spread is added to, or subtracted from, the reference rate which results in the coupon. For example, the floater might reset its interest rate quarterly at the reference rate plus 0.50%. This is not the quoted margin, it is the reference rate plus the quoted margin.\nB Correct because this specified yield spread over the reference rate is called the quoted margin on the FRN. The role of the quoted margin is to compensate the investor for the difference in the credit risk of the issuer and that implied by the reference rate.\nC Incorrect because the required margin is the yield spread over, or under, the reference rate such that the FRN is priced at par value on a rate reset date. Changes in the required margin usually come from changes in the issuer's credit risk. The required margin is not specified but changes based on market forces."},
  {"num": 32, "subject": "固定收益", "question": "For a floating-rate note, the specified yield spread over the reference rate best defines the:", "options": {"A": "coupon.", "B": "quoted margin.", "C": "required margin."}, "answer": "B", "explanation": "A Incorrect because candidates confuse the redemption value with the present value and thereby add the interest earned to the redemption value as part of the calculation. DR ≠ (365/160) × (140,500/(5,000,000 + 140,500)) = 0.0624 ≈ 6.2%.\nB Correct because the discount rate, DR = (Year/Days) × ((FV – PV)/FV), where Year = number of days in the year, Days = number of days between settlement and maturity, FV = future value paid at maturity/face value of the money market instrument, PV = present value/price of the money market instrument, and FV – PV, is the interest earned. DR = (365/160) × (140,500/5,000,000) = 0.0641 ≈ 6.4%.\nC Incorrect because this is the add-on rate. AOR = Year/Days × ((FV – PV)/PV)"},
  {"num": 33, "subject": "固定收益", "question": "A commercial paper has the following characteristics:\nFor a 365-day year, the discount rate is closest to:", "options": {"A": "6.2%.", "B": "6.4%.", "C": "6.6%."}, "answer": "A", "explanation": "A Correct because the applicable interest rate in December is the six-month market reference rate in June plus the 45 basis point margin = 1.95% + 0.45% = 2.40%.\nB Incorrect because the 45 bps margin is added to the average of the June and December six-month market reference rates = (2.25% + 1.95%) / 2 + 0.45% = 2.55%.\nC Incorrect because the 45 bps margin is added to the market reference rate in December = 2.25% + 0.45% = 2.70%."},
  {"num": 34, "subject": "固定收益", "question": "A floating-rate note makes semiannual interest payments and has a coupon rate equal to the six-month market reference rate plus 45 basis points. The interest payments are made in June and December. If the six-month market reference rate was 1.95% in June and 2.25% in December of the same year, the coupon rate paid in December of that year was closest to:", "options": {"A": "2.40%.", "B": "2.55%.", "C": "2.70%."}, "answer": "A", "explanation": "A Correct because the formula to calculate a bond price given a sequence of spot rates is the following: PV =(PMT / (1+Z1)1) + (PMT / (1+Z2)2) + … + (PMT + FV) / (1+ZN)N), where Z1 = spot rate, or zero-coupon yield, or zero rate, for Period 1 Z2 = spot rate, or zero-coupon yield, or zero rate, for Period 2 ZN = spot rate, or zero-coupon yield, or zero rate, for Period N. For Sequence 1, applying this formula, the bond price is: (2/1.02) + (2/1.0712) + (102/1.1477) = 1.9608 + 1.8670 + 88.871 ≈ 92.70. For Sequence 2, the bond price is: (2/1.047) + (2/1.712) + (102/1.0612) = 1.9608 + 1.8674 + 96.1169 ≈ 99.89. The bond price using Sequence 1 is less than the price using Sequence 2.\nB Incorrect because for Sequence 1, applying this formula, the bond price is: (2/1.02) + (2/1.0712) + (102/1.1477) = 1.9608 + 1.8670 + 88.871 ≈ 92.70. For Sequence 2, the bond price is: (2/1.047) + (2/1.712) + (102/1.0612) = 1.9608 + 1.8674 + 96.1169 ≈ 99.89. The bond price using Sequence 1 is less than the price using Sequence 2.\nC Incorrect because for Sequence 1, applying this formula, the bond price is: (2/1.02) + (2/1.0712) + (102/1.1477) = 1.9608 + 1.8670 + 88.871 ≈ 92.70."},
  {"num": 35, "subject": "固定收益", "question": "An analyst gathers the following information about spot rates:\nFor a 3-year, 2% annual coupon payment bond, the price using Sequence 1 is:", "options": {"A": "less than the price using Sequence 2.", "B": "the same as the price using Sequence 2.", "C": "greater than the price using Sequence 2."}, "answer": "B", "explanation": "A Incorrect because the spot curve can be calculated as the geometric average of the forward rates.\nB Correct because implied forward rates (also known as forward yields) are calculated from spot rates. An implied forward rate is a break-even reinvestment rate. When the market is in equilibrium (no arbitrage) the implied forward rate is the same as the forward rate.\nC Incorrect because spot rates are yields-to-maturity on zero-coupon bonds maturing at the date of each cash flow."},
  {"num": 36, "subject": "固定收益", "question": "Implied forward rates are best defined as the:", "options": {"A": "geometric average of spot rates.", "B": "breakeven reinvestment rates between zero-coupon bonds.", "C": "current yield to maturity on zero-coupon bonds of different maturities."}, "answer": "B", "explanation": "A Incorrect because the price of the bond is calculated using as discount rates the average of the spot rates; (6% + 5% +4%)/3 = 15%/3= 5%. Hence, PV ≠ 4/(1.05)1 + 4/(1.05)2 + 104/(1.05)3 = 4/1.05 + 4/1.1025 + 104/1.157625 = 3.8095+ 3.6281 + 89.8391= 97.276 ≈ 97.28.\nB Correct because given the spot rates, the price of a bond can be calculated using the following formula: PV = [PMT/(1 + Z1)1 + PMT/(1 + Z2)2 + …+ (PMT + FV)/(1 + ZN)N] Hence, PV = 4/(1 + 0.06)1 + 4/(1 + 0.05)2 + (4 + 100)/(1 + 0.04)3 = 4/1.06 + 4/1.1025 + 104/1.1249 = 3.77358+ 3.62812 + 92.4556 = 99.8573 ≈ 99.86.\nC Incorrect because the price of the bond is calculated using the 3-year spot rate as discount rate for all cash flows. Hence, PV ≠ 4/(1 + 0.04)1 + 4/(1 + 0.04)2 + (4 + 100)/(1 + 0.04)3 = 4/1.04 + 4/1.0816 + 104/1.1249 = 3.8461+ 3.6982+ 92.4527 = 99.9969 ≈ 100.00."},
  {"num": 37, "subject": "固定收益", "question": "An analyst gathers the following information about a spot curve:\nIf the coupon rate of a 3-year annual-pay bond is 4%, the price of the bond is closest to:", "options": {"A": "97.28.", "B": "99.86.", "C": "100.00."}, "answer": "B", "explanation": "A Incorrect because the bond price (or value) determined using the spot rates is sometimes referred to as the bond’s 'no-arbitrage value'. If the current market price equals the no-arbitrage value, discounting the cash flows by either spot rates or yield to maturity arrives to the same price. The level of the current market price vis a vis par has no bearing the no-arbitrage value.\nB Correct because bond price (or value) determined using the spot rates is sometimes referred to as the bond’s 'no-arbitrage value'. If the current market price equals the 'no-arbitrage value, discounting the cash flows by either spot rates or yield to maturity arrives to the same price.\nC Incorrect because bond price (or value) determined using the spot rates is sometimes referred to as the bond’s 'no-arbitrage value'."},
  {"num": 38, "subject": "固定收益", "question": "A bond trading at its no-arbitrage value is priced at a premium. The sum of the present value of the bond's cash flows discounted at spot rates is:", "options": {"A": "less than the sum of the present values of the bond's cash flows discounted at its yield to maturity.", "B": "equal to the sum of the present values of the bond's cash flows discounted at its yield to maturity.", "C": "greater than the sum of the present values of the bond's cash flows discounted at its yield to maturity."}, "answer": "A", "explanation": "A Correct because the general formula for the relationship between two spot rates and the implied forward rate is: (1 + zA)A × (1 + IFRA,B-A)B-A = (1 + zB)B, where zx is the x-year spot rate and IFRx,y is the y-year forward rate, x years from now. Using the formula, the 6 year spot rate can be calculated in two different ways: 1. Using A = 2, B = 6: (1 + z6)6 = (1 + z2)2 × (1 + IFR2,4)4 2. Using A = 4, B = 6: (1 + z6)6 = (1 + z4)4 × (1 + IFR4,2)2 Equating the two we get: (1 + z2)2 × (1 + IFR2,4)4 = (1 + z4)4 × (1 + IFR4,2)2 . Using the numbers from the stem: (1 + 0.01)2 × (1 + 0.03)4 = (1 + 0.025)4 × (1 + IFR4,2)2 1.0201 × 1.1255 = 1.1038 × (1 + IFR4,2)2 ⇒ IFR4,2 = (1.1481/1.1038)0.5 – 1 = 0.0199 ≈ 2%.\nB Incorrect because instead of using the formula for the relationship between spot rates and the implied forward rates, the candidate assumed that the 2 year forward rate, 4 years from today is equal to the 4 year forward rate, 2 years from today.\nC Incorrect because when calculating IFR4,2, in the last step, the candidate forgets to take the square root. IFR4,2 ≠ 1.1481/1.1038 – 1 = 0.0401 ≈ 4%."},
  {"num": 39, "subject": "固定收益", "question": "An analyst gathers the following spot and forward rates:\nThe 2-year forward rate, four years from today is closest to:", "options": {"A": "2%.", "B": "3%.", "C": "4%."}, "answer": "C", "explanation": "A Incorrect because a par curve is a sequence of yields-to-maturity such that each bond is priced at par value. Par rates are not break-even reinvestment rates.\nB Incorrect because the spot rate is a sequence of yields-to-maturity on zero-coupon bonds. A forward rate links one spot rate to another and for this reason can be characterized as a break-even reinvestment rate. A spot rate alone is, however, not a break-even reinvestment rate.\nC Correct because an implied forward rate is a break-even reinvestment rate. It links the return on an investment in a shorter-term zero-coupon bond to the return on an investment in a longer-term zero-coupon bond."},
  {"num": 40, "subject": "固定收益", "question": "A break-even reinvestment rate is most likely equivalent to a(n):", "options": {"A": "par rate.", "B": "spot rate.", "C": "implied forward rate."}, "answer": "C", "explanation": "A Incorrect because each denominator is raised to the power of the corresponding year. PV ≠ PMT / (1 + 0y1y) + PMT / (1 + 0y1y × 1y1y)2 + (PMT + FV) / (1 + 0y1y × 1y1y × 2y1y)3 PV ≠ 1 / (1 + 1%) + 1 / ((1 + 1%)(1 + 2%))2 + (1 + 100) / ((1 + 1%)(1 + 2%)(1 + 4%))3 = 0.9901 + 0.9422 +82.1215 = 84.0538, rounded to 84.05.\nB Incorrect because the forward rates are used directly as spot rates. Hence, PV ≠ PMT / (1 + Z1)1 + PMT / (1 + Z2)2 + … + (PMT + FV) / (1 + ZN)N PV ≠ 1 / (1 + 1%)1 + 1 / (1 + 2%)2 + (1 + 100) / (1 + 4%)3 = 0.9901 + 0.9612 +89.7886 = 91.7399, rounded to 91.74.\nC Correct because the geometric average of the forward rates gives us the spot rates (ie. (0y1y × 1y1y) = (1 + Z2)2, (0y1y × 1y1y × 2y1y) = (1 + Z3)3)), hence the price of a bond using forward rates can be calculated using: PV = PMT / (1 + Z1)1 + PMT / (1 + Z2)2 + … + (PMT + FV) / (1 + ZN)N where Z1 = spot rate, or the zero-coupon yield, or zero rate, for Period 1, Z2 = spot rate, or the zero-coupon yield, or zero rate, for Period 2, ZN = spot rate, or the zero-coupon yield, or zero rate, for Period N."},
  {"num": 41, "subject": "固定收益", "question": "An analyst gathers the following information about forward rates:\nUsing only this information, the price per 100 of par value of a 3-year, 1% annual coupon bond is closest to:", "options": {"A": "84.05.", "B": "91.74.", "C": "96.23."}, "answer": "C", "explanation": "A Incorrect because the denominator of each term is incorrectly raised to a power: Price per 100 of par value ≠ 0.2 / (1+0.1%)1 + 0.2 / ((1+0.1%) × (1+0.3%))2 + (100+0.2) / ((1+0.1%) × (1+0.3%)× (1+0.6%))3 = 97.64.\nB Incorrect because the bond is priced on the basis of spot rates rather than forward rates: Price per 100 of par value ≠ 0.2 / (1+0.1%)1 + 0.2 / (1+0.3%)2 + (100+0.2) / (1+0.6%)3 = 98.82.\nC Correct because the Price per 100 of par value = 0.2 / (1+0.1%) + 0.2 / ((1+0.1%) × (1+0.3%)) + (100+0.2) / ((1+0.1%) × (1+0.3%)× (1+0.6%)) = 99.60."},
  {"num": 42, "subject": "固定收益", "question": "An analyst observes the following series of 1-year forward rates:\nBased on only this information, the price per 100 of par value of a 3-year 0.2% annual coupon bond is closest to:", "options": {"A": "97.64.", "B": "98.82.", "C": "99.60."}, "answer": "C", "explanation": "A Incorrect because the sale and purchase price are accidentally swapped in the formula: 102.06 = (95.27 + 24.28) / (1 + r)^7 => r = 0.022853 ≈ 2.29%. Calculator solution: N = 7; PV = –102.06; FV = 95.27 + 24.28; CPT I/Y = 2.29%.\nB Incorrect because holding period and tenor of bond are accidentally swapped in the formula: 95.27 = (102.06 + 24.28) / (1 + r)^10 => r = 0.028628 ≈ 2.86%. Calculator solution: N = 10; PV = –95.27; FV = 102.06 + 24.28; CPT I/Y = 2.86%.\nC Correct because a horizon yield is the internal rate of return between the total return (the sum of reinvested coupon payments and the sale price or redemption amount) and the purchase price of the bond. The horizon yield on a bond investment is the annualized holding-period rate of return."},
  {"num": 43, "subject": "固定收益", "question": "An investor gathers the following information about an investment in a bond with a 10-year tenor:\nIf the holding period was seven years, the horizon yield is closest to:", "options": {"A": "2.29%.", "B": "2.86%.", "C": "4.11%."}, "answer": "C", "explanation": "A Incorrect because changes in interest rates change the future value of reinvested coupon payments. Therefore, the investor faces coupon reinvestment risk, too.\nB Incorrect because the investor will be selling the bond before maturity and faces the risk that it will be sold at a higher or lower price (market price risk).\nC Correct because the investor faces coupon reinvestment risk for all coupons received (first coupon plus any others until sale) and also faces market price risk as changes in the interest rate will impact the sale price of the bond."},
  {"num": 44, "subject": "固定收益", "question": "With respect to interest rate risk, an investor who sells a fixed-rate bond after the first coupon is received and before its maturity is exposed to:", "options": {"A": "market price risk, only.", "B": "coupon reinvestment risk, only.", "C": "both market price risk and coupon reinvestment risk."}, "answer": "B", "explanation": "A Incorrect because 4.75% is used as the coupon rate and 5.50% as the reinvestment rate, resulting in (4.75 × 1.0550^2) + (4.75 × 1.0550) + 4.75 = 15.0481 ≈ 15.05. Interest rates are the rates at which coupon payments are reinvested and the market discount rates at the time of purchase and at the time of sale if the bond is not held to maturity.\nB Correct because the first coupon is reinvested at 4.75% for two years, the second coupon is reinvested at 4.75% for one year, and the third coupon has not yet been reinvested. (5.50 × 1.0475^2) + (5.50 × 1.0475) + 5.50 = 17.2962 ≈ 17.30. Interest rates are the rates at which coupon payments are reinvested and the market discount rates at the time of purchase and at the time of sale if the bond is not held to maturity.\nC Incorrect because the coupons are deemed to have been reinvested over 3 years, 2 years, and 1 year, respectively, resulting in (5.50 × 1.0475^3) + (5.50 × 1.0475 ^2) + (5.50 × 1.0475) = 18.1177 ≈ 18.12."},
  {"num": 45, "subject": "固定收益", "question": "An analyst gathers the following information about a bond:\nIf the market discount rate is 4.75% for the holding period, the future value of reinvested coupons at the end of the holding period is closest to:", "options": {"A": "15.05.", "B": "17.30.", "C": "18.12."}, "answer": "A", "explanation": "A Correct because there are two offsetting types of interest rate risk that affect the bond investor: coupon reinvestment risk and market price risk. The future value of reinvested coupon payments (and in a portfolio, the principal on bonds that mature before the horizon date) increases when interest rates go up and decreases when rates go down. The sale price on a bond that matures after the horizon date (and thus needs to be sold) decreases when interest rates go up and increases when rates go down.\nB Incorrect because the future value of reinvested coupon payments (and in a portfolio, the principal on bonds that mature before the horizon date) increases when interest rates go up. The sale price on a bond that matures after the horizon date (and thus needs to be sold) decreases when interest rates go up.\nC Incorrect because the future value of reinvested coupon payments (and in a portfolio, the principal on bonds that mature before the horizon date) increases when interest rates go up. The sale price on a bond that matures after the horizon date (and thus needs to be sold) decreases when interest rates go up."},
  {"num": 46, "subject": "固定收益", "question": "For a fixed-rate bond, when interest rates decrease, the future value of reinvested coupon payments most likely:", "options": {"A": "decreases and the market price of the bond increases.", "B": "increases and the market price of the bond decreases.", "C": "increases and the market price of the bond increases."}, "answer": "C", "explanation": "A Incorrect because the candidate calculates the Macaulay duration incorrectly: MacDur ≠ 7.4 / (1 + 9%) = 6.8. Because the duration gap is equal to the bond's Macaulay duration minus the investment horizon the investment horizon is incorrectly stated as 6.8 years.\nB Incorrect because the candidate confuses the Macaulay duration with the modified duration, thus incorrectly determining the investment horizon as 7.4 years.\nC Correct because we use the fact that ModDur = MacDur / (1 + r) to calculate the Macaulay duration of the bond: MacDur = 7.4 × (1 + 9%) = 8.07. Because the duration gap is equal to the bond's Macaulay duration minus the investment horizon the investment horizon is closest to 8.1 years."},
  {"num": 47, "subject": "固定收益", "question": "An investor holds a bond with the following characteristics:\nIf the duration gap is zero, the investment horizon is closest to:", "options": {"A": "6.8 years.", "B": "7.4 years.", "C": "8.1 years."}, "answer": "C", "explanation": "A Incorrect because it determines ApproxModDur but then adjusts the calculated duration measure by dividing it by (1 + r), instead of multiplying. AppxModDur = [(PV-) − (PV+)]/[2 × (ΔYield) × (PV0)] = (100.45 – 99.56)/(2 × 0.001 × 100) = 4.45. ApproxMacDur ≠ ApproxModDur / (1 + r) = 4.45/(1 + 0.04) = 4.279 ≈ 4.28.\nB Incorrect because it does not further adjust the modified duration to determine the Macaulay duration. AppxModDur = [(PV-) − (PV+)]/[2 × (ΔYield) × (PV0)] = (100.45 – 99.56)/(2 × 0.001 × 100) = 4.45.\nC Correct because it adjusts the Approximate Modified Duration by 1 + yield to maturity to determine the Macaulay duration. AppxModDur = [(PV-) − (PV+)]/[2 × (ΔYield) × (PV0)] = (100.45 – 99.56)/(2 × 0.001 × 100) = 4.45.\nB Incorrect because a buy-and-hold investor has a higher total return if interest rates rise due to the unexpected excess coupon reinvestment proceeds. If interest rates fall, a buy-and-hold investor realizes no market price returns as he is redeemed at par at maturity. This choice may be attractive to uninformed candidates who focus on the buy-and-hold investor, and not any market interest rate changes.\nC Correct because a long-term investor faces coupon reinvestment risk as well as market price risk if the bond needs to be sold prior to maturity. A buy-and-hold investor in a 10-year bond with a 10-year time horizon is concerned only with coupon reinvestment risk. This situation assumes, of course, that the issuer makes all of the coupon and principal payments as scheduled. The buy-and-hold investor has a higher total return if interest rates rise and a lower total return if rates fall."},
  {"num": 48, "subject": "固定收益", "question": "An analyst gathers the following information about a 4% annual-payment bond with a current yield-to-maturity of 4.0%:\nThe bond’s annualized Macaulay duration is closest to:", "options": {"A": "4.28.", "B": "4.45.", "C": "4.63."}, "answer": "B", "explanation": "A Incorrect because the Macaulay duration of a zero-coupon bond is equal to the time-to-maturity, not less-than the time-to-maturity.\nB Correct because the Macaulay duration of a zero-coupon bond is its time-to-maturity.\nC Incorrect because the Macaulay duration of a zero-coupon bond is equal to the time-to-maturity, not greater-than the time-to-maturity."},
  {"num": 49, "subject": "固定收益", "question": "If interest rates rise over the holding period, the total return of a coupon bond held until maturity is most likely to be:", "options": {"A": "less than the yield to maturity at purchase.", "B": "equal to the yield to maturity at purchase.", "C": "greater than the yield to maturity at purchase."}, "answer": "B", "explanation": "A Incorrect because capital gains and losses are measured from the carrying value of the bond and not from the purchase price or par value.\nB Correct because capital gains arise if a bond is sold at a price above its constant-yield price trajectory and capital losses occur if a bond is sold at a price below its constant-yield price trajectory. Also, capital gains and losses are measured from the carrying value of the bond and not from the purchase price. The carrying value includes the amortization of the discount or premium if the bond is purchased at a price below or above par value. The carrying value is any point on the constant-yield price trajectory.\nC Incorrect because capital gains and losses are measured from the carrying value of the bond and not from the purchase price."},
  {"num": 50, "subject": "固定收益", "question": "The Macaulay duration of a zero-coupon bond is most likely:", "options": {"A": "less than the time to maturity.", "B": "equal to the time to maturity.", "C": "greater than the time to maturity."}, "answer": "C", "explanation": "A Incorrect because, since the reinvestment rate is less than the horizon yield, the yield-to-maturity is greater than the horizon yield of 4.2%.\nB Incorrect because, since the reinvestment rate is less than the horizon yield, the yield-to-maturity is greater than the horizon yield of 4.2%.\nC Correct because the realized horizon yield matches the original yield-to-maturity if (1) coupon payments are reinvested at the same interest rate as the original yield-to-maturity, and (2) the bond is sold at a price on the constant-yield price trajectory, which implies that the investor does not have any capital gains or losses when the bond is sold. Since the reinvestment rate is less than the horizon yield and the bond is held to maturity, the yield to maturity is greater than the horizon yield."},
  {"num": 51, "subject": "固定收益", "question": "An investor sells a fixed-rate bond originally purchased at a discount. The resulting capital gain or loss should be measured by comparing the bond's selling price with its:", "options": {"A": "par value.", "B": "carrying value.", "C": "purchase price."}, "answer": "B", "explanation": "A Incorrect because a callable bond does not have a well-defined internal rate of return (yield-to-maturity). Therefore, yield duration statistics, such as modified and Macaulay durations, do not apply; effective duration is the appropriate duration measure.\nB Correct because modified duration can be used to measure the interest rate risk of a non-complex bond such as a US Treasury bond, while effective duration is essential to the measurement of the interest rate risk of a complex bond, such as a bond that contains an embedded call option.\nC Incorrect because another fixed-income security for which yield duration statistics, such as modified and Macaulay durations, are not relevant is a mortgage-backed bond."},
  {"num": 52, "subject": "固定收益", "question": "A portfolio manager gathers the following information about an option-free bond that was held to maturity:\nThe yield to maturity at purchase was most likely:", "options": {"A": "less than 4.2%.", "B": "equal to 4.2%.", "C": "greater than 4.2%."}, "answer": "C", "explanation": "A Incorrect because the Macaulay and modified duration statistics for a fixed-rate bond depend primarily on the coupon rate, yield-to-maturity, and time-to-maturity. A higher coupon rate or a higher yield-to-maturity reduces the duration measures. A longer time-to-maturity usually leads to a higher duration. It always does so for a bond priced at a premium or at par value. Bond 1 has a lower coupon than Bond 3, a lower yield-to-maturity, and a longer maturity. The Macaulay duration of Bond 1 is therefore greater than that of Bond 3.\nB Incorrect because the Macaulay and modified duration statistics for a fixed-rate bond depend primarily on the coupon rate, yield-to-maturity, and time-to-maturity. A higher coupon rate or a higher yield-to-maturity reduces the duration measures. A longer time-to-maturity usually leads to a higher duration. It always does so for a bond priced at a premium or at par value. Bond 2 has a lower coupon than Bond 3, the same yield-to-maturity, and a longer maturity. The Macaulay duration of Bond 2 is therefore greater than that of Bond 3.\nC Correct because the Macaulay and modified duration statistics for a fixed-rate bond depend primarily on the coupon rate, yield-to-maturity, and time-to-maturity. A higher coupon rate or a higher yield-to-maturity reduces the duration measures. A longer time-to-maturity usually leads to a higher duration. It always does so for a bond priced at a premium or at par value. In this case, Bond 3 has a higher coupon, the same or higher yield-to-maturity, and the shortest time to maturity. It therefore has the lowest Macaulay duration."},
  {"num": 53, "subject": "固定收益", "question": "Modified duration is the most appropriate measure of interest rate risk for which of the following securities?", "options": {"A": "Callable bond.", "B": "US Treasury bond.", "C": "Mortgage-backed bond."}, "answer": "A", "explanation": "A Correct because as time passes during the coupon period (moving from right to left in the diagram), the Macaulay duration declines smoothly and then jumps upward after the coupon is paid. The usual pattern is that longer times-to-maturity correspond to higher Macaulay duration statistics. This pattern always holds for bonds trading at par value or at a premium above par. Conversely, a shorter time to maturity corresponds to a lower Macaulay duration during the coupon period.\nB Incorrect because the usual pattern is that longer times-to-maturity correspond to higher Macaulay duration statistics. This pattern always holds for bonds trading at par value or at a premium above par. Macaulay duration statistic stays constant if the bond is a perpetuity.\nC Incorrect because if the bond is priced at a discount [not at a premium], a longer time-to-maturity might lead to a lower duration. This situation only occurs if the coupon rate is low (but not zero) relative to the yield and the time-to-maturity is long. Conversely, only for special cases of discount bonds, a shorter time to maturity might lead to a higher duration statistic."},
  {"num": 54, "subject": "固定收益", "question": "An analyst gathers the following information about three option-free bonds, each trading at a premium:\nAll else being equal, the bond with the lowest Macaulay duration is most likely:", "options": {"A": "Bond 1.", "B": "Bond 2.", "C": "Bond 3."}, "answer": "B", "explanation": "A Incorrect because the clean price is used: ΔPVFull ≠ — (5.2 × 90) × — 0.001 = 0.468 ≈ 0.47.\nB Correct because the money duration of a bond is a measure of the price change in units of the currency in which the bond is denominated: MoneyDur = AnnModDur × PVFull and, ΔPVFull ≈ –MoneyDur × ΔYield where MoneyDur = money duration, AnnModDur = annual modified duration, PVFull = full price of bond = PVFlat + AI and ΔPVFull = change in full price. (p. 409) Therefore, ΔPVFull ≈ —(5.2 ×( 90 + 5)) × — 0.001 = 0.494 ≈ 0.49.\nC Incorrect because the par value is used. ΔPVFull ≠ — (5.2 × 100) × — 0.001 = 0.52."},
  {"num": 55, "subject": "固定收益", "question": "For an option-free fixed-rate bond trading at a premium, as the coupon payment date approaches, Macaulay duration most likely:", "options": {"A": "decreases.", "B": "remains constant.", "C": "increases."}, "answer": "C", "explanation": "A Incorrect because the candidate uses only the increase in price in the numerator: (101.25 – 100.00)/(2 × 0.001 × 100.00) = 6.25, or 6.3.\nB Incorrect because the candidate uses the range of yields, e.g., 3.1 – 2.9, in the denominator: (101.25 – 98.90)/(2 × 0.002 × 100.00) = 5.875, or 5.9.\nC Correct because Approx ModDur = ;"},
  {"num": 56, "subject": "固定收益", "question": "An analyst gathers the following information about a bond:\nIf yield-to-maturity decreases by 10 basis points, the change in price for this bond is closest to:", "options": {"A": "$0.47.", "B": "$0.49.", "C": "$0.52."}, "answer": "C", "explanation": "A Incorrect because the PVBP cannot be a negative value because bond duration is derived by discounting bond cash flows.\nB Incorrect because 0.1021 is the percentage price change for a 1 bp change in rates, not a dollar amount.\nC Correct because price value of a basis point (the absolute value of the change in the price of a bond for a 1-basis-point change in yield) is related to duration, the approximate percentage price change for a 100 bp change in rates. It follows that the approximate percentage price change for a 1 bp change in rates can be determined:"},
  {"num": 57, "subject": "固定收益", "question": "An analyst gathers the following information about the price of a semiannual-pay bond at various yield levels:\nIf the bond is currently priced at par, the approximate modified duration is closest to:", "options": {"A": "5.9.", "B": "6.3.", "C": "11.8."}, "answer": "C", "explanation": "A Incorrect because a perpetuity or perpetual bond is a bond that does not mature. Therefore, there is no time-to-maturity. On the other hand, the Macaulay duration of a zero-coupon bond is its time-to-maturity.\nB Incorrect because the Macaulay duration decreases smoothly as t goes from t = 0 to t = T, which creates a “saw-tooth” pattern. As time passes during the coupon period, the Macaulay duration declines smoothly and then jumps upward after the coupon is paid. As per the justification of the correct answer, the Macaulay duration of a non-callable perpetual bond is a function of its yield, and it is graphically represented as a horizontal line.\nC Correct because a perpetuity or perpetual bond is a bond that does not mature. There is no principal to redeem. The investor receives a fixed coupon payment forever, unless the bond is callable. Non-callable perpetuities have an interesting Macaulay duration: MacDur = (1 + r)/r as N approaches infinity, where r represents yield to maturity. The Macaulay duration of a non-callable perpetual bond is a function of its yield only."},
  {"num": 58, "subject": "固定收益", "question": "The duration of an option-free bond is 10.21. If the current price of the bond is 121.355, the price value of a basis point (PVBP) is closest to:", "options": {"A": "–0.1239.", "B": "0.1021.", "C": "0.1239."}, "answer": "B", "explanation": "A Incorrect because duration is a quantitative measure of interest rate risk. There are several duration measures, including those that measure a bond’s price sensitivity to changes in its own yield-to-maturity and assume underlying cash flows are certain (yield duration) and those that measure changes in a benchmark yield curve, with less certain underlying cash flows (curve duration).\nB Correct because duration is a quantitative measure of interest rate risk. There are several duration measures, including those that measure a bond’s price sensitivity to changes in its own yield-to-maturity and assume underlying cash flows are certain (yield duration) and those that measure changes in a benchmark yield curve, with less certain underlying cash flows (curve duration).\nC Incorrect because duration is a quantitative measure of interest rate risk. There are several duration measures, including those that measure a bond’s price sensitivity to changes in its own yield-to-maturity and assume underlying cash flows are certain (yield duration) and those that measure changes in a benchmark yield curve, with less certain underlying cash flows (curve duration). Macaulay duration, modified duration, money duration, and the price value of a basis point (PVBP) are yield duration measures."},
  {"num": 59, "subject": "固定收益", "question": "For a non-callable perpetual bond with a constant yield to maturity, the Macaulay duration is:", "options": {"A": "equal to the bond's time to maturity.", "B": "represented graphically as a \"saw-tooth\" pattern.", "C": "calculated as (1 + yield to maturity) / yield to maturity."}, "answer": "B", "explanation": "A Incorrect because 100bp (0.01) is used in the denominator rather than 0.0075: (106.32 – 105.45)/2(105.9)0.01 = 0.4108, rounded to 0.41.\nB Correct because effective duration = . So, (106.32 – 105.45)/2(105.9)0.0075 = 0.547, rounded to 0.55.\nC Incorrect because it omits the 2 in the denominator:"},
  {"num": 60, "subject": "固定收益", "question": "The sensitivity of a bond's price to benchmark interest rates best defines:", "options": {"A": "yield duration.", "B": "curve duration.", "C": "modified duration."}, "answer": "B", "explanation": "A Incorrect because it weights the bonds by par value. DP= [(100,000 ÷ 300,000) × 5] + [(200,000 ÷ 300,000) × 4] = (0.333 × 5) + (0.667 × 4) = 1.665 + 2.668 = 4.333 = 4.33\nB Correct because the portfolio's duration is the weighted average (by market value) of the duration of the bonds in the portfolio. Duration of portfolio = [(120,000 ÷ 300,000) × 5] + [(180,000 ÷ 300,000) × 4] = (0.4 × 5) + (0.6 × 4) = 2.00 + 2.40 = 4.40\nC Incorrect because it weights the bonds by their duration."},
  {"num": 61, "subject": "固定收益", "question": "An analyst gathers the following information about a bond:\nIf the current price of the bond is 105.90, the effective duration is closest to:", "options": {"A": "0.41.", "B": "0.55.", "C": "1.10."}, "answer": "A", "explanation": "A Correct because modified duration provides an estimate of the percentage price change for a bond given a change in its yield-to-maturity. A modified duration of 2.4 translates to a 2.4% percentage price change given a 100 basis points change in the bond's yield to maturity. Therefore, for a 50 basis point decrease in yields, the bond's price will change by (2.4)(0.0050)($912,575) = $10,951 ≈ $11,000.\nB Incorrect because it uses an incorrect calculation (0.024)($912,575) = $21,902 ≈ $22,000.\nC Incorrect because it uses an incorrect calculation (0.024)($1,000,000) = $24,000."},
  {"num": 62, "subject": "固定收益", "question": "An investor gathers the following information about a bond portfolio comprised of two option-free bonds:\nThe duration of the portfolio is closest to:", "options": {"A": "4.33.", "B": "4.40.", "C": "4.55."}, "answer": "B", "explanation": "A Incorrect because the denominator is incorrectly multiplied by 2, as happens in the calculation of approximate duration: = 521\nB Correct because ApproxCon = .Therefore the approximate convexity of this =\nC Incorrect because the approximate convexity is incorrectly calculated as approximate duration, with a mistake in that the change in yield (0.001) is squared:"},
  {"num": 63, "subject": "固定收益", "question": "An analyst gathers the following information about an option-free bond:\nIf yields are expected to decrease by 50 basis points, the expected price change for the bond is closest to:", "options": {"A": "$11,000.", "B": "$22,000.", "C": "$24,000."}, "answer": "A", "explanation": "A Correct because the Macaulay and modified durations for the portfolio are calculated as the weighted average of the statistics for the individual bonds. The shares of overall portfolio market value are the weights. First we calculate the modified duration (ModDur) of the individual bonds using formula below: ModDur = MacDur / (1 + r) ModDur of Bond 1 = 7.5 / (1 + 4%) = 7.211538 ModDur of Bond 2 = 5.4 / (1 + 3%) = 5.242718. Next, we calculate the weights for the individual bonds based on market values, as follows: Weight for Bond 1 = $200,000 / ($200,000 + $400,000) = 0.333333 Weight for Bond 2 = $400,000 / ($200,000 + $400,000) = 0.666667 Modified duration of the portfolio = (Weight for Bond 1 × ModDur of Bond 1) + (Weight for Bond 2 × ModDur of Bond 2) = (0.333333 × 7.211538) + (0.666667 × 5.242718) = 5.898992 ≈ 5.9.\nB Incorrect because the weights based on par value are used. Weight for Bond 1 ≠ $300,000 / ($300,000 + $450,000) = 0.4 Weight for Bond 2 ≠ $450,000 / ($300,000 + $450,000) = 0.6 Modified duration of the portfolio ≠ (0.4 × 7.211538) + (0.6 × 5.242718) = 6.030246 ≈ 6.0.\nC Incorrect because it uses Macaulay duration instead of modified duration for the individual bonds, and represents the Macaulay duration of the portfolio."},
  {"num": 64, "subject": "固定收益", "question": "An analyst gathers the following information about a bond:\nThe approximate convexity of this bond is closest to:", "options": {"A": "521.", "B": "1,042.", "C": "2,604."}, "answer": "A", "explanation": "A Correct because %∆PVFull = (–AnnModDur × ∆Yield) + [(0.5 × AnnConvexity × ∆(Yield)2]= (–6.9 × 0.0075) + (0.5 × –212 × 0.00752) = –0.05175 – 0.0059625 = 0.0577125, rounded to 5.77%. The percentage decline in price = –0.0577125 × 99.4 = –5.7366, and the bond price = 99.4 – 5.7366 = 93.6634, rounded to 93.66.\nB Incorrect because the price is calculated using par instead of 99.4: Price ≠ 100 – 5.74 = 94.26.\nC Incorrect because the convexity adjustment is input as a positive number:(–6.9 × 0.0075) + (0.5 × 212 × 0.00752) = –0.05175 + 0.0059625 = 0.04579, rounded to 4.58%. The percentage decline in price = 0.04579 × 99.4 = 4.5515, and the bond price = 99.4 – 4.5515 = 94.8485, rounded to 94.85."},
  {"num": 65, "subject": "固定收益", "question": "A bond portfolio consists of the following option-free annual-pay coupon bonds:\nThe modified duration of this portfolio is closest to:", "options": {"A": "5.9.", "B": "6.0.", "C": "6.1."}, "answer": "B", "explanation": "A Incorrect because the convexity adjustment is subtracted rather than added. The percentage change in price is not equal to –4.901961 * –0.01 – (0.5 * 28.835 * –0.012) = 0.04901961 – 0.0014418 = 4.757781%, rounded to 4.76%.\nB Correct because the Macaulay duration of a zero-coupon bond is its time-to-maturity and modified duration is the Macaulay duration statistic divided by one plus the yield per period. Here, modified duration = 5/1.02 = 4.901961. Thus, the percentage change in price = –4.901961 * –0.01 + (0.5 * 28.835 * –0.012) = 0.04901961 + 0.0014418 = 5.04614%, rounded to 5.05%.\nC Incorrect because the convexity adjustment is applied to the Macaulay duration rather than the modified duration. The percentage change in price is not equal to –5 * –0.01 + (0.5 * 28.835 * –0.012) = 0.05 + 0.0014418 = 5.14418%, rounded to 5.14%."},
  {"num": 66, "subject": "固定收益", "question": "A bond priced at 99.4 has a modified duration of 6.9 and an annual convexity statistic of –212. If the market yield increases by 75 basis points, the price of this bond is closest to:", "options": {"A": "93.7.", "B": "94.3.", "C": "94.9."}, "answer": "A", "explanation": "A Correct because money duration (MoneyDur) is calculated as the annual modified duration times the full price (PVFull) of the bond, including accrued interest. Thus the modified durations of the bonds are 730/95 = 7.6842 and 515/120 = 4.29167, respectively. The modified duration of a bond portfolio is calculated as the weighted average of the statistics for the individual bonds. The shares of overall portfolio market value are the weights. Here, the market values of the bonds are £25 million * 95/100 = £23,750,000 and £25 million * 120/100 = £30,000,000. Thus the weight of the first bond in the portfolio is £23,750,000 / (£23,750,000 + £30,000,000) = 44.186% and the weight of the second bond in the portfolio is £30,000,000 / (£23,750,000 + £30,000,000) = 55.814%. The modified duration of the portfolio is therefore 44.186% * 7.6842 + 55.814% * 4.29167 = 3.3953 + 2.3953 = 5.7907, rounded to 5.8.\nB Incorrect because the modified duration of the portfolio is not equal to the weighted average of the money durations of the bonds divided by 100. Portfolio modified duration <> 44.186% * 730 / 100 + 55.814% * 5.15 / 100 = 6.1. Instead, the modified duration of a bond portfolio is calculated as the weighted average of the statistics for the individual bonds. The shares of overall portfolio market value are the weights.\nC Incorrect because the modified duration of the portfolio is not equal to the simple average of the money durations of the bonds divided by 100. Portfolio modified duration 50% * 730 / 100 + 50% * 5.15 / 100 = 6.225, rounded to 6.2. Instead, the modified duration of a bond portfolio is calculated as the weighted average of the statistics for the individual bonds. The shares of overall portfolio market value are the weights. Candidates may choose this option because the par values of the bonds are the same."},
  {"num": 67, "subject": "固定收益", "question": "An analyst gathers the following information about a zero-coupon bond:\nIf the yield decreases by 1%, the bond's percentage change in price is closest to:", "options": {"A": "4.76%.", "B": "5.05%.", "C": "5.14%."}, "answer": "C", "explanation": "A Incorrect because the two bonds are assumed to have the same price, yield-to-maturity, and modified duration. The benefit of greater convexity occurs when their yields-to-maturity change. For the same decrease in yield-to-maturity, the more convex bond appreciates more in price. And for the same increase in yield-to-maturity, the more convex bond depreciates less in price. The conclusion is that the more convex bond outperforms the less convex bond in both bull (rising price) and bear (falling price) markets. The more convex bond always outperforms the less convex bond.\nB Incorrect because the two bonds are assumed to have the same price, yield-to-maturity, and modified duration. The benefit of greater convexity occurs when their yields-to-maturity change. For the same decrease in yield-to-maturity, the more convex bond appreciates more in price. And for the same increase in yield-to-maturity, the more convex bond depreciates less in price. The conclusion is that the more convex bond outperforms the less convex bond in both bull (rising price) and bear (falling price) markets. The more convex bond always outperforms the less convex bond.\nC Correct because the two bonds are assumed to have the same price, yield-to-maturity, and modified duration. The benefit of greater convexity occurs when their yields-to-maturity change. And for the same increase in yield-to-maturity, the more convex bond depreciates less in price (than the less convex bond)."},
  {"num": 68, "subject": "固定收益", "question": "An analyst gathers the following details about a bond portfolio:\nIf each bond has a par value of £25 million, the modified duration of this bond portfolio is closest to:", "options": {"A": "5.8.", "B": "6.1.", "C": "6.2."}, "answer": "C", "explanation": "A Incorrect because the modified duration is not negated. %ΔPVFull ≠ (AnnModDur × ΔYield) + [1/2 × AnnConvexity × (ΔYield)2] = (13.2 × −0.0010) + [1/2 × 1081 × (−0.0010)2] = –0.0132 + 0.0005405 = −1.26595% ≈ −1.27%.\nB Incorrect because the convexity adjustment is subtracted instead of added: %ΔPVFull ≈ (−AnnModDur × ΔYield) – [1/2 × AnnConvexity × (ΔYield)2] = (−13.2 × −0.0010) – [1/2 × 1081 × (−0.0010)2] = 0.0132 – 0.0005405 = 1.26595% ≈ 1.27%.\nC Correct because %ΔPVFull ≈ (−AnnModDur × ΔYield) + [1/2 × AnnConvexity × (ΔYield)2] = (−13.2 × −0.0010) + [1/2 × 1081 × (−0.0010)2] = 0.0132 + 0.0005405 = 1.37405% ≈ 1.37%."},
  {"num": 69, "subject": "固定收益", "question": "Two par bonds have the same duration but different convexity. All else being equal, if yields to maturity increase by 10 basis points, it is most likely that:", "options": {"A": "the more convex bond underperforms the less convex bond.", "B": "both bond prices decrease by the same amount.", "C": "the more convex bond outperforms the less convex bond."}, "answer": "C", "explanation": "A Incorrect because it omits the basis point change × 100 from the calculation. Effective duration ≠ (PV- – PV+)/2 = (103 – 98)/2 = 2.5.\nB Incorrect because it is the difference in the prices (103 – 98 = 5).\nC Correct because the effective duration is calculated as (PV- – PV+)/(2 × ∆Curve × PV0), where: PV- = the bond price when the benchmark yield is decreased, PV+ = the bond price when the benchmark yield is increased, and PV0 = then current bond price."},
  {"num": 70, "subject": "固定收益", "question": "An analyst gathers the following information about an option-free coupon bond that pays annually:\nIf the bond's yield decreases by 10 basis points, the expected percentage price change for this bond is closest to:", "options": {"A": "−1.27%.", "B": "1.27%.", "C": "1.37%."}, "answer": "A", "explanation": "A Correct because the price of a putable bond is always higher than that of an otherwise comparable non-putable bond. The price difference is the value of the embedded put option and the price of the non-callable bond is always greater than that of the callable bond with otherwise identical features.\nB Incorrect because the price of a putable bond is always higher than that of an otherwise comparable non-putable bond. The price difference is the value of the embedded put option.\nC Incorrect because the price of the non-callable bond is always greater than that of the callable bond with otherwise identical features."},
  {"num": 71, "subject": "固定收益", "question": "An analyst gathers the following information about a bond currently trading at par:\nThe effective duration of this bond is closest to:", "options": {"A": "2.5.", "B": "5.0.", "C": "10.0."}, "answer": "B", "explanation": "A Incorrect because the difference between approximate modified duration and effective duration is in the denominator. Modified duration is a >yield duration statistic in that it measures interest rate risk in terms of a change in the bond's own yield-to-maturity (ΔYield). This question refers to changes in the benchmark yield curve, not the bond's own yield to maturity; therefore, modified duration is an incorrect measure.\nB Correct because for parallel shifts in the benchmark yield curve, key rate durations will indicate the same interest rate sensitivity as effective duration.\nC Incorrect because the difference between approximate modified duration and effective duration is in the denominator. Modified duration is a yield duration statistic in that it measures interest rate risk in terms of a change in the bond's own yield-to-maturity (ΔYield). Additionally, The calculation of the modified duration (ModDur) statistic of a bond requires a simple adjustment to Macaulay duration. It is the Macaulay duration statistic divided by one plus the yield per period. Thus, the Macaulay duration, as a mathematical derivative of modified duration, is also a measure of risk in terms of the change in a bond's own yield-to-maturity. This question refers to changes in the benchmark yield curve, not the bond's own yield-to-maturity; therefore, modified duration is an incorrect measure."},
  {"num": 72, "subject": "固定收益", "question": "Among three otherwise comparable bonds, the bond with the highest price is most likely to be:", "options": {"A": "putable.", "B": "callable.", "C": "option-free."}, "answer": "B", "explanation": "A Incorrect because if interest rates are low compared with the coupon rate, the value of the put option is low and the impact of a change in the benchmark yield on the putable bond's price is very similar to the impact on the price of a non-putable bond, e.g., not limited. Furthermore, a rational investor would not exercise the put option when the market interest rate is lower than the coupon rate of the bond.\nB Correct because when interest rates are low, the effective duration of the callable bond is lower than that of the otherwise comparable non-callable bond because the callable bond price does not increase as much when benchmark yields fall. The presence of the call option limits price appreciation especially when interest rates are falling and the bond is more likely to be called.\nC Incorrect because the presence of an embedded option reduces the sensitivity of the bond price to changes in the benchmark yield curve, assuming no change in credit risk. An option-free bond serves as the base case, whereas with a call, price appreciation is limited when market rates go below the coupon rate and with a put, price depreciation is limited when market rates go above the coupon rate."},
  {"num": 73, "subject": "固定收益", "question": "With respect to a bond with an embedded option, for parallel shifts in the benchmark yield curve, effective duration most likely indicates the same interest rate sensitivity as:", "options": {"A": "modified duration.", "B": "key rate durations.", "C": "Macaulay duration."}, "answer": "B", "explanation": "A Incorrect because the effective duration is incorrectly calculated as EffDur = [(PV0) – (PV+)] / [(Δ Curve) × (PV0)] = (95.35 – 92.25) / (0.005 × 95.35) = 6.50.\nB Correct because the effective duration of a bond is the sensitivity of the bond's price to a change in a benchmark yield curve. EffDur = [(PV– ) – (PV+)] / [2 × (ΔCurve) × (PV0)] With PV0 = 95.35, PV– = 99.50, PV+ = 92.25, EffDur = (99.50 – 92.25) / (2 × 0.005 × 95.35) = 7.60.\nC Incorrect because the effective duration is incorrectly calculated as"},
  {"num": 74, "subject": "固定收益", "question": "All else being equal, when the market interest rate falls below a bond's coupon rate, potential price appreciation is most limited for a:", "options": {"A": "putable bond.", "B": "callable bond.", "C": "option-free bond."}, "answer": "B", "explanation": "A Incorrect because modified duration is a yield duration statistic. There are several types of bond duration. In general, these can be divided into yield duration and curve duration. Yield duration is the sensitivity of the bond price with respect to the bond’s own yield- to- maturity.\nB Correct because effective duration is a curve duration statistic in that it measures interest rate risk in terms of a parallel shift in the benchmark yield curve.\nC Incorrect because Macaulay duration is a weighted average of the time to receipt of"},
  {"num": 75, "subject": "固定收益", "question": "An analyst gathers the following information about a bond which is currently trading at 95.35 per 100 par:\nThe effective duration of the bond is closest to:", "options": {"A": "6.5.", "B": "7.6.", "C": "8.7."}, "answer": "B", "explanation": "A Incorrect because it uses the current price instead of the price if interest rates increase in the numerator = (PV+ − PV0 ) / (2 × Δcurve × PV0) = ( 100.75 − 100.00) / ( 2 × 0.001 × 100.00) = 3.75.\nB Correct because effective duration = (PV+ − PV- ) / (2 × Δcurve × PV0) = ( 100.75 − 99.26) / (2 × 0.001 × 100.00) = 7.45.\nC Incorrect because it uses the current price instead of the price if interest rates increase in the numerator and fails to multiply by 2 in the denominator; = (PV+ − PV0 ) / (Δcurve × PV0) = (100.75 − 100.00) / ( 0.001 × 100.00 ) = 7.50."},
  {"num": 76, "subject": "固定收益", "question": "Which of the following is a curve duration measure?", "options": {"A": "Modified duration.", "B": "Effective duration.", "C": "Macaulay duration."}, "answer": "C", "explanation": "A Incorrect because although effective duration is the most appropriate interest rate risk measure for bonds with embedded options, it also is useful with traditional bonds to supplement the information provided by the Macaulay and modified yield durations.\nB Incorrect because a practical consideration in using effective duration is in setting the change in the benchmark yield curve. With approximate modified duration, accuracy is improved by choosing a smaller yield-to-maturity change. But the pricing models for more-complex securities, such as callable and mortgage-backed bonds, include assumptions about the behavior of the corporate issuers, businesses, or homeowners. Rates typically need to change by a minimum amount to affect the decision to call a bond or refinance a mortgage loan because issuing new debt involves transaction costs. Therefore, estimates of interest rate risk using effective duration are not necessarily improved by choosing a smaller change in benchmark rates.\nC Correct because the modified duration and effective duration on an option-free bond are identical only in the rare circumstance of an absolutely flat yield curve."},
  {"num": 77, "subject": "固定收益", "question": "An analyst gathers the following information about a 6% coupon bond currently trading at par:\nThe bond's effective duration is closest to:", "options": {"A": "3.75.", "B": "7.45.", "C": "7.50."}, "answer": "A", "explanation": "A Correct because effective duration is essential to the measurement of the interest rate risk of a complex bond, such as a bond that contains an embedded call option. The problem is that future cash flows are uncertain because they are contingent on future interest rates. The issuer’s decision to call the bond depends on the ability to refinance the debt at a lower cost of funds. Effective duration is the appropriate duration measure.\nB Incorrect because a callable bond does not have a well-defined internal rate of return (yield-to-maturity). Therefore, yield duration statistics, such as modified and Macaulay durations, do not apply; effective duration is the appropriate duration measure.\nC Incorrect because effective duration measures the bond's sensitivity to changes in the benchmark yield curve and not changes in credit spread, which are measured by other means (pricing models). This curve duration measure [effective duration] indicates the bond’s sensitivity to the benchmark yield curve—in particular, the government par curve—assuming no change in the credit spread. A pricing model can be used to determine a 'credit duration' statistic—that is, the sensitivity of the bond price to a change in the credit spread."},
  {"num": 78, "subject": "固定收益", "question": "Effective duration is:", "options": {"A": "a useful interest rate risk measure only for bonds with embedded options.", "B": "an accurate estimate of interest rate risk only when the assumed benchmark rate change is small.", "C": "the same as the modified duration of an option-free bond only when the yield curve is perfectly flat."}, "answer": "C", "explanation": "A Incorrect because this describes modified duration. Modified duration provides an estimate of the percentage price change for a bond given a change in its yield-to-maturity.\nB Incorrect because the duration of a callable bond is not the sensitivity of the bond price to a change in the yield-to-worst (i.e., the lowest of the yield-to-maturity, yield-to-first-call, yield-to-second-call, and so forth). In contrast to effective duration, key rate durations help identify 'shaping risk' for a bond–that is, a bond’s sensitivity to changes in the shape of the benchmark yield curve (e.g., the yield curve becoming steeper or flatter).\nC Correct because key rate duration (or partial duration) is a measure of a bond’s sensitivity to a change in the benchmark yield curve at a specific maturity segment. In contrast to effective duration, key rate durations help identify 'shaping risk' for a bond—that is, a bond’s sensitivity to changes in the shape of the benchmark yield curve (e.g., the yield curve becoming steeper or flatter)."},
  {"num": 79, "subject": "固定收益", "question": "For a bond with an embedded option, effective duration is the most appropriate measure of interest rate risk because the bond's:", "options": {"A": "future cash flows are uncertain.", "B": "internal rate of return is well-defined.", "C": "pricing is sensitive to changes in credit spreads."}, "answer": "A", "explanation": "A Correct because key rate duration (or partial duration) is a measure of a bond’s sensitivity to a change in the benchmark yield curve at a specific maturity segment. In contrast to effective duration, key rate durations help identify 'shaping risk' for a bond—that is, a bond’s sensitivity to changes in the shape of the benchmark yield curve (e.g., the yield curve becoming steeper or flatter).\nB Incorrect because effective duration indicates the bond’s sensitivity to the benchmark yield curve assuming that all yields change by the same amount. In contrast to effective duration, key rate durations help identify 'shaping risk' for a bond—that is, a bond’s sensitivity to changes in the shape of the benchmark yield curve (e.g., the yield curve becoming steeper or flatter).\nC Incorrect because yield duration statistics measuring the sensitivity of a bond’s full price to the bond’s own yield-to-maturity include the Macaulay duration, modified duration, money duration, and price value of a basis point. The Macaulay duration measures the sensitivity of a bond's full price to a change in its yield to maturity, not to changes in the shape of the benchmark yield curve."},
  {"num": 80, "subject": "固定收益", "question": "The key rate duration best measures a bond's sensitivity to a change in the:", "options": {"A": "level of the yield-to-maturity.", "B": "slope of the yield-to-worst curve.", "C": "shape of the benchmark yield curve."}, "answer": "C", "explanation": "A Incorrect because when the benchmark yield is high and the value of the embedded call option is low, the callable and the non-callable bonds experience very similar effects from interest rate changes. They both have positive convexity. But as the benchmark yield is reduced, the curves diverge. At some point, the callable bond moves into the range of negative convexity, which indicates that the embedded call option has more value to the issuer and is more likely to be exercised.\nB Incorrect because when the benchmark yield is high and the value of the embedded call option is low, the callable and the non-callable bonds experience very similar effects from interest rate changes. They both have positive convexity. But as the benchmark yield is reduced, the curves diverge. At some point, the callable bond moves into the range of negative convexity, which indicates that the embedded call option has more value to the issuer and is more likely to be exercised.\nC Correct because when the benchmark yield is high and the value of the embedded call option is low, the callable and the non-callable bonds experience very similar effects from interest rate changes. They both have positive convexity. But as the benchmark yield is reduced, the curves diverge. At some point, the callable bond moves into the range of negative convexity, which indicates that the embedded call option has more value to the issuer and is more likely to be exercised."},
  {"num": 81, "subject": "固定收益", "question": "Which of the following duration statistics best measures the sensitivity of a bond’s price to a flattening of the yield curve?", "options": {"A": "Key rate duration.", "B": "Effective duration.", "C": "Macaulay duration."}, "answer": "C", "explanation": "A Incorrect because the duration of a callable bond is not the sensitivity of the bond price to a change in the yield-to-worst (i.e., the lowest of the yield-to-maturity, yield-to-first-call, yield-to-second-call, and so forth) a callable bond does not have a well-defined internal rate of return (yield-to-maturity). Therefore, yield duration statistics, such as modified and Macaulay durations, do not apply; effective duration is the appropriate duration measure.\nB Incorrect because only the primary, or first-order, effect of a shift in the benchmark yield curve is measured by effective duration, the secondary, or second-order, effect is measured by effective convexity. The convexity adjustment is measured by effective convexity and not accounted for in effective duration.\nC Correct because a callable bond does not have a well-defined internal rate of return (yield to maturity). Therefore, yield duration statistics, such as modified and Macaulay durations, do not apply; effective duration is the appropriate duration measure."},
  {"num": 82, "subject": "固定收益", "question": "Callable bonds exhibit:", "options": {"A": "positive convexity only.", "B": "negative convexity only.", "C": "either positive or negative convexity."}, "answer": "A", "explanation": "A Correct because the effective duration of a bond is the sensitivity of the bond’s price to a change in a benchmark yield. Modified duration is a yield duration statistic in that it measures interest rate risk in terms of a change in the bond’s own yield-to-maturity (ΔYield). Effective duration is a curve duration statistic in that it measures interest rate risk in terms of a parallel shift in the benchmark yield curve (ΔCurve). Effective duration is essential to the measurement of the interest rate risk of a complex bond, such as a bond that contains an embedded call option. The problem is that future cash flows are uncertain because they are contingent on future interest rates. Therefore, yield duration statistics, such as modified and Macaulay durations, do not apply; effective duration is the appropriate duration measure.\nB Incorrect because effective duration is essential to the measurement of the interest rate risk of a complex bond, such as a bond that contains an embedded call option. The problem is that future cash flows are uncertain because they are contingent on future interest rates. Therefore, yield duration statistics, such as modified and Macaulay durations, do not apply.\nC Incorrect because effective duration is essential to the measurement of the interest rate risk of a complex bond, such as a bond that contains an embedded call option. The problem is that future cash flows are uncertain because they are contingent on future interest rates. Therefore, yield duration statistics, such as modified and Macaulay durations, do not apply; effective duration is the appropriate duration measure."},
  {"num": 83, "subject": "固定收益", "question": "Effective duration is the appropriate interest rate risk measure for callable bonds because it:", "options": {"A": "measures the sensitivity of the bond price to a change in the yield to worst.", "B": "accounts for the convexity adjustment which can be significant for callable bonds.", "C": "can be calculated for bonds that do not have a well-defined internal rate of return."}, "answer": "A", "explanation": "A Correct because in general, the differences [between yield duration and convexity and curve duration and convexity] are heightened when the benchmark yield curve is not flat, when the bond has a long time-to-maturity, and the bond is priced at a significant discount or premium. Therefore, the difference between yield duration and curve duration are most similar when the benchmark yield curve is flat.\nB Incorrect because these differences are heightened when the benchmark yield curve is not flat.\nC Incorrect because these differences are heightened when the bond is priced at a significant discount or premium."},
  {"num": 84, "subject": "固定收益", "question": "The most appropriate measure of interest rate risk for a bond with an embedded option is:", "options": {"A": "effective duration.", "B": "modified duration.", "C": "Macaulay duration."}, "answer": "A", "explanation": "A Correct because the convexity adjustment is the annual convexity statistic, AnnConvexity, times one-half, multiplied by the change in the yield-to-maturity squared. This additional term is a positive amount on a traditional (option-free) fixed-rate bond for either an increase or decrease in the yield.\nB Incorrect because negative convexity, which could be called 'concavity,' is an important feature of callable bonds. As a second-order effect, effective convexity indicates the change in the first-order effect (i.e., effective duration) as the benchmark yield curve is changed. But the slope of the line tangent to the callable bond flattens as the benchmark yield goes down. Technically, it reaches an inflection point, which is when the effective convexity shifts from positive to negative. In summary, when the benchmark yield is high and the value of the embedded call option is low, the callable and the non-callable bonds experience very similar effects from interest rate changes. They both have positive convexity. But as the benchmark yield is reduced, the curves diverge. At some point, the callable bond moves into the range of negative convexity, which indicates that the embedded call option has more value to the issuer and is more likely to be exercised. Therefore, the convexity adjustment is not negative for a callable bond when the value of the option is low; it can be negative only when the option value is high.\nC Incorrect because the convexity adjustment is the annual convexity statistic, AnnConvexity, times one-half, multiplied by the change in the yield-to-maturity squared. This additional term is a positive amount on a traditional (option-free) fixed-rate bond for either an increase or decrease in the yield. The convexity measure is positive in response to interest rate changes, regardless of the change in yields up or down. For bonds with a call option, the convexity adjustment may positive or negative, but that is based on the level, or moneyness, of the call option, not based on the change in interest rates. Additionally, effective convexity indicates the change in the first-order effect (i.e., effective duration) as the benchmark yield curve is changed. But the slope of the line tangent to the callable bond flattens as the benchmark yield goes down. Technically, it reaches an inflection point, which is when the effective convexity shifts from positive to negative. The convexity adjustment is negative (not positive) when yields decrease and positive (not negative) when bond yields increase."},
  {"num": 85, "subject": "固定收益", "question": "The yield duration and the curve duration of a zero-coupon bond are most similar when the:", "options": {"A": "benchmark yield curve is flat.", "B": "bond has a long time to maturity.", "C": "bond is priced at a significant discount."}, "answer": "C", "explanation": "A Incorrect because effective duration and effective convexity are curve-based metrics that are useful for gauging the interest rate risk of complex instruments—such as those with embedded contingency provisions—whose future cash flows are uncertain. These metrics are typically determined from bond prices derived using an option valuation model, given specific (parallel) changes in the underlying benchmark government yield curve.\nB Incorrect because bonds with embedded options do not have well-defined yields-to-maturity, so Macaulay and modified durations are not appropriate interest rate risk measures for such bonds. Rather, the appropriate measure of interest rate risk is the sensitivity of the bond’s price to a change in a benchmark yield curve—for example, the government par curve—known as effective duration, a curve duration rather than a yield duration statistic. The credit spread is a component of the yield to maturity, a yield duration statistic, while effective duration is a curve duration.\nC Correct because if a bond has contingency features, such as embedded options, as with a callable (or puttable) bond, then future cash flows are uncertain since option exercise depends on the level of market interest rates relative to coupon interest being paid (or received). Consequently, bonds with embedded options do not have well-defined yields-to-maturity, so Macaulay and modified durations are not appropriate interest rate risk measures for such bonds. Rather, the appropriate measure of interest rate risk is the sensitivity of the bond’s price to a change in a benchmark yield curve—for example, the government par curve—known as effective duration, a curve duration rather than a yield duration statistic."},
  {"num": 86, "subject": "固定收益", "question": "Which of the following statements is most accurate? The convexity adjustment is:", "options": {"A": "positive for an option-free bond in all circumstances.", "B": "negative for a callable bond when the value of the option is very low.", "C": "positive when bond yields decrease and negative when bond yields increase."}, "answer": "B", "explanation": "A Incorrect because loss severity is often expressed as (1 − Recovery rate), where the recovery rate is the percentage of the principal amount recovered in the event of default.\nB Correct because Expected loss = Default probability × Loss severity given default.\nC Incorrect because loss severity is most relevant for lower-quality debt issuers. Because default risk (default probability) is quite low for most high-quality debt issuers, bond investors tend to focus primarily on assessing this probability and devote less effort to assessing the potential loss severity arising from default."},
  {"num": 87, "subject": "固定收益", "question": "Effective duration is the most appropriate interest rate risk measure for a bond when:", "options": {"A": "the shape of the yield curve changes.", "B": "there is a change in the bond's credit spread.", "C": "the issuer has the right to pay off the bond prior to maturity."}, "answer": "A", "explanation": "A Correct because market liquidity risk is the risk that the price at which investors can actually transact—buying or selling—may differ from the price indicated in the market. The lower the quality of the issuer, the higher the market liquidity risk.\nB Incorrect because the lower the quality of the issuer, the higher the market liquidity risk. In this case the investment grade borrower has less market liquidity risk, not the same.\nC Incorrect because the lower the quality of the issuer, the higher the market liquidity risk. In this case the investment grade borrower has less market liquidity risk, not more."},
  {"num": 88, "subject": "固定收益", "question": "For a bond investment, loss severity is:", "options": {"A": "independent of the recovery rate.", "B": "used in the calculation of the expected loss.", "C": "the primary focus when assessing the creditworthiness of high-quality issuers."}, "answer": "C", "explanation": "A Incorrect because the yield-to-maturity on a corporate bond consists of a government benchmark yield and a spread, a change in the bond’s yield-to-maturity can originate in either component or a combination of the two. The key point is that for an option-free fixed-rate bond, the same duration and convexity statistics that apply for a change in benchmark yield also apply for a change in spread.\nB Incorrect because the yield-to-maturity on a corporate bond consists of a government benchmark yield and a spread, a change in the bond’s yield-to-maturity can originate in either component or a combination of the two. The key point is that for an option-free fixed-rate bond, the same duration and convexity statistics that apply for a change in benchmark yield also apply for a change in spread.\nC Correct because the key point is that for an option-free fixed-rate bond, the same duration and convexity statistics that apply for a change in benchmark yield also apply for a change in spread."},
  {"num": 89, "subject": "固定收益", "question": "All else being equal, an investment-grade bond issuer most likely has:", "options": {"A": "less market liquidity risk than a below-investment-grade issuer.", "B": "the same market liquidity risk as a below-investment-grade issuer.", "C": "greater market liquidity risk than a below-investment-grade issuer."}, "answer": "B", "explanation": "A Incorrect because yield spreads widen based on two primary factors: (1) a decline in an issuer’s creditworthiness, sometimes referred to as credit migration or downgrade risk, and (2) an increase in market liquidity risk.\nB Correct because in periods of high demand for bonds, spreads will move tighter.\nC Incorrect because yield spreads widen based on two primary factors: (1) a decline in an issuer’s creditworthiness, sometimes referred to as credit migration or downgrade risk, and (2) an increase in market liquidity risk. Most markets bonds trade primarily over the counter, through broker-dealers trading for their own accounts. Their ability and willingness to make markets, as reflected in the bid-ask spread, is an important determinant of market liquidity risk."},
  {"num": 90, "subject": "固定收益", "question": "For an option-free fixed-rate corporate bond, the duration and convexity statistics are most likely relevant for a change in:", "options": {"A": "the credit spread only.", "B": "the benchmark yield only.", "C": "both the credit spread and the benchmark yield."}, "answer": "B", "explanation": "A Incorrect because Expected loss = Default probability × (1 – Recovery rate). Since expected loss is affected by changes in the recovery rate, it is not independent of the recovery rate.\nB Correct because Expected loss = Default probability × Loss severity given default, where loss severity is often expressed as (1 – Recovery rate), where the recovery rate is the percentage of the principal amount recovered in the event of default. Thus expected loss can also be written as Expected loss = Default probability × (1 – Recovery rate), which means that the higher the recovery rate, the lower the expected loss.\nC Incorrect because the relationship Expected loss = Default probability × (1 – Recovery rate) implies that expected loss increases when the recovery rate decreases and vice versa, hence it does not change proportionally to the recovery rate."},
  {"num": 91, "subject": "固定收益", "question": "Tightening corporate bond yield spreads are most likely associated with:", "options": {"A": "issuers’ deteriorating creditworthiness.", "B": "periods of high demand for corporate bonds.", "C": "broker-dealers' reduced ability and willingness to make markets."}, "answer": "C", "explanation": "A Incorrect because per capita income is a concern for sovereign bonds or general obligation bonds, not non-sovereign government revenue bonds. Income per capita: More prosperous countries generally have a broader and deeper tax base with which to support debt. The economic analysis of non-sovereign government GO bonds, including US municipal bonds, focuses on employment, per capita income (and changes in it over time), per capita debt (and changes in it over time), the tax base (depth, breadth, diversification, stability, etc.).\nB Incorrect because the tax base is a concern for sovereign bonds or general obligation bonds. Income per capita: More prosperous countries generally have a broader and deeper tax base with which to support debt. The economic analysis of non-sovereign government GO bonds, including US municipal bonds, focuses on employment, per capita income (and changes in it over time), per capita debt (and changes in it over time), the tax base (depth, breadth, diversification, stability, etc.).\nC Correct because revenue bonds are issued for specific project financing (e.g., financing for a new sewer system, a toll road, bridge, hospital, a sports arena, etc.). Revenue bonds, which are issued to finance a specific project, have a higher degree of risk than GO bonds because they are dependent on a single source of revenue. A key credit measure for revenue-backed non-sovereign government bonds is the debt-service-coverage (DSC) ratio, which measures how much revenue is available to cover debt payments (principal and interest) after operating expenses."},
  {"num": 92, "subject": "固定收益", "question": "All else being equal, expected loss for a debt instrument:", "options": {"A": "is independent of the recovery rate.", "B": "decreases as the recovery rate increases.", "C": "changes proportionally to the recovery rate."}, "answer": "B", "explanation": "A Incorrect because recognizing these different payment priorities, and thus the potential for higher (or lower) loss severity in the event of default, the rating agencies have adopted a notching process whereby their credit ratings on issues can be moved up or down from the issuer rating, which is usually the rating applied to its senior unsecured debt. Issue ratings are thus notched up or down from the issuer rating, and not from more junior ratings such as junior subordinated ratings.\nB Correct because the rating agencies have adopted a notching process whereby their credit ratings on issues can be moved up or down from the issuer rating, which is usually the rating applied to its senior unsecured debt. As a general rule, the higher the senior unsecured rating, the smaller the notching adjustment.\nC Incorrect because recognizing these different payment priorities, and thus the potential for higher (or lower) loss severity in the event of default, the rating agencies have adopted a notching process whereby their credit ratings on issues can be moved up or down from the issuer rating and also cross-default provisions, whereby events of default (such as non-payment of interest) on one bond trigger default on all outstanding debt, imply the same default probability for all issues, specific issues may be assigned different credit ratings—higher or lower—due to a rating adjustment methodology known as notching. It is the higher loss severity, and not higher probability of default, that is driving the notching process."},
  {"num": 93, "subject": "固定收益", "question": "Which of the following is most likely a key factor in the credit analysis of revenue-backed non-sovereign government bonds?", "options": {"A": "Per capita income.", "B": "Breadth of the tax base.", "C": "Debt-service-coverage ratio of the project."}, "answer": "B", "explanation": "A Incorrect because EBITDA/interest is a coverage ratio, not a leverage ratio. There are a few measures of leverage used by credit analysts. The most common are the debt/capital, debt/EBITDA, and measures of funds or cash flows/debt ratios.\nB Correct because coverage ratios measure an issuer's ability to meet—to “cover”—its interest payments. The two most common are the EBITDA/interest expense and EBIT/interest expense ratios.\nC Incorrect because while there are several measures of cash flow and profitability used in credit analysis, EBITDA/interest is not a measure of profitability. EBITDA is a commonly used measure of cash flow that takes operating income and adds back depreciation and amortization expense because those are noncash items."},
  {"num": 94, "subject": "固定收益", "question": "With respect to the notching process adopted by credit rating agencies, a corporate's subordinated debt is most likely:", "options": {"A": "notched up from the corporate's junior subordinated debt.", "B": "subject to a smaller notching adjustment the higher the corporate's issuer rating.", "C": "notched down from the corporate's issuer rating due to higher probability of default."}, "answer": "B", "explanation": "A Incorrect because as noted in the rationale for the correct answer, the issuer credit rating usually applies to senior unsecured debt.\nB Correct because the issuer credit rating usually applies to its senior unsecured debt.\nC Incorrect because as noted in the rationale for the correct answer, the issuer credit rating usually applies to senior unsecured debt."},
  {"num": 95, "subject": "固定收益", "question": "The EBITDA/interest expense ratio is best classified as a:", "options": {"A": "leverage ratio.", "B": "coverage ratio.", "C": "profitability ratio."}, "answer": "B", "explanation": "A Incorrect because this is net income plus depreciation & amortization divided by interest expense. Interest coverage ≠ (85 + 15) / 15 = $100/15 = 6.7, rounded to 7.\nB Correct because operating income is defined as operating revenues minus operating expenses and is commonly referred to as 'earnings before interest and taxes' (EBIT). Interest coverage using EBIT is operating income/interest expense. = $120/15 = 8.\nC Incorrect because this is interest coverage using EBIT plus depreciation & amortization (EBITDA. not EBIT) divided by interest expense."},
  {"num": 96, "subject": "固定收益", "question": "A bond issuer has a credit rating of BBB. Based only on this information, the rating of a senior unsecured bond from this issuer is most likely to be:", "options": {"A": "lower than BBB.", "B": "BBB.", "C": "higher than BBB."}, "answer": "B", "explanation": "A Incorrect because all creditors at the same level of the capital structure are treated as one class; thus, a senior unsecured bondholder whose debt is due in 30 years has the same pro rata claim in bankruptcy as one whose debt matures in six months. This provision is referred to as bonds ranking pari passu ('on an equal footing') in right of payment.\nB Correct because both bonds represent forms of senior unsecured debt and therefore, all creditors are at the same level of the capital structure and treated as one class; thus, a senior unsecured bondholder whose debt is due in 30 years has the same pro rata claim in bankruptcy as one whose debt matures in six months. This provision is referred to as bonds ranking pari passu ('on an equal footing') in right of payment.\nC Incorrect because all creditors at the same level of the capital structure are treated as one class; thus, a senior unsecured bondholder whose debt is due in 30 years has the same pro rata claim in bankruptcy as one whose debt matures in six months. This provision is referred to as bonds ranking pari passu ('on an equal footing') in right of payment."},
  {"num": 97, "subject": "固定收益", "question": "An analyst gathers the following information about a company (in $ millions):\nInterest coverage using EBIT is closest to:", "options": {"A": "7x.", "B": "8x.", "C": "9x."}, "answer": "A", "explanation": "A Correct because this is a secured debt and therefore has higher priority than any unsecured debt. In the event of default, unsecured debtholders’ claims rank below (i.e., get paid after) those of secured creditors under what’s known as the priority of claims. First lien debt or loan refers to a pledge of certain assets that could include buildings but might also include property and equipment, licenses, patents, brands, and so on. There can also be second lien, or even third lien, secured debt, which, as the name implies, has a secured interest in the pledged assets but ranks below first lien debt in both collateral protection and priority of payment.\nB Incorrect because within unsecured debt, there can also be finer gradations and seniority rankings. The highest-ranked unsecured debt is senior unsecured debt. It is the most common type of all corporate bonds outstanding. Other, lower-ranked debt includes subordinated debt and junior subordinated debt. Among the various creditor classes, these obligations have among the lowest priority of claims and frequently have little or no recovery in the event of default.\nC Incorrect because in the event of default, unsecured debtholders’ claims rank below (i.e., get paid after) those of secured creditors under what’s known as the priority of claims. Within unsecured debt, there can also be finer gradations and seniority rankings. The highest-ranked unsecured debt is senior unsecured debt."},
  {"num": 98, "subject": "固定收益", "question": "An analyst gathers the following information about a company that only has senior unsecured debt:\nIn a bankruptcy scenario, if the priority of claims is enforced, it is most likely that:", "options": {"A": "fixed-rate bond is repaid first because it matures earlier.", "B": "both bondholders are repaid proportionally to the amount owed.", "C": "FRN is repaid first because it has the highest amount outstanding."}, "answer": "C", "explanation": "A Incorrect because a corporate family rating is meant to address an obligor’s overall creditworthiness, whereas issue ratings refer to specific financial obligation of an issuer and take into consideration such factors as ranking in the capital structure (e.g., secured or subordinated). Hence, the priority of claims in a bankruptcy is reflected in an issue rating and not in a corporate family rating.\nB Incorrect because corporate credit ratings or issue ratings (not corporate family ratings) refer to specific financial obligations of an issuer.\nC Correct because corporate family ratings or issuer ratings will address an obligor’s overall creditworthiness – its ability to and willingness to make timely payments of interest and principal on its debt. The issuer credit rating usually applies to its senior unsecured debt."},
  {"num": 99, "subject": "固定收益", "question": "Which of the following debt categories has the highest ranking in terms of priority of payment?", "options": {"A": "Second lien debt.", "B": "Subordinated debt.", "C": "Senior unsecured debt."}, "answer": "C", "explanation": "A Incorrect because the issuer credit rating usually applies to senior unsecured debt, not subordinated debt or senior secured debt.\nB Incorrect because the issuer credit rating usually applies to senior unsecured debt, not subordinated debt or senior secured debt.\nC Correct because an issuer credit rating is meant to address an obligor's overall creditworthiness – its ability and willingness to make timely payments of interest and principal on its debt. The issuer credit rating usually applies to its senior unsecured debt."},
  {"num": 100, "subject": "固定收益", "question": "A corporate family rating most likely:", "options": {"A": "reflects the priority of claims in a bankruptcy.", "B": "refers to specific financial obligations of an issuer.", "C": "is assigned to a company based on its overall creditworthiness."}, "answer": "B", "explanation": "A Incorrect because this is part of the prospectus. Another important legal document is the prospectus, which describes the structure of the securitization.\nB Correct because an important legal document is the purchase agreement between the seller of the collateral and the SPE, which sets forth the representations and warranties that the seller makes about the assets sold. These representations and warranties assure investors about the quality of the assets.\nC Incorrect because this is part of the prospectus. Securitizations often use several forms of credit enhancements, which are documented in the prospectus."},
  {"num": 101, "subject": "固定收益", "question": "An issuer's credit rating most likely applies to its:", "options": {"A": "subordinated debt.", "B": "senior secured debt.", "C": "senior unsecured debt."}, "answer": "C", "explanation": "A Incorrect because the seller of the collateral, sometimes called the depositor is the corporation that originated the loans. They are sold to an SPE and held by the trustee.\nB Incorrect because the SPE purchases the loans or receivables and uses them as collateral to issue the ABS. After the sale is completed, it is the SPE, not the depositor/seller, that legally owns them. The SPE owns the collateral but does not hold the collateral, and although the trustee does not own the underlying collateral it does hold it.\nC Correct because a trustee or trustee agent is typically a financial institution with trust powers that safeguards the assets after they have been sold to the SPE, holds the funds due to the ABS holders until they are paid, and provides periodic information to the ABS holders."},
  {"num": 102, "subject": "固定收益", "question": "In a securitization, the purchase agreement between the seller of the collateral and the special purpose entity most likely provides:", "options": {"A": "a description of the transaction structure.", "B": "representations about the quality of the assets.", "C": "documentation of enhancements used to reduce credit risk."}, "answer": "A", "explanation": "A Correct because collateralized debt obligation (CDO) is a generic term used to describe a security backed by a diversified pool of one or more debt obligations: CDOs backed by ABS, RMBS, CMBS, and other CDOs are structured finance CDOs.\nB Incorrect because collateralized debt obligation (CDO) is a generic term used to describe a security backed by a diversified pool of one or more debt obligations: CDOs backed by leveraged bank loans are collateralized loan obligations (CLOs).\nC Incorrect because collateralized debt obligation (CDO) is a generic term used to describe a security backed by a diversified pool of one or more debt obligations: CDOs backed by corporate and emerging market bonds are collateralized bond obligations (CBOs)."},
  {"num": 103, "subject": "固定收益", "question": "In the securitization process, the trustee most likely:", "options": {"A": "sells the underlying collateral.", "B": "owns the underlying collateral.", "C": "holds the underlying collateral."}, "answer": "C", "explanation": "A Incorrect because in contrast [to asset-backed securities], in the case of covered bonds, the pool of assets remains on the financial institution's balance sheet. In the event of default, bondholders have recourse against both the financial institution and the cover pool.\nB Incorrect because in contrast [to asset-backed securities], in the case of covered bonds, the pool of assets remains on the financial institution's balance sheet. In the event of default, bondholders have recourse against both the financial institution and the cover pool.\nC Correct because a covered bond is a debt obligation backed by a segregated pool of assets called a “cover pool” In the event of default, bondholders have recourse against both the financial institution and the cover pool."},
  {"num": 104, "subject": "固定收益", "question": "Which of the following types of collateralized debt obligations (CDOs) are most likely backed by asset-backed securities?", "options": {"A": "Structured finance CDOs.", "B": "Collateralized loan obligations.", "C": "Collateralized bond obligations."}, "answer": "C", "explanation": "A Incorrect because a non-amortizing loan does not involve scheduled principal repayments, an ABS backed by non-amortizing loans is not affected by prepayment risk. Credit card receivable ABS are an example of ABS backed by non-amortizing loans.\nB Incorrect because a non-amortizing loan does not involve scheduled principal repayments, an ABS backed by non-amortizing loans is not affected by prepayment risk. Credit card receivable ABS are an example of ABS backed by non-amortizing loans.\nC Correct because the collateral of credit card receivable ABS is a pool of non-amortizing loans. These loans have lockout periods during which the cash flows that are paid out to security holders are based only on finance charges collected and fees. When the lockout period is over, the principal that is repaid by the cardholders is no longer reinvested but instead is distributed to investors."},
  {"num": 105, "subject": "固定收益", "question": "In the event of default, investors in covered bonds most likely have recourse against:", "options": {"A": "the issuer only.", "B": "a segregated pool of assets only.", "C": "both the issuer and a segregated pool of assets."}, "answer": "B", "explanation": "A Incorrect because the creation of bond classes that possess different expected maturities is referred to as time tranching. Subordination is a form of credit tranching, not time tranching.\nB Correct because it is common for securitizations to include a form of internal credit enhancement called subordination, also referred to as credit tranching. In such a structure, there is more than one bond class or tranche, and the bond classes differ as to how they will share any losses resulting from defaults of the borrowers whose loans are in the collateral. The bond classes are classified as senior bond classes or subordinated bond classes—hence, the reason this structure is also referred to as a senior/subordinated structure.\nC Incorrect because prepayment risk is the uncertainty that the cash flows will be different from the scheduled cash flows as set forth in the loan agreement because of the borrowers' ability to alter payments. This risk is related to time tranching, not credit tranching."},
  {"num": 106, "subject": "固定收益", "question": "A credit card receivable asset-backed security most likely:", "options": {"A": "faces high prepayment risk.", "B": "uses fully-amortizing loans as collateral.", "C": "reinvests principal repayments during the lockout period."}, "answer": "C", "explanation": "A Incorrect because for a non-recourse mortgage, the borrower may have an incentive to default on an underwater mortgage and allow the lender to foreclose on the property, even if resources are available to continue to make mortgage payments. This type of default by a borrower is referred to as a “strategic default.” Therefore, the risk of a strategic default is higher (not lower) for a non-recourse mortgage.\nB Incorrect because for a non-recourse mortgage, the borrower may have an incentive to default on an underwater mortgage and allow the lender to foreclose on the property, even if resources are available to continue to make mortgage payments. This type of default by a borrower is referred to as a “strategic default.” Therefore, the risk of a strategic default is higher (not the same) for a non-recourse mortgage.\nC Correct because for a non-recourse mortgage, the borrower may have an incentive to default on an underwater mortgage and allow the lender to foreclose on the property, even if resources are available to continue to make mortgage payments. This type of default by a borrower is referred to as a “strategic default\". In countries where residential mortgages are recourse loans, a strategic default is less likely because the lender can seek to recover the shortfall from the borrower's other assets and/or income. Therefore, the risk of a strategic default is higher for a non-recourse mortgage."},
  {"num": 107, "subject": "固定收益", "question": "In a securitization, a senior/subordinated structure is most likely a form of:", "options": {"A": "time tranching.", "B": "credit tranching.", "C": "prepayment risk management."}, "answer": "C", "explanation": "A Incorrect because in a recourse loan, the lender has a claim against the borrower for the shortfall between the amount of the outstanding mortgage balance and the proceeds received from the sale of the property. In a non-recourse loan, the lender does not have such a claim and thus can look only to the property to recover the outstanding mortgage balance.\nB Incorrect because a mortgage may entitle the borrower to prepay all or part of the outstanding mortgage principal prior to the scheduled due date when the principal must be repaid. This contractual provision is referred to as a prepayment option or an early repayment option. From the lender’s or investor’s viewpoint, the effect of a prepayment option is that the amount and timing of the cash flows from a mortgage cannot be known with certainty. The prepayment option benefits the borrower rather than the lender.\nC Correct because the purpose of the prepayment penalty is to compensate the lender for the difference between the contract rate and the prevailing mortgage rate if the borrower prepays when interest rates decline."},
  {"num": 108, "subject": "固定收益", "question": "All else being equal, the risk of a strategic default for a non-recourse mortgage is most likely:", "options": {"A": "lower than for a recourse mortgage.", "B": "the same as for a recourse mortgage.", "C": "greater than for a recourse mortgage."}, "answer": "A", "explanation": "A Correct because extension risk is the risk that when interest rates rise, prepayments will be lower than forecasted because homeowners are reluctant to give up the benefits of a contractual interest rate that now looks low. As a result, a security backed by mortgages will typically have a longer maturity than was anticipated at the time of purchase.\nB Incorrect because contraction risk is the risk that when interest rates decline, actual prepayments will be higher than forecasted because homeowners will refinance at now-available lower interest rates. Thus, a security backed by mortgages will have a shorter maturity than was anticipated at the time of purchase. Holding a security whose maturity becomes shorter when interest rates decline has two adverse consequences for investors. First, investors must reinvest the proceeds at lower interest rates. Second, if the security is prepayable or callable, its price appreciation is not as great as that of an otherwise identical bond that does not have a prepayment or call option. Increased contraction risk occurs when interest rates decline, not increase.\nC Incorrect because contraction risk is the risk that when interest rates decline, actual prepayments will be higher than forecasted because homeowners will refinance at now-available lower interest rates. First, investors must reinvest the proceeds at lower interest rates. When interest rates decline, as opposed to increase, prepayments are likely to increase and be reinvested at lower rates, thus increasing reinvestment risk. This is not likely to occur when interest rates rise."},
  {"num": 109, "subject": "固定收益", "question": "Which of the following mortgage features most likely benefits the lender?", "options": {"A": "Non-recourse loan.", "B": "Prepayment option.", "C": "Prepayment penalty."}, "answer": "A", "explanation": "A Correct because a mortgage pass-through security’s coupon rate is called the pass- through rate. The pass-through rate is lower than the mortgage rate on the underlying pool of mortgages by an amount equal to the servicing and other administrative fees. The pass-through rate that the investor receives is said to be 'net interest' or 'net coupon'.\nB Incorrect because not all of the mortgages that are included in a pool of securitized mortgages have the same mortgage rate and the same maturity. The WAC is calculated by weighting the mortgage rate of each mortgage in the pool by the percentage of the outstanding mortgage balance relative to the outstanding amount of all the mortgages in the pool. This rate, less servicing and other administrative fees, determines the pass-through rate.\nC Incorrect because a mortgage pass-through security’s coupon rate is called the pass- through rate. The pass-through rate is lower than the mortgage rate on the underlying pool of mortgages by an amount equal to the servicing and other administrative fees. The pass-through rate that the investor receives is said to be ‘net interest’ or ‘net coupon'."},
  {"num": 110, "subject": "固定收益", "question": "When interest rates increase, mortgage-backed securities most likely exhibit increased:", "options": {"A": "extension risk.", "B": "contraction risk.", "C": "reinvestment risk."}, "answer": "B", "explanation": "A Incorrect because this relates to credit tranching, not time tranching. In credit tranching, there is more than one bond class or tranche, and the share classes differ as to how they will share losses resulting from defaults of the borrowers whose loans are in the collateral.\nB Correct because the creation of bond classes that possess different expected maturities is referred to as time tranching.\nC Incorrect because tranching does not change underlying collateral, rather it only changes how losses or prepayments will be shared. In such a structure, there is more than one bond class or tranche, and the share classes differ as to how they will share losses resulting from defaults of the borrowers whose loans are in the collateral."},
  {"num": 111, "subject": "固定收益", "question": "The coupon of a residential mortgage-backed security is the:", "options": {"A": "pass-through rate.", "B": "weighted average coupon rate.", "C": "rate on the underlying pool of mortgages."}, "answer": "A", "explanation": "A is correct . The notes mature (the date Antelas AG will pay the final coupon and principal amount) four years after the trade settlement date, and the coupon rate is variable, determined by the MRR plus a fixed 250 bp spread."},
  {"num": 112, "subject": "固定收益", "question": "In a securitization, time tranching most likely refers to differences in:", "options": {"A": "default risk.", "B": "expected maturities.", "C": "underlying collateral."}, "answer": "C", "explanation": "C is correct . Secured corporate bonds rely on the operating cash flows of the firm as their primary source for interest and principal payments and a legal claim on assets as a secondary source of payment.\nA is incorrect because asset-backed securities (ABS) are issued by special-purpose entities created to take ownership in loans or receivables, the cash flows from which are used to pay interest and principal to investors.\nB is incorrect because it describes unsecured, not secured, corporate debt."},
  {"num": 1, "subject": "经济学", "question": "Firms operating under a monopolistic competition market structure most likely:", "options": {"A": "have few competitors.", "B": "benefit from high barriers to entry.", "C": "sell products that are close substitutes for those offered by other firms."}, "answer": "C", "explanation": "A Incorrect because under monopolistic competition, there are a large number of potential buyers and sellers.\nB Incorrect because under monopolistic competition, entry into and exit from the market are possible with fairly low costs. Furthermore, barriers to entry in a monopolistic competition market structure are low.\nC Correct because under monopolistic competition, the products offered by each seller are close substitutes for the products offered by other firms, and each firm tries to make its product look different."},
  {"num": 2, "subject": "经济学", "question": "A market structure characterized by homogeneous/standardized product differentiation is best described as:", "options": {"A": "monopoly.", "B": "monopolistic competition.", "C": "perfect competition and oligopoly."}, "answer": "C", "explanation": "A Incorrect because a monopoly does not have a standardized product.\nB Incorrect because monopolistic competition does not have a standardized product.\nC Correct . Perfect competition and oligopoly are characterized by homogeneous/standardized product differentiation."},
  {"num": 3, "subject": "经济学", "question": "Which of the following statements about a downward-sloping long-run average cost (LRAC) curve is most accurate? A downward-sloping LRAC curve is representative of a firm experiencing:", "options": {"A": "economies of scale.", "B": "diseconomies of scale.", "C": "decreasing levels of investment."}, "answer": "A", "explanation": "A Correct . When the LRAC curve is downward sloping, it means the firm is producing units at lower average costs per unit as production levels rise. This situation represents economies of scale in production.\nB Incorrect . An upward-sloping LRAC curve would be representative of diseconomies of scale.\nC Incorrect . Decreasing levels of investment alone would not result in a downward-sloping LRAC curve; it would also depend on the volume of production. If the level of production drops proportionately more than the level of investment, the LRAC curve could be upward sloping."},
  {"num": 4, "subject": "经济学", "question": "In a perfectly competitive market, a firm's breakeven point is the minimum point of the:", "options": {"A": "average total cost curve.", "B": "average fixed cost curve.", "C": "average variable cost curve."}, "answer": "A", "explanation": "A Correct because economists refer to the minimum AVC point as the shutdown point and the minimum ATC point as the breakeven point.\nB Incorrect because economists refer to the minimum AVC point as the shutdown point and the minimum ATC point as the breakeven point. The AFC curve does not have a minimum point because it decreases throughout the production span, reflecting the spreading of a constant cost over more and more production units.\nC Incorrect because economists refer to the minimum AVC point as the shutdown point and the minimum ATC point as the breakeven point."},
  {"num": 5, "subject": "经济学", "question": "In the long run, a monopolistically competitive firm:", "options": {"A": "earns positive economic profits.", "B": "faces a perfectly elastic demand curve.", "C": "produces at a higher level of average cost than the minimum average cost."}, "answer": "C", "explanation": "A Incorrect because in the hybrid market of monopolistic competition, zero economic profit in long-run equilibrium resembles perfect competition.\nB Incorrect because each good sold in the product group is somewhat different from the others, the demand curve for each firm in the monopolistic competition market structure is downward sloping to the right. Price and the quantity demanded are negatively related. If the environment of the firm is perfectly competitive, it must take the market price of its output as given, so it faces a perfectly elastic, horizontal demand curve.\nC Correct because in the hybrid market of monopolistic competition, zero economic profit in long-run equilibrium resembles perfect competition. However, the long-run level of output, Q1, is less than Q2, which corresponds to the minimum average cost of production and would be the long-run level of output in a perfectly competitive market."},
  {"num": 6, "subject": "经济学", "question": "In an oligopoly market, which of the following best describes the situation when firms have no incentive to deviate from their current pricing strategy based on the anticipated choices of competitors?", "options": {"A": "The Nash equilibrium.", "B": "The Stackelberg model.", "C": "Pricing interdependence."}, "answer": "A", "explanation": "A Correct because the Nash equilibrium is present when two or more participants in a non- cooperative game have no incentive to deviate from their respective equilibrium strategies after they have considered and anticipated their opponent’s rational choices or strategies.\nB Incorrect because in the Stackelberg model the leader firm chooses its output first and then the follower firm chooses after observing the leader's output, indicating followers see an incentive to adjust their strategies based on the observed choices of leaders.\nC Incorrect because if there is pricing interdependence competitors will match a price reduction and ignore a price increase, indicating competitors believe they have an incentive to adjust their strategy based on observed competitor choices."},
  {"num": 7, "subject": "经济学", "question": "In which of the following market structures does marginal revenue equal price?", "options": {"A": "Oligopoly.", "B": "Monopoly.", "C": "Perfect competition."}, "answer": "C", "explanation": "A Incorrect because only in perfect competition does the marginal revenue equal price. In the remaining structures, price generally exceeds marginal revenue because a firm can sell more units only by reducing the per unit price.\nB Incorrect because only in perfect competition does the marginal revenue equal price. In the remaining structures, price generally exceeds marginal revenue because a firm can sell more units only by reducing the per unit price.\nC Correct because only in perfect competition does the marginal revenue equal price. In the remaining structures, price generally exceeds marginal revenue because a firm can sell more units only by reducing the per unit price."},
  {"num": 8, "subject": "经济学", "question": "The perfectly competitive firm's supply curve is its long-run:", "options": {"A": "marginal cost schedule.", "B": "average revenue schedule.", "C": "average total cost schedule."}, "answer": "A", "explanation": "A Correct because the long-run marginal cost schedule is the perfectly competitive firm's supply curve.\nB Incorrect because the firm's demand schedule is the same as the firm's marginal revenue and average revenue.\nC Incorrect because the long-run marginal cost schedule (not the average total cost schedule) is the perfectly competitive firm's supply curve."},
  {"num": 9, "subject": "经济学", "question": "To calculate the Herfindahl–Hirschman index:", "options": {"A": "add the market shares of the largest firms.", "B": "add the market shares of the largest firms and then square the sum.", "C": "square the market shares of the largest firms and then add the results."}, "answer": "C", "explanation": "A Incorrect because adding the firms' market shares would calculate the concentration ratio, not the HHI.\nB Incorrect because to avoid the known issues with concentration ratios, economists O.C. Herfindahl and A.O. Hirschman suggested an index where the market shares of the top N companies are first squared and then added.\nC Correct because to avoid the known issues with concentration ratios, economists O.C. Herfindahl and A.O. Hirschman suggested an index where the market shares of the top N companies are first squared and then added."},
  {"num": 10, "subject": "经济学", "question": "An analyst gathers the following information about three markets:\nWhich market is most likely an oligopoly?", "options": {"A": "Market 1.", "B": "Market 2.", "C": "Market 3."}, "answer": "B", "explanation": "A Incorrect because in an oligopoly market there are a small (not large) number of potential sellers and products are often highly differentiated through marketing, features, and other non-price strategies. Market 1 resembles the characteristics of perfect competition.\nB Correct because in an oligopoly market there are a small number of potential sellers and products are often highly differentiated through marketing, features, and other non-price strategies.\nC Incorrect because in an oligopoly market there are a small (not large) number of potential sellers and products are often highly differentiated through marketing, features, and other non-price strategies. Market 3 resembles the characteristics of monopolistic competition."},
  {"num": 11, "subject": "经济学", "question": "Monopolistic competition is best characterized by:", "options": {"A": "high barriers to entry and exit.", "B": "a small number of buyers and sellers.", "C": "product differentiation through non-price strategies."}, "answer": "C", "explanation": "A Incorrect because for a monopolistically competitive firm: entry into and exit from the market are possible with fairly low costs.\nB Incorrect because for a monopolistically competitive firm: there are a large number of potential buyers and sellers.\nC Correct because for a monopolistically competitive firm: suppliers differentiate their products through advertising and other non-price strategies."},
  {"num": 12, "subject": "经济学", "question": "If a perfectly competitive industry becomes monopolistically competitive, each firm's long-run average total cost per unit sold will most likely:", "options": {"A": "decrease.", "B": "remain the same.", "C": "increase."}, "answer": "C", "explanation": "A Incorrect because under monopolistic competition each firm does not produce the efficient quantity, whereas under perfect competition each firm does produce the efficient quantity. Therefore, average total cost is minimized under perfect competition.\nB Incorrect because under monopolistic competition each firm does not produce the efficient quantity, whereas under perfect competition each firm does produce the efficient quantity. Therefore, average total cost is minimized under perfect competition.\nC Correct because unlike long-run equilibrium in perfect competition, in the market of monopolistic competition, the equilibrium position is at a higher level of average cost than the level of output that minimizes average cost. Average cost does not reach its minimum until output level Q2 is achieved. Under perfect competition a product is produced at the efficient quantity (marginal revenue equals marginal cost) and average total cost is minimized. The demand faced by each firm is perfectly elastic (horizontal demand curve). However, under monopolistic competition the demand curve is downward sloping and the quantity produced (marginal revenue equals marginal cost) is not where average total cost is minimized. Thus, average total cost is lower under perfect competition."},
  {"num": 13, "subject": "经济学", "question": "If a monopolistically competitive industry becomes perfectly competitive, each firm's long-run average total cost per unit sold will most likely:", "options": {"A": "decrease.", "B": "remain the same.", "C": "increase."}, "answer": "A", "explanation": "A Correct because under perfect competition a product is produced at the efficient quantity (marginal revenue equals marginal cost) and the average total cost is minimized. The demand curve faced by each firm is perfectly elastic (horizontal demand curve). However, under monopolistic competition the demand curve is downward sloping and the quantity produced (marginal revenue equals marginal cost) is not where average total cost is minimized. Thus, average total cost is lower under perfect competition.\nB Incorrect because under monopolistic competition each firm does not produce the efficient quantity, whereas in perfect competition, each firm does produce the efficient quantity. Since production occurs at the efficient level in perfect competition, average total cost is minimized.\nC Incorrect because under monopolistic competition each firm does not produce the efficient quantity, whereas in perfect competition, each firm does produce the efficient quantity. Since production occurs at the efficient level in perfect competition, average total cost is minimized."},
  {"num": 14, "subject": "经济学", "question": "In the short run, the shutdown point of a company with a total variable cost of $3 million and a total fixed cost of $5 million is when total revenue declines to:", "options": {"A": "$3 million.", "B": "$5 million.", "C": "$8 million."}, "answer": "A", "explanation": "A Correct because as long as the firm’s revenues cover at least its variable cost, the firm is better off continuing to operate. If price is greater than average variable cost (AVC), the firm is covering not only all of its variable cost but also a portion of fixed cost. Also, average revenue (AR) is revenue per unit.\nB Incorrect because in the short run the company will shut down production when total revenue is less than total variable cost of $3 million, not total fixed cost of $5 million.\nC Incorrect because in the short run the company will shut down production when total revenue is less than total variable costs of $3 million, not less than total cost of $8 million."},
  {"num": 15, "subject": "经济学", "question": "Which of the following is most likely a lagging economic indicator?", "options": {"A": "Inventory-sales ratio.", "B": "S&P 500 Stock Index.", "C": "Manufacturers' new orders for consumer goods and materials."}, "answer": "A", "explanation": "A Correct because inventories accumulate as sales initially decline and then, once a business adjusts its ordering, become depleted as sales pick up, so this ratio tends to lag the cycle.\nB Incorrect because this is a leading economic indicator. Stock prices anticipate economic turning points, both up and down, so their movements offer a useful early signal on economic cycles.\nC Incorrect because this is a leading economic indicator. Businesses cannot wait too long to meet demands for consumer goods or materials without ordering, so these gauges tend to lead at upturns and downturns. Indirectly, they capture changes in business sentiment as well, which also often leads the cycle."},
  {"num": 16, "subject": "经济学", "question": "During the recovery phase of the business cycle, inflation most likely:", "options": {"A": "decelerates but with a lag.", "B": "remains moderate.", "C": "further accelerates."}, "answer": "B", "explanation": "A Incorrect because, in the “recovery” phase, inflation remains moderate and in the “contraction” phase inflation decelerates but with a lag.\nB Correct because, in the “recovery” phase, inflation remains moderate.\nC Incorrect because, in the “recovery” phase, inflation remains moderate and in the “slowdown” phase inflation further accelerates."},
  {"num": 17, "subject": "经济学", "question": "Which of the following indexes is most likely considered a leading economic indicator?", "options": {"A": "Consumer price index.", "B": "Broad stock market index.", "C": "Industrial production index."}, "answer": "B", "explanation": "A Incorrect because the consumer price index is considered a lagging indicator: Inflation generally adjusts to the cycle late, especially the more stable services area.\nB Correct because as a leading economic indicator, a positive change in the S&P 500 Index is supposed to lead (come before) an increase in aggregate economic activity. An increase in the S&P 500 would be positive for future economic growth, all else equal. Additionally, the Euro Stoxx Equity Index is considered a leading indicator in the Eurozone.\nC Incorrect because this index measures industrial output, thus capturing the behavior of the most volatile part of the economy. This index is considered one of the 4 coincidental indicators in the United States as tracked by the Conference Board."},
  {"num": 18, "subject": "经济学", "question": "The interest rate spread between 10-year treasury yields and overnight borrowing rates most likely:", "options": {"A": "is a lagging economic indicator.", "B": "decreases when the market expects an economic downturn.", "C": "increases as the market expects future short-term interest rates to decrease."}, "answer": "B", "explanation": "A Incorrect because leading economic indicators have turning points that usually precede those of the overall economy. Lagging economic indicators have turning points that take place later than those of the overall economy. Interest rate spread between 10-year treasury yields and overnight borrowing rates is a leading economic indicator.\nB Correct because long-term yields express market expectations about the direction of short-term interest rates, and rates ultimately follow the economic cycle up and down, a wider spread, by anticipating short rate increases, also anticipates an economic upswing. Conversely, a narrower spread, by anticipating short rate decreases, also anticipates an economic downturn.\nC Incorrect because long-term yields express market expectations about the direction of short-term interest rates, and rates ultimately follow the economic cycle up and down, a wider spread, by anticipating short rate increases, also anticipates an economic upswing. Conversely, a narrower spread, by anticipating short rate decreases, also anticipates an economic downturn."},
  {"num": 19, "subject": "经济学", "question": "Which of the following is most likely a coincident indicator of economic activity?", "options": {"A": "Average duration of unemployment.", "B": "Average weekly hours, manufacturing.", "C": "Employees on non-agricultural payrolls."}, "answer": "C", "explanation": "A Incorrect because businesses wait until downturns look genuine to lay off, and wait until recoveries look secure to rehire, this measure is important because it lags the cycle on both the way down and the way up. Thus, average duration of unemployment is a lagging economic indicator.\nB Incorrect because businesses will cut overtime before laying off workers in a downturn and increase it before rehiring in a cyclical upturn, these measures move up and down before the general economy. Thus, average weekly hours, manufacturing is a leading economic indicator.\nC Correct because once recession or recovery is clear, businesses adjust their full-time payrolls. Non-agricultural payrolls and manufacturing and trade sales are coincident indicators."},
  {"num": 20, "subject": "经济学", "question": "The business cycle phase that is characterized by slowing growth in economic activity is the:", "options": {"A": "slowdown.", "B": "expansion.", "C": "contraction."}, "answer": "A", "explanation": "A Correct because in the slowdown phase, activity measures are above average but decelerating. Moving to below-average rates of growth.\nB Incorrect because in the expansion phase, the recovery gathers pace, output increases, and the rate of growth is above average.\nC Incorrect because in the contraction phase, economic output falls below potential economic output."},
  {"num": 21, "subject": "经济学", "question": "Which of the following changes most likely reflects a discretionary fiscal policy action?", "options": {"A": "A decrease in corporate tax revenues due to lower corporate profitability.", "B": "An increase in government expenditures due to new infrastructure projects.", "C": "An increase in payments of unemployment benefits due to increasing unemployment."}, "answer": "B", "explanation": "A Incorrect because the deficit can change for reasons unrelated to actual fiscal policy changes. Automatic stabilizers will lead to changes in the budget deficit unrelated to fiscal policy changes; a recession will cause tax revenues to fall and the budget deficit to rise.\nB Correct because in addition to these automatic adjustments, governments also use discretionary fiscal adjustments to influence aggregate demand. These will involve tax changes and/or spending cuts or increase usually with the aim of stabilizing the economy. An increase in government expenditures due to new infrastructure projects is a discretionary fiscal policy action because new public spending on social goods and infrastructure, such as hospitals and schools, boosting personal incomes with the objective of raising aggregate demand.\nC Incorrect because automatic stabilizers—such as income tax, VAT, and social benefits—are important because as output and employment fall and reduce tax revenues, so net tax revenues also fall as unemployment benefits rise. This acts as a fiscal stimulus and serves to reduce the size of the multiplier, dampening the output response of whatever caused the fall in output in the first place. By their very nature, automatic stabilizers do not require policy changes; no policymaker has to decide that an economic shock has occurred and how to respond."},
  {"num": 22, "subject": "经济学", "question": "With respect to fiscal policy, transfer payments are best described as:", "options": {"A": "welfare payments.", "B": "infrastructure spending.", "C": "spending on recurring goods and services."}, "answer": "A", "explanation": "A Correct because transfer payments are welfare payments made through the social security system, and, depending on the country, comprise payments for state pensions, housing benefits, tax credits and income support for poorer families, child benefits, unemployment benefits and job search allowances.\nB Incorrect because capital expenditure includes infrastructure spending on roads, hospitals, prisons, and schools, not transfer payments.\nC Incorrect because current government spending involves spending on goods and services that are provided on a regular, recurring basis—including health, education, and defense, not transfer payments."},
  {"num": 23, "subject": "经济学", "question": "A decline in tax revenues due to a recession is best described as an example of a(n):", "options": {"A": "automatic stabilizer.", "B": "expansionary fiscal policy.", "C": "contractionary fiscal policy."}, "answer": "A", "explanation": "A Correct because falling tax revenues due to a recession is an example of automatic stabilizer, not a discretionary fiscal policy. Automatic stabilizers will lead to changes in the budget deficit unrelated to fiscal policy changes; a recession will cause tax revenues to fall and the budget deficit to rise.\nB Incorrect because falling tax revenues due to a recession are an example of an automatic stabilizer. Automatic stabilizers will lead to changes in the budget deficit unrelated to fiscal policy changes; a recession will cause tax revenues to fall and the budget deficit to rise. An expansionary fiscal policy is discretionary in order to help manage the economy through its influence on aggregate national output, that is, real GDP. In a recession, governments can raise spending (expansionary fiscal policy) in an attempt to raise employment and output.\nC Incorrect because falling tax revenues due to a recession are an example of an automatic stabilizer. Automatic stabilizers will lead to changes in the budget deficit unrelated to fiscal policy changes; a recession will cause tax revenues to fall and the budget deficit to rise. A contractionary fiscal policy is discretionary in order to help manage the economy through its influence on aggregate national output, that is, real GDP. When an economy has full employment and wages and prices are rising too fast—then government spending may be reduced and taxes raised (contractionary fiscal policy)."},
  {"num": 24, "subject": "经济学", "question": "Which of the following is an expansionary fiscal policy?", "options": {"A": "An increase in sales taxes.", "B": "A decrease in interest rates.", "C": "An increase in public spending on infrastructure."}, "answer": "C", "explanation": "A Incorrect because expansionary (fiscal) policy could take the form of cuts in sales (indirect) taxes to lower prices which raises real incomes with the objective of raising consumer demand. Thus, an increase in sales taxes would be contractionary, not expansionary.\nB Incorrect because when the economy is slowing and inflation and monetary trends are weakening, central banks may increase liquidity by cutting their target (interest) rate. In these circumstances, monetary policy is said to be expansionary. Thus while expansionary, this is an example of monetary rather than fiscal policy.\nC Correct because there are a number of ways that fiscal policy can influence aggregate demand. Expansionary policy could take the form of new public spending on social goods and infrastructure."},
  {"num": 25, "subject": "经济学", "question": "Which of the following fiscal policy actions is most likely contractionary?", "options": {"A": "Increasing taxes and decreasing spending.", "B": "Decreasing taxes and increasing spending.", "C": "Decreasing taxes and decreasing spending."}, "answer": "A", "explanation": "A Correct because increasing taxes and decreasing spending are indicative of a contractionary fiscal policy. When an economy has full employment and wages and prices are rising too fast—then government spending may be reduced and taxes raised (contractionary fiscal policy).\nB Incorrect because decreasing taxes and increasing spending are indicative of a budget deficit, which is expansionary. An expansionary policy could take one or more of the following forms: cuts in sales (indirect) taxes to lower prices which raises real incomes with the objective of raising consumer demand, cuts in corporation (company) taxes to boost business profits, which may raise capital spending, and cuts in tax rates on personal savings to raise disposable income for those with savings, with the objective of raising consumer demand. Expansionary fiscal policy also includes new public spending on social goods and infrastructure, such as hospitals and schools, boosting personal incomes with the objective of raising aggregate demand. An increase in a budget surplus would be associated with contractionary fiscal policy, while a rise in a deficit is an expansionary fiscal policy.\nC Incorrect because a decrease in taxes is expansionary, while a decrease in spending is contractionary. Without knowing the relative magnitudes, we cannot say whether the policy is expansionary or contractionary. An expansionary policy could take one or more of the following forms: cuts in sales (indirect) taxes to lower prices which raises real incomes with the objective of raising consumer demand, cuts in corporation (company) taxes to boost business profits, which may raise capital spending, and cuts in tax rates on personal savings to raise disposable income for those with savings, with the objective of raising consumer demand. However, an increase (not decrease) in spending is expansionary. Expansionary fiscal policy also includes new public spending on social goods and infrastructure, such as hospitals and schools, boosting personal incomes with the objective of raising aggregate demand. An increase in a budget surplus would be associated with contractionary fiscal policy, while a rise in a deficit is an expansionary fiscal policy."},
  {"num": 26, "subject": "经济学", "question": "A fiscal policy tool that can immediately influence spending is most likely:", "options": {"A": "indirect taxes.", "B": "exchange rate targeting.", "C": "capital expenditure plans."}, "answer": "A", "explanation": "A Correct because indirect taxes can be adjusted almost immediately after they are announced and can influence spending behavior instantly and generate revenue for the government at little or no cost to the government.\nB Incorrect because exchange rate targeting is a monetary policy tool, not a fiscal policy tool. Many developing economies choose to operate monetary policy by targeting their currency's exchange rate.\nC Incorrect because capital spending plans take longer to formulate and implement, typically over a period of years. The slower the impact of a fiscal change, the more likely other exogenous changes will already be influencing the economy before the fiscal change kicks in."},
  {"num": 27, "subject": "经济学", "question": "An objective of fiscal policy is to:", "options": {"A": "maintain price stability.", "B": "redistribute the wealth within an economy.", "C": "influence the quantity of credit in an economy."}, "answer": "B", "explanation": "A Incorrect because fiscal policy refers to the government’s decisions about taxation and spending. It is for central banks that there is one overarching objective that most seem to acknowledge explicitly, and that is the objective of maintaining price stability.\nB Correct because fiscal policy can be used to redistribute income and wealth.\nC Incorrect because monetary policy (not fiscal policy) refers to central bank activities that are directed toward influencing the quantity of money and credit in an economy."},
  {"num": 28, "subject": "经济学", "question": "Which of the following government actions is most likely an expansionary fiscal policy?", "options": {"A": "Increasing sales tax rate.", "B": "Decreasing savings tax rate.", "C": "Decreasing infrastructure spending."}, "answer": "B", "explanation": "A Incorrect because an increase in taxes, including tax on sales, would not be expansionary fiscal policy. For example, an expansionary policy could take the form of cuts in sales (indirect) taxes to lower prices which raises real incomes with the objective of raising consumer demand.\nB Correct because a decrease in taxes, including tax on savings, would be expansionary fiscal policy. For example, an expansionary policy could take the form of cuts in tax rates on personal savings to raise disposable income for those with savings, with the objective of raising consumer demand.\nC Incorrect because a decrease in public spending, including infrastructure, would not be an expansionary fiscal policy. For example, an expansionary policy could take the form of new public spending on social goods and infrastructure, such as hospitals and schools, boosting personal incomes with the objective of raising aggregate demand."},
  {"num": 29, "subject": "经济学", "question": "Monetary policy is used to:", "options": {"A": "promote stable growth.", "B": "redistribute income and wealth.", "C": "determine taxation and spending."}, "answer": "A", "explanation": "A Correct because the overarching goal of both monetary and fiscal policy is normally the creation of an economic environment where growth is stable and positive and inflation is stable and low.\nB Incorrect because fiscal policy, not monetary policy, is used to redistribute income and wealth. Monetary policy refers to central bank activities that are directed toward influencing the quantity of money and credit in an economy. Whereas fiscal policy can be used to redistribute income and wealth.\nC Incorrect because fiscal policy, not monetary policy, determines taxation and spending. Monetary policy refers to central bank activities that are directed toward influencing the quantity of money and credit in an economy. Whereas fiscal policy refers to the government’s decisions about taxation and spending."},
  {"num": 30, "subject": "经济学", "question": "An argument against being concerned about high national debt levels is that:", "options": {"A": "the debt is owed internally to fellow citizens.", "B": "government borrowing leads to higher private sector investment.", "C": "the central bank can print money to finance a government deficit."}, "answer": "A", "explanation": "A Correct because this internally owed debt may overstate the problem. The arguments against being concerned about national debt (relative to GDP) include the following: The scale of the problem may be overstated because the debt is owed internally to fellow citizens.\nB Incorrect because government borrowing leads to lower private sector investment. The arguments in favor of being concerned include: Government borrowing may divert private sector investment from taking place (an effect known as crowding out); if there is a limited amount of savings to be spent on investment, then larger government demands will lead to higher interest rates and lower private sector investing.\nC Incorrect because this is an argument against high national debt due to the risk of high inflation. The arguments in favor of being concerned include: If markets lose confidence in a government, then the central bank may have to print money to finance a government deficit. This may lead ultimately to high inflation."},
  {"num": 31, "subject": "经济学", "question": "If an economy has a long-term growth potential of 2% per year and the central bank's inflation target is 3% per year, the neutral rate of interest is most likely:", "options": {"A": "1%.", "B": "3%.", "C": "5%."}, "answer": "C", "explanation": "A Incorrect because it is the difference between the inflation target of 3% and the long-term growth potential of 2%. 3% - 2% = 1%\nB Incorrect because it is the inflation rate and ignores the growth potential. As such this would be an expansionary rate of interest. Neutral rate = Trend growth + Inflation target.\nC Correct because the Neutral rate = Trend growth + Inflation target = 2% + 3% = 5%."},
  {"num": 32, "subject": "经济学", "question": "The inflation target of an effective central bank is most likely:", "options": {"A": "equal to zero to avoid the risk of deflation.", "B": "sufficiently below zero to maintain high credibility.", "C": "low enough to ensure a significant degree of price stability."}, "answer": "C", "explanation": "A Incorrect because an inflation-targeting framework normally has a clear, symmetric and forward-looking medium-term inflation target, sufficiently above 0 percent to avoid the risk of deflation but low enough to ensure a significant degree of price stability\nB Incorrect because an inflation-targeting framework normally has a clear, symmetric and forward-looking medium-term inflation target, sufficiently above 0 percent to avoid the risk of deflation but low enough to ensure a significant degree of price stability.\nC Correct because an inflation-targeting framework normally has a clear, symmetric and forward-looking medium-term inflation target, sufficiently above 0 percent to avoid the risk of deflation but low enough to ensure a significant degree of price stability."},
  {"num": 33, "subject": "经济学", "question": "Which of the following is most likely to limit the effectiveness of monetary policy?", "options": {"A": "A liquidity trap.", "B": "The crowding out effect.", "C": "A time lag to implement government spending."}, "answer": "A", "explanation": "A Correct because there may be occasions where the demand for money becomes infinitely elastic so that further injections of money into the economy will not serve to further lower interest rates or affect real activity. This is known as a liquidity trap. In this extreme circumstance, monetary policy can become completely ineffective.\nB Incorrect because crowding out is the reduction in private sector investment due to increased government borrowing and describes a difficulty in implementing fiscal, not monetary, policy.\nC Incorrect because this is the action lag and describes a difficulty in implementing fiscal policy. An example of the action lag is the government's decision to raise spending on capital projects to increase employment and incomes, but they may take many months to implement."},
  {"num": 34, "subject": "经济学", "question": "When a central bank sells government bonds to commercial banks, broad money growth:", "options": {"A": "decreases.", "B": "remains the same.", "C": "increases."}, "answer": "A", "explanation": "A Correct because when a central bank sells government bonds to a commercial bank the reserves of commercial banks decline, reducing their capacity to make loans (i.e., create credit) to households and corporations and thus causing broad money growth to decline through the money multiplier mechanism.\nB Incorrect because when a central bank sells government bonds to a commercial bank the reserves of commercial banks decline, reducing their capacity to make loans (i.e., create credit) to households and corporations and thus causing broad money growth to decline through the money multiplier mechanism.\nC Incorrect because when a central bank sells government bonds to a commercial bank the reserves of commercial banks decline, reducing their capacity to make loans (i.e., create credit) to households and corporations and thus causing broad money growth to decline through the money multiplier mechanism."},
  {"num": 35, "subject": "经济学", "question": "Independence, credibility, and transparency are most likely:", "options": {"A": "key objectives of fiscal policy.", "B": "properties of the monetary transmission mechanism.", "C": "qualities that determine the success of an inflation-targeting central bank."}, "answer": "C", "explanation": "A Incorrect because these are qualities of a central bank. A primary aim for fiscal policy is to help manage the economy through its influence on aggregate national output, that is, real GDP.\nB Incorrect because these are qualities of a successful inflation-targeting central bank. The monetary transmission mechanism is the process whereby a central bank’s interest rate gets transmitted through the economy and ultimately affects the rate of increase of prices—that is, inflation. Those channels include bank lending rates, asset prices, agents’ expectations, and exchange rates.\nC Correct because although inflation-targeting regimes vary a little from economy to economy, their success is thought to depend on three key concepts: central bank independence, credibility, and transparency."},
  {"num": 36, "subject": "经济学", "question": "With respect to conventional monetary policy, combating inflation is most likely:", "options": {"A": "less difficult than combating deflation.", "B": "equally difficult as combating deflation.", "C": "more difficult than combating deflation."}, "answer": "A", "explanation": "A Correct because deflation is more difficult for conventional monetary policy to deal with than inflation. This is because once the monetary authority has cut nominal interest rates to zero to stimulate the economy, it cannot cut them any further.\nB Incorrect because deflation is more difficult for conventional monetary policy to deal with than inflation. This is because once the monetary authority has cut nominal interest rates to zero to stimulate the economy, it cannot cut them any further.\nC Incorrect because deflation is more difficult for conventional monetary policy to deal with than inflation. This is because once the monetary authority has cut nominal interest rates to zero to stimulate the economy, it cannot cut them any further."},
  {"num": 37, "subject": "经济学", "question": "Fiat money:", "options": {"A": "is not currently used in any major economy.", "B": "can be exchanged for a precious metal at the country's central bank.", "C": "derives its value via government decree and because people accept it for payment."}, "answer": "C", "explanation": "A Incorrect because money in all major economies today is not convertible by law into anything else, but it is, in law, legal tender. Money that is not convertible into any other commodity is known as fiat money.\nB Incorrect because money that is not convertible into any other commodity is known as fiat money.\nC Correct because fiat money derives its value via government decree and because people accept it for payment of goods and services and for debt repayment."},
  {"num": 38, "subject": "经济学", "question": "Which of the following is a limitation of monetary policy?", "options": {"A": "The presence of automatic stabilizers in the economy.", "B": "The ineffectiveness of interest rate adjustments in deflationary environments.", "C": "The uneven distribution of income and wealth among different segments of the population."}, "answer": "B", "explanation": "A Incorrect because this is not a limitation of monetary policy. Automatic stabilizers are features which reduce output fluctuations in the economy and impact fiscal policy.\nB Correct because this is a limitation of monetary policy. The limitations of monetary policy include problems in the transmission mechanism and the relative ineffectiveness of interest rate adjustment as a policy tool in deflationary environments.\nC Incorrect because this is not a limitation of monetary policy. This is an aspect of the economy that fiscal policy tools try to address. The limitations of monetary policy include problems in the transmission mechanism and the relative ineffectiveness of interest rate adjustment as a policy tool in deflationary environments."},
  {"num": 39, "subject": "经济学", "question": "To be effective in targeting inflation a central bank is least likely to need:", "options": {"A": "government oversight.", "B": "transparency of decisions.", "C": "credibility with market participants."}, "answer": "A", "explanation": "A Correct because an inflation-targeting framework normally has an independent and credible central bank. Such an independent central back does not need government oversight.\nB Incorrect because by explaining their views on the economy and by being transparent in decision making, the independent, inflation-targeting central banks seek to gain reputation and credibility, making it easier to influence inflation expectations and hence ultimately easier to meet the inflation target.\nC Incorrect because an inflation-targeting framework normally has an independent and credible central bank. It is important that the central bank has credibility with market participants."},
  {"num": 40, "subject": "经济学", "question": "An analyst gathers the following data about an economy:\nIf monetary policy is contractionary, the central bank's inflation target is:", "options": {"A": "less than 1.0%.", "B": "equal to 1.0%.", "C": "greater than 1.0%."}, "answer": "A", "explanation": "A Correct because when policy rates are above the neutral rate, monetary policy is contractionary; when they are below the neutral rate, monetary policy is expansionary. The calculation of the neutral rate is as follows: Neutral rate = Trend growth + Inflation target. Therefore, if monetary policy is contractionary then the policy rate (1.5%) must be greater than the neutral rate. Hence the long-term inflation rate must be less than 1.0% in order for the policy rate to be greater than the neutral rate.\nB Incorrect because when policy rates are above the neutral rate, monetary policy is contractionary; when they are below the neutral rate, monetary policy is expansionary. The calculation of the neutral rate is as follows: Neutral rate = Trend growth + Inflation target. Therefore, if monetary policy is contractionary then the policy rate (1.5%) must be greater than the neutral rate. Hence the long-term inflation rate must be less than 1.0% in order for the policy rate to be greater than the neutral rate.\nC Incorrect because when policy rates are above the neutral rate, monetary policy is contractionary; when they are below the neutral rate, monetary policy is expansionary. The calculation of the neutral rate is as follows: Neutral rate = Trend growth + Inflation target. Therefore, if monetary policy is contractionary then the policy rate (1.5%) must be greater than the neutral rate. Hence the long-term inflation rate must be less than 1.0% in order for the policy rate to be greater than the neutral rate."},
  {"num": 41, "subject": "经济学", "question": "To reduce inflation, a central bank most likely implements an interest rate policy that is:", "options": {"A": "contractionary.", "B": "neutral.", "C": "expansionary."}, "answer": "A", "explanation": "A Correct because when central banks believe that economic activity is likely to lead to an increase in inflation, they might increase interest rates, thereby reducing liquidity. In these cases, market analysts describe such actions as contractionary.\nB Incorrect because the neutral rate is that rate of interest that neither spurs on nor slows down the underlying economy. As such, when policy rates are above the neutral rate, monetary policy is contractionary; when they are below the neutral rate, monetary policy is expansionary.\nC Incorrect because when the economy is slowing and inflation and monetary trends are weakening, central banks may increase liquidity by cutting their target rate. In these circumstances, monetary policy is said to be expansionary."},
  {"num": 42, "subject": "经济学", "question": "Under which of the following conditions is monetary policy most effective? When the:", "options": {"A": "demand for money is infinitely elastic.", "B": "central bank targets an exchange rate.", "C": "risk of inflation is greater than deflation."}, "answer": "C", "explanation": "A Incorrect because this leads to a liquidity trap. In very extreme instances, there may be occasions where the demand for money becomes infinitely elastic so that further injections of money into the economy will not serve to further lower interest rates or affect real activity. This is known as a liquidity trap. In this extreme circumstance, monetary policy can become completely ineffective.\nB Incorrect because when the central bank or monetary authority chooses to target an exchange rate, interest rates and conditions in the domestic economy must adapt to accommodate this target and domestic interest rates and money supply can become more volatile.\nC Correct because deflation is more problematic for the central bank than inflation. Deflation is a pervasive and persistent fall in a general price index and is more difficult for conventional monetary policy to deal with than inflation. This is because cutting nominal interest rates much below zero to stimulate the economy is difficult. It is at this point that the economic conditions for a liquidity trap arise."},
  {"num": 43, "subject": "经济学", "question": "Which of the following monetary policy actions is most likely considered expansionary? The central bank:", "options": {"A": "acts as the lender in a repurchase agreement.", "B": "sells government bonds to commercial banks.", "C": "raises reserve requirements of commercial banks."}, "answer": "A", "explanation": "A Correct because if the central bank wishes to increase the supply of money, it might buy bonds (usually government bonds) from the banks, with an agreement to sell them back at some time in the future. This transaction is known as a repurchase agreement. The lender in a repurchase agreement is the party that initially buys the bonds and agrees to sell them back at a later point in time. By purchasing bonds from banks, the central bank is increasing the money supply, or increasing liquidity, which is expansionary.\nB Incorrect because the central bank can sell government bonds to commercial banks. By doing this, the reserves of commercial banks decline, reducing their capacity to make loans (i.e., create credit) to households and corporations and thus causing broad money growth to decline through the money multiplier mechanism. This reduction in liquidity is contractionary, not expansionary.\nC Incorrect because a central bank could restrict money creation by raising the reserve requirements of banks. This causes banks to keep more money in reserve, which reduces the money supply. This monetary policy action is contractionary, not expansionary."},
  {"num": 44, "subject": "经济学", "question": "The overarching objective of most central banks is to maintain:", "options": {"A": "price stability.", "B": "full employment.", "C": "the government's ability to service its debt."}, "answer": "A", "explanation": "A Correct because there is one overarching objective that most central banks seem to acknowledge explicitly, and that is the objective of maintaining price stability.\nB Incorrect because although some central banks are charged with doing all they can to maintain full employment and output there is one overarching objective that most central banks seem to acknowledge explicitly, and that is the objective of maintaining price stability.\nC Incorrect because although some central banks have related but less tangible roles, like maintaining confidence in the financial system. There is one overarching objective that most central banks seem to acknowledge explicitly, and that is the objective of maintaining price stability. Maintaining the government's ability to service debt is not a main objective of central banks."},
  {"num": 45, "subject": "经济学", "question": "All else being equal, and assuming that wages and prices of goods are rigid, a decrease in government spending and decreasing interest rates most likely reflect:", "options": {"A": "easy fiscal policy and easy monetary policy.", "B": "tight fiscal policy and easy monetary policy.", "C": "easy fiscal policy and tight monetary policy."}, "answer": "B", "explanation": "A Incorrect because it's an easy monetary policy/easy fiscal policy: policy if both fiscal and monetary policy are easy, then the joint impact will be highly expansionary—leading to a rise in aggregate demand, lower interest rates (at least if the monetary impact is larger), and growing private and public sectors.\nB Correct because it's a tight fiscal policy/easy monetary policy: if a fiscal contraction is accompanied by expansionary monetary policy and low interest rates, then the private sector will be stimulated and will rise as a share of GDP, while the public sector will shrink. Falling government spending leads to a drop in aggregate demand or contraction.\nC Incorrect because it's an easy fiscal policy/tight monetary policy: if taxes are cut or government spending rises, the expansionary fiscal policy will lead to a rise in aggregate output. If this is accompanied by a reduction in money supply to offset the fiscal expansion, then interest rates will rise and have a negative effect on private sector demand. We have higher output and higher interest rates, and government spending will be a larger proportion of overall national income."},
  {"num": 46, "subject": "经济学", "question": "A role of most central banks is to:", "options": {"A": "set income tax rates.", "B": "decide on government expenditures.", "C": "regulate their country's payments system."}, "answer": "C", "explanation": "A Incorrect because the second set of tools used for influencing economic activity consists of the tools associated with fiscal policy. These involve the use of government spending and changing tax revenue to affect a number of aspects of the economy. Therefore, fiscal policies such as setting income tax rates are established by governments, not central banks.\nB Incorrect because the second set of tools used for influencing economic activity consists of the tools associated with fiscal policy. These involve the use of government spending and changing tax revenue to affect a number of aspects of the economy. Therefore, fiscal policies such as government spending are established by governments, not central banks.\nC Correct because central banks play several key roles in modern economies. Generally, a central bank is the regulator and supervisor of the payments system."},
  {"num": 47, "subject": "经济学", "question": "If contractionary fiscal policy and expansionary monetary policy have offsetting effects on GDP, the public sector's share of GDP will most likely:", "options": {"A": "decrease.", "B": "remain the same.", "C": "increase."}, "answer": "A", "explanation": "A Correct because if a fiscal contraction is accompanied by expansionary monetary policy and low interest rates, then the private sector will be stimulated and will rise as a share of GDP, while the public sector will shrink.\nB Incorrect because if a fiscal contraction is accompanied by expansionary monetary policy and low interest rates, then the private sector will be stimulated and will rise as a share of GDP, while the public sector will shrink.\nC Incorrect because if a fiscal contraction is accompanied by expansionary monetary policy and low interest rates, then the private sector will be stimulated and will rise as a share of GDP, while the public sector will shrink."},
  {"num": 48, "subject": "经济学", "question": "With respect to motivations for globalization, which of the following is best characterized as an intrinsic gain?", "options": {"A": "Increased supply chain efficiency.", "B": "Accelerated productivity from learning new methods.", "C": "Access to resources that are not readily available in the home country."}, "answer": "B", "explanation": "A Incorrect because this is a way to increase profits and not an intrinsic gain, which is a benefit beyond profit itself. Another way to increase profits is to reduce costs. Globalization allows companies to access lower tax-operating environments, reduce labor costs, or seek other supply chain efficiency gains, all of which are cost-reduction measures.\nB Correct because intrinsic gain is a side effect or consequence of an activity that generates a benefit beyond profit itself. It is difficult to measure but contributes to globalization's momentum. It can also be a stabilizing force, increasing empathy between actors and reducing the likelihood that a geopolitical threat is levied. One example of intrinsic gain is the accelerated productivity from learning new methods.\nC Incorrect because non-state actors, such as companies and investors, who choose to participate in globalization consider three potential gains: Increasing profits, access to resources and markets and intrinsic gain. Hence access to resources is not best characterized as an intrinsic gain. Moreover, if those resources are not readily available or affordable in the home country, then the non-state actor may globalize to improve access."},
  {"num": 49, "subject": "经济学", "question": "Which of the following organizations was founded with the goal of assisting in the reconstruction of the international payment system?", "options": {"A": "The World Trade Organization.", "B": "The International Monetary Fund.", "C": "The International Bank for Reconstruction and Development."}, "answer": "B", "explanation": "A Incorrect because WTO provides the legal and institutional foundation of the multinational trading system. It is the only international organization that regulates cross-border trade relationships among nations on a global scale.\nB Correct because IMF was founded with the goal to stabilize exchange rates and assist the reconstruction of the world’s international payment system.\nC Incorrect because the World Bank was created to facilitate post-war reconstruction and development. Also, World Bank’s two closely affiliated entities—the International Bank for Reconstruction and Development (IBRD) and the International Development Association (IDA)—provide low or no-interest loans and grants to countries that have unfavourable or no access to international credit markets."},
  {"num": 50, "subject": "经济学", "question": "Which of the following behavioral archetypes best describes a country that is high on the globalization spectrum but low on the cooperation spectrum?", "options": {"A": "Autarky.", "B": "Hegemony.", "C": "Bilateralism."}, "answer": "B", "explanation": "A Incorrect because there are four archetypes of country behavior: autarky, hegemony, multilateralism, and bilateralism, where autarky is situated low on the cooperation spectrum and low (not high) on the globalization spectrum. Autarky describes countries seeking political self-sufficiency with little or no external trade or finance. State-owned enterprises control strategic domestic industries.\nB Correct because using the two axes we have discussed—political cooperation versus non-cooperation and globalization versus nationalism—investment analysts can assess geopolitical actors and the likelihood of threat to investment outcomes. Specifically, there are four archetypes of country behavior: autarky, hegemony, multilateralism, and bilateralism, where hegemony is situated low on the cooperation spectrum and high on the globalization spectrum. Hegemonic countries tend to be regional or even global leaders, and they use their political or economic influence of others to control resources. State-owned enterprises tend to control key export markets. Examples of hegemonic countries include the United States and Russia.\nC Incorrect because there are four archetypes of country behavior: autarky, hegemony, multilateralism, and bilateralism, where bilateralism is situated high on the cooperation (not globalization) spectrum and low on the globalization (not cooperation) spectrum. Bilateralism is the conduct of political, economic, financial, or cultural cooperation between two countries. Countries engaging in bilateralism may have relations with many different countries, but they are one-at-a-time agreements without multiple partners."},
  {"num": 51, "subject": "经济学", "question": "With respect to geopolitics, setting standards for the size and shape of containers used for shipping is most likely an example of:", "options": {"A": "regulatory cooperation.", "B": "process standardization.", "C": "operational synchronization."}, "answer": "C", "explanation": "A Incorrect because regulatory cooperation includes setting up regulatory bodies such as Basel Committee on Banking Supervision (BCBS) rather than setting standards for container size and shape.\nB Incorrect because process standardization includes establishing processes like Society for Worldwide Interbank Financial Telecommunication (SWIFT) rather than setting standards for container size and shape.\nC Correct because an example of operational synchronization is standards set for containers of uniform size and shape using multi-modal forms of transport (land, sea, air, rail) and port cranes."},
  {"num": 52, "subject": "经济学", "question": "Which of the following would most likely lead to an increase in globalization? A decrease in:", "options": {"A": "soft power.", "B": "nationalism.", "C": "standardization."}, "answer": "B", "explanation": "A Incorrect because soft power has a positive effect on globalization. Soft power is a means of influencing another country's decisions without force or coercion. Soft power can be built over time through such actions as cultural programs, advertisement, travel grants, and university exchange. And globalization also has cultural and communicative features. Although it can be difficult to measure these features, such as the spread of information or culture, it has increased interactions between citizens of countries all over the world. Internet usage allows for the near-instantaneous spread of cultural information and context.\nB Correct because globalization is marked by economic and financial cooperation, including the active trade of goods and services, capital flows, currency exchange, and cultural and information exchange. Actors participating in globalization are likely to reach beyond their national borders for access to new markets, talent, or learning. By contrast, anti-globalization or nationalism is the promotion of a country’s own economic interests to the exclusion or detriment of the interests of other nations.\nC Incorrect because standardization is the process of creating protocols for the production, sale, transport, or use of a product or service. Standardization occurs when relevant parties agree to follow these protocols together. It helps support expanded economic and financial activities across borders. And as globalization deepens, companies develop standards and processes to incorporate multiple cultures into their overall corporate culture. They must cooperate with multiple sets of rules, and they may establish standard procedures based on the groups of companies they operate in."},
  {"num": 53, "subject": "经济学", "question": "Which of the following changes are investors most likely to make in response to a black swan risk?", "options": {"A": "Tactical.", "B": "Sector specific.", "C": "Asset allocation."}, "answer": "A", "explanation": "A Correct because the velocity of geopolitical risk is the pace at which it impacts an investor portfolio. For the sake of simplicity, we explore short-term or 'high velocity' impacts, medium-term, and long-term or 'low velocity' impacts. In the short term, we may see volatility in the markets affecting entire industries or even the entire market. Exogenous or 'black swan' events tend to fit into this category, causing market volatility and investor flight to quality. A black swan risk is an event that is rare and difficult to predict but has an important impact. Investors with the appropriate time horizon and risk tolerance may make tactical changes to their investment choices as a result of these events. Long-term changes are unlikely to be necessary.\nB Incorrect because this relates to a medium-term impact of geopolitical risk instead: Risks with a medium-term impact may begin to impair companies’ processes, costs, and investment opportunities, resulting in lower valuations. These risks tend to be distributed towards specific sectors, meaning they will impact some companies much more than others.\nC Incorrect because this relates to a low velocity impact of geopolitical risk instead: The velocity of geopolitical risk is the pace at which it impacts an investor portfolio. For the sake of simplicity, we explore short-term or 'high velocity' impacts, medium-term, and long-term or 'low velocity' impacts. And long-term risks may have important environmental, social, governance, and other impacts. This can impact an investor’s asset allocation—including choice of asset classes and investment styles—for a long-term horizon; however, the immediate impact on portfolios is likely to be more limited."},
  {"num": 54, "subject": "经济学", "question": "Cyber threats most likely fall into the category of:", "options": {"A": "event risk.", "B": "thematic risk.", "C": "exogenous risk."}, "answer": "B", "explanation": "A Incorrect because event risk evolves around set dates, such as elections, new legislation, or other date-driven milestones, such as holidays or political anniversaries, known in advance, whilst thematic risks are known risks that evolve and expand over a period of time and cyber threats are an example of thematic risk.\nB Correct because cyber threats are another example of thematic risk.\nC Incorrect because exogenous risk is a sudden or unanticipated risk that impacts either a country’s cooperative stance, the ability of non-state actors to globalize, or both. Examples include sudden uprisings, invasions, or the aftermath of natural disasters, whilst thematic risks are known risks that evolve and expand over a period of time and cyber threats are an example of thematic risk."},
  {"num": 55, "subject": "经济学", "question": "Natural disasters are an example of:", "options": {"A": "event risk.", "B": "thematic risk.", "C": "exogenous risk."}, "answer": "C", "explanation": "A Incorrect because event risk evolves around set dates, such as elections, new legislation, or other date-driven milestones, such as holidays or political anniversaries, known in advance.\nB Incorrect because thematic risks are known risks that evolve and expand over a period of time. Climate change, pattern migration, the rise of populist forces, and the ongoing threat of terrorism fall into this category.\nC Correct because exogenous risk is a sudden or unanticipated risk that impacts either a country’s cooperative stance, the ability of non-state actors to globalize, or both. Examples include sudden uprisings, invasions, or the aftermath of natural disasters."},
  {"num": 56, "subject": "经济学", "question": "Which of the following is most likely a benefit of globalization?", "options": {"A": "Increased profits.", "B": "More equal income distribution.", "C": "Stronger environmental, social, and governance standards."}, "answer": "A", "explanation": "A Correct because the opportunity to generate higher profits may motivate companies to globalize. The first way to generate profit is to increase sales. Companies may choose to engage in globalization in order to access new customers for their goods and services. Another way to increase profits is to reduce costs. Globalization allows companies to access lower tax-operating environments, reduce labor costs, or seek other supply chain efficiency gains.\nB Incorrect because globalization can contribute to income and wealth inequality, as well as differences in opportunity, within and between countries.\nC Incorrect because companies operating in lower-cost countries often operate in the local standards of those countries. If standards on environmental protection, social benefits, or corporate governance are lower in one country compared to another and companies ultimately reduce their standards of production in that context, then globalization can create a drain on human, administrative, and environmental resources."},
  {"num": 57, "subject": "经济学", "question": "The main objective of the World Bank Group is to:", "options": {"A": "support exchange rate stability and an open system of international payments.", "B": "provide the legal and institutional foundation of the multinational trading system.", "C": "help developing countries fight poverty and enhance environmentally sound economic growth."}, "answer": "C", "explanation": "A Incorrect because this refers to a key objective for the International Monetary Fund. That is, the IMF supports exchange rate stability and an open system of international payments.\nB Incorrect because this refers to a key objective for the World Trade Organization. That is, the WTO provides the legal and institutional foundation of the multinational trading system.\nC Correct because the World Bank's main objective is to help developing countries fight poverty and enhance environmentally sound economic growth."},
  {"num": 58, "subject": "经济学", "question": "With respect to trading blocs, a common market most likely incorporates all aspects of a(n):", "options": {"A": "customs union.", "B": "monetary union.", "C": "economic union."}, "answer": "A", "explanation": "A Correct because the common market is the next level of economic integration that incorporates all aspects of the customs union and extends it by allowing free movement of factors of production among members.\nB Incorrect because the common market is the customs union plus the free movement of factors of production among members. An economic union plus a common currency is a monetary union. That is, if the members of the economic union decide to adopt a common currency, then it is also a monetary union.\nC Incorrect because the common market is the customs union plus the free movement of factors of production among members. Common economic institutions and coordination of economic policies among members are traits of an economic union. That is, an economic union requires an even greater degree of integration. It incorporates all aspects of a common market and in addition requires common economic institutions and coordination of economic policies among members."},
  {"num": 59, "subject": "经济学", "question": "The implementation of an export subsidy for a normal good produced in a small country will most likely increase the:", "options": {"A": "domestic consumption of the good.", "B": "price of the good in the domestic market.", "C": "national welfare of the country providing the subsidy."}, "answer": "B", "explanation": "A Incorrect because in the case of an export subsidy, the exporter has the incentive to shift sales from the domestic to the export market. This scenario raises the price in the domestic market by the amount of the subsidy in the small country case (price before subsidy plus subsidy). As the domestic price in the small country is higher, the consumption of the good will decline (rather than increase).\nB Correct because in the case of an export subsidy, the exporter has the incentive to shift sales from the domestic to the export market because it receives the international price plus the per-unit subsidy for each unit of the good exported. This scenario raises the price in the domestic market by the amount of the subsidy in the small country case (price before subsidy plus subsidy).\nC Incorrect because an export subsidy is a payment by the government to a firm for each unit of a good that is exported. Its goal is to stimulate exports. But it interferes with the functioning of the free market and may distort trade away from comparative advantage. Hence, it reduces welfare. The net welfare effect is negative in both the large and small country cases. Thus, export subsidies decrease rather than increase national welfare."},
  {"num": 60, "subject": "经济学", "question": "An argument against free trade is that:", "options": {"A": "it has the potential to lead to greater income inequality.", "B": "it increases average production costs in goods and services.", "C": "it discourages foreign research and development in an economy."}, "answer": "A", "explanation": "A Correct because opponents of free trade point to the potential for greater income inequality and the loss of jobs in developed countries as a result of import competition.\nB Incorrect because firms benefit from greater economies of scale. Hence, scale economies allow firms to benefit from the larger market size and experience lower average cost of production as a result of trade.\nC Incorrect because trade can lead to increased exchange of ideas, freer flow of technical expertise, and greater awareness of changing consumer tastes and preferences in global markets. It can also contribute to the development of higher quality and more effective institutions and policies that encourage domestic innovation. For example, Coe and Helpman (1995) show that foreign research and development (R&D) has beneficial effects on domestic productivity. These effects become stronger the more open an economy is to foreign trade."},
  {"num": 61, "subject": "经济学", "question": "When a country that is a price taker imposes a tariff on an imported good:", "options": {"A": "national welfare increases.", "B": "consumers gain consumer surplus.", "C": "local producers gain producer surplus."}, "answer": "C", "explanation": "A Incorrect because a small country is one that is a price taker in the world market for a product and cannot influence the world market price. The welfare effect can be summarized as follows: Consumers suffer a loss of consumer surplus, local producers gain producer surplus and the net welfare effect results in a deadweight loss to the country's welfare.\nB Incorrect because the economic impact of a tariff on imports in a small country is one that is a price taker in the world market for a product and cannot influence the world market price. The welfare effect can be summarized as follows: Consumers suffer a loss of consumer surplus, local producers gain producer surplus and the net welfare effect results in a deadweight loss to the country's welfare.\nC Correct because the economic impact of a tariff on imports in a small country is one that is a price taker in the world market for a product and cannot influence the world market price. The welfare effect can be summarized as follows: Consumers suffer a loss of consumer surplus, local producers gain producer surplus and the net welfare effect results in a deadweight loss to the country's welfare."},
  {"num": 62, "subject": "经济学", "question": "An analyst gathers the following information:\nNote: the exchange rate is expressed as the number of units of domestic currency per unit of foreign currency.\nThe change in the real exchange rate is closest to:", "options": {"A": "4%.", "B": "5%.", "C": "7%."}, "answer": "B", "explanation": "A Incorrect because it does not add 1 to the inflation rates and the nominal appreciation rate in the formula, and calculates the change of the real exchange rate as (6%) × (2%)/(3%) = 4%.\nB Correct because the change in the real exchange rate is (1 + ΔSd/f/Sd/f) × (1 + ΔPf/Pf) / (1 + ΔPd/Pd) − 1 = (1 + 6%) × (1 + 2%)/(1 + 3%) − 1 = 1.06 × 1.02/1.03 − 1 = 0.0497 ≈ 0.05 = 5%, where ΔSd/f/Sd/f is the change of the nominal exchange rate, ΔPf/Pf is the foreign inflation rate, and ΔPd/Pd is the domestic inflation rate. Using the appropriate approximate formula, 6.0% + 2.0% – 3.0% = 5% leads to the same answer choice.\nC Incorrect because it interchanges domestic and foreign inflation rates in the formula, and calculates the change of real exchange rate as (1 + 6%) × (1 + 3%)/(1 + 2%) − 1 = 1.06 × 1.03/1.02 − 1 = 0.0704 ≈ 0.07 = 7%."},
  {"num": 63, "subject": "经济学", "question": "When a country has a fiscal surplus and an excess of private saving over investment, its exports are:", "options": {"A": "less than its imports.", "B": "equal to its imports.", "C": "greater than its imports."}, "answer": "C", "explanation": "A Incorrect because when a country has a fiscal surplus (T > G) and an excess of private saving over investment (S > I), its exports are greater than (not less than) its imports (X > M).\nB Incorrect because when a country has a fiscal surplus (T > G) and an excess of private saving over investment (S > I), its exports are greater than (not less than) its imports (X > M).\nC Correct because using a fundamental identity from macroeconomics, the relationship between the trade balance and expenditure/saving decisions can be expressed as: X– M = (S – I) + (T – G) where X represents exports, M is imports, S is private savings, I is investment in plant and equipment, T is taxes net of transfers, and G is government expenditure. From this relationship, we can see that a trade surplus (X > M) must be reflected in a fiscal surplus (T > G), an excess of private saving over investment (S > I), or both. We can also see that when a country has a fiscal surplus (T > G) and an excess of private saving over investment (S > I), its exports are greater than its imports (X > M)."},
  {"num": 64, "subject": "经济学", "question": "The conversion of nominal exchange rates into real exchange rates requires the:", "options": {"A": "GDP of both countries.", "B": "price levels in both countries.", "C": "interest rates in both countries."}, "answer": "B", "explanation": "A Incorrect because real exchange rates adjust for the price level in both countries not GDP. Real exchange rates, which are indexes often constructed by economists and other market analysts to assess changes in the relative purchasing power of one currency compared with another. Creating these indexes requires adjusting the nominal exchange rate by using the price levels in each country of the currency pair.\nB Correct because real exchange rates, which are indexes often constructed by economists and other market analysts to assess changes in the relative purchasing power of one currency compared with another. Creating these indexes requires adjusting the nominal exchange rate by using the price levels in each country of the currency pair.\nC Incorrect because real exchange rates adjust for the price level in both countries not interest rates. Real exchange rates, which are indexes often constructed by economists and other market analysts to assess changes in the relative purchasing power of one currency compared with another. Creating these indexes requires adjusting the nominal exchange rate by using the price levels in each country of the currency pair."},
  {"num": 65, "subject": "经济学", "question": "Price levels increase by 2% in the US and by 6% in the Eurozone. If the nominal spot exchange rate of the USD/EUR (amount of US dollars per 1 euro) decreases by 4%, the absolute change in the real exchange rate is closest to:", "options": {"A": "0%.", "B": "4%.", "C": "8%."}, "answer": "A", "explanation": "A Correct because the change in the real exchange rate is: (1-4%)×()-1≈0% Thus, the change in the real exchange rate is approximately zero percent. The rough calculation is: −4% + 6% − 2% = 0%.\nB Incorrect because the price increase in the U.S. is assumed to be additive; −4% + 6% + 2% = 4%.\nC Incorrect because the change in the nominal exchange rate is misinterpreted; 4% + 6% − 2% = 8%."},
  {"num": 66, "subject": "经济学", "question": "An ideal international currency regime would most likely have:", "options": {"A": "currencies that are fully convertible.", "B": "floating exchange rates between currencies.", "C": "a common monetary policy across different countries."}, "answer": "A", "explanation": "A Correct because the ideal currency regime would have three properties. One of those properties is, all currencies would be fully convertible (i.e., currencies could be freely exchanged for any purpose and in any amount). This condition ensures unrestricted flow of capital.\nB Incorrect because the ideal currency regime would have three properties. One of those properties states the exchange rate between any two currencies would be credibly fixed, not floating.\nC Incorrect because the ideal currency regime would have three properties. One of those properties states each country would be able to undertake fully independent (not common) monetary policy in pursuit of domestic objectives, such as growth and inflation targets."},
  {"num": 67, "subject": "经济学", "question": "In contrast to real exchange rates, nominal foreign exchange rates:", "options": {"A": "tend to deviate from purchasing power parity.", "B": "represent the relative price levels in the domestic and foreign countries.", "C": "are indexes useful for understanding international trade and capital flows."}, "answer": "A", "explanation": "A Correct because nominal exchange rates exhibit persistent deviations from PPP.\nB Incorrect because relative price levels are represented by the real exchange rate. The real exchange rate is an index that adjusts the nominal exchange rate for each country’s price level. Creating these indexes requires adjusting the nominal exchange rate by using the price levels in each country of the currency pair (hence the name “real exchange rates”) in order to compare the relative purchasing power between countries. An equivalent way of viewing the real exchange rate is that it represents the relative price levels in the domestic and foreign countries.\nC Incorrect because nominal exchange rates are not indexes. The real exchange rate represents indexes created by analysts to understand the international competitiveness of an economy and the real purchasing power of a currency. In this context, real exchange rates can be useful for understanding trends in international trade and capital flows and hence can be seen as one of the influences on nominal spot exchange rates."},
  {"num": 68, "subject": "经济学", "question": "Which of the following economic conditions for a country best supports a well-functioning currency board exchange rate system?", "options": {"A": "Flexible domestic prices and wages", "B": "Rapid growth in supply of the global reserve asset", "C": "Large non-traded sectors of the domestic economy"}, "answer": "A", "explanation": "A Correct because a currency board system works best if domestic prices and wages are very flexible.\nB Incorrect because a currency board system works best when the global supply of the reserve asset grows at a slow, steady rate consistent with long-run real growth with stable prices.\nC Incorrect because a currency board system works best if non-traded sectors of the domestic economy are relatively small."},
  {"num": 69, "subject": "经济学", "question": "Dollarization is best described as an exchange rate regime whereby a country:", "options": {"A": "uses the currency of another nation as its medium of exchange.", "B": "participates in a monetary union whose members share the same legal tender.", "C": "makes a commitment to exchange domestic currency for a specified foreign currency at a fixed exchange rate."}, "answer": "A", "explanation": "A Correct because in case of dollarization the country uses the currency of another nation as its medium of exchange and unit of account.\nB Incorrect because the IMF identifies two types of arrangements in which a country does not have its own legal tender. In the first, known as dollarization, the country uses the currency of another nation as its medium of exchange and unit of account. In the second, the country participates in a monetary union whose members share the same legal tender. Therefore dollarization is not best described as an exchange rate regime whereby the county participates in a monetary union whose members share the same legal tender.\nC Incorrect because in case of dollarization the country uses the currency of another nation as its medium of exchange and unit of account. In contrast, a currency board is a monetary regime based on an explicit legislative commitment to exchange domestic currency for a specified foreign currency at a fixed exchange rate, combined with restrictions on the issuing authority to ensure fulfillment of its legal obligation."},
  {"num": 70, "subject": "经济学", "question": "All else being equal, in an efficient market a forward exchange rate will decrease as a result of an increase in the:", "options": {"A": "spot exchange rate.", "B": "foreign risk-free interest rate.", "C": "domestic risk-free interest rate."}, "answer": "C", "explanation": "A Incorrect because the forward exchange rate will increase, rather than decrease, as a result of an increase in the spot exchange rate.\nB Incorrect because the forward exchange rate will increase, rather than decrease, as a result of an increase in the foreign risk-free interest rate.\nC Correct because the arbitrage equation can be re-arranged, as needs require, to get the formula for the forward rate, as follows:"},
  {"num": 71, "subject": "经济学", "question": "An analyst gathers the following information:\nUSD/AUD is the amount of USD per 1 AUD.\nThe USD/AUD 1-year forward rate is closest to:", "options": {"A": "0.7959.", "B": "0.8096.", "C": "0.8292."}, "answer": "A", "explanation": "A Correct because Ff/d = Sf/d ((1+if)/(1+id)). Substituting the values, Ff/d = 0.8027 × ((1+0.0242)/(1+0.033)) ≈ 0.7959.\nB Incorrect because it uses the incorrect formula Ff/d = Sf/d ((1+id)/(1+if)). Substituting the values, Ff/d = 0.8027 × ((1+0.033)/(1+0.0242)) ≈ 0.8096.\nC Incorrect because it uses the incorrect formula Ff/d = Sf/d (1+if). Substituting the values, Ff/d = 0.8027 × (1+0.033) ≈ 0.8292."},
  {"num": 72, "subject": "经济学", "question": "With respect to the foreign exchange market, an arbitrage relationship involving countries' relative interest rates serves as the basis for:", "options": {"A": "real exchange rates.", "B": "forward exchange rates.", "C": "nominal exchange rates."}, "answer": "B", "explanation": "A Incorrect because real exchange rates are indexes often constructed by economists and other market analysts to assess changes in the relative purchasing power of one currency compared with another, and are therefore not based on an arbitrage relationship.\nB Correct because forward exchange rates are based on an arbitrage relationship that equates the investment return on two alternative but equivalent investments, which involves the relationship between the risk-free interest rates of the two countries concerned. The arbitrage relationship is Ff/d = Sf/d(1 + if)/(1 + id), where Ff/d is the forward rate, Sf/d is the spot rate, and if (id) is the foreign (domestic) risk-free interest rate.\nC Incorrect because the nominal exchange rate is the number of units of one currency (called the price currency) that one unit of another currency (called the base currency) will buy, and is set by market forces e.g., capital flows, trade flows, etc. While it is true that cross-rate (nominal exchange rate) quotes must be consistent, the market will arbitrage the mispricings, the specific arbitrage relationship relating to nominal exchange rates does not involve relative interest rates, it is simply based on currency market quotations (and subsequently by the derived currency cross-rates)."},
  {"num": 73, "subject": "经济学", "question": "An analyst gathers the following foreign exchange rate information:\nCAD/USD is the amount of CAD per 1 USD.\nJPY/USD is the amount of JPY per 1 USD.\nThe percentage change in the JPY/CAD cross-rate for the period is closest to:", "options": {"A": "–2.7%.", "B": "1.4%.", "C": "2.8%."}, "answer": "B", "explanation": "A Incorrect because the CAD/USD exchange rate was not inverted, as required in the correct calculation: Beginning of period JPY/CAD rate = 1.3216 × 105.42 = 139.32 End of period JPY/CAD exchange rate = 1.2944 × 104.74 = 135.58 Therefore the percentage change in JPY/CAD was calculated incorrectly as 135.58/139.32 – 1 = –2.68% ≈ –2.7%.\nB Correct because sometimes it is necessary to invert one of the quotes in order to get the intermediary currency to cancel out in the equation to get the cross-rate. For example, to get a Canada–yen (JPY/CAD) quote, one is typically using the dollar–Canada (CAD/USD) rate and dollar–yen (JPY/USD) rate, which are the market conventions. Hence, to get a Canada–yen (JPY/CAD) quote, we must first invert the dollar–Canada (CAD/USD) quote before multiplying by the dollar–yen (JPY/USD) quote. The beginning of period JPY/CAD exchange rate is therefore = 1/1.3216 × 105.42 = 0.75666 × 105.42 = 79.77 The end of period JPY/CAD exchange rate is therefore = 1/1.2944 × 104.74 = 0.77256 × 104.74 = 80.92 The percentage change in the JPY/CAD exchange rate over the period is therefore = 80.92/79.77 – 1 = 1.44% ≈ 1.4%.\nC Incorrect because the beginning and end of period JPY/USD exchange rates have been reversed chronologically as follows: Beginning of period JPY/CAD rate = 1/1.3216 × 104.74 = 0.75666 × 104.74 = 79.25"},
  {"num": 74, "subject": "经济学", "question": "If the spot USD/EUR exchange rate (the amount of USD per 1 EUR) is 1.1605 and the 1-year forward rate is 1.17240, the forward points are:", "options": {"A": "+101.5.", "B": "+102.5.", "C": "+119.0."}, "answer": "C", "explanation": "A Incorrect because calculating (1 – (1.1605/1.17240)) × 10,000 ≈ 101.5 is not using the correct formula of (1.1724 – 1.1605) × 10,000 = 119.0.\nB Incorrect because calculating (1.17240/1.1605 – 1) × 10,000 ≈ 102.5 is not using the correct formula of (1.17240 – 1.1605) × 10,000 = 119.0.\nC Correct because the forward rate is calculated as (1.17240 – 1.1605) × 10,000 = 119.0."},
  {"num": 75, "subject": "经济学", "question": "An analyst gathers the following information about spot rates:\nUSD/GBP is the amount of USD per 1 GBP.\nUSD/EUR is the amount of USD per 1 EUR.\nThe spot EUR/GBP cross rate is closest to:", "options": {"A": "0.9351.", "B": "1.0694.", "C": "1.4855."}, "answer": "B", "explanation": "A Incorrect because sometimes it is necessary to invert one of the quotes in order to get the intermediary currency to cancel out in the equation to get the cross-rate. The formula for the EUR/GBP cross rate is USD/GBP × (USD/EUR)-1 = USD/GBP × EUR/USD. This answer inverts the wrong exchange rate and reverses the formula to 1.1786 / 1.2604 ≈ 0.9351. This answer would be the GBP/EUR cross rate, not the EUR/GBP cross rate.\nB Correct because sometimes it is necessary to invert one of the quotes in order to get the intermediary currency to cancel out in the equation to get the cross-rate. For example, to get a Canada–yen (JPY/CAD) quote, one is typically using the dollar–Canada (CAD/USD) rate and dollar–yen (JPY/USD) rate, which are the market conventions. This Canada–yen calculation requires that the dollar–Canada rate (CAD/USD) be inverted to a USD/CAD quote for the calculations to work. The formula for the EUR/GBP cross rate is USD/GBP × (USD/EUR)-1 = USD/GBP × EUR/USD = 1.2604 / 1.1786 ≈ 1.0694.\nC Incorrect because sometimes it is necessary to invert one of the quotes in order to get the intermediary currency to cancel out in the equation to get the cross-rate. This answer does not invert the quotes but rather multiplies the two spot rates. 1.2604 × 1.1786 ≈ 1.4855."}
];
